def _avg_close_position_ratio(df, bars: int = 3) -> float:
    try:
        if df is None or len(df) < 1:
            return 0.0
        recent = df.tail(min(len(df), max(int(bars), 1)))
        vals = []
        for _idx, row in recent.iterrows():
            hi = safe_float(row.get("high", 0), 0)
            lo = safe_float(row.get("low", 0), 0)
            cl = safe_float(row.get("close", 0), 0)
            rng = hi - lo
            if rng <= 0:
                continue
            vals.append((cl - lo) / rng)
        return float(sum(vals) / len(vals)) if vals else 0.0
    except Exception:
        return 0.0


def _consecutive_bar_streak(df, bullish: bool = True, bars: int = 5) -> int:
    try:
        if df is None or len(df) < 1:
            return 0
        recent = df.tail(min(len(df), max(int(bars), 1)))
        streak = 0
        rows = list(recent.itertuples())[::-1]
        for row in rows:
            op = safe_float(getattr(row, 'open', 0), 0)
            cl = safe_float(getattr(row, 'close', 0), 0)
            hi = safe_float(getattr(row, 'high', 0), 0)
            lo = safe_float(getattr(row, 'low', 0), 0)
            if _is_flat_or_doji_candle(op, cl, hi, lo):
                break
            ok = cl > op if bullish else cl < op
            if ok:
                streak += 1
            else:
                break
        return int(streak)
    except Exception:
        return 0


def _strong_bullish_candle_count(df, bars: int = 5) -> int:
    try:
        if df is None or len(df) < 1:
            return 0
        recent = df.tail(min(len(df), max(int(bars), 1)))
        cnt = 0
        for _idx, row in recent.iterrows():
            op = safe_float(row.get("open", 0), 0)
            cl = safe_float(row.get("close", 0), 0)
            hi = safe_float(row.get("high", 0), 0)
            lo = safe_float(row.get("low", 0), 0)
            rng = hi - lo
            if rng <= 0 or _is_flat_or_doji_candle(op, cl, hi, lo):
                continue
            body_ratio = abs(cl - op) / rng
            close_pos = (cl - lo) / rng
            if cl > op and body_ratio >= 0.55 and close_pos >= 0.70:
                cnt += 1
        return int(cnt)
    except Exception:
        return 0

def compute_breakout_ready_context_from_df(df1, current_price: float = 0.0) -> dict:
    ctx = {
        "prebreakout_hold_near_high_bars": 0,
        "prebreakout_pullback_depth_pct": 0.0,
        "prebreakout_retest_gap_bars": 999,
        "prebreakout_volume_reaccel_score": 0.0,
        "prebreakout_ready_score": 0.0,
        "prebreakout_label": "лҸҢнҢҢ м „ мӨҖл№„лҸ„ нҷ•мқёмӨ‘",
    }
    try:
        if df1 is None or len(df1) < 10:
            return ctx
        price = safe_float(current_price, 0)
        if price <= 0:
            price = safe_float(df1["close"].iloc[-1], 0)
        recent = df1.tail(min(len(df1), 18)).copy()
        highs = recent["high"].astype(float)
        lows = recent["low"].astype(float)
        closes = recent["close"].astype(float)
        vols = recent["volume"].astype(float)
        recent_high = safe_float(highs.max(), 0)
        if recent_high <= 0 or price <= 0:
            return ctx
        near_high_pct = ((recent_high - closes) / recent_high) * 100.0
        hold_bars = int((near_high_pct.tail(6) <= 0.65).sum())
        near_idx = [i for i, v in enumerate(near_high_pct[:-1]) if v <= 0.75]
        retest_gap = len(near_high_pct) - near_idx[-1] - 1 if near_idx else 999
        recent_pullback_low = safe_float(lows.tail(6).min(), price)
        pullback_depth = ((recent_high - recent_pullback_low) / recent_high) * 100.0 if recent_high > 0 else 0.0
        recent_vol = safe_float(vols.tail(3).mean(), 0)
        prev_vol = safe_float(vols.iloc[:-3].tail(5).mean(), 0)
        vol_reaccel = ((recent_vol / prev_vol) - 1.0) if prev_vol > 0 else 0.0
        score = 0.0
        if hold_bars >= 3:
            score += 1.1
        elif hold_bars >= 2:
            score += 0.6
        if 0 < pullback_depth <= 1.0:
            score += 0.9
        elif pullback_depth <= 1.8:
            score += 0.35
        elif pullback_depth >= 3.0:
            score -= 0.55
        if 1 <= retest_gap <= 4:
            score += 0.7
        elif retest_gap <= 8:
            score += 0.25
        if vol_reaccel >= 0.45:
            score += 0.9
        elif vol_reaccel >= 0.15:
            score += 0.45
        elif vol_reaccel <= -0.25:
            score -= 0.4
        # ETH н‘ңліё ліҙм •: кұ°лһҳлҹү мһ¬к°ҖмҶҚл§ҢмңјлЎң кі м җ м§Ғм „ мӨҖл№„лҸ„лҘј мўӢкІҢ ліҙм§Җ м•ҠлҠ”лӢӨ.
        try:
            recent_tail = recent.tail(min(len(recent), 5))
            body_strength = 0.0
            close_strength = 0.0
            for _idx, _row in recent_tail.iterrows():
                op = safe_float(_row.get("open", 0), 0)
                cl = safe_float(_row.get("close", 0), 0)
                hi = safe_float(_row.get("high", 0), 0)
                lo = safe_float(_row.get("low", 0), 0)
                rng = hi - lo
                if rng > 0:
                    body_strength += abs(cl - op) / rng
                    close_strength += (cl - lo) / rng
            n_tail = max(len(recent_tail), 1)
            body_strength = body_strength / n_tail
            close_strength = close_strength / n_tail
            price_chg_5 = ((safe_float(closes.iloc[-1], 0) - safe_float(closes.tail(6).iloc[0], 0)) / safe_float(closes.tail(6).iloc[0], 1)) * 100.0 if len(closes) >= 6 and safe_float(closes.tail(6).iloc[0], 0) > 0 else 0.0
            if body_strength < 0.16 and close_strength < 0.55:
                score -= 0.55
            if price_chg_5 < 0.10:
                score -= 0.45
            if vol_reaccel < 0.05:
                score -= 0.25
            if pullback_depth >= 2.80 and vol_reaccel <= 0.10:
                score -= 0.55
        except Exception:
            pass
        label = "лҸҢнҢҢ м „ мӨҖл№„лҸ„ ліҙнҶө"
        if score >= 2.60:
            label = "кі м җ л°”лЎң м•„лһҳ мӨҖл№„ мўӢмқҢ"
        elif score >= 1.35:
            label = "кі м җ лӢӨмӢң л¶ҷлҠ” мӨ‘"
        elif score <= -0.4:
            label = "лҸҢнҢҢ м „ нһҳ м•Ҫн•Ё"
        ctx.update({
            "prebreakout_hold_near_high_bars": hold_bars,
            "prebreakout_pullback_depth_pct": round(pullback_depth, 2),
            "prebreakout_retest_gap_bars": int(retest_gap),
            "prebreakout_volume_reaccel_score": round(vol_reaccel, 2),
            "prebreakout_ready_score": round(score, 2),
            "prebreakout_label": label,
        })
    except Exception:
        return ctx
    return ctx


def compute_breakout_ready_context(ticker: str, current_price: float = 0.0, df1=None) -> dict:
    try:
        df1 = df1 if df1 is not None else get_ohlcv(str(ticker or "").upper().strip(), "minute1")
        return compute_breakout_ready_context_from_df(df1, current_price=current_price)
    except Exception:
        return compute_breakout_ready_context_from_df(None, current_price=current_price)


def compute_chart_lifecycle_context_from_df(df1, current_price: float = 0.0) -> dict:
    """v2.5.184: 1л¶„лҙү м ҖмһҘк°’ кё°мӨҖмңјлЎң мҙҲмһ…/мһ¬м¶ңл°ң/лҠҰмқҖ м¶”кІ©мқ„ л¶„лҰ¬н•ңлӢӨ.

    л№ лҘё мҠӨмә” мЎ°кұҙмқ„ нҒ¬кІҢ мЎ°мқҙлҠ” мҡ©лҸ„к°Җ м•„лӢҲлӢӨ. мқҙлҜё м •л°Җл¶„м„қм—җ л“Өм–ҙмҳЁ нӣ„ліҙк°Җ
    м§ҖкёҲ м–ҙлҠҗ мң„м№ҳмқём§Җ review_dump/м•ҢлҰј/ліҙмҲҳнҷ” лЎңм§Ғмқҙ к°ҷмқҖ л§җлЎң мқҪкІҢ л§Ңл“ңлҠ” ліҙмЎ° м»Ён…ҚмҠӨнҠёлӢӨ.
    """
    ctx = {
        "chart_lifecycle_code": "UNKNOWN",
        "chart_lifecycle_label": "мң„м№ҳнҢҗлҸ… нҷ•мқёмӨ‘",
        "chart_lifecycle_warning": "",
        "chart_lifecycle_early_score": 0.0,
        "chart_lifecycle_restart_score": 0.0,
        "chart_lifecycle_late_score": 0.0,
        "chart_lifecycle_good_early": False,
        "chart_lifecycle_good_restart": False,
        "chart_lifecycle_late_flag": False,
        "chart_lifecycle_gap_pct": 999.0,
        "chart_lifecycle_from_low_pct": 0.0,
        "chart_lifecycle_zone_ratio": -1.0,
        "chart_lifecycle_bars_since_high": 999,
        "chart_lifecycle_bars_since_low": 999,
        "chart_lifecycle_close_strength_3": 0.0,
        "chart_lifecycle_wick_pressure_3": 0.0,
        "chart_lifecycle_vol_reaccel": 0.0,
        "chart_lifecycle_higher_low": False,
    }
    try:
        if df1 is None or len(df1) < 12:
            return ctx
        price = safe_float(current_price, 0)
        if price <= 0:
            price = safe_float(df1["close"].iloc[-1], 0)
        if price <= 0:
            return ctx

        recent = df1.tail(min(len(df1), 30)).copy()
        if len(recent) < 8:
            return ctx
        highs = recent["high"].astype(float)
        lows = recent["low"].astype(float)
        closes = recent["close"].astype(float)
        vols = recent["volume"].astype(float).fillna(0) if "volume" in recent.columns else None
        high_v = safe_float(highs.max(), 0)
        low_v = safe_float(lows.min(), 0)
        if high_v <= 0 or low_v <= 0 or high_v <= low_v:
            return ctx

        high_vals = list(highs.values)
        low_vals = list(lows.values)
        idx_high = high_vals.index(max(high_vals)) if high_vals else 0
        idx_low = low_vals.index(min(low_vals)) if low_vals else 0
        bars_since_high = max(len(high_vals) - idx_high - 1, 0)
        bars_since_low = max(len(low_vals) - idx_low - 1, 0)
        gap_pct = ((high_v - price) / high_v) * 100.0 if high_v > 0 else 999.0
        from_low_pct = ((price - low_v) / low_v) * 100.0 if low_v > 0 else 0.0
        zone_ratio = (price - low_v) / (high_v - low_v) if high_v > low_v else -1.0

        def _back_change(n: int) -> float:
            try:
                if len(closes) <= n:
                    return 0.0
                base = safe_float(closes.iloc[-n - 1], 0)
                if base <= 0:
                    return 0.0
                return ((price - base) / base) * 100.0
            except Exception:
                return 0.0

        chg5 = _back_change(5)
        chg10 = _back_change(10)
        chg30 = _back_change(30)
        upper1 = _last_upper_wick_pct(df1)
        upper3 = _avg_upper_wick_pct(df1, 3)
        lower3 = _avg_lower_wick_pct(df1, 3)
        close1 = _last_close_position_ratio(df1)
        close3 = _avg_close_position_ratio(df1, 3)
        body3 = _avg_candle_body_ratio(df1, 3)

        vol_reaccel = 0.0
        if vols is not None and len(vols) >= 8:
            recent_vol = safe_float(vols.tail(3).mean(), 0)
            prev_vol = safe_float(vols.iloc[:-3].tail(10).mean(), 0)
            if prev_vol > 0:
                vol_reaccel = (recent_vol / prev_vol) - 1.0

        higher_low = False
        try:
            tail_lows = [safe_float(x, 0) for x in lows.tail(5).tolist()]
            if len(tail_lows) >= 4 and min(tail_lows[:-1]) > 0:
                prev_window = tail_lows[-5:-2] if len(tail_lows) >= 5 else tail_lows[:-2]
                higher_low = bool(tail_lows[-1] >= min(tail_lows[-4:-1]) and tail_lows[-2] >= min(prev_window))
        except Exception:
            higher_low = False

        early_score = 0.0
        if 0.12 <= chg5 <= 1.45:
            early_score += 0.75
        elif 0.03 <= chg5 < 0.12 and chg10 >= 0.05:
            early_score += 0.35
        if 0.12 <= from_low_pct <= CHART_LIFE_EARLY_MAX_FROM_LOW_PCT:
            early_score += 0.85
        elif from_low_pct <= 3.00:
            early_score += 0.25
        if CHART_LIFE_GOOD_HIGH_GAP_MIN_PCT <= gap_pct <= 3.80:
            early_score += 0.75
        elif 0.70 <= gap_pct < CHART_LIFE_GOOD_HIGH_GAP_MIN_PCT:
            early_score += 0.20
        if max(close1, close3) >= 0.62:
            early_score += 0.35
        if upper1 <= 0.55 and upper3 <= 0.45:
            early_score += 0.30
        if vol_reaccel >= 0.15:
            early_score += 0.45
        elif vol_reaccel >= -0.10:
            early_score += 0.15

        restart_score = 0.0
        if 2 <= bars_since_high <= 14 and 0.35 <= gap_pct <= 3.80:
            restart_score += 0.55
        if higher_low:
            restart_score += 0.80
        if 0.35 <= from_low_pct <= CHART_LIFE_RESTART_MAX_FROM_LOW_PCT:
            restart_score += 0.55
        if gap_pct >= 1.15:
            restart_score += 0.55
        if close3 >= 0.50:
            restart_score += 0.35
        if lower3 >= 0.08:
            restart_score += 0.25
        if vol_reaccel >= -0.05:
            restart_score += 0.35
        if chg5 >= -0.05 or chg10 >= 0.05:
            restart_score += 0.25
        if bars_since_low <= 10 and bars_since_high >= 2:
            restart_score += 0.25

        late_score = 0.0
        if 0 <= gap_pct <= CHART_LIFE_LATE_NEAR_HIGH_PCT and from_low_pct >= CHART_LIFE_LATE_FROM_LOW_MIN_PCT:
            late_score += 1.05
        if from_low_pct >= 3.20 and gap_pct <= 1.45:
            late_score += 0.85
        if bars_since_high <= 5 and gap_pct <= 1.20 and chg5 <= 0.25:
            late_score += 0.75
        if upper1 >= 0.60 and close1 <= 0.56:
            late_score += 0.60
        if upper3 >= 0.45 and close3 <= 0.50:
            late_score += 0.45
        if body3 <= 0.16 and from_low_pct >= 2.30 and gap_pct <= 1.10:
            late_score += 0.35
        if chg30 >= 3.50 and chg5 <= 0.10 and gap_pct <= 1.60:
            late_score += 0.55

        code = "CHECK"
        label = "мң„м№ҳнҢҗлҸ… нҷ•мқёмӨ‘"
        warning = ""
        good_early = early_score >= 2.55 and late_score < CHART_LIFE_LATE_SCORE_BLOCK
        good_restart = restart_score >= 2.65 and late_score < CHART_LIFE_LATE_SCORE_BLOCK
        late_flag = late_score >= CHART_LIFE_LATE_SCORE_BLOCK
        if late_flag:
            code = "LATE_CHASE"
            label = "лҠҰмқҖ м¶”кІ©к¶Ң"
            warning = "кі м җ к·јмІҳ/мң—кј¬лҰ¬/м Җм җлҢҖл№„ м§„н–үмқ„ к°ҷмқҙ ліҙл©ҙ м§ҖкёҲ л”°лқјл¶ҷкё° лі„лЎң"
        elif good_restart:
            code = "RESTART_GOOD"
            label = "мһ¬м¶ңл°ң кө¬мЎ° мўӢмқҢ"
        elif good_early:
            code = "EARLY_GOOD"
            label = "мҙҲмһ… кө¬мЎ° мўӢмқҢ"
        elif early_score >= 1.70 or restart_score >= 1.75:
            code = "WATCHING"
            label = "мҙҲмһ…/мһ¬м¶ңл°ң нҷ•мқёмӨ‘"
        elif from_low_pct <= 0.10 and abs(chg5) <= 0.05:
            code = "TOO_EARLY"
            label = "м•„м§Ғ л„Ҳл¬ҙ мқҙлҘё мһҗлҰ¬"
        elif gap_pct >= 900:
            code = "UNKNOWN"
            label = "мң„м№ҳнҢҗлҸ… нҷ•мқёмӨ‘"

        ctx.update({
            "chart_lifecycle_code": code,
            "chart_lifecycle_label": label,
            "chart_lifecycle_warning": warning,
            "chart_lifecycle_early_score": round(early_score, 2),
            "chart_lifecycle_restart_score": round(restart_score, 2),
            "chart_lifecycle_late_score": round(late_score, 2),
            "chart_lifecycle_good_early": bool(good_early),
            "chart_lifecycle_good_restart": bool(good_restart),
            "chart_lifecycle_late_flag": bool(late_flag),
            "chart_lifecycle_gap_pct": round(gap_pct, 2),
            "chart_lifecycle_from_low_pct": round(from_low_pct, 2),
            "chart_lifecycle_zone_ratio": round(zone_ratio, 4),
            "chart_lifecycle_bars_since_high": int(bars_since_high),
            "chart_lifecycle_bars_since_low": int(bars_since_low),
            "chart_lifecycle_close_strength_3": round(close3, 4),
            "chart_lifecycle_wick_pressure_3": round(upper3, 2),
            "chart_lifecycle_vol_reaccel": round(vol_reaccel, 2),
            "chart_lifecycle_higher_low": bool(higher_low),
        })
    except Exception:
        return ctx
    return ctx


def compute_current_candle_context_from_df(df1, current_price: float = 0.0) -> dict:
    """v2.5.225: л§Ҳм§Җл§ү 1л¶„лҙү нҳ„мһ¬лҙүмқ„ v2лЎң нҢҗлҸ…н•ңлӢӨ.

    м „мІҙ мЎ°кұҙмқ„ л¬ҙмһ‘м • мЎ°мқҙлҠ” мҡ©лҸ„к°Җ м•„лӢҲлӢӨ. к°ҷмқҖ нӣ„ліҙлқјлҸ„
    - мӮҙм•„лӮҳлҠ” нҳ„мһ¬лҙү
    - м•„лһ«кј¬лҰ¬ нҡҢліө
    - л§үнҢҗ л°ҖлҰј
    - мң„кј¬лҰ¬ н„ёлҰј
    - мқҳлҜё м—ҶлҠ” мһ‘мқҖ мӣҖм§Ғмһ„
    мқ„ лҚ” м„ лӘ…н•ҳкІҢ лӮҳлҲ„кі , мҠ№кІ©/ліҙлҘҳ нҢҗлӢЁм—җлҠ” ліҙмЎ°к°’мңјлЎңл§Ң м—°кІ°н•ңлӢӨ.
    """
    ctx = {
        "current_candle_code": "UNKNOWN",
        "current_candle_label": "нҳ„мһ¬лҙү нҷ•мқёмӨ‘",
        "current_candle_warning": "",
        "current_candle_live_score": 0.0,
        "current_candle_reclaim_score": 0.0,
        "current_candle_pressure_score": 0.0,
        "current_candle_follow_score": 0.0,
        "current_candle_quality_grade": "нҷ•мқёмӨ‘",
        "current_candle_change_pct": 0.0,
        "current_candle_prev_change_pct": 0.0,
        "current_candle_body_ratio": 0.0,
        "current_candle_body_pct": 0.0,
        "current_candle_range_pct": 0.0,
        "current_candle_close_pos_ratio": 0.0,
        "current_candle_upper_wick_pct": 0.0,
        "current_candle_lower_wick_pct": 0.0,
        "current_candle_volume_ratio": 0.0,
        "current_candle_recent_close_strength": 0.0,
        "current_candle_recent_upper_wick_pct": 0.0,
        "current_candle_recent_lower_wick_pct": 0.0,
        "current_candle_recent_body_ratio": 0.0,
        "current_candle_bullish": False,
        "current_candle_upper_dump": False,
        "current_candle_lower_reclaim": False,
        "current_candle_live_ok": False,
        "current_candle_soft_pressure": False,
        "current_candle_hard_pressure": False,
        "current_candle_micro_noise": False,
    }
    try:
        if df1 is None or len(df1) < 4:
            return ctx
        row = df1.iloc[-1]
        op = safe_float(row.get("open", 0), 0)
        cl = safe_float(current_price, 0)
        if cl <= 0:
            cl = safe_float(row.get("close", 0), 0)
        hi = max(safe_float(row.get("high", 0), 0), cl)
        lo = safe_float(row.get("low", 0), 0)
        if lo <= 0:
            lo = min(op, cl) if min(op, cl) > 0 else 0.0
        vol = safe_float(row.get("volume", 0), 0)
        if op <= 0 or cl <= 0 or hi <= 0 or lo <= 0 or hi < lo:
            return ctx

        rng = max(hi - lo, 0.0)
        base_price = max(op, 1e-9)
        body = abs(cl - op)
        body_ratio = (body / rng) if rng > 0 else 0.0
        body_pct = (body / base_price) * 100.0
        range_pct = (rng / base_price) * 100.0 if base_price > 0 else 0.0
        close_pos = ((cl - lo) / rng) if rng > 0 else 0.0
        upper_base = max(op, cl)
        lower_base = min(op, cl)
        upper_wick_pct = ((hi - upper_base) / upper_base) * 100.0 if upper_base > 0 and hi > upper_base else 0.0
        lower_wick_pct = ((lower_base - lo) / lower_base) * 100.0 if lower_base > 0 and lo < lower_base else 0.0
        change_pct = ((cl - op) / op) * 100.0 if op > 0 else 0.0
        prev_close = safe_float(df1["close"].iloc[-2], 0) if len(df1) >= 2 else 0.0
        prev_change_pct = ((cl - prev_close) / prev_close) * 100.0 if prev_close > 0 else 0.0

        close3 = _avg_close_position_ratio(df1, 3)
        upper3 = _avg_upper_wick_pct(df1, 3)
        lower3 = _avg_lower_wick_pct(df1, 3)
        body3 = _avg_candle_body_ratio(df1, 3)
        bull_streak = _consecutive_bar_streak(df1, bullish=True, bars=4)
        bear_streak = _consecutive_bar_streak(df1, bullish=False, bars=4)
        strong_bulls = _strong_bullish_candle_count(df1, bars=4)

        vol_ratio = 0.0
        try:
            vols = df1["volume"].astype(float).fillna(0)
            prev_vol = safe_float(vols.iloc[:-1].tail(10).mean(), 0)
            if prev_vol > 0:
                vol_ratio = vol / prev_vol
        except Exception:
            vol_ratio = 0.0

        live_score = 0.0
        if cl >= op:
            live_score += 0.30
        if change_pct >= 0.18:
            live_score += 0.62
        elif change_pct >= 0.08:
            live_score += 0.45
        elif change_pct >= 0.02:
            live_score += 0.20
        if close_pos >= 0.78:
            live_score += 0.72
        elif close_pos >= CURRENT_CANDLE_CLOSE_STRONG_RATIO:
            live_score += 0.55
        elif close_pos >= 0.55:
            live_score += 0.25
        if body_ratio >= 0.52:
            live_score += 0.42
        elif body_ratio >= CURRENT_CANDLE_LIVE_BODY_RATIO_MIN:
            live_score += 0.32
        if upper_wick_pct <= 0.28:
            live_score += 0.33
        elif upper_wick_pct <= CURRENT_CANDLE_UPPER_WICK_WARN_PCT:
            live_score += 0.18
        if vol_ratio >= 1.0 + CURRENT_CANDLE_VOL_REACCEL_MIN:
            live_score += 0.35
        elif vol_ratio >= 0.85:
            live_score += 0.15
        if prev_change_pct >= 0:
            live_score += 0.12
        if close3 >= 0.60:
            live_score += 0.18
        if bull_streak >= 2 or strong_bulls >= 1:
            live_score += 0.16

        reclaim_score = 0.0
        if lower_wick_pct >= CURRENT_CANDLE_LOWER_WICK_RECLAIM_PCT:
            reclaim_score += 0.55
        if lower_wick_pct >= 0.28:
            reclaim_score += 0.25
        if lower_wick_pct >= upper_wick_pct and lower_wick_pct > 0:
            reclaim_score += 0.22
        if close_pos >= 0.58:
            reclaim_score += 0.45
        if change_pct >= -0.05:
            reclaim_score += 0.28
        if prev_change_pct >= -0.10:
            reclaim_score += 0.18
        if vol_ratio >= 0.95:
            reclaim_score += 0.18
        if lower3 >= 0.08 and close3 >= 0.50:
            reclaim_score += 0.18

        pressure_score = 0.0
        if upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_WARN_PCT:
            pressure_score += 0.55
        if upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_BLOCK_PCT:
            pressure_score += 0.40
        if close_pos <= CURRENT_CANDLE_CLOSE_WEAK_RATIO:
            pressure_score += 0.45
        if close_pos <= 0.28:
            pressure_score += 0.25
        if change_pct <= -0.12:
            pressure_score += 0.52
        elif change_pct <= -0.03:
            pressure_score += 0.34
        elif change_pct <= 0.03 and upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_WARN_PCT:
            pressure_score += 0.20
        if vol_ratio >= 1.0 + CURRENT_CANDLE_VOL_REACCEL_MIN and close_pos <= 0.55:
            pressure_score += 0.30
        if body_ratio <= 0.16 and upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_WARN_PCT:
            pressure_score += 0.20
        if upper3 >= 0.45 and close3 <= 0.50:
            pressure_score += 0.25
        if bear_streak >= 2:
            pressure_score += 0.20

        micro_noise = bool(
            range_pct <= CURRENT_CANDLE_V2_MICRO_NOISE_RANGE_PCT
            or (body_pct <= CURRENT_CANDLE_V2_MICRO_NOISE_BODY_PCT and range_pct <= 0.08)
        )
        hard_pressure = bool(
            pressure_score >= CURRENT_CANDLE_V2_HARD_PRESSURE_SCORE
            or (upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_BLOCK_PCT and close_pos <= CURRENT_CANDLE_CLOSE_WEAK_RATIO)
            or (change_pct <= -0.18 and close_pos <= 0.35)
        )
        soft_pressure = bool(
            hard_pressure
            or pressure_score >= CURRENT_CANDLE_V2_SOFT_PRESSURE_SCORE
            or (upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_WARN_PCT and close_pos <= 0.56)
            or (change_pct < 0 and close_pos <= CURRENT_CANDLE_CLOSE_WEAK_RATIO)
        )
        lower_reclaim = bool(
            reclaim_score >= CURRENT_CANDLE_V2_RECLAIM_WEAK_SCORE
            and not hard_pressure
            and lower_wick_pct >= CURRENT_CANDLE_LOWER_WICK_RECLAIM_PCT
        )
        strong_reclaim = bool(lower_reclaim and reclaim_score >= CURRENT_CANDLE_V2_RECLAIM_STRONG_SCORE and pressure_score < CURRENT_CANDLE_V2_SOFT_PRESSURE_SCORE)
        live_ok = bool(live_score >= CURRENT_CANDLE_V2_LIVE_WEAK_SCORE and not hard_pressure)
        strong_live = bool(live_score >= CURRENT_CANDLE_V2_LIVE_STRONG_SCORE and pressure_score < CURRENT_CANDLE_V2_SOFT_PRESSURE_SCORE)
        follow_score = (live_score * 0.55) + (reclaim_score * 0.35) - (pressure_score * 0.65)

        code = "CHECK"
        label = "нҳ„мһ¬лҙү м¶”к°Җ нҷ•мқё"
        warning = ""
        grade = "нҷ•мқёмӨ‘"
        if micro_noise:
            code = "MICRO_NOISE"
            label = "нҳ„мһ¬лҙү мқҳлҜё мһ‘мқҢ"
            grade = "м•Ҫн•Ё"
        elif hard_pressure and upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_WARN_PCT:
            code = "UPPER_WICK_DUMP_HARD"
            label = "мң„кј¬лҰ¬ к°•н•ҳкІҢ н„ёлҰј"
            warning = "мң„лЎң м°”л Җм§Җл§Ң мў…к°Җк°Җ л°Җл Өм„ң м¶”кІ©н•ҳл©ҙ лі„лЎң"
            grade = "мң„н—ҳ"
        elif hard_pressure:
            code = "CLOSING_WEAK_HARD"
            label = "л§үнҢҗ л°ҖлҰј к°•н•Ё"
            warning = "нҳ„мһ¬лҙү л§Ҳк°җ мң„м№ҳк°Җ лӮ®м•„ л°”лЎң л”°лқјл¶ҷкё° лі„лЎң"
            grade = "мң„н—ҳ"
        elif soft_pressure and upper_wick_pct >= CURRENT_CANDLE_UPPER_WICK_WARN_PCT:
            code = "UPPER_WICK_DUMP_SOFT"
            label = "мң„кј¬лҰ¬ л°ҖлҰј"
            warning = "мң„кј¬лҰ¬к°Җ мһҲм–ҙ м¶”кІ©мқҖ н•ң лІҲ лҚ” нҷ•мқё"
            grade = "мЈјмқҳ"
        elif soft_pressure:
            code = "CLOSING_WEAK_SOFT"
            label = "л§үнҢҗ л°ҖлҰј"
            warning = "л§Ҳк°җ мң„м№ҳк°Җ м•Ҫн•ҙм„ң л°”лЎң м¶”кІ©мқҖ мЈјмқҳ"
            grade = "мЈјмқҳ"
        elif strong_reclaim:
            code = "LOWER_RECLAIM_STRONG"
            label = "м•„лһ«кј¬лҰ¬ нҡҢліө к°•н•Ё"
            grade = "мўӢмқҢ"
        elif lower_reclaim:
            code = "LOWER_RECLAIM_WEAK"
            label = "м•„лһ«кј¬лҰ¬ нҡҢліө"
            grade = "ліҙнҶө"
        elif strong_live:
            code = "LIVE_UP_STRONG"
            label = "нҳ„мһ¬лҙү нҷ•мӢӨнһҲ мӮҙм•„лӮЁ"
            grade = "мўӢмқҢ"
        elif live_ok:
            code = "LIVE_UP_WEAK"
            label = "нҳ„мһ¬лҙү мӮҙм•„лӮЁ"
            grade = "ліҙнҶө"
        elif cl >= op and close_pos >= 0.55:
            code = "MILD_UP"
            label = "нҳ„мһ¬лҙү м•Ҫн•ҳкІҢ м–‘нҳё"
            grade = "ліҙнҶө"
        elif close_pos <= CURRENT_CANDLE_CLOSE_WEAK_RATIO and change_pct <= 0.02:
            code = "CLOSING_WEAK_SOFT"
            label = "л§үнҢҗ л°ҖлҰј"
            warning = "л§Ҳк°җ мң„м№ҳк°Җ лӮ®м•„м„ң л°”лЎң л”°лқјл¶ҷкё° м• л§Ө"
            grade = "мЈјмқҳ"

        ctx.update({
            "current_candle_code": code,
            "current_candle_label": label,
            "current_candle_warning": warning,
            "current_candle_live_score": round(live_score, 2),
            "current_candle_reclaim_score": round(reclaim_score, 2),
            "current_candle_pressure_score": round(pressure_score, 2),
            "current_candle_follow_score": round(follow_score, 2),
            "current_candle_quality_grade": grade,
            "current_candle_change_pct": round(change_pct, 3),
            "current_candle_prev_change_pct": round(prev_change_pct, 3),
            "current_candle_body_ratio": round(body_ratio, 4),
            "current_candle_body_pct": round(body_pct, 3),
            "current_candle_range_pct": round(range_pct, 3),
            "current_candle_close_pos_ratio": round(close_pos, 4),
            "current_candle_upper_wick_pct": round(upper_wick_pct, 3),
            "current_candle_lower_wick_pct": round(lower_wick_pct, 3),
            "current_candle_volume_ratio": round(vol_ratio, 2),
            "current_candle_recent_close_strength": round(close3, 4),
            "current_candle_recent_upper_wick_pct": round(upper3, 3),
            "current_candle_recent_lower_wick_pct": round(lower3, 3),
            "current_candle_recent_body_ratio": round(body3, 4),
            "current_candle_bullish": bool(cl >= op),
            "current_candle_upper_dump": bool(code.startswith("UPPER_WICK_DUMP")),
            "current_candle_lower_reclaim": bool(lower_reclaim),
            "current_candle_live_ok": bool(live_ok),
            "current_candle_soft_pressure": bool(soft_pressure),
            "current_candle_hard_pressure": bool(hard_pressure),
            "current_candle_micro_noise": bool(micro_noise),
        })
    except Exception:
        return ctx
    return ctx


def compute_alert_chart_context_from_df(df1, df4h=None, current_price: float = 0.0) -> dict:
    ctx = {
        "chart_state": "нқҗлҰ„ нҷ•мқё",
        "chart_state_code": "CHECK",
        "chart_warning": "",
        "recent_pullback_pct": 0.0,
        "recent_bars_since_high": 999,
        "recent_upper_wick_pct": 0.0,
        "is_fading_after_spike": False,
        "htf_trend": "мғҒмң„нқҗлҰ„ нҷ•мқёмӨ‘",
        "htf_trend_code": "UNKNOWN",
        "htf_gap_pct": 999.0,
        "htf_rise_pct": 0.0,
        "prebreakout_ready_score": 0.0,
        "prebreakout_label": "лҸҢнҢҢ м „ мӨҖл№„лҸ„ нҷ•мқёмӨ‘",
        "prebreakout_hold_near_high_bars": 0,
        "prebreakout_pullback_depth_pct": 0.0,
        "prebreakout_retest_gap_bars": 999,
        "prebreakout_volume_reaccel_score": 0.0,
        "chart_lifecycle_code": "UNKNOWN",
        "chart_lifecycle_label": "мң„м№ҳнҢҗлҸ… нҷ•мқёмӨ‘",
        "chart_lifecycle_warning": "",
        "chart_lifecycle_early_score": 0.0,
        "chart_lifecycle_restart_score": 0.0,
        "chart_lifecycle_late_score": 0.0,
        "chart_lifecycle_good_early": False,
        "chart_lifecycle_good_restart": False,
        "chart_lifecycle_late_flag": False,
        "chart_lifecycle_gap_pct": 999.0,
        "chart_lifecycle_from_low_pct": 0.0,
        "chart_lifecycle_zone_ratio": -1.0,
        "chart_lifecycle_bars_since_high": 999,
        "chart_lifecycle_bars_since_low": 999,
        "chart_lifecycle_close_strength_3": 0.0,
        "chart_lifecycle_wick_pressure_3": 0.0,
        "chart_lifecycle_vol_reaccel": 0.0,
        "chart_lifecycle_higher_low": False,
        "current_candle_code": "UNKNOWN",
        "current_candle_label": "нҳ„мһ¬лҙү нҷ•мқёмӨ‘",
        "current_candle_warning": "",
        "current_candle_live_score": 0.0,
        "current_candle_reclaim_score": 0.0,
        "current_candle_pressure_score": 0.0,
        "current_candle_follow_score": 0.0,
        "current_candle_quality_grade": "нҷ•мқёмӨ‘",
        "current_candle_change_pct": 0.0,
        "current_candle_prev_change_pct": 0.0,
        "current_candle_body_ratio": 0.0,
        "current_candle_body_pct": 0.0,
        "current_candle_range_pct": 0.0,
        "current_candle_close_pos_ratio": 0.0,
        "current_candle_upper_wick_pct": 0.0,
        "current_candle_lower_wick_pct": 0.0,
        "current_candle_volume_ratio": 0.0,
        "current_candle_recent_close_strength": 0.0,
        "current_candle_recent_upper_wick_pct": 0.0,
        "current_candle_recent_lower_wick_pct": 0.0,
        "current_candle_recent_body_ratio": 0.0,
        "current_candle_bullish": False,
        "current_candle_upper_dump": False,
        "current_candle_lower_reclaim": False,
        "current_candle_live_ok": False,
        "current_candle_soft_pressure": False,
        "current_candle_hard_pressure": False,
        "current_candle_micro_noise": False,
    }
    try:
        price = safe_float(current_price, 0)
        if df1 is not None and len(df1) >= 12:
            close_price = safe_float(df1["close"].iloc[-1], 0)
            if price <= 0:
                price = close_price
            recent = df1.tail(min(len(df1), max(12, int(ALERT_CHART_CONTEXT_WINDOW_1M))))
            recent_high = safe_float(recent["high"].max(), 0)
            recent_low = safe_float(recent["low"].min(), 0)
            vals = list(recent["high"].astype(float).values)
            idx_high = vals.index(max(vals)) if vals else 0
            bars_since_high = max(len(vals) - idx_high - 1, 0)
            pullback_pct = ((recent_high - price) / recent_high) * 100.0 if recent_high > 0 and price > 0 else 0.0
            rise_from_low = ((price - recent_low) / recent_low) * 100.0 if recent_low > 0 and price > 0 else 0.0
            snap = compute_pre_alert_snapshot_from_df(df1, current_price=price)
            chg5 = safe_float(snap.get("chg_5m", 0), 0)
            chg30 = safe_float(snap.get("chg_30m", 0), 0)
            below_high = safe_float(snap.get("below_30m_high_pct", 999), 999)
            upper_wick_pct = _last_upper_wick_pct(df1)
            lifecycle_ctx = compute_chart_lifecycle_context_from_df(df1, current_price=price)
            ctx.update(lifecycle_ctx)
            current_candle_ctx = compute_current_candle_context_from_df(df1, current_price=price)
            ctx.update(current_candle_ctx)
            lifecycle_code = str(lifecycle_ctx.get("chart_lifecycle_code", "") or "")
            current_candle_code = str(current_candle_ctx.get("current_candle_code", "") or "")
            current_pressure = safe_float(current_candle_ctx.get("current_candle_pressure_score", 0), 0)
            state = "нқҗлҰ„ нҷ•мқё"
            state_code = "CHECK"
            warning = ""
            fading = False
            if recent_high > 0 and pullback_pct >= ALERT_PULLBACK_LIVE_BLOCK_PCT and bars_since_high <= 8 and chg30 < 0.35:
                state = "кі м җ м°Қкі  л°ҖлҰј"
                state_code = "FADE_AFTER_SPIKE"
                warning = f"л°©кёҲ кі м җ м°Қкі  {pullback_pct:.2f}% л°ҖлҰ° мғҒнғң"
                fading = True
            elif upper_wick_pct >= ALERT_WOBBLE_UPPER_WICK_PCT and below_high <= 2.40 and max(chg5, chg30) > 0:
                state = "мң„м—җм„ң нқ”л“ӨлҰј"
                state_code = "HIGH_WOBBLE"
                warning = "мң„кј¬лҰ¬/нқ”л“ӨлҰјмқҙ ліҙм—¬м„ң м¶”кІ© мЈјмқҳ"
            elif chg5 >= 0.45 and chg30 >= 0.30 and rise_from_low <= 2.40 and below_high >= 1.20:
                state = "л§ү мӢңмһ‘"
                state_code = "STARTING"
            elif chg5 >= 0.10 and chg30 < 0.20 and rise_from_low <= 1.80 and below_high >= 1.40:
                state = "лҲҢлҰј л’Ө мһ¬м¶ңл°ң"
                state_code = "RESTARTING"
            elif rise_from_low >= 3.00 and below_high <= 1.20:
                state = "мқҙлҜё н•ң лІҲ мҸң мһҗлҰ¬"
                state_code = "EXTENDED"
                warning = "мқҙлҜё н•ң лІҲ к°•н•ҳкІҢ мӣҖм§Ғмқё л’Өлқј лҠҰмқ„ мҲҳ мһҲмқҢ"
            elif chg5 > 0 and chg30 >= 0:
                state = "л“ӨмҚ©мқҙлҠ” мӨ‘"
                state_code = "WAKING_UP"
            if lifecycle_code == "LATE_CHASE" and state_code not in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}:
                state = "лҠҰмқҖ м¶”кІ©к¶Ң"
                state_code = "LATE_CHASE"
                warning = lifecycle_ctx.get("chart_lifecycle_warning", "") or "м°ЁнҠё мң„м№ҳмғҒ м§ҖкёҲ л”°лқјл¶ҷкё° лі„лЎң"
            elif lifecycle_code == "RESTART_GOOD" and state_code in {"CHECK", "WAKING_UP", "RESTARTING"}:
                state = "лҲҢлҰј л’Ө мһ¬м¶ңл°ң"
                state_code = "RESTARTING"
            elif lifecycle_code == "EARLY_GOOD" and state_code in {"CHECK", "WAKING_UP"}:
                state = "л§ү мӢңмһ‘"
                state_code = "STARTING"
            current_hard_pressure = bool(current_candle_ctx.get("current_candle_hard_pressure", False))
            current_soft_pressure = bool(current_candle_ctx.get("current_candle_soft_pressure", False))
            current_lower_reclaim = bool(current_candle_ctx.get("current_candle_lower_reclaim", False))
            current_live_ok = bool(current_candle_ctx.get("current_candle_live_ok", False))
            if current_hard_pressure and state_code not in {"FADE_AFTER_SPIKE", "EXTENDED", "LATE_CHASE"}:
                state = "нҳ„мһ¬лҙү л°ҖлҰј"
                state_code = "CURRENT_CANDLE_WEAK"
                warning = current_candle_ctx.get("current_candle_warning", "") or "нҳ„мһ¬лҙү л§Ҳк°җ мң„м№ҳк°Җ м•Ҫн•ҙм„ң м¶”кІ© мЈјмқҳ"
            elif current_soft_pressure and state_code in {"CHECK", "WAKING_UP"}:
                state = "нҳ„мһ¬лҙү м•Ҫн•ң л°ҖлҰј"
                state_code = "CURRENT_CANDLE_SOFT_WEAK"
                warning = current_candle_ctx.get("current_candle_warning", "") or "нҳ„мһ¬лҙүмқҙ м•Ҫк°„ л°Җл Ө м¶”кІ©мқҖ н•ң лІҲ лҚ” нҷ•мқё"
            elif current_lower_reclaim and state_code in {"CHECK", "WAKING_UP", "RESTARTING"}:
                state = "м•„лһ«кј¬лҰ¬ нӣ„ нҡҢліө"
                state_code = "LOWER_RECLAIM"
            elif current_live_ok and state_code in {"CHECK", "WAKING_UP"}:
                state = "нҳ„мһ¬лҙү мӮҙм•„лӮЁ"
                state_code = "CURRENT_CANDLE_LIVE"
            ctx.update({
                "chart_state": state,
                "chart_state_code": state_code,
                "chart_warning": warning,
                "recent_pullback_pct": round(pullback_pct, 2),
                "recent_bars_since_high": int(bars_since_high),
                "recent_upper_wick_pct": round(upper_wick_pct, 2),
                "is_fading_after_spike": bool(fading),
            })
            prep_ctx = compute_breakout_ready_context_from_df(df1, current_price=price)
            ctx.update(prep_ctx)
            if (
                state_code in {"CHECK", "WAKING_UP", "RESTARTING"}
                and safe_float(prep_ctx.get("prebreakout_ready_score", 0), 0) >= 2.60
                and below_high >= 0.8
                and chg5 >= 0.15
                and safe_float(prep_ctx.get("prebreakout_volume_reaccel_score", 0), 0) >= 0.05
            ):
                ctx["chart_state"] = "кі м җ л°”лЎң м•„лһҳ мӨҖл№„лҗЁ"
                ctx["chart_state_code"] = "PRE_BREAK_READY"
        if df4h is not None and len(df4h) >= 12:
            price4 = price if price > 0 else safe_float(df4h["close"].iloc[-1], 0)
            ma7 = ma(df4h, 7)
            ma30 = ma(df4h, 30)
            recent = df4h.tail(min(len(df4h), max(12, int(ALERT_HTF_LOOKBACK))))
            htf_high = safe_float(recent["high"].max(), 0)
            htf_low = safe_float(recent["low"].min(), 0)
            htf_gap = ((htf_high - price4) / htf_high) * 100.0 if htf_high > 0 and price4 > 0 else 999.0
            htf_rise = ((price4 - htf_low) / htf_low) * 100.0 if htf_low > 0 and price4 > 0 else 0.0
            trend = "мғҒмң„нқҗлҰ„ нҷ•мқёмӨ‘"
            trend_code = "UNKNOWN"
            if price4 >= ma7 > 0 and ma7 >= max(ma30, 0):
                trend = "4мӢңк°„ мғҒмҠ№"
                trend_code = "UP"
            elif price4 >= max(ma30, 0) and ma7 >= max(ma30 * 0.985, 0):
                trend = "4мӢңк°„ нҡҢліө"
                trend_code = "RECOVER"
            elif price4 < ma7 and ma7 > max(ma30, 0):
                trend = "4мӢңк°„ кі м җ лҲҢлҰј"
                trend_code = "PULLBACK"
            elif price4 < ma7 and ma7 < max(ma30, 0):
                trend = "4мӢңк°„ м•Ҫн•Ё"
                trend_code = "WEAK"
            if htf_gap <= ALERT_HTF_STRONG_NEAR_HIGH_PCT and htf_rise >= 6.0 and trend_code in {"UP", "RECOVER"}:
                trend = "4мӢңк°„ мң„мӘҪ"
                trend_code = "NEAR_HIGH"
            ctx.update({
                "htf_trend": trend,
                "htf_trend_code": trend_code,
                "htf_gap_pct": round(htf_gap, 2),
                "htf_rise_pct": round(htf_rise, 2),
            })
    except Exception:
        return ctx
    return ctx

def compute_alert_chart_context(ticker: str, current_price: float = 0.0, df1=None, df4h=None) -> dict:
    try:
        df1 = df1 if df1 is not None else get_ohlcv(ticker, "minute1")
        df4h = df4h if df4h is not None else get_ohlcv(ticker, ALERT_HTF_INTERVAL)
        return compute_alert_chart_context_from_df(df1, df4h=df4h, current_price=current_price)
    except Exception:
        return compute_alert_chart_context_from_df(None, df4h=None, current_price=current_price)

def ensure_alert_chart_context(item: dict) -> dict:
    ctx = item.get("alert_chart_context") if isinstance(item, dict) else None
    if isinstance(ctx, dict):
        return ctx
    # v2.5.180: review_dump/review_trace/status к°ҷмқҖ м¶ңл Ҙ н•ЁмҲҳк°Җ мғҲ OHLCV мЎ°нҡҢлҘј л§Ңл“Өл©ҙ
    # мӮ¬мҡ©мһҗк°Җ лӘ…л №м–ҙлҘј ліј л•Ңл§ҲлӢӨ м •л°Җл¶„м„қ лі‘лӘ©мқҙ лӢӨмӢң мғқкёҙлӢӨ.
    # м¶ңл Ҙ лӢЁкі„м—җм„ңлҠ” м ҖмһҘлҗң к°’л§Ң м“°кі , м—Ҷмңјл©ҙ "нҷ•мқёмӨ‘" кё°ліёк°’мқ„ лҸҢл ӨмӨҖлӢӨ.
    current_price = safe_float((item or {}).get("current_price", (item or {}).get("price", 0)), 0) if isinstance(item, dict) else 0
    ctx = compute_alert_chart_context_from_df(None, df4h=None, current_price=current_price)
    try:
        ctx["chart_state"] = "м ҖмһҘлҗң м •л°Җ м°ЁнҠё м—ҶмқҢ"
        ctx["chart_state_code"] = "PENDING"
        ctx["chart_warning"] = "м¶ңл Ҙ мӨ‘ мғҲ OHLCV мЎ°нҡҢлҘј л§үм•„ лі‘лӘ© л°©м§Җ"
        ctx["precision_ohlcv_fetch_blocked"] = True
        if isinstance(item, dict):
            item["alert_chart_context"] = ctx
    except Exception:
        pass
    return ctx

def format_chart_context_line(item: dict) -> str:
    ctx = ensure_alert_chart_context(item)
    state = str(ctx.get("chart_state", "нқҗлҰ„ нҷ•мқё") or "нқҗлҰ„ нҷ•мқё")
    htf = str(ctx.get("htf_trend", "мғҒмң„нқҗлҰ„ нҷ•мқёмӨ‘") or "мғҒмң„нқҗлҰ„ нҷ•мқёмӨ‘")
    pullback = safe_float(ctx.get("recent_pullback_pct", 0), 0)
    warning = str(ctx.get("chart_warning", "") or "").strip()
    parts = [f"- м°ЁнҠё: {state}", f"мғҒмң„нқҗлҰ„ {htf}"]
    if pullback > 0.05:
        parts.append(f"м§Ғм „кі м җ л’Ө {pullback:.2f}% л°ҖлҰј")
    line = " / ".join(parts)
    if warning:
        line += f" / мЈјмқҳ: {warning}"
    return line

