    bits = [f"- мң„м№ҳнҢҗлҸ…: {label}", f"мҙҲмһ… {early:.2f}", f"мһ¬м¶ңл°ң {restart:.2f}", f"лҠҰмқҢмң„н—ҳ {late:.2f}"]
