def strategy_help_text(strategy_label: str) -> str:
    return STRATEGY_GUIDE.get(strategy_label, "м „лһө м„ӨлӘ… мӨҖл№„мӨ‘")
def build_info_text() -> str:
    lines = [
        "рҹ“ҳ мҡ©м–ҙ / м „лһө м„ӨлӘ…",
        "",
        "[м „лһө м„ӨлӘ…]",
    ]
    for name, desc in STRATEGY_GUIDE.items():
        lines.append(f"- {name}: {desc}")
    lines.append("")
    lines.append("[м•ҢлҰјм—җм„ң мһҗмЈј ліҙлҠ” л§җ]")
    for name, desc in TERM_GUIDE:
        lines.append(f"- {name}: {desc}")
    lines.append("")
    lines.append("[н•ҙм„қ нҢҒ]")
    lines.append("- мғҒмҠ№%к°Җ л„Ҳл¬ҙ нҒ° нӣ„ліҙлҠ” мқҙлҜё лҠҰмқҖ мһҗлҰ¬мқј мҲҳ мһҲм–ҙ")
    lines.append("- кұ°лһҳлҹүл§Ң м„ёлӢӨкі  л°”лЎң мӮ¬л©ҙ м•Ҳ лҗҳкі , к°ҖкІ© мң м§Җк№Ңм§Җ к°ҷмқҙ лҙҗм•ј н•ҙ")
    lines.append("- мһҗлҸҷл§ӨмҲҳлҠ” кәјл‘” мғҒнғңм—җм„ң м•ҢлҰј н’Ҳм§Ҳл¶Җн„° ліҙлҠ” кІҢ м•Ҳм „н•ҙ")
    lines.append("- /compare лЎң мөңк·ј м•ҢлҰјмқҙ мӢӨм ңлЎң м–ҙл• лҠ”м§ҖмҷҖ лҶ“м№ң мҪ”мқёмқ„ к°ҷмқҙ ліј мҲҳ мһҲм–ҙ")
    lines.append("- /fills лЎң мөңк·ј л§ӨмҲҳк°Җ м•ҢлҰјк°ҖліҙлӢӨ м–јл§ҲлӮҳ лҠҰм—ҲлҠ”м§Җ ліј мҲҳ мһҲм–ҙ")
    return "\n".join(lines)
def format_strategy_with_help(strategy_label: str) -> str:
    return f"{strategy_label} ({strategy_help_text(strategy_label)})"
def circled_number(n: int) -> str:
    nums = ["в‘ ", "в‘Ў", "в‘ў", "в‘Ј", "в‘Ө", "в‘Ҙ", "в‘Ұ", "в‘§", "в‘Ё", "в‘©"]
    if 1 <= n <= len(nums):
        return nums[n - 1]
    return f"{n}."

def bold_number_badge(n: int) -> str:
    return f"гҖҗ{circled_number(n)}гҖ‘"

def bold_ticker_text(ticker: str) -> str:
    t = str(ticker or "?").upper().strip() or "?"
    return f"гҖҠ{t}гҖӢ"

def highlight_line(order: int, ticker: str, icon: str = "") -> str:
    prefix = f"{bold_number_badge(order)} "
    if icon:
        prefix += f"{icon} "
    return f"{prefix}{bold_ticker_text(ticker)}"


def ticker_review_icon(item_or_row: dict = None) -> str:
    """review кі„м—ҙм—җм„ң мҪ”мқё мӨ„ м•һм—җ л¶ҷмқј лҲҲм—җ лқ„лҠ” н‘ңмӢң."""
    item_or_row = item_or_row if isinstance(item_or_row, dict) else {}
    try:
        # мҪ”мқё к°ҖкІ©мқҙ м•„лӢҲлқј 'мӢӨм ң кұ°лһҳлҢҖкёҲ'мқҙ кұ°мқҳ м—ҶлҠ” мһЎмқҢ нӣ„ліҙлҘј лЁјм Җ н‘ңмӢңн•ңлӢӨ.
        if is_fast_scan_tiny_turnover_noise(item_or_row):
            return "рҹ’Ө"
    except Exception:
        pass
    bucket = str(item_or_row.get("alert_bucket", item_or_row.get("bucket", "")) or "").lower()
    grade = str(item_or_row.get("alert_grade", item_or_row.get("grade", "")) or "").upper()
    primary = str(item_or_row.get("primary_reason", item_or_row.get("label_text", "")) or "")
    if bucket in {"user_alert", "м§ҖкёҲ ліј нӣ„ліҙ"} or grade in {"S", "A"}:
        return "рҹ”Ҙ"
    if bucket in {"internal_watch", "pre_entry"} or "к°җмӢң" in primary or "нҷ•мқё" in primary:
        return "рҹ‘Җ"
    if "кёүл“ұ" in primary or "нҸӯл°ң" in primary or "к°•м„ё" in primary:
        return "рҹҡҖ"
    if "мҙҲм Җк°Җ" in primary or "мһЎмқҢ" in primary:
        return "рҹ§Ҡ"
    if bucket == "discard":
        return "рҹҷҲ"
    return "рҹ“Ң"


def format_pct_or_pending(value, digits: int = 2, pending_text: str = "нҷ•мқё м•Ҳ лҗЁ", zero_text: str = None, negative_text: str = "кі м җ лҸҢнҢҢ/кі„мӮ° нҷ•мқё") -> str:
    """999.00%, мқҳлҜё м—ҶлҠ” 0.00%, мқҢмҲҳ кі м җкұ°лҰ¬ к°ҷмқҖ к°’мқ„ мӮ¬лһҢ л§җлЎң л°”кҝ” н‘ңмӢң."""
    v = safe_float(value, 999)
    if v >= 900:
        return pending_text
    if v < -0.000001:
        return negative_text
    if zero_text is not None and abs(v) <= 0.000001:
        return zero_text
    return f"{v:.{digits}f}%"


def format_money_or_tiny(value) -> str:
    """мӢӨм ң кұ°лһҳлҢҖкёҲ к°’л§Ң л°ӣм•ҳмқ„ л•Ңмқҳ ліҙмҲҳм Ғ н‘ңмӢң.

    0мӣҗмқҖ м§„м§ң л¬ҙкұ°лһҳмқј мҲҳлҸ„ мһҲм§Җл§Ң API/мҠӨлғ…мғ· кІҪлЎңм—җм„ңлҠ” лҜёнҷ•мқёмқј мҲҳлҸ„ мһҲлӢӨ.
    к·ёлһҳм„ң к°’л§Ң мһҲлҠ” мғҒнҷ©м—җм„ңлҠ” н•Ёл¶ҖлЎң 'кұ°лһҳ кұ°мқҳ м—ҶмқҢ'мңјлЎң лӢЁм •н•ҳм§Җ м•ҠлҠ”лӢӨ.
    """
    v = safe_float(value, 0)
    if v <= 0:
        return "кұ°лһҳлҢҖкёҲ лҜёнҷ•мқё"
    if v < 10000:
        return f"мӢӨкұ°лһҳлҢҖкёҲ кұ°мқҳ м—ҶмқҢ({v:,.0f}мӣҗ)"
    if v < 1_000_000:
        return f"мӢӨкұ°лһҳлҢҖкёҲ мһ‘мқҢ({v:,.0f}мӣҗ)"
    if v < 10_000_000:
        return f"мӢӨкұ°лһҳлҢҖкёҲ м–ҮмқҢ({v:,.0f}мӣҗ)"
    return f"лҸҲ л¶ҷмқҢ нҷ•мқё({v:,.0f}мӣҗ)"




def format_money_compact_amount_krw(value) -> str:
    """л§Ңмӣҗ лӢЁмң„ л°ҳмҳ¬лҰјмңјлЎң '0л§Ң'мқҙ лңЁм§Җ м•ҠкІҢ кёҲм•Ўмқ„ м§§кІҢ н‘ңмӢңн•ңлӢӨ."""
    v = safe_float(value, 0)
    if v <= 0:
        return "0мӣҗ"
    if v < 10_000:
        return f"{v:,.0f}мӣҗ"
    if v < 100_000:
        return f"{v/10000:.1f}л§Ң"
    if v < 10_000_000:
        return f"{v/10000:.0f}л§Ң"
    if v < 100_000_000:
        return f"{v/10000:.0f}л§Ң"
    return f"{v/100000000:.2f}м–ө"


def get_internal_watch_counts_for_summary() -> tuple:
    """мғҒлӢЁ мҡ”м•Ҫм—җм„ң лӮҙл¶Җк°җмӢң м§„н–ү/мҷ„лЈҢлҘј л”°лЎң ліҙм—¬мЈјкё° мң„н•ң м•Ҳм „ м№ҙмҡҙн„°."""
    try:
        active, logs = _get_internal_watch_state_parts()
        return len(active or {}), len(dedupe_internal_watch_logs(logs or []))
    except Exception:
        return 0, 0

def _row_snapshot_money_unknown(row: dict, key: str = "turnover_5m") -> bool:
    """нҳ„мһ¬к°Җ мҠӨлғ…мғ·мңјлЎң к°ҖкІ©л§Ң лЁјм Җ мһЎмқҖ мғҒнғңмқём§Җ нҢҗлӢЁн•ңлӢӨ.

    мқҙ кІҪмҡ° 0мӣҗмқҖ мӢӨм ң л¬ҙкұ°лһҳк°Җ м•„лӢҲлқј 'м•„м§Ғ кұ°лһҳлҢҖкёҲмқ„ нҷ•мқён•ҳм§Җ лӘ»н•Ё'м—җ к°Җк№қлӢӨ.
    """
    row = row if isinstance(row, dict) else {}
    try:
        v = max(
            safe_float(row.get(key, row.get("turnover", 0)), 0),
            safe_float(row.get("turnover", 0), 0),
            safe_float(row.get("turnover_1m", row.get("turnover_recent_1m", 0)), 0),
            safe_float(row.get("turnover_3m", row.get("turnover_recent_3m", 0)), 0),
            safe_float(row.get("turnover_15m", 0), 0),
        )
        if v > 0:
            return False
        src = " ".join([
            str(row.get("source", "") or ""),
            str(row.get("cache_source", "") or ""),
            str(row.get("candidate_source", "") or ""),
            str(row.get("precision_chart_source", "") or ""),
        ]).lower()
        return bool(
            row.get("turnover_unknown_snapshot", False)
            or row.get("snapshot_turnover_unknown", False)
            or row.get("realtime_rank_injected", False)
            or "snapshot" in src
            or "light_snapshot" in src
            or "realtime_snapshot" in src
        )
    except Exception:
        return False


def format_money_or_unknown(value, snapshot_based: bool = False) -> str:
    """кұ°лһҳлҢҖкёҲ 0/лҜёнҷ•мқё/мӢӨм ңмһ‘мқҢ/лҸҲл¶ҷмқҢ мғҒнғңлҘј кө¬л¶„н•ҙ н‘ңмӢңн•ңлӢӨ."""
    v = safe_float(value, 0)
    if v <= 0 and snapshot_based:
        return "кұ°лһҳлҢҖкёҲ нҷ•мқё м „"
    return format_money_or_tiny(v)


def _row_turnover_value(row: dict, key: str = "turnover_5m") -> float:
    row = row if isinstance(row, dict) else {}
    return max(
        safe_float(row.get(key, row.get("turnover", 0)), 0),
        safe_float(row.get("turnover", 0), 0),
        safe_float(row.get("turnover_recent_5m", 0), 0),
        safe_float(row.get("turnover_5m", 0), 0),
        safe_float(row.get("actual_turnover_5m", 0), 0),
        safe_float(row.get("verified_turnover_5m", 0), 0),
    )


def _row_snapshot_detected_age_sec(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    now_ts = time.time()
    candidates = [
        row.get("snapshot_rank_detected_ts", 0),
        row.get("turnover_verify_requested_ts", 0),
        row.get("cache_updated_at", 0),
        row.get("ts", 0),
        row.get("saved_at", 0),
    ]
    vals = [safe_float(x, 0) for x in candidates if safe_float(x, 0) > 0]
    if not vals:
        return 0.0
    return max(0.0, now_ts - max(vals))


def format_money_for_row(row: dict, key: str = "turnover_5m") -> str:
    row = apply_verified_turnover_to_row(row if isinstance(row, dict) else {})
    status = money_status_code_for_row(row, key=key)
    v = _row_turnover_value(row, key=key)
    if status == "checking":
        return "кұ°лһҳлҢҖкёҲ нҷ•мқё м „"
    if status == "delayed":
        return "кұ°лһҳлҢҖкёҲ нҷ•мқё м§Җм—°"
    if status in {"suspect", "volume_suspect"}:
        return "лҢҖкёҲк°’ мқҳмӢ¬/мһ¬нҷ•мқё"
    if status == "retry":
        return "лҢҖкёҲ мһ¬нҷ•мқё лҢҖкё°"
    if status == "verify_failed":
        return "кұ°лһҳлҢҖкёҲ мЎ°нҡҢ мӢӨнҢЁ"
    if status == "actual_zero":
        return "мӢӨм ң кұ°лһҳлҢҖкёҲ кұ°мқҳ м—ҶмқҢ(0мӣҗ нҷ•мқё)"
    if status == "unknown":
        return "кұ°лһҳлҢҖкёҲ лҜёнҷ•мқё"
    if status == "tiny":
        return f"мӢӨкұ°лһҳлҢҖкёҲ мһ‘мқҢ({v:,.0f}мӣҗ)"
    if status == "thin":
        return f"мӢӨкұ°лһҳлҢҖкёҲ м–ҮмқҢ({v:,.0f}мӣҗ)"
    return f"лҸҲ л¶ҷмқҢ нҷ•мқё({v:,.0f}мӣҗ)"


def format_money_compact_for_row(row: dict, key: str = "turnover_5m") -> str:
    row = apply_verified_turnover_to_row(row if isinstance(row, dict) else {})
    status = money_status_code_for_row(row, key=key)
    v = _row_turnover_value(row, key=key)
    if status == "checking":
        return "лҸҲ нҷ•мқём „"
    if status == "delayed":
        return "лҢҖкёҲнҷ•мқём§Җм—°"
    if status in {"suspect", "volume_suspect"}:
        return "лҢҖкёҲк°’мқҳмӢ¬"
    if status == "retry":
        return "лҢҖкёҲмһ¬нҷ•мқё"
    if status == "verify_failed":
        return "лҢҖкёҲмЎ°нҡҢмӢӨнҢЁ"
    if status == "actual_zero":
        return "мӢӨм ңлҸҲкұ°мқҳм—ҶмқҢ 0мӣҗ"
    if status == "unknown":
        return "лҸҲ лҜёнҷ•мқё"
    if status == "tiny":
        return f"мӢӨм ңлҸҲмһ‘мқҢ {format_money_compact_amount_krw(v)}"
    if status == "thin":
        return f"лҸҲм–ҮмқҢ {format_money_compact_amount_krw(v)}"
    return f"лҸҲнҷ•мқё {format_money_compact_amount_krw(v)}"


def money_status_code_for_row(row: dict, key: str = "turnover_5m") -> str:
    """м¶ңл Ҙ/н•„н„°м—җм„ң 'нҷ•мқё м „'кіј 'мӢӨм ң мһ‘мқҢ'мқ„ м„һм§Җ м•Ҡкё° мң„н•ң мғҒнғң мҪ”л“ң."""
    row = apply_verified_turnover_to_row(row if isinstance(row, dict) else {})
    v = _row_turnover_value(row, key=key)
    verified = bool(row.get("turnover_verified", row.get("actual_turnover_verified", False)))
    verify_status = str(row.get("turnover_verify_status", "") or "").lower().strip()
    if verified and v <= 0:
        return "actual_zero"
    if v > 0:
        if v < 1_000_000:
            return "tiny"
        if v < 10_000_000:
            return "thin"
        return "ok"
    if verify_status in {"suspect", "volume_suspect"}:
        return "suspect"
    if verify_status == "retry":
        return "delayed"
    if verify_status in {"failed", "timeout", "error"}:
        return "verify_failed"
    if v <= 0 and _row_snapshot_money_unknown(row, key=key):
        age = _row_snapshot_detected_age_sec(row)
        if age >= safe_float(globals().get("REALTIME_RANK_TURNOVER_VERIFY_DELAY_SEC", 150), 150):
            return "delayed"
        return "checking"
    return "unknown"


def is_money_unverified_for_row(row: dict) -> bool:
    return money_status_code_for_row(row) in {"checking", "delayed", "verify_failed", "unknown", "suspect"}


def money_block_reason_for_row(row: dict) -> str:
    row = apply_verified_turnover_to_row(row if isinstance(row, dict) else {})
    status = money_status_code_for_row(row)
    detail = str(row.get("turnover_verify_fail_detail", "") or "").strip()
    if not detail and status in {"delayed", "suspect", "verify_failed"}:
        detail = explain_ohlcv_failure_reason(str(row.get("ticker", "") or ""), "minute1", raw_reason=str(row.get("turnover_verify_reason", "") or ""))
    suffix = f" / мӣҗмқё: {detail}" if detail and status in {"delayed", "suspect", "verify_failed"} else ""
    if status == "checking":
        return "лҢҖкёҲ нҷ•мқё м „мқҙлқј м•„м§Ғ лҸҲ м—ҶмқҢмңјлЎң лӢЁм • кёҲм§Җ"
    if status == "delayed":
        return "лҢҖкёҲ нҷ•мқёмқҙ м§Җм—°лҗЁ. к°ҖкІ©мқҖ лҙӨм§Җл§Ң мӢӨм ң лҸҲмқҖ м•„м§Ғ лӘ» лҙ„" + suffix
    if status == "suspect":
        return "лҢҖкёҲк°’мқҙ л№„м •мғҒм ҒмңјлЎң мһ‘м•„ мһ¬нҷ•мқё н•„мҡ”" + suffix
    if status == "verify_failed":
        return "лҢҖкёҲ мЎ°нҡҢ мӢӨнҢЁ. м•ҢлҰј мҠ№кІ© м „ мһ¬нҷ•мқё н•„мҡ”" + suffix
    if status == "actual_zero":
        return "мӢӨм ң кұ°лһҳлҢҖкёҲмқҙ кұ°мқҳ м—Ҷм–ҙ мӢӨм „м„ұ лӮ®мқҢ"
    if status == "tiny":
        return "мӢӨм ң кұ°лһҳлҢҖкёҲмқҙ мһ‘м•„м„ң ліҙмҲҳм ҒмңјлЎң лҙ„"
    if status == "thin":
        return "лҸҲмқҖ л¶ҷм—Ҳм§Җл§Ң м–ҮмқҢ"
    if status == "ok":
        return "мӢӨм ң кұ°лһҳлҢҖкёҲ нҷ•мқёлҗЁ"
    return "лҢҖкёҲ лҜёнҷ•мқё"



def _row_strongest_rank_move(row: dict) -> float:
    row = row if isinstance(row, dict) else {}
    return max(
        safe_float(row.get("change_1", 0), 0),
        safe_float(row.get("change_3", 0), 0),
        safe_float(row.get("change_5", 0), 0),
        safe_float(row.get("change_15", 0), 0),
        safe_float(row.get("change_30", 0), 0),
        safe_float(row.get("change_60", 0), 0),
    )

def is_real_money_zero_or_tiny_for_row(row: dict) -> bool:
    """мӢӨм ң кұ°лһҳлҢҖкёҲмқҙ 0мӣҗ~к·№мҶҢм•ЎмңјлЎң нҷ•мқёлҗң нӣ„ліҙмқём§Җ л¶„лҰ¬н•ңлӢӨ.

    нҷ•мқё м „/мЎ°нҡҢ мӢӨнҢЁ/мһ¬нҷ•мқё лҢҖкё°лҠ” м—¬кё° нҸ¬н•Ён•ҳм§Җ м•ҠлҠ”лӢӨ.
    к·ёлһҳм•ј лҢҖкёҲмЎ°нҡҢмӢӨнҢЁлҘј 'лҸҲ м—ҶмқҢ'мңјлЎң мҳӨнҢҗн•ҳм§Җ м•ҠлҠ”лӢӨ.
    """
    return money_status_code_for_row(row if isinstance(row, dict) else {}) in {"actual_zero", "tiny"}

def is_money_weak_but_not_unknown_for_row(row: dict) -> bool:
    """мӢӨм ңлЎң м–Үкұ°лӮҳ мһ‘мқҖ лҸҲмңјлЎң нҷ•мқёлҗң нӣ„ліҙ. нҷ•мқё м „/мЎ°нҡҢ мӢӨнҢЁмҷҖ л¶„лҰ¬."""
    return money_status_code_for_row(row if isinstance(row, dict) else {}) in {"actual_zero", "tiny", "thin"}


def classify_money_sustain_for_row(row: dict) -> dict:
    """v2.5.239: кұ°лһҳлҢҖкёҲ мҙқм•Ўл§Ң ліҙм§Җ м•Ҡкі  лҸҲмқҙ мқҙм–ҙм§ҖлҠ”м§Җ/л°ҳм§қмқём§Җ л¶„лҰ¬н•ңлӢӨ.

    мғҲ API/OHLCV нҳём¶ң м—Ҷмқҙ мқҙлҜё м ҖмһҘлҗң row + WebSocket мІҙкІ° мәҗмӢңл§Ң мқҪлҠ”лӢӨ.
    л°ҳнҷҳк°’мқҖ лӮҙл¶Җк°җмӢң мҡ°м„ мҲңмң„мҷҖ м¶ңл Ҙ л¬ёкө¬м—җл§Ң м“°л©°, мӮ¬мҡ©мһҗ м•ҢлҰј кё°мӨҖмқ„ м „мІҙм ҒмңјлЎң мЎ°мқҙм§Җ м•ҠлҠ”лӢӨ.
    """
    try:
        if not bool(globals().get("MONEY_SUSTAIN_CLASSIFY_ON", True)):
            return {"label": "лҸҲнқҗлҰ„ лҜёмӮ¬мҡ©", "score": 0.0, "flash_risk": False, "watch_priority": "normal", "reason": "кәјм§җ"}
        row = apply_verified_turnover_to_row(dict(row) if isinstance(row, dict) else {})
        ticker = str(row.get("ticker", "") or "").upper().strip()
        status = money_status_code_for_row(row)
        ch1 = safe_float(row.get("change_1", 0), 0)
        ch3 = safe_float(row.get("change_3", 0), 0)
        ch5 = safe_float(row.get("change_5", 0), 0)
        ch15 = safe_float(row.get("change_15", 0), 0)
        ch30 = safe_float(row.get("change_30", 0), 0)
        strongest = max(ch1, ch3, ch5, ch15, ch30, safe_float(row.get("change_60", 0), 0))
        turn5 = _row_turnover_value(row, key="turnover_5m")
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        amount60 = safe_float(row.get("ws_trade_amount_60s", 0), 0)
        buy_ratio = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        trade_label = str(row.get("ws_trade_label_60s", "") or "")
        if cnt <= 0 and ticker and "get_ws_trade_summary_for_ticker" in globals():
            try:
                s60 = get_ws_trade_summary_for_ticker(ticker, 60)
                if isinstance(s60, dict) and int(safe_float(s60.get("count", 0), 0)) > 0:
                    cnt = int(safe_float(s60.get("count", 0), 0))
                    amount60 = safe_float(s60.get("amount", 0), 0)
                    buy_ratio = safe_float(s60.get("buy_ratio", 0), 0)
                    trade_label = str(s60.get("label", "") or trade_label)
            except Exception:
                pass
        candle_code = str(row.get("current_candle_code", "") or "")
        candle_pressure = safe_float(row.get("current_candle_pressure_score", 0), 0)
        current_chg = safe_float(row.get("current_candle_change_pct", 0), 0)
        hard_pressure = bool(row.get("current_candle_hard_pressure", False)) or candle_code in {"UPPER_WICK_DUMP_HARD", "CLOSING_WEAK_HARD"}
        soft_pressure = bool(row.get("current_candle_soft_pressure", False)) or candle_pressure >= 1.0 or candle_code in {"UPPER_WICK_DUMP_SOFT", "CLOSING_WEAK_SOFT", "UPPER_WICK_DUMP", "CLOSING_WEAK"}
        sell_pressure_core = (cnt >= 5 and buy_ratio > 0 and buy_ratio <= safe_float(globals().get("MONEY_SUSTAIN_SELL_PRESSURE_RATIO", 38.0), 38.0)) or trade_label == "л§ӨлҸ„мІҙкІ° мҡ°м„ё"
        sell_pressure_v246 = (cnt >= int(safe_float(globals().get("MONEY_SUSTAIN_V246_SELL_HEAVY_MIN_COUNT", 5), 5)) and buy_ratio > 0 and buy_ratio <= safe_float(globals().get("MONEY_SUSTAIN_V246_SELL_HEAVY_BUY_RATIO_MAX", 45.0), 45.0))
        sell_pressure = bool(sell_pressure_core or sell_pressure_v246)
        strong_trade = cnt >= int(safe_float(globals().get("MONEY_SUSTAIN_GOOD_TRADE_COUNT_60S", 5), 5)) and buy_ratio >= safe_float(globals().get("MONEY_SUSTAIN_GOOD_BUY_RATIO", 55.0), 55.0)
        strong_amount = amount60 >= safe_float(globals().get("MONEY_SUSTAIN_GOOD_TRADE_AMOUNT_60S", 1_000_000), 1_000_000)
        strong_turnover = turn5 >= safe_float(globals().get("MONEY_SUSTAIN_GOOD_TURNOVER_5M", 50_000_000), 50_000_000)
        large_turnover_sell_pressure = bool(strong_turnover and sell_pressure_v246 and turn5 >= safe_float(globals().get("MONEY_SUSTAIN_V246_LARGE_TURNOVER_SELL_PRESSURE_KRW", 50_000_000), 50_000_000))
        flash_drop = (
            (max(ch3, ch5, ch15, ch30) >= safe_float(globals().get("MONEY_SUSTAIN_FLASH_MIN_PREV_MOVE", 0.55), 0.55) and ch1 <= safe_float(globals().get("MONEY_SUSTAIN_FLASH_DROP_1M", -0.22), -0.22))
            or (max(ch5, ch15, ch30) >= safe_float(globals().get("MONEY_SUSTAIN_FLASH_MIN_PREV_MOVE", 0.55), 0.55) and ch3 <= safe_float(globals().get("MONEY_SUSTAIN_FLASH_DROP_3M", -0.10), -0.10))
            or (strongest >= 0.75 and current_chg < -0.05 and soft_pressure)
            or hard_pressure
        )
        flash_risk = bool(flash_drop or sell_pressure)
        score = 0.0
        if strong_turnover:
            score += 1.0
        if strong_trade:
            score += 1.0
        if strong_amount:
            score += 0.6
        if buy_ratio >= 70 and cnt >= 4:
            score += 0.4
        if flash_risk:
            score -= 1.2
        if 'large_turnover_sell_pressure' in locals() and large_turnover_sell_pressure:
            score -= 0.8
        if status in {"actual_zero", "tiny"}:
            score -= 0.8
        elif status == "thin":
            score -= 0.3
        if status in {"checking", "delayed", "verify_failed", "unknown", "suspect"}:
            score -= 0.4
        if flash_risk:
            if 'large_turnover_sell_pressure' in locals() and large_turnover_sell_pressure:
                label = "лҸҲмқҖ нҒ¬м§Җл§Ң л§ӨлҸ„мҡ°м„ё"
                prio = "low"
                reason = "кұ°лһҳлҢҖкёҲмқҖ нҒ¬м§Җл§Ң мөңк·ј мІҙкІ° л§ӨмҲҳл№„мңЁмқҙ лӮ®м•„ м¶”кІ© мң„н—ҳ"
            else:
                label = "л°ҳм§қ/мӢқлҠ”мӨ‘"
                prio = "low"
                reason = "к°ҖкІ©мқҖ мӣҖм§ҒмҳҖм§Җл§Ң л§ӨлҸ„мҡ°м„ё/нҳ„мһ¬лҙү л°ҖлҰј/лӢЁкё° н•ҳлқҪ мӢ нҳё"
        elif status in {"checking", "delayed", "verify_failed", "unknown", "suspect"}:
            label = "лҢҖкёҲнҷ•мқём „"
            prio = "watch" if strongest >= 1.2 or strong_trade else "low"
            reason = "к°ҖкІ©мқҖ лҙӨм§Җл§Ң мӢӨм ң лҸҲ нҷ•мқё м „"
        elif status in {"actual_zero", "tiny"}:
            label = "мӢӨм ңлҸҲмһ‘мқҢ"
            prio = "low"
            reason = "мӢӨм ң кұ°лһҳлҢҖкёҲмқҙ мһ‘мқҢ"
        elif status == "thin":
            if strong_trade or strong_amount or strongest >= 1.5:
                label = "лҸҲм–Үм§Җл§Ң к°•м„ё"
                prio = "watch"
                reason = "лҸҲмқҖ м–Үм§Җл§Ң мІҙкІ°/к°ҖкІ© нһҳмқҖ мһҲмқҢ"
            else:
                label = "лҸҲм–ҮмқҢ"
                prio = "low"
                reason = "лҸҲмқҙ м–Үм•„ мҡ°м„ мҲңмң„ лӮ®мқҢ"
        elif score >= 1.5:
            label = "лҸҲмң м§Җ к°•н•Ё"
            prio = "high"
            reason = "кұ°лһҳлҢҖкёҲкіј мөңк·ј мІҙкІ°мқҙ к°ҷмқҙ мң м§ҖлҗЁ"
        elif score >= 0.7 or strong_turnover:
            label = "лҸҲмң м§Җ нҷ•мқёмӨ‘"
            prio = "normal"
            reason = "кұ°лһҳлҢҖкёҲмқҖ нҷ•мқёлҗҗкі  м§ҖмҶҚм„ұ нҷ•мқё мӨ‘"
        else:
            label = "лҸҲ м•Ҫн•Ё нҷ•мқё"
            prio = "watch"
            reason = "кұ°лһҳлҢҖкёҲмқҖ мһҲмңјлӮҳ мөңк·ј мІҙкІ° м§ҖмҶҚм„ұмқҖ м•Ҫн•Ё"
        return {"label": label, "score": round(score, 3), "flash_risk": bool(flash_risk), "watch_priority": prio, "reason": reason, "trade_count": cnt, "trade_amount_60s": amount60, "buy_ratio": buy_ratio, "money_status": status}
    except Exception as e:
        return {"label": "лҸҲнқҗлҰ„ нҷ•мқёмӢӨнҢЁ", "score": 0.0, "flash_risk": False, "watch_priority": "normal", "reason": str(e)[:80]}


def apply_money_sustain_context(row: dict) -> dict:
    """v2.5.239: rank/watch rowм—җ лҸҲмң м§Җ/л°ҳм§қнҳ• лқјлІЁмқ„ л¶ҷмқёлӢӨ."""
    try:
        if not isinstance(row, dict):
            return row
        ctx = classify_money_sustain_for_row(row)
        row["money_sustain_label"] = str(ctx.get("label", "") or "")
        row["money_sustain_score"] = safe_float(ctx.get("score", 0), 0)
        row["money_flash_risk"] = bool(ctx.get("flash_risk", False))
        row["money_watch_priority"] = str(ctx.get("watch_priority", "normal") or "normal")
        row["money_sustain_reason"] = str(ctx.get("reason", "") or "")
        return row
    except Exception:
        return row




def is_current_candle_weak_for_label_v244(row: dict) -> bool:
    """v2.5.244: лҸҲнқҗлҰ„/нҳ„мһ¬лҙү л¬ёкө¬ м •н•©м„ұмҡ© м•Ҫм„ё нҳ„мһ¬лҙү нҢҗм •.

    мӮ¬мҡ©мһҗ м•ҢлҰј мЎ°кұҙмқ„ мЎ°мқҙлҠ” н•ЁмҲҳк°Җ м•„лӢҲлқј rank/watch н‘ңмӢңмҷҖ лӮҙл¶Җк°җмӢң мғҒнғңл¬ёкө¬к°Җ
    м°ЁнҠё мҲҳм№ҳмҷҖ м–ҙкёӢлӮҳм§Җ м•ҠкІҢ л§һм¶”лҠ” ліҙмЎ° н•ЁмҲҳлӢӨ.
    """
    try:
        row = row if isinstance(row, dict) else {}
        code = str(row.get("current_candle_code", "") or "")
        pressure = safe_float(row.get("current_candle_pressure_score", 0), 0)
        chg = safe_float(row.get("current_candle_change_pct", 0), 0)
        upper = safe_float(row.get("current_candle_upper_wick_pct", 0), 0)
        follow = safe_float(row.get("current_candle_follow_score", 0), 0)
        if bool(row.get("current_candle_hard_pressure", False)):
            return True
        if code in {"UPPER_WICK_DUMP_HARD", "CLOSING_WEAK_HARD", "UPPER_WICK_DUMP", "CLOSING_WEAK", "LATE_DUMP", "UPPER_WICK_DUMP_SOFT", "CLOSING_WEAK_SOFT"}:
            return True
        if pressure >= safe_float(globals().get("LOW_STRUCTURE_V244_CURRENT_PRESSURE_BLOCK", 1.25), 1.25):
            return True
        if upper >= 0.65 and chg <= 0.05:
            return True
        if follow <= -0.20 and pressure >= 0.85:
            return True
        return False
    except Exception:
        return False


def is_money_or_candle_flash_watch_limited_v244(row: dict) -> bool:
    """v2.5.244: л°ҳм§қ/мӢқлҠ”мӨ‘ + нҳ„мһ¬лҙү м•Ҫнҷ” нӣ„ліҙлҘј мҙҲмһ… к°•м„ёмІҳлҹј ліҙмқҙм§Җ м•ҠкІҢ л¶„лҰ¬."""
    try:
        row = row if isinstance(row, dict) else {}
        sustain = classify_money_sustain_for_row(row)
        label = str(row.get("money_sustain_label", "") or sustain.get("label", "") or "")
        flash = bool(row.get("money_flash_risk", False)) or bool(sustain.get("flash_risk", False)) or ("л°ҳм§қ" in label or "мӢқлҠ”" in label or "л§ӨлҸ„мҡ°м„ё" in label)
        buy = safe_float(row.get("ws_trade_buy_ratio_60s", 0), 0)
        cnt = int(safe_float(row.get("ws_trade_count_60s", 0), 0))
        sell_heavy_max = safe_float(globals().get("MONEY_SUSTAIN_V246_SELL_HEAVY_BUY_RATIO_MAX", 45.0), 45.0)
        if flash and (is_current_candle_weak_for_label_v244(row) or (cnt >= 5 and 0 < buy <= sell_heavy_max)):
            return True
        return False
    except Exception:
        return False


def get_low_structure_route_label_v244(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        route = str(row.get("low_structure_route_v244", "") or "").strip()
        if route and route != "м Җм җ кө¬мЎ° нҷ•мқёмӨ‘":
            return route
        score = max(
            safe_float(row.get("low_defense_v2_score", 0), 0),
            safe_float(row.get("low_structure_score_v2", 0), 0),
            safe_float(row.get("low_zone_defense_score", 0), 0),
        )
        rising = safe_float(row.get("low_rising_score_v2", 0), 0)
        reclaim = int(safe_float(row.get("low_recent_reclaim_bars_v244", row.get("low_zone_reclaim_count", 0)), 0))
        from_low = safe_float(row.get("from_low", row.get("from_30m_low_pct", row.get("low_from_ref_pct_v2", 0))), 0)
        if bool(row.get("low_dead_stay_flag_v2", False)):
            return "мЈҪмқҖ м Җм җ мЈјмқҳ"
        if bool(row.get("low_break_weak_reclaim_flag_v2", False)):
            return "м•Ҫн•ң нҡҢліө мЈјмқҳ"
        if score >= safe_float(globals().get("LOW_STRUCTURE_V244_RESTART_SCORE_MIN", 1.45), 1.45) and rising >= safe_float(globals().get("LOW_STRUCTURE_V244_RISING_SCORE_MIN", 0.70), 0.70) and from_low <= safe_float(globals().get("LOW_STRUCTURE_V244_MAX_FROM_LOW_FOR_RESTART", 3.20), 3.20):
            return "м Җм җлҶ’мһ„ мһ¬м¶ңл°ңнҳ•"
        if score >= 1.20 and reclaim >= 2 and from_low <= 3.60:
            return "м Җм җл°©м–ҙ мһ¬м¶ңл°ңнҳ•"
        if score >= 0.80:
            return "м Җм җл°©м–ҙ кҙҖм°°нҳ•"
        return ""
    except Exception:
        return ""


def apply_watch_display_consistency_v244(row: dict) -> dict:
    """v2.5.244: лҸҲнқҗлҰ„/нҳ„мһ¬лҙү/м Җм җл°©м–ҙ лқјлІЁмқҙ м„ңлЎң м¶©лҸҢн•ҳм§Җ м•ҠкІҢ м¶ңл Ҙмҡ© н•„л“ңлҘј м •лҰ¬."""
    try:
        if not isinstance(row, dict):
            return row
        row = apply_money_sustain_context(row)
        row = apply_precision_minute1_state_to_row(row) if 'apply_precision_minute1_state_to_row' in globals() else row
        row = apply_low_defense_quality_v248(row) if 'apply_low_defense_quality_v248' in globals() else row
        row = apply_high_rebreakout_hold_v248(row) if 'apply_high_rebreakout_hold_v248' in globals() else row
        low_route = get_low_structure_route_label_v244(row)
        low_unverified = is_low_structure_unverified_v245(row) if 'is_low_structure_unverified_v245' in globals() else False
        if low_unverified:
            row["low_structure_verify_status"] = "unverified"
            row.setdefault("rank_watch_low_route", "м Җм җл°©м–ҙ нҢҗлӢЁліҙлҘҳ")
        flash_limited = is_money_or_candle_flash_watch_limited_v244(row)
        weak_candle = is_current_candle_weak_for_label_v244(row)
        if flash_limited:
            row["rank_watch_action"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["primary_reason"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["label_text"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["chart_lifecycle_label"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["rank_watch_chart_state"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["one_liner"] = "лҸҲнқҗлҰ„/нҳ„мһ¬лҙүмқҙ мӢқлҠ” мӘҪмқҙлқј мҙҲмһ… к°•м„ёк°Җ м•„лӢҲлқј л°ҳм§қнҳ•мңјлЎң лӮ®м¶° кҙҖм°°"
        elif weak_candle:
            row["rank_watch_action"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["primary_reason"] = "мң„кј¬лҰ¬/нҳ„мһ¬лҙү л°ҖлҰј кҙҖм°°"
            row["label_text"] = "л°ҳм§қнҳ• кҙҖм°°"
            row["chart_lifecycle_label"] = "мң„кј¬лҰ¬/нҳ„мһ¬лҙү л°ҖлҰј"
            row["rank_watch_chart_state"] = "мң„кј¬лҰ¬/нҳ„мһ¬лҙү л°ҖлҰј"
        elif low_route in {"м Җм җлҶ’мһ„ мһ¬м¶ңл°ңнҳ•", "м Җм җл°©м–ҙ мһ¬м¶ңл°ңнҳ•", "м Җм җл°©м–ҙ кҙҖм°°нҳ•"}:
            qlabel = str(row.get("low_defense_final_label_v248", "") or low_route)
            qok = bool(row.get("low_defense_promote_ok_v248", True))
            row["rank_watch_low_route"] = qlabel
            if not qok:
                row["low_defense_quality_blocked_v248"] = True
                row["rank_watch_action"] = "ліөкё°мҡ© кё°лЎқ"
                row["primary_reason"] = "м Җм җл°©м–ҙ кө¬мЎ°л§Ң нҷ•мқё"
                row["label_text"] = "м Җм җл°©м–ҙ кө¬мЎ°л§Ң нҷ•мқё"
                row["chart_lifecycle_label"] = "м Җм җл°©м–ҙ кө¬мЎ° мһҲмқҢ/мҠ№кІ©кёҲм§Җ"
                row["rank_watch_chart_state"] = "м Җм җл°©м–ҙ кө¬мЎ° мһҲмқҢ/мҠ№кІ©кёҲм§Җ"
                row["one_liner"] = str(row.get("low_defense_quality_short_v248", "м Җм җл°©м–ҙ кө¬мЎ°лҠ” мһҲм§Җл§Ң лҸҲ/нҳ„мһ¬лҙү н’Ҳм§Ҳ л•Ңл¬ём—җ мҠ№кІ© кёҲм§Җ"))
            elif low_route != "м Җм җл°©м–ҙ кҙҖм°°нҳ•":
                row["primary_reason"] = low_route
                row["label_text"] = low_route
                row["chart_lifecycle_label"] = low_route
                row["rank_watch_chart_state"] = low_route
                row.setdefault("one_liner", "м Җм җл°©м–ҙ/м Җм җлҶ’мһ„мқҙ мӮҙм•„ мһҲм–ҙ мһ¬м¶ңл°ң м—¬л¶ҖлҘј лӮҙл¶Җк°җмӢңлЎң нҷ•мқё")
        hlabel = str(row.get("high_rebreakout_v248_label", "") or "")
        if hlabel and hlabel in {"кі м җ м•һ л°ҖлҰј/м¶”кІ©кёҲм§Җ", "кі м җ мһ¬лҸҢнҢҢ мң м§Җ нҷ•мқё", "кі м җ мһ¬м ‘к·ј кҙҖм°°"}:
            row.setdefault("high_rebreakout_hint", hlabel)
        row = apply_final_candidate_display_context_v251(row) if 'apply_final_candidate_display_context_v251' in globals() else row
        return row
    except Exception:
        return row

def format_money_sustain_compact(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        label = str(row.get("money_sustain_label", "") or "").strip()
        if not label:
            label = str(classify_money_sustain_for_row(row).get("label", "") or "").strip()
        return label or "лҸҲнқҗлҰ„ нҷ•мқёмӨ‘"
    except Exception:
        return "лҸҲнқҗлҰ„ нҷ•мқёмӨ‘"


def _active_internal_watch_money_counts(active: dict = None) -> dict:
    try:
        if active is None:
            active, _ = _get_internal_watch_state_parts()
        rows = [x for x in (active or {}).values() if isinstance(x, dict)]
    except Exception:
        rows = []
    counts = {"zero": 0, "tiny": 0, "thin": 0, "weak": 0, "unknown": 0, "ok": 0}
    for row in rows:
        first = row.get("first_snapshot") if isinstance(row.get("first_snapshot"), dict) else row
        code = money_status_code_for_row(first)
        if code == "actual_zero":
            counts["zero"] += 1
            counts["weak"] += 1
        elif code == "tiny":
            counts["tiny"] += 1
            counts["weak"] += 1
        elif code == "thin":
            counts["thin"] += 1
            counts["weak"] += 1
        elif code in {"checking", "delayed", "verify_failed", "unknown", "suspect"}:
            counts["unknown"] += 1
        else:
            counts["ok"] += 1
    return counts

def should_allow_internal_watch_by_money(item: dict, active: dict = None) -> tuple:
    """мҲңмң„к¶Ң нӣ„ліҙлҘј лӮҙл¶Җк°җмӢңм—җ л„Јм–ҙлҸ„ лҗҳлҠ”м§Җ кұ°лһҳлҢҖкёҲ мғҒнғңлЎң 1м°Ё м ңн•ңн•ңлӢӨ.

    лӘ©м Ғ:
    - мӢӨкұ°лһҳлҢҖкёҲ 0л§Ң/к·№мҶҢм•Ў нӣ„ліҙк°Җ /work_checkлҘј лҸ„л°°н•ҳм§Җ м•ҠкІҢ м ңн•ң
    - лҢҖкёҲмЎ°нҡҢмӢӨнҢЁ/нҷ•мқём „мқҖ лҸҲ м—ҶмқҢмңјлЎң лӢЁм •н•ҳм§Җ м•Ҡкі  мһ¬нҷ•мқё лҢҖкё°лЎң л‘ 
    - м§„м§ң к°•н•ң лҸҲм–ҮмқҢ нӣ„ліҙл§Ң мҶҢмҲҳ лӮҙл¶Җк°җмӢңм—җ лӮЁк№Җ
    """
    item = item if isinstance(item, dict) else {}
    code = money_status_code_for_row(item)
    strongest = _row_strongest_rank_move(item)
    score = safe_float(item.get("snapshot_rank_score", item.get("lite_score", 0)), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    sustain_ctx = classify_money_sustain_for_row(item)
    if bool(sustain_ctx.get("flash_risk", False)) and bool(globals().get("MONEY_SUSTAIN_INTERNAL_WATCH_BLOCK_FLASH", True)):
        if strongest < 1.80 and score < 7.00:
            return False, "л°ҳм§қнҳ•/мӢқлҠ”мӨ‘ нӣ„ліҙлҠ” ліөкё°л§Ң лӮЁк№Җ"
    if str(sustain_ctx.get("watch_priority", "")) == "low" and bool(globals().get("MONEY_SUSTAIN_INTERNAL_WATCH_BLOCK_THIN_WEAK", True)):
        if code in {"actual_zero", "tiny", "thin"} and strongest < 1.50 and score < 6.50:
            return False, f"{sustain_ctx.get('label','лҸҲ м•Ҫн•Ё')} нӣ„ліҙлҠ” ліөкё°л§Ң лӮЁк№Җ"
    counts = _active_internal_watch_money_counts(active)
    zero_limit = int(safe_float(globals().get("INTERNAL_WATCH_ZERO_MONEY_MAX_ACTIVE", 0), 0))
    weak_limit = int(safe_float(globals().get("INTERNAL_WATCH_WEAK_MONEY_MAX_ACTIVE", 3), 3))
    weak_strong = safe_float(globals().get("INTERNAL_WATCH_WEAK_MONEY_MIN_STRONGEST", 2.2), 2.2)
    weak_score = safe_float(globals().get("INTERNAL_WATCH_WEAK_MONEY_MIN_SCORE", 7.5), 7.5)
    if code == "actual_zero":
        if counts.get("zero", 0) >= max(0, zero_limit):
            return False, "мӢӨкұ°лһҳлҢҖкёҲ 0мӣҗ нӣ„ліҙлҠ” лӮҙл¶Җк°җмӢң кё°лЎқ м ңн•ң"
        return True, "мӢӨкұ°лһҳлҢҖкёҲ 0мӣҗ мҳҲмҷё к°җмӢң"
    if code == "tiny":
        if strongest < weak_strong and score < weak_score and leader < 2.0:
            return False, "мӢӨкұ°лһҳлҢҖкёҲ к·№мҶҢм•Ў нӣ„ліҙлҠ” ліөкё°л§Ң лӮЁк№Җ"
        if counts.get("weak", 0) >= max(1, weak_limit):
            return False, "лҸҲ м•Ҫн•ң лӮҙл¶Җк°җмӢңк°Җ л§Һм•„ ліөкё°л§Ң лӮЁк№Җ"
        return True, "лҸҲ м•Ҫн•ҳм§Җл§Ң к°•м„ёк°Җ м»Өм„ң м ңн•ң к°җмӢң"
    if code == "thin":
        if counts.get("weak", 0) >= max(1, weak_limit) and strongest < weak_strong and score < weak_score:
            return False, "лҸҲ м–ҮмқҖ нӣ„ліҙк°Җ л§Һм•„ ліөкё°л§Ң лӮЁк№Җ"
        return True, "лҸҲ м–ҮмқҢ м ңн•ң к°җмӢң"
    if code in {"verify_failed", "delayed", "checking", "unknown", "suspect"}:
        # лҸҲ м—ҶмқҢмңјлЎң лӢЁм •н•ҳм§Җ м•ҠлҠ”лӢӨ. лӢӨл§Ң нҷ•мқём „ нӣ„ліҙк°Җ лӮҙл¶Җк°җмӢңлҘј лӢӨ мһЎм•„лЁ№м§Җ м•ҠкІҢ м ңн•ңн•ңлӢӨ.
        unknown_limit = int(safe_float(globals().get("INTERNAL_WATCH_UNVERIFIED_MAX_ACTIVE", 6), 6))
        if strongest < 0.90 and score < 2.50:
            return False, "лҢҖкёҲ нҷ•мқё м „ м•Ҫн•ң нӣ„ліҙлқј ліөкё°л§Ң лӮЁк№Җ"
        if counts.get("unknown", 0) >= max(1, unknown_limit) and strongest < 1.80 and score < 5.00 and leader < 1.20:
            return False, "лҢҖкёҲ нҷ•мқём „ лӮҙл¶Җк°җмӢңк°Җ л§Һм•„ ліөкё°л§Ң лӮЁк№Җ"
        return True, "лҢҖкёҲ мһ¬нҷ•мқё лҢҖкё°"
    return True, "кұ°лһҳлҢҖкёҲ нҷ•мқёлҗЁ"

def summarize_hidden_review_watch_rows(rows: list) -> str:
    rows = [r for r in (rows or []) if isinstance(r, dict)]
    if not rows:
        return ""
    money_weak = 0
    retry = 0
    fading = 0
    strong = 0
    etc = 0
    for row in rows:
        first = row.get("first_snapshot") if isinstance(row.get("first_snapshot"), dict) else row
        code = money_status_code_for_row(first)
        now_up = safe_float(row.get("last_up_pct", 0), 0)
        min_down = safe_float(row.get("min_down_pct", 0), 0)
        max_up = safe_float(row.get("max_up_pct", 0), 0)
        if code in {"actual_zero", "tiny", "thin"}:
            money_weak += 1
        elif code in {"verify_failed", "delayed", "checking", "unknown", "suspect"}:
            retry += 1
        elif now_up <= -0.70 or min_down <= -1.00:
            fading += 1
        elif max_up >= 1.20 and now_up >= 0.45:
            strong += 1
        else:
            etc += 1
    parts = []
    if money_weak:
        parts.append(f"лҸҲм•Ҫн•Ё {money_weak}")
    if retry:
        parts.append(f"лҢҖкёҲнҷ•мқё/мһ¬нҷ•мқё {retry}")
    if fading:
        parts.append(f"мӢқлҠ”мӨ‘ {fading}")
    if strong:
        parts.append(f"мўӢмқҖн‘ңліё {strong}")
    if etc:
        parts.append(f"кё°нғҖ {etc}")
    return f"- мҲЁк№Җ мҡ”м•Ҫ: {len(rows)}к°ң мҲЁк№Җ / " + " / ".join(parts) if parts else f"- мҲЁк№Җ мҡ”м•Ҫ: {len(rows)}к°ң"

def summarize_hidden_rank_rows(rows: list) -> str:
    rows = [r for r in (rows or []) if isinstance(r, dict)]
    if not rows:
        return ""
    precision = 0
    record = 0
    money_weak = 0
    retry = 0
    late = 0
    for row in rows:
        code = money_status_code_for_row(row)
        if realtime_rank_watch_action_label(row) == "м •л°ҖкІҖнҶ  лҢҖкё°":
            precision += 1
        else:
            record += 1
        if code in {"actual_zero", "tiny", "thin"}:
            money_weak += 1
        elif code in {"verify_failed", "delayed", "checking", "unknown", "suspect"}:
            retry += 1
        try:
            if str(classify_rank_watch_chart_state(row).get("label", "")) == "мң„м—җм„ң мӢқлҠ” мӨ‘":
                late += 1
        except Exception:
            pass
    parts = [f"м •л°ҖкІҖнҶ  {precision}", f"ліөкё° {record}"]
    if money_weak:
        parts.append(f"лҸҲм•Ҫн•Ё {money_weak}")
    if retry:
        parts.append(f"лҢҖкёҲнҷ•мқё/мһ¬нҷ•мқё {retry}")
    if late:
        parts.append(f"мӢқлҠ”мӨ‘ {late}")
    return f"- мҲЁк№Җ мҡ”м•Ҫ: {len(rows)}к°ң мҲЁк№Җ / " + " / ".join(parts)

def get_fast_item_effective_turnover(item: dict) -> float:
    """мҪ”мқё к°ҖкІ©мқҙ м•„лӢҲлқј мӢӨм ң кұ°лһҳлҢҖкёҲ кё°мӨҖ. лӘҮл°ұ мӣҗм§ңлҰ¬ 'мҪ”мқё к°ҖкІ©'мқ„ л§үм§Җ м•ҠлҠ”лӢӨ."""
    item = item if isinstance(item, dict) else {}
    return max(
        safe_float(item.get("turnover_1m", 0), 0),
        safe_float(item.get("turnover_3m", 0), 0),
        safe_float(item.get("turnover_5m", 0), 0),
        safe_float(item.get("turnover_15m", item.get("turnover", 0)), 0),
        safe_float(item.get("turnover", 0), 0),
    )

def is_fast_scan_tiny_turnover_noise(item: dict) -> bool:
    """кұ°лһҳлҢҖкёҲ лӘҮл°ұ~лӘҮмІң мӣҗм§ңлҰ¬ н‘ңмӢң мһЎмқҢл§Ң мҲЁкёҙлӢӨ. мҪ”мқё к°ҖкІ© кё°мӨҖ м°ЁлӢЁмқҙ м•„лӢҲлӢӨ."""
    item = item if isinstance(item, dict) else {}
    if str(item.get("alert_bucket", "") or "") == "user_alert":
        return False
    if money_status_code_for_row(item) in {"checking", "unknown", "delayed", "verify_failed"}:
        # нҷ•мқё м „/лҜёнҷ•мқё/м§Җм—°/мЎ°нҡҢмӢӨнҢЁмқё лҸҲ мғҒнғңлҘј 'кұ°лһҳ кұ°мқҳ м—ҶмқҢ' мһЎмқҢмңјлЎң мҲЁкё°м§Җ м•ҠлҠ”лӢӨ.
        return False
    turnover = get_fast_item_effective_turnover(item)
    if turnover >= FAST_SCAN_DISPLAY_TINY_TURNOVER_HIDE:
        return False
    # нҒ° мӣҖм§Ғмһ„мқёлҚ° лҸҲмқҙ кұ°мқҳ м—Ҷмңјл©ҙ кё°ліё лӘ©лЎқм—җлҠ” мҲЁкё°лҗҳ, мғҒм„ё/мӣҗліём—җлҠ” лӮЁкёҙлӢӨ.
    chg_fast = max(
        abs(safe_float(item.get("change_1", 0), 0)),
        abs(safe_float(item.get("change_3", 0), 0)),
        abs(safe_float(item.get("change_5", 0), 0)),
        abs(safe_float(item.get("change_15", 0), 0)),
        abs(safe_float(item.get("change_30", 0), 0)),
    )
    return bool(turnover < FAST_SCAN_DISPLAY_TINY_TURNOVER_HIDE and chg_fast < 3.5)

def is_review_trace_tiny_noise(row: dict) -> bool:
    """кё°ліё лҰ¬л·°/м—ӯм¶”м Ғ лӘ©м°Ём—җм„ң мҲЁкёё кұ°лһҳлҢҖкёҲ мһЎмқҢмқём§Җ нҢҗлӢЁн•ңлӢӨ.

    мҪ”мқё к°ҖкІ©мқҙ лӮ®лӢӨлҠ” лң»мқҙ м•„лӢҲлқј, мөңк·ј мӢӨм ң кұ°лһҳлҢҖкёҲмқҙ л„Ҳл¬ҙ мһ‘м•„м„ң
    мӢӨм „ л¶„м„қмҡ© кё°ліё лӘ©лЎқмқ„ м–ҙм§ҖлҹҪнһҲлҠ” н‘ңліёл§Ң мҲЁкёҙлӢӨ.
    мғҒм„ё мЎ°нҡҢмҷҖ мӣҗліё нҺҳмқҙм§Җм—җлҠ” кё°лЎқмқ„ лӮЁкёҙлӢӨ.
    """
    row = row if isinstance(row, dict) else {}
    try:
        bucket = str(row.get("alert_bucket", row.get("bucket", "")) or "").lower()
        if bucket in {"user_alert", "м§ҖкёҲ ліј нӣ„ліҙ"}:
            return False
        return bool(is_fast_scan_tiny_turnover_noise(row))
    except Exception:
        return False


def is_fast_scan_factory_keep_candidate(item: dict) -> bool:
    """л№ лҘё мҠӨмә” кіөмһҘлқјмқё 1м°Ё ліҙмЎҙ кё°мӨҖ. л„Ҳл¬ҙ м•Ҫн•ң мһЎмқҢл§Ң л№јкі , кёүк°ҖмҶҚмқҖ мӮҙлҰ°лӢӨ."""
    item = item if isinstance(item, dict) else {}
    turnover = get_fast_item_effective_turnover(item)
    chg_fast = max(
        safe_float(item.get("change_1", 0), 0),
        safe_float(item.get("change_3", 0), 0),
        safe_float(item.get("change_5", 0), 0),
        safe_float(item.get("change_15", 0), 0),
        safe_float(item.get("change_30", 0), 0),
    )
    leader = safe_float(item.get("leader_score", 0), 0)
    vol = safe_float(item.get("vol_ratio", item.get("vol_ratio_1m", 0)), 0)
    if turnover >= FAST_SCAN_FACTORY_MIN_KEEP_TURNOVER:
        return True
    if chg_fast >= 2.0 or leader >= 1.8 or vol >= 8.0:
        return True
    return False

def _record_fast_scan_budget_event(tag: str, message: str, extra: dict = None):
    """м •мғҒм Ғмқё л¶„н• мІҳлҰ¬к№Ңм§Җ лі‘лӘ© лЎңк·ёлҘј лҸ„л°°н•ҳм§Җ м•ҠкІҢ мӨ„мқёлӢӨ."""
    try:
        now_ts = time.time()
        key = str(tag or "fast_scan_budget")
        last = safe_float(FAST_SCAN_PARTIAL_LOG_STATE.get(key, 0), 0) if isinstance(FAST_SCAN_PARTIAL_LOG_STATE, dict) else 0
        if now_ts - last >= FAST_SCAN_PARTIAL_LOG_COOLDOWN_SEC:
            FAST_SCAN_PARTIAL_LOG_STATE[key] = now_ts
            append_runtime_event_log(key, message, extra=extra or {})
    except Exception:
        pass

def get_watch_item_icon(item: dict, alert_type: str = "new") -> str:
    if alert_type == "upgrade":
        return "в¬ҶпёҸ"
    if alert_type == "renotice":
        return "рҹ”Ғ"
    strategy_label = item.get("strategy_label", "")
    change_pct = safe_float(item.get("change_pct", 0))
    if strategy_label == "мҳҲл№„ нӣ„ліҙ к°җмӢң":
        return "рҹ§ӯ"
    if strategy_label == "мӢ м Җк°Җ л°ҳл“ұ к°җмӢң":
        return "рҹӘ«"
    if change_pct >= 12.0:
        return "вҡ пёҸ"
    if strategy_label in ["мғҒмҠ№ мӢңмһ‘нҳ•", "мҙҲл°ҳ м„ м җнҳ•"]:
        return "рҹҢұ"
    if strategy_label in ["м¶”м„ё м§ҖмҶҚнҳ•", "кёүл“ұ лҸҢнҢҢнҳ•"]:
        return "рҹ“Ҳ"
    return "рҹ‘Җ"
def get_watch_caution_text(item: dict) -> str:
    change_pct = safe_float(item.get("change_pct", 0))
    vol_ratio = safe_float(item.get("vol_ratio", 0))
    strategy_label = item.get("strategy_label", "")
    high_gap_pct = get_reference_high_gap_pct(item)
    snap = ensure_pre_alert_snapshot(item)
    if strategy_label == "мҳҲл№„ нӣ„ліҙ к°җмӢң":
        return "м§ҖкёҲ мӮ¬л©ҙ м•Ҳ лҗЁ. лЁјм Җ нқҗлҰ„л§Ң нҷ•мқё"
    if strategy_label == "мӢ м Җк°Җ л°ҳл“ұ к°җмӢң":
        return "м§ҖкёҲ л§ӨмҲҳ кёҲм§Җ. м Җк°Җ лӢӨмӢң к№Ём§Җл©ҙ л°”лЎң лІ„лҰҙ нӣ„ліҙ"
    if is_chart_position_extended(item):
        return "мқҙлҜё мң„мӘҪ мһҗлҰ¬лқј м§ҖкёҲ м¶”кІ©мқҖ лі„лЎң"
    if 0 <= high_gap_pct <= 0.70:
        return "м§ҖкёҲ л“Өм–ҙк°Җл©ҙ лҠҰмқҢ"
    if change_pct >= 18.0:
        return "мқҙлҜё л§Һмқҙ мҳ¬лһҗмқҢ. м§ҖкёҲ м¶”кІ© кёҲм§Җ"
    if change_pct >= 12.0:
        return "мқҙлҜё кҪӨ мҳӨлҘё мһҗлҰ¬лқј м§ҖкёҲ мӮ¬кё° лі„лЎң"
    if strategy_label == "лҲҢлҰј л°ҳл“ұнҳ•" and change_pct >= 7.0:
        return "мқҙлҜё н•ң лІҲ мҳӨлҘё л’Ө мһ¬мӢңлҸ„лқј м§ҖкёҲ мӮ¬кё° лі„лЎң"
    if change_pct >= 10.0 and vol_ratio < 2.4:
        return "мҳ¬лқјк°„ кІғ к°ҷм•„лҸ„ нһҳмқҙ м•Ҫн•Ё"
    if safe_float(snap.get("from_30m_low_pct", 0)) >= 4.5 and safe_float(snap.get("below_30m_high_pct", 0)) <= 1.0:
        return "мқҙлҜё н•ң лІҲ нҠ„ мһҗлҰ¬лқј м¶”кІ© кёҲм§Җ"
    return ""
def get_watch_judgement_text(item: dict) -> str:
    strategy_label = item.get("strategy_label", "")
    change_pct = safe_float(item.get("change_pct", 0))
    vol_ratio = safe_float(item.get("vol_ratio", 0))
    caution = get_watch_caution_text(item)
    snap = ensure_pre_alert_snapshot(item)
    if strategy_label == "мҳҲл№„ нӣ„ліҙ к°җмӢң":
        return "рҹ‘Җ м§ҖкёҲ мӮ¬л©ҙ м•Ҳ лҗЁ"
    if strategy_label == "мӢ м Җк°Җ л°ҳл“ұ к°җмӢң":
        return "рҹ‘Җ м§ҖкёҲмқҖ кө¬кІҪл§Ң"
    if caution:
        if "лҠҰ" in caution or "м¶”кІ©" in caution:
            return "вӣ” мқҙлҜё лҠҰмқҢ"
        if "кі м җ" in caution:
            return "вӣ” кі м җмқҙ л„Ҳл¬ҙ к°Җк№ҢмӣҖ"
        if "нһҳмқҙ м•Ҫ" in caution or "мң м§Җ" in caution:
            return "вҡ пёҸ нһҳмқҙ м•„м§Ғ м•Ҫн•Ё"
        return "вӣ” м§ҖкёҲ мӮ¬кё° лі„лЎң"
    if is_recovery_profile_promising(item):
        return "рҹ‘Җ нҡҢліө мҙҲмһ…нҳ•, лӢӨмӢң л¶ҷлҠ”м§Җ ліј мһҗлҰ¬"
    if strategy_label in ["мғҒмҠ№ мӢңмһ‘нҳ•", "мҙҲл°ҳ м„ м җнҳ•"]:
        if change_pct <= 2.2 and vol_ratio >= 2.4 and safe_float(snap.get("from_30m_low_pct", 0)) <= 3.8:
            return "вң… м§ҖкёҲл§Ң мһ к№җ ліј л§Ңн•Ё"
        return "рҹ‘Җ мҙҲл°ҳмІҳлҹј ліҙм—¬лҸ„ м•„м§Ғ нһҳ л¶ҖмЎұ"
    if strategy_label == "лҲҢлҰј л°ҳл“ұнҳ•":
        return "рҹ‘Җ лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқёл¶Җн„°"
    if strategy_label in ["м¶”м„ё м§ҖмҶҚнҳ•", "кёүл“ұ лҸҢнҢҢнҳ•"]:
        return "вҡ пёҸ нһҳмқҖ мһҲлҠ”лҚ° м§ҖкёҲ м¶”кІ©мқҖ лі„лЎң"
    return "рҹ‘Җ м§ҖкёҲмқҖ кө¬кІҪл§Ң"
def get_watch_one_line_text(item: dict, caution: str, reason_text: str) -> str:
    section_key = str(item.get("section_key", "") or get_watch_display_group(item)).strip()
    recovery_like = is_recovery_profile_promising(item)
    high_gap_pct = get_effective_high_gap_pct(item)
    late_caution = is_late_conclusion_text(caution)
    if recovery_like and section_key in {"watch", "recovery", "internal_watch"} and not late_caution and high_gap_pct >= 1.00:
        return "нҡҢліө мҙҲмһ…нҳ•мқҙлқј лӢӨмӢң л¶ҷлҠ”м§Җ ліј мһҗлҰ¬"
    for candidate in [caution, reason_text]:
        candidate = (candidate or "").strip()
        if not candidate:
            continue
        if section_key in {"watch", "recovery", "internal_watch"} and "м§ҖкёҲ мӮ¬кё°м—” лі„лЎң" in candidate and high_gap_pct >= 1.00 and not late_caution:
            return "м§ҖкёҲ л°”лЎң мӮ¬лҠ” мһҗлҰ° м•„лӢҲм§Җл§Ң нқҗлҰ„мқҖ лҚ” ліј нӣ„ліҙ"
        return candidate
    strategy_label = item.get("strategy_label", "")
    if recovery_like:
        return "нҡҢліө мҙҲмһ…нҳ•мқҙлқј лӢӨмӢң л¶ҷлҠ”м§Җ ліј мһҗлҰ¬"
    if strategy_label == "мҳҲл№„ нӣ„ліҙ к°җмӢң":
        return "мЎ°кёҲ лҚ” ліҙл©ҙ лҗЁ"
    if strategy_label == "мӢ м Җк°Җ л°ҳл“ұ к°җмӢң":
        return "л°ҳл“ұ нҷ•мқё м „мқҙлқј м§ҖкёҲ л§ӨмҲҳлҠ” кёҲм§Җ"
    if strategy_label in ["мғҒмҠ№ мӢңмһ‘нҳ•", "мҙҲл°ҳ м„ м җнҳ•"]:
        return "мҙҲмһ… нӣ„ліҙм§Җл§Ң м•„м§Ғ м• л§Ө"
    if strategy_label == "лҲҢлҰј л°ҳл“ұнҳ•":
        return "нҡҢліөнҳ•мқёлҚ° м•„м§Ғ нһҳ л¶ҖмЎұ"
    return "м§ҖкёҲмқҖ нқҗлҰ„л§Ң нҷ•мқё"
def should_use_compact_watch_alert(item: dict, judgement: str, caution: str) -> bool:
    return get_watch_alert_detail_level(item, judgement, caution) == "compact"
def get_watch_alert_detail_level(item: dict, judgement: str = "", caution: str = "") -> str:
    strategy_label = item.get("strategy_label", "")
    strategy = item.get("strategy", "")
    trade_tier = str(item.get("trade_tier", "B") or "B").upper().strip()
    judgement = judgement or get_watch_judgement_text(item)
    caution = caution or get_watch_caution_text(item)
    if strategy_label in ["мҳҲл№„ нӣ„ліҙ к°җмӢң", "мӢ м Җк°Җ л°ҳл“ұ к°җмӢң"]:
        return "compact"
    weak_keywords = ["кө¬кІҪл§Ң", "нһҳ л¶ҖмЎұ", "мӮ¬л©ҙ м•Ҳ лҗЁ", "м¶”кІ©мқҖ лі„лЎң", "м§ҖкёҲ мӮ¬кё° лі„лЎң", "лӢӨмӢң нҷ•мқёл¶Җн„°"]
    if caution or any(word in judgement for word in weak_keywords):
        return "compact"
    if trade_tier in ["S", "A"] or strategy in ["EARLY", "PRE_BREAKOUT", "TREND_CONT", "BREAKOUT"]:
        return "strong"
    return "normal"
def get_watch_display_conclusion(item: dict, judgement: str = "", caution: str = "", section_override: str = "") -> str:
    strategy_label = item.get("strategy_label", "")
    strategy = str(item.get("strategy", "") or "").strip()
    judgement = judgement or get_watch_judgement_text(item)
    caution = caution or get_watch_caution_text(item)
    if caution:
        if ("лҠҰмқҢ" in caution or "м¶”кІ©" in caution or "мӮ¬кё° лі„лЎң" in caution) and not (is_recovery_profile_promising(item) and get_effective_high_gap_pct(item) >= 1.00):
            conclusion = "м§ҖкёҲ мӮ¬кё° лі„лЎң"
        elif "нһҳмқҙ м•Ҫ" in caution or ("мӮ¬кё° лі„лЎң" in caution and is_recovery_profile_promising(item)):
            conclusion = "нһҳмқҖ л¶ҷлҠ”м§Җ лҚ” нҷ•мқё н•„мҡ”"
        else:
            conclusion = caution
    elif strategy_label == "мӢ м Җк°Җ л°ҳл“ұ к°җмӢң":
        conclusion = "лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқё лЁјм Җ"
    elif is_recovery_profile_promising(item):
        conclusion = "лӢӨмӢң л¶ҷлҠ”м§Җ нҷ•мқё лЁјм Җ"
    elif strategy_label == "мҳҲл№„ нӣ„ліҙ к°җмӢң":
        conclusion = "м§ҖкёҲмқҖ кө¬кІҪл§Ң"
    elif "ліј л§Ңн•Ё" in judgement:
        conclusion = "м§ҖкёҲ ліјл§Ңн•Ё"
    elif strategy_label == "лҲҢлҰј л°ҳл“ұнҳ•":
        conclusion = "лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқё лЁјм Җ"
    elif strategy_label in ["м¶”м„ё м§ҖмҶҚнҳ•", "кёүл“ұ лҸҢнҢҢнҳ•"]:
        conclusion = "нһҳмқҖ мһҲлҠ”лҚ° м¶”кІ© кёҲм§Җ"
    elif strategy_label in ["мғҒмҠ№ мӢңмһ‘нҳ•", "мҙҲл°ҳ м„ м җнҳ•"]:
        conclusion = "мЎ°кёҲ лҚ” нҷ•мқё н•„мҡ”"
    else:
        conclusion = "м§ҖкёҲмқҖ кө¬кІҪл§Ң"
    floor = get_conclusion_section_floor(conclusion)
    target = str(section_override or "").strip()
    if target == "entry" and floor in {"watch", "recovery", "late"}:
        if strategy in {"EARLY", "PRE_BREAKOUT", "PREPUMP", "LEADER_WATCH"}:
            return "м§ҖкёҲ ліјл§Ңн•Ё"
        return "м§ҖкёҲмқҖ нқҗлҰ„л§Ң нҷ•мқё"
    if target == "recovery" and floor in {"watch", "late"}:
        return "лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқё лЁјм Җ"
    if target == "watch" and floor == "late":
        return "м§ҖкёҲмқҖ кө¬кІҪл§Ң"
    return conclusion
def is_late_conclusion_text(text: str) -> bool:
    text = str(text or "")
    late_keywords = ["лҠҰ", "м¶”кІ©", "мӮ¬кё° лі„лЎң", "л§ӨмҲҳ кёҲм§Җ"]
    return any(word in text for word in late_keywords)
def get_conclusion_section_floor(conclusion: str) -> str:
    conclusion = str(conclusion or "").strip()
    if not conclusion:
        return ""
    if "л§ӨмҲҳ кёҲм§Җ" in conclusion:
        return "watch"
    if any(word in conclusion for word in ["м§ҖкёҲ мӮ¬кё° лі„лЎң", "лҠҰ", "м¶”кІ© кёҲм§Җ"]):
        return "late"
    if any(word in conclusion for word in ["лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқё", "мЎ°кёҲ лҚ” нҷ•мқё", "нһҳмқҙ м•Ҫн•ҙм„ң лҚ” нҷ•мқё"]):
        return "recovery"
    if "кө¬кІҪл§Ң" in conclusion:
        return "watch"
    if any(word in conclusion for word in ["м§ҖкёҲ ліјл§Ңн•Ё", "м§ҖкёҲл§Ң мһ к№җ ліј л§Ңн•Ё", "м§ҖкёҲ м§„мһ… к°ҖлҠҘ"]):
        return "entry"
    return ""
def is_watch_excluded_ticker(ticker: str) -> bool:
    return str(ticker or "").upper().strip() in WATCH_EXCLUDED_TICKERS

def get_goal_shape_metrics(item: dict) -> dict:
    """мҡ°лҰ¬ лӘ©н‘ң(мҙҲл°ҳ м„ м җ/мһ¬м¶ңл°ң/мӢӨмӢңк°„ к°•м„ё мҙҲмһ…/лҠҰмқҖ мһҗлҰ¬ м°ЁлӢЁ)мҡ© ліҙмЎ° мҲҳм№ҳ."""
    item = item if isinstance(item, dict) else {}
    snap = ensure_pre_alert_snapshot(item)
    ctx = ensure_alert_chart_context(item)
    return {
        "chg_5": safe_float(snap.get("chg_5m", item.get("change_5", item.get("change_pct", 0))), 0),
        "chg_30": safe_float(snap.get("chg_30m", item.get("change_30", 0)), 0),
        "from_low": safe_float(snap.get("from_30m_low_pct", item.get("from_low", item.get("from_30m_low_pct", 0))), 0),
        "high_gap": get_reference_high_gap_pct(item),
        "vol_ratio": safe_float(item.get("vol_ratio", item.get("vol_ratio_1m", 0)), 0),
        "leader": safe_float(item.get("leader_score", 0), 0),
        "turnover_5m": safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0),
        "low_defense": safe_float(item.get("low_zone_defense_score", item.get("recovery_quality_score", 0)), 0),
        "turnover_keep": safe_float(item.get("turnover_persistence_score", 0), 0),
        "rebreakout": safe_float(item.get("rebreakout_display_score", item.get("rebreakout_score", 0)), 0),
        "hold_score": safe_float(item.get("breakout_hold_score", 0), 0),
        "hold_bars_05": int(safe_float(item.get("hold_near_high_bars_05", 0), 0)),
        "hold_bars_10": int(safe_float(item.get("hold_near_high_bars_10", 0), 0)),
        "prep_score": safe_float(item.get("prebreakout_ready_score", 0), 0),
        "prep_pullback": safe_float(item.get("prebreakout_pullback_depth_pct", 0), 0),
        "prep_reaccel": safe_float(item.get("prebreakout_volume_reaccel_score", 0), 0),
        "upper1": safe_float(item.get("upper_wick_pct_1", item.get("recent_upper_wick_pct", 0)), 0),
        "upper3": safe_float(item.get("upper_wick_pct_3", 0), 0),
        "bearish_streak": int(safe_float(item.get("bearish_streak_5", 0), 0)),
        "quant_label": str(item.get("chart_quant_label", "") or ""),
        "state_code": str(ctx.get("chart_state_code", "") or ""),
        "chart_warning": str(ctx.get("chart_warning", "") or ""),
    }


def is_recovery_rescue_watch_candidate(item: dict) -> bool:
    """THETAнҳ•: 30л¶„мқҖ м•Ҫн•ҳм§Җл§Ң м Җм җм—җм„ң мӮҙм•„лӮҳкі  лҸҲ/кҙҖмӢ¬мқҙ л¶ҷмқҖ мһ¬м¶ңл°ң лҢҖкё° нӣ„ліҙ."""
    m = get_goal_shape_metrics(item)
    if m["chg_30"] > -0.35:
        return False
    if not (0.25 <= m["from_low"] <= 1.65):
        return False
    if not (1.60 <= m["high_gap"] <= 5.40):
        return False
    if m["chg_5"] < -0.65:
        return False
    interest_ok = (m["vol_ratio"] >= 2.20 or m["leader"] >= 2.00 or m["turnover_keep"] >= 2.10 or m["turnover_5m"] >= 8_000_000)
    return bool(interest_ok)


def is_rebreakout_wait_watch_candidate(item: dict) -> bool:
    """CVCнҳ•: кі м җмқҖ к°Җк№қм§Җл§Ң м Җм җл°©м–ҙ/лҸҲмң м§Җ/мһ¬лҸ„м „мқҙ мўӢм•„ мһ¬лҸҢнҢҢ нҷ•мқёмқ„ кё°лӢӨлҰҙ нӣ„ліҙ."""
    m = get_goal_shape_metrics(item)
    if not (0.10 <= m["high_gap"] <= 0.75):
        return False
    if m["from_low"] >= 3.20:
        return False
    structure_ok = (m["low_defense"] >= 1.80 and m["turnover_keep"] >= 1.80 and m["rebreakout"] >= 3.20)
    stay_ok = (m["hold_bars_05"] >= 1 or m["hold_bars_10"] >= 1 or m["hold_score"] >= 1.0)
    flow_ok = (m["vol_ratio"] >= 2.20 or m["leader"] >= 2.00 or m["turnover_5m"] >= 3_000_000)
    return bool(structure_ok and stay_ok and flow_ok)


def is_high_zone_wobble_block_candidate(item: dict) -> bool:
    """ENJнҳ•: мқҙлҜё н•ң лІҲ нҒ¬кІҢ нҠ„ л’Ө кі м җк¶Ңм—җм„ң нқ”л“ңлҠ” лҠҰмқҖ нӣ„ліҙ."""
    m = get_goal_shape_metrics(item)
    if m["state_code"] in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}:
        return True
    extended_or_shaken = (
        (m["from_low"] >= 1.70 and m["high_gap"] <= 3.30 and m["prep_pullback"] >= 3.00)
        or (m["from_low"] >= 2.40 and m["upper3"] >= 0.25 and m["high_gap"] <= 3.20)
        or (m["bearish_streak"] >= 2 and m["high_gap"] <= 3.20 and m["from_low"] >= 1.20)
    )
    weak_follow_through = (m["turnover_keep"] <= 0.50 or m["low_defense"] <= 0.50 or m["chg_5"] <= 0.15)
    return bool(extended_or_shaken and weak_follow_through)


def is_hot_rank_early_probe_shape(row_or_item: dict) -> bool:
    """AWEнҳ•: кёүл“ұ/мӢңмһҘмҲңмң„м—җлҠ” мһЎнҳ”м§Җл§Ң ліём„  нӣ„ліҙлЎң л№ м§Ҳ мҲҳ мһҲлҠ” мҙҲл°ҳ нғҗмғү ліҙк°•."""
    r = row_or_item if isinstance(row_or_item, dict) else {}
    chg1_rank = int(safe_float(r.get("change_1_rank", r.get("change1_rank", 0)), 0) or 0)
    chg5_rank = int(safe_float(r.get("change_5_rank", r.get("change5_rank", 0)), 0) or 0)
    turnover_rank = int(safe_float(r.get("turnover_rank", r.get("turnover_rank_pulse", 0)), 0) or 0)
    surge_rank = int(safe_float(r.get("surge_rank", r.get("leader_rank", 0)), 0) or 0)
    chg5 = safe_float(r.get("chg_5m", r.get("change_5", r.get("change_pct", 0))), 0)
    chg30 = safe_float(r.get("chg_30m", r.get("change_30", 0)), 0)
    from_low = safe_float(r.get("from_30m_low_pct", r.get("from_low", 0)), 0)
    high_gap = safe_float(r.get("below_30m_high_pct", r.get("below_high", r.get("high_gap_pct", 999))), 999)
    hot_rank = ((0 < chg1_rank <= 8) or (0 < chg5_rank <= 15) or (0 < turnover_rank <= 30) or (0 < surge_rank <= 35))
    if not hot_rank:
        return False
    if not (-2.20 <= chg30 <= 0.80):
        return False
    if not (-0.25 <= chg5 <= 0.90):
        return False
    if not (0.00 <= from_low <= 1.25):
        return False
    if not (1.20 <= high_gap <= 4.80):
        return False
    return True

def has_meaningful_watch_motion(item: dict) -> bool:
    ticker = item.get("ticker", "")
    if is_watch_excluded_ticker(ticker):
        return False
    if is_recovery_rescue_watch_candidate(item) or is_rebreakout_wait_watch_candidate(item):
        return True
    snap = ensure_pre_alert_snapshot(item)
    chg_5 = abs(safe_float(snap.get("chg_5m", 0), 0))
    chg_30 = abs(safe_float(snap.get("chg_30m", 0), 0))
    from_low = abs(safe_float(snap.get("from_30m_low_pct", 0), 0))
    change_now = abs(safe_float(item.get("change_pct", 0), 0))
    range_pct = abs(safe_float(item.get("range_pct", 0), 0))
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    strong_motion = max(chg_30, from_low, chg_5, change_now)
    overall_motion = max(strong_motion, range_pct)
    if vol_ratio >= WATCH_HIGH_VOL_MIN:
        return strong_motion >= WATCH_HIGH_VOL_MIN_MOVE_PCT or range_pct >= WATCH_MIN_RANGE_PCT
    if vol_ratio >= 1.70 and (chg_5 >= 0.00 or chg_30 >= 0.05 or from_low >= 0.05):
        return True
    if leader_score >= 0.90 and vol_ratio >= 1.15 and (chg_5 >= -0.02 or chg_30 >= 0.05 or from_low >= 0.05):
        return True
    if overall_motion < WATCH_MIN_EFFECTIVE_30M_MOVE_PCT:
        return False
    if from_low < WATCH_MIN_RECOVERY_FROM_LOW_PCT and chg_30 < WATCH_MIN_EFFECTIVE_30M_MOVE_PCT and change_now < WATCH_HIGH_VOL_MIN_MOVE_PCT:
        return False
    return True
def is_fast_start_entry_candidate(item: dict, judgement: str = "", caution: str = "", regime: dict = None) -> bool:
    if not has_meaningful_watch_motion(item):
        return False
    if is_watch_late_candidate(item, judgement, caution):
        return False
    if caution:
        return False
    regime = regime or get_market_regime()
    regime_name = str((regime or {}).get("name", "NORMAL") or "NORMAL")
    if regime_name == "BLOCK":
        return False
    strategy = str(item.get("strategy", "") or "").strip()
    if strategy not in {"LEADER_WATCH", "PREPUMP", "PULLBACK"}:
        return False
    if not is_chart_position_good_for_live(item):
        return False
    snap = ensure_pre_alert_snapshot(item)
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", 0), 0)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    high_gap_pct = get_reference_high_gap_pct(item)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    change_pct = safe_float(item.get("change_pct", 0), 0)
    tags = set(item.get("pattern_tags", []))
    if high_gap_pct < max(FAST_ENTRY_MIN_HIGH_GAP_PCT, 0.85) or high_gap_pct > 2.40:
        return False
    if from_low > 3.20:
        return False
    if chg_5 < 0.05:
        return False
    if change_pct > 4.20 and high_gap_pct < 1.25:
        return False
    if strategy in {"PREWATCH", "NEWLOW_RECOVER"}:
        if chg_5 < 0.10 or high_gap_pct < 0.75:
            return False
    if strategy == "LEADER_WATCH" and chg_30 < 0.10 and from_low < 0.25:
        return False
    strength = 0
    if chg_5 >= max(FAST_ENTRY_MIN_5M_PCT, 0.10):
        strength += 1
    if chg_30 >= max(FAST_ENTRY_MIN_30M_PCT, 0.15):
        strength += 1
    if from_low >= max(FAST_ENTRY_MIN_FROM_LOW_PCT, 0.25):
        strength += 1
    if vol_ratio >= max(FAST_ENTRY_MIN_VOL_RATIO, 1.35):
        strength += 1
    if leader_score >= max(FAST_ENTRY_MIN_LEADER_SCORE, 1.10):
        strength += 1
    if tags.intersection({"м Җм җлҶ’мһ„", "мғҒлӢЁм••м¶•", "м–‘лҙүм Ҳл°ҳмң м§Җ", "к°Җм§ңн•ҳлқҪнҡҢліө", "лҲҢлҰјмһ¬нҷ•мқё", "м Җк°ҖнҡҢліө"}):
        strength += 1
    if vol_ratio >= 2.60 and max(chg_5, chg_30, from_low) >= 0.55:
        strength += 1
    threshold = 4
    if strategy in {"PREWATCH", "NEWLOW_RECOVER"}:
        threshold = 4
    elif strategy == "LEADER_WATCH":
        threshold = 3
    if regime_name == "SIDEWAYS":
        if chg_5 >= 0.20 and vol_ratio >= 1.65 and high_gap_pct >= 0.80:
            threshold -= 1
    elif regime_name == "WEAK":
        threshold += 1
    if strategy == "LEADER_WATCH" and vol_ratio >= 1.90 and leader_score >= 1.20 and max(chg_5, chg_30, from_low) >= 0.30:
        threshold -= 1
    if strategy in {"PREWATCH", "NEWLOW_RECOVER"} and vol_ratio >= 1.90 and max(chg_5, from_low, chg_30) >= 0.35 and high_gap_pct >= 0.90:
        threshold -= 1
    if max(chg_5, chg_30, from_low) >= 0.70 and vol_ratio >= 1.55 and high_gap_pct >= 0.85:
        threshold -= 1
    threshold = max(2, threshold)
    return strength >= threshold
def should_promote_recovery_candidate_to_entry(item: dict, judgement: str = "", caution: str = "", regime: dict = None) -> bool:
    if not has_meaningful_watch_motion(item):
        return False
    if is_watch_late_candidate(item, judgement, caution):
        return False
    if caution:
        return False
    regime = regime or get_market_regime()
    regime_name = str((regime or {}).get("name", "NORMAL") or "NORMAL")
    if regime_name == "BLOCK":
        return False
    strategy = str(item.get("strategy", "") or "").strip()
    if strategy in {"PREWATCH", "NEWLOW_RECOVER"}:
        return False
    restart_ok, _restart_reason = get_restart_quality_status(item)
    if not restart_ok:
        return False
    snap = ensure_pre_alert_snapshot(item)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", 0), 0)
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    high_gap_pct = get_reference_high_gap_pct(item)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    change_pct = safe_float(item.get("change_pct", 0), 0)
    tags = set(item.get("pattern_tags", []))
    chart_ctx = ensure_alert_chart_context(item)
    state_code = str(chart_ctx.get("chart_state_code", "") or "")
    chart_profile = get_item_chart_profile(item)
    chart_rise = safe_float(chart_profile.get("chart_rise_pct", from_low), from_low)

    if state_code in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}:
        return False
    if high_gap_pct < max(RECOVERY_ENTRY_MIN_HIGH_GAP_PCT, 0.85):
        return False
    if high_gap_pct <= 0.55:
        return False
    if chg_5 < 0.08:
        return False
    if from_low > 3.10 and high_gap_pct < 1.20:
        return False
    if chart_rise >= 3.90 and high_gap_pct < 1.60:
        return False
    if chg_30 < -1.20 and from_low < 0.90 and high_gap_pct < 2.10:
        return False
    if strategy in {"LEADER_WATCH", "PREPUMP", "PULLBACK"} and chg_5 < 0.10 and max(chg_30, from_low) < 0.25 and high_gap_pct < 1.60:
        return False
    if strategy in {"LEADER_WATCH", "PREPUMP", "PULLBACK"} and vol_ratio < 1.35 and leader_score < 0.75 and max(chg_5, chg_30, from_low) < 0.40:
        return False
    if regime_name == "WEAK" and REGIME_RECOVERY_ENTRY_BLOCK_IN_WEAK and not should_keep_recovery_candidate_in_weak_regime(item, regime=regime):
        return False

    strength = 0
    if chg_30 >= max(RECOVERY_ENTRY_MIN_30M_PCT, 0.10):
        strength += 1
    if from_low >= max(RECOVERY_ENTRY_MIN_FROM_LOW_PCT, 0.25):
        strength += 1
    if vol_ratio >= max(RECOVERY_ENTRY_MIN_VOL_RATIO, 1.30):
        strength += 1
    if leader_score >= max(RECOVERY_ENTRY_MIN_LEADER_SCORE, 0.80):
        strength += 1
    if chg_5 >= max(RECOVERY_ENTRY_MIN_5M_PCT, 0.08) or change_pct >= 0.35:
        strength += 1
    if high_gap_pct >= 1.15:
        strength += 1
    if tags.intersection({"м Җм җлҶ’мһ„", "к°Җм§ңн•ҳлқҪнҡҢліө", "н•ҳлқҪліөкө¬", "лҲҢлҰјмһ¬нҷ•мқё", "м Җк°ҖнҡҢліө"}):
        strength += 1
    if vol_ratio >= 2.40 and max(from_low, chg_30, change_pct) >= 0.35:
        strength += 1
    if leader_score >= 1.60 and high_gap_pct >= 1.00:
        strength += 1
    if vol_ratio >= 1.25 and leader_score >= 0.75 and max(chg_5, chg_30, from_low, change_pct) >= 0.18:
        strength += 1

    threshold = 3
    if strategy == "LEADER_WATCH":
        threshold = 2
    elif strategy in {"PREPUMP", "PULLBACK"}:
        threshold = 3

    if strategy == "LEADER_WATCH" and leader_score >= 1.10 and vol_ratio >= 1.25 and max(from_low, chg_30, change_pct) >= 0.18:
        threshold -= 1
    if strategy in {"PREPUMP", "PULLBACK"} and high_gap_pct >= 1.10 and vol_ratio >= 1.30 and max(chg_5, chg_30, from_low, change_pct) >= 0.18:
        threshold -= 1
    if high_gap_pct >= 1.25 and vol_ratio >= 1.15 and max(chg_5, chg_30, from_low, change_pct) >= 0.15:
        threshold -= 1
    if regime_name == "SIDEWAYS":
        threshold += max(REGIME_RECOVERY_ENTRY_SIDEWAYS_EXTRA_STRENGTH, 0)
        if chg_5 >= 0.10 and vol_ratio >= 1.45 and high_gap_pct >= 0.85:
            threshold -= 1
    if int(safe_float(item.get("turnover_rank", 999), 999)) <= 20 and high_gap_pct >= 1.45 and chg_30 >= -1.80:
        threshold -= 1
    if regime_name == "WEAK":
        threshold += 1
    threshold = max(2, threshold)
    return strength >= threshold

def should_keep_recovery_candidate_in_weak_regime(item: dict, regime: dict = None) -> bool:
    regime = regime or get_market_regime()
    if str((regime or {}).get("name", "NORMAL") or "NORMAL") != "WEAK":
        return True
    snap = ensure_pre_alert_snapshot(item)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    return (
        vol_ratio >= REGIME_RECOVERY_ONLY_MIN_VOL_WEAK
        and leader_score >= REGIME_RECOVERY_ONLY_MIN_LEADER_WEAK
        and from_low >= 0.65
        and chg_5 >= 0.00
    )
def is_watch_late_candidate(item: dict, judgement: str = "", caution: str = "") -> bool:
    judgement = judgement or get_watch_judgement_text(item)
    caution = caution or get_watch_caution_text(item)
    conclusion = get_watch_display_conclusion(item, judgement, caution)
    strategy = str(item.get("strategy", "") or "").strip()
    high_gap_pct = get_reference_high_gap_pct(item)
    snap = ensure_pre_alert_snapshot(item)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    if strategy in ["PREWATCH", "NEWLOW_RECOVER"]:
        return False
    if is_late_conclusion_text(caution) or is_late_conclusion_text(conclusion):
        return True
    if strategy in ["TREND_CONT", "BREAKOUT", "CHASE"] and 0 <= high_gap_pct <= 1.50:
        return True
    if from_low >= 2.20 and 0 <= high_gap_pct <= 1.60:
        return True
    return False
def is_low_zone_recovery_candidate(item: dict, judgement: str = "", caution: str = "") -> bool:
    if not has_meaningful_watch_motion(item):
        return False
    strategy = str(item.get("strategy", "") or "").strip()
    if is_watch_late_candidate(item, judgement, caution):
        return False
    if not is_restart_candidate_strong(item):
        return False
    snap = ensure_pre_alert_snapshot(item)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", 0), 0)
    high_gap_pct = get_reference_high_gap_pct(item)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    tags = set(item.get("pattern_tags", []))
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    if high_gap_pct <= 0.55:
        return False
    if max(chg_5, chg_30, from_low) < 0.35 and vol_ratio < 2.30:
        return False
    if from_low > 2.60 and high_gap_pct < 1.30:
        return False
    if strategy in ["PREWATCH", "NEWLOW_RECOVER"]:
        return (
            high_gap_pct >= 1.00
            and (
                (chg_5 >= 0.18 and vol_ratio >= 1.85 and max(chg_30, from_low) >= 0.45)
                or (chg_30 >= 0.45 and from_low >= 0.50 and vol_ratio >= 1.70)
                or (leader_score >= 1.45 and vol_ratio >= 2.10 and from_low >= 0.45 and chg_5 >= 0.15)
            )
        )
    if strategy == "LEADER_WATCH":
        return (
            from_low >= 0.25
            and high_gap_pct >= 0.80
            and (
                (chg_30 >= 0.28 and vol_ratio >= 1.45)
                or (chg_5 >= 0.12 and vol_ratio >= 1.35 and from_low >= 0.25)
                or (leader_score >= 1.10 and vol_ratio >= 1.30 and from_low >= 0.25)
            )
        )
    if strategy in ["PREPUMP", "PULLBACK"]:
        return high_gap_pct >= 0.95 and vol_ratio >= 1.60 and (chg_5 >= 0.15 or chg_30 >= 0.35 or from_low >= 0.50)
    if tags.intersection({"м Җм җлҶ’мһ„", "к°Җм§ңн•ҳлқҪнҡҢліө", "н•ҳлқҪліөкө¬", "лҲҢлҰјмһ¬нҷ•мқё"}) and from_low <= 2.10 and high_gap_pct >= 1.10 and max(chg_5, chg_30) >= 0.10:
        return True
    if leader_score >= 2.00 and vol_ratio >= 2.30 and from_low <= 1.95 and high_gap_pct >= 1.20 and max(chg_5, chg_30, from_low) >= 0.35:
        return True
    return False

def get_watch_section_key(item: dict, judgement: str = "", caution: str = "", regime: dict = None) -> str:
    judgement = judgement or get_watch_judgement_text(item)
    caution = caution or get_watch_caution_text(item)
    conclusion = get_watch_display_conclusion(item, judgement, caution)
    regime = regime or get_market_regime()
    regime_name = str((regime or {}).get("name", "NORMAL") or "NORMAL")
    strategy = str(item.get("strategy", "") or "").strip()
    trade_tier = get_watch_tier_text(item)
    snap = ensure_pre_alert_snapshot(item)
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", 0), 0)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    high_gap_pct = get_reference_high_gap_pct(item)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    if high_gap_pct <= 0.20:
        section = "late"
    elif is_chart_position_extended(item):
        section = "late" if high_gap_pct <= 1.40 else "recovery"
    elif is_watch_late_candidate(item, judgement, caution):
        section = "late"
    elif is_fast_start_entry_candidate(item, judgement, caution, regime=regime):
        section = "entry"
    elif is_low_zone_recovery_candidate(item, judgement, caution):
        section = "entry" if should_promote_recovery_candidate_to_entry(item, judgement, caution, regime=regime) else "recovery"
    else:
        section = "recovery" if strategy in {"LEADER_WATCH", "PREWATCH", "NEWLOW_RECOVER", "PREPUMP", "PULLBACK"} else "entry"
    if regime_name == "BLOCK":
        section = "late" if section == "late" else "watch"
    elif regime_name == "WEAK":
        if section == "entry":
            if is_low_zone_recovery_candidate(item, judgement, caution):
                section = "recovery" if should_keep_recovery_candidate_in_weak_regime(item, regime=regime) else "watch"
            else:
                section = "late" if strategy in ["TREND_CONT", "BREAKOUT", "CHASE"] else "watch"
        elif section == "recovery" and not should_keep_recovery_candidate_in_weak_regime(item, regime=regime):
            section = "watch"
    elif regime_name == "SIDEWAYS" and section == "entry" and strategy in ["TREND_CONT", "BREAKOUT", "CHASE"]:
        section = "late"
    floor = get_conclusion_section_floor(conclusion)
    if floor == "late":
        section = "late"
    elif floor == "watch" and section in {"entry", "recovery"}:
        section = "watch"
    elif floor == "recovery" and section == "entry":
        section = "recovery"
    if strategy in {"PREWATCH", "NEWLOW_RECOVER"} and section == "entry":
        if not is_fast_start_entry_candidate(item, judgement, caution, regime=regime):
            section = "recovery"
    if strategy == "LEADER_WATCH" and section == "watch" and has_meaningful_watch_motion(item):
        section = "recovery"
    if section == "entry":
        allowed_entry_conclusions = {"м§ҖкёҲ ліјл§Ңн•Ё", "м§ҖкёҲл§Ң мһ к№җ ліј л§Ңн•Ё", "м§ҖкёҲ м§„мһ… к°ҖлҠҘ"}
        entry_like = is_fast_start_entry_candidate(item, judgement, caution, regime=regime)
        if floor not in {"entry", ""} and not entry_like:
            section = "recovery" if is_low_zone_recovery_candidate(item, judgement, caution) else "watch"
        elif conclusion not in allowed_entry_conclusions and not entry_like:
            section = "recovery" if is_low_zone_recovery_candidate(item, judgement, caution) else "watch"
    if section == "entry":
        weak_entry_text = (
            "мӮ¬л©ҙ м•Ҳ лҗЁ" in conclusion
            or "нқҗлҰ„л§Ң нҷ•мқё" in conclusion
            or "лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқё" in conclusion
        )
        if weak_entry_text:
            section = "recovery" if is_low_zone_recovery_candidate(item, judgement, caution) else "watch"
    if section == "entry" and trade_tier == "B":
        recovery_like = is_low_zone_recovery_candidate(item, judgement, caution)
        if strategy in {"PREWATCH", "NEWLOW_RECOVER"}:
            section = "recovery" if recovery_like else "watch"
        elif high_gap_pct <= 0.60:
            section = "late"
        elif chg_5 < 0.05:
            section = "recovery" if recovery_like else "watch"
        elif chg_30 <= 0.05 and from_low <= 0.15:
            section = "recovery" if recovery_like else "watch"
        elif leader_score < 0.80 and vol_ratio < 1.35:
            section = "recovery" if recovery_like else "watch"
        elif from_low >= 1.50 and high_gap_pct < 1.10:
            section = "recovery"
        elif vol_ratio < 1.05 and not recovery_like:
            section = "watch"
        elif strategy in {"PREWATCH", "NEWLOW_RECOVER"} and (chg_5 < 0.10 or high_gap_pct < 0.75):
            section = "recovery"
        elif strategy == "LEADER_WATCH" and (vol_ratio < 1.20 or high_gap_pct < 0.60):
            section = "recovery" if recovery_like else "watch"
    if section == "entry" and strategy == "LEADER_WATCH":
        if chg_5 < 0.10 and chg_30 < 0.20:
            section = "recovery" if is_low_zone_recovery_candidate(item, judgement, caution) else "watch"
    return section
def normalize_alert_section_key(section_key: str) -> str:
    key = str(section_key or "").strip()
    return {
        "early": "entry",
        "live": "entry",
        "restart": "recovery",
    }.get(key, key)
def get_watch_bucket_label(section_key: str) -> str:
    key = str(section_key or "").strip()
    return {
        "early": "м§ҖкёҲ ліј нӣ„ліҙ",
        "restart": "лҜёлҰ¬ ліј нӣ„ліҙ",
        "live": "м§ҖкёҲ ліј нӣ„ліҙ",
        "late": "лҠҰм–ҙм„ң лІ„лҰҙ нӣ„ліҙ",
        "watch": "лҜёлҰ¬ ліј нӣ„ліҙ",
        "entry": "м§ҖкёҲ ліј нӣ„ліҙ",
        "recovery": "лҜёлҰ¬ ліј нӣ„ліҙ",
    }.get(key, "лҜёлҰ¬ ліј нӣ„ліҙ")
def get_watch_display_group(item: dict, judgement: str = "", caution: str = "", section_override: str = "", regime: dict = None) -> str:
    regime = regime or get_market_regime()
    judgement = judgement or get_watch_judgement_text(item)
    caution = caution or get_watch_caution_text(item)
    raw_key = normalize_alert_section_key(section_override or get_watch_section_key(item, judgement, caution, regime=regime))
    if raw_key in {"late", "watch"}:
        return raw_key
    strategy = str(item.get("strategy", "") or "").strip()
    snap = ensure_pre_alert_snapshot(item)
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", 0), 0)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    high_gap_pct = get_reference_high_gap_pct(item)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    change_pct = safe_float(item.get("change_pct", 0), 0)
    chart_profile = get_item_chart_profile(item)
    rise_pct = safe_float(chart_profile.get("chart_rise_pct", 0), 0)
    restart_ok, _restart_reason = get_restart_quality_status(item)
    # лӘ©н‘ң кё°мӨҖ ліҙк°•: THETA/CVCнҳ•мқҖ лӮҙл¶Җ к°җмӢңлЎң мӮҙлҰ¬кі , ENJнҳ• кі м җк¶Ң нқ”л“ӨлҰјмқҖ нҷ•мӢӨнһҲ лӮҙлҰ°лӢӨ.
    if is_high_zone_wobble_block_candidate(item):
        return "late"
    if is_rebreakout_wait_watch_candidate(item):
        item["goal_shape_note"] = "мһ¬лҸҢнҢҢ нҷ•мқё м „ лӮҙл¶Җ к°җмӢң"
        return "restart"
    if is_recovery_rescue_watch_candidate(item):
        item["goal_shape_note"] = "н•ҳлқҪ нӣ„ нҡҢліө мһ¬м¶ңл°ң лҢҖкё°"
        return "restart"
    if strategy in {"PULLBACK", "PREWATCH", "NEWLOW_RECOVER"}:
        if not restart_ok:
            return "watch"
        if high_gap_pct < 0.95:
            return "watch"
        if rise_pct >= 3.00 and high_gap_pct < 2.00:
            return "watch"
        if chg_5 < -0.10 and max(chg_30, from_low) < 0.45:
            return "watch"
        return "restart" if restart_ok else "watch"
    if strategy == "PREPUMP":
        if high_gap_pct >= 1.10 and from_low <= 1.60 and chg_5 >= 0.05 and not is_chart_position_extended(item):
            return "early"
        return "restart" if restart_ok else "watch"
    if strategy == "LEADER_WATCH":
        if high_gap_pct < 0.55 or not is_chart_position_good_for_live(item):
            return "late"
        if max(chg_30, from_low) >= LIVE_DISPLAY_OVERHEAT_30M_PCT and high_gap_pct < 2.10:
            return "late"
        if chg_5 >= LIVE_DISPLAY_OVERHEAT_5M_PCT and max(chg_30, from_low) >= 3.20 and high_gap_pct < 2.30:
            return "late"
        if chg_5 <= 0.05 and max(chg_30, from_low) < 0.35:
            return "watch"
        if chg_5 < LIVE_DISPLAY_MIN_5M_PCT:
            return "restart" if restart_ok and max(chg_30, from_low) >= 0.35 and high_gap_pct >= 1.05 else "watch"
        if vol_ratio < LIVE_DISPLAY_MIN_VOL_RATIO:
            return "restart" if restart_ok and max(chg_30, from_low) >= 0.40 and high_gap_pct >= 1.05 else "watch"
        if leader_score < LIVE_DISPLAY_MIN_LEADER_SCORE and vol_ratio < (LIVE_DISPLAY_MIN_VOL_RATIO + 1.20):
            return "watch"
        if high_gap_pct < LIVE_DISPLAY_MIN_HIGH_GAP_PCT:
            return "restart" if restart_ok else "watch"
        if chg_30 <= LIVE_DISPLAY_MIN_30M_PCT and from_low >= LIVE_DISPLAY_WEAK_30M_MAX_FROM_LOW_PCT and high_gap_pct <= 1.20:
            return "restart" if restart_ok else "watch"
        live_strength = 0
        if chg_5 >= LIVE_DISPLAY_MIN_5M_PCT:
            live_strength += 1
        if vol_ratio >= LIVE_DISPLAY_MIN_VOL_RATIO:
            live_strength += 1
        if leader_score >= max(1.20, LIVE_DISPLAY_MIN_LEADER_SCORE):
            live_strength += 1
        if chg_30 >= LIVE_DISPLAY_MIN_30M_PCT:
            live_strength += 1
        if max(chg_30, from_low) >= 0.55:
            live_strength += 1
        if change_pct >= 0.75:
            live_strength += 1
        if high_gap_pct >= LIVE_DISPLAY_MIN_HIGH_GAP_PCT:
            live_strength += 1
        if rise_pct >= 3.30 and high_gap_pct < 2.40:
            live_strength -= 2
        if max(chg_30, from_low) >= LIVE_DISPLAY_OVERHEAT_30M_PCT and high_gap_pct < 2.40:
            live_strength -= 2
        if chg_5 >= LIVE_DISPLAY_OVERHEAT_5M_PCT and max(chg_30, from_low) >= 3.20 and high_gap_pct < 2.60:
            live_strength -= 2
        if live_strength >= 5 and chg_5 >= LIVE_DISPLAY_MIN_5M_PCT and vol_ratio >= LIVE_DISPLAY_MIN_VOL_RATIO and high_gap_pct >= LIVE_DISPLAY_MIN_HIGH_GAP_PCT:
            return "live"
        return "restart" if restart_ok else "watch"
    if strategy in {"TREND_CONT", "BREAKOUT", "CHASE"}:
        chart_ctx = ensure_alert_chart_context(item)
        if str(chart_ctx.get("chart_state_code", "")) in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE"} and chg_30 < 0.60:
            return "restart" if restart_ok else "watch"
        if high_gap_pct < 0.55 or not is_chart_position_good_for_live(item):
            return "late"
        if max(chg_30, from_low) >= LIVE_DISPLAY_OVERHEAT_30M_PCT and high_gap_pct < 2.10:
            return "late"
        if chg_5 >= LIVE_DISPLAY_OVERHEAT_5M_PCT and max(chg_30, from_low) >= 3.20 and high_gap_pct < 2.30:
            return "late"
        if (
            chg_5 >= max(0.40, LIVE_DISPLAY_MIN_5M_PCT - 0.05)
            and max(chg_30, from_low) >= 0.45
            and vol_ratio >= 1.80
            and high_gap_pct >= 0.85
            and leader_score >= 0.85
        ):
            return "live"
        return "restart" if restart_ok else "watch"
    if strategy in {"EARLY", "PRE_BREAKOUT"}:
        return "early" if is_chart_position_good_for_live(item) else ("restart" if restart_ok else "watch")
    if raw_key == "recovery":
        return "restart" if restart_ok else "watch"
    return "early"
def get_watch_section_header(section_key: str, regime: dict = None) -> str:
    base = {
        "early": "вң… м§ҖкёҲ ліј нӣ„ліҙ",
        "restart": "рҹ‘Җ лҜёлҰ¬ ліј нӣ„ліҙ",
        "live": "вң… м§ҖкёҲ ліј нӣ„ліҙ",
        "late": "вӣ” лҠҰм–ҙм„ң лІ„лҰҙ нӣ„ліҙ",
        "watch": "рҹ‘Җ лҜёлҰ¬ ліј нӣ„ліҙ",
        "entry": "вң… м§ҖкёҲ ліј нӣ„ліҙ",
        "recovery": "рҹ‘Җ лҜёлҰ¬ ліј нӣ„ліҙ",
    }.get(section_key, "рҹ‘Җ лҜёлҰ¬ ліј нӣ„ліҙ")
    regime = regime or {}
    regime_name = str(regime.get("name", "NORMAL") or "NORMAL")
    normalized = normalize_alert_section_key(section_key)
    note = ""
    if regime_name == "BLOCK":
        note = "- мһҘ мғҒнғң: BTCк°Җ м•Ҫн•ҙм„ң мҳӨлҠҳмқҖ к°җмӢң мң„мЈј"
    elif regime_name == "WEAK" and normalized in {"entry", "recovery", "watch"}:
        note = "- мһҘ мғҒнғң: м•Ҫн•ң мһҘмқҙлқј мҙҲл°ҳ/мһ¬м¶ңл°ң нӣ„ліҙлҸ„ лҚ” ліҙмҲҳм ҒмңјлЎң лҙ„"
    elif regime_name == "SIDEWAYS" and section_key in {"early", "live", "late", "entry"}:
        note = "- мһҘ мғҒнғң: нҡЎліҙ мһҘмқҙлқј лҠҰмқҖ м¶”кІ©мқҖ лҚ” л§үлҠ” мӨ‘"
    elif regime_name == "STRONG_UP" and section_key in {"early", "restart", "live", "entry", "recovery"}:
        note = "- мһҘ мғҒнғң: мһҘмқҙ мўӢм•„м„ң мҙҲл°ҳ/мһ¬м¶ңл°ң нӣ„ліҙк°Җ лҚ” мһҳ мҳ¬лқјмҳӨлҠ” кө¬к°„"
    if note:
        return base + "\n" + note
    return base
def get_user_alert_momentum_decay_reason(item: dict, section: str = "") -> str:
    """v2.5.165: 1мӢңк°„ к°•м„ё л’Ө мөңк·ј 15/30л¶„ нһҳмқҙ кәҫмқё нӣ„ліҙлҠ” мӮ¬мҡ©мһҗ м•ҢлҰј мҠ№кІ©мқ„ л§үлҠ”лӢӨ.
    мҠӨмә”/н‘ңмӢңлҠ” мӮҙлҰ¬лҗҳ, л°”лЎң м•ҢлҰјмңјлЎң мҳ¬лҰ¬лҠ” кІғл§Ң л§үлҠ” мҡ©лҸ„лӢӨ.
    """
    if not USER_ALERT_MOMENTUM_DECAY_BLOCK_ON or not isinstance(item, dict):
        return ""
    section = str(section or item.get("section", "") or "").strip()
    snap = ensure_pre_alert_snapshot(item)
    chg_5 = max(safe_float(item.get("change_5", 0), 0), safe_float(snap.get("chg_5m", 0), 0))
    chg_15 = safe_float(item.get("change_15", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", item.get("change_30", 0)), 0)
    chg_60 = safe_float(item.get("change_60", 0), 0)
    from_low = max(safe_float(item.get("from_low", 0), 0), safe_float(snap.get("from_30m_low_pct", 0), 0))
    high_gap = get_effective_high_gap_pct(item)
    chart_ctx = ensure_alert_chart_context(item)
    state_code = str(chart_ctx.get("chart_state_code", "") or "")
    pullback = safe_float(chart_ctx.get("recent_pullback_pct", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    turnover_5m = safe_float(item.get("turnover_5m", item.get("turnover", 0)), 0)

    if (
        chg_60 >= USER_ALERT_DECAY_STRONG_60M_PCT
        and chg_15 <= USER_ALERT_DECAY_15M_NEG_PCT
        and chg_30 <= USER_ALERT_DECAY_30M_FLAT_PCT
        and from_low >= USER_ALERT_DECAY_FROM_LOW_MIN_PCT
        and high_gap >= USER_ALERT_DECAY_MIN_HIGH_GAP_PCT
    ):
        return "1мӢңк°„ к°•м„ё л’Ө мөңк·ј 15/30л¶„ нһҳмқҙ кәҫм—¬ мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ. мһ¬к°ҖмҶҚ нҷ•мқё н•„мҡ”"

    if (
        state_code == "FADE_AFTER_SPIKE"
        and pullback >= USER_ALERT_DECAY_PULLBACK_BLOCK_PCT
        and (chg_15 <= 0.10 or chg_30 <= 0.20)
        and high_gap >= 0.65
    ):
        return f"кі м җ м°Қкі  {pullback:.2f}% л°ҖлҰ° л’Өлқј мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ. лӢӨмӢң кі м җ мһ¬м ‘к·ј нҷ•мқё н•„мҡ”"

    if (
        section in {"live", "early", "strong"}
        and chg_5 >= 0.80
        and chg_15 < 0.00
        and chg_30 <= 0.10
        and from_low >= 2.00
        and vol_ratio < 4.80
        and turnover_5m < 180_000_000
    ):
        return "5л¶„мқҖ л°ҳмқ‘н–Ҳм§Җл§Ң 15/30л¶„ м§ҖмҶҚм„ұмқҙ м•Ҫн•ҙ мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ"

    return ""

def estimate_bithumb_low_price_tick_unit_v227(price: float) -> float:
    """v2.5.227: мҙҲм Җк°Җ мҪ”мқёмқҳ н•ң нӢұ л№„мңЁмқ„ ліҙмҲҳм ҒмңјлЎң м¶”м •н•ңлӢӨ.

    кұ°лһҳмҶҢ нҳёк°ҖлӢЁмң„к°Җ л°”лҖҢм–ҙлҸ„ мӮ¬мҡ©мһҗ м•ҢлҰј мөңмў… кІҢмқҙнҠём—җм„ңл§Ң м“°лҠ” ліҙмЎ°к°’мқҙлӢӨ.
    SHIBмІҳлҹј 0.009мӣҗлҢҖм—җм„ң 0.0001мӣҗ н•ң м№ёмқҙ 1% м•ҲнҢҺмңјлЎң ліҙмқҙлҠ” мјҖмқҙмҠӨлҘј мһЎкё° мң„н•ң лӘ©м ҒмқҙлӢӨ.
    """
    price = safe_float(price, 0)
    if price <= 0:
        return 0.0
    if price < 0.1:
        return 0.0001
    if price < 1:
        return 0.001
    if price < 10:
        return 0.01
    if price < 100:
        return 0.1
    if price < 1000:
        return 1.0
    return 5.0


def estimate_move_ticks_v227(price: float, move_pct: float) -> float:
    price = safe_float(price, 0)
    move_pct = abs(safe_float(move_pct, 0))
    tick = estimate_bithumb_low_price_tick_unit_v227(price)
    if price <= 0 or tick <= 0 or move_pct <= 0:
        return 0.0
    try:
        base = price / (1.0 + move_pct / 100.0)
        return abs(price - base) / tick
    except Exception:
        return 0.0


def is_ultra_low_tick_noise_user_alert_v227(item: dict) -> bool:
    """SHIBнҳ•: 0.009мӣҗлҢҖ н•ңл‘җ нӢұ мӣҖм§Ғмһ„мқҙ +1%лҢҖ кёүк°ҖмҶҚмІҳлҹј ліҙмқҙлҠ” м°©мӢңлҘј мӮ¬мҡ©мһҗ м•ҢлҰјм—җм„ңл§Ң л§үлҠ”лӢӨ."""
    if not USER_ALERT_ULTRA_LOW_TICK_NOISE_V227_ON:
        return False
    item = item if isinstance(item, dict) else {}
    try:
        price = safe_float(item.get("price", item.get("current_price", item.get("snapshot_price", 0))), 0)
        if price <= 0 or price > USER_ALERT_ULTRA_LOW_TICK_PRICE_MAX:
            return False
        tick = estimate_bithumb_low_price_tick_unit_v227(price)
        tick_pct = (tick / price) * 100.0 if price > 0 and tick > 0 else 0.0
        if tick_pct < USER_ALERT_ULTRA_LOW_TICK_MIN_TICK_PCT:
            return False
        snap = item.get("pre_alert_snapshot") if isinstance(item.get("pre_alert_snapshot"), dict) else {}
        ch1 = safe_float(item.get("change_1", item.get("chg_1m", 0)), 0)
        ch3 = safe_float(item.get("change_3", item.get("chg_3m", 0)), 0)
        ch5 = safe_float(item.get("change_5", snap.get("chg_5m", item.get("change_pct", 0))), 0)
        ch15 = safe_float(item.get("change_15", item.get("chg_15m", 0)), 0)
        ch30 = safe_float(item.get("change_30", snap.get("chg_30m", item.get("chg_30m", 0))), 0)
        ch60 = safe_float(item.get("change_60", item.get("chg_60m", 0)), 0)
        from_low = safe_float(item.get("from_low", snap.get("from_30m_low_pct", item.get("from_30m_low_pct", 0))), 0)
        strongest_short = max(abs(ch1), abs(ch3), abs(ch5), abs(from_low))
        est_ticks = max(
            estimate_move_ticks_v227(price, ch1),
            estimate_move_ticks_v227(price, ch3),
            estimate_move_ticks_v227(price, ch5),
            estimate_move_ticks_v227(price, from_low),
        )
        mid_weak = (ch15 <= 0.05 and ch30 <= 0.05 and ch60 <= 0.05)
        mid_negative = (ch15 < 0.0 and ch30 < 0.0) or (ch30 < 0.0 and ch60 < 0.0)
        if USER_ALERT_ULTRA_LOW_TICK_REQUIRE_MID_WEAK and not (mid_weak or mid_negative):
            return False
        if est_ticks <= USER_ALERT_ULTRA_LOW_TICK_MAX_REAL_TICKS and strongest_short <= max(USER_ALERT_ULTRA_LOW_TICK_MAX_SHORT_MOVE_PCT, tick_pct * 2.65):
            item["ultra_low_tick_noise_block"] = True
            item["rank_tick_noise_block"] = True
            item["tick_noise_v227_tick_pct"] = round(tick_pct, 3)
            item["tick_noise_v227_est_ticks"] = round(est_ticks, 2)
            return True
        return False
    except Exception:
        return False


def get_current_candle_user_alert_block_reason_v227(item: dict, section: str = "") -> str:
    """нҳ„мһ¬лҙү нҢҗм •кіј мӢӨм ң мӮ¬мҡ©мһҗ м•ҢлҰј лқјмҡ°нҢ…мқ„ л§һм¶ҳлӢӨ."""
    if not USER_ALERT_BLOCK_WEAK_CURRENT_CANDLE_ON:
        return ""
    item = item if isinstance(item, dict) else {}
    try:
        ctx = ensure_alert_chart_context(item)
        code = str(item.get("current_candle_code", ctx.get("current_candle_code", "")) or "")
        label = str(item.get("current_candle_label", ctx.get("current_candle_label", "")) or "")
        state_code = str(ctx.get("chart_state_code", "") or "")
        hard_codes = {"CLOSING_WEAK_HARD", "UPPER_WICK_DUMP_HARD"}
        soft_codes = {"CLOSING_WEAK_SOFT", "UPPER_WICK_DUMP_SOFT"}
        if code in hard_codes or state_code == "CURRENT_CANDLE_WEAK":
            return f"нҳ„мһ¬лҙүмқҙ {label or 'л§үнҢҗк°•л°ҖлҰј'} мғҒнғңлқј мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ. лӮҙл¶Җк°җмӢңм—җм„ң лӢӨмқҢ лҙү нҷ•мқё"
        if code in soft_codes or state_code == "CURRENT_CANDLE_SOFT_WEAK":
            return f"нҳ„мһ¬лҙүмқҙ {label or 'л§үнҢҗл°ҖлҰј'} мғҒнғңлқј мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ. мӮҙм•„лӮЁ/м•„лһ«кј¬лҰ¬ нҡҢліө нҷ•мқё н•„мҡ”"
        return ""
    except Exception:
        return ""


def get_precision_pending_user_alert_block_reason_v227(item: dict) -> str:
    """1л¶„лҙү/м •л°Җл¶„м„қ нҷ•мқё м „мқҙлқјлҠ” л¬ёкө¬к°Җ л¶ҷмқҖ нӣ„ліҙлҠ” мӢӨм ң мӮ¬мҡ©мһҗ м•ҢлҰјмңјлЎң ліҙлӮҙм§Җ м•ҠлҠ”лӢӨ."""
    if not USER_ALERT_BLOCK_PENDING_PRECISION_ON:
        return ""
    item = item if isinstance(item, dict) else {}
    try:
        texts = []
        for key in ("one_liner", "quality_block_reason", "user_alert_block_reason_detail", "decision_path", "precision_stage", "label_text", "rank_watch_action"):
            val = item.get(key)
            if val:
                texts.append(str(val))
        if isinstance(item.get("reasons"), list):
            texts.extend([str(x) for x in item.get("reasons", [])[:6]])
        joined = " / ".join(texts)
        pending_words = [
            "1л¶„лҙү нҷ•мқё м „",
            "м •л°Җл¶„м„қ м „мқҙлқј мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ",
            "м •л°Җл¶„м„қ м „/л¶Җл¶„",
            "м •л°ҖкІҖнҶ  лҢҖкё°",
            "кұ°лһҳлҢҖкёҲ/м°ЁнҠё нҷ•мқё м „мқҙлқј м•ҢлҰјмқҖ ліҙлҘҳ",
            "м•ҢлҰј м „ лӮҙл¶Җк°җмӢң нӣ„ліҙ",
        ]
        if any(word in joined for word in pending_words):
            return "1л¶„лҙү/м •л°Җл¶„м„қ нҷ•мқё м „ лӢЁкі„лқј мӮ¬мҡ©мһҗ м•ҢлҰј ліҙлҘҳ. лӮҙл¶Җк°җмӢң/ліөкё°лЎңл§Ң мң м§Җ"
        return ""
    except Exception:
        return ""


def get_user_alert_final_gate_block_reason_v227(item: dict, section: str = "", primary_reason: str = "") -> str:
    """v2.5.227 мӮ¬мҡ©мһҗ м•ҢлҰј мөңмў… кІҢмқҙнҠё.

    мўӢмқҖ нӣ„ліҙлҘј мЈҪмқҙлҠ” м „мІҙ н•„н„°к°Җ м•„лӢҲлқј, мӮ¬мҡ©мһҗм—җкІҢ ліҙлӮҙкё° м§Ғм „мқҳ лӘ…л°ұн•ң л¶Ҳмқјм№ҳл§Ң л§үлҠ”лӢӨ.
    """
    if not USER_ALERT_FINAL_GATE_ON:
        return ""
    item = item if isinstance(item, dict) else {}
    try:
        if is_ultra_low_tick_noise_user_alert_v227(item):
            return "мҙҲм Җк°Җ н•ңл‘җ нӢұ мӣҖм§Ғмһ„мқҙ нҚјм„јнҠёлЎң кіјмһҘлҗң нӣ„ліҙлқј мӮ¬мҡ©мһҗ м•ҢлҰј м ңмҷё. лӮҙл¶Җкё°лЎқ/ліөкё°л§Ң мң м§Җ"
        pending_reason = get_precision_pending_user_alert_block_reason_v227(item)
        if pending_reason:
            return pending_reason
        candle_reason = get_current_candle_user_alert_block_reason_v227(item, section=section)
        if candle_reason:
            return candle_reason
        try:
            flow_reason = get_fast_scan_user_alert_flow_block_reason_v226(item, section=section, primary_reason=primary_reason)
            if flow_reason:
                return flow_reason
        except Exception:
            pass
        return ""
    except Exception:
        return ""


def apply_user_alert_final_gate_demote_v227(item: dict, reason: str) -> dict:
    """мөңмў… кІҢмқҙнҠём—җ кұёлҰ° нӣ„ліҙлҘј мӮӯм ңн•ҳм§Җ м•Ҡкі  лӮҙл¶Җк°җмӢң/ліөкё°мҡ©мңјлЎң лӮ®м¶ҳлӢӨ."""
    item = dict(item or {})
    if not reason:
        return item
    item["alert_bucket"] = "internal_watch"
    item["alert_grade"] = "B" if str(item.get("alert_grade", "") or "").upper() in {"S", "A", "B"} else "C"
    item["bucket_rank"] = max(2, int(safe_float(item.get("bucket_rank", 2), 2)))
    item["quality_block_reason"] = reason
    item["user_alert_block_reason_detail"] = reason
    reasons = list(item.get("reasons", [])) if isinstance(item.get("reasons"), list) else []
    if reason not in reasons:
        reasons.insert(0, reason)
    item["reasons"] = reasons[:6]
    one = str(item.get("one_liner", "") or "").strip()
    if one and "м•ҢлҰј ліҙлҘҳ" not in one:
        item["one_liner"] = one + " / мӮ¬мҡ©мһҗ м•ҢлҰјмқҖ ліҙлҘҳ"
    elif not one:
        item["one_liner"] = "мӮ¬мҡ©мһҗ м•ҢлҰјмқҖ ліҙлҘҳн•ҳкі  лӮҙл¶Җк°җмӢңлЎң мң м§Җ"
    return item


def classify_user_alert_grade(item: dict, display_key: str = "", regime: dict = None) -> str:
    section = str(display_key or get_watch_display_group(item, regime=regime)).strip()
    snap = ensure_pre_alert_snapshot(item)
    ctx = ensure_alert_chart_context(item)
    profile = get_item_chart_profile(item)
    chart_ctx = ensure_alert_chart_context(item)
    hot_score = get_user_alert_hot_score(item)
    high_gap_pct = get_effective_high_gap_pct(item)
    from_low = safe_float(snap.get("from_30m_low_pct", 0), 0)
    chg_5 = safe_float(snap.get("chg_5m", 0), 0)
    chg_30 = safe_float(snap.get("chg_30m", 0), 0)
    chart_rise = safe_float(profile.get("chart_rise_pct", from_low), from_low)
    edge = safe_float(item.get("edge_score", item.get("signal_score", 0)), 0)
    shortlist_rank = int(safe_float(item.get("shortlist_rank", 999), 999))
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    trade_tier = str(item.get("trade_tier", "B") or "B").upper().strip()
    state_code = str(ctx.get("chart_state_code", "") or "")
    htf_code = str(ctx.get("htf_trend_code", "") or "")
    decay_reason = get_user_alert_momentum_decay_reason(item, section=section)

    if decay_reason and section in {"live", "early", "strong"}:
        item["user_alert_block_reason_detail"] = decay_reason
        return "B"

    if section in {"late", "watch"}:
        return "C"
    if section == "live" and state_code in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"} and hot_score < USER_ALERT_RESCUE_STRONG_HOT_SCORE:
        return "C"
    if section == "restart" and chg_5 < 0 and chg_30 < 0 and hot_score < USER_ALERT_RESCUE_STRONG_HOT_SCORE:
        return "C"

    if section in {"live", "early"}:
        if (
            chg_5 >= 0.95 and chg_30 >= 0.65 and vol_ratio >= 6.0 and leader >= 1.60
            and high_gap_pct >= 1.20 and chart_rise <= 3.20 and state_code not in {"FADE_AFTER_SPIKE", "HIGH_WOBBLE", "EXTENDED"}
        ):
            return "S"
        if (
            chg_5 >= 0.28 and vol_ratio >= 1.55 and leader >= 0.85 and high_gap_pct >= 0.70
            and chart_rise <= 4.10 and state_code not in {"FADE_AFTER_SPIKE", "EXTENDED"}
            and (chg_30 >= -0.15 or hot_score >= USER_ALERT_RESCUE_STRONG_HOT_SCORE)
        ):
            if trade_tier in {"S", "A"} or hot_score >= USER_ALERT_RESCUE_MIN_HOT_SCORE or edge >= 5.10 or htf_code in {"UP", "RECOVER", "NEAR_HIGH"}:
                return "A"
        if vol_ratio >= 1.15 and leader >= 0.55 and high_gap_pct >= 0.55 and state_code not in {"FADE_AFTER_SPIKE"}:
            return "B"
        return "C"

    if section == "restart":
        if is_restart_candidate_strong(item) and high_gap_pct >= 1.00 and vol_ratio >= 1.70 and leader >= 0.95 and max(chg_5, chg_30, from_low) >= 0.18 and state_code not in {"FADE_AFTER_SPIKE", "EXTENDED"}:
            if trade_tier in {"S", "A"} or hot_score >= USER_ALERT_RESCUE_MIN_HOT_SCORE or edge >= 5.10 or htf_code in {"UP", "RECOVER"}:
                return "A"
        if is_restart_candidate_strong(item) and high_gap_pct >= 0.85 and vol_ratio >= 1.15 and leader >= 0.70 and max(chg_5, chg_30, from_low) >= 0.05:
            return "B"
        return "C"

    return trade_tier if trade_tier in {"S", "A"} else "B"

def get_watch_tier_text(item: dict) -> str:
    grade = str(item.get("user_alert_grade", "") or "").upper().strip()
    if grade in {"S", "A", "B", "C"}:
        return grade
    return classify_user_alert_grade(item)
def format_alert_price_line(item: dict) -> str:
    return f"- нҳ„мһ¬к°Җ: {fmt_price(item.get('current_price', 0))} / мғҒмҠ№ {safe_float(item.get('change_pct', 0)):.2f}% / кұ°лһҳлҹү {safe_float(item.get('vol_ratio', 0)):.2f}л°°"
def format_alert_flow_line(item: dict, short: bool = False) -> str:
    snap = ensure_pre_alert_snapshot(item)
    chg_5 = safe_float(snap.get('chg_5m', 0))
    chg_30 = safe_float(snap.get('chg_30m', 0))
    from_low = safe_float(snap.get('from_30m_low_pct', 0))
    high_gap = safe_float(snap.get('below_30m_high_pct', 0), 0)
    if short:
        return f"- нқҗлҰ„(мөңк·ј30л¶„ кё°мӨҖ): 5л¶„ {chg_5:+.2f}% / 30л¶„ {chg_30:+.2f}% / м Җм җлҢҖл№„ {from_low:+.2f}% / {format_recent_high_gap_text(high_gap)}"
    return f"- нқҗлҰ„(мөңк·ј30л¶„ кё°мӨҖ): 5л¶„ {chg_5:+.2f}% / 30л¶„ {chg_30:+.2f}% / м Җм җлҢҖл№„ {from_low:+.2f}% / {format_recent_high_gap_text(high_gap)}"
def get_alert_price_recheck_limit(section_key: str = "") -> float:
    key = str(section_key or "").strip()
    if key == "live":
        return ALERT_PRICE_RECHECK_LIVE_MAX_UP_PCT
    if key in {"restart", "recovery"}:
        return ALERT_PRICE_RECHECK_RESTART_MAX_UP_PCT
    return ALERT_PRICE_RECHECK_ENTRY_MAX_UP_PCT

def refresh_watch_item_before_alert(item: dict, section_key: str = "", regime: dict = None):
    if not isinstance(item, dict):
        return item, False, "нӣ„ліҙ лҚ°мқҙн„° мҳӨлҘҳ"
    if not ALERT_PRICE_RECHECK_ON:
        return item, True, ""
    ticker = str(item.get("ticker", "") or "").upper().strip()
    base_price = safe_float(item.get("current_price", item.get("price", 0)), 0)
    if not ticker or base_price <= 0:
        return item, True, ""
    refreshed = dict(item)
    live_price = get_price(ticker)
    if live_price <= 0:
        return refreshed, True, ""
    drift_pct = ((live_price - base_price) / base_price) * 100.0 if base_price > 0 else 0.0
    refreshed["current_price"] = live_price
    refreshed["price"] = live_price
    refreshed["price_before_alert"] = base_price
    refreshed["price_drift_pct"] = round(drift_pct, 2)
    # v2.5.181: м•ҢлҰј м§Ғм „м—җлҠ” мғҲ OHLCVлҘј м ҲлҢҖ м§Ғм ‘ мЎ°нҡҢн•ҳм§Җ м•ҠлҠ”лӢӨ.
    # м—¬кё°м„ң minute1/4hлҘј кё°лӢӨлҰ¬лӢӨк°Җ м•ҢлҰјмқҙ лҠҰкұ°лӮҳ мӮ¬лқјм§ҖлҠ” кІғмқҙ н•өмӢ¬ лі‘лӘ©мқҙм—ҲлӢӨ.
    # м ҖмһҘлҗң мәҗмӢңк°Җ мһҲмңјл©ҙ м“°кі , м—Ҷмңјл©ҙ нҳ„мһ¬к°Җ мҠӨлғ…мғ· кё°мӨҖмңјлЎңл§Ң к°ҖкІ© лІҢм–ҙм§җмқ„ нҷ•мқён•ңлӢӨ.
    df = get_api_cache_entry(API_OHLCV_CACHE, (ticker, "minute1"), max(get_ohlcv_cache_ttl("minute1") * 12, 60.0), copy_dataframe=True)
    df4h = get_api_cache_entry(API_OHLCV_CACHE, (ticker, str(ALERT_HTF_INTERVAL).lower()), max(get_ohlcv_cache_ttl(ALERT_HTF_INTERVAL) * 6, 600.0), copy_dataframe=True)
    if df is not None and len(df) >= 8:
        refreshed.update(compute_chart_position_profile(df, live_price, lookback=CHART_POS_LOOKBACK_1M))
        refreshed["pre_alert_snapshot"] = compute_pre_alert_snapshot_from_df(df, current_price=live_price)
    else:
        existing_snap = refreshed.get("pre_alert_snapshot") if isinstance(refreshed.get("pre_alert_snapshot"), dict) else {}
        if existing_snap:
            snap_copy = dict(existing_snap)
            snap_copy["current_price"] = live_price
            refreshed["pre_alert_snapshot"] = snap_copy
        else:
            refreshed["pre_alert_snapshot"] = compute_pre_alert_snapshot_from_df(None, current_price=live_price)
        refreshed["precision_stage"] = refreshed.get("precision_stage") or "мҠӨлғ…мғ· мҡ°м„  / OHLCV лҢҖкё°"
    if df is not None and len(df) >= 8:
        refreshed["alert_chart_context"] = compute_alert_chart_context_from_df(df, df4h=df4h, current_price=live_price)
    elif isinstance(refreshed.get("alert_chart_context"), dict) and refreshed.get("alert_chart_context"):
        refreshed["alert_chart_context"] = dict(refreshed.get("alert_chart_context"))
    else:
        refreshed["alert_chart_context"] = {"chart_warning": "м•ҢлҰј м§Ғм „ мғҲ OHLCV мЎ°нҡҢ мғқлһө", "chart_state_label": "мҠӨлғ…мғ· мҡ°м„  нҷ•мқё"}
    high_gap_pct = get_reference_high_gap_pct(refreshed)
    snap = ensure_pre_alert_snapshot(refreshed)
    if drift_pct >= ALERT_PRICE_RECHECK_SKIP_UP_PCT:
        return refreshed, False, f"м•ҢлҰј м§Ғм „ к°ҖкІ©мқҙ л„Ҳл¬ҙ л№ЁлҰ¬ мҳ¬лқјк°Җм„ң м ңмҷё (+{drift_pct:.2f}%)"
    limit = get_alert_price_recheck_limit(section_key)
    if drift_pct > limit and section_key in {"early", "entry", "live", "restart", "recovery"}:
        return refreshed, False, f"м•ҢлҰј м§Ғм „ к°ҖкІ©мқҙ мқҙлҜё лІҢм–ҙм ём„ң м ңмҷё (+{drift_pct:.2f}%)"
    if section_key == "live" and drift_pct > ALERT_PRICE_RECHECK_LIVE_NEAR_HIGH_MAX_UP_PCT and 0 <= high_gap_pct <= 1.15:
        return refreshed, False, f"мӢӨмӢңк°„ к°•м„ёмқёлҚ° м•ҢлҰј м§Ғм „ к°ҖкІ©мқҙ лҚ” мҳ¬лқј лҠҰм–ҙм ём„ң м ңмҷё (+{drift_pct:.2f}%)"
    if section_key in {"restart", "recovery"} and drift_pct > ALERT_PRICE_RECHECK_RESTART_NEAR_HIGH_MAX_UP_PCT and 0 <= high_gap_pct <= 1.15:
        return refreshed, False, f"мһ¬м¶ңл°ң нӣ„ліҙмқёлҚ° м•ҢлҰј м§Ғм „ к°ҖкІ©мқҙ лІҢм–ҙм ём„ң м ңмҷё (+{drift_pct:.2f}%)"
    if section_key in {"restart", "recovery"} and not is_restart_candidate_strong(refreshed):
        _ok, restart_reason = get_restart_quality_status(refreshed)
        return refreshed, False, restart_reason or "мһ¬м¶ңл°ң нһҳмқҙ м•Ҫн•ҙм ём„ң м ңмҷё"
    if section_key == "live" and 0 <= high_gap_pct <= 0.60:
        return refreshed, False, "мӢӨмӢңк°„ к°•м„ёлЎң ліҙкё°м—” мқҙлҜё кі м җмқҙ л„Ҳл¬ҙ к°Җк№ҢмӣҢм„ң м ңмҷё"
    if section_key == "live" and safe_float(snap.get("chg_5m", 0), 0) < 0.18 and safe_float(refreshed.get("vol_ratio", 0), 0) < 3.20:
        return refreshed, False, "мӢӨмӢңк°„ к°•м„ёлЎң ліҙкё°м—” л°©кёҲ нһҳмқҙ м•Ҫн•ҙм ём„ң м ңмҷё"
    if section_key in {"restart", "recovery"} and safe_float(snap.get("chg_5m", 0), 0) < 0.30 and max(safe_float(snap.get("chg_30m", 0), 0), safe_float(snap.get("from_30m_low_pct", 0), 0)) < 0.95:
        return refreshed, False, "мһ¬м¶ңл°ң нӣ„ліҙлЎң ліҙкё°м—” л°©кёҲ л°ҳл“ұ нһҳмқҙ м•Ҫн•ҙм„ң м ңмҷё"
    regime = regime or get_market_regime()
    refreshed_group = get_watch_display_group(refreshed, regime=regime)
    if section_key == "live" and refreshed_group != "live":
        return refreshed, False, "мӢӨмӢңк°„ к°•м„ё мҙҲмһ…мңјлЎң ліҙкё° м–ҙл ӨмӣҢм ё м ңмҷё"
    if section_key in {"early", "entry"} and refreshed_group != "early":
        return refreshed, False, "мҙҲл°ҳ м„ м җнҳ•мңјлЎң ліҙкё° м–ҙл ӨмӣҢм ё м ңмҷё"
    if section_key in {"restart", "recovery"} and refreshed_group != "restart":
        return refreshed, False, "мһ¬м¶ңл°ң нӣ„ліҙлЎң ліҙкё° м–ҙл ӨмӣҢм ё м ңмҷё"
    return refreshed, True, ""
def get_alert_no_chase_pct(item: dict) -> float:
    strategy = str(item.get("strategy", "") or "").strip().upper()
    tier = str(item.get("trade_tier", "B") or "B").upper().strip()
    high_gap_pct = get_reference_high_gap_pct(item)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    base_map = {
        "EARLY": 0.60,
        "PREPUMP": 0.55,
        "PULLBACK": 0.45,
        "PRE_BREAKOUT": 0.40,
        "TREND_CONT": 0.35,
        "BREAKOUT": 0.28,
        "CHASE": 0.18,
        "LEADER_WATCH": 0.35,
        "PREWATCH": 0.35,
        "NEWLOW_RECOVER": 0.30,
    }
    pct = base_map.get(strategy, 0.40)
    if tier == "S":
        pct += 0.08
    elif tier == "B":
        pct -= 0.05
    if 0 <= high_gap_pct <= 0.60:
        pct -= 0.08
    elif high_gap_pct >= 1.40:
        pct += 0.05
    if vol_ratio >= 4.5:
        pct += 0.03
    return round(max(0.12, min(pct, 0.95)), 2)
def build_normal_alert_action_lines(item: dict):
    current_price = safe_float(item.get("current_price", 0), 0)
    if current_price <= 0:
        return []
    no_chase_pct = get_alert_no_chase_pct(item)
    no_chase_price = current_price * (1 + no_chase_pct / 100.0)
    return [f"- м¶”кІ© кёҲм§Җм„ : {fmt_price(no_chase_price)} (+{no_chase_pct:.2f}%)"]
def should_show_trade_plan_in_alert(item: dict) -> bool:
    judgement = get_watch_judgement_text(item)
    caution = get_watch_caution_text(item)
    return get_watch_alert_detail_level(item, judgement, caution) == "strong"
def build_alert_trade_plan_lines(item: dict):
    if not should_show_trade_plan_in_alert(item):
        return []
    current_price = safe_float(item.get("current_price", 0), 0)
    stop_loss_pct = safe_float(item.get("stop_loss_pct", 0), 0)
    take_profit_pct = safe_float(item.get("take_profit_pct", 0), 0)
    if current_price <= 0:
        return []
    stop_price = current_price * (1 + stop_loss_pct / 100.0) if stop_loss_pct else 0.0
    target_price = current_price * (1 + take_profit_pct / 100.0) if take_profit_pct else 0.0
    no_chase_pct = get_alert_no_chase_pct(item)
    no_chase_price = current_price * (1 + no_chase_pct / 100.0)
    lines = [f"- м§„мһ…к°Җ(м°ёкі ): {fmt_price(current_price)}"]
    if stop_price > 0:
        lines.append(f"- мҶҗм Ҳк°Җ: {fmt_price(stop_price)} ({fmt_pct(stop_loss_pct)})")
    if target_price > 0:
        lines.append(f"- 1м°Ё лӘ©н‘ңк°Җ: {fmt_price(target_price)} ({fmt_pct(take_profit_pct)})")
    lines.append(f"- м¶”кІ© кёҲм§Җм„ : {fmt_price(no_chase_price)} (+{no_chase_pct:.2f}%)")
    return lines
def format_watch_alert_line(item: dict, order: int = 1, alert_type: str = "new", reason_text: str = "", section_override: str = "") -> str:
    tags = item.get("pattern_tags", [])
    tag_text = ", ".join(tags[:3]) if tags else ""
    icon = get_watch_item_icon(item, alert_type=alert_type)
    caution = get_watch_caution_text(item)
    judgement = get_watch_judgement_text(item)
    detail_level = get_watch_alert_detail_level(item, judgement, caution)
    bucket_key = section_override or get_watch_display_group(item, judgement, caution)
    normalized_key = normalize_alert_section_key(bucket_key)
    item["user_alert_grade"] = classify_user_alert_grade(item, display_key=normalized_key)
    conclusion = get_watch_display_conclusion(item, judgement, caution, section_override=normalized_key)
    one_line = get_watch_one_line_text(item, caution, reason_text)
    bucket_label = get_watch_bucket_label(bucket_key)
    strategy = str(item.get("strategy", "") or "").strip()
    if strategy in {"PREWATCH", "NEWLOW_RECOVER"}:
        if bucket_key in {"early", "live"} and conclusion in {"м§ҖкёҲ л§ӨмҲҳ кёҲм§Җ", "м§ҖкёҲмқҖ кө¬кІҪл§Ң"}:
            conclusion = "м§ҖкёҲ ліјл§Ңн•Ё"
        elif bucket_key == "restart" and conclusion in {"м§ҖкёҲ л§ӨмҲҳ кёҲм§Җ", "м§ҖкёҲмқҖ кө¬кІҪл§Ң"}:
            conclusion = "лӢӨмӢң мӮ¬лҠ”м§Җ нҷ•мқё лЁјм Җ"
    if bucket_key in {"restart", "late", "watch"}:
        summary = one_line
        if bucket_key == "restart" and not summary:
            summary = "н•ң лІҲ мӣҖм§Ғмқё л’Ө лӢӨмӢң к°ҖлҠ”м§Җ лЁјм Җ нҷ•мқё"
        elif bucket_key == "late" and not summary:
            summary = "мқҙлҜё мҳ¬лқјмҳЁ мһҗлҰ¬лқј м§ҖкёҲ м¶”кІ©мқҖ кёҲм§Җ"
        elif bucket_key == "watch" and not summary:
            summary = "м§ҖкёҲмқҖ нқҗлҰ„л§Ң нҷ•мқё"
        lines = [
            highlight_line(order, item.get('ticker', '?'), icon),
            f"- мң нҳ•: {bucket_label}",
            f"- кІ°лЎ : {conclusion}",
            format_alert_price_line(item),
            format_alert_flow_line(item, short=False),
            format_recent_30m_price_context(ensure_pre_alert_snapshot(item), current_price=safe_float(item.get('current_price', item.get('price', 0)), 0)),
            format_recent_60m_price_context(item),
            format_recent_4h_price_context(item),
            format_daily_price_context(item),
            format_chart_quant_line(item, short=True),
            format_mtf_context_line(item, short=True),
            format_chart_context_line(item),
            format_current_candle_line(item),
            format_chart_lifecycle_line(item),
            f"- мҡ”м•Ҫ: {summary}",
        ]
        if alert_type in ["upgrade", "renotice"] and reason_text:
            reason_norm = reason_text.replace(" ", "").strip()
            summary_norm = summary.replace(" ", "").strip()
            if reason_norm and reason_norm != summary_norm:
                lines.append(f"- ліҖнҷ”: {reason_text}")
        return "\n".join(lines)
    lines = [
        highlight_line(order, item.get('ticker', '?'), icon),
        f"- мң нҳ•: {bucket_label}",
        f"- кІ°лЎ : {conclusion}",
        format_alert_price_line(item),
        f"- м „лһө: {item['strategy_label']} / л“ұкёү {get_watch_tier_text(item)} / мЈјлҸ„лҸ„ {safe_float(item.get('leader_score',0)):.2f}",
        format_alert_flow_line(item, short=(detail_level == 'normal')),
        format_recent_30m_price_context(ensure_pre_alert_snapshot(item), current_price=safe_float(item.get('current_price', item.get('price', 0)), 0)),
        format_recent_60m_price_context(item),
        format_recent_4h_price_context(item),
        format_daily_price_context(item),
        format_chart_quant_line(item, short=(detail_level != 'strong')),
        format_mtf_context_line(item, short=(detail_level != 'strong')),
        format_chart_context_line(item),
        format_current_candle_line(item),
        format_chart_lifecycle_line(item),
    ]
    if detail_level == "strong":
        lines.extend(build_alert_trade_plan_lines(item))
        if tag_text:
            lines.append(f"- кө¬мЎ°: {tag_text}")
    else:
        lines.extend(build_normal_alert_action_lines(item))
    if alert_type in ["upgrade", "renotice"] and reason_text:
        reason_norm = reason_text.replace(" ", "").strip()
        one_line_norm = one_line.replace(" ", "").strip() if one_line else ""
        if reason_norm and reason_norm != one_line_norm:
            lines.append(f"- ліҖнҷ”: {reason_text}")
    elif detail_level == "strong" and caution:
        lines.append(f"- мЈјмқҳ: {caution}")
    elif detail_level == "normal" and reason_text:
        lines.append(f"- м°ёкі : {reason_text}")
    return "\n".join(lines)
