def format_reverse_trace_ts(ts: float) -> str:
    try:
        return datetime.fromtimestamp(float(ts), ZoneInfo(TIMEZONE)).strftime('%m-%d %H:%M:%S')
    except Exception:
        return '--:--:--'

def format_htf_brief_for_row(row: dict) -> str:
    label = str(row.get('htf_setup_label', '') or 'нҷ•мқёмӨ‘').strip()
    trend = str(row.get('htf_trend_label', '') or '').strip()
    gap = safe_float(row.get('htf_gap_pct', 999), 999)
    rise = safe_float(row.get('htf_rise_pct', 0), 0)
    slope7 = safe_float(row.get('htf_ma7_slope_pct', 0), 0)
    slope30 = safe_float(row.get('htf_ma30_slope_pct', 0), 0)
    if 'лҚ°мқҙн„° л¶ҖмЎұ' in label or gap >= 900:
        return label
    suffix = f" / {trend}" if trend else ""
    return f"{label}{suffix} (кі м җкұ°лҰ¬ {gap:.2f}% / м Җм җлҢҖл№„ {rise:.2f}% / MA7кё°мҡёкё° {slope7:+.2f}% / MA30кё°мҡёкё° {slope30:+.2f}%)"

def format_daily_brief_for_row(row: dict) -> str:
    label = str(row.get('daily_setup_label', '') or 'нҷ•мқёмӨ‘').strip()
    gap = safe_float(row.get('daily_gap_pct', 999), 999)
    rise = safe_float(row.get('daily_rise_pct', 0), 0)
    return f"{label} (кі м җкұ°лҰ¬ {gap:.2f}% / м Җм җлҢҖл№„ {rise:.2f}%)"

def format_rank_line_for_reverse_trace(row: dict) -> str:
    parts = []
    for label, key in (("кұ°лһҳлҢҖкёҲ", "turnover_rank"), ("5л¶„", "change5_rank"), ("мЈјлӘ©", "leader_rank")):
        bit = format_rank_item(label, row.get(key, 0))
        if bit:
            parts.append(bit)
    return " / ".join(parts) if parts else "лӮҙл¶Җ мң мӮ¬ мҲңмң„ к°җмӢң кё°лЎқ"


def format_reverse_trace_block(row: dict, idx: int = 1) -> str:
    if not isinstance(row, dict):
        return ''
    try:
        row = apply_precision_minute1_state_to_row(dict(row)) if 'apply_precision_minute1_state_to_row' in globals() else dict(row)
    except Exception:
        row = dict(row)
    reason = str(row.get('reason', '') or '').strip()
    reasons = row.get('reasons', []) if isinstance(row.get('reasons', []), list) else []
    extra = ', '.join([str(x).strip() for x in reasons if str(x).strip()][:2])
    if reason and extra:
        reason_text = f"{reason} / {extra}"
    else:
        reason_text = reason or extra or '-'
    pattern_text = str(row.get('label_text', '') or '').strip()
    if not pattern_text:
        pattern_text = get_fast_scan_label_text(str(row.get('primary_reason', '') or ''))
    final_bucket_text = get_fast_scan_bucket_text(row.get('bucket', ''))
    if str(row.get('bucket', '') or '') == 'rank_watch':
        final_label = realtime_rank_watch_action_label(row)
    else:
        final_label = pattern_text if final_bucket_text == 'лӮҙл¶Җ к°җмӢң' else final_bucket_text
    rebreakout_gap_text = ''
    rebreakout_gap = safe_float(row.get('rebreakout_gap_pct', 999), 999)
    if 0 <= rebreakout_gap < 900:
        rebreakout_gap_text = f" / лӢЁкё°кі м җкұ°лҰ¬ {rebreakout_gap:.2f}%"
    ticker = str(row.get('ticker', '?') or '?').upper().strip()
    high_gap_text = format_pct_or_pending(row.get('below_30m_high_pct', row.get('below_high', 999)), pending_text="кі м җ кұ°лҰ¬ нҷ•мқё м•Ҳ лҗЁ", zero_text="кі м җ л°”лЎң к·јмІҳ")
    lines = [
        f"{circled_number(idx)} {ticker_review_icon(row)} {ticker}",
        f"- мӢңк°„: {format_reverse_trace_ts(safe_float(row.get('ts', 0), 0))}",
        f"- лӢЁкі„: {get_reverse_trace_stage_label(row.get('stage', ''))} / мөңмў…л¶„лҘҳ: {get_reverse_trace_bucket_display(row)} / л“ұкёү {str(row.get('grade', '-') or '-')}",
        f"- нҢЁн„ҙнғңк·ё: {pattern_text or '-'}",
        f"- мөңмў…нҢҗм •: {final_label}",
        f"- кё°лЎқлң»: {realtime_rank_watch_action_explain(row)}" if str(row.get('bucket', '') or '') == 'rank_watch' else '',
        f"- нқҗлҰ„: 1л¶„ {safe_float(row.get('change_1', 0), 0):+.2f}% / 3л¶„ {safe_float(row.get('change_3', 0), 0):+.2f}% / 5л¶„ {safe_float(row.get('change_5', 0), 0):+.2f}% / 15л¶„ {safe_float(row.get('change_15', 0), 0):+.2f}% / 30л¶„ {safe_float(row.get('change_30', 0), 0):+.2f}% / 1мӢңк°„ {safe_float(row.get('change_60', 0), 0):+.2f}%",
        f"- мң„м№ҳ: м Җм җлҢҖл№„ {safe_float(row.get('from_low', 0), 0):+.2f}% / мөңк·ј30л¶„ кі м җкұ°лҰ¬ {high_gap_text}",
        format_gap_context_line(row),
        format_chart_lifecycle_line(row),
        format_recent_30m_price_context(row, current_price=safe_float(row.get('current_price', row.get('price', 0)), 0), prefix='- мөңк·ј30л¶„ кё°мӨҖк°’'),
        format_recent_60m_price_context(row, prefix='- мөңк·ј60л¶„ кё°мӨҖк°’'),
        f"- мғҒмң„лҙү: 4мӢңк°„ {format_htf_brief_for_row(row)} / мқјлҙү {format_daily_brief_for_row(row)}",
        f"- нһҳ: кұ°лһҳлҹү {safe_float(row.get('vol_ratio', 0), 0):.2f}л°° / мӢңмһҘмЈјлӘ© {safe_float(row.get('leader_score', 0), 0):.2f} / мөңк·ј5л¶„ кұ°лһҳлҢҖкёҲ {format_money_for_row(row)}",
        format_reverse_trace_chart_line(row, rebreakout_gap_text=rebreakout_gap_text),
        f"- мҲңмң„: {format_rank_line_for_reverse_trace(row)}",
        f"- мқҙмң : {reason_text}",
    ]
    lines = [x for x in lines if str(x).strip()]
    return '\n'.join(lines)

def trace_recent_command(update, context: CallbackContext):
    load_reverse_trace_logs()
    limit = 5
    if getattr(context, 'args', None):
        try:
            limit = int(context.args[0])
        except Exception:
            limit = 5
    limit = max(1, min(limit, 10))
    rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    if not rows:
        send("рҹ§ӯ м•„м§Ғ м—ӯм¶”м Ғ кё°лЎқмқҙ м—Ҷм–ҙ\n\n- м•ҢлҰј/нӣ„ліҙк°Җ мЎ°кёҲ лҚ” мҢ“мқҙл©ҙ м—¬кё°м„ң мөңк·ј нқҗлҰ„мқ„ л°”лЎң ліј мҲҳ мһҲм–ҙ")
        return
    recent = rows[-limit:]
    lines = ['рҹ§ӯ мөңк·ј м—ӯм¶”м Ғ кё°лЎқ', '', f'- мөңк·ј {len(recent)}кұҙ']
    for idx, row in enumerate(reversed(recent), start=1):
        lines.append('')
        lines.append(format_reverse_trace_block(row, idx=idx))
    send_text_chunks('\n'.join(lines), limit=TG_MESSAGE_SOFT_LIMIT)

def trace_command(update, context: CallbackContext):
    load_reverse_trace_logs()
    args = list(getattr(context, 'args', []) or [])
    if not args:
        trace_recent_command(update, context)
        return
    ticker = str(args[0] or '').upper().strip()
    if not ticker:
        send("рҹ§ӯ мҪ”мқёлӘ…мқ„ к°ҷмқҙ м Ғм–ҙмӨҳ\n\nмҳҲ) /trace SPURS")
        return
    rows = [x for x in reverse_trace_logs if isinstance(x, dict) and str(x.get('ticker', '') or '').upper().strip() == ticker]
    if not rows:
        send(f"рҹ§ӯ {ticker} м—ӯм¶”м Ғ кё°лЎқмқҙ м•„м§Ғ м—Ҷм–ҙ\n\n- м•„м§Ғ нӣ„ліҙ/м•ҢлҰј кё°лЎқмқҙ м•Ҳ мҢ“мҳҖкұ°лӮҳ\n- лЎңк·ё м ҖмһҘ м „мқј мҲҳ мһҲм–ҙ")
        return
    recent = rows[-8:]
    lines = [f'рҹ§ӯ {ticker} м—ӯм¶”м Ғ кё°лЎқ', '', f'- мөңк·ј {len(recent)}кұҙ']
    for idx, row in enumerate(reversed(recent), start=1):
        lines.append('')
        lines.append(format_reverse_trace_block(row, idx=idx))
    send('\n'.join(lines))

