def get_btc_df():
    for interval in ["minute60", "minute30", "minute10"]:
        df = get_ohlcv("BTC", interval)
        if df is not None and len(df) >= 20:
            return df, interval
    df = get_ohlcv("BTC", "day")
    if df is not None and len(df) >= 20:
        return df, "day"
    return None, None
def get_btc_multi_tf_snapshot():
    snapshot = {}
    configs = [
        ("short", "minute10", 6),
        ("mid", "minute60", 6),
        ("day", "day", 3),
    ]
    for name, interval, bars in configs:
        try:
            df = get_ohlcv("BTC", interval)
            if df is None or len(df) < max(20, bars + 1):
                continue
            price = safe_float(df["close"].iloc[-1], 0)
            if price <= 0:
                continue
            change_pct = get_recent_change_pct(df, bars)
            ma20v = ma(df, 20)
            snapshot[name] = {
                "interval": interval,
                "price": price,
                "change_pct": change_pct,
                "ma20": ma20v,
                "above_ma20": (ma20v > 0 and price >= ma20v),
            }
        except Exception:
            continue
    return snapshot
def get_btc_market_state():
    df, _ = get_btc_df()
    if df is None:
        return True, "BTC мЎ°нҡҢ мӢӨнҢЁм§Җл§Ң м§„н–ү", 0.0
    price = get_price("BTC")
    if price <= 0:
        return True, "BTC нҳ„мһ¬к°Җ мЎ°нҡҢ мӢӨнҢЁм§Җл§Ң м§„н–ү", 0.0
    recent_drop_pct = get_recent_change_pct(df, 4)
    ma20 = ma(df, 20)
    if recent_drop_pct <= BTC_STRONG_BLOCK_PCT:
        return False, f"BTCк°Җ нҒ¬кІҢ л№ м§ҖлҠ” мӨ‘мқҙм•ј ({recent_drop_pct:.2f}%)", recent_drop_pct
    if recent_drop_pct <= BTC_CRASH_BLOCK_PCT:
        return False, f"BTCк°Җ м•Ҫн•ҙм„ң мӢ к·ң м§„мһ…мқ„ мү¬кі  мһҲм–ҙ ({recent_drop_pct:.2f}%)", recent_drop_pct
    if BTC_MA_FILTER and ma20 > 0 and price < ma20 * 0.992:
        return False, "BTCк°Җ м•Ҫн•ң мһҗлҰ¬лқј мӢ к·ң м§„мһ…мқ„ мү¬кі  мһҲм–ҙ", recent_drop_pct
    return True, "мӢңмһҘ л¶„мң„кё° л¬ҙлӮң", recent_drop_pct
def get_market_regime():
    snapshot = get_btc_multi_tf_snapshot()
    if not snapshot:
        return {
            "name": "UNKNOWN",
            "label": "unknown",
            "btc_change_pct": 0.0,
            "allow_auto_buy": True,
            "allow_breakout": True,
            "watch_entry_allowed": True,
            "watch_recovery_allowed": True,
            "message": "мӢңмһҘ мғҒнғң нҢҗлӢЁ мӢӨнҢЁ",
            "watch_message": "мӢңмһҘ мғҒнғңлҘј м•„м§Ғ лӘ» мқҪм—Ҳм–ҙ",
            "short_change_pct": 0.0,
            "mid_change_pct": 0.0,
            "day_change_pct": 0.0,
        }
    short = snapshot.get("short", {})
    mid = snapshot.get("mid", {})
    day = snapshot.get("day", {})
    short_change = safe_float(short.get("change_pct", 0), 0)
    mid_change = safe_float(mid.get("change_pct", short_change), short_change)
    day_change = safe_float(day.get("change_pct", mid_change), mid_change)
    weak_count = 0
    strong_count = 0
    if short:
        if short_change <= BTC_SHORT_WEAK_PCT:
            weak_count += 1
        if short_change >= 0.80 and bool(short.get("above_ma20", False)):
            strong_count += 1
    if mid:
        if mid_change <= BTC_MID_WEAK_PCT:
            weak_count += 1
        if not bool(mid.get("above_ma20", False)):
            weak_count += 1
        if mid_change >= REGIME_STRONG_UP_PCT and bool(mid.get("above_ma20", False)):
            strong_count += 1
    if day:
        if day_change <= BTC_DAY_WEAK_PCT:
            weak_count += 1
        if not bool(day.get("above_ma20", False)):
            weak_count += 1
        if day_change >= 1.20 and bool(day.get("above_ma20", False)):
            strong_count += 1
    if day_change <= BTC_DAY_BLOCK_PCT or mid_change <= BTC_STRONG_BLOCK_PCT:
        return {
            "name": "BLOCK",
            "label": "multi-tf",
            "btc_change_pct": mid_change,
            "allow_auto_buy": False,
            "allow_breakout": False,
            "watch_entry_allowed": False,
            "watch_recovery_allowed": False,
            "message": "BTCк°Җ м—¬лҹ¬ кө¬к°„м—җм„ң м•Ҫн•ҙм„ң мӢ к·ң м§„мһ…мқ„ мү¬лҠ” мһҘ",
            "watch_message": "мһҘ м•Ҫн•Ё В· к°җмӢңл§Ң н•ҳкі  м§„мһ…мқҖ мү¬кё°",
            "short_change_pct": short_change,
            "mid_change_pct": mid_change,
            "day_change_pct": day_change,
        }
    if weak_count >= 3 or (mid_change <= REGIME_WEAK_MAX_ABS_PCT and day_change <= 0):
        return {
            "name": "WEAK",
            "label": "multi-tf",
            "btc_change_pct": mid_change,
            "allow_auto_buy": True,
            "allow_breakout": False,
            "watch_entry_allowed": False,
            "watch_recovery_allowed": True,
            "message": "м•Ҫн•ң мһҘмқҙлқј м Җм җк¶Ң нӣ„ліҙлҸ„ ліҙмҲҳм ҒмңјлЎң лҙҗм•ј н•ҙ",
            "watch_message": "м•Ҫн•ң мһҘ В· нҡҢліө нӣ„ліҙк№Ңм§Җл§Ң ліҙкі  м§„мһ… мҠ№кІ©мқҖ лҚ” ліҙмҲҳм ҒмңјлЎң",
            "short_change_pct": short_change,
            "mid_change_pct": mid_change,
            "day_change_pct": day_change,
        }
    if abs(short_change) <= 0.45 and abs(mid_change) <= 0.85:
        return {
            "name": "SIDEWAYS",
            "label": "multi-tf",
            "btc_change_pct": mid_change,
            "allow_auto_buy": True,
            "allow_breakout": not REGIME_BLOCK_BREAKOUT_ON_SIDEWAYS,
            "watch_entry_allowed": True,
            "watch_recovery_allowed": True,
            "message": "нҡЎліҙ мһҘмқҙлқј кёүн•ң м¶”кІ©мқҖ мЎ°мӢ¬н•ҙм•ј н•ҙ",
            "watch_message": "нҡЎліҙ мһҘ В· лҠҰмқҖ м¶”кІ©мқҖ л§үкі  м Җм җк¶Ң нҡҢліөл§Ң лҚ” м—„кІ©н•ҳкІҢ ліҙкё°",
            "short_change_pct": short_change,
            "mid_change_pct": mid_change,
            "day_change_pct": day_change,
        }
    if strong_count >= 3:
        return {
            "name": "STRONG_UP",
            "label": "multi-tf",
            "btc_change_pct": mid_change,
            "allow_auto_buy": True,
            "allow_breakout": True,
            "watch_entry_allowed": True,
            "watch_recovery_allowed": True,
            "message": "м—¬лҹ¬ мӢңк°„лҢҖк°Җ к°ҷмқҙ мўӢм•„м„ң к°•н•ң мғҒмҠ№ мһҘмңјлЎң ліҙлҠ” мӨ‘",
            "watch_message": "мһҘ мўӢмқҢ В· нҡҢліө нӣ„ліҙк°Җ м§„мһ… нӣ„ліҙлЎң мҳ¬лқјк°Җкё° мү¬мҡҙ кө¬к°„",
            "short_change_pct": short_change,
            "mid_change_pct": mid_change,
            "day_change_pct": day_change,
        }
    return {
        "name": "NORMAL",
        "label": "multi-tf",
        "btc_change_pct": mid_change,
        "allow_auto_buy": True,
        "allow_breakout": True,
        "watch_entry_allowed": True,
        "watch_recovery_allowed": True,
        "message": "л¬ҙлӮңн•ң мһҘмқҙлқј кё°ліё кё°мӨҖлҢҖлЎң ліҙл©ҙ лҸј",
        "watch_message": "ліҙнҶө мһҘ В· кё°мӨҖлҢҖлЎң нӣ„ліҙлҘј ліҙл©ҙ лҸј",
        "short_change_pct": short_change,
        "mid_change_pct": mid_change,
        "day_change_pct": day_change,
    }
