def build_review_pack_text() -> str:
    now_ts = time.time()
    display = get_latest_scan_display_state(now_ts=now_ts, limit=8)
    user_items = list(display.get('user_items') or [])
    internal_items = list(display.get('internal_items') or [])
    discard_items = list(display.get('discard_items') or [])
    hidden_now_noise = [x for x in (user_items + internal_items + discard_items) if is_fast_scan_tiny_turnover_noise(x)]
    # кё°ліё ліөл¶ҷнҢ©м—җм„ңлҠ” мһЎмқҢ нӣ„ліҙлҘј мҲЁкё°кі , н•„мҡ”н•ҳл©ҙ review_dump/detailм—җм„ңл§Ң ліёлӢӨ.
    user_items = [x for x in user_items if not is_fast_scan_tiny_turnover_noise(x)]
    internal_items = [x for x in internal_items if not is_fast_scan_tiny_turnover_noise(x)]
    discard_items = [x for x in discard_items if not is_fast_scan_tiny_turnover_noise(x)]
    note = format_scan_display_state_line(display)
    load_reverse_trace_logs()
    trace_rows = [x for x in reverse_trace_logs if isinstance(x, dict)]
    recent_trace = list(reversed(trace_rows[-80:]))
    seen = set()
    trace_compact = []
    hidden_trace_noise = 0
    for row in recent_trace:
        tk = str(row.get('ticker', '') or '').upper().strip()
        if not tk or tk in seen:
            continue
        if is_review_trace_tiny_noise(row):
            hidden_trace_noise += 1
            seen.add(tk)
            continue
        seen.add(tk)
        trace_compact.append(row)
        if len(trace_compact) >= REVIEW_PACK_TRACE_LIMIT:
            break
    try:
        health = build_scan_health_text(compact=True)
    except TypeError:
        health = build_scan_health_text()
    except Exception as e:
        health = f"мҠӨмә”м§„лӢЁ мғқм„ұ мӢӨнҢЁ: {e}"
    lines = [
        "рҹ§© лҰ¬л·°нҢ© вҖ” ліөл¶ҷмҡ© н•өмӢ¬ мҡ”м•Ҫ",
        f"- мӢңк°Ғ: {now_kst().strftime('%m-%d %H:%M:%S')}",
        f"- мҠӨмә”: {note}",
        f"- нӣ„ліҙ: л°”лЎң {len(user_items)} / кҙҖм°° {len(internal_items)} / лӮҙл¶Җкё°лЎқ {len(discard_items)}" + (f" / кұ°лһҳлҢҖкёҲ мһЎмқҢ мҲЁк№Җ {len(hidden_now_noise)}" if hidden_now_noise else ""),
        "- мқҙ лӮҙмҡ©л§Ң ліҙлӮҙлҸ„ кё°ліё л¶„м„қмқҖ к°ҖлҠҘ. нҠ№м • мҪ”мқёмқҙ к¶ҒкёҲн•ҳл©ҙ м•„лһҳ мғҒм„ё лӘ…л №л§Ң м¶”к°ҖлЎң ліҙлӮҙл©ҙ лҗЁ",
        "",
        "рҹ©ә [мҠӨмә” н•өмӢ¬]",
    ]
    for ln in str(health).splitlines()[:16]:
        if ln.strip():
            lines.append(ln)
    rows_now = user_items + internal_items + discard_items
    lines += ["", "рҹ“Ң [нҳ„мһ¬ нӣ„ліҙ м••м¶•]"]
    if not rows_now:
        lines.append("- м—ҶмқҢ")
    else:
        for idx, it in enumerate(rows_now[:8], start=1):
            tk = str(it.get('ticker', '?') or '?').upper()
            bucket = get_fast_scan_bucket_text(it.get('alert_bucket', ''))
            grade = str(it.get('alert_grade', it.get('user_alert_grade', '-')) or '-')
            gap_text = format_pct_or_pending(it.get('below_high', it.get('below_30m_high_pct',999)), pending_text="нҷ•мқё м•Ҳ лҗЁ", zero_text="кі м җ к·јмІҳ")
            money_text = format_money_for_row(it)
            lines.append(f"{idx}. {ticker_review_icon(it)} {tk} / {bucket} / {grade} / 5л¶„ {safe_float(it.get('change_5',0),0):+.2f}% / 30л¶„ {safe_float(it.get('change_30',0),0):+.2f}% / м Җм җ+{safe_float(it.get('from_low',0),0):.2f}% / кі м җкұ°лҰ¬ {gap_text} / лҸҲ {money_text}")
    lines += ["", "рҹ§ӯ [мөңк·ј м—ӯм¶”м Ғ м••м¶•]"]
    if hidden_trace_noise:
        lines.append(f"- кұ°лһҳлҢҖкёҲ мһЎмқҢ {hidden_trace_noise}к°ң мҲЁк№Җ")
    if not trace_compact:
        lines.append("- мӢӨм „м„ұ мһҲлҠ” мөңк·ј м—ӯм¶”м Ғ м—ҶмқҢ")
    else:
        for idx, row in enumerate(trace_compact, start=1):
            lines.append(format_reverse_trace_catalog_line(row, repeat=1, idx=idx))
    lines += ["", "рҹ§· [м¶”к°ҖлЎң н•„мҡ”н•  л•Ңл§Ң]", "- нҠ№м • мҪ”мқё мғҒм„ё: /review_trace_detail мҪ”мқёлӘ…", "- мӣҗліё 1/2/3мӘҪ лІ„нҠј: /review_full", "- м „мІҙ лҚӨн”„: /review_dump"]
    return "\n".join(lines)

def collect_review_pack_detail_tickers(limit: int = 12) -> list:
    """review_pack/checkм—җ л¶ҷмқј мғҒм„ё лІ„нҠј нӣ„ліҙлҘј к°ҖліҚкІҢ лӘЁмқҖлӢӨ."""
    out = []
    seen = set()
    def add(tk):
        tk = str(tk or '').upper().strip()
        if tk and tk not in seen:
            seen.add(tk)
            out.append(tk)
    try:
        display = get_latest_scan_display_state(now_ts=time.time(), limit=8)
        rows_now = list(display.get('user_items') or []) + list(display.get('internal_items') or []) + list(display.get('discard_items') or [])
        for it in rows_now:
            if len(out) >= limit:
                break
            if isinstance(it, dict) and not is_fast_scan_tiny_turnover_noise(it):
                add(it.get('ticker'))
    except Exception:
        pass
    try:
        load_reverse_trace_logs()
        for row in reversed([x for x in reverse_trace_logs if isinstance(x, dict)][-120:]):
            if len(out) >= limit:
                break
            if is_review_trace_tiny_noise(row):
                continue
            add(row.get('ticker'))
    except Exception:
        pass
    try:
        rank_rows = get_light_snapshot_rank_rows(limit=10, min_move_pct=REALTIME_RANK_MIN_RECORD_MOVE_PCT)
        for row in rank_rows:
            if len(out) >= limit:
                break
            add(row.get('ticker'))
    except Exception:
        pass
    return out[:max(1, int(limit or 12))]


def build_review_pack_detail_keyboard(limit: int = 12):
    return build_detail_buttons_for_tickers(collect_review_pack_detail_tickers(limit=limit), max_buttons=limit, per_row=2)


def build_check_text() -> str:
    """мғҒнғң + мҠӨмә”н—¬мҠӨ + лҰ¬л·°нҢ©мқ„ н•ң лІҲм—җ ліҙлҠ” м••м¶• м җкІҖ."""
    now_ts = time.time()
    try:
        display = get_latest_scan_display_state(now_ts=now_ts, limit=8)
    except Exception:
        display = {}
    user_items = list(display.get('user_items') or [])
    internal_items = list(display.get('internal_items') or [])
    discard_items = list(display.get('discard_items') or [])
    hidden_now_noise = [x for x in (user_items + internal_items + discard_items) if is_fast_scan_tiny_turnover_noise(x)]
    user_items = [x for x in user_items if not is_fast_scan_tiny_turnover_noise(x)]
    internal_items = [x for x in internal_items if not is_fast_scan_tiny_turnover_noise(x)]
    discard_items = [x for x in discard_items if not is_fast_scan_tiny_turnover_noise(x)]
    note = format_scan_display_state_line(display) if display else 'мҠӨмә” мғҒнғң нҷ•мқёмӨ‘'
    lines = [
        'вң… л№ лҘё м җкІҖ /check',
        f'- мӢңк°Ғ: {now_kst().strftime("%m-%d %H:%M:%S")}',
        '',
        '1) мғҒнғң',
        f'- мһҗлҸҷл§ӨмҲҳ: {"мјңм§җ" if AUTO_BUY else "кәјм§җ"}',
        f'- ліҙмң  нҸ¬м§Җм…ҳ: {len(active_positions)}к°ң' if active_positions else '- ліҙмң  нҸ¬м§Җм…ҳ: м—ҶмқҢ',
        f'- нӣ„ліҙ: л°”лЎң {len(user_items)} / кҙҖм°° {len(internal_items)} / лӮҙл¶Җкё°лЎқ {len(discard_items)}' + (f' / мһЎмқҢмҲЁк№Җ {len(hidden_now_noise)}' if hidden_now_noise else ''),
        f'- кё°мӨҖ: {note}',
        '',
        '2) мҠӨмә”н—¬мҠӨ м••м¶•',
    ]
    try:
        health_lines = str(build_scan_health_text(compact=True)).splitlines()
        for ln in health_lines[:18]:
            if ln.strip():
                lines.append(ln)
    except Exception as e:
        lines.append(f'- мҠӨмә”н—¬мҠӨ мғқм„ұ мӢӨнҢЁ: {e}')
    rows_now = user_items + internal_items + discard_items
    lines += ['', '3) лҰ¬л·°нҢ© м••м¶•', 'рҹ“Ң нҳ„мһ¬ нӣ„ліҙ']
    if not rows_now:
        lines.append('- м—ҶмқҢ')
    else:
        for idx, it in enumerate(rows_now[:6], start=1):
            tk = str(it.get('ticker', '?') or '?').upper()
            bucket = get_fast_scan_bucket_text(it.get('alert_bucket', ''))
            grade = str(it.get('alert_grade', it.get('user_alert_grade', '-')) or '-')
            money_text = format_money_for_row(it)
            lines.append(f'{idx}. {ticker_review_icon(it)} {tk} / {bucket} / {grade} / 5л¶„ {safe_float(it.get("change_5",0),0):+.2f}% / 30л¶„ {safe_float(it.get("change_30",0),0):+.2f}% / лҸҲ {money_text}')
    lines += ['', 'рҹ§ӯ мөңк·ј м—ӯм¶”м Ғ']
    try:
        load_reverse_trace_logs()
        trace_rows = list(reversed([x for x in reverse_trace_logs if isinstance(x, dict)][-100:]))
        seen = set()
        shown = 0
        hidden_trace_noise = 0
        for row in trace_rows:
            tk = str(row.get('ticker', '') or '').upper().strip()
            if not tk or tk in seen:
                continue
            seen.add(tk)
            if is_review_trace_tiny_noise(row):
                hidden_trace_noise += 1
                continue
            lines.append(format_reverse_trace_catalog_line(row, repeat=1, idx=shown + 1))
            shown += 1
            if shown >= 5:
                break
        if hidden_trace_noise:
            lines.append(f'- кұ°лһҳлҢҖкёҲ мһЎмқҢ {hidden_trace_noise}к°ң мҲЁк№Җ')
        if shown <= 0:
            lines.append('- мӢӨм „м„ұ мһҲлҠ” мөңк·ј м—ӯм¶”м Ғ м—ҶмқҢ')
    except Exception as e:
        lines.append(f'- м—ӯм¶”м Ғ м••м¶• мғқм„ұ мӢӨнҢЁ: {e}')
    lines += ['', 'рҹ§· лҚ” ліј л•Ң: /rank_watch, /review_dump', '- нҠ№м • мҪ”мқёмқҖ м•„лһҳ мғҒм„ё лІ„нҠј лҳҗлҠ” /review_trace_detail мҪ”мқёлӘ…']
    return "\n".join(lines)


