def review_navigation_callback(update, context: CallbackContext):
    """review_trace кҙҖл Ё мқёлқјмқё лІ„нҠј мІҳлҰ¬."""
    query = getattr(update, 'callback_query', None)
    if not query:
        return
    try:
        query.answer()
    except Exception:
        pass
    data = str(getattr(query, 'data', '') or '')
    try:
        if data.startswith('rv:detail:'):
            ticker = data.split(':', 2)[-1].upper().strip()
            if not ticker:
                send("вҡ пёҸ мғҒм„ёлҘј ліј мҪ”мқёлӘ…мқҙ м—Ҷм–ҙ")
                return
            send_text_chunks(build_review_trace_detail_text(ticker), prefix="")
            return
        if data.startswith('rv:full:'):
            try:
                page = int(data.split(':')[-1])
            except Exception:
                page = 1
            total, total_pages, _page_size = _review_trace_total_pages()
            keyboard = build_review_trace_full_keyboard(page=page, total_pages=total_pages) if total > 0 else None
            send_text_chunks(build_review_trace_page_text(page=page), prefix="", reply_markup=keyboard)
            return
        if data == 'rv:trace':
            send_text_chunks(build_review_trace_grouped_text(limit=REVIEW_TRACE_GROUPED_DISPLAY_LIMIT), prefix="")
            return
        if data == 'rv:pack':
            send_text_chunks(build_review_pack_text(), prefix="")
            return
        send("вҡ пёҸ м•Ң мҲҳ м—ҶлҠ” review лІ„нҠјмқҙм•ј")
    except Exception as e:
        send(f"вҡ пёҸ review лІ„нҠј мІҳлҰ¬ м—җлҹ¬: {e}")


def build_review_dump_text(alert_limit: int = 20, missed_limit: int = 20, trace_limit: int = REVIEW_DUMP_TRACE_DISPLAY_LIMIT) -> str:
    sections = build_review_dump_sections(alert_limit=alert_limit, missed_limit=missed_limit, trace_limit=trace_limit)
    parts = []
    for _name, body in sections:
        body = str(body or "").strip()
        if body:
            parts.append(body)
    return "\n\n".join(parts)

def build_review_dump_sections(alert_limit: int = 20, missed_limit: int = 20, trace_limit: int = REVIEW_DUMP_TRACE_DISPLAY_LIMIT):
    sections = []
    try:
        scan_display_at_start = get_latest_scan_display_state(now_ts=time.time(), limit=50)
    except Exception:
        scan_display_at_start = None
    sections.append((
        "header",
        "\n".join([
            "рҹ§ҫ review_dump",
            f"- мӢңк°Ғ: {now_kst().strftime('%m-%d %H:%M:%S')}",
            "- м°ёкі : лӮҙл¶Җ мҠӨмә”мқҙ лҜёлҰ¬ м ҖмһҘн•ң мҠӨлғ…мғ· кё°мӨҖмңјлЎң ліҙм—¬мӨҳ",
            "- нҳ„мһ¬ мҠӨмә” мғҒнғңлҠ” лӘ…л № мһ…л Ҙ мӢңм җ кё°мӨҖмқҙкі , м•„лһҳ ліөкё° н‘ңліёмқҖ кіјкұ° кё°лЎқмқҙ м„һм—¬ мһҲм–ҙ",
            "- review_dumpлҠ” л¶„м„қмҡ©мқҙм§Җл§Ң мӨ‘ліө мӣҗліёмқҖ м •лҰ¬н•ҙм„ң ліҙм—¬мӨҳ",
            "- м§§кІҢ ліј л•ҢлҠ” /review_pack лҳҗлҠ” /review мӮ¬мҡ©",
            "- мӣҗліёмқҖ /review_fullм—җм„ң 1мӘҪ/2мӘҪ лІ„нҠјмңјлЎң нҷ•мқё",
        ])
    ))

    try:
        detail_index = build_review_dump_rich_detail_index(scan_display_at_start)
    except Exception:
        detail_index = {}

    try:
        sections.append(("quick_summary", build_review_dump_quick_summary(scan_display_at_start)))
    except Exception as e:
        sections.append(("quick_summary", f"рҹ“Ң л№ лҘё мҡ”м•Ҫ\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        _alert_rows_for_cross = collect_recent_alert_review_rows(limit=80, summary_limit=80)
        _missed_rows_for_cross = get_all_missed_review_rows(include_supplemental=True, supplemental_limit=300)
        sections.append(("bithumb_strength_crosscheck", build_review_dump_bithumb_strength_crosscheck_section(scan_display_at_start, detail_index=detail_index, alert_rows=_alert_rows_for_cross, missed_rows=_missed_rows_for_cross, limit=30)))
    except Exception as e:
        sections.append(("bithumb_strength_crosscheck", f"рҹ“Ҡ [лҙҮ лӮҙл¶Җ к°•м„ё мәҗмӢң лҢҖмЎ°мҡ©]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("rank_missing", build_review_dump_rank_missing_section(scan_display_at_start, detail_index=detail_index, limit=REALTIME_RANK_DISPLAY_LIMIT)))
    except Exception as e:
        sections.append(("rank_missing", f"рҹҡЁ [мҲңмң„к¶Ң лҲ„лқҪ мқҳмӢ¬]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("scan_debug", build_review_dump_current_candidates_detail(scan_display_at_start, limit_each=4, detail_index=detail_index)))
    except Exception as e:
        sections.append(("scan_debug", f"[нҳ„мһ¬ нӣ„ліҙ мғҒм„ё / м°ЁнҠё м •көҗнҷ” м „мІҙ н‘ңмӢң]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("internal_watch_tracking", format_internal_watch_tracking_report(limit=12)))
    except Exception as e:
        sections.append(("internal_watch_tracking", f"рҹ§Ә [лӮҙл¶Җ к°җмӢң м„ұкіјм¶”м Ғ]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("no_scan_check", build_review_dump_no_scan_check_section()))
    except Exception as e:
        sections.append(("no_scan_check", f"рҹ§Ҝ [лӘ…л №м–ҙ no-scan м җкІҖ]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("scan_health", build_scan_health_text()))
    except Exception as e:
        sections.append(("scan_health", f"[мҠӨмә” мғҒнғң м§„лӢЁ]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        alert_rows = collect_recent_alert_review_rows(limit=max(1, int(alert_limit)), summary_limit=max(20, int(alert_limit)))
        if not alert_rows:
            sections.append(("alerts", "рҹ“Ё [мөңк·ј м•ҢлҰј]\n- м•„м§Ғ мөңк·ј м•ҢлҰј н‘ңліёмқҙ м—Ҷм–ҙ"))
        else:
            summary = summarize_alert_review_rows(alert_rows[:max(20, int(alert_limit))])
            lines = [
                "рҹ“Ё [мөңк·ј м•ҢлҰј мҡ”м•Ҫ]",
                f"- мўӢмқҖн‘ңліё {summary.get('good', 0)}кұҙ / ліҙмЎ°н‘ңліё {summary.get('assist', 0)}кұҙ / к°Җм§ңмғҒмҠ№ {summary.get('spike', 0)}кұҙ / м•Ҫн•Ё {summary.get('weak', 0)}кұҙ / мӢӨнҢЁ {summary.get('bad', 0)}кұҙ",
                "",
                f"[мөңк·ј м•ҢлҰј {min(len(alert_rows), alert_limit)}кұҙ]",
            ]
            for idx, row in enumerate(alert_rows[:alert_limit], start=1):
                lines += ["", format_alert_review_block(row, idx=idx)]
            sections.append(("alerts", "\n".join(lines)))
    except Exception as e:
        sections.append(("alerts", f"рҹ“Ё [мөңк·ј м•ҢлҰј]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        missed_rows = get_all_missed_review_rows(include_supplemental=True, supplemental_limit=max(300, int(missed_limit) if int(missed_limit) < 1000 else 300))
        if not missed_rows:
            sections.append(("missed", "рҹҺЈ [лҶ“м№ң к°•н•ң мӣҖм§Ғмһ„]\n- м•„м§Ғ лҶ“м№ң н‘ңліёмқҙ м—Ҷм–ҙ"))
        else:
            summary = summarize_missed_review_logs(missed_rows[-max(20, min(len(missed_rows), int(missed_limit))):])
            lines = [
                "рҹҺЈ [лҶ“м№ң к°•н•ң мӣҖм§Ғмһ„ мҡ”м•Ҫ]",
                f"- нғҗмғү лҶ“м№Ё {summary.get('нғҗмғү лҶ“м№Ё', 0)}кұҙ / мҠ№кІ© лҶ“м№Ё {summary.get('мҠ№кІ© лҶ“м№Ё', 0)}кұҙ / лҠҰм–ҙм„ң м•Ҳ мҳ¬лҰј {summary.get('лҠҰм–ҙм„ң м•Ҳ мҳ¬лҰј', 0)}кұҙ / л¶„лҘҳ лҶ“м№Ё {summary.get('л¶„лҘҳ лҶ“м№Ё', 0)}кұҙ / мӣҖм§ҒмҳҖм§Җл§Ң м• л§Ө {summary.get('мӣҖм§ҒмҳҖм§Җл§Ң м• л§Ө', 0)}кұҙ / лҚ°мқҙн„° мӢӨнҢЁ {summary.get('лҚ°мқҙн„° мӢӨнҢЁ', 0)}кұҙ",
                "",
                f"[лҶ“м№ң к°•н•ң мӣҖм§Ғмһ„ мғҒм„ё {min(len(missed_rows), missed_limit)}/{len(missed_rows)}кұҙ]",
            ]
            for idx, row in enumerate(reversed(missed_rows[-missed_limit:]), start=1):
                lines += ["", format_missed_review_log_block(row, idx=idx)]
            sections.append(("missed", "\n".join(lines)))
    except Exception as e:
        sections.append(("missed", f"рҹҺЈ [лҶ“м№ң к°•н•ң мӣҖм§Ғмһ„]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        cache_for_hourly = shared_market_cache if isinstance(shared_market_cache, dict) else {}
        sections.append(("hourly_momentum", format_hourly_momentum_watch_report(cache_for_hourly, limit=8, detail_index=detail_index)))
    except Exception as e:
        sections.append(("hourly_momentum", f"[1мӢңк°„ кёүл“ұ к°җмӢңнҢҗ]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("trace", build_review_dump_trace_grouped_section(trace_limit=max(1, int(trace_limit)), raw_window=160)))
    except Exception as e:
        sections.append(("trace", f"[мөңк·ј м—ӯм¶”м Ғ]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    try:
        sections.append(("internal_failures", collect_internal_failure_summary_for_review_dump(limit=15)))
    except Exception as e:
        sections.append(("internal_failures", f"рҹ§Ҝ [лӮҙл¶Җ мӢӨнҢЁ/лҚ°мқҙн„° мҳӨлҘҳ]\n- мғқм„ұ мҳӨлҘҳ: {e}"))

    return sections

