def fills_command(update, context: CallbackContext):
    rows = get_recent_buy_fill_logs(limit=10)
    if not rows:
        send("рҹ“Ҹ м•„м§Ғ мІҙкІ° н’Ҳм§Ҳмқ„ ліј л§ӨмҲҳ кё°лЎқмқҙ м—Ҷм–ҙ")
        return
    gap_values = [safe_float(x.get("entry_gap_pct", 0), 0) for x in rows]
    avg_gap = sum(gap_values) / len(gap_values) if gap_values else 0.0
    late_count = len([x for x in gap_values if x >= 0.35])
    lines = [
        "рҹ“Ҹ мөңк·ј мІҙкІ° н’Ҳм§Ҳ",
        "",
        f"- мөңк·ј л§ӨмҲҳ {len(rows)}кұҙ",
        f"- нҸүк·  мІҙкІ° м°Ёмқҙ {avg_gap:+.2f}%",
        f"- лҠҰкІҢ мІҙкІ°лҗң нҺё( +0.35% мқҙмғҒ ) {late_count}кұҙ",
        "",
        "[мөңк·ј 10кұҙ]",
    ]
    for idx, row in enumerate(rows, start=1):
        gap_pct = safe_float(row.get("entry_gap_pct", 0), 0)
        signal_price = safe_float(row.get("signal_price", 0), 0)
        signal_text = fmt_price(signal_price) if signal_price > 0 else "-"
        lines += [
            "",
            f"{circled_number(idx)} {row.get('ticker', '?')} / {row.get('strategy_label', '-')}",
            f"- м•ҢлҰјк°Җ {signal_text} / мІҙкІ°к°Җ {fmt_price(row.get('entry', 0))} / м°Ёмқҙ {gap_pct:+.2f}%",
            f"- мӮ¬мҡ©кёҲм•Ў {fmt_price(row.get('used_krw', 0))} / л“ұкёү {row.get('trade_tier', '-')}",
        ]
    send("\n".join(lines))

