def get_scan_debug_candidate_section(change_5: float, vol_ratio: float, leader_score: float, rsi: float) -> str:
    change_5 = safe_float(change_5, 0)
    vol_ratio = safe_float(vol_ratio, 0)
    leader_score = safe_float(leader_score, 0)
    rsi = safe_float(rsi, 50)
    if change_5 >= 1.90 and vol_ratio < 6.00:
        return "weak"
    if rsi >= 84:
        return "weak"
    if change_5 >= 0.25 and vol_ratio >= 1.55 and leader_score >= 0.45:
        return "strong"
    if (change_5 >= 0.05 and vol_ratio >= 1.15 and leader_score >= 0.25) or (vol_ratio >= 2.20 and leader_score >= 0.20):
        return "watch"
    return "weak"
def build_scan_debug_reasons(change_5: float, vol_ratio: float, leader_score: float, rsi: float, section: str = ""):
    change_5 = safe_float(change_5, 0)
    vol_ratio = safe_float(vol_ratio, 0)
    leader_score = safe_float(leader_score, 0)
    rsi = safe_float(rsi, 50)
    section = section or get_scan_debug_candidate_section(change_5, vol_ratio, leader_score, rsi)
    if section == "strong":
        return ["мҙҲмһ… к°ҖлҠҘ нӣ„ліҙ"]
    if section == "watch":
        return ["мҙҲмһ…/нҡҢліө нҷ•мқё нӣ„ліҙ"]
    reasons = []
    if change_5 <= -0.05:
        reasons.append("5л¶„ нһҳмқҙ м•„м§Ғ м—ҶмқҢ")
    elif change_5 < 0.05:
        reasons.append("5л¶„ мғҒмҠ№мқҙ м•„м§Ғ м•Ҫн•Ё")
    if vol_ratio < 1.15:
        reasons.append("кұ°лһҳлҹүмқҙ м•„м§Ғ м•Ҫн•Ё")
    if leader_score < 0.25:
        reasons.append("мӢңмһҘмЈјлӘ©лҸ„к°Җ м•„м§Ғ м•Ҫн•Ё")
    if rsi >= 84 or (change_5 >= 1.90 and vol_ratio < 6.00):
        reasons.append("л„Ҳл¬ҙ л№ лҘҙкІҢ мҳӨлҘё нҺё")
    if not reasons:
        reasons.append("м§ҖкёҲмқҖ кө¬кІҪл§Ң")
    return reasons
def normalize_scan_debug_score(base_score: float, change_5: float, vol_ratio: float, leader_score: float, rsi: float, turnover: float = 0.0) -> float:
    score = min(max(safe_float(base_score, 0), 0), 38.0)
    change_5 = safe_float(change_5, 0)
    vol_ratio = safe_float(vol_ratio, 0)
    leader_score = safe_float(leader_score, 0)
    rsi = safe_float(rsi, 50)
    turnover = safe_float(turnover, 0)
    score += min(max(change_5, 0), 1.80) * 4.6
    score += min(max(vol_ratio - 1.0, 0), 5.0) * 1.3
    score += min(leader_score, 4.0) * 1.5
    score += min(turnover / 1000000000.0, 2.2)
    if change_5 <= 0:
        score = min(score, 14.0)
        score -= 8.0
    elif change_5 < 0.18:
        score = min(score, 20.0)
        score -= 4.5
    elif change_5 < 0.35:
        score = min(score, 28.0)
        score -= 1.5
    if vol_ratio >= 10.0 and change_5 <= 0.25:
        score = min(score, 16.0)
    if rsi >= 82:
        score = min(score, 18.0)
        score -= 2.0
    return round(max(score, 0.0), 2)
def finalize_scan_debug_item(raw_item: dict) -> dict:
    item = dict(raw_item or {})
    change_5 = safe_float(item.get("change_5", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader_score = safe_float(item.get("leader_score", 0), 0)
    rsi = safe_float(item.get("rsi", 50), 50)
    turnover = safe_float(item.get("turnover", 0), 0)
    base_score = safe_float(item.get("lite_score", 0), 0)
    section = get_scan_debug_candidate_section(change_5, vol_ratio, leader_score, rsi)
    item["section"] = section
    item["section_rank"] = {"strong": 2, "watch": 1, "weak": 0}.get(section, 0)
    item["lite_score"] = normalize_scan_debug_score(base_score, change_5, vol_ratio, leader_score, rsi, turnover)
    item["reasons"] = build_scan_debug_reasons(change_5, vol_ratio, leader_score, rsi, section=section)
    return item
def get_recent_watch_snapshot_items(limit=8):
    try:
        now_ts = time.time()
        items = []
        for ticker, snap in recent_watch_snapshots.items():
            if not isinstance(snap, dict):
                continue
            saved_at = safe_float(snap.get("saved_at", now_ts))
            age = int(now_ts - saved_at)
            if age > 1800:
                continue
            items.append(finalize_scan_debug_item({
                "ticker": ticker,
                "price": safe_float(snap.get("price", 0)),
                "change_5": safe_float(snap.get("change_5", snap.get("change_pct", 0))),
                "vol_ratio": safe_float(snap.get("vol_ratio", 0)),
                "leader_score": safe_float(snap.get("leader_score", 0)),
                "turnover": safe_float(snap.get("turnover", 0)),
                "lite_score": safe_float(snap.get("edge_score", snap.get("signal_score", 0))),
                "rsi": safe_float(snap.get("rsi", 50)),
                "saved_at": saved_at,
            }))
        items.sort(key=lambda x: (safe_float(x.get("section_rank", 0)), safe_float(x.get("lite_score", 0)), safe_float(x.get("saved_at", 0))), reverse=True)
        return items[:limit]
    except Exception:
        return []
def get_scan_debug_candidates_legacy():
    try:
        now_ts = time.time()
        cache_age = int(now_ts - shared_market_cache_time) if shared_market_cache_time else None
        snapshot_age = int(now_ts - last_scan_debug_snapshot_time) if last_scan_debug_snapshot_time else None
        def build_items_from_cache(cache_dict, limit=8):
            items = []
            if not isinstance(cache_dict, dict):
                return items
            for ticker, data in cache_dict.items():
                try:
                    price = safe_float(data.get("price", 0))
                    if price <= 0:
                        continue
                    change_1 = safe_float(data.get("change_1", 0))
                    change_3 = safe_float(data.get("change_3", 0))
                    change_5 = safe_float(data.get("change_5", 0))
                    vol_ratio = safe_float(data.get("vol_ratio", data.get("vol_ratio_1m", 0)))
                    leader = safe_float(data.get("leader_score", 0))
                    turnover = safe_float(data.get("turnover", 0))
                    rsi = safe_float(data.get("rsi", data.get("rsi_1m", 50)))
                    raw_score = (
                        max(change_5, 0) * 6.5
                        + max(change_3, 0) * 3.2
                        + max(change_1, 0) * 1.6
                        + max(vol_ratio - 1.0, 0) * 3.0
                        + min(turnover / 1000000000.0, 3.0)
                        + leader * 4.0
                    )
                    items.append(finalize_scan_debug_item({
                        "ticker": ticker,
                        "price": price,
                        "change_5": change_5,
                        "vol_ratio": vol_ratio,
                        "leader_score": leader,
                        "turnover": turnover,
                        "lite_score": raw_score,
                        "rsi": rsi,
                    }))
                except Exception:
                    continue
            items.sort(
                key=lambda x: (
                    safe_float(x.get("section_rank", 0)),
                    safe_float(x.get("lite_score", 0)),
                    safe_float(x.get("change_5", 0)),
                    safe_float(x.get("turnover", 0)),
                ),
                reverse=True,
            )
            return items[:limit]
        # 1мҲңмң„: мөңк·ј shared cache м§Ғм ‘ мӮ¬мҡ© (к°ҖмһҘ л№ лҰ„)
        debug_cache_max_age = 900
        if shared_market_cache and cache_age is not None and cache_age <= debug_cache_max_age:
            items = build_items_from_cache(shared_market_cache, limit=8)
            if items:
                note = f"мөңк·ј {cache_age}мҙҲ м•Ҳм—җ лӘЁмқҖ мӢңмһҘ лҚ°мқҙн„° кё°мӨҖ"
                if cache_age > 180:
                    note += " (мЎ°кёҲ м§ҖлӮң лҚ°мқҙн„°)"
                return items, note
        # 2мҲңмң„: мөңк·ј scan_debug мҠӨлғ…мғ· fallback
        if isinstance(last_scan_debug_snapshot, dict) and last_scan_debug_snapshot and snapshot_age is not None and snapshot_age <= 1800:
            items = build_items_from_cache(last_scan_debug_snapshot, limit=8)
            if items:
                note = f"мөңк·ј {snapshot_age}мҙҲ м•Ҳм—җ м ҖмһҘлҗң мӢңмһҘ мҠӨлғ…мғ· кё°мӨҖ"
                if snapshot_age > 300:
                    note += " (мЎ°кёҲ м§ҖлӮң лҚ°мқҙн„°)"
                return items, note
        # 3мҲңмң„: мөңк·ј нӣ„ліҙ мҠӨлғ…мғ·
        recent_items = [x for x in get_recent_watch_snapshot_items(limit=12) if str(x.get("section", "")) != "weak"]
        if recent_items:
            return recent_items[:8], "л°©кёҲ мһЎнһҢ нӣ„ліҙ кё°мӨҖ"
        # 4мҲңмң„: м§ҖкёҲмқҖ кё°лӢӨлҰҙ нӣ„ліҙ(pending) fallback
        if pending_buy_candidates:
            items = []
            sorted_candidates = sorted(
                pending_buy_candidates.values(),
                key=lambda x: (safe_float(x.get("leader_score", 0)) * 0.8) + safe_float(x.get("edge_score", 0)),
                reverse=True,
            )[:8]
            for row in sorted_candidates:
                ticker = str(row.get("ticker", "?") or "?")
                if is_watch_excluded_ticker(ticker):
                    continue
                price = safe_float(row.get("first_price", 0))
                score = safe_float(row.get("edge_score", 0))
                leader = safe_float(row.get("leader_score", 0))
                strategy_label = str(row.get("strategy_label", "?") or "?")
                seen_count = int(safe_float(row.get("seen_count", 1), 1))
                item = finalize_scan_debug_item({
                    "ticker": ticker,
                    "price": price,
                    "change_5": 0.0,
                    "vol_ratio": 0.0,
                    "leader_score": leader,
                    "turnover": 0.0,
                    "lite_score": score,
                    "rsi": 50.0,
                    "extra_reasons": ["м§ҖкёҲмқҖ кё°лӢӨлҰҙ нӣ„ліҙ кё°мӨҖ", f"{strategy_label}", f"л°ҳліө нҸ¬м°© {seen_count}нҡҢ"],
                })
                if str(item.get("section", "")) == "weak" and score < 6.0:
                    continue
                items.append(item)
            if items:
                items.sort(key=lambda x: (safe_float(x.get("section_rank", 0)), safe_float(x.get("lite_score", 0)), safe_float(x.get("leader_score", 0))), reverse=True)
                return items[:8], "мөңк·ј мӢӨмӢңк°„ нӣ„ліҙк°Җ л№„м–ҙ мһҲм–ҙ м§ҖкёҲмқҖ кё°лӢӨлҰҙ нӣ„ліҙ кё°мӨҖмңјлЎң ліҙм—¬мӨҢ"
        # 5мҲңмң„: мөңк·ј м•ҢлҰј нӣ„ліҙ fallback
        recent_entries = get_recent_candidate_entries(limit=12)
        if recent_entries:
            items = []
            for entry in recent_entries:
                item, alert_type, reason_text, header = unpack_recent_entry(entry)
                if not isinstance(item, dict):
                    continue
                if is_watch_excluded_ticker(item.get("ticker", "")):
                    continue
                snap = ensure_pre_alert_snapshot(item)
                price = safe_float(item.get("current_price", item.get("price", 0)))
                score = safe_float(item.get("edge_score", item.get("signal_score", 0)))
                leader = safe_float(item.get("leader_score", 0))
                vol_ratio = safe_float(item.get("vol_ratio", 0))
                change_5 = safe_float(snap.get("chg_5m", item.get("change_pct", 0)))
                source_label = (header or item.get("strategy_label", "") or "мөңк·ј нӣ„ліҙ").strip()
                debug_item = finalize_scan_debug_item({
                    "ticker": str(item.get("ticker", "?") or "?"),
                    "price": price,
                    "change_5": change_5,
                    "vol_ratio": vol_ratio,
                    "leader_score": leader,
                    "turnover": 0.0,
                    "lite_score": score + leader * 0.6,
                    "rsi": safe_float(item.get("rsi", 50)),
                })
                if str(debug_item.get("section", "")) == "weak" and change_5 <= 0.15:
                    continue
                items.append(debug_item)
            items.sort(key=lambda x: (safe_float(x.get("section_rank", 0)), safe_float(x.get("lite_score", 0))), reverse=True)
            if items:
                return items[:8], "мөңк·ј мӢңмһҘ нӣ„ліҙк°Җ л№„м–ҙ мһҲм–ҙ мөңк·ј м•ҢлҰј нӣ„ліҙ кё°мӨҖмңјлЎң ліҙм—¬мӨҢ"
        if cache_age is None:
            return [], "мөңк·ј мӢңмһҘ лҚ°мқҙн„°к°Җ м•„м§Ғ м—ҶмқҢ. м§ҖкёҲмқҖ кё°лӢӨлҰҙ нӣ„ліҙлӮҳ мөңк·ј нӣ„ліҙк°Җ мғқкё°л©ҙ м—¬кё°м—җлҸ„ к°ҷмқҙ ліҙм—¬мӨ„кІҢ"
        return [], f"мөңк·ј {cache_age}мҙҲ м•Ҳм—җлҠ” м§ҖкёҲ ліј нӣ„ліҙк°Җ м•„м§Ғ м—ҶмқҢ"
    except Exception as e:
        return None, f"нӣ„ліҙ мғҒм„ёліҙкё° мЎ°нҡҢ м—җлҹ¬: {e}"
def split_scan_debug_results(results):
    strong_items = [x for x in results if str(x.get("section", "")) == "strong"][:3]
    if strong_items:
        watch_items = [x for x in results if str(x.get("section", "")) == "watch"][:2]
    else:
        watch_items = [x for x in results if str(x.get("section", "")) == "watch"][:3]
    weak_items = [x for x in results if str(x.get("section", "")) == "weak"][:2]
    return strong_items, watch_items, weak_items


def is_scan_debug_overblocked_candidate(item: dict) -> bool:
    item = item if isinstance(item, dict) else {}
    bucket = str(item.get("alert_bucket", "") or "").strip()
    section = str(item.get("section", "") or "").strip()
    one_liner = str(item.get("one_liner", "") or "").strip()
    label = str(item.get("user_label_text", item.get("label_text", "")) or "").strip()
    quant_label = str(item.get("chart_quant_label", "") or "").strip()
    below_high = safe_float(item.get("below_high", item.get("below_30m_high_pct", 999)), 999)
    from_low = safe_float(item.get("from_low", item.get("from_30m_low_pct", 0)), 0)
    change_5 = safe_float(item.get("change_5", 0), 0)
    vol_ratio = safe_float(item.get("vol_ratio", 0), 0)
    leader = safe_float(item.get("leader_score", 0), 0)
    recovery_speed = safe_float(item.get("recovery_speed_pct", 0), 0)
    if bucket == "discard":
        return True
    if section == "weak":
        return True
    if "м§ҖкёҲ мӮ¬кё°м—” лі„лЎң" in one_liner and below_high <= 1.60:
        return True
    if quant_label in {"кі м җ л„Ҳл¬ҙ к°Җк№ҢмӣҖ", "кі м җ к·јмІҳ л°•мҠӨ нҡЎліҙ", "м§Ғм „ лӢЁкё°кі м җ мһ¬м ‘к·ј"} and below_high <= 1.20:
        return True
    if label in {"кө¬кІҪл§Ң", "кө¬кІҪл§Ң нӣ„ліҙ"} and (change_5 <= 0.30 or recovery_speed <= 0.10 or from_low <= 0.20) and below_high <= 1.60:
        return True
    if change_5 <= 0.05 and from_low <= 0.45 and below_high <= 1.35 and vol_ratio < 3.20 and leader < 2.60:
        return True
    if from_low <= 0.10 and recovery_speed <= 0.05 and below_high <= 1.10:
        return True
    if "мӢӨм „ м§„мһ…к°җмқҖ м•Ҫн•Ё" in one_liner and change_5 <= 0.10 and below_high <= 1.30:
        return True
    return False


def is_scan_debug_low_value_top_candidate(item: dict) -> bool:
    item = item if isinstance(item, dict) else {}
    one = str(item.get("one_liner", "") or "")
    grade = str(item.get("alert_grade", item.get("user_alert_grade", "")) or "").upper().strip()
    below_high = safe_float(item.get("below_high", 999), 999)
    from_low = safe_float(item.get("from_low", 0), 0)
    change_5 = safe_float(item.get("change_5", 0), 0)
    bucket = str(item.get("alert_bucket", "") or "")
    if bucket == "user_alert":
        return False
    weak_text = any(x in one for x in ["м§ҖкёҲ мӮ¬кё°м—” лі„лЎң", "кө¬кІҪл§Ң", "мӢӨм „ м§„мһ…к°җмқҖ м•„м§Ғ м•Ҫн•Ё", "мӢӨм „ м§„мһ…к°җмқҖ м•Ҫн•Ё"])
    if grade == "C" and weak_text:
        return True
    if weak_text and below_high <= 0.50:
        return True
    if grade == "C" and change_5 < 0.10 and below_high <= 0.80 and from_low < 0.80:
        return True
    return False


def get_scan_debug_display_shortlist(results, limit: int = 3):
    limit = max(1, int(limit))
    strong_items, watch_items, weak_items = split_scan_debug_results(results)

    # v2.5.182: к°ҖкІ©мқҙ мӢј мҪ”мқёмқҙ м•„лӢҲлқј "мӢӨм ң кұ°лһҳлҢҖкёҲмқҙ кұ°мқҳ м—ҶлҠ” н‘ңмӢң мһЎмқҢ"л§Ң кё°ліё лӘ©лЎқм—җм„ң мҲЁкёҙлӢӨ.
    hidden_noise = [x for x in list(strong_items) + list(watch_items) + list(weak_items) if is_fast_scan_tiny_turnover_noise(x)]
    strong_items = [x for x in strong_items if not is_fast_scan_tiny_turnover_noise(x)]
    watch_items = [x for x in watch_items if not is_fast_scan_tiny_turnover_noise(x)]
    weak_items = [x for x in weak_items if not is_fast_scan_tiny_turnover_noise(x)]

    primary_pool = list(strong_items) + list(watch_items)
    preferred = []
    fallback = []
    for item in primary_pool:
        if is_scan_debug_overblocked_candidate(item):
            continue
        if is_scan_debug_low_value_top_candidate(item):
            fallback.append(item)
        else:
            preferred.append(item)
    shortlist = preferred[:limit]
    # ліҙм—¬мӨ„ нӣ„ліҙк°Җ м•„мҳҲ м—Ҷмқ„ л•Ңл§Ң лӮ®мқҖ к°Җм№ҳ нӣ„ліҙлҘј м ңн•ңм ҒмңјлЎң ліҙм—¬мӨҖлӢӨ.
    if not shortlist:
        shortlist = fallback[:min(limit, 1)]
    if len(shortlist) < limit and not shortlist:
        for item in weak_items:
            if item in shortlist or is_scan_debug_overblocked_candidate(item):
                continue
            shortlist.append(item)
            if len(shortlist) >= limit:
                break
    if hidden_noise:
        try:
            for it in shortlist:
                it.setdefault("hidden_tiny_turnover_count", len(hidden_noise))
        except Exception:
            pass
    return shortlist[:limit], strong_items, watch_items, weak_items
def get_scan_debug_shortlist(limit=3):
    results, note = get_scan_debug_candidates()
    if results is None:
        return [], note
    shortlist, _strong_items, _watch_items, _weak_items = get_scan_debug_display_shortlist(results, limit=limit)
    return shortlist, note
def build_scan_debug_text_legacy():
    results, note = get_scan_debug_candidates()
    if results is None:
        return f"вҡ пёҸ нӣ„ліҙ мғҒм„ёліҙкё° м—җлҹ¬\n{note}"
    lines = ["рҹ”Һ м§ҖкёҲ ліј нӣ„ліҙ ліҙкё°"]
    health_warning = build_scan_health_warning_text()
    if health_warning:
        lines.append(health_warning)
    if note:
        lines.append(f"м•ҲлӮҙ: {note}")
    if not results:
        lines.append("")
        lines.append("м§ҖкёҲ ліј нӣ„ліҙ м—ҶмқҢ")
        return "\n".join(lines)
    strong_items, watch_items, weak_items = split_scan_debug_results(results)
    def append_group(title: str, items):
        if not items:
            return
        lines.append("")
        lines.append(title)
        for i, item in enumerate(items, 1):
            price_text = f"{safe_float(item.get('price', 0)):,.4f}".rstrip("0").rstrip(".")
            lines.append("")
            lines.append(f"{i}. {item.get('ticker','?')} / нҳ„мһ¬к°Җ {price_text}")
            lines.append(
                f"   5л¶„ мғҒмҠ№ {safe_float(item.get('change_5',0)):.2f}% / кұ°лһҳлҹү {safe_float(item.get('vol_ratio',0)):.2f}л°° / мӢңмһҘмЈјлӘ©лҸ„ {safe_float(item.get('leader_score',0)):.2f}"
            )
            lines.append(f"   м°ёкі  м җмҲҳ {safe_float(item.get('lite_score',0)):.2f}")
            if item.get("one_liner"):
                lines.append(f"   н•ңмӨ„нҸү: {item.get('one_liner')}")
            if safe_float(item.get("from_low", 0), 0) or safe_float(item.get("below_high", 999), 999) < 900:
                lines.append(f"   30л¶„ м Җм җлҢҖл№„ {safe_float(item.get('from_low',0),0):+.2f}% / {format_fast_scan_high_gap_text(safe_float(item.get('below_high',999),999))}")
            lines.append(f"   мһЎнһҢ мқҙмң : {' / '.join(item.get('reasons', [])[:3])}")
    append_group("рҹҢұ мҙҲл°ҳ/мӢӨмӢңк°„ к°•м„ё нӣ„ліҙ", strong_items)
    append_group("рҹ”Ғ мһ¬м¶ңл°ң нҷ•мқё нӣ„ліҙ", watch_items)
    append_group("вӣ” лҠҰм—Ҳкұ°лӮҳ м•„м§Ғ м•Ҫн•ң нӣ„ліҙ", weak_items[:3])
    return "\n".join(lines)
def scan_debug_command(update, context: CallbackContext):
    try:
        send_text_chunks(build_scan_debug_text())
    except Exception as e:
        send(f"вҡ пёҸ нӣ„ліҙ мғҒм„ёліҙкё° м—җлҹ¬: {e}")
def append_debug_shortlist_parts_legacy(parts: list):
    try:
        shortlist, note = get_scan_debug_shortlist(limit=3)
        header = "рҹ”Һ м§ҖкёҲ нҷ•мқён•  мғҒмң„ нӣ„ліҙ"
        if note:
            header += f" ({note})"
        if not shortlist:
            parts.append(header + "\n\nнӣ„ліҙ м—ҶмқҢ")
            return
        lines = [header]
        for item in shortlist:
            label = "мҙҲл°ҳ/мӢӨмӢңк°„" if str(item.get("section", "")) == "strong" else ("мһ¬м¶ңл°ң" if str(item.get("section", "")) == "watch" else "лҠҰмқҢ/м•Ҫн•Ё")
            lines.append(
                f"вҖў {item.get('ticker','?')} / {label} / 5л¶„ {safe_float(item.get('change_5',0)):.2f}% / кұ°лһҳлҹү {safe_float(item.get('vol_ratio',0)):.2f}л°° / мЈјлӘ©лҸ„ {safe_float(item.get('leader_score',0)):.2f}"
            )
            if item.get("one_liner"):
                lines.append(f"  - {item.get('one_liner')}")
        parts.append("\n".join(lines))
    except Exception as e:
        parts.append(f"вҡ пёҸ мғҒмң„ мҠӨмә” нӣ„ліҙ н‘ңмӢң м—җлҹ¬: {e}")
def status_command(update, context: CallbackContext):
    if _maybe_handle_multiline_command_batch(update, context):
        return
    parts = []
    parts.append("рҹҹў мһҗлҸҷл§ӨмҲҳ : мјңм§җ" if AUTO_BUY else "рҹ”ҙ мһҗлҸҷл§ӨмҲҳ : кәјм§җ")
    health_warning = build_scan_health_warning_text()
    if health_warning:
        parts.append(health_warning)
    paused, pause_msg = should_pause_auto_buy_now()
    if paused:
        parts.append(f"вҸё м§ҖкёҲмқҖ мһ к№җ мү¬лҠ” мӨ‘: {pause_msg}")
    elif auto_pause_bypass_until and time.time() < auto_pause_bypass_until:
        remain = int(auto_pause_bypass_until - time.time())
        if auto_pause_bypass_reason == "restart":
            parts.append(f"рҹ”„ мһ¬мӢңмһ‘мңјлЎң мү¬кё° мҙҲкё°нҷ”лҗЁ / {max(remain, 0)}мҙҲ л’Ө лӢӨмӢң мһҗлҸҷ мү¬кё° нҢҗлӢЁ")
        else:
            parts.append(f"рҹӣ  мһҗлҸҷ мү¬кё° мҲҳлҸҷ н•ҙм ң м Ғмҡ© мӨ‘ / {max(remain, 0)}мҙҲ лӮЁмқҢ")
    if active_positions:
        lines, dust_lines = [], []
        for ticker, pos in active_positions.items():
            price = get_price(ticker)
            entry = float(pos["entry_price"])
            qty = float(pos.get("qty", 0))
            pnl = ((price - entry) / entry) * 100 if entry > 0 and price > 0 else 0
            held_min = int((time.time() - int(pos["entered_at"])) / 60)
            value = qty * price if price > 0 else 0
            tag_text = ""
            if pos.get("pattern_tags"):
                tag_text = " / кө¬мЎ° " + ",".join(pos["pattern_tags"][:3])
            line = (
                f"вҖў {ticker} / л°©мӢқ {pos['strategy_label']} / м§„мһ… {fmt_price(entry)} / нҳ„мһ¬ {fmt_price(price)} "
                f"/ мҲҳмқөлҘ  {fmt_pct(pnl)} / нҸүк°ҖкёҲм•Ў {fmt_price(value)} / ліҙмң  {held_min}л¶„ / кё°лҢҖм җмҲҳ {pos.get('edge_score', 0):.2f} / л“ұкёү {pos.get('trade_tier','B')} / мЈјлҸ„мЈј {safe_float(pos.get('leader_score',0)):.2f} / мІҙкІ° {format_entry_gap_text(pos.get('entry_gap_pct', 0))}{tag_text}"
            )
            if value < MIN_ORDER_KRW:
                dust_lines.append(line + " / мғҒнғң мҶҢм•ЎнҸ¬м§Җм…ҳ лҢҖкё°мӨ‘")
            else:
                lines.append(line)
        if lines:
            parts.append("рҹ“Ң нҳ„мһ¬ нҸ¬м§Җм…ҳ\n\n" + "\n".join(lines))
        if dust_lines:
            parts.append("рҹӘҷ мҶҢм•Ў нҸ¬м§Җм…ҳ(мөңмҶҢ мЈјл¬ёкёҲм•Ў лҜёл§Ң)\n\n" + "\n".join(dust_lines))
    else:
        parts.append("рҹ“ӯ нҳ„мһ¬ ліҙмң  нҸ¬м§Җм…ҳ м—ҶмқҢ")
    if pending_buy_candidates:
        c_lines = []
        sorted_candidates = sorted(
            pending_buy_candidates.values(),
            key=lambda x: (safe_float(x.get("leader_score", 0)) * 0.8) + safe_float(x.get("edge_score", 0)),
            reverse=True,
        )[:3]
        for item in sorted_candidates:
            c_lines.append(
                f"вҖў {item['ticker']} / {item.get('strategy_label','?')} / м җмҲҳ {safe_float(item.get('edge_score', 0)):.2f} / мЈјлҸ„мЈј {safe_float(item.get('leader_score', 0)):.2f}"
            )
        parts.append("рҹ•’ м§ҖкёҲмқҖ кё°лӢӨлҰҙ нӣ„ліҙ\n" + "\n".join(c_lines))
    append_debug_shortlist_parts(parts)
    if pending_sells:
        p = ["вҡ пёҸ л§ӨлҸ„ нҷ•мқё лҢҖкё°мӨ‘"]
        for ticker in pending_sells.keys():
            p.append(f"вҖў {ticker}")
        parts.append("\n".join(p))
    send_text_chunks("\n\n".join(parts))

