            if (new_pri < old_pri + safe_float(globals().get("PRECISION_MINUTE1_PENDING_PRIORITY_DELTA", 0.65), 0.65)) and age < safe_float(globals().get("PRECISION_MINUTE1_PENDING_REQUEUE_SEC", 18), 18) and not bool(profile.get("strong_wait_v260", False)):
                _precision_v260_inc("pending_hold", f"pending мң м§Җ {ticker}"); _precision_minute1_reject("pending_hold_v260", ticker, {"old": old_pri, "new": new_pri, "age": age}); return False
