# =========================================================
# v2.5.261: REST/WS нҳјн•© лҚ°мқҙн„° н’Ҳм§Ҳмёө + мҶҢм•Ў лӢЁмқјмқөм Ҳ/ліҙнҳёмҶҗм Ҳ к°•нҷ”
# =========================================================
# лӘ©н‘ң:
# - REST мӢӨнҢЁ/мҝЁлӢӨмҡҙмқҙ нӣ„ліҙ мӢӨнҢЁлЎң мқҙм–ҙм§Җм§Җ м•ҠкІҢ WebSocket мІҙкІ°/нҳ„мһ¬к°Җ/лқјмқҙнҠёмҠӨлғ…мғ·мқ„ н•©міҗ ліёлӢӨ.
# - minute1 RESTлҠ” нҷ•м •мҡ©, WebSocket 1л¶„ мң мӮ¬мә”л“ӨмқҖ мӢӨмӢңк°„ к°җм§Җмҡ©мңјлЎң л¶„лҰ¬н•ңлӢӨ.
# - мһҗлҸҷл§Өл§Ө мҙҲкё° 1л§Ңмӣҗ мҡҙмҡ©мқ„ м „м ңлЎң TP1/TP2/TP3 л¶„н• ліҙлӢӨ лӢЁмқј мқөм Ҳ + ліҙнҳёмҶҗм Ҳмқ„ мҡ°м„ н•ңлӢӨ.
WS_SYNTHETIC_1M_ON_V261 = True
WS_SYNTHETIC_1M_WINDOW_SEC_V261 = 5 * 60
WS_SYNTHETIC_1M_MIN_TRADES_V261 = 2
WS_SYNTHETIC_1M_MIN_AMOUNT_V261 = 300_000
DATA_FUSION_V261_ON = True
STARTER_SINGLE_EXIT_MODE_V261 = True
STARTER_TRADE_KRW_HINT_V261 = 10_000
PAPER_V261_SINGLE_TP_ON = True
PAPER_V261_LOCK1_UP_PCT = 0.90
PAPER_V261_LOCK1_KEEP_PCT = 0.28
PAPER_V261_LOCK2_UP_PCT = 1.80
PAPER_V261_LOCK2_KEEP_PCT = 0.95
PAPER_V261_LOCK3_UP_PCT = 3.00
PAPER_V261_LOCK3_KEEP_PCT = 1.75
PAPER_V261_SLOW_EXIT_MIN_SEC = 28 * 60
PAPER_V261_SLOW_EXIT_MAX_PNL = 0.10
PAPER_V261_STATS = {
    "ws1m_built": 0,
    "ws1m_insufficient": 0,
    "rest_fail_ws_used": 0,
    "data_quality_a": 0,
    "data_quality_b": 0,
    "data_quality_c": 0,
    "data_quality_d": 0,
    "signal_ws_filled": 0,
    "paper_single_tp": 0,
    "paper_profit_lock": 0,
    "paper_slow_exit": 0,
    "last_note": "лҢҖкё°",
}

def _v261_inc(key: str, note: str = ""):
    try:
        PAPER_V261_STATS[key] = int(safe_float(PAPER_V261_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V261_STATS["last_note"] = str(note)[:140]
    except Exception:
        pass


def _v261_ws_trade_rows(ticker: str, window_sec: float = None) -> list:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return []
    now_ts = time.time()
    window_sec = safe_float(window_sec if window_sec is not None else WS_SYNTHETIC_1M_WINDOW_SEC_V261, 300)
    try:
        with WS_TRADE_LOCK:
            rows = list((globals().get("WS_TRADE_CACHE", {}) or {}).get(ticker) or [])
        return [dict(r) for r in rows if isinstance(r, dict) and now_ts - safe_float(r.get("ts", 0), 0) <= window_sec]
    except Exception:
        return []


def build_ws_1m_synthetic_df_v261(ticker: str, window_sec: float = None):
    """WebSocket мІҙкІ°мқ„ 1л¶„ мң мӮ¬мә”л“ӨлЎң л¬¶лҠ”лӢӨ. REST minute1 лҢҖмІҙ к°җм§Җмҡ©мқҙл©° нҷ•м •лҙүмқҙ м•„лӢҲлӢӨ."""
    if not WS_SYNTHETIC_1M_ON_V261:
        return None, {"ok": False, "reason": "off"}
    ticker = str(ticker or "").upper().strip()
    rows = _v261_ws_trade_rows(ticker, window_sec=window_sec)
    if len(rows) < int(safe_float(WS_SYNTHETIC_1M_MIN_TRADES_V261, 2)):
        _v261_inc("ws1m_insufficient", f"ws1m л¶ҖмЎұ {ticker}/trades")
        return None, {"ok": False, "reason": "not_enough_trades", "count": len(rows)}
    amount = sum(max(0.0, safe_float(r.get("amount", 0), 0)) for r in rows)
    if amount < safe_float(WS_SYNTHETIC_1M_MIN_AMOUNT_V261, 300000):
        _v261_inc("ws1m_insufficient", f"ws1m л¶ҖмЎұ {ticker}/amount")
        return None, {"ok": False, "reason": "not_enough_amount", "count": len(rows), "amount": amount}
    try:
        import pandas as _pd
        buckets = {}
        for r in rows:
            ts = safe_float(r.get("ts", 0), 0)
            price = safe_float(r.get("price", 0), 0)
            volume = safe_float(r.get("volume", 0), 0)
            amt = safe_float(r.get("amount", 0), 0)
            if ts <= 0 or price <= 0:
                continue
            minute_ts = int(ts // 60) * 60
            b = buckets.setdefault(minute_ts, {"open": price, "high": price, "low": price, "close": price, "volume": 0.0, "amount": 0.0, "count": 0})
            if b["count"] <= 0:
                b["open"] = price
            b["high"] = max(b["high"], price)
            b["low"] = min(b["low"], price)
            b["close"] = price
            b["volume"] += max(0.0, volume)
            b["amount"] += max(0.0, amt)
            b["count"] += 1
        if not buckets:
            return None, {"ok": False, "reason": "empty_buckets"}
        idx = sorted(buckets.keys())
        df = _pd.DataFrame([buckets[k] for k in idx], index=_pd.to_datetime(idx, unit="s"))
        if len(df) < 4:
            first = df.iloc[0].copy()
            prepend = []
            base_ts = idx[0]
            for i in range(4 - len(df)):
                row = dict(first)
                row["volume"] = 0.0
                row["amount"] = 0.0
                row["count"] = 0
                prepend.append((base_ts - 60 * (4 - len(df) - i), row))
            if prepend:
                pdf = _pd.DataFrame([x[1] for x in prepend], index=_pd.to_datetime([x[0] for x in prepend], unit="s"))
                df = _pd.concat([pdf, df])
        info = get_ws_trade_summary_for_ticker(ticker, 60) if 'get_ws_trade_summary_for_ticker' in globals() else {}
        _v261_inc("ws1m_built", f"ws1m {ticker}/{len(rows)}")
        return df[["open", "high", "low", "close", "volume"]], {"ok": True, "count": len(rows), "amount": amount, "summary": info, "minutes": len(df)}
    except Exception as e:
        return None, {"ok": False, "reason": f"error:{e.__class__.__name__}", "count": len(rows), "amount": amount}


def store_ws_1m_synthetic_precision_state_v261(ticker: str, row_hint: dict = None, reason: str = "ws_1m_synthetic") -> dict:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return {}
    row_hint = dict(row_hint or {})
    try:
        df, meta = build_ws_1m_synthetic_df_v261(ticker)
        if df is None or not bool((meta or {}).get("ok")):
            return {}
        st = store_precision_minute1_chart_state(ticker, df=df, source="ws_1m_synthetic", reason=reason, row_hint=row_hint)
        if not isinstance(st, dict):
            st = {}
        st["precision_chart_source"] = "ws_1m_synthetic"
        st["precision_chart_verified"] = False
        st["precision_minute1_verified"] = False
        st["precision_chart_note"] = "WS 1л¶„ мң мӮ¬мә”л“Ө к°җм§Җ / REST нҷ•м • лҢҖкё°"
        st["ws_1m_synthetic"] = True
        st["ws_1m_trade_count"] = int(safe_float((meta or {}).get("count", 0), 0))
        st["ws_1m_amount"] = safe_float((meta or {}).get("amount", 0), 0)
        summary = (meta or {}).get("summary") if isinstance((meta or {}).get("summary"), dict) else {}
        st["ws_1m_buy_ratio"] = safe_float(summary.get("buy_ratio", 0), 0)
        st["data_quality_grade_v261"] = "B"
        st["data_quality_text_v261"] = "B: WS 1л¶„ мң мӮ¬мә”л“Ө / REST нҷ•м •лҢҖкё°"
        d = _precision_minute1_state_dict()
        d[ticker] = st
        _v261_inc("rest_fail_ws_used", f"RESTлҢҖкё°вҶ’WSліҙмЎ° {ticker}")
        return dict(st)
    except Exception as e:
        append_runtime_event_log("store_ws_1m_synthetic_precision_state_v261", "WS 1л¶„ мң мӮ¬мә”л“Ө м ҖмһҘ мҳӨлҘҳ", extra={"ticker": ticker, "error": str(e)[:120]})
        return {}


def get_data_quality_v261(row: dict) -> dict:
    row = row if isinstance(row, dict) else {}
    ticker = str(row.get("ticker", "") or "").upper().strip()
    try:
        verified = bool(row.get("precision_chart_verified", row.get("precision_minute1_verified", False)))
        source = str(row.get("precision_chart_source", "") or "")
        cnt = int(safe_float(row.get("ws_trade_count_60s", row.get("ws_1m_trade_count", 0)), 0))
        amt = safe_float(row.get("ws_trade_amount_60s", row.get("ws_1m_amount", 0)), 0)
        buy = safe_float(row.get("ws_trade_buy_ratio_60s", row.get("ws_1m_buy_ratio", 0)), 0)
        if ticker and (cnt <= 0 or amt <= 0) and 'get_ws_trade_summary_for_ticker' in globals():
            s = get_ws_trade_summary_for_ticker(ticker, 60)
            if isinstance(s, dict):
                cnt = max(cnt, int(safe_float(s.get("count", 0), 0)))
                amt = max(amt, safe_float(s.get("amount", 0), 0))
                buy = max(buy, safe_float(s.get("buy_ratio", 0), 0))
        has_price = safe_float(row.get("current_price", row.get("price", 0)), 0) > 0
        if verified:
            grade, text = "A", "A: REST 1л¶„лҙү нҷ•м • + ліҙмЎ°лҚ°мқҙн„°"
        elif source == "ws_1m_synthetic" or (cnt >= 3 and amt >= WS_SYNTHETIC_1M_MIN_AMOUNT_V261):
            grade, text = "B", "B: WS мІҙкІ° м¶©л¶„ / REST нҷ•м •лҢҖкё°"
        elif has_price or source:
            grade, text = "C", "C: нҳ„мһ¬к°ҖВ·мәҗмӢң ліҙмЎ° / м •л°Җ м•Ҫн•Ё"
        else:
            grade, text = "D", "D: лҚ°мқҙн„° л¶ҖмЎұ / м¶”м Ғл§Ң"
        key = f"data_quality_{grade.lower()}"
        if key in PAPER_V261_STATS:
            _v261_inc(key)
        return {"grade": grade, "text": text, "ws_count": cnt, "ws_amount": amt, "ws_buy_ratio": buy, "source": source}
    except Exception:
        return {"grade": "D", "text": "D: лҚ°мқҙн„°н’Ҳм§Ҳ кі„мӮ° мҳӨлҘҳ", "ws_count": 0, "ws_amount": 0, "ws_buy_ratio": 0, "source": "error"}

_PREV_APPLY_PRECISION_STATE_V261 = apply_precision_minute1_state_to_row
def apply_precision_minute1_state_to_row(row: dict) -> dict:
    out = _PREV_APPLY_PRECISION_STATE_V261(row)
    try:
        if not isinstance(out, dict):
            return out
        ticker = str(out.get("ticker", "") or "").upper().strip()
        if ticker:
            if 'apply_ws_trade_metrics_to_item' in globals():
                out = apply_ws_trade_metrics_to_item(out)
            dq = get_data_quality_v261(out)
            out["data_quality_grade_v261"] = dq.get("grade")
            out["data_quality_text_v261"] = dq.get("text")
            out.setdefault("ws_1m_trade_count", dq.get("ws_count", 0))
            out.setdefault("ws_1m_amount", dq.get("ws_amount", 0))
            out.setdefault("ws_1m_buy_ratio", dq.get("ws_buy_ratio", 0))
        return out
    except Exception:
        return out

_PREV_SIGNAL_MONEY_STATUS_V261 = _signal_v256_money_status
def _signal_v256_money_status(row: dict):
    code, sustain, amount, cnt, buy = _PREV_SIGNAL_MONEY_STATUS_V261(row)
    try:
        ticker = str((row or {}).get("ticker", "") or "").upper().strip()
        if ticker and 'get_ws_trade_summary_for_ticker' in globals() and (int(safe_float(cnt, 0)) <= 0 or safe_float(amount, 0) <= 0):
            s60 = get_ws_trade_summary_for_ticker(ticker, 60)
            if isinstance(s60, dict) and int(safe_float(s60.get("count", 0), 0)) > 0:
                cnt = max(int(safe_float(cnt, 0)), int(safe_float(s60.get("count", 0), 0)))
                amount = max(safe_float(amount, 0), safe_float(s60.get("amount", 0), 0))
                buy = safe_float(s60.get("buy_ratio", buy), buy)
                label = str(s60.get("label", "") or "")
                if label and (not sustain or "нҷ•мқё" in str(sustain)):
                    sustain = label
                _v261_inc("signal_ws_filled", f"signal WSліҙк°• {ticker}/{cnt}")
    except Exception:
        pass
    return code, sustain, amount, cnt, buy

_PREV_PROCESS_PRECISION_MINUTE1_V261 = process_precision_minute1_chart_once
def process_precision_minute1_chart_once(ticker: str, reason: str = "worker") -> bool:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return False
    ok = False
    try:
        ok = bool(_PREV_PROCESS_PRECISION_MINUTE1_V261(ticker, reason=reason))
    except Exception as e:
        append_runtime_event_log("precision_minute1_process_v261_base_error", "кё°мЎҙ minute1 мІҳлҰ¬ мҳӨлҘҳ нӣ„ WS ліҙмЎ° мӢңлҸ„", extra={"ticker": ticker, "error": str(e)[:120]})
        ok = False
    try:
        st = get_precision_minute1_chart_state(ticker)
        if ok and bool((st or {}).get("precision_chart_verified", False)):
            return True
        hint = {"ticker": ticker}
        if isinstance(st, dict):
            hint.update(st)
        store_ws_1m_synthetic_precision_state_v261(ticker, row_hint=hint, reason=f"rest_pending:{reason}")
    except Exception:
        pass
    return ok

_PREV_SIGNAL_FORMAT_ONE_V261 = _signal_v256_format_one
def _signal_v256_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    try:
        enriched = apply_precision_minute1_state_to_row(dict(row or {})) if isinstance(row, dict) else row
    except Exception:
        enriched = row
    text = _PREV_SIGNAL_FORMAT_ONE_V261(enriched, order=order, show_detail=show_detail)
    try:
        dq = get_data_quality_v261(enriched if isinstance(enriched, dict) else {})
        lines = str(text).splitlines()
        insert_at = 3 if len(lines) > 3 else len(lines)
        lines.insert(insert_at, f"- лҚ°мқҙн„°н’Ҳм§Ҳ: {dq.get('text')} / WS {int(safe_float(dq.get('ws_count',0),0))}кұҙВ·л§ӨмҲҳ {safe_float(dq.get('ws_buy_ratio',0),0):.0f}%")
        for i, line in enumerate(lines):
            if line.startswith("- мқөм Ҳ: TP1"):
                lines[i] = line + f"\n- мҶҢм•ЎлӘЁл“ң: мһҗлҸҷл§Өл§Ө мҙҲкё° {STARTER_TRADE_KRW_HINT_V261:,}мӣҗ кё°мӨҖмқҖ TP1~3 л¶„н• ліҙлӢӨ лӢЁмқјмқөм ҲВ·ліҙнҳёмҶҗм Ҳ мҡ°м„ "
                break
        return "\n".join(lines)
    except Exception:
        return text

def paper_update_positions_once_v258():
    if not PAPER_TRADING_ON:
        return
    now_ts = time.time()
    changed = False
    try:
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            status = str(pos.get("status", "") or "").upper()
            fallback = safe_float(pos.get("last_price", pos.get("entry_price", 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            pos["last_price"] = price
            pos["last_price_source"] = src
            pos["last_price_age"] = safe_float(age, 0)
            pos["updated_ts"] = now_ts
            if status == "PENDING":
                if now_ts - safe_float(pos.get("created_ts", now_ts), now_ts) >= PAPER_PENDING_TTL_SEC:
                    _paper_cancel_pending_v258(pid, pos, "pending_timeout", now_ts)
                    continue
                entry_rule = str(pos.get("entry_rule", "") or "")
                low = safe_float(pos.get("planned_entry_low", 0), 0)
                high = safe_float(pos.get("planned_entry_high", 0), 0)
                chase = safe_float(pos.get("chase_stop", 0), 0)
                enter = False
                if entry_rule == "breakout" and low > 0 and price >= low and (chase <= 0 or price <= chase):
                    enter = True
                elif entry_rule == "pullback" and low > 0 and high > 0 and low <= price <= high:
                    enter = True
                elif entry_rule == "now":
                    enter = True
                if chase > 0 and price > chase and entry_rule != "now":
                    _paper_cancel_pending_v258(pid, pos, "chase_over_before_entry", now_ts)
                    continue
                if enter:
                    pos["status"] = "OPEN"
                    pos["entry_price"] = price
                    pos["entered_ts"] = now_ts
                    pos["remaining_ratio"] = 1.0
                    pos["realized_pct"] = 0.0
                    pos["single_exit_mode_v261"] = bool(STARTER_SINGLE_EXIT_MODE_V261)
                    PAPER_V258_STATS["entered"] = int(safe_float(PAPER_V258_STATS.get("entered", 0), 0)) + 1
                    changed = True
            if str(pos.get("status", "") or "").upper() == "OPEN":
                entry = safe_float(pos.get("entry_price", 0), 0)
                if entry <= 0:
                    continue
                pnl = _paper_pct_v258(entry, price)
                pos["max_up_pct"] = max(safe_float(pos.get("max_up_pct", pnl), pnl), pnl)
                pos["min_down_pct"] = min(safe_float(pos.get("min_down_pct", pnl), pnl), pnl)
                max_up = safe_float(pos.get("max_up_pct", pnl), pnl)
                tp1 = safe_float(pos.get("tp1", 0), 0)
                stop = safe_float(pos.get("stop", 0), 0)
                open_age = now_ts - safe_float(pos.get("entered_ts", now_ts), now_ts)
                close_reason = ""
                if PAPER_V261_SINGLE_TP_ON and tp1 > 0 and price >= tp1:
                    pos["tp1_hit"] = True
                    pos["tp1_ts"] = now_ts
                    close_reason = "single_tp_exit_v261"
                    _v261_inc("paper_single_tp", f"single TP {ticker}")
                elif max_up >= PAPER_V261_LOCK3_UP_PCT and pnl <= PAPER_V261_LOCK3_KEEP_PCT:
                    close_reason = "profit_lock_3_v261"
                    _v261_inc("paper_profit_lock", f"lock3 {ticker}/{pnl:+.2f}")
                elif max_up >= PAPER_V261_LOCK2_UP_PCT and pnl <= PAPER_V261_LOCK2_KEEP_PCT:
                    close_reason = "profit_lock_2_v261"
                    _v261_inc("paper_profit_lock", f"lock2 {ticker}/{pnl:+.2f}")
                elif max_up >= PAPER_V261_LOCK1_UP_PCT and pnl <= PAPER_V261_LOCK1_KEEP_PCT:
                    close_reason = "profit_lock_1_v261"
                    _v261_inc("paper_profit_lock", f"lock1 {ticker}/{pnl:+.2f}")
                elif stop > 0 and price <= stop:
                    close_reason = "stop_loss" if max_up < PAPER_V261_LOCK1_UP_PCT else "protect_stop_after_profit_v261"
                elif open_age >= PAPER_OPEN_TTL_SEC:
                    close_reason = "time_exit"
                elif open_age >= PAPER_V261_SLOW_EXIT_MIN_SEC and max_up < PAPER_V261_LOCK1_UP_PCT and pnl <= PAPER_V261_SLOW_EXIT_MAX_PNL:
                    close_reason = "slow_no_progress_exit_v261"
                    _v261_inc("paper_slow_exit", f"slow {ticker}/{pnl:+.2f}")
                if close_reason:
                    _paper_close_position_v258(pid, pos, price, close_reason, now_ts)
                    continue
                if max_up >= PAPER_V261_LOCK2_UP_PCT:
                    pos["stop"] = max(stop, entry * (1 + PAPER_V261_LOCK2_KEEP_PCT / 100.0))
                elif max_up >= PAPER_V261_LOCK1_UP_PCT:
                    pos["stop"] = max(stop, entry * (1 + PAPER_V261_LOCK1_KEEP_PCT / 100.0))
                with PAPER_STATE_LOCK:
                    if pid in paper_positions:
                        paper_positions[pid].update(pos)
                changed = True
        if changed:
            save_paper_state_v258()
    except Exception as e:
        append_runtime_error_log("paper_update_positions_v261", str(e), exc=e, include_traceback=False)

