# =========================================================
# v2.5.262: нӣ„ліҙн’Ҳм§Ҳ + м°ЁнҠём •көҗнҷ” 1м°Ё + мӢ нҳё/нҶөкі„ н‘ңмӢң ліҙк°•
# =========================================================
# лӘ©н‘ң:
# - нӣ„ліҙлҘј лҚ” л§Һмқҙ ліҙм—¬мЈјлҠ” кІғмқҙ м•„лӢҲлқј, м§„м§ң л§ӨмҲҳ нӣ„ліҙмҷҖ м°ёкі  нӣ„ліҙлҘј л¶„лҰ¬н•ңлӢӨ.
# - нҳ„мһ¬лҙү/кі м җ/лҸҲнқҗлҰ„мқ„ лҚ” мһҳ лӮҳлҲ м„ң кі м җ м•һ мһЎнӣ„ліҙк°Җ мғҒмң„ мӢ нҳёмІҳлҹј ліҙмқҙлҠ” л¬ём ңлҘј мӨ„мқёлӢӨ.
# - /signalм—җ лҚ°мқҙн„°н’Ҳм§Ҳкіј м°ЁнҠёмғҒнғңлҘј мүҪкІҢ н‘ңмӢңн•ңлӢӨ.
# - /paper_statsлҠ” кё°мЎҙ кё°лЎқмқ„ мҙҲкё°нҷ”н•ҳм§Җ м•Ҡкі  v262 м Ғмҡ© мқҙнӣ„ м„ұкіјлҘј л”°лЎң ліҙм—¬мӨҖлӢӨ.
PAPER_V262_START_TS = time.time()
PAPER_V262_STATS = {
    "buy_ok_demoted": 0,
    "breakout_demoted": 0,
    "reference_only": 0,
    "chart_weak_block": 0,
    "money_flash_block": 0,
    "signal_trade_count": 0,
    "signal_reference_count": 0,
    "last_note": "лҢҖкё°",
}


def _v262_inc(key: str, note: str = ""):
    try:
        PAPER_V262_STATS[key] = int(safe_float(PAPER_V262_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V262_STATS["last_note"] = str(note)[:120]
    except Exception:
        pass


def _v262_has_text(text: str, words) -> bool:
    text = str(text or "")
    return any(str(w) in text for w in list(words or []))


def _signal_v262_chart_state(row: dict, cls: dict = None) -> dict:
    row = row if isinstance(row, dict) else {}
    cls = cls if isinstance(cls, dict) else {}
    candle = str(cls.get("candle_label", row.get("current_candle_label", row.get("current_candle_code", ""))) or "")
    money = str(cls.get("money_sustain", "") or "")
    high_code = str(cls.get("high_code", row.get("high_rebreakout_v248_code", "")) or "")
    high_label = str(cls.get("high_label", row.get("high_rebreakout_v248_label", "")) or "")
    high_gap = safe_float(cls.get("high_gap", _signal_v256_high_gap(row) if '_signal_v256_high_gap' in globals() else 999), 999)
    trade_count = int(safe_float(cls.get("trade_count", 0), 0))
    buy_ratio = safe_float(cls.get("buy_ratio", 0), 0)
    live_score = safe_float(row.get("current_candle_live_score", row.get("current_candle_follow_score", 0)), 0)
    upper_wick = safe_float(row.get("current_upper_wick_ratio", row.get("upper_wick_ratio", 0)), 0)
    lower_wick = safe_float(row.get("current_lower_wick_ratio", row.get("lower_wick_ratio", 0)), 0)

    if _v262_has_text(candle, ["л§үнҢҗк°•л°ҖлҰј", "к°•л°ҖлҰј", "л°ҖлҰј", "мң„кј¬лҰ¬", "мң—кј¬лҰ¬"]):
        candle_code = "weak"; candle_text = "нҳ„мһ¬лҙү л°ҖлҰј/мң—кј¬лҰ¬"
    elif _v262_has_text(candle, ["м•„лһ«кј¬лҰ¬к°•нҡҢліө", "м•„лһ«кј¬лҰ¬ нҡҢліө", "нҡҢліө"]):
        candle_code = "recover"; candle_text = "м•„лһ«кј¬лҰ¬ нҡҢліө"
    elif _v262_has_text(candle, ["нҷ•мӢӨмӮҙм•„лӮЁ", "нҷ•мӢӨнһҲ мӮҙм•„лӮЁ", "мӮҙм•„лӮЁ"]) or live_score >= 2.2:
        candle_code = "alive"; candle_text = "нҳ„мһ¬лҙү мӮҙм•„лӮЁ"
    elif _v262_has_text(candle, ["мһ‘мқҖмӣҖм§Ғмһ„", "мқҳлҜё мһ‘мқҢ", "нҷ•мқёмӨ‘"]) or not candle:
        candle_code = "small"; candle_text = "нҳ„мһ¬лҙү к·јкұ° м•Ҫн•Ё"
    else:
        candle_code = "watch"; candle_text = candle[:24] or "нҳ„мһ¬лҙү нҷ•мқёмӨ‘"

    if high_code == "rebreak_hold" and trade_count >= 3 and buy_ratio >= 45:
        high_state = "hold"; high_text = "кі м җ лҸҢнҢҢ нӣ„ мң м§Җ"
    elif 0 <= high_gap <= 0.08:
        high_state = "touch"; high_text = "кі м җ л°”лЎң м•һ/л§һлӢҝмқҢ"
    elif 0.08 < high_gap <= 0.6:
        high_state = "near"; high_text = "кі м җ к·јмІҳ лҢҖкё°"
    elif high_code in {"near_high_reject", "reject", "false_break"} or _v262_has_text(high_label, ["л°ҖлҰј", "кұ°м Ҳ", "л§үнһҳ"]):
        high_state = "reject"; high_text = "кі м җм—җм„ң л§үнһҳ"
    else:
        high_state = "room"; high_text = "кі м җ м—¬мң /нҷ•мқёмӨ‘"

    if _v262_has_text(money, ["л§ӨлҸ„мҡ°м„ё", "л§ӨлҸ„ мҡ°м„ё"]):
        money_state = "sell"; money_text = "лҸҲмқҖ мһҲм§Җл§Ң л§ӨлҸ„мҡ°м„ё"
    elif _v262_has_text(money, ["л°ҳм§қ", "мӢқлҠ”"]):
        money_state = "flash"; money_text = "л°ҳм§қ/мӢқлҠ”мӨ‘"
    elif _v262_has_text(money, ["лҸҲм–Ү", "мӢӨм ңлҸҲмһ‘мқҢ", "лҢҖкёҲнҷ•мқём „"]):
        money_state = "thin"; money_text = "лҸҲ м•Ҫн•Ё/м–ҮмқҢ"
    elif _v262_has_text(money, ["лҸҲмң м§Җ к°•н•Ё", "лҸҲмң м§Җ"]):
        money_state = "sustain"; money_text = str(money)[:28] or "лҸҲмң м§Җ"
    else:
        money_state = "watch"; money_text = str(money)[:28] or "лҸҲнқҗлҰ„ нҷ•мқёмӨ‘"

    return {
        "candle_code": candle_code, "candle_text": candle_text,
        "high_state": high_state, "high_text": high_text,
        "money_state": money_state, "money_text": money_text,
        "high_gap": high_gap, "trade_count": trade_count, "buy_ratio": buy_ratio,
        "upper_wick": upper_wick, "lower_wick": lower_wick,
    }


_PREV_SIGNAL_V257_CLASSIFY_V262 = _signal_v257_classify

def _signal_v257_classify(row: dict) -> dict:
    cls = dict(_PREV_SIGNAL_V257_CLASSIFY_V262(row) or {})
    try:
        st = _signal_v262_chart_state(row, cls)
        grade = str(cls.get("grade", "") or "").upper()
        score = safe_float(cls.get("score", 0), 0)
        chg3 = safe_float(cls.get("chg3", 0), 0)
        high_gap = safe_float(cls.get("high_gap", st.get("high_gap", 999)), 999)
        trade_count = int(safe_float(cls.get("trade_count", st.get("trade_count", 0)), 0))
        buy_ratio = safe_float(cls.get("buy_ratio", st.get("buy_ratio", 0)), 0)
        money_amount = safe_float(cls.get("money_amount", 0), 0)
        reasons = list(cls.get("reasons") or [])
        data_q = {}
        try:
            data_q = get_data_quality_v261(row if isinstance(row, dict) else {}) if 'get_data_quality_v261' in globals() else {}
        except Exception:
            data_q = {}
        data_grade = str(data_q.get("grade", "") or "")

        cls["chart_v262_candle"] = st.get("candle_text")
        cls["chart_v262_high"] = st.get("high_text")
        cls["chart_v262_money"] = st.get("money_text")
        cls["chart_v262_candle_code"] = st.get("candle_code")
        cls["chart_v262_high_state"] = st.get("high_state")
        cls["chart_v262_money_state"] = st.get("money_state")
        cls["data_quality_v262"] = data_grade

        downgrade = ""
        if grade == "BUY_OK":
            if st.get("candle_code") in {"weak", "small"}:
                downgrade = "нҳ„мһ¬лҙү к·јкұ° л¶ҖмЎұ"
            elif st.get("money_state") in {"sell", "flash", "thin"}:
                downgrade = "лҸҲнқҗлҰ„ м•Ҫн•Ё"
            elif trade_count < 2 or buy_ratio < 45:
                downgrade = "60мҙҲ мІҙкІ°/л§ӨмҲҳ к·јкұ° л¶ҖмЎұ"
            elif chg3 < 0:
                downgrade = "3л¶„ нқҗлҰ„ мқҢмҲҳ"
            elif data_grade == "D":
                downgrade = "лҚ°мқҙн„° л¶ҖмЎұ"
            if downgrade:
                _v262_inc("buy_ok_demoted", f"BUY_OK к°•л“ұ {cls.get('ticker','?')}/{downgrade}")
                cls["grade"] = "PULLBACK_WAIT" if st.get("money_state") not in {"thin", "sell"} else "DISCARD"
                cls["decision"] = "лҲҢлҰј лҢҖкё°" if cls["grade"] == "PULLBACK_WAIT" else "лІ„лҰј"
                cls["action"] = "м§ҖкёҲ л°”лЎң мӮ¬лҠ” кұҙ кёҲм§Җ. к·јкұ°к°Җ лҚ” мҢ“мқҙкұ°лӮҳ лҲҢлҰј кө¬к°„м—җ л“Өм–ҙмҳ¬ л•Ңл§Ң ліёлӢӨ." if cls["grade"] == "PULLBACK_WAIT" else "м§ҖкёҲ л§ӨмҲҳ мӢ нҳё м•„лӢҳ. лӘ…л №м–ҙ/ліөкё°м—җм„ңл§Ң м¶”м Ғ."
                reasons.insert(0, downgrade)
                cls["signal_v262_demoted"] = True

        grade = str(cls.get("grade", "") or "").upper()
        if grade == "BREAKOUT_WAIT":
            if st.get("money_state") in {"sell", "flash", "thin"}:
                downgrade = "лҸҲнқҗлҰ„мқҙ м•Ҫн•ҙм„ң лҸҢнҢҢлҢҖкё° к°•л“ұ"
            elif st.get("candle_code") == "weak":
                downgrade = "нҳ„мһ¬лҙүмқҙ л°Җл Өм„ң лҸҢнҢҢлҢҖкё° к°•л“ұ"
            elif st.get("high_state") == "touch" and (trade_count < 3 or buy_ratio < 45):
                downgrade = "кі м җ л§һлӢҝмқҢ + мІҙкІ° к·јкұ° л¶ҖмЎұ"
            elif money_amount < 50_000_000 and score < 8.0:
                downgrade = "лҢҖкёҲ/м җмҲҳ л¶ҖмЎұ"
            else:
                downgrade = ""
            if downgrade:
                _v262_inc("breakout_demoted", f"лҸҢнҢҢлҢҖкё° к°•л“ұ {cls.get('ticker','?')}/{downgrade}")
                cls["grade"] = "DISCARD"
                cls["decision"] = "м°ёкі  нӣ„ліҙ"
                cls["action"] = "м§ҖкёҲ л§ӨмҲҳ мӢ нҳёлҠ” м•„лӢҳ. кі м җ мң„м—җм„ң лІ„нӢ°лҠ”м§Җ лҚ” нҷ•мқён•  м°ёкі  нӣ„ліҙ."
                reasons.insert(0, downgrade)
                cls["signal_v262_reference_only"] = True

        grade = str(cls.get("grade", "") or "").upper()
        if grade == "PULLBACK_WAIT":
            if st.get("money_state") in {"sell", "thin"} or st.get("candle_code") == "weak":
                _v262_inc("chart_weak_block", f"лҲҢлҰј м•Ҫнҷ” {cls.get('ticker','?')}")
                cls["grade"] = "DISCARD"
                cls["decision"] = "м°ёкі  нӣ„ліҙ"
                cls["action"] = "лҲҢлҰјмІҳлҹј ліҙм—¬лҸ„ лҸҲнқҗлҰ„/нҳ„мһ¬лҙүмқҙ м•Ҫн•ҙм„ң м§ҖкёҲмқҖ м°ёкі л§Ң н•ңлӢӨ."
                reasons.insert(0, "лҲҢлҰј нӣ„ліҙм§Җл§Ң лҸҲнқҗлҰ„/нҳ„мһ¬лҙү м•Ҫн•Ё")
                cls["signal_v262_reference_only"] = True

        if str(cls.get("grade", "") or "").upper() == "DISCARD":
            _v262_inc("reference_only")
        try:
            reasons = _dedupe_reason_bits_v251(reasons) if '_dedupe_reason_bits_v251' in globals() else reasons
        except Exception:
            pass
        cls["reasons"] = reasons[:5]
    except Exception as e:
        try:
            append_runtime_error_log("signal_v262_classify", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
    return cls


_PREV_SIGNAL_V257_FORMAT_ONE_V262 = _signal_v257_format_one

def _signal_v257_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _PREV_SIGNAL_V257_FORMAT_ONE_V262(row, order=order, show_detail=show_detail)
    try:
        rr = apply_precision_minute1_state_to_row(dict(row or {})) if 'apply_precision_minute1_state_to_row' in globals() and isinstance(row, dict) else dict(row or {})
    except Exception:
        rr = dict(row or {})
    try:
        cls = _signal_v257_classify(rr)
        st = _signal_v262_chart_state(rr, cls)
        dq = get_data_quality_v261(rr) if 'get_data_quality_v261' in globals() else {}
        dq_text = str(dq.get("text", "лҚ°мқҙн„°н’Ҳм§Ҳ нҷ•мқёмӨ‘") or "лҚ°мқҙн„°н’Ҳм§Ҳ нҷ•мқёмӨ‘")
        ws_count = int(safe_float(dq.get("ws_count", cls.get("trade_count", 0)), 0))
        ws_buy = safe_float(dq.get("ws_buy_ratio", cls.get("buy_ratio", 0)), 0)
        lines = str(text).splitlines()
        insert_at = 1 if len(lines) > 1 else len(lines)
        if not any("лҚ°мқҙн„°н’Ҳм§Ҳ" in x for x in lines[:5]):
            lines.insert(insert_at, f"- лҚ°мқҙн„°н’Ҳм§Ҳ: {dq_text} / мӢӨмӢңк°„мІҙкІ° {ws_count}кұҙВ·л§ӨмҲҳ {ws_buy:.0f}%")
            insert_at += 1
        chart_line = f"- м°ЁнҠёмғҒнғң: нҳ„мһ¬лҙү {st.get('candle_text')} / кі м җ {st.get('high_text')} / лҸҲнқҗлҰ„ {st.get('money_text')}"
        if not any("м°ЁнҠёмғҒнғң:" in x for x in lines[:6]):
            lines.insert(insert_at, chart_line)
        for i, line in enumerate(lines):
            if line.startswith("- мқөм Ҳ: TP1") and "мҶҢм•ЎлӘЁл“ң" not in "\n".join(lines[i:i+2]):
                lines[i] = line + "\n- мҶҢм•ЎлӘЁл“ң: 1л§Ңмӣҗ мӢңмһ‘ кё°мӨҖмқҖ TP1~3 л¶„н• ліҙлӢӨ лӢЁмқјмқөм ҲВ·ліҙнҳёмҶҗм Ҳ мҡ°м„ "
                break
        return "\n".join(lines)
    except Exception:
        return text


def _signal_v262_weight(cls: dict) -> tuple:
    grade = str((cls or {}).get("grade", "") or "").upper()
    base = {"BUY_OK": 5, "PULLBACK_WAIT": 3, "BREAKOUT_WAIT": 3, "DISCARD": 1}.get(grade, 1)
    score = safe_float((cls or {}).get("score", 0), 0)
    money = safe_float((cls or {}).get("money_amount", 0), 0)
    chg = max(safe_float((cls or {}).get("chg3", 0), 0), safe_float((cls or {}).get("chg5", 0), 0))
    return (base, score, money, chg)


_PREV_BUILD_SIGNAL_TEXT_V262 = build_signal_text_v256

def build_signal_text_v256(args=None, limit: int = None) -> str:
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = " ".join([str(x) for x in args]).upper().strip()
    if target and target.isdigit():
        limit = max(1, min(int(target), 12)); target = ""
    rows = _signal_v257_collect_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V257, limit * 14))
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    if not rows:
        return "\n".join([
            "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
            f"- мӢңк°Ғ: {now_line}",
            "- м•„м§Ғ мӢ нҳё кі„мӮ°м—җ м“ё мҠӨлғ…мғ·мқҙ м—Ҷм–ҙ.",
            "- лЁјм Җ /rank_shortм—җм„ң нӣ„ліҙк°Җ ліҙмқҙлҠ”м§Җ нҷ•мқён•ҙмӨҳ.",
        ])

    if target:
        target_rows = [r for r in rows if _signal_v257_ticker(r) == target]
        if not target_rows:
            SIGNAL_V257_STATS["specific_miss"] = int(safe_float(SIGNAL_V257_STATS.get("specific_miss", 0), 0)) + 1
            return "\n".join([
                "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
                f"- мӢңк°Ғ: {now_line}",
                f"- {target}лҠ” нҳ„мһ¬ м ҖмһҘ мҠӨлғ…мғ·м—җм„ң лӘ» м°ҫм•ҳм–ҙ.",
                "- мғҲ APIлҘј л¶ҖлҘҙм§Җ м•ҠлҠ” лӘ…л №мқҙлқј мөңк·ј мҠӨлғ…мғ·м—җ м—Ҷмңјл©ҙ кі„мӮ°н•ҳм§Җ м•Ҡм•„.",
            ])
        SIGNAL_V257_STATS["specific_hit"] = int(safe_float(SIGNAL_V257_STATS.get("specific_hit", 0), 0)) + 1
        best = sorted(target_rows, key=lambda r: _signal_v262_weight(_signal_v257_classify(r)), reverse=True)[0]
        lines = [
            "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
            f"- мӢңк°Ғ: {now_line}",
            "- мғҲ API/OHLCV м§Ғм ‘мЎ°нҡҢ м—ҶмқҢ. м ҖмһҘлҗң rank/review/internal_watch + WS ліҙмЎ° кё°мӨҖ.",
            "- v2.5.262: лҚ°мқҙн„°н’Ҳм§ҲВ·нҳ„мһ¬лҙүВ·кі м җВ·лҸҲнқҗлҰ„мқ„ к°ҷмқҙ ліҙкі , м§„м§ң л§ӨмҲҳ нӣ„ліҙмҷҖ м°ёкі  нӣ„ліҙлҘј л¶„лҰ¬.",
            "- мҰүмӢң н‘ёмӢң м•ҢлҰјмқҖ л§ӨмҲҳВ·л§ӨлҸ„ мӢ нҳёл§Ң н—Ҳмҡ©. кҙҖмӢ¬/ліөкё°/лӮҙл¶Җк°җмӢңлҠ” лӘ…л №м–ҙм—җм„ңл§Ң лҙ„.",
            "",
            _signal_v257_format_one(best, order=1, show_detail=True),
            "",
            "лӘ…л №м–ҙ: /signal мҪ”мқёлӘ…  мҳҲ) /signal A",
        ]
        return "\n".join(lines).strip()

    classified = []
    for r in rows:
        try:
            c = _signal_v257_classify(r)
            classified.append((c, r))
        except Exception:
            continue
    classified.sort(key=lambda x: _signal_v262_weight(x[0]), reverse=True)
    trade = [(c, r) for c, r in classified if str(c.get("grade", "")).upper() == "BUY_OK"]
    wait = [(c, r) for c, r in classified if str(c.get("grade", "")).upper() in {"BREAKOUT_WAIT", "PULLBACK_WAIT"}]
    ref = [(c, r) for c, r in classified if str(c.get("grade", "")).upper() == "DISCARD"]
    PAPER_V262_STATS["signal_trade_count"] = len(trade)
    PAPER_V262_STATS["signal_reference_count"] = len(wait) + len(ref)

    lines = [
        "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
        f"- мӢңк°Ғ: {now_line}",
        "- мғҲ API/OHLCV м§Ғм ‘мЎ°нҡҢ м—ҶмқҢ. м ҖмһҘлҗң rank/review/internal_watch + WS ліҙмЎ° кё°мӨҖ.",
        "- v2.5.262: лҚ°мқҙн„°н’Ҳм§ҲВ·нҳ„мһ¬лҙүВ·кі м җВ·лҸҲнқҗлҰ„мқ„ к°ҷмқҙ ліҙкі , м§„м§ң л§ӨмҲҳ нӣ„ліҙмҷҖ м°ёкі  нӣ„ліҙлҘј л¶„лҰ¬.",
        "- мҰүмӢң н‘ёмӢң м•ҢлҰјмқҖ л§ӨмҲҳВ·л§ӨлҸ„ мӢ нҳёл§Ң н—Ҳмҡ©. кҙҖмӢ¬/ліөкё°/лӮҙл¶Җк°җмӢңлҠ” лӘ…л №м–ҙм—җм„ңл§Ң лҙ„.",
        "",
    ]
    shown = 0
    if trade:
        lines.append("рҹ”Ҙ м§„м§ң л§ӨмҲҳ нӣ„ліҙ")
        for c, r in trade[:max(1, min(2, limit))]:
            shown += 1
            lines.append(_signal_v257_format_one(r, order=shown, show_detail=False)); lines.append("")
    else:
        lines.append("- нҳ„мһ¬ мҰүмӢң л§ӨмҲҳ мӢ нҳё м—ҶмқҢ. м•„лһҳлҠ” м°ёкі  нӣ„ліҙл§Ң ліҙм—¬мӨҢ."); lines.append("")
    refs_to_show = wait[:max(1, limit - shown)]
    if not refs_to_show:
        refs_to_show = ref[:min(3, max(1, limit))]
    if refs_to_show:
        lines.append("рҹ§· м°ёкі  нӣ„ліҙ / л°”лЎң л§ӨмҲҳ м•„лӢҳ")
        for c, r in refs_to_show[:max(1, limit - shown if shown else limit)]:
            shown += 1
            lines.append(_signal_v257_format_one(r, order=shown, show_detail=False)); lines.append("")
    lines.append("лӘ…л №м–ҙ: /signal мҪ”мқёлӘ…  мҳҲ) /signal A")
    return "\n".join(lines).strip()


_PREV_BUILD_PAPER_STATS_TEXT_V262 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try:
        base = _PREV_BUILD_PAPER_STATS_TEXT_V262()
    except Exception as e:
        base = f"рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats\n- кё°ліё нҶөкі„ мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        now_ts = time.time()
        rows = _paper_closed_logs_v258()
        def by_start(ts):
            return [r for r in rows if safe_float(r.get("close_ts", r.get("cancel_ts", 0)), 0) >= ts]
        v262_rows = by_start(PAPER_V262_START_TS)
        six_rows = by_start(now_ts - 6 * 3600)
        extra = [
            "",
            "[лІ„м „лі„ м„ұкіј - мҙҲкё°нҷ” м—Ҷмқҙ л”°лЎң кі„мӮ°]",
            _paper_stats_line_v258("v262 м Ғмҡ© нӣ„", v262_rows),
            _paper_stats_line_v258("мөңк·ј 6мӢңк°„", six_rows),
        ]
        if v262_rows:
            strict_rows = [r for r in v262_rows if str(r.get("lane", "")) == "strict_signal"]
            loose_rows = [r for r in v262_rows if str(r.get("lane", "")) == "loose_threshold_test"]
            extra += [
                _paper_stats_line_v258("v262 мӢӨм „кёү strict", strict_rows),
                _paper_stats_line_v258("v262 мӢӨн—ҳмёө loose", loose_rows),
            ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base


_PREV_BUILD_CACHE_STATUS_TEXT_V262 = build_cache_status_text

def build_cache_status_text():
    try:
        base = _PREV_BUILD_CACHE_STATUS_TEXT_V262()
    except Exception as e:
        base = f"рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status\n- кё°ліё мғҒнғң мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        extra = [
            "",
            "рҹ“Ҳ v2.5.262 нӣ„ліҙн’Ҳм§Ҳ/м°ЁнҠём •көҗнҷ” 1м°Ё",
            f"- мӢ нҳёл¶„лҰ¬: м§„м§ңл§ӨмҲҳ {PAPER_V262_STATS.get('signal_trade_count',0)} / м°ёкі нӣ„ліҙ {PAPER_V262_STATS.get('signal_reference_count',0)}",
            f"- к°•л“ұ: BUY_OK {PAPER_V262_STATS.get('buy_ok_demoted',0)} / лҸҢнҢҢлҢҖкё° {PAPER_V262_STATS.get('breakout_demoted',0)} / м°ёкі м „нҷҳ {PAPER_V262_STATS.get('reference_only',0)}",
            f"- м°ЁнҠё/лҸҲнқҗлҰ„ м°ЁлӢЁ: нҳ„мһ¬лҙүм•Ҫн•Ё {PAPER_V262_STATS.get('chart_weak_block',0)} / л°ҳм§қВ·лҸҲм•Ҫн•Ё {PAPER_V262_STATS.get('money_flash_block',0)}",
            f"- мөңк·ј: {PAPER_V262_STATS.get('last_note','лҢҖкё°')}",
            "- мү¬мҡҙ лң»: м§ҖкёҲ мӮ¬лҸ„ лҗҳлҠ” нӣ„ліҙмҷҖ к·ёлғҘ м§Җмјңліј нӣ„ліҙлҘј лӮҳлҲ„кі , нҳ„мһ¬лҙүВ·кі м җВ·лҸҲнқҗлҰ„мқҙ м•Ҫн•ҳл©ҙ мң„лЎң лӘ» мҳ¬лқјмҳӨкІҢ н•Ё.",
        ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base


try:
    _PREV_BUILD_STARTUP_NOTICE_V262 = build_startup_notice_text
    def build_startup_notice_text():
        txt = _PREV_BUILD_STARTUP_NOTICE_V262()
        return str(txt).replace("v2.5.261", "v2.5.262").replace("REST/WS нҳјн•© лҚ°мқҙн„°н’Ҳм§Ҳ + мҶҢм•Ў лӢЁмқјмқөм Ҳ/ліҙнҳёмҶҗм Ҳ к°•нҷ”", "нӣ„ліҙн’Ҳм§Ҳ/м°ЁнҠём •көҗнҷ” 1м°Ё + мӢ нҳёл¶„лҰ¬")
except Exception:
    pass


# =========================================================
# v2.5.264: v263 мӢӨнҢЁ ліҙм •нҢҗ - нӣ„ліҙмёө м„ёл¶„нҷ”/л¬ён„ұнҳ• м°ЁлӢЁ м•Ҳм „ м Ғмҡ©
# =========================================================
# мӣҗм№ҷ:
# - нӣ„ліҙ мһ…кө¬(rank/review)лҠ” л§үм§Җ м•ҠлҠ”лӢӨ.
# - л§ӨмҲҳ м•ҢлҰј/paper м§„мһ…л§Ң л¬ён„ұмёөмңјлЎң мўҒнһҢлӢӨ.
# - кё°мЎҙ v262 н•ЁмҲҳлҠ” ліҙмЎҙн•ҳкі , м¶ңл Ҙ/л¶„лҘҳл§Ң м–ҮкІҢ лҚ®лҠ”лӢӨ.
PAPER_V264_START_TS = time.time()
PAPER_V264_STATS = {
    "buy_ready": 0,
    "breakout_watch": 0,
    "pullback_watch": 0,
    "watch_only": 0,
    "review_only": 0,
    "true_discard": 0,
    "paper_blocked": 0,
    "last_note": "лҢҖкё°",
}


def _v264_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V264_STATS:
            PAPER_V264_STATS[key] = int(safe_float(PAPER_V264_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V264_STATS["last_note"] = str(note)[:140]
    except Exception:
        pass


def _v264_text_has(text, words) -> bool:
    try:
        t = str(text or "")
        return any(str(w) in t for w in list(words or []))
    except Exception:
        return False


def _v264_bucket_from_cls(cls: dict, row: dict = None) -> dict:
    """нӣ„ліҙлҘј мЈҪмқҙм§Җ м•Ҡкі  мёөмңјлЎң лӮҳлҲҲлӢӨ. л§ӨмҲҳ/paperл§Ң мёөлі„ л¬ён„ұмңјлЎң л§үлҠ”лӢӨ."""
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    grade = str(cls.get("grade", "") or "").upper()
    score = safe_float(cls.get("score", 0), 0)
    money = safe_float(cls.get("money_amount", 0), 0)
    trade_count = int(safe_float(cls.get("trade_count", 0), 0))
    buy_ratio = safe_float(cls.get("buy_ratio", 0), 0)
    chg3 = safe_float(cls.get("chg3", 0), 0)
    chg5 = safe_float(cls.get("chg5", 0), 0)
    high_gap = safe_float(cls.get("high_gap", 999), 999)
    candle = str(cls.get("chart_v262_candle", cls.get("candle_label", "")) or "")
    money_text = str(cls.get("chart_v262_money", cls.get("money_sustain", "")) or "")
    high_text = str(cls.get("chart_v262_high", cls.get("high_label", "")) or "")
    data_grade = str(cls.get("data_quality_v262", row.get("data_quality_grade_v261", "")) or "")
    max_chg = max(chg3, chg5)

    candle_weak = _v264_text_has(candle, ["л°ҖлҰј", "мң—кј¬лҰ¬", "к·јкұ° м•Ҫн•Ё", "мқҳлҜё мһ‘мқҢ"])
    candle_alive = _v264_text_has(candle, ["мӮҙм•„лӮЁ", "нҡҢліө"])
    money_weak = _v264_text_has(money_text, ["л§ӨлҸ„мҡ°м„ё", "л°ҳм§қ", "мӢқлҠ”", "лҸҲ м•Ҫн•Ё", "лҸҲм–Ү", "мӢӨм ңлҸҲмһ‘мқҢ", "лҢҖкёҲнҷ•мқём „"])
    money_thin = _v264_text_has(money_text, ["лҸҲ м•Ҫн•Ё", "лҸҲм–Ү", "мӢӨм ңлҸҲмһ‘мқҢ", "лҢҖкёҲнҷ•мқём „"])
    high_touch = _v264_text_has(high_text, ["л§һлӢҝмқҢ", "л°”лЎң м•һ"])
    high_hold = _v264_text_has(high_text, ["лҸҢнҢҢ нӣ„ мң м§Җ"])

    # м§„м§ң лІ„лҰј: лҸҲ/м°ЁнҠё/мІҙкІ°мқҙ лӘЁл‘җ м•Ҫн•ҙм„ң paperлҸ„ нғңмҡ°л©ҙ нҶөкі„л§Ң л§қк°Җм§ҖлҠ” нӣ„ліҙ
    if data_grade == "D":
        return {"bucket": "true_discard", "label": "м§„м§ң лІ„лҰј", "reason": "лҚ°мқҙн„° л¶ҖмЎұ"}
    if money < 5_000_000 and score < 8.0:
        return {"bucket": "true_discard", "label": "м§„м§ң лІ„лҰј", "reason": "мӢӨм ң лҸҲмқҙ л„Ҳл¬ҙ мһ‘мқҢ"}
    if money_thin and trade_count < 2 and score < 8.5:
        return {"bucket": "true_discard", "label": "м§„м§ң лІ„лҰј", "reason": "лҸҲм–ҮмқҢ+мІҙкІ°л¶ҖмЎұ"}
    if candle_weak and money_weak and max_chg <= 0.15:
        return {"bucket": "true_discard", "label": "м§„м§ң лІ„лҰј", "reason": "нҳ„мһ¬лҙү/лҸҲнқҗлҰ„ л‘ҳ лӢӨ м•Ҫн•Ё"}

    if grade == "BUY_OK":
        bad = []
        if money < 150_000_000: bad.append("лҢҖкёҲ л¶ҖмЎұ")
        if trade_count < 5: bad.append("мІҙкІ°мҲҳ л¶ҖмЎұ")
        if buy_ratio < 55: bad.append("л§ӨмҲҳл№„мңЁ л¶ҖмЎұ")
        if chg3 < 0: bad.append("3л¶„ нқҗлҰ„ мқҢмҲҳ")
        if candle_weak or not candle_alive: bad.append("нҳ„мһ¬лҙү к·јкұ° л¶ҖмЎұ")
        if money_weak: bad.append("лҸҲнқҗлҰ„ м•Ҫн•Ё")
        if high_touch and buy_ratio < 62: bad.append("кі м җ л§һлӢҝмқҢ")
        if bad:
            return {"bucket": "watch_only", "label": "кө¬кІҪл§Ң", "reason": " / ".join(bad[:2])}
        return {"bucket": "buy_ready", "label": "м§„м§ң л§ӨмҲҳ", "reason": "лҸҲ/мІҙкІ°/нҳ„мһ¬лҙү нҶөкіј"}

    if grade == "BREAKOUT_WAIT":
        if money_weak or candle_weak:
            return {"bucket": "watch_only", "label": "кө¬кІҪл§Ң", "reason": "лҸҢнҢҢлҢҖкё°м§Җл§Ң лҸҲ/нҳ„мһ¬лҙү м•Ҫн•Ё"}
        if trade_count >= 4 and buy_ratio >= 45 and money >= 100_000_000 and (high_hold or 0 <= high_gap <= 0.8):
            return {"bucket": "breakout_watch", "label": "лҸҢнҢҢлҢҖкё°", "reason": "лҸҢнҢҢ нҷ•мқё лҢҖкё°"}
        return {"bucket": "review_only", "label": "ліөкё°/к°җмӢңл§Ң", "reason": "лҸҢнҢҢ к·јкұ° л¶ҖмЎұ"}

    if grade == "PULLBACK_WAIT":
        if money_thin or candle_weak:
            return {"bucket": "watch_only", "label": "кө¬кІҪл§Ң", "reason": "лҲҢлҰјлҢҖкё°м§Җл§Ң лҸҲ/нҳ„мһ¬лҙү м•Ҫн•Ё"}
        if money >= 80_000_000 and max_chg >= 0 and (trade_count >= 2 or buy_ratio >= 45):
            return {"bucket": "pullback_watch", "label": "лҲҢлҰјлҢҖкё°", "reason": "лҲҢлҰј/мһ¬м¶ңл°ң лҢҖкё°"}
        return {"bucket": "review_only", "label": "ліөкё°/к°җмӢңл§Ң", "reason": "лҲҢлҰј к·јкұ° л¶ҖмЎұ"}

    if money >= 100_000_000 and (trade_count >= 3 or score >= 6.0):
        return {"bucket": "review_only", "label": "ліөкё°/к°җмӢңл§Ң", "reason": "л§ӨмҲҳлҠ” м•„лӢҲм§Җл§Ң м¶”м Ғк°Җм№ҳ мһҲмқҢ"}
    return {"bucket": "true_discard", "label": "м§„м§ң лІ„лҰј", "reason": "л§ӨмҲҳ/к°җмӢң к·јкұ° л¶ҖмЎұ"}


_BASE_SIGNAL_CLASSIFY_V264 = _signal_v257_classify

def _signal_v257_classify(row: dict) -> dict:
    cls = dict(_BASE_SIGNAL_CLASSIFY_V264(row) or {})
    try:
        bucket = _v264_bucket_from_cls(cls, row if isinstance(row, dict) else {})
        b = str(bucket.get("bucket", "review_only") or "review_only")
        cls["v264_bucket"] = b
        cls["v264_label"] = str(bucket.get("label", ""))
        cls["v264_reason"] = str(bucket.get("reason", ""))
        _v264_inc(b, f"{cls.get('ticker','?')}/{bucket.get('label','')}/{bucket.get('reason','')}")
    except Exception as e:
        try:
            append_runtime_error_log("signal_v264_classify", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
    return cls


_BASE_SIGNAL_FORMAT_ONE_V264 = _signal_v257_format_one

def _signal_v264_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _BASE_SIGNAL_FORMAT_ONE_V264(row, order=order, show_detail=show_detail)
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {})
        label = str(cls.get("v264_label", "") or "")
        reason = str(cls.get("v264_reason", "") or "")
        if label:
            lines = str(text).splitlines()
            if not any("л¬ён„ұмёө:" in x for x in lines[:8]):
                lines.insert(1 if len(lines) > 1 else len(lines), f"- л¬ён„ұмёө: {label} / {reason}")
            return "\n".join(lines)
    except Exception:
        pass
    return text


def _signal_v264_weight(cls: dict) -> tuple:
    bucket = str((cls or {}).get("v264_bucket", "") or "")
    bucket_score = {"buy_ready": 6, "breakout_watch": 4, "pullback_watch": 4, "review_only": 2, "watch_only": 1, "true_discard": 0}.get(bucket, 1)
    score = safe_float((cls or {}).get("score", 0), 0)
    money = safe_float((cls or {}).get("money_amount", 0), 0)
    trade = int(safe_float((cls or {}).get("trade_count", 0), 0))
    buy = safe_float((cls or {}).get("buy_ratio", 0), 0)
    return (bucket_score, score, min(money, 50_000_000_000), trade, buy)


_BASE_BUILD_SIGNAL_TEXT_V264 = build_signal_text_v256

def build_signal_text_v256(args=None, limit: int = None) -> str:
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = " ".join([str(x) for x in args]).upper().strip()
    if target and target.isdigit():
        limit = max(1, min(int(target), 12)); target = ""
    rows = _signal_v257_collect_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V257, limit * 16))
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    if not rows:
        return "\n".join([
            "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
            f"- мӢңк°Ғ: {now_line}",
            "- м•„м§Ғ мӢ нҳё кі„мӮ°м—җ м“ё мҠӨлғ…мғ·мқҙ м—Ҷм–ҙ.",
            "- мқҙкұҙ л§ӨмҲҳ нӣ„ліҙк°Җ м—ҶлӢӨлҠ” лң»мқҙм§Җ rank/review нғҗмғүмқ„ кәјлІ„лҰ° кұҙ м•„лӢҲм•ј.",
        ])
    classified = []
    for r in rows:
        try:
            c = _signal_v257_classify(r)
            classified.append((c, r))
        except Exception:
            continue
    classified.sort(key=lambda x: _signal_v264_weight(x[0]), reverse=True)

    if target:
        target_rows = [(c, r) for c, r in classified if _signal_v257_ticker(r) == target]
        if not target_rows:
            return "\n".join([
                "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
                f"- мӢңк°Ғ: {now_line}",
                f"- {target}лҠ” нҳ„мһ¬ м ҖмһҘ мҠӨлғ…мғ·м—җм„ң лӘ» м°ҫм•ҳм–ҙ.",
                "- мғҲ APIлҘј л¶ҖлҘҙм§Җ м•ҠлҠ” лӘ…л №мқҙлқј мөңк·ј мҠӨлғ…мғ·м—җ м—Ҷмңјл©ҙ кі„мӮ°н•ҳм§Җ м•Ҡм•„.",
            ])
        c, best = sorted(target_rows, key=lambda x: _signal_v264_weight(x[0]), reverse=True)[0]
        return "\n".join([
            "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
            f"- мӢңк°Ғ: {now_line}",
            "- мғҲ API/OHLCV м§Ғм ‘мЎ°нҡҢ м—ҶмқҢ. м ҖмһҘлҗң rank/review/internal_watch + WS ліҙмЎ° кё°мӨҖ.",
            "- v2.5.264: нӣ„ліҙлҠ” мӮҙлҰ¬кі , л§ӨмҲҳ м•ҢлҰјл§Ң л¬ён„ұмёөмңјлЎң мўҒкІҢ л¶„лҰ¬.",
            "- мҰүмӢң н‘ёмӢң м•ҢлҰјмқҖ л§ӨмҲҳВ·л§ӨлҸ„ мӢ нҳёл§Ң н—Ҳмҡ©. к°җмӢң/ліөкё°лҠ” лӘ…л №м–ҙм—җм„ңл§Ң лҙ„.",
            "",
            _signal_v264_format_one(best, order=1, show_detail=True),
            "",
            "лӘ…л №м–ҙ: /signal мҪ”мқёлӘ…  мҳҲ) /signal A",
        ]).strip()

    buy = [(c, r) for c, r in classified if c.get("v264_bucket") == "buy_ready"]
    wait = [(c, r) for c, r in classified if c.get("v264_bucket") in {"breakout_watch", "pullback_watch"}]
    review = [(c, r) for c, r in classified if c.get("v264_bucket") in {"review_only", "watch_only"}]
    discard = [(c, r) for c, r in classified if c.get("v264_bucket") == "true_discard"]

    lines = [
        "рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal",
        f"- мӢңк°Ғ: {now_line}",
        "- мғҲ API/OHLCV м§Ғм ‘мЎ°нҡҢ м—ҶмқҢ. м ҖмһҘлҗң rank/review/internal_watch + WS ліҙмЎ° кё°мӨҖ.",
        "- v2.5.264: нӣ„ліҙлҠ” мӮҙлҰ¬кі , л§ӨмҲҳ м•ҢлҰјл§Ң л¬ён„ұмёөмңјлЎң мўҒкІҢ л¶„лҰ¬.",
        "- мҰүмӢң н‘ёмӢң м•ҢлҰјмқҖ л§ӨмҲҳВ·л§ӨлҸ„ мӢ нҳёл§Ң н—Ҳмҡ©. к°җмӢң/ліөкё°лҠ” лӘ…л №м–ҙм—җм„ңл§Ң лҙ„.",
        "",
    ]
    shown = 0
    if buy:
        lines.append("рҹ”Ҙ м§„м§ң л§ӨмҲҳ нӣ„ліҙ")
        for c, r in buy[:min(2, limit)]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    else:
        lines.append("- нҳ„мһ¬ мҰүмӢң л§ӨмҲҳ мӢ нҳё м—ҶмқҢ. нӣ„ліҙлҠ” м•„лһҳ л¬ён„ұмёөмңјлЎң лӮҳлҲ м„ң кі„мҶҚ м¶”м Ғн•Ё."); lines.append("")
    if wait and shown < limit:
        lines.append("рҹҹЎ лҢҖкё° нӣ„ліҙ / мЎ°кұҙ мўӢм•„м§Җл©ҙ л§ӨмҲҳ нӣ„ліҙлЎң мҠ№кІ© к°ҖлҠҘ")
        for c, r in wait[:max(1, min(limit - shown, 4))]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    if review and shown < limit:
        lines.append("рҹ§· кө¬кІҪВ·ліөкё° нӣ„ліҙ / м§ҖкёҲ л§ӨмҲҳ м•„лӢҳ")
        for c, r in review[:max(1, min(limit - shown, 3))]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    if not wait and not review and discard:
        lines.append("вӣ” м§„м§ң лІ„лҰј нӣ„ліҙ / м°ёкі л§Ң")
        for c, r in discard[:min(3, limit)]:
            shown += 1; lines.append(_signal_v264_format_one(r, order=shown, show_detail=False)); lines.append("")
    lines.append("лӘ…л №м–ҙ: /signal мҪ”мқёлӘ…  мҳҲ) /signal A")
    return "\n".join(lines).strip()


_BASE_PAPER_CLASSIFY_FOR_REGISTER_V264 = _paper_classify_for_register_v258

def _paper_classify_for_register_v258(row: dict):
    try:
        ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_FOR_REGISTER_V264(row)
    except Exception as e:
        try:
            append_runtime_error_log("paper_classify_base_v264", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return False, "blocked_v264", f"кё°ліё paper л¶„лҘҳ мҳӨлҘҳ: {e}", {}
    try:
        cls = dict(cls or {})
        bucket = str(cls.get("v264_bucket", "") or "")
        if bucket not in {"buy_ready", "breakout_watch", "pullback_watch"}:
            _v264_inc("paper_blocked", f"paper м°ЁлӢЁ {cls.get('ticker','?')}/{bucket or 'none'}")
            return False, "blocked_v264", f"v264 л¬ён„ұмёө paper м°ЁлӢЁ: {cls.get('v264_label','-')} / {cls.get('v264_reason','')}", cls
        return ok, lane, reason, cls
    except Exception:
        return ok, lane, reason, cls


_BASE_CACHE_STATUS_TEXT_V264 = build_cache_status_text

def build_cache_status_text():
    try:
        base = _BASE_CACHE_STATUS_TEXT_V264()
    except Exception as e:
        base = f"рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status\n- кё°ліё мғҒнғң мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        extra = [
            "",
            "рҹ§ұ v2.5.264 нӣ„ліҙмёө м„ёл¶„нҷ”/л¬ён„ұнҳ• м°ЁлӢЁ",
            f"- л¬ён„ұмёө: м§„м§ңл§ӨмҲҳ {PAPER_V264_STATS.get('buy_ready',0)} / лҸҢнҢҢлҢҖкё° {PAPER_V264_STATS.get('breakout_watch',0)} / лҲҢлҰјлҢҖкё° {PAPER_V264_STATS.get('pullback_watch',0)} / кө¬кІҪ {PAPER_V264_STATS.get('watch_only',0)} / ліөкё° {PAPER_V264_STATS.get('review_only',0)} / м§„м§ңлІ„лҰј {PAPER_V264_STATS.get('true_discard',0)}",
            f"- paper м°ЁлӢЁ: {PAPER_V264_STATS.get('paper_blocked',0)}",
            f"- мөңк·ј: {PAPER_V264_STATS.get('last_note','лҢҖкё°')}",
            "- мү¬мҡҙ лң»: нӣ„ліҙ мһ…кө¬лҠ” л§үм§Җ м•Ҡкі , л§ӨмҲҳВ·лҢҖкё°В·кө¬кІҪВ·ліөкё°В·м§„м§ңлІ„лҰјмңјлЎң лӮҳлҲ м„ң м•ҢлҰјмқҙ л§ҲлҘҙм§Җ м•ҠкІҢ н•Ё.",
        ]
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base


_BASE_PAPER_STATS_TEXT_V264 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try:
        base = _BASE_PAPER_STATS_TEXT_V264()
    except Exception as e:
        base = f"рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats\n- кё°ліё нҶөкі„ мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        rows = _paper_closed_logs_v258()
        v264_rows = [r for r in rows if safe_float(r.get("close_ts", r.get("cancel_ts", 0)), 0) >= PAPER_V264_START_TS]
        extra = ["", "[v264 мқҙнӣ„ м„ұкіј - л¬ён„ұмёө м Ғмҡ© нӣ„]", _paper_stats_line_v258("v264 м Ғмҡ© нӣ„", v264_rows)]
        if v264_rows:
            strict_rows = [r for r in v264_rows if str(r.get("lane", "")) == "strict_signal"]
            loose_rows = [r for r in v264_rows if str(r.get("lane", "")) == "loose_threshold_test"]
            extra.append(_paper_stats_line_v258("v264 strict", strict_rows))
            extra.append(_paper_stats_line_v258("v264 loose", loose_rows))
        return str(base).rstrip() + "\n" + "\n".join(extra)
    except Exception:
        return base


try:
    _BASE_STARTUP_NOTICE_V264 = build_startup_notice_text
    def build_startup_notice_text():
        txt = _BASE_STARTUP_NOTICE_V264()
        return str(txt).replace("v2.5.262", "v2.5.264").replace("нӣ„ліҙн’Ҳм§Ҳ/м°ЁнҠём •көҗнҷ” 1м°Ё + мӢ нҳёл¶„лҰ¬", "v263 мӢӨнҢЁ ліҙм • + нӣ„ліҙмёө м„ёл¶„нҷ”")
except Exception:
    pass



# =========================================================
# v2.5.265: л¬ён„ұмёө л¬ёкө¬ м •лҰ¬ + мғҒнҷ©лі„ лӢЁмқјл§ӨлҸ„/мҶҗм ҲнҸӯ м•Ҳм „мһҘм№ҳ
# =========================================================
# мү¬мҡҙ лң»:
# - нӣ„ліҙлҠ” кі„мҶҚ мӮҙл Өл‘җлҗҳ, м§„м§ң лІ„лҰҙ нӣ„ліҙл§Ң "м§„м§ң лІ„лҰј"мқҙлқјкі  н‘ңмӢңн•ңлӢӨ.
# - 1л§Ңмӣҗ мӢңмһ‘ кё°мӨҖмқҖ л¶„н• л§ӨлҸ„ліҙлӢӨ лӢЁмқјл§ӨлҸ„лӢӨ. лӢЁ, мһҘ/мҪ”мқё нһҳм—җ л”°лқј м§§кІҢ лЁ№кұ°лӮҳ лҚ” лҒҢкі  к°„лӢӨ.
# - POLA -5%лҢҖ к°ҷмқҖ лӘЁмқҳ мҶҗмӢӨмқҙ л°ҳліөлҗҳм§Җ м•ҠлҸ„лЎқ мҶҗм ҲнҸӯмқ„ мўҒнһҲкі , paperм—җм„ңлҠ” stop к°ҖкІ© кё°мӨҖмңјлЎң мІӯмӮ°н•ңлӢӨ.
# - л§Ө мҲҳм •л§ҲлӢӨ мөңмў… лӘ©н‘ң 10лӢЁкі„мҷҖ к°ҷмқҙ лҙҗм•ј н•ңлӢӨлҠ” кі м • мӣҗм№ҷмқ„ мқёмҲҳмқёкі„ мғҒлӢЁм—җ мң м§Җн•ңлӢӨ.
PAPER_V265_START_TS = time.time()
PAPER_V265_STRICT_MAX_LOSS_PCT = 1.45
PAPER_V265_LOOSE_MAX_LOSS_PCT = 1.20
PAPER_V265_WEAK_MAX_LOSS_PCT = 1.05
PAPER_V265_HARD_LOSS_PCT = 1.85
PAPER_V265_QUICK_TP_PCT = 0.75
PAPER_V265_BASIC_TP_MIN_PCT = 0.90
PAPER_V265_TREND_MIN_HOLD_TP_PCT = 1.25
PAPER_V265_SLOW_EXIT_MIN_SEC = 22 * 60
PAPER_V265_STATS = {
    "stop_capped": 0,
    "hard_stop": 0,
    "quick_exit": 0,
    "basic_exit": 0,
    "trend_exit": 0,
    "protect_exit": 0,
    "slow_exit": 0,
    "paper_tagged": 0,
    "last_note": "лҢҖкё°",
}

def _v265_inc(key: str, note: str = ""):
    try:
        PAPER_V265_STATS[key] = int(safe_float(PAPER_V265_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V265_STATS["last_note"] = str(note)[:140]
    except Exception:
        pass


def _v265_market_mode() -> dict:
    """мӢңмһҘмғҒнғңлҘј мү¬мҡҙ л§ӨлҸ„лӘЁл“ңмҡ©мңјлЎң мӨ„мқёлӢӨ. мЎ°нҡҢ мӢӨнҢЁл©ҙ ліҙнҶөмңјлЎң лӢЁм •н•ҳм§Җ м•ҠлҠ”лӢӨ."""
    try:
        reg = get_market_regime() if 'get_market_regime' in globals() else {}
        name = str((reg or {}).get('name', 'UNKNOWN') or 'UNKNOWN').upper()
        if name in {'BLOCK', 'WEAK'}:
            mode = 'weak'
            text = 'м•Ҫн•ң мһҘ'
        elif name == 'STRONG_UP':
            mode = 'strong'
            text = 'к°•н•ң мһҘ'
        elif name in {'SIDEWAYS', 'NORMAL'}:
            mode = 'normal'
            text = 'ліҙнҶө/нҡЎліҙ мһҘ'
        else:
            mode = 'unknown'
            text = 'мӢңмһҘ нҢҗлӢЁ л¶ҖмЎұ'
        return {"mode": mode, "text": text, "raw": reg}
    except Exception:
        return {"mode": "unknown", "text": "мӢңмһҘ нҢҗлӢЁ мҳӨлҘҳ", "raw": {}}


def _v265_trade_strength(ticker: str, pos: dict = None) -> dict:
    ticker = str(ticker or '').upper().strip()
    pos = pos if isinstance(pos, dict) else {}
    cnt = int(safe_float(pos.get('trade_count', 0), 0))
    buy = safe_float(pos.get('buy_ratio', 0), 0)
    amount = safe_float(pos.get('money_amount', 0), 0)
    try:
        if ticker and 'get_ws_trade_summary_for_ticker' in globals():
            s = get_ws_trade_summary_for_ticker(ticker, 60)
            if isinstance(s, dict):
                cnt = max(cnt, int(safe_float(s.get('count', 0), 0)))
                if int(safe_float(s.get('count', 0), 0)) > 0:
                    buy = safe_float(s.get('buy_ratio', buy), buy)
                amount = max(amount, safe_float(s.get('amount', 0), 0))
    except Exception:
        pass
    strong = cnt >= 8 and buy >= 55 and amount >= 50_000_000
    weak = (cnt <= 1) or (buy > 0 and buy < 35)
    sell_heavy = buy > 0 and buy < 45
    return {"count": cnt, "buy_ratio": buy, "amount": amount, "strong": strong, "weak": weak, "sell_heavy": sell_heavy}


def _v265_stop_cap_pct(pos: dict, market_mode: str = None) -> float:
    lane = str((pos or {}).get('lane', '') or '')
    entry_rule = str((pos or {}).get('entry_rule', '') or '')
    if lane == 'loose_threshold_test':
        cap = PAPER_V265_LOOSE_MAX_LOSS_PCT
    else:
        cap = PAPER_V265_STRICT_MAX_LOSS_PCT
    if entry_rule == 'breakout':
        cap = min(cap, 1.25)
    if market_mode == 'weak':
        cap = min(cap, PAPER_V265_WEAK_MAX_LOSS_PCT)
    return max(0.45, safe_float(cap, 1.3))


def _v265_tighten_stop(pos: dict, market_mode: str = None) -> dict:
    pos = dict(pos or {})
    entry = safe_float(pos.get('entry_price', 0), 0)
    if entry <= 0:
        return pos
    stop = safe_float(pos.get('stop', 0), 0)
    cap_pct = _v265_stop_cap_pct(pos, market_mode=market_mode)
    min_stop = entry * (1 - cap_pct / 100.0)
    if stop <= 0 or stop < min_stop:
        pos['stop'] = min_stop
        pos['v265_stop_cap_pct'] = cap_pct
        pos['v265_stop_capped'] = True
        _v265_inc('stop_capped', f"мҶҗм ҲнҸӯ ліҙм • {pos.get('ticker','?')}/{cap_pct:.2f}%")
    return pos


def _v265_sell_mode(pos: dict, pnl: float, max_up: float, trade: dict, market: dict) -> dict:
    pos = pos if isinstance(pos, dict) else {}
    trade = trade if isinstance(trade, dict) else {}
    market = market if isinstance(market, dict) else {}
    m = str(market.get('mode', 'unknown'))
    entry_rule = str(pos.get('entry_rule', '') or '')
    buy = safe_float(trade.get('buy_ratio', 0), 0)
    cnt = int(safe_float(trade.get('count', 0), 0))
    strong_coin = bool(trade.get('strong')) or (max_up >= 1.2 and buy >= 50 and cnt >= 5)
    weak_coin = bool(trade.get('weak')) or bool(trade.get('sell_heavy'))
    if m == 'weak' or weak_coin:
        return {"mode": "quick", "text": "м§§кІҢ лЁ№кё°", "why": "мһҘ/мІҙкІ°мқҙ м•Ҫн•ҙм„ң мҡ•мӢ¬ мӨ„мһ„"}
    if m == 'strong' and strong_coin:
        return {"mode": "trend", "text": "лҚ” лҒҢкі  к°Җкё°", "why": "мһҘкіј мҪ”мқё нһҳмқҙ мӮҙм•„мһҲмқҢ"}
    if entry_rule == 'now' and buy < 50:
        return {"mode": "quick", "text": "м§§кІҢ лЁ№кё°", "why": "мҰүмӢңм§„мһ…мқёлҚ° л§ӨмҲҳм„ёк°Җ м•Ҫн•Ё"}
    return {"mode": "basic", "text": "кё°ліё мқөм Ҳ", "why": "кё°ліё кё°мӨҖ"}


def _v265_close_price_for_stop(entry: float, price: float, stop: float) -> float:
    entry = safe_float(entry, 0); price = safe_float(price, 0); stop = safe_float(stop, 0)
    if entry > 0 and stop > 0 and price > 0 and price <= stop:
        return max(price, stop)
    return price

_PREV_PAPER_REGISTER_CANDIDATE_V265 = paper_register_candidate_v258

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    ok = _PREV_PAPER_REGISTER_CANDIDATE_V265(row, trigger=trigger)
    if not ok:
        return False
    try:
        ticker = _paper_ticker_v258(row)
        cls = _signal_v257_classify(row if isinstance(row, dict) else {}) if '_signal_v257_classify' in globals() else {}
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            best_id = None; best_ts = -1.0
            for pid, p in (paper_positions or {}).items():
                if isinstance(p, dict) and str(p.get('ticker','')).upper().strip() == ticker:
                    ts = safe_float(p.get('created_ts', 0), 0)
                    if ts > best_ts:
                        best_ts = ts; best_id = pid
            if best_id and now_ts - best_ts <= 10:
                p = paper_positions[best_id]
                p['paper_version'] = 'v2.5.265'
                p['v265_bucket'] = str(cls.get('v264_bucket', p.get('v264_bucket', '')) or '')
                p['v265_label'] = str(cls.get('v264_label', p.get('v264_label', '')) or '')
                p['v265_reason'] = str(cls.get('v264_reason', p.get('v264_reason', '')) or '')
                old_reason = str(p.get('register_reason', '') or '')
                if p.get('v265_label'):
                    p['register_reason'] = f"{p.get('v265_label')} / {p.get('v265_reason')}"
                p['note'] = 'мӢӨм ң мЈјл¬ё м•„лӢҳ / v265 л¬ён„ұмёө+мғҒнҷ©лі„ лӢЁмқјл§ӨлҸ„ кІҖмҰқ'
                if str(p.get('status','')).upper() == 'OPEN':
                    paper_positions[best_id] = _v265_tighten_stop(p, market_mode=_v265_market_mode().get('mode'))
                _v265_inc('paper_tagged', f"л“ұлЎқнғңк·ё {ticker}/{p.get('v265_label') or old_reason}")
        save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log('paper_register_v265_followup', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return True


def paper_update_positions_once_v258():
    if not PAPER_TRADING_ON:
        return
    now_ts = time.time()
    changed = False
    try:
        market = _v265_market_mode()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            ticker = str(pos.get('ticker', '') or '').upper().strip()
            if not ticker:
                continue
            status = str(pos.get('status', '') or '').upper()
            fallback = safe_float(pos.get('last_price', pos.get('entry_price', 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            pos['last_price'] = price
            pos['last_price_source'] = src
            pos['last_price_age'] = safe_float(age, 0)
            pos['updated_ts'] = now_ts
            if status == 'PENDING':
                if now_ts - safe_float(pos.get('created_ts', now_ts), now_ts) >= PAPER_PENDING_TTL_SEC:
                    _paper_cancel_pending_v258(pid, pos, 'pending_timeout', now_ts)
                    continue
                entry_rule = str(pos.get('entry_rule', '') or '')
                low = safe_float(pos.get('planned_entry_low', 0), 0)
                high = safe_float(pos.get('planned_entry_high', 0), 0)
                chase = safe_float(pos.get('chase_stop', 0), 0)
                enter = False
                if entry_rule == 'breakout' and low > 0 and price >= low and (chase <= 0 or price <= chase):
                    enter = True
                elif entry_rule == 'pullback' and low > 0 and high > 0 and low <= price <= high:
                    enter = True
                elif entry_rule == 'now':
                    enter = True
                if chase > 0 and price > chase and entry_rule != 'now':
                    _paper_cancel_pending_v258(pid, pos, 'chase_over_before_entry', now_ts)
                    continue
                if enter:
                    pos['status'] = 'OPEN'
                    pos['entry_price'] = price
                    pos['entered_ts'] = now_ts
                    pos['remaining_ratio'] = 1.0
                    pos['realized_pct'] = 0.0
                    pos['single_exit_mode_v265'] = True
                    pos = _v265_tighten_stop(pos, market_mode=market.get('mode'))
                    PAPER_V258_STATS['entered'] = int(safe_float(PAPER_V258_STATS.get('entered', 0), 0)) + 1
                    changed = True
            if str(pos.get('status', '') or '').upper() == 'OPEN':
                entry = safe_float(pos.get('entry_price', 0), 0)
                if entry <= 0:
                    continue
                pos = _v265_tighten_stop(pos, market_mode=market.get('mode'))
                pnl = _paper_pct_v258(entry, price)
                pos['max_up_pct'] = max(safe_float(pos.get('max_up_pct', pnl), pnl), pnl)
                pos['min_down_pct'] = min(safe_float(pos.get('min_down_pct', pnl), pnl), pnl)
                max_up = safe_float(pos.get('max_up_pct', pnl), pnl)
                tp1 = safe_float(pos.get('tp1', 0), 0)
                tp2 = safe_float(pos.get('tp2', 0), 0)
                tp3 = safe_float(pos.get('tp3', 0), 0)
                stop = safe_float(pos.get('stop', 0), 0)
                open_age = now_ts - safe_float(pos.get('entered_ts', now_ts), now_ts)
                trade = _v265_trade_strength(ticker, pos)
                sell_mode = _v265_sell_mode(pos, pnl, max_up, trade, market)
                pos['v265_sell_mode'] = sell_mode.get('mode')
                pos['v265_sell_mode_text'] = sell_mode.get('text')
                pos['v265_sell_mode_why'] = sell_mode.get('why')
                pos['v265_ws_trade_count'] = int(safe_float(trade.get('count',0),0))
                pos['v265_ws_buy_ratio'] = safe_float(trade.get('buy_ratio',0),0)
                close_reason = ''
                close_price = price
                if stop > 0 and price <= stop:
                    close_reason = 'stop_loss_v265' if max_up < PAPER_V261_LOCK1_UP_PCT else 'protect_stop_v265'
                    close_price = _v265_close_price_for_stop(entry, price, stop)
                    if max_up >= PAPER_V261_LOCK1_UP_PCT:
                        _v265_inc('protect_exit', f"ліҙнҳёмІӯмӮ° {ticker}/{pnl:+.2f}")
                    else:
                        _v265_inc('hard_stop', f"мҶҗм Ҳ {ticker}/{_paper_pct_v258(entry, close_price):+.2f}")
                elif pnl <= -PAPER_V265_HARD_LOSS_PCT:
                    hard_price = entry * (1 - PAPER_V265_HARD_LOSS_PCT / 100.0)
                    close_reason = 'hard_stop_v265'
                    close_price = max(price, hard_price)
                    _v265_inc('hard_stop', f"л№„мғҒмҶҗм Ҳ {ticker}/{_paper_pct_v258(entry, close_price):+.2f}")
                else:
                    mode = str(sell_mode.get('mode','basic'))
                    tp1_pct = _paper_pct_v258(entry, tp1) if tp1 > 0 else 0.0
                    quick_target = max(PAPER_V265_QUICK_TP_PCT, min(1.05, tp1_pct if tp1_pct > 0 else PAPER_V265_QUICK_TP_PCT))
                    basic_target = max(PAPER_V265_BASIC_TP_MIN_PCT, tp1_pct if tp1_pct > 0 else PAPER_V265_BASIC_TP_MIN_PCT)
                    if mode == 'quick':
                        if pnl >= quick_target:
                            close_reason = 'quick_take_profit_v265'; _v265_inc('quick_exit', f"м§§кІҢмқөм Ҳ {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK1_UP_PCT and pnl <= max(0.15, PAPER_V261_LOCK1_KEEP_PCT):
                            close_reason = 'quick_profit_protect_v265'; _v265_inc('protect_exit', f"л№ лҘёліҙнҳё {ticker}/{pnl:+.2f}")
                    elif mode == 'trend':
                        if tp3 > 0 and price >= tp3:
                            close_reason = 'trend_tp3_exit_v265'; _v265_inc('trend_exit', f"м¶”м„ёTP3 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK3_UP_PCT and pnl <= PAPER_V261_LOCK3_KEEP_PCT:
                            close_reason = 'trend_profit_lock_3_v265'; _v265_inc('protect_exit', f"м¶”м„ёліҙнҳё3 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK2_UP_PCT and pnl <= PAPER_V261_LOCK2_KEEP_PCT:
                            close_reason = 'trend_profit_lock_2_v265'; _v265_inc('protect_exit', f"м¶”м„ёліҙнҳё2 {ticker}/{pnl:+.2f}")
                        elif pnl >= basic_target and bool(trade.get('sell_heavy')):
                            close_reason = 'trend_weakening_exit_v265'; _v265_inc('trend_exit', f"нһҳл№ м§җмІӯмӮ° {ticker}/{pnl:+.2f}")
                    else:
                        if pnl >= basic_target or (tp1 > 0 and price >= tp1):
                            close_reason = 'basic_single_tp_v265'; _v265_inc('basic_exit', f"кё°ліёмқөм Ҳ {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK2_UP_PCT and pnl <= PAPER_V261_LOCK2_KEEP_PCT:
                            close_reason = 'basic_profit_lock_2_v265'; _v265_inc('protect_exit', f"кё°ліёліҙнҳё2 {ticker}/{pnl:+.2f}")
                        elif max_up >= PAPER_V261_LOCK1_UP_PCT and pnl <= PAPER_V261_LOCK1_KEEP_PCT:
                            close_reason = 'basic_profit_lock_1_v265'; _v265_inc('protect_exit', f"кё°ліёліҙнҳё1 {ticker}/{pnl:+.2f}")
                    if not close_reason:
                        if open_age >= PAPER_OPEN_TTL_SEC:
                            close_reason = f"time_exit_{mode}_v265"
                        elif open_age >= PAPER_V265_SLOW_EXIT_MIN_SEC and max_up < PAPER_V261_LOCK1_UP_PCT and pnl <= PAPER_V261_SLOW_EXIT_MAX_PNL:
                            close_reason = f"slow_no_progress_exit_{mode}_v265"; _v265_inc('slow_exit', f"л¬ҙм§„н–үм •лҰ¬ {ticker}/{pnl:+.2f}")
                if close_reason:
                    pos['v265_market_mode'] = market.get('text')
                    pos['v265_close_rule'] = close_reason
                    _paper_close_position_v258(pid, pos, close_price, close_reason, now_ts)
                    continue
                stop_now = safe_float(pos.get('stop', 0), 0)
                if max_up >= PAPER_V261_LOCK3_UP_PCT:
                    pos['stop'] = max(stop_now, entry * (1 + PAPER_V261_LOCK3_KEEP_PCT / 100.0))
                elif max_up >= PAPER_V261_LOCK2_UP_PCT:
                    pos['stop'] = max(stop_now, entry * (1 + PAPER_V261_LOCK2_KEEP_PCT / 100.0))
                elif max_up >= PAPER_V261_LOCK1_UP_PCT:
                    pos['stop'] = max(stop_now, entry * (1 + PAPER_V261_LOCK1_KEEP_PCT / 100.0))
                with PAPER_STATE_LOCK:
                    if pid in paper_positions:
                        paper_positions[pid].update(pos)
                changed = True
        if changed:
            save_paper_state_v258()
    except Exception as e:
        append_runtime_error_log('paper_update_positions_v265', str(e), exc=e, include_traceback=False)

_PREV_SIGNAL_V264_FORMAT_ONE_FOR_V265 = _signal_v264_format_one

def _signal_v264_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _PREV_SIGNAL_V264_FORMAT_ONE_FOR_V265(row, order=order, show_detail=show_detail)
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {})
        bucket = str(cls.get('v264_bucket', '') or '')
        lines = str(text).splitlines()
        if not lines:
            return text
        import re as _re
        m = _re.match(r'^(\d+\.\s+)(\S+)\s+([^/]+?)\s*/\s*([^/]+)(/.*)?$', lines[0])
        if m:
            prefix, icon, ticker_part, _old, tail = m.groups(); tail = tail or ''
            if bucket == 'review_only': lines[0] = f"{prefix}рҹ§· {ticker_part.strip()} / ліөкё°В·к°җмӢң{tail}"
            elif bucket == 'watch_only': lines[0] = f"{prefix}рҹ‘Җ {ticker_part.strip()} / кө¬кІҪл§Ң{tail}"
            elif bucket == 'true_discard': lines[0] = f"{prefix}вӣ” {ticker_part.strip()} / м§„м§ң лІ„лҰј{tail}"
            elif bucket == 'breakout_watch': lines[0] = f"{prefix}рҹҹ  {ticker_part.strip()} / лҸҢнҢҢлҢҖкё°{tail}"
            elif bucket == 'pullback_watch': lines[0] = f"{prefix}рҹҹЎ {ticker_part.strip()} / лҲҢлҰјлҢҖкё°{tail}"
            elif bucket == 'buy_ready': lines[0] = f"{prefix}рҹ”Ҙ {ticker_part.strip()} / м§„м§ң л§ӨмҲҳ нӣ„ліҙ{tail}"
        if bucket in {'review_only', 'watch_only'}:
            lines = [x.replace('м§ҖкёҲ лҸҲ л„Јмқ„ нӣ„ліҙ м•„лӢҳ. лӘ…л №м–ҙ/ліөкё°м—җм„ңл§Ң м¶”м Ғ.', 'м§ҖкёҲ л§ӨмҲҳлҠ” м•„лӢҳ. к°җмӢң/ліөкё°м—җм„ң кі„мҶҚ м¶”м Ғ.') for x in lines]
        return "\n".join(lines)
    except Exception:
        return text

_PREV_BUILD_PAPER_TEXT_V265 = build_paper_text_v258

def build_paper_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_TEXT_V265(limit=limit)
    try:
        reps = {
            '- v261: REST/WS нҳјн•© лҚ°мқҙн„°н’Ҳм§Ҳмқ„ ліҙкі , 1л§Ңмӣҗ мҶҢм•Ў кё°мӨҖмқҖ лӢЁмқјмқөм ҲВ·ліҙнҳёмҶҗм Ҳ мӨ‘мӢ¬.': '- v265: нӣ„ліҙмёө кё°мӨҖмңјлЎң л“ұлЎқн•ҳкі , мһҘ/мҪ”мқё нһҳм—җ л”°лқј м§§кІҢ лЁ№кё°В·кё°ліёмқөм ҲВ·лҚ” лҒҢкі к°Җкё°лҘј лӮҳлҲ”.',
            'л“ұлЎқмқҙмң : strict нҶөкіј v260': 'л“ұлЎқмқҙмң : л¬ён„ұмёө strict лҢҖкё°нӣ„ліҙ',
            'л“ұлЎқмқҙмң : loose л¬ён„ұ кІҖмҰқмёө v260': 'л“ұлЎқмқҙмң : л¬ён„ұмёө loose мӢӨн—ҳнӣ„ліҙ',
            'л“ұлЎқмқҙмң : strict нҶөкіј': 'л“ұлЎқмқҙмң : л¬ён„ұмёө strict лҢҖкё°нӣ„ліҙ',
        }
        for a,b in reps.items(): text = str(text).replace(a,b)
        with PAPER_STATE_LOCK:
            open_modes = {str(p.get('ticker','')).upper().strip(): (str(p.get('v265_sell_mode_text','') or ''), str(p.get('v265_sell_mode_why','') or '')) for p in (paper_positions or {}).values() if isinstance(p, dict)}
        lines = []
        for line in str(text).splitlines():
            lines.append(line)
            if line.startswith('- мҶҗм Ҳ '):
                recent = '\n'.join(lines[-4:])
                import re as _re
                m = _re.search(r'вң…\s+([A-Z0-9]+)\s+/', recent)
                if m:
                    mode, why = open_modes.get(m.group(1), ('',''))
                    if mode: lines.append(f"- л§ӨлҸ„лӘЁл“ң: {mode} / {why}")
        return '\n'.join(lines)
    except Exception:
        return text

