_PREV_BUILD_PAPER_STATS_TEXT_V265 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try: base = _PREV_BUILD_PAPER_STATS_TEXT_V265()
    except Exception as e: base = f"рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats\n- кё°ліё нҶөкі„ мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        rows = _paper_closed_logs_v258()
        v265_rows = [r for r in rows if safe_float(r.get('close_ts', r.get('cancel_ts', 0)), 0) >= PAPER_V265_START_TS]
        extra = ['', '[v265 мқҙнӣ„ м„ұкіј - мғҒнҷ©лі„ л§ӨлҸ„/мҶҗм ҲнҸӯ ліҙм • нӣ„]', _paper_stats_line_v258('v265 м Ғмҡ© нӣ„', v265_rows)]
        if v265_rows:
            strict_rows = [r for r in v265_rows if str(r.get('lane','')) == 'strict_signal']
            loose_rows = [r for r in v265_rows if str(r.get('lane','')) == 'loose_threshold_test']
            extra.append(_paper_stats_line_v258('v265 strict', strict_rows))
            extra.append(_paper_stats_line_v258('v265 loose', loose_rows))
            buckets=[('м§„м§ңл§ӨмҲҳ','buy_ready'),('лҸҢнҢҢлҢҖкё°','breakout_watch'),('лҲҢлҰјлҢҖкё°','pullback_watch'),('кө¬кІҪл§Ң','watch_only'),('ліөкё°/к°җмӢң','review_only'),('м§„м§ңлІ„лҰј','true_discard')]
            extra.append(''); extra.append('[v265 нӣ„ліҙмёөлі„ м„ұкіј]')
            any_bucket=False
            for label,key in buckets:
                br=[r for r in v265_rows if str(r.get('v265_bucket', r.get('v264_bucket',''))) == key]
                if br: any_bucket=True; extra.append(_paper_stats_line_v258(label, br))
            if not any_bucket: extra.append('- нӣ„ліҙмёө кё°лЎқмқҖ v265 мӢ к·ң л“ұлЎқл¶„л¶Җн„° мҢ“мһ„')
            reasons={}
            for r in v265_rows:
                reasons.setdefault(str(r.get('close_reason','') or '-'), []).append(r)
            if reasons:
                extra.append(''); extra.append('[v265 л§ӨлҸ„мӮ¬мң лі„ м„ұкіј]')
                for reason, rr in sorted(reasons.items(), key=lambda kv: len(kv[1]), reverse=True)[:6]:
                    extra.append(_paper_stats_line_v258(reason, rr))
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base

