# =========================================================
# v2.5.266: мўӢмқҖмһҗлҰ¬ м—°кІ° + лҠҰмқҖм§„мһ… м°ЁлӢЁ + м§„мһ…м§Ғм „ мһ¬кІҖмӮ¬
# =========================================================
# лӘ©м Ғ:
# - м°ЁнҠём •көҗнҷ”/мҠӨмә”мқҙ мһЎмқҖ мўӢмқҖ н‘ңліёмқ„ paper м§„мһ… нӣ„ліҙлЎң м—°кІ°н•ңлӢӨ.
# - лӢЁмҲң м°ЁлӢЁмқҙ м•„лӢҲлқј мҙҲмһ…/мһ¬м¶ңл°ң/мўӢмқҖн‘ңліё мһ¬мҠ№кІ© кІҪлЎңлҘј л§Ңл“ лӢӨ.
# - м§„мһ…к°Җм—җ лӢҝм•„лҸ„ л°”лЎң л§ӨмҲҳ к°Җм •н•ҳм§Җ м•Ҡкі , к·ё мҲңк°„ нһҳмқҙ мӮҙм•„ мһҲлҠ”м§Җ лӢӨмӢң нҷ•мқён•ңлӢӨ.
PAPER_V266_START_TS = time.time()
PAPER_V266_STATS = {
    "early_entry": 0,
    "restart_pullback": 0,
    "good_sample_reentry": 0,
    "late_block": 0,
    "precheck_pass": 0,
    "precheck_cancel": 0,
    "good_promoted": 0,
    "paper_blocked_late": 0,
    "last_note": "лҢҖкё°",
}


def _v266_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V266_STATS:
            PAPER_V266_STATS[key] = int(safe_float(PAPER_V266_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V266_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v266_has(text, words) -> bool:
    try:
        t = str(text or "")
        return any(str(w) in t for w in list(words or []))
    except Exception:
        return False


def _v266_row_text(row: dict, cls: dict = None) -> str:
    try:
        parts = []
        for obj in [row if isinstance(row, dict) else {}, cls if isinstance(cls, dict) else {}]:
            for k in ["status", "state", "review_status", "result_status", "watch_status", "pattern_tag", "primary_reason", "one_liner", "decision", "action", "v264_label", "v264_reason"]:
                v = obj.get(k)
                if v not in (None, ""):
                    parts.append(str(v))
            rs = obj.get("reasons")
            if isinstance(rs, (list, tuple)):
                parts.extend([str(x) for x in rs[:5]])
            elif rs:
                parts.append(str(rs))
        return " / ".join(parts)
    except Exception:
        return ""


def _v266_metric(cls: dict, row: dict, keys, default=0.0):
    for k in keys:
        try:
            if isinstance(cls, dict) and k in cls:
                v = safe_float(cls.get(k), default)
                if v != default or default == 0.0:
                    return v
            if isinstance(row, dict) and k in row:
                v = safe_float(row.get(k), default)
                if v != default or default == 0.0:
                    return v
        except Exception:
            pass
    return default


def _v266_strength_bits(cls: dict, row: dict = None) -> dict:
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    chg1 = _v266_metric(cls, row, ["chg1", "change_1"], 0.0)
    chg3 = _v266_metric(cls, row, ["chg3", "change_3"], 0.0)
    chg5 = _v266_metric(cls, row, ["chg5", "change_5"], 0.0)
    high_gap = _v266_metric(cls, row, ["high_gap", "below_high", "below_30m_high_pct"], 999.0)
    from_low = _v266_metric(cls, row, ["from_low", "from_30m_low_pct", "low_from_ref_pct_v2"], 0.0)
    money = _v266_metric(cls, row, ["money_amount", "turnover_5m", "verified_turnover_5m", "turnover"], 0.0)
    trade_count = int(_v266_metric(cls, row, ["trade_count", "ws_trade_count_60s", "ws_1m_trade_count"], 0.0))
    buy_ratio = _v266_metric(cls, row, ["buy_ratio", "ws_trade_buy_ratio_60s", "ws_1m_buy_ratio"], 0.0)
    score = _v266_metric(cls, row, ["score", "rank_score", "lite_score"], 0.0)
    candle = " / ".join([str(cls.get("candle_label", "") or ""), str(cls.get("chart_v262_candle", "") or ""), str(row.get("current_candle_text", "") or "")])
    money_text = " / ".join([str(cls.get("money_sustain", "") or ""), str(cls.get("chart_v262_money", "") or ""), str(row.get("money_flow_text", "") or "")])
    high_text = " / ".join([str(cls.get("high_label", "") or ""), str(cls.get("chart_v262_high", "") or ""), str(row.get("high_distance_text", "") or "")])
    joined = _v266_row_text(row, cls)
    candle_weak = _v266_has(candle, ["л°ҖлҰј", "мң—кј¬лҰ¬", "к·јкұ° м•Ҫн•Ё", "мқҳлҜё мһ‘мқҢ", "мһ‘мқҖмӣҖм§Ғмһ„"])
    candle_alive = _v266_has(candle, ["мӮҙм•„лӮЁ", "нҡҢліө", "м•„лһ«кј¬лҰ¬"])
    money_weak = _v266_has(money_text, ["л§ӨлҸ„мҡ°м„ё", "л§ӨлҸ„ мҡ°м„ё", "л°ҳм§қ", "мӢқлҠ”", "лҸҲ м•Ҫн•Ё", "лҸҲм–Ү", "мӢӨм ңлҸҲмһ‘мқҢ", "лҢҖкёҲнҷ•мқём „"])
    high_touch = (0 <= high_gap <= 0.12) or _v266_has(high_text, ["л§һлӢҝмқҢ", "л°”лЎң м•һ", "кі м җ к·јмІҳ"])
    high_hold = _v266_has(high_text, ["лҸҢнҢҢ нӣ„ мң м§Җ", "мһ¬лҸҢнҢҢ мң м§Җ"])
    good_sample = _v266_has(joined, ["кІҖмҰқ н‘ңліё мўӢмқҢ", "к°•м„ё нӣ„ мң м§Җ нҷ•мқё", "10л¶„ к°җмӢң нҢҗлӢЁ мўӢмқҢ", "лҚ” м§Җмјңліј н‘ңліё"])
    late = (from_low >= 2.20 and high_touch) or (from_low >= 3.20) or (_v266_has(joined, ["лҠҰмқҢ", "м¶”кІ©кёҲм§Җ", "кі м җ м•һ л°ҖлҰј"]))
    return {"chg1": chg1, "chg3": chg3, "chg5": chg5, "max_chg": max(chg1, chg3, chg5), "high_gap": high_gap, "from_low": from_low, "money": money, "trade_count": trade_count, "buy_ratio": buy_ratio, "score": score, "candle": candle, "money_text": money_text, "high_text": high_text, "joined": joined, "candle_weak": candle_weak, "candle_alive": candle_alive, "money_weak": money_weak, "high_touch": high_touch, "high_hold": high_hold, "good_sample": good_sample, "late": late}


def _v266_bucket_from_cls(cls: dict, row: dict = None) -> dict:
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    bits = _v266_strength_bits(cls, row)
    grade = str(cls.get("grade", "") or "").upper()
    v264_bucket = str(cls.get("v264_bucket", "") or "")
    if bits["late"] and (bits["candle_weak"] or bits["money_weak"] or bits["buy_ratio"] < 55 or bits["trade_count"] < 5):
        return {"bucket": "late_block", "label": "лҠҰмқҖм§„мһ… м°ЁлӢЁ", "reason": "мқҙлҜё мҳӨлҘё л’Ө кі м җк·јмІҳ/нһҳ м•Ҫн•Ё", "paper_ok": False, "entry_rule": "observe"}
    if grade == "BREAKOUT_WAIT" and bits["high_touch"] and (bits["trade_count"] < 5 or bits["buy_ratio"] < 55 or bits["candle_weak"]):
        return {"bucket": "late_block", "label": "лҠҰмқҖлҸҢнҢҢ м°ЁлӢЁ", "reason": "кі м җл§һлӢҝмқҢ+мІҙкІ°/нҳ„мһ¬лҙү л¶ҖмЎұ", "paper_ok": False, "entry_rule": "observe"}
    if bits["good_sample"] and bits["money"] >= 80_000_000 and not bits["money_weak"] and bits["from_low"] <= 3.20:
        if bits["candle_alive"] or bits["buy_ratio"] >= 50 or bits["trade_count"] >= 8:
            return {"bucket": "good_sample_reentry", "label": "мўӢмқҖн‘ңліё мһ¬мҠ№кІ©", "reason": "кІҖмҰқн‘ңліё мўӢмқҢвҶ’мһ¬м¶ңл°ң к°җмӢң", "paper_ok": True, "entry_rule": "pullback"}
    if bits["money"] >= 100_000_000 and 0.20 <= bits["max_chg"] <= 1.25 and bits["from_low"] <= 1.80 and bits["high_gap"] >= 0.18:
        if bits["trade_count"] >= 3 and bits["buy_ratio"] >= 50 and (bits["candle_alive"] or not bits["candle_weak"]) and not bits["money_weak"]:
            return {"bucket": "early_entry", "label": "мҙҲмһ… м§„мһ… нӣ„ліҙ", "reason": "кіјм—ҙ м „ лҸҲ/мІҙкІ°/нҳ„мһ¬лҙү нҶөкіј", "paper_ok": True, "entry_rule": "now"}
    restart_text = _v266_has(bits["joined"], ["мһ¬м¶ңл°ң", "лҲҢлҰј", "м Җм җл°©м–ҙ", "нҡҢліө нҷ•мқё", "мҙҲмһ…/нҡҢліө"])
    if (grade == "PULLBACK_WAIT" or restart_text or v264_bucket == "pullback_watch") and bits["money"] >= 70_000_000:
        if bits["from_low"] <= 2.60 and not bits["candle_weak"] and not bits["money_weak"] and (bits["buy_ratio"] >= 45 or bits["trade_count"] >= 4):
            return {"bucket": "restart_pullback", "label": "лҲҢлҰјВ·мһ¬м¶ңл°ң нӣ„ліҙ", "reason": "м Җм җ мһ¬мқҙнғҲ м—Ҷмқҙ лӢӨмӢң мӮҙм•„лӮЁ", "paper_ok": True, "entry_rule": "pullback"}
    if v264_bucket in {"breakout_watch", "pullback_watch", "buy_ready"}:
        return {"bucket": "v264_wait", "label": "кё°мЎҙ лҢҖкё° нӣ„ліҙ", "reason": str(cls.get("v264_reason", "") or "v264 лҢҖкё°"), "paper_ok": True, "entry_rule": "breakout" if v264_bucket == "breakout_watch" else ("pullback" if v264_bucket == "pullback_watch" else "now")}
    return {"bucket": "watch_only", "label": "к°җмӢңл§Ң", "reason": "мўӢмқҖ м§„мһ… мЎ°кұҙмқҖ м•„м§Ғ л¶ҖмЎұ", "paper_ok": False, "entry_rule": "observe"}


_BASE_SIGNAL_CLASSIFY_V266 = _signal_v257_classify

def _signal_v257_classify(row: dict) -> dict:
    cls = dict(_BASE_SIGNAL_CLASSIFY_V266(row) or {})
    try:
        bucket = _v266_bucket_from_cls(cls, row if isinstance(row, dict) else {})
        b = str(bucket.get("bucket", "watch_only") or "watch_only")
        cls["v266_bucket"] = b
        cls["v266_label"] = str(bucket.get("label", ""))
        cls["v266_reason"] = str(bucket.get("reason", ""))
        cls["v266_paper_ok"] = bool(bucket.get("paper_ok", False))
        cls["v266_entry_rule"] = str(bucket.get("entry_rule", "observe") or "observe")
        if b == "early_entry":
            cls["grade"] = "BUY_OK"; cls["decision"] = "мҙҲмһ… м§„мһ… нӣ„ліҙ"; cls["action"] = "мҙҲмһ… мЎ°кұҙмқҖ мўӢм§Җл§Ң м§„мһ… м§Ғм „ нҳ„мһ¬лҙү/л§ӨмҲҳм„ёлҘј лӢӨмӢң нҷ•мқён•ҳкі  л“Өм–ҙк°җ."
            _v266_inc("early_entry", f"мҙҲмһ…мҠ№кІ© {cls.get('ticker','?')}")
        elif b in {"restart_pullback", "good_sample_reentry"}:
            cls["grade"] = "PULLBACK_WAIT"; cls["decision"] = "лҲҢлҰјВ·мһ¬м¶ңл°ң лҢҖкё°"; cls["action"] = "мўӢмқҖ н‘ңліё/мһ¬м¶ңл°ң мЎ°кұҙмқ„ ліҙкі  лҲҢлҰј лҳҗлҠ” мһ¬м¶ңл°ң мһҗлҰ¬л§Ң нҷ•мқён•Ё."
            _v266_inc("restart_pullback" if b == "restart_pullback" else "good_sample_reentry", f"мһ¬мҠ№кІ© {cls.get('ticker','?')}/{b}")
        elif b == "late_block":
            cls["grade"] = "DISCARD"; cls["decision"] = "лҠҰмқҖм§„мһ… м°ЁлӢЁ"; cls["action"] = "нӣ„ліҙлҠ” к°җмӢңн•ҳм§Җл§Ң м§ҖкёҲ лҸҲ л„Јмқ„ мһҗлҰ¬лҠ” м•„лӢҳ. лҠҰмқҖ м¶”кІ©мқ„ л§үмқҢ."
            _v266_inc("late_block", f"лҠҰмқҖм§„мһ… м°ЁлӢЁ {cls.get('ticker','?')}")
    except Exception as e:
        try: append_runtime_error_log("signal_v266_classify", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return cls


def _v266_find_current_cls(ticker: str) -> dict:
    ticker = str(ticker or "").upper().strip()
    if not ticker:
        return {}
    try:
        rows = _signal_v257_collect_rows(source_limit=120) if '_signal_v257_collect_rows' in globals() else []
        best = None; best_w = (-999, -999, -999)
        for r in list(rows or []):
            if not isinstance(r, dict) or _signal_v257_ticker(r) != ticker:
                continue
            c = _signal_v257_classify(r)
            b = str(c.get('v266_bucket', c.get('v264_bucket','')) or '')
            bw = {"early_entry": 6, "restart_pullback": 5, "good_sample_reentry": 5, "v264_wait": 4, "late_block": 0}.get(b, 1)
            w = (bw, safe_float(c.get('score',0),0), safe_float(c.get('money_amount',0),0))
            if w > best_w:
                best, best_w = c, w
        return best or {}
    except Exception:
        return {}


def _v266_pre_entry_recheck(pos: dict, ticker: str, price: float) -> tuple[bool, str, dict]:
    try:
        cls = _v266_find_current_cls(ticker)
        if not cls:
            cls = dict(pos or {}); cls.setdefault('ticker', ticker); cls.setdefault('trade_count', pos.get('trade_count', 0)); cls.setdefault('buy_ratio', pos.get('buy_ratio', 0)); cls.setdefault('money_amount', pos.get('money_amount', 0))
        bits = _v266_strength_bits(cls, cls)
        entry_rule = str(pos.get('entry_rule', '') or '')
        lane = str(pos.get('lane', '') or '')
        bucket = str(cls.get('v266_bucket', pos.get('v266_bucket', pos.get('v265_bucket', pos.get('v264_bucket','')))) or '')
        bad = []
        if bits['candle_weak']: bad.append('нҳ„мһ¬лҙү л°ҖлҰј/мң—кј¬лҰ¬')
        if bits['money_weak']: bad.append('лҸҲнқҗлҰ„ мӢқмқҢ/л§ӨлҸ„мҡ°м„ё')
        if entry_rule == 'breakout':
            if bits['trade_count'] < 3: bad.append('лҸҢнҢҢ мІҙкІ° л¶ҖмЎұ')
            if bits['buy_ratio'] < 50: bad.append('лҸҢнҢҢ л§ӨмҲҳм„ё л¶ҖмЎұ')
            if bits['high_touch'] and not bits['high_hold'] and bits['buy_ratio'] < 60: bad.append('кі м җ мң„ мң м§Җ лҜёнҷ•мқё')
            if bits['from_low'] >= 2.30 and bits['high_touch']: bad.append('мқҙлҜё мҳӨлҘё л’Ө кі м җм¶”кІ©')
        elif entry_rule == 'pullback':
            if bits['trade_count'] < 2 and bits['buy_ratio'] < 45: bad.append('лҲҢлҰј мһ¬м¶ңл°ң мІҙкІ° л¶ҖмЎұ')
            if bits['from_low'] >= 3.20: bad.append('лҲҢлҰјмқҙлқјкё°м—” мқҙлҜё л§Һмқҙ мҳӨлҰ„')
        elif entry_rule == 'now':
            if bits['trade_count'] < 3 or bits['buy_ratio'] < 50: bad.append('мҰүмӢңм§„мһ… л§ӨмҲҳм„ё л¶ҖмЎұ')
        if lane == 'strict_signal' and bucket in {'late_block', 'watch_only', 'review_only', 'true_discard'}: bad.append('нҳ„мһ¬ л¬ён„ұмёөмқҙ м§„мһ…мёө м•„лӢҳ')
        if bad:
            return False, ' / '.join(bad[:3]), cls
        return True, 'м§„мһ…м§Ғм „ мһ¬кІҖмӮ¬ нҶөкіј', cls
    except Exception as e:
        return False, f'мһ¬кІҖмӮ¬ мҳӨлҘҳ:{e.__class__.__name__}', {}


_BASE_PAPER_CLASSIFY_V266 = _paper_classify_for_register_v258

def _paper_classify_for_register_v258(row: dict):
    try:
        ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V266(row)
    except Exception as e:
        return False, 'blocked_v266', f'кё°ліё paper л¶„лҘҳ мҳӨлҘҳ:{e}', {}
    try:
        cls = dict(_signal_v257_classify(row) or cls or {})
        b = str(cls.get('v266_bucket', '') or '')
        if b == 'late_block':
            _v266_inc('paper_blocked_late', f"paper лҠҰмқҖм§„мһ… м°ЁлӢЁ {cls.get('ticker','?')}")
            return False, 'blocked_v266_late', f"v266 лҠҰмқҖм§„мһ… м°ЁлӢЁ: {cls.get('v266_reason','')}", cls
        if b in {'early_entry', 'restart_pullback', 'good_sample_reentry'}:
            entry_rule = str(cls.get('v266_entry_rule', 'now') or 'now')
            cls['paper_entry_rule_v259'] = entry_rule
            cls['v266_entry_connected'] = True
            if b == 'early_entry':
                cls['grade'] = 'BUY_OK'; lane = 'strict_signal' if safe_float(cls.get('money_amount',0),0) >= 100_000_000 else 'loose_threshold_test'
            else:
                cls['grade'] = 'PULLBACK_WAIT'; lane = 'strict_signal' if safe_float(cls.get('money_amount',0),0) >= 80_000_000 else 'loose_threshold_test'
            _v266_inc('good_promoted', f"мўӢмқҖмһҗлҰ¬ paper м—°кІ° {cls.get('ticker','?')}/{b}")
            return True, lane, f"v266 мўӢмқҖмһҗлҰ¬ м—°кІ°: {cls.get('v266_label','')} / {cls.get('v266_reason','')}", cls
        return ok, lane, reason, cls
    except Exception:
        return ok, lane, reason, cls


_BASE_PAPER_REGISTER_V266 = paper_register_candidate_v258

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    ok = _BASE_PAPER_REGISTER_V266(row, trigger=trigger)
    if not ok:
        return ok
    try:
        ticker = _paper_ticker_v258(row)
        cls = _signal_v257_classify(row)
        with PAPER_STATE_LOCK:
            for pid, p in list((paper_positions or {}).items()):
                if isinstance(p, dict) and str(p.get('ticker','')).upper().strip() == ticker and not p.get('v266_tagged'):
                    p['paper_version'] = 'v2.5.266'; p['v266_tagged'] = True; p['v266_bucket'] = str(cls.get('v266_bucket','') or ''); p['v266_label'] = str(cls.get('v266_label','') or ''); p['v266_reason'] = str(cls.get('v266_reason','') or '')
                    if p.get('v266_label'): p['register_reason'] = f"{p.get('v266_label')} / {p.get('v266_reason')}"
                    paper_positions[pid] = p
                    break
        save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log('paper_register_v266_followup', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return ok

# мӣҗлһҳ v265 paper_update_positions_once_v258 м „мІҙлҘј ліҙмЎҙн•ҳкі , pending м§„мһ… м§Ғм „л§Ң к°ҖлЎңмұҲлӢӨ.
_BASE_PAPER_UPDATE_V266 = paper_update_positions_once_v258

def paper_update_positions_once_v258():
    # лЁјм Җ pending мӨ‘ м§„мһ…к°Җм—җ лӢҝмқҖ нӣ„ліҙлҘј кІҖмӮ¬н•ҙ нһҳ л№ м§„ кІғмқҖ м·ЁмҶҢн•ңлӢӨ.
    try:
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict) and str(pos.get('status','')).upper() == 'PENDING']
        for pid, pos in items:
            ticker = str(pos.get('ticker','') or '').upper().strip()
            if not ticker:
                continue
            fallback = safe_float(pos.get('last_price', pos.get('entry_price', 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            entry_rule = str(pos.get('entry_rule','') or '')
            low = safe_float(pos.get('planned_entry_low',0),0); high = safe_float(pos.get('planned_entry_high',0),0); chase = safe_float(pos.get('chase_stop',0),0)
            enter = False
            if entry_rule == 'breakout' and low > 0 and price >= low and (chase <= 0 or price <= chase): enter = True
            elif entry_rule == 'pullback' and low > 0 and high > 0 and low <= price <= high: enter = True
            elif entry_rule == 'now': enter = True
            if enter:
                ok_recheck, recheck_reason, _cls = _v266_pre_entry_recheck(pos, ticker, price)
                if not ok_recheck:
                    pos['v266_precheck_reason'] = recheck_reason
                    _v266_inc('precheck_cancel', f"м§„мһ…м·ЁмҶҢ {ticker}/{recheck_reason}")
                    _paper_cancel_pending_v258(pid, pos, 'entry_precheck_cancel_v266', now_ts)
                else:
                    _v266_inc('precheck_pass', f"м§„мһ…нҶөкіј {ticker}")
                    with PAPER_STATE_LOCK:
                        if pid in paper_positions:
                            paper_positions[pid]['v266_precheck_pass'] = True
                            paper_positions[pid]['v266_precheck_reason'] = recheck_reason
        # мқҙнӣ„ кё°мЎҙ v265 м—…лҚ°мқҙнҠёк°Җ мӢӨм ң м§„мһ…/мІӯмӮ° мІҳлҰ¬.
    except Exception as e:
        try: append_runtime_error_log('paper_precheck_v266', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return _BASE_PAPER_UPDATE_V266()

_PREV_SIGNAL_FORMAT_ONE_V266 = _signal_v264_format_one

def _signal_v264_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _PREV_SIGNAL_FORMAT_ONE_V266(row, order=order, show_detail=show_detail)
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {})
        label = str(cls.get('v266_label', '') or '')
        reason = str(cls.get('v266_reason', '') or '')
        if label:
            lines = str(text).splitlines()
            if not any('v266м§„мһ…мёө:' in x for x in lines[:10]):
                lines.insert(2 if len(lines) > 2 else len(lines), f"- v266м§„мһ…мёө: {label} / {reason}")
            return '\n'.join(lines)
    except Exception:
        pass
    return text

