_PREV_BUILD_PAPER_TEXT_V266 = build_paper_text_v258

def build_paper_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_TEXT_V266(limit=limit)
    try:
        text = str(text).replace('- v265: нӣ„ліҙмёө кё°мӨҖмңјлЎң л“ұлЎқн•ҳкі , мһҘ/мҪ”мқё нһҳм—җ л”°лқј м§§кІҢ лЁ№кё°В·кё°ліёмқөм ҲВ·лҚ” лҒҢкі к°Җкё°лҘј лӮҳлҲ”.', '- v266: мўӢмқҖ н‘ңліё/мҙҲмһ…/мһ¬м¶ңл°ңмқ„ м§„мһ… нӣ„ліҙлЎң м—°кІ°н•ҳкі , м§„мһ… м§Ғм „ нһҳ л№ м§Җл©ҙ м·ЁмҶҢн•Ё.')
        text = text.replace('л“ұлЎқмқҙмң : л¬ён„ұмёө strict лҢҖкё°нӣ„ліҙ', 'л“ұлЎқмқҙмң : v266 м§„мһ…мёө strict нӣ„ліҙ')
        text = text.replace('л“ұлЎқмқҙмң : л¬ён„ұмёө loose мӢӨн—ҳнӣ„ліҙ', 'л“ұлЎқмқҙмң : v266 м§„мһ…мёө loose мӢӨн—ҳнӣ„ліҙ')
        return text
    except Exception:
        return text

_PREV_BUILD_PAPER_RECENT_TEXT_V266 = build_paper_recent_text_v258

def build_paper_recent_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_RECENT_TEXT_V266(limit=limit)
    try:
        note_map = {'entry_precheck_cancel_v266': 'м§„мһ…м§Ғм „ нһҳл№ м§җ м·ЁмҶҢ', 'stop_loss_v266': 'v266 мҶҗм ҲнҸӯ м ңн•ң мҶҗм Ҳ', 'protect_stop_v266': 'v266 мҲҳмқөліҙнҳё мҶҗм Ҳ', 'hard_stop_v266': 'v266 л№„мғҒмҶҗм Ҳ', 'quick_take_profit_v266': 'v266 л№ лҘёмқөм Ҳ', 'basic_single_tp_v266': 'v266 кё°ліёмқөм Ҳ', 'trend_tp3_exit_v266': 'v266 кёёкІҢлЁ№кё°', 'quick_profit_protect_v266': 'v266 л№ лҘё мҲҳмқөліҙнҳё', 'basic_profit_lock_1_v266': 'v266 кё°ліё ліҙнҳё1', 'basic_profit_lock_2_v266': 'v266 кё°ліё ліҙнҳё2', 'trend_profit_lock_2_v266': 'v266 м¶”м„ё ліҙнҳё2', 'trend_profit_lock_3_v266': 'v266 м¶”м„ё ліҙнҳё3', 'trend_weakening_exit_v266': 'v266 нһҳл№ м§җмІӯмӮ°', 'slow_no_progress_exit_quick_v266': 'v266 м•Ҫн•ҙм„ң л¬ҙм§„н–үм •лҰ¬', 'slow_no_progress_exit_basic_v266': 'v266 л¬ҙм§„н–үм •лҰ¬', 'slow_no_progress_exit_trend_v266': 'v266 м¶”м„ё мӢӨнҢЁ м •лҰ¬'}
        out=[]
        for line in str(text).splitlines():
            extra=''
            for k,v in note_map.items():
                if k in line:
                    extra=f" / {v}"; break
            out.append(line+extra)
        return '\n'.join(out)
    except Exception:
        return text

_PREV_BUILD_PAPER_STATS_TEXT_V266 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try: base = _PREV_BUILD_PAPER_STATS_TEXT_V266()
    except Exception as e: base = f"рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats\n- кё°ліё нҶөкі„ мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        rows = _paper_closed_logs_v258()
        v266_rows = [r for r in rows if safe_float(r.get('close_ts', r.get('cancel_ts', 0)), 0) >= PAPER_V266_START_TS]
        extra = ['', '[v266 мқҙнӣ„ м„ұкіј - мўӢмқҖмһҗлҰ¬ м—°кІ°/м§„мһ…м§Ғм „ мһ¬кІҖмӮ¬ нӣ„]', _paper_stats_line_v258('v266 м Ғмҡ© нӣ„', v266_rows)]
        if v266_rows:
            strict_rows = [r for r in v266_rows if str(r.get('lane','')) == 'strict_signal']
            loose_rows = [r for r in v266_rows if str(r.get('lane','')) == 'loose_threshold_test']
            extra.append(_paper_stats_line_v258('v266 strict', strict_rows)); extra.append(_paper_stats_line_v258('v266 loose', loose_rows))
            buckets=[('мҙҲмһ…м§„мһ…','early_entry'),('мһ¬м¶ңл°ң/лҲҢлҰј','restart_pullback'),('мўӢмқҖн‘ңліё мһ¬мҠ№кІ©','good_sample_reentry'),('кё°мЎҙлҢҖкё°','v264_wait'),('лҠҰмқҖм§„мһ… м°ЁлӢЁ','late_block')]
            extra.append(''); extra.append('[v266 м§„мһ…мёөлі„ м„ұкіј]')
            any_bucket=False
            for label,key in buckets:
                br=[r for r in v266_rows if str(r.get('v266_bucket','')) == key]
                if br:
                    any_bucket=True; extra.append(_paper_stats_line_v258(label, br))
            if not any_bucket: extra.append('- v266 м§„мһ…мёө кё°лЎқмқҖ мӢ к·ң л“ұлЎқл¶„л¶Җн„° мҢ“мһ„')
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base

_PREV_BUILD_CACHE_STATUS_TEXT_V266 = build_cache_status_text

def build_cache_status_text():
    try: base = _PREV_BUILD_CACHE_STATUS_TEXT_V266()
    except Exception as e: base = f"рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status\n- кё°ліё мғҒнғң мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        extra=['','рҹ§ӯ v2.5.266 мўӢмқҖмһҗлҰ¬ м—°кІ°/лҠҰмқҖм§„мһ… м°ЁлӢЁ', f"- мҙҲмһ…м§„мһ… {PAPER_V266_STATS.get('early_entry',0)} / мһ¬м¶ңл°ң {PAPER_V266_STATS.get('restart_pullback',0)} / мўӢмқҖн‘ңліёмһ¬мҠ№кІ© {PAPER_V266_STATS.get('good_sample_reentry',0)} / лҠҰмқҖм§„мһ…м°ЁлӢЁ {PAPER_V266_STATS.get('late_block',0)}", f"- м§„мһ…м§Ғм „ мһ¬кІҖмӮ¬: нҶөкіј {PAPER_V266_STATS.get('precheck_pass',0)} / м·ЁмҶҢ {PAPER_V266_STATS.get('precheck_cancel',0)} / paper лҠҰмқҖм§„мһ…м°ЁлӢЁ {PAPER_V266_STATS.get('paper_blocked_late',0)}", f"- мўӢмқҖмһҗлҰ¬ paper м—°кІ° {PAPER_V266_STATS.get('good_promoted',0)} / мөңк·ј: {PAPER_V266_STATS.get('last_note','лҢҖкё°')}", '- мү¬мҡҙ лң»: м°ЁнҠём •көҗнҷ”к°Җ л°ңкІ¬н•ң мўӢмқҖ н‘ңліёмқҖ м§„мһ… нӣ„ліҙлЎң м—°кІ°н•ҳкі , м§„мһ…к°Җм—җ лӢҝм•„лҸ„ нһҳмқҙ л№ мЎҢмңјл©ҙ м·ЁмҶҢн•ңлӢӨ.']
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base

try:
    _PREV_STARTUP_NOTICE_V266 = build_startup_notice_text
    def build_startup_notice_text():
        txt = _PREV_STARTUP_NOTICE_V266()
        return str(txt).replace('v2.5.265', 'v2.5.266').replace('л¬ён„ұмёө л¬ёкө¬ м •лҰ¬ + мғҒнҷ©лі„ лӢЁмқјл§ӨлҸ„/мҶҗм ҲнҸӯ ліҙм •', 'мўӢмқҖмһҗлҰ¬ м—°кІ° + лҠҰмқҖм§„мһ… м°ЁлӢЁ + м§„мһ…м§Ғм „ мһ¬кІҖмӮ¬')
except Exception:
    pass

# =========================================================
# v2.5.267: л“ұлЎқ нӣ„ мһ¬нҸүк°Җ + now м§„мһ… л¶„лҰ¬ + мўӢмқҖн‘ңліё мһ¬мҠ№кІ© к°•нҷ”
# =========================================================
# лӘ©м Ғ:
# - мўӢмқҖ мһҗлҰ¬лЎң л“ұлЎқн•ң л’Өм—җлҸ„ кі„мҶҚ мўӢмқҖ мғҒнғңмқём§Җ лӢӨмӢң нҷ•мқён•ңлӢӨ.
# - м§„мһ…лҢҖкё° мӨ‘ мӢ нҳёк°Җ м§„м§ңлІ„лҰј/лҸҲм•Ҫн•Ё/мІҙкІ°0мңјлЎң л°”лҖҢл©ҙ pending_timeoutк№Ңм§Җ кё°лӢӨлҰ¬м§Җ м•Ҡкі  м·ЁмҶҢн•ңлӢӨ.
# - ліҙмң к°Җм • мӨ‘ мӢ нҳёк°Җ кёүкІ©нһҲ лӮҳл№ м§Җл©ҙ мҶҗм Ҳм„  м „мқҙлқјлҸ„ л№ лҘём •лҰ¬/ліҙнҳёмІӯмӮ°н•ңлӢӨ.
# - now мҰүмӢңм§„мһ…мқҖ к°ҖмһҘ мң„н—ҳн•ҳлҜҖлЎң мІҙкІ°/л§ӨмҲҳм„ё/лҸҲ/нҳ„мһ¬лҙүмқҙ м¶©л¶„н•  л•Ңл§Ң paperм—җ нғңмҡҙлӢӨ.
# - review_watchмқҳ мўӢмқҖ н‘ңліё/к°•м„ё мң м§Җ нӣ„ліҙлҘј мһ¬м¶ңл°ңВ·лҲҢлҰј нӣ„ліҙлЎң лҚ” мһҳ м—°кІ°н•ңлӢӨ.
PAPER_V267_START_TS = time.time()
PAPER_V267_STATS = {
    "pending_cancel": 0,
    "open_recheck_exit": 0,
    "protect_recheck_exit": 0,
    "now_blocked": 0,
    "now_to_wait": 0,
    "good_sample_boost": 0,
    "stale_signal_sync": 0,
    "last_note": "лҢҖкё°",
}


def _v267_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V267_STATS:
            PAPER_V267_STATS[key] = int(safe_float(PAPER_V267_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V267_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v267_text_has(text, words) -> bool:
    try:
        t = str(text or "")
        return any(str(w) in t for w in list(words or []))
    except Exception:
        return False


def _v267_is_true_discard(cls: dict, bits: dict = None) -> tuple[bool, str]:
    cls = cls if isinstance(cls, dict) else {}
    bits = bits if isinstance(bits, dict) else {}
    joined = " / ".join([
        str(cls.get("grade", "") or ""), str(cls.get("decision", "") or ""), str(cls.get("action", "") or ""),
        str(cls.get("v264_label", "") or ""), str(cls.get("v264_reason", "") or ""),
        str(cls.get("v266_label", "") or ""), str(cls.get("v266_reason", "") or ""),
        str(cls.get("reason", "") or ""), " / ".join([str(x) for x in (cls.get("reasons") or [])[:5]]) if isinstance(cls.get("reasons"), list) else str(cls.get("reasons", "") or ""),
    ])
    grade = str(cls.get("grade", "") or "").upper()
    v264_bucket = str(cls.get("v264_bucket", "") or "")
    v266_bucket = str(cls.get("v266_bucket", "") or "")
    money = safe_float(cls.get("money_amount", bits.get("money", 0)), 0)
    trade_count = int(safe_float(cls.get("trade_count", bits.get("trade_count", 0)), 0))
    buy_ratio = safe_float(cls.get("buy_ratio", bits.get("buy_ratio", 0)), 0)
    if v264_bucket == "true_discard" or v266_bucket in {"true_discard", "late_block"}:
        return True, "нҳ„мһ¬ мӢ нҳёк°Җ м§„м§ңлІ„лҰј/лҠҰмқҖм§„мһ… м°ЁлӢЁ"
    if grade == "DISCARD" and _v267_text_has(joined, ["м§„м§ң лІ„лҰј", "мӢӨм ң лҸҲмқҙ л„Ҳл¬ҙ мһ‘мқҢ", "мӢӨм ңлҸҲмһ‘мқҢ", "л§ӨмҲҳ/к°җмӢң к·јкұ° л¶ҖмЎұ"]):
        return True, "нҳ„мһ¬ мӢ нҳёк°Җ м§„м§ңлІ„лҰј"
    if money <= 1_000_000 and trade_count <= 0:
        return True, "мӢӨм ң лҸҲ л„Ҳл¬ҙ мһ‘кі  мІҙкІ° м—ҶмқҢ"
    if trade_count <= 0 and buy_ratio <= 0 and grade == "DISCARD":
        return True, "мІҙкІ°/л§ӨмҲҳм„ё м—ҶмқҢ"
    return False, ""


def _v267_current_cls_for_pos(ticker: str, pos: dict = None) -> dict:
    ticker = str(ticker or "").upper().strip()
    pos = pos if isinstance(pos, dict) else {}
    cls = {}
    try:
        if "_v266_find_current_cls" in globals():
            cls = dict(_v266_find_current_cls(ticker) or {})
    except Exception:
        cls = {}
    if not cls:
        cls = dict(pos or {})
        cls.setdefault("ticker", ticker)
        cls.setdefault("trade_count", pos.get("trade_count", 0))
        cls.setdefault("buy_ratio", pos.get("buy_ratio", 0))
        cls.setdefault("money_amount", pos.get("money_amount", 0))
        cls.setdefault("score", pos.get("score", 0))
    return cls


# v266мқҳ нӣ„ліҙмёө нҢҗлӢЁмқ„ ліҙк°•н•ңлӢӨ. кё°мЎҙ нҢҗлӢЁмқҙ мўӢмқҖ нӣ„ліҙлҘј мһЎмңјл©ҙ к·ёлҢҖлЎң л‘җкі ,
# лҶ“м№ҳлҚҳ кІҖмҰқн‘ңліё/мһ¬м¶ңл°ң н‘ңліёл§Ң мўҒкІҢ м¶”к°Җ мҠ№кІ©н•ңлӢӨ.
_BASE_V266_BUCKET_FOR_V267 = _v266_bucket_from_cls

def _v266_bucket_from_cls(cls: dict, row: dict = None) -> dict:
    base = _BASE_V266_BUCKET_FOR_V267(cls, row)
    try:
        if isinstance(base, dict) and bool(base.get("paper_ok", False)):
            return base
        cls = cls if isinstance(cls, dict) else {}
        row = row if isinstance(row, dict) else {}
        bits = _v266_strength_bits(cls, row) if "_v266_strength_bits" in globals() else {}
        joined = str(bits.get("joined", "") or "")
        money = safe_float(bits.get("money", cls.get("money_amount", 0)), 0)
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", 0)), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", 0)), 0)
        from_low = safe_float(bits.get("from_low", cls.get("from_low", 0)), 0)
        high_gap = safe_float(bits.get("high_gap", cls.get("high_gap", 999)), 999)
        candle_weak = bool(bits.get("candle_weak", False))
        money_weak = bool(bits.get("money_weak", False))
        true_discard, _ = _v267_is_true_discard(cls, bits)
        if true_discard:
            return base
        good_words = ["кІҖмҰқ н‘ңліё мўӢмқҢ", "к°•м„ё нӣ„ мң м§Җ нҷ•мқё", "10л¶„ к°җмӢң нҢҗлӢЁ мўӢмқҢ", "мўӢмқҖн‘ңліё", "к°җмӢң нҢҗлӢЁ мўӢмқҢ"]
        restart_words = ["мһ¬м¶ңл°ң", "лҲҢлҰј", "м Җм җл°©м–ҙ", "мҙҲмһ…/нҡҢліө", "нҡҢліө нҷ•мқё", "лӢӨмӢң мӮҙм•„лӮЁ"]
        good_sample = bool(bits.get("good_sample", False)) or _v267_text_has(joined, good_words)
        restart_like = _v267_text_has(joined, restart_words)
        # мўӢмқҖ н‘ңліёмқҖ лҸҲмқҙ л„Ҳл¬ҙ м–Үм§Җ м•Ҡкі , мҷ„м „нһҲ мӢқмқҖ мғҒнғңк°Җ м•„лӢҲл©ҙ лҲҢлҰј/мһ¬м¶ңл°ң нӣ„ліҙлЎң мӮҙлҰ°лӢӨ.
        if good_sample and money >= 30_000_000 and from_low <= 3.80 and not (candle_weak and money_weak):
            if trade_count >= 1 or buy_ratio >= 35 or bool(bits.get("candle_alive", False)):
                _v267_inc("good_sample_boost", f"мўӢмқҖн‘ңліё мһ¬мҠ№кІ© {cls.get('ticker','?')}")
                return {"bucket": "good_sample_reentry", "label": "мўӢмқҖн‘ңліё мһ¬мҠ№кІ©", "reason": "кІҖмҰқн‘ңліё мўӢмқҢвҶ’лҲҢлҰј/мһ¬м¶ңл°ң нӣ„ліҙ", "paper_ok": True, "entry_rule": "pullback"}
        # лҲҢлҰј/мһ¬м¶ңл°ң л¬ёкө¬к°Җ мһҲлҠ”лҚ° кё°мЎҙ v266м—җм„ң к°җмӢңл§ҢмңјлЎң л№ м§„ кІҪмҡ°лҘј мўҒкІҢ ліөкө¬.
        if restart_like and money >= 50_000_000 and from_low <= 2.80 and not candle_weak and not money_weak:
            if trade_count >= 2 or buy_ratio >= 45:
                _v267_inc("good_sample_boost", f"мһ¬м¶ңл°ң ліҙк°• {cls.get('ticker','?')}")
                return {"bucket": "restart_pullback", "label": "лҲҢлҰјВ·мһ¬м¶ңл°ң нӣ„ліҙ", "reason": "мһ¬м¶ңл°ң л¬ёкө¬+лҸҲ/нҳ„мһ¬лҙү мң м§Җ", "paper_ok": True, "entry_rule": "pullback"}
        # кі м җ л§һлӢҝмқҢмқҙл©ҙм„ң мІҙкІ°мқҙ л№Ҳм•Ҫн•ң лҸҢнҢҢлҠ” кё°мЎҙ лҢҖкё°лқј н•ҙлҸ„ лҸҲ л„ЈлҠ” кёёмқҖ л§үлҠ”лӢӨ.
        if (0 <= high_gap <= 0.12) and (trade_count <= 1 or buy_ratio < 35) and str(cls.get("grade", "")).upper() in {"BREAKOUT_WAIT", "BUY_OK"}:
            return {"bucket": "late_block", "label": "лҠҰмқҖм§„мһ… м°ЁлӢЁ", "reason": "кі м җл§һлӢҝмқҢ+мІҙкІ° л¶ҖмЎұ", "paper_ok": False, "entry_rule": "observe"}
    except Exception:
        pass
    return base


_BASE_PAPER_CLASSIFY_V267 = _paper_classify_for_register_v258

def _paper_classify_for_register_v258(row: dict):
    ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V267(row)
    try:
        cls = dict(cls or {})
        bits = _v266_strength_bits(cls, row if isinstance(row, dict) else {}) if "_v266_strength_bits" in globals() else {}
        true_discard, td_reason = _v267_is_true_discard(cls, bits)
        if true_discard:
            _v267_inc("stale_signal_sync", f"л“ұлЎқм°ЁлӢЁ {cls.get('ticker','?')}/{td_reason}")
            return False, "blocked_v267_discard", f"v267 л“ұлЎқм°ЁлӢЁ: {td_reason}", cls
        entry_rule = str(cls.get("paper_entry_rule_v259", cls.get("v266_entry_rule", "")) or "")
        grade = str(cls.get("grade", "") or "").upper()
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", 0)), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", 0)), 0)
        money = safe_float(bits.get("money", cls.get("money_amount", 0)), 0)
        high_gap = safe_float(bits.get("high_gap", cls.get("high_gap", 999)), 999)
        candle_alive = bool(bits.get("candle_alive", False))
        candle_weak = bool(bits.get("candle_weak", False))
        money_weak = bool(bits.get("money_weak", False))
        high_touch = bool(bits.get("high_touch", False))
        # now мҰүмӢңм§„мһ…мқҖ нҷ•мӢӨн•ң кІҪмҡ°л§Ң н—Ҳмҡ©. л¶ҖмЎұн•ҳл©ҙ нӣ„ліҙлҠ” лӮЁкё°кі  paper м§„мһ…л§Ң л§үлҠ”лӢӨ.
        if ok and (entry_rule == "now" or grade == "BUY_OK"):
            strong_now = (money >= 100_000_000 and trade_count >= 4 and buy_ratio >= 55 and candle_alive and not money_weak and not candle_weak)
            high_ok = (not high_touch) or (trade_count >= 8 and buy_ratio >= 60 and high_gap >= 0.05)
            if not (strong_now and high_ok):
                _v267_inc("now_blocked", f"now м°ЁлӢЁ {cls.get('ticker','?')}")
                cls["v267_now_block_reason"] = "мҰүмӢңм§„мһ… к·јкұ° л¶ҖмЎұ"
                return False, "blocked_v267_now", "v267 now мҰүмӢңм§„мһ… м°ЁлӢЁ: мІҙкІ°/л§ӨмҲҳм„ё/нҳ„мһ¬лҙү/кі м җкұ°лҰ¬ л¶ҖмЎұ", cls
    except Exception as e:
        try: append_runtime_error_log("paper_classify_v267", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return ok, lane, reason, cls


_BASE_PAPER_REGISTER_V267 = paper_register_candidate_v258

def paper_register_candidate_v258(row: dict, trigger: str = "auto") -> bool:
    ok = _BASE_PAPER_REGISTER_V267(row, trigger=trigger)
    if not ok:
        return ok
    try:
        ticker = _paper_ticker_v258(row)
        cls = _signal_v257_classify(row)
        with PAPER_STATE_LOCK:
            for pid, p in list((paper_positions or {}).items()):
                if isinstance(p, dict) and str(p.get("ticker", "")).upper().strip() == ticker and not p.get("v267_tagged"):
                    p["paper_version"] = "v2.5.267"
                    p["v267_tagged"] = True
                    p["v267_registered_ts"] = time.time()
                    p["v267_bucket"] = str(cls.get("v266_bucket", "") or p.get("v266_bucket", ""))
                    p["v267_label"] = str(cls.get("v266_label", "") or p.get("v266_label", ""))
                    p["v267_reason"] = str(cls.get("v266_reason", "") or p.get("v266_reason", ""))
                    if p.get("v267_label"):
                        p["register_reason"] = f"{p.get('v267_label')} / {p.get('v267_reason')}"
                    paper_positions[pid] = p
                    break
        save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log("paper_register_v267_followup", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return ok


def _v267_pending_cancel_reason(pos: dict, cls: dict, price: float, now_ts: float) -> str:
    try:
        bits = _v266_strength_bits(cls, cls) if "_v266_strength_bits" in globals() else {}
        true_discard, td_reason = _v267_is_true_discard(cls, bits)
        age = now_ts - safe_float(pos.get("created_ts", now_ts), now_ts)
        entry_rule = str(pos.get("entry_rule", "") or "")
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", pos.get("trade_count", 0))), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", pos.get("buy_ratio", 0))), 0)
        money = safe_float(bits.get("money", cls.get("money_amount", pos.get("money_amount", 0))), 0)
        if true_discard:
            return td_reason
        if age >= 45 and money <= 1_000_000 and trade_count <= 0:
            return "м§„мһ…лҢҖкё° мӨ‘ мӢӨм ңлҸҲ/мІҙкІ° мӮ¬лқјм§җ"
        if age >= 60 and trade_count <= 0 and buy_ratio <= 0:
            return "м§„мһ…лҢҖкё° мӨ‘ 60мҙҲ мІҙкІ° м—ҶмқҢ"
        if age >= 45 and bool(bits.get("candle_weak", False)) and bool(bits.get("money_weak", False)):
            return "м§„мһ…лҢҖкё° мӨ‘ нҳ„мһ¬лҙү/лҸҲнқҗлҰ„ мӢқмқҢ"
        if entry_rule == "breakout" and age >= 45 and bool(bits.get("high_touch", False)) and trade_count < 2:
            return "лҸҢнҢҢлҢҖкё°мқёлҚ° кі м җ м•һ мІҙкІ° л¶ҖмЎұ"
        if entry_rule == "now" and age >= 20 and (trade_count < 3 or buy_ratio < 45 or bool(bits.get("candle_weak", False))):
            return "мҰүмӢңм§„мһ… лҢҖкё° мӨ‘ нһҳ л¶ҖмЎұ"
    except Exception:
        pass
    return ""


def _v267_open_recheck_reason(pos: dict, cls: dict, price: float, now_ts: float) -> tuple[str, str]:
    try:
        entry = safe_float(pos.get("entry_price", 0), 0)
        if entry <= 0 or price <= 0:
            return "", ""
        bits = _v266_strength_bits(cls, cls) if "_v266_strength_bits" in globals() else {}
        pnl = _paper_pct_v258(entry, price)
        max_up = safe_float(pos.get("max_up_pct", pnl), pnl)
        open_age = now_ts - safe_float(pos.get("entered_ts", pos.get("created_ts", now_ts)), now_ts)
        true_discard, td_reason = _v267_is_true_discard(cls, bits)
        trade_count = int(safe_float(bits.get("trade_count", cls.get("trade_count", pos.get("trade_count", 0))), 0))
        buy_ratio = safe_float(bits.get("buy_ratio", cls.get("buy_ratio", pos.get("buy_ratio", 0))), 0)
        if open_age < 25:
            return "", ""
        # мҲҳмқөмқ„ лҙӨлӢӨк°Җ мӢ нҳёк°Җ м•Ҫн•ҙм§Җл©ҙ ліҙнҳёмІӯмӮ°.
        if max_up >= 0.45 and (true_discard or bool(bits.get("candle_weak", False)) or bool(bits.get("money_weak", False)) or buy_ratio < 35):
            return "protect_recheck_exit_v267", "мҲҳмқө нӣ„ мӢ нҳё м•Ҫнҷ”"
        # мҶҗмӢӨмқҙ мһ‘кІҢ мӢңмһ‘лҗҗкі  нҳ„мһ¬ мӢ нҳёк°Җ лІ„лҰј/мІҙкІ°л¶ҖмЎұмқҙл©ҙ мҶҗм Ҳм„ к№Ңм§Җ кё°лӢӨлҰ¬м§Җ м•Ҡкі  м •лҰ¬.
        if pnl <= -0.25 and true_discard:
            return "open_recheck_exit_v267", td_reason or "ліҙмң  мӨ‘ м§„м§ңлІ„лҰј м „нҷҳ"
        if pnl <= -0.35 and trade_count <= 0 and buy_ratio <= 0:
            return "open_recheck_exit_v267", "ліҙмң  мӨ‘ мІҙкІ°/л§ӨмҲҳм„ё м—ҶмқҢ"
        if pnl <= -0.45 and bool(bits.get("candle_weak", False)) and bool(bits.get("money_weak", False)):
            return "open_recheck_exit_v267", "ліҙмң  мӨ‘ нҳ„мһ¬лҙү/лҸҲнқҗлҰ„ мӢқмқҢ"
        # now м§„мһ…мқҖ м—„кІ©нһҲ ліёлӢӨ. нһҳ м—Ҷмңјл©ҙ л№ лҘём •лҰ¬.
        if str(pos.get("entry_rule", "") or "") == "now" and open_age >= 60 and pnl <= 0.10 and (trade_count < 3 or buy_ratio < 45):
            return "now_recheck_exit_v267", "now м§„мһ… нӣ„ нһҳ л¶ҖмЎұ"
    except Exception:
        pass
    return "", ""


_BASE_PAPER_UPDATE_V267 = paper_update_positions_once_v258

def paper_update_positions_once_v258():
    # v267: кё°мЎҙ v266/v265 м—…лҚ°мқҙнҠё м „м—җ лҢҖкё°/ліҙмң  мғҒнғңлҘј нҳ„мһ¬ мӢ нҳёмҷҖ лҸҷкё°нҷ”н•ңлӢӨ.
    try:
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            status = str(pos.get("status", "") or "").upper()
            fallback = safe_float(pos.get("last_price", pos.get("entry_price", 0)), 0)
            price, src, age = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            cls = _v267_current_cls_for_pos(ticker, pos)
            if status == "PENDING":
                reason = _v267_pending_cancel_reason(pos, cls, price, now_ts)
                if reason:
                    pos["v267_cancel_reason"] = reason
                    pos["last_price"] = price
                    pos["last_price_source"] = src
                    _v267_inc("pending_cancel", f"лҢҖкё°м·ЁмҶҢ {ticker}/{reason}")
                    _paper_cancel_pending_v258(pid, pos, "early_pending_cancel_v267", now_ts)
                    continue
            elif status == "OPEN":
                close_reason, detail = _v267_open_recheck_reason(pos, cls, price, now_ts)
                if close_reason:
                    pos["v267_exit_reason"] = detail
                    pos["last_price"] = price
                    pos["last_price_source"] = src
                    if close_reason == "protect_recheck_exit_v267":
                        _v267_inc("protect_recheck_exit", f"ліҙнҳём •лҰ¬ {ticker}/{detail}")
                    else:
                        _v267_inc("open_recheck_exit", f"ліҙмң м •лҰ¬ {ticker}/{detail}")
                    _paper_close_position_v258(pid, pos, price, close_reason, now_ts)
                    continue
    except Exception as e:
        try: append_runtime_error_log("paper_recheck_v267", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return _BASE_PAPER_UPDATE_V267()


