def build_paper_recent_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_RECENT_TEXT_V267(limit=limit)
    try:
        note_map = {
            'early_pending_cancel_v267': 'v267 лҢҖкё° мӨ‘ мӢ нҳём•…нҷ” м·ЁмҶҢ',
            'open_recheck_exit_v267': 'v267 ліҙмң  мӨ‘ мӢ нҳём•…нҷ” м •лҰ¬',
            'protect_recheck_exit_v267': 'v267 мҲҳмқө нӣ„ мӢ нҳём•Ҫнҷ” ліҙнҳёмІӯмӮ°',
            'now_recheck_exit_v267': 'v267 now нһҳл¶ҖмЎұ л№ лҘём •лҰ¬',
        }
        out = []
        for line in str(text).splitlines():
            extra = ''
            for k, v in note_map.items():
                if k in line:
                    extra = f" / {v}"; break
            out.append(line + extra)
        return '\n'.join(out)
    except Exception:
        return text


_PREV_BUILD_PAPER_STATS_TEXT_V267 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try:
        base = _PREV_BUILD_PAPER_STATS_TEXT_V267()
    except Exception as e:
        base = f"рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats\n- кё°ліё нҶөкі„ мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        rows_all = _paper_closed_logs_v258(include_cancelled=True)
        rows_closed = [r for r in rows_all if str(r.get('status','')).upper() == 'CLOSED' and safe_float(r.get('entry_price',0),0) > 0]
        v267_closed = [r for r in rows_closed if safe_float(r.get('close_ts', 0), 0) >= PAPER_V267_START_TS]
        v267_all = [r for r in rows_all if safe_float(r.get('close_ts', r.get('cancel_ts', 0)), 0) >= PAPER_V267_START_TS]
        extra = ['', '[v267 мқҙнӣ„ м„ұкіј - л“ұлЎқ нӣ„ мһ¬нҸүк°Җ/now л¶„лҰ¬ нӣ„]', _paper_stats_line_v258('v267 м Ғмҡ© нӣ„', v267_closed)]
        if v267_closed:
            strict_rows = [r for r in v267_closed if str(r.get('lane','')) == 'strict_signal']
            loose_rows = [r for r in v267_closed if str(r.get('lane','')) == 'loose_threshold_test']
            extra.append(_paper_stats_line_v258('v267 strict', strict_rows))
            extra.append(_paper_stats_line_v258('v267 loose', loose_rows))
            for label, reason in [('ліҙмң мһ¬нҸүк°Җ м •лҰ¬','open_recheck_exit_v267'), ('мҲҳмқөліҙнҳё мһ¬нҸүк°Җ','protect_recheck_exit_v267'), ('now л№ лҘём •лҰ¬','now_recheck_exit_v267')]:
                rr = [r for r in v267_closed if str(r.get('close_reason','')) == reason]
                if rr:
                    extra.append(_paper_stats_line_v258(label, rr))
        cancels = [r for r in v267_all if str(r.get('close_reason','')) == 'early_pending_cancel_v267']
        extra.append(f"- v267 мЎ°кё° м§„мһ…м·ЁмҶҢ: {len(cancels)}кұҙ")
        extra.append(f"- v267 нҳ„мһ¬ м№ҙмҡҙн„°: лҢҖкё°м·ЁмҶҢ {PAPER_V267_STATS.get('pending_cancel',0)} / ліҙмң м •лҰ¬ {PAPER_V267_STATS.get('open_recheck_exit',0)} / ліҙнҳёмІӯмӮ° {PAPER_V267_STATS.get('protect_recheck_exit',0)} / nowм°ЁлӢЁ {PAPER_V267_STATS.get('now_blocked',0)} / мўӢмқҖн‘ңліёліҙк°• {PAPER_V267_STATS.get('good_sample_boost',0)}")
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base


