# ============================================================
# v2.5.268: now 2лӢЁкі„ мӨҖл№„м§„мһ… + нҳјлҸҷ мӨ„мқё м§„мһ…мғҒнғң л¶„лҰ¬
# - мЎ°кұҙмқ„ м „мІҙм ҒмңјлЎң лҚ” мЎ°мқҙлҠ” мҲҳм •мқҙ м•„лӢҲлқј, мҰүмӢңм§„мһ…(now)мқ„ л°”лЎң ліҙмң к°Җм •мңјлЎң нғңмҡ°кё° м „ м§§кІҢ мһ¬нҷ•мқён•ҳлҠ” кө¬мЎ°лӢӨ.
# - нӣ„ліҙлҠ” мң м§Җн•ҳкі , лҸҲ л“Өм–ҙк°ҖлҠ” мҲңк°„л§Ң 30~90мҙҲ нҷ•мқён•ңлӢӨ.
# - к°•н•ң nowлҠ” к·ёлҢҖлЎң мҰүмӢңм§„мһ…, м• л§Өн•ң nowлҠ” м§„мһ…мӨҖл№„лЎң мқҙлҸҷ, мӢқмңјл©ҙ мһҗлҸҷм·ЁмҶҢн•ңлӢӨ.
# ============================================================

PAPER_V268_START_TS = time.time()
PAPER_V268_NOW_PREPARE_MIN_SEC = 25
PAPER_V268_NOW_PREPARE_MAX_SEC = 100
PAPER_V268_STATS = {
    "now_direct_allowed": 0,
    "now_prepare_registered": 0,
    "now_prepare_confirmed": 0,
    "now_prepare_cancel": 0,
    "now_prepare_timeout": 0,
    "now_prepare_blocked": 0,
    "last_note": "лҢҖкё°",
}


def _v268_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V268_STATS:
            PAPER_V268_STATS[key] = int(safe_float(PAPER_V268_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V268_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v268_now_strength(cls: dict, row: dict = None) -> dict:
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    bits = _v266_strength_bits(cls, row) if '_v266_strength_bits' in globals() else {}
    true_discard, td_reason = _v267_is_true_discard(cls, bits) if '_v267_is_true_discard' in globals() else (False, '')
    grade = str(cls.get('grade', '') or '').upper()
    entry_rule = str(cls.get('paper_entry_rule_v259', cls.get('v266_entry_rule', '')) or '').lower()
    bucket = str(cls.get('v266_bucket', cls.get('v264_bucket', '')) or '')
    trade_count = int(safe_float(bits.get('trade_count', cls.get('trade_count', 0)), 0))
    buy_ratio = safe_float(bits.get('buy_ratio', cls.get('buy_ratio', 0)), 0)
    money = safe_float(bits.get('money', cls.get('money_amount', 0)), 0)
    from_low = safe_float(bits.get('from_low', cls.get('from_low', 0)), 0)
    high_gap = safe_float(bits.get('high_gap', 999), 999)
    candle_weak = bool(bits.get('candle_weak', False))
    candle_alive = bool(bits.get('candle_alive', False))
    money_weak = bool(bits.get('money_weak', False))
    high_touch = bool(bits.get('high_touch', False))
    high_hold = bool(bits.get('high_hold', False))
    is_now_candidate = (grade == 'BUY_OK' or entry_rule == 'now' or bucket in {'early_entry', 'buy_ready'})
    direct_ok = (
        is_now_candidate
        and not true_discard
        and money >= 100_000_000
        and trade_count >= 4
        and buy_ratio >= 55
        and not candle_weak
        and not money_weak
        and (candle_alive or buy_ratio >= 65)
        and not (high_touch and not high_hold and buy_ratio < 65)
        and from_low <= 2.40
    )
    prepare_ok = (
        is_now_candidate
        and not true_discard
        and money >= 50_000_000
        and from_low <= 3.00
        and not (candle_weak and money_weak)
        and not (money <= 1_000_000 or td_reason in {'мӢӨм ң лҸҲмқҙ л„Ҳл¬ҙ мһ‘мқҢ', 'мӢӨм ңлҸҲмһ‘мқҢ'})
    )
    cancel_reason = ''
    if true_discard:
        cancel_reason = td_reason or 'нҳ„мһ¬ мӢ нҳёк°Җ м§„м§ңлІ„лҰј'
    elif money <= 1_000_000:
        cancel_reason = 'мӢӨм ң лҸҲмқҙ л„Ҳл¬ҙ мһ‘мқҢ'
    elif candle_weak and money_weak:
        cancel_reason = 'нҳ„мһ¬лҙүкіј лҸҲнқҗлҰ„мқҙ к°ҷмқҙ м•Ҫн•Ё'
    elif from_low >= 3.30 and high_touch:
        cancel_reason = 'мқҙлҜё мҳӨлҘё л’Ө кі м җк·јмІҳ'
    return {
        'is_now_candidate': is_now_candidate,
        'direct_ok': direct_ok,
        'prepare_ok': prepare_ok,
        'cancel_reason': cancel_reason,
        'true_discard': true_discard,
        'trade_count': trade_count,
        'buy_ratio': buy_ratio,
        'money': money,
        'from_low': from_low,
        'high_gap': high_gap,
        'candle_weak': candle_weak,
        'candle_alive': candle_alive,
        'money_weak': money_weak,
        'high_touch': high_touch,
        'high_hold': high_hold,
        'bucket': bucket,
        'grade': grade,
    }


def _v268_make_now_prepare_position(row: dict, cls: dict, lane: str = 'strict_signal', reason: str = 'now м§„мһ…мӨҖл№„') -> bool:
    try:
        if not PAPER_TRADING_ON:
            return False
        ticker = _paper_ticker_v258(row)
        if not ticker:
            return False
        now_ts = time.time()
        if _paper_has_active_ticker_v258(ticker) or _paper_recent_closed_cooldown_v258(ticker, now_ts):
            return False
        if len(_paper_open_rows_v258()) >= PAPER_MAX_ACTIVE:
            return False
        prices = _signal_v256_compute_prices(row, cls)
        price = safe_float(cls.get('price', 0), 0)
        if price <= 0:
            return False
        pos_id = _paper_make_id_v258(ticker)
        low = safe_float(prices.get('entry_low', 0), 0)
        high = safe_float(prices.get('entry_high', 0), 0)
        if low <= 0 or high <= 0:
            low = price * 0.998
            high = price * 1.002
        pos = {
            'id': pos_id,
            'ticker': ticker,
            'status': 'PENDING',
            'lane': lane,
            'paper_version': 'v2.5.268',
            'trigger': 'now_prepare',
            'register_reason': reason,
            'signal_grade': str(cls.get('grade', 'BUY_OK') or 'BUY_OK'),
            'signal_decision': str(cls.get('decision', '') or 'мҰүмӢңм§„мһ… мӨҖл№„'),
            'original_grade': str(cls.get('paper_original_grade', cls.get('grade', 'BUY_OK')) or 'BUY_OK'),
            'created_ts': now_ts,
            'entry_rule': 'now_prepare',
            'planned_entry_low': low,
            'planned_entry_high': high,
            'chase_stop': safe_float(prices.get('chase_stop', price * 1.012), price * 1.012),
            'entry_price': 0.0,
            'entered_ts': 0.0,
            'last_price': price,
            'last_price_source': 'signal_snapshot_now_prepare',
            'stop': safe_float(prices.get('stop', 0), 0),
            'tp1': safe_float(prices.get('tp1', 0), 0),
            'tp2': safe_float(prices.get('tp2', 0), 0),
            'tp3': safe_float(prices.get('tp3', 0), 0),
            'remaining_ratio': 1.0,
            'realized_pct': 0.0,
            'tp1_hit': False,
            'tp2_hit': False,
            'tp3_hit': False,
            'max_up_pct': 0.0,
            'min_down_pct': 0.0,
            'score': safe_float(cls.get('score', 0), 0),
            'money_amount': safe_float(cls.get('money_amount', 0), 0),
            'trade_count': int(safe_float(cls.get('trade_count', 0), 0)),
            'buy_ratio': safe_float(cls.get('buy_ratio', 0), 0),
            'reasons': list(cls.get('reasons') or [])[:5],
            'v268_now_prepare': True,
            'v268_prepare_started_ts': now_ts,
            'v268_prepare_reason': reason,
            'note': 'мӢӨм ң мЈјл¬ё м•„лӢҳ / v268 now 2лӢЁкі„ мӨҖл№„м§„мһ… кІҖмҰқ',
        }
        with PAPER_STATE_LOCK:
            paper_positions[pos_id] = pos
        PAPER_V258_STATS['registered'] = int(safe_float(PAPER_V258_STATS.get('registered', 0), 0)) + 1
        _v268_inc('now_prepare_registered', f"nowмӨҖл№„ л“ұлЎқ {ticker}")
        save_paper_state_v258()
        return True
    except Exception as e:
        try: append_runtime_error_log('paper_now_prepare_register_v268', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False


_BASE_PAPER_REGISTER_V268 = paper_register_candidate_v258

def paper_register_candidate_v258(row: dict, trigger: str = 'auto') -> bool:
    # v268: now нӣ„ліҙлҠ” кі§л°”лЎң OPENмңјлЎң л§Ңл“Өкё° м „м—җ к°•н•ң now / мӨҖл№„ nowлҘј лЁјм Җ лӮҳлҲҲлӢӨ.
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {}) if '_signal_v257_classify' in globals() else {}
        cls = dict(cls or {})
        st = _v268_now_strength(cls, row if isinstance(row, dict) else {})
        if st.get('is_now_candidate'):
            if st.get('direct_ok'):
                _v268_inc('now_direct_allowed', f"nowм§Ғн–ү н—Ҳмҡ© {cls.get('ticker','?')}")
                return _BASE_PAPER_REGISTER_V268(row, trigger=trigger)
            if st.get('prepare_ok'):
                lane = 'strict_signal' if safe_float(st.get('money', 0), 0) >= 100_000_000 else 'loose_threshold_test'
                cls['grade'] = 'BUY_OK'
                cls['paper_entry_rule_v259'] = 'now_prepare'
                cls['decision'] = 'мҰүмӢңм§„мһ… мӨҖл№„'
                reason = 'мҰүмӢңм§„мһ… мӨҖл№„ / 30~90мҙҲ м•Ҳм—җ л§ӨмҲҳм„ёВ·нҳ„мһ¬лҙү мң м§Җ нҷ•мқё нӣ„ м§„мһ…'
                return _v268_make_now_prepare_position(row, cls, lane=lane, reason=reason)
            _v268_inc('now_prepare_blocked', f"nowмӨҖл№„ л¶Ҳк°Җ {cls.get('ticker','?')}/{st.get('cancel_reason','мЎ°кұҙл¶ҖмЎұ')}")
            return False
    except Exception as e:
        try: append_runtime_error_log('paper_register_v268_precheck', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return _BASE_PAPER_REGISTER_V268(row, trigger=trigger)


def _v268_now_prepare_decision(pos: dict, cls: dict, price: float, now_ts: float) -> tuple[str, str]:
    try:
        created = safe_float(pos.get('v268_prepare_started_ts', pos.get('created_ts', now_ts)), now_ts)
        age = max(0.0, now_ts - created)
        bits = _v266_strength_bits(cls, cls) if '_v266_strength_bits' in globals() else {}
        true_discard, td_reason = _v267_is_true_discard(cls, bits) if '_v267_is_true_discard' in globals() else (False, '')
        trade_count = int(safe_float(bits.get('trade_count', cls.get('trade_count', 0)), 0))
        buy_ratio = safe_float(bits.get('buy_ratio', cls.get('buy_ratio', 0)), 0)
        money = safe_float(bits.get('money', cls.get('money_amount', 0)), 0)
        candle_weak = bool(bits.get('candle_weak', False))
        candle_alive = bool(bits.get('candle_alive', False))
        money_weak = bool(bits.get('money_weak', False))
        from_low = safe_float(bits.get('from_low', 0), 0)
        high_touch = bool(bits.get('high_touch', False))
        high_hold = bool(bits.get('high_hold', False))
        if true_discard:
            return 'cancel', td_reason or 'м§„мһ…мӨҖл№„ мӨ‘ м§„м§ңлІ„лҰј м „нҷҳ'
        if age >= 20 and money <= 1_000_000:
            return 'cancel', 'м§„мһ…мӨҖл№„ мӨ‘ мӢӨм ң лҸҲмқҙ л„Ҳл¬ҙ мһ‘мқҢ'
        if age >= 25 and trade_count <= 0 and buy_ratio <= 0:
            return 'cancel', 'м§„мһ…мӨҖл№„ мӨ‘ мІҙкІ° м—ҶмқҢ'
        if age >= 25 and candle_weak and money_weak:
            return 'cancel', 'м§„мһ…мӨҖл№„ мӨ‘ нҳ„мһ¬лҙү/лҸҲнқҗлҰ„ лҸҷмӢң м•Ҫнҷ”'
        if age >= PAPER_V268_NOW_PREPARE_MAX_SEC:
            return 'timeout', 'м§„мһ…мӨҖл№„ мӢңк°„ мҙҲкіј'
        confirm = (
            age >= PAPER_V268_NOW_PREPARE_MIN_SEC
            and money >= 70_000_000
            and not candle_weak
            and not money_weak
            and (trade_count >= 4 or buy_ratio >= 60)
            and buy_ratio >= 45
            and (candle_alive or trade_count >= 6)
            and from_low <= 2.80
            and not (high_touch and not high_hold and buy_ratio < 60)
        )
        if confirm:
            return 'enter', 'м§„мһ…мӨҖл№„ нҶөкіј / л§ӨмҲҳм„ёВ·нҳ„мһ¬лҙү мң м§Җ'
        return '', ''
    except Exception as e:
        return 'cancel', f'м§„мһ…мӨҖл№„ мһ¬кІҖмӮ¬ мҳӨлҘҳ:{e.__class__.__name__}'


_BASE_PAPER_UPDATE_V268 = paper_update_positions_once_v258

def paper_update_positions_once_v258():
    # v268: now_prepareлҠ” 30~90мҙҲ м•Ҳм—җ нҷ•мқёлҗҳл©ҙ м§„мһ…, мӢқмңјл©ҙ м·ЁмҶҢн•ңлӢӨ.
    changed = False
    try:
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict) and str(pos.get('status','')).upper() == 'PENDING' and str(pos.get('entry_rule','')) == 'now_prepare']
        for pid, pos in items:
            ticker = str(pos.get('ticker','') or '').upper().strip()
            if not ticker:
                continue
            fallback = safe_float(pos.get('last_price', pos.get('planned_entry_high', 0)), 0)
            price, src, age_src = _paper_price_v258(ticker, fallback=fallback)
            if price <= 0:
                continue
            cls = _v267_current_cls_for_pos(ticker, pos) if '_v267_current_cls_for_pos' in globals() else {}
            decision, reason = _v268_now_prepare_decision(pos, cls, price, now_ts)
            pos['last_price'] = price
            pos['last_price_source'] = src
            pos['last_price_age'] = safe_float(age_src, 0)
            pos['updated_ts'] = now_ts
            if decision == 'cancel':
                pos['v268_prepare_cancel_reason'] = reason
                _v268_inc('now_prepare_cancel', f"nowмӨҖл№„ м·ЁмҶҢ {ticker}/{reason}")
                _paper_cancel_pending_v258(pid, pos, 'now_prepare_cancel_v268', now_ts)
                changed = True
                continue
            if decision == 'timeout':
                pos['v268_prepare_cancel_reason'] = reason
                _v268_inc('now_prepare_timeout', f"nowмӨҖл№„ мӢңк°„мҙҲкіј {ticker}")
                _paper_cancel_pending_v258(pid, pos, 'now_prepare_timeout_v268', now_ts)
                changed = True
                continue
            if decision == 'enter':
                pos['status'] = 'OPEN'
                pos['entry_rule'] = 'now'
                pos['entry_price'] = price
                pos['entered_ts'] = now_ts
                pos['v268_now_prepare_entered'] = True
                pos['v268_enter_reason'] = reason
                pos['single_exit_mode_v265'] = True
                try:
                    if '_v265_tighten_stop' in globals():
                        market = _v265_market_mode() if '_v265_market_mode' in globals() else {}
                        pos = _v265_tighten_stop(pos, market_mode=market.get('mode'))
                except Exception:
                    pass
                with PAPER_STATE_LOCK:
                    if pid in paper_positions:
                        paper_positions[pid].update(pos)
                PAPER_V258_STATS['entered'] = int(safe_float(PAPER_V258_STATS.get('entered', 0), 0)) + 1
                _v268_inc('now_prepare_confirmed', f"nowмӨҖл№„ нҶөкіј {ticker}")
                changed = True
                continue
            with PAPER_STATE_LOCK:
                if pid in paper_positions:
                    paper_positions[pid].update(pos)
            changed = True
        if changed:
            save_paper_state_v258()
    except Exception as e:
        try: append_runtime_error_log('paper_update_now_prepare_v268', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return _BASE_PAPER_UPDATE_V268()


