_PREV_BUILD_PAPER_RECENT_TEXT_V268 = build_paper_recent_text_v258

def build_paper_recent_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_RECENT_TEXT_V268(limit=limit)
    try:
        note_map = {
            'now_prepare_cancel_v268': 'v268 now мӨҖл№„ мӨ‘ нһҳл№ м§җ м·ЁмҶҢ',
            'now_prepare_timeout_v268': 'v268 now мӨҖл№„ мӢңк°„мҙҲкіј м·ЁмҶҢ',
        }
        out = []
        for line in str(text).splitlines():
            extra = ''
            for k, v in note_map.items():
                if k in line:
                    extra = f" / {v}"; break
            out.append(line + extra)
        return '\n'.join(out)
    except Exception:
        return text


_PREV_BUILD_PAPER_STATS_TEXT_V268 = build_paper_stats_text_v258

def build_paper_stats_text_v258() -> str:
    try:
        base = _PREV_BUILD_PAPER_STATS_TEXT_V268()
    except Exception as e:
        base = f"рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats\n- кё°ліё нҶөкі„ мғқм„ұ мҳӨлҘҳ: {e}"
    try:
        rows_all = _paper_closed_logs_v258(include_cancelled=True)
        rows_closed = [r for r in rows_all if str(r.get('status','')).upper() == 'CLOSED' and safe_float(r.get('entry_price',0),0) > 0]
        v268_closed = [r for r in rows_closed if safe_float(r.get('close_ts', 0), 0) >= PAPER_V268_START_TS]
        v268_all = [r for r in rows_all if safe_float(r.get('close_ts', r.get('cancel_ts', 0)), 0) >= PAPER_V268_START_TS]
        extra = ['', '[v268 мқҙнӣ„ м„ұкіј - now 2лӢЁкі„ мӨҖл№„м§„мһ… нӣ„]', _paper_stats_line_v258('v268 м Ғмҡ© нӣ„', v268_closed)]
        if v268_closed:
            now_confirmed = [r for r in v268_closed if r.get('v268_now_prepare_entered') or str(r.get('entry_rule','')) == 'now']
            if now_confirmed:
                extra.append(_paper_stats_line_v258('v268 now/мӨҖл№„нҶөкіј', now_confirmed))
        cancels = [r for r in v268_all if str(r.get('close_reason','')) in {'now_prepare_cancel_v268','now_prepare_timeout_v268'}]
        extra.append(f"- v268 now мӨҖл№„ м·ЁмҶҢ: {len(cancels)}кұҙ")
        extra.append(f"- v268 нҳ„мһ¬ м№ҙмҡҙн„°: nowм§Ғн–ү {PAPER_V268_STATS.get('now_direct_allowed',0)} / мӨҖл№„л“ұлЎқ {PAPER_V268_STATS.get('now_prepare_registered',0)} / мӨҖл№„нҶөкіј {PAPER_V268_STATS.get('now_prepare_confirmed',0)} / мӨҖл№„м·ЁмҶҢ {PAPER_V268_STATS.get('now_prepare_cancel',0)} / мӢңк°„мҙҲкіј {PAPER_V268_STATS.get('now_prepare_timeout',0)}")
        return str(base).rstrip() + '\n' + '\n'.join(extra)
    except Exception:
        return base


