# ============================================================
# v2.5.270: лҜёлҰ¬ліј нӣ„ліҙ/мҳҲм—ҙ нӣ„ліҙ ліөкө¬ + нӣ„ліҙлҠ” л„“кІҢ, л§ӨмҲҳлҠ” мўҒкІҢ
# - мЎ°кұҙ мЎ°мқҙкё° м•„лӢҳ. ліөкё°/к°җмӢңлЎң л¬»нһҢ нӣ„ліҙлҘј рҹ‘Җ лҜёлҰ¬ліј нӣ„ліҙлЎң лӢӨмӢң ліҙмқҙкІҢ н•ңлӢӨ.
# - мӢӨм ң л§ӨмҲҳ/paper OPENмқҖ мўҒкІҢ мң м§Җн•ҳкі , лҜёлҰ¬ліј нӣ„ліҙлҠ” мӨҖл№„/лҢҖкё° кІҖмҰқмңјлЎңл§Ң м—°кІ°н•ңлӢӨ.
# - м§„м§ң м“°л Ҳкё°л§Ң л¬ён„ұмңјлЎң лІ„лҰ°лӢӨ.
# ============================================================
PAPER_V270_START_TS = time.time()
PAPER_V270_STATS = {"preview": 0, "preview_registered": 0, "trash_kept": 0, "buy_narrow": 0, "last_note": "лҢҖкё°"}


def _v270_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V270_STATS:
            PAPER_V270_STATS[key] = int(safe_float(PAPER_V270_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V270_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v270_txt_has(text, words):
    t = str(text or "")
    return any(str(w) in t for w in list(words or []))


def _v270_ctx(cls: dict, row: dict = None) -> dict:
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    try:
        bits = _v266_strength_bits(cls, row) if '_v266_strength_bits' in globals() else {}
    except Exception:
        bits = {}
    joined = " ".join([
        str(bits.get('joined','') or ''), str(cls.get('decision','') or ''), str(cls.get('reasons','') or ''),
        str(cls.get('v264_reason','') or ''), str(cls.get('v266_reason','') or ''),
        str(cls.get('chart_v262_candle', cls.get('candle_label','')) or ''),
        str(cls.get('chart_v262_money', cls.get('money_sustain','')) or ''),
        str(cls.get('chart_v262_high', cls.get('high_label','')) or ''),
    ])
    money = safe_float(bits.get('money', cls.get('money_amount', 0)), 0)
    tc = int(safe_float(bits.get('trade_count', cls.get('trade_count', 0)), 0))
    br = safe_float(bits.get('buy_ratio', cls.get('buy_ratio', 0)), 0)
    fl = safe_float(bits.get('from_low', cls.get('from_low', cls.get('from_30m_low_pct', 0))), 0)
    hg = safe_float(bits.get('high_gap', cls.get('high_gap', 999)), 999)
    chg = max(
        safe_float(cls.get('chg3', row.get('chg3', 0)), 0),
        safe_float(cls.get('chg5', row.get('chg5', 0)), 0),
        safe_float(cls.get('chg15', row.get('chg15', 0)), 0),
    )
    score = safe_float(cls.get('score', row.get('score', 0)), 0)
    candle_weak = bool(bits.get('candle_weak', False)) or _v270_txt_has(joined, ['нҳ„мһ¬лҙү л°ҖлҰј','мң—кј¬лҰ¬','л§үнҢҗ л°ҖлҰј'])
    candle_alive = bool(bits.get('candle_alive', False)) or _v270_txt_has(joined, ['мӮҙм•„лӮЁ','м•„лһ«кј¬лҰ¬','нҡҢліө'])
    money_weak = bool(bits.get('money_weak', False)) or _v270_txt_has(joined, ['л§ӨлҸ„мҡ°м„ё','л°ҳм§қ/мӢқлҠ”','мӢқлҠ”мӨ‘'])
    money_thin = _v270_txt_has(joined, ['мӢӨм ңлҸҲмһ‘мқҢ','лҸҲм–ҮмқҢ','лҸҲ м•Ҫн•Ё','лҢҖкёҲнҷ•мқём „']) or money < 5_000_000
    good_words = _v270_txt_has(joined, ['кІҖмҰқ н‘ңліё мўӢмқҢ','к°•м„ё нӣ„ мң м§Җ','мҙҲмһ…','мһ¬м¶ңл°ң','м Җм җл°©м–ҙ','нҡҢліө нҷ•мқё'])
    high_watch = (0 <= hg <= 0.90) or _v270_txt_has(joined, ['кі м җ л°”лЎң м•һ','кі м җ л§һлӢҝмқҢ','кі м җ лҸҢнҢҢ нӣ„ мң м§Җ','мһ¬лҸҢнҢҢ мң м§Җ'])
    return {'bits':bits,'joined':joined,'money':money,'trade_count':tc,'buy_ratio':br,'from_low':fl,'high_gap':hg,'chg':chg,'score':score,'candle_weak':candle_weak,'candle_alive':candle_alive,'money_weak':money_weak,'money_thin':money_thin,'good_words':good_words,'high_watch':high_watch}


def _v270_bucket(cls: dict, row: dict = None) -> dict:
    cls = cls if isinstance(cls, dict) else {}
    c = _v270_ctx(cls, row)
    old = str(cls.get('v266_bucket', cls.get('v264_bucket','')) or '')
    grade = str(cls.get('grade','') or '').upper()
    if c['money'] <= 1_000_000 or (c['money_thin'] and c['trade_count'] <= 0 and c['chg'] < 0.35):
        _v270_inc('trash_kept', f"м§„м§ңлІ„лҰј мң м§Җ {cls.get('ticker','?')}")
        return {'bucket':'true_discard','reason':'мӢӨм ң лҸҲмқҙ л„Ҳл¬ҙ мһ‘мқҢ/лҸҲм–ҮмқҢ','entry_rule':'observe'}
    if old in {'buy_ready','early_entry','restart_pullback','good_sample_reentry','breakout_watch','pullback_watch'}:
        _v270_inc('buy_narrow', f"кё°мЎҙ лҢҖкё°мёө мң м§Җ {cls.get('ticker','?')}/{old}")
        return {'bucket':old,'reason':str(cls.get('v266_reason', cls.get('v264_reason','кё°мЎҙ лҢҖкё° нӣ„ліҙ')) or 'кё°мЎҙ лҢҖкё° нӣ„ліҙ'),'entry_rule':str(cls.get('v266_entry_rule', cls.get('paper_entry_rule_v259','')) or '')}
    preheat = 0
    why = []
    if c['money'] >= 20_000_000: preheat += 1; why.append('лҸҲмқҖ л¶ҷмқҢ')
    if c['money'] >= 100_000_000: preheat += 1; why.append('лҢҖкёҲ м¶©л¶„')
    if c['trade_count'] >= 2 or c['buy_ratio'] >= 45: preheat += 1; why.append('мІҙкІ° л¶ҷкё° мӢңмһ‘')
    if c['chg'] >= 0.35 or c['score'] >= 5.0: preheat += 1; why.append('мҙҲл°ҳ мӣҖм§Ғмһ„')
    if c['candle_alive'] or not c['candle_weak']: preheat += 1; why.append('нҳ„мһ¬лҙү м•„м§Ғ м•Ҳ мЈҪмқҢ')
    if c['good_words']: preheat += 1; why.append('мўӢмқҖ н‘ңліё л¬ёкө¬')
    if c['high_watch']: preheat += 1; why.append('кі м җ м „нӣ„ кҙҖм°°к¶Ң')
    if c['from_low'] <= 2.80: preheat += 1; why.append('м Җм җлҢҖл№„ кіјм—ҙ м•„лӢҳ')
    if c['candle_weak'] and c['money_weak']: preheat -= 2
    if c['from_low'] > 3.20 and c['high_watch']: preheat -= 2
    if preheat >= 4:
        entry_rule = 'pullback' if (c['good_words'] or grade == 'PULLBACK_WAIT' or c['from_low'] <= 2.00) else 'breakout'
        if grade == 'BUY_OK': entry_rule = 'now_prepare'
        _v270_inc('preview', f"лҜёлҰ¬ліј нӣ„ліҙ {cls.get('ticker','?')}/{entry_rule}")
        return {'bucket':'preheat_preview','reason':' / '.join(why[:3]) or 'лңЁкё° м§Ғм „ к°җмӢңк¶Ң','entry_rule':entry_rule}
    return {'bucket':old or 'review_only','reason':str(cls.get('v264_reason','лҜёлҰ¬ліҙкё° м „ лӢЁкі„') or 'лҜёлҰ¬ліҙкё° м „ лӢЁкі„'),'entry_rule':'observe'}


_BASE_SIGNAL_CLASSIFY_V270 = _signal_v257_classify

def _signal_v257_classify(row: dict) -> dict:
    cls = dict(_BASE_SIGNAL_CLASSIFY_V270(row) or {})
    try:
        v = _v270_bucket(cls, row if isinstance(row, dict) else {})
        cls['v270_bucket'] = str(v.get('bucket','') or '')
        cls['v270_reason'] = str(v.get('reason','') or '')
        cls['v270_entry_rule'] = str(v.get('entry_rule','') or '')
    except Exception as e:
        try: append_runtime_error_log('signal_v270_classify', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return cls


_BASE_SIGNAL_FORMAT_V270 = _signal_v264_format_one if '_signal_v264_format_one' in globals() else _signal_v257_format_one

def _signal_v270_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
    text = _BASE_SIGNAL_FORMAT_V270(row, order=order, show_detail=show_detail)
    try:
        cls = _signal_v257_classify(row if isinstance(row, dict) else {})
        if str(cls.get('v270_bucket','')) == 'preheat_preview':
            lines = str(text).splitlines()
            at = 1 if len(lines) > 1 else len(lines)
            if not any('v270мҳҲм—ҙмёө:' in x for x in lines[:8]):
                lines.insert(at, f"- v270мҳҲм—ҙмёө: рҹ‘Җ лҜёлҰ¬ліј нӣ„ліҙ / {cls.get('v270_reason','')}")
                lines.insert(at+1, '- лң»: м§ҖкёҲ л§ӨмҲҳлҠ” м•„лӢҳ. лңЁкё° м§Ғм „мқём§Җ 30~90мҙҲ лҚ” ліҙлҠ” нӣ„ліҙ.')
            out = '\n'.join(lines)
            out = out.replace('вӣ” ', 'рҹ‘Җ ', 1).replace('/ лІ„лҰј /', '/ лҜёлҰ¬ліј нӣ„ліҙ /', 1).replace('/ ліөкё°В·к°җмӢң/', '/ лҜёлҰ¬ліј нӣ„ліҙ/', 1)
            out = out.replace('м§ҖкёҲ лҸҲ л„Јмқ„ нӣ„ліҙ м•„лӢҳ. лӘ…л №м–ҙ/ліөкё°м—җм„ңл§Ң м¶”м Ғ.', 'м§ҖкёҲ л§ӨмҲҳлҠ” м•„лӢҳ. лңЁкё° м§Ғм „ нӣ„ліҙлЎң лҜёлҰ¬ м§Җмјңлҙ„.')
            out = out.replace('м§ҖкёҲ л§ӨмҲҳлҠ” м•„лӢҳ. к°җмӢң/ліөкё°м—җм„ң кі„мҶҚ м¶”м Ғ.', 'м§ҖкёҲ л§ӨмҲҳлҠ” м•„лӢҳ. лңЁкё° м§Ғм „ нӣ„ліҙлЎң лҜёлҰ¬ м§Җмјңлҙ„.')
            return out
    except Exception:
        pass
    return text


def _signal_v270_weight(cls: dict) -> tuple:
    b = str((cls or {}).get('v270_bucket', (cls or {}).get('v266_bucket', (cls or {}).get('v264_bucket',''))) or '')
    bs = {'buy_ready':8,'early_entry':8,'restart_pullback':7,'good_sample_reentry':7,'breakout_watch':6,'pullback_watch':6,'preheat_preview':5,'review_only':2,'watch_only':2,'late_block':1,'true_discard':0}.get(b, 2)
    return (bs, safe_float((cls or {}).get('score',0),0), min(safe_float((cls or {}).get('money_amount',0),0), 50_000_000_000), int(safe_float((cls or {}).get('trade_count',0),0)), safe_float((cls or {}).get('buy_ratio',0),0))


_PREV_BUILD_SIGNAL_TEXT_V270 = build_signal_text_v256

def build_signal_text_v256(args=None, limit: int = None) -> str:
    args = list(args or [])
    limit = int(limit or SIGNAL_COMMAND_DEFAULT_LIMIT_V256)
    target = ' '.join([str(x) for x in args]).upper().strip()
    if target and target.isdigit(): limit = max(1, min(int(target), 12)); target = ''
    now_line = now_kst().strftime('%m-%d %H:%M:%S') if 'now_kst' in globals() else format_ts_mdhm(time.time())
    try: rows = _signal_v257_collect_rows(source_limit=max(SIGNAL_COMMAND_SOURCE_LIMIT_V257, limit * 18))
    except Exception: rows = []
    if not rows:
        return '\n'.join(['рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal', f'- мӢңк°Ғ: {now_line}', '- м•„м§Ғ мӢ нҳё кі„мӮ°м—җ м“ё мҠӨлғ…мғ·мқҙ м—Ҷм–ҙ.', '- v270 мӣҗм№ҷ: нӣ„ліҙ мһ…кө¬лҠ” л„“кІҢ, мӢӨм ң л§ӨмҲҳлҠ” мўҒкІҢ. нӣ„ліҙк°Җ л§ҲлҘё мғҒнғңм—җм„ңлҠ” мЎ°кұҙ мЎ°мқҙкё° кёҲм§Җ.'])
    pairs = []
    for r in list(rows or []):
        try: pairs.append((_signal_v257_classify(r), r))
        except Exception: pass
    pairs.sort(key=lambda x: _signal_v270_weight(x[0]), reverse=True)
    if target:
        targets = [(c,r) for c,r in pairs if _signal_v257_ticker(r) == target]
        if not targets:
            return '\n'.join(['рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal', f'- мӢңк°Ғ: {now_line}', f'- {target}лҠ” нҳ„мһ¬ м ҖмһҘ мҠӨлғ…мғ·м—җм„ң лӘ» м°ҫм•ҳм–ҙ.', '- мғҲ APIлҘј л¶ҖлҘҙм§Җ м•ҠлҠ” лӘ…л №мқҙлқј мөңк·ј мҠӨлғ…мғ·м—җ м—Ҷмңјл©ҙ кі„мӮ°н•ҳм§Җ м•Ҡм•„.'])
        c,best = sorted(targets, key=lambda x:_signal_v270_weight(x[0]), reverse=True)[0]
        return '\n'.join(['рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal', f'- мӢңк°Ғ: {now_line}', '- мғҲ API/OHLCV м§Ғм ‘мЎ°нҡҢ м—ҶмқҢ. м ҖмһҘлҗң rank/review/internal_watch + WS ліҙмЎ° кё°мӨҖ.', '- v2.5.270: нӣ„ліҙ мһ…кө¬лҠ” л„“кІҢ, л§ӨмҲҳлҠ” мўҒкІҢ. лҜёлҰ¬ліј нӣ„ліҙ/мҳҲм—ҙ нӣ„ліҙлҘј лӢӨмӢң ліҙм—¬мӨҢ.', '- мЎ°кұҙ мЎ°мқҙкё° м•„лӢҳ. м§„м§ң м“°л Ҳкё°л§Ң лІ„лҰ¬кі , м• л§Өн•ҳкІҢ мўӢмқҖ нӣ„ліҙлҠ” лҜёлҰ¬ліҙкё°лЎң мҳ¬лҰј.', '', _signal_v270_format_one(best, order=1, show_detail=True), '', 'лӘ…л №м–ҙ: /signal мҪ”мқёлӘ…  мҳҲ) /signal A']).strip()
    buy = [(c,r) for c,r in pairs if str(c.get('v270_bucket','')) in {'buy_ready','early_entry'}]
    wait = [(c,r) for c,r in pairs if str(c.get('v270_bucket','')) in {'breakout_watch','pullback_watch','restart_pullback','good_sample_reentry'}]
    preview = [(c,r) for c,r in pairs if str(c.get('v270_bucket','')) == 'preheat_preview']
    review = [(c,r) for c,r in pairs if str(c.get('v270_bucket','')) in {'review_only','watch_only','late_block'}]
    lines = ['рҹҺҜ л§ӨмҲҳВ·мҶҗм ҲВ·мқөм Ҳ мӢ нҳё /signal', f'- мӢңк°Ғ: {now_line}', '- мғҲ API/OHLCV м§Ғм ‘мЎ°нҡҢ м—ҶмқҢ. м ҖмһҘлҗң rank/review/internal_watch + WS ліҙмЎ° кё°мӨҖ.', '- v2.5.270: нӣ„ліҙ мһ…кө¬лҠ” л„“кІҢ, л§ӨмҲҳлҠ” мўҒкІҢ. лҜёлҰ¬ліј нӣ„ліҙ/мҳҲм—ҙ нӣ„ліҙлҘј лӢӨмӢң ліҙм—¬мӨҢ.', '- мӣҗм№ҷ: нӣ„ліҙк°Җ м•Ҳ лң° л•ҢлҠ” мЎ°кұҙ мЎ°мқҙкё° кёҲм§Җ. мўӢмқҖ нӣ„ліҙк°Җ ліҙмқё л’Ө м“°л Ҳкё°л§Ң л¬ён„ұмңјлЎң кұ°лҰ„.', '']
    shown = 0
    if buy:
        lines.append('рҹ”Ҙ м§„м§ң л§ӨмҲҳ нӣ„ліҙ / мӢӨм ң л§ӨмҲҳ л¬ён„ұ нҶөкіј')
        for c,r in buy[:min(2,limit)]: shown += 1; lines.append(_signal_v270_format_one(r, order=shown, show_detail=False)); lines.append('')
    else:
        lines.append('- нҳ„мһ¬ мҰүмӢң л§ӨмҲҳ мӢ нҳё м—ҶмқҢ. л§ӨмҲҳ л¬ён„ұмқҖ мўҒкІҢ мң м§Җн•Ё.'); lines.append('')
    if wait:
        lines.append('рҹҹЎ м§„мһ…мӨҖл№„В·лҢҖкё° нӣ„ліҙ / мЎ°кұҙ мўӢм•„м§Җл©ҙ paper м§„мһ…')
        for c,r in wait[:max(1,min(3,limit-shown))]: shown += 1; lines.append(_signal_v270_format_one(r, order=shown, show_detail=False)); lines.append('')
    if preview:
        lines.append('рҹ‘Җ лҜёлҰ¬ліј нӣ„ліҙ / лңЁкё° м§Ғм „ к°җмӢң, м§ҖкёҲ л§ӨмҲҳ м•„лӢҳ')
        for c,r in preview[:max(1,min(5,limit-shown if limit-shown>0 else 3))]: shown += 1; lines.append(_signal_v270_format_one(r, order=shown, show_detail=False)); lines.append('')
    if not wait and not preview:
        lines.append('рҹ‘Җ лҜёлҰ¬ліј нӣ„ліҙ м—ҶмқҢ / мқҙ мғҒнғңм—җм„ң мЎ°кұҙмқ„ лҚ” мЎ°мқҙл©ҙ м•Ҳ лҗЁ'); lines.append('')
    if review and shown < limit:
        lines.append('рҹ§· ліөкё°В·к°җмӢң нӣ„ліҙ / м•„м§Ғ лҜёлҰ¬ліҙкё° м „ лӢЁкі„')
        for c,r in review[:max(1,min(2,limit-shown))]: shown += 1; lines.append(_signal_v270_format_one(r, order=shown, show_detail=False)); lines.append('')
    lines.append('лӘ…л №м–ҙ: /signal мҪ”мқёлӘ…  мҳҲ) /signal A')
    return '\n'.join(lines).strip()


_BASE_PAPER_CLASSIFY_V270 = _paper_classify_for_register_v258

def _paper_classify_for_register_v258(row: dict):
    try: ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V270(row)
    except Exception as e: return False, 'blocked_v270_base_error', f'кё°ліё paper л¶„лҘҳ мҳӨлҘҳ:{e}', {}
    try:
        cls2 = dict(_signal_v257_classify(row if isinstance(row, dict) else {}) or cls or {})
        b = str(cls2.get('v270_bucket','') or '')
        if ok: return ok, lane, reason, cls
        if b != 'preheat_preview': return ok, lane, reason, cls
        er = str(cls2.get('v270_entry_rule','') or 'now_prepare')
        if er == 'pullback': cls2['grade']='PULLBACK_WAIT'; cls2['paper_entry_rule_v259']='pullback'
        elif er == 'breakout': cls2['grade']='BREAKOUT_WAIT'; cls2['paper_entry_rule_v259']='breakout'
        else: cls2['grade']='BUY_OK'; cls2['paper_entry_rule_v259']='now_prepare'; cls2['decision']='лҜёлҰ¬ліј нӣ„ліҙ м§„мһ…мӨҖл№„'
        cls2['paper_original_grade'] = str(cls2.get('paper_original_grade', 'PREVIEW') or 'PREVIEW')
        cls2['v270_preview_registered'] = True
        _v270_inc('preview_registered', f"лҜёлҰ¬ліј нӣ„ліҙ paper м—°кІ° {cls2.get('ticker','?')}/{er}")
        return True, 'preheat_preview_test', f"v270 лҜёлҰ¬ліј нӣ„ліҙ кІҖмҰқ: {cls2.get('v270_reason','')}", cls2
    except Exception as e:
        try: append_runtime_error_log('paper_classify_v270_preview', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ok, lane, reason, cls


_PREV_BUILD_PAPER_TEXT_V270 = build_paper_text_v258

def build_paper_text_v258(limit: int = 10) -> str:
    text = _PREV_BUILD_PAPER_TEXT_V270(limit=limit)
    try:
        s = str(text).replace('- v269: v268 м—°кІ° ліөкө¬ мҷ„лЈҢ. nowлҠ” к°•н•ң мҰүмӢңм§„мһ…В·м§„мһ…мӨҖл№„В·кө¬кІҪмңјлЎң лӮҳлҲ„кі , м§„мһ…мӨҖл№„лҠ” 30~90мҙҲ нҷ•мқё нӣ„ м§„мһ….', '- v270: нӣ„ліҙлҠ” л„“кІҢ ліҙкі , л§ӨмҲҳлҠ” мўҒкІҢ. лҜёлҰ¬ліј нӣ„ліҙлҠ” л°”лЎң л§ӨмҲҳн•ҳм§Җ м•Ҡкі  мӨҖл№„/лҢҖкё° кІҖмҰқмңјлЎңл§Ң м—°кІ°.')
        return s.replace('/ preheat_preview_test /', '/ лҜёлҰ¬ліјкІҖмҰқ /')
    except Exception: return text


