# =========================================================
# v2.5.273: м¶ңл Ҙ м •лҰ¬ + лҜёлҰ¬ліј 30/90мҙҲ м¶”м Ғ + мўӢмқҖн‘ңліё мһ¬мҠ№кІ©
# =========================================================
# мқҙлІҲ мҲҳм • лӘ©м Ғ:
# - мЎ°кұҙмқ„ лҚ” мЎ°мқҙлҠ” мҲҳм •мқҙ м•„лӢҲлӢӨ.
# - /cache_statusмқҳ мҳӨлһҳлҗң лІ„м „ мғҒм„ёлҘј м ‘м–ҙм„ң мөңк·ј 5к°ң лІ„м „ мӨ‘мӢ¬мңјлЎң ліёлӢӨ.
# - /paper_statsмқҳ мҠ№лҘ /мҲҳмқөлҘ /PFлҘј мӨ„л°”кҝҲмңјлЎң ліҙкё° мүҪкІҢ л§Ңл“ лӢӨ.
# - лҜёлҰ¬ліј нӣ„ліҙлҠ” 30мҙҲ/90мҙҲ нӣ„ мӮҙм•„лӮЁлҠ”м§Җ м¶”м Ғн•ҳкі , мҷң л§ӨмҲҳк№Ңм§Җ лӘ» мҳ¬лқјк°ҖлҠ”м§Җ лҲ„м Ғн•ңлӢӨ.
# - review_watchмқҳ "кІҖмҰқ н‘ңліё мўӢмқҢ/к°•м„ё нӣ„ мң м§Җ" н‘ңліёмқҙ мЎ°кұҙл§Ң л§һмңјл©ҙ мһ¬мҠ№кІ© кІҪлЎңлЎң мқҙм–ҙм§ҖкІҢ н•ңлӢӨ.
PAPER_V273_START_TS = time.time()
PAPER_V273_STATS = {
    "preview_track_new": 0,
    "preview_30_alive": 0,
    "preview_30_weak": 0,
    "preview_90_promote": 0,
    "preview_90_watch": 0,
    "preview_90_discard": 0,
    "good_sample_reentry": 0,
    "reason_counts": {},
    "last_note": "лҢҖкё°",
}
PREHEAT_TRACK_V273 = {}
PREHEAT_TRACK_V273_MAX = 260


def _v273_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V273_STATS and key != "reason_counts":
            PAPER_V273_STATS[key] = int(safe_float(PAPER_V273_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V273_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v273_inc_reason(reason: str):
    try:
        r = str(reason or "кё°нғҖ").strip()[:40] or "кё°нғҖ"
        d = PAPER_V273_STATS.setdefault("reason_counts", {})
        d[r] = int(safe_float(d.get(r, 0), 0)) + 1
    except Exception:
        pass


def _v273_ticker(row: dict, cls: dict = None) -> str:
    try:
        if isinstance(cls, dict) and cls.get("ticker"):
            return str(cls.get("ticker", "")).upper().strip()
        if '_signal_v257_ticker' in globals():
            t = _signal_v257_ticker(row if isinstance(row, dict) else {})
            if t:
                return str(t).upper().strip()
        if isinstance(row, dict):
            for k in ("ticker", "symbol", "coin"):
                if row.get(k):
                    return str(row.get(k)).upper().strip()
    except Exception:
        pass
    return ""


def _v273_current_price(row: dict, cls: dict = None) -> float:
    try:
        for obj in (cls, row):
            if isinstance(obj, dict):
                for k in ("current_price", "price", "last_price", "close"):
                    v = safe_float(obj.get(k, 0), 0)
                    if v > 0:
                        return v
    except Exception:
        pass
    return 0.0


def _v273_join_payload(cls: dict, row: dict = None) -> str:
    try:
        vals = []
        for obj in (cls, row):
            if not isinstance(obj, dict):
                continue
            for k in [
                "ticker", "decision", "reasons", "v270_reason", "v266_reason", "v264_reason",
                "chart_v262_candle", "chart_v262_money", "chart_v262_high", "money_sustain",
                "high_label", "candle_label", "review_label", "watch_status", "status", "note",
            ]:
                v = obj.get(k, "")
                if v not in (None, ""):
                    vals.append(str(v))
        return " / ".join(vals)[:1800]
    except Exception:
        return ""


def _v273_reason_list_for_not_buy(cls: dict, row: dict = None) -> list:
    reasons = []
    try:
        c = _v270_ctx(cls if isinstance(cls, dict) else {}, row if isinstance(row, dict) else {}) if '_v270_ctx' in globals() else {}
        joined = _v273_join_payload(cls, row)
        if safe_float(c.get('trade_count', 0), 0) < 3:
            reasons.append('мІҙкІ° л¶ҖмЎұ')
        if safe_float(c.get('buy_ratio', 0), 0) < 45:
            reasons.append('л§ӨмҲҳм„ё л¶ҖмЎұ')
        if bool(c.get('candle_weak', False)) or any(w in joined for w in ['нҳ„мһ¬лҙү л°ҖлҰј', 'мң—кј¬лҰ¬', 'л§үнҢҗ л°ҖлҰј']):
            reasons.append('нҳ„мһ¬лҙү м•Ҫн•Ё')
        if 0 <= safe_float(c.get('high_gap', 999), 999) <= 0.12 or any(w in joined for w in ['кі м җ л§һлӢҝмқҢ', 'кі м җ л°”лЎң м•һ']):
            reasons.append('кі м җ л§һлӢҝмқҢ/мң м§Җ л¶ҖмЎұ')
        if bool(c.get('money_weak', False)) or any(w in joined for w in ['л§ӨлҸ„мҡ°м„ё', 'л°ҳм§қ/мӢқлҠ”', 'мӢқлҠ”мӨ‘']):
            reasons.append('лҸҲмқҖ мһҲм§Җл§Ң л§ӨлҸ„мҡ°м„ё/мӢқмқҢ')
        if bool(c.get('money_thin', False)):
            reasons.append('мӢӨм ңлҸҲ л¶ҖмЎұ')
        if safe_float(c.get('from_low', 0), 0) > 2.8:
            reasons.append('м Җм җлҢҖл№„ лҠҰмқҢ')
        dq = str((cls or {}).get('data_quality', (cls or {}).get('data_quality_grade', '')) or '')
        if dq.upper().startswith('C') or 'лҚ°мқҙн„°н’Ҳм§Ҳ: C' in joined:
            reasons.append('лҚ°мқҙн„°н’Ҳм§Ҳ C')
    except Exception:
        pass
    if not reasons:
        reasons.append('л§ӨмҲҳ л¬ён„ұ м „ нҷ•мқёмӨ‘')
    # мӨ‘ліө м ңкұ°, мҲңм„ң мң м§Җ
    out = []
    for r in reasons:
        if r not in out:
            out.append(r)
    return out[:4]


def _v273_track_preview(cls: dict, row: dict = None) -> dict:
    """лҜёлҰ¬ліј нӣ„ліҙлҘј 30мҙҲ/90мҙҲ лӢЁмң„лЎң м¶”м Ғн•ңлӢӨ. мЎ°кұҙ к°•нҷ”к°Җ м•„лӢҲлқј кҙҖм°° кё°лЎқмқҙлӢӨ."""
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    result = {"status_30": "", "status_90": "", "elapsed": 0.0, "promote": False}
    try:
        if str(cls.get('v270_bucket', '')) != 'preheat_preview':
            return result
        ticker = _v273_ticker(row, cls)
        if not ticker:
            return result
        now_ts = time.time()
        price = _v273_current_price(row, cls)
        if price <= 0:
            return result
        c = _v270_ctx(cls, row) if '_v270_ctx' in globals() else {}
        if len(PREHEAT_TRACK_V273) > PREHEAT_TRACK_V273_MAX:
            cutoff = now_ts - 20 * 60
            for k in list(PREHEAT_TRACK_V273.keys()):
                if safe_float(PREHEAT_TRACK_V273.get(k, {}).get('last_ts', 0), 0) < cutoff:
                    PREHEAT_TRACK_V273.pop(k, None)
        tr = PREHEAT_TRACK_V273.get(ticker)
        if not isinstance(tr, dict):
            tr = {
                'first_ts': now_ts, 'last_ts': now_ts, 'first_price': price,
                'best_price': price, 'low_price': price, 'status_30': '', 'status_90': '',
                'last_reason_sig': '', 'reason_ts': 0,
            }
            PREHEAT_TRACK_V273[ticker] = tr
            _v273_inc('preview_track_new', f'лҜёлҰ¬ліј м¶”м Ғ мӢңмһ‘ {ticker}')
        tr['last_ts'] = now_ts
        tr['best_price'] = max(safe_float(tr.get('best_price', price), price), price)
        tr['low_price'] = min(safe_float(tr.get('low_price', price), price), price)
        elapsed = max(0.0, now_ts - safe_float(tr.get('first_ts', now_ts), now_ts))
        result['elapsed'] = elapsed
        first_price = safe_float(tr.get('first_price', price), price)
        chg_from_first = ((price - first_price) / first_price) * 100.0 if first_price > 0 else 0.0
        best_from_first = ((safe_float(tr.get('best_price', price), price) - first_price) / first_price) * 100.0 if first_price > 0 else 0.0
        candle_weak = bool(c.get('candle_weak', False))
        money_weak = bool(c.get('money_weak', False))
        trade_count = int(safe_float(c.get('trade_count', 0), 0))
        buy_ratio = safe_float(c.get('buy_ratio', 0), 0)
        alive = bool(chg_from_first >= -0.30 and not (candle_weak and money_weak))
        promote = bool((best_from_first >= 0.35 or chg_from_first >= 0.20 or safe_float(c.get('chg', 0), 0) >= 0.65)
                       and trade_count >= 2 and buy_ratio >= 45 and not candle_weak)
        discard = bool(chg_from_first <= -0.55 or (candle_weak and money_weak))
        if elapsed >= 30 and not tr.get('status_30'):
            if alive:
                tr['status_30'] = 'мӮҙм•„лӮЁмқҢ'
                _v273_inc('preview_30_alive', f'30мҙҲ мӮҙм•„лӮЁмқҢ {ticker}')
            else:
                tr['status_30'] = 'л°ҖлҰј/мӢқмқҢ'
                _v273_inc('preview_30_weak', f'30мҙҲ л°ҖлҰј {ticker}')
        if elapsed >= 90 and not tr.get('status_90'):
            if promote:
                tr['status_90'] = 'мҠ№кІ©к°ҖлҠҘ'
                _v273_inc('preview_90_promote', f'90мҙҲ мҠ№кІ©к°ҖлҠҘ {ticker}')
            elif discard:
                tr['status_90'] = 'лІ„лҰј'
                _v273_inc('preview_90_discard', f'90мҙҲ лІ„лҰј {ticker}')
            else:
                tr['status_90'] = 'кө¬кІҪмң м§Җ'
                _v273_inc('preview_90_watch', f'90мҙҲ кө¬кІҪмң м§Җ {ticker}')
        reasons = _v273_reason_list_for_not_buy(cls, row)
        sig = '|'.join(reasons)
        if sig and (sig != tr.get('last_reason_sig') or now_ts - safe_float(tr.get('reason_ts', 0), 0) > 90):
            tr['last_reason_sig'] = sig
            tr['reason_ts'] = now_ts
            for reason in reasons[:3]:
                _v273_inc_reason(reason)
        result.update({'status_30': str(tr.get('status_30','')), 'status_90': str(tr.get('status_90','')), 'promote': bool(promote or tr.get('status_90') == 'мҠ№кІ©к°ҖлҠҘ')})
    except Exception as e:
        try: append_runtime_error_log('v273_track_preview', str(e), exc=e, include_traceback=False)
        except Exception: pass
    return result


def _v273_is_good_sample_reentry(cls: dict, row: dict = None) -> bool:
    try:
        cls = cls if isinstance(cls, dict) else {}
        row = row if isinstance(row, dict) else {}
        joined = _v273_join_payload(cls, row)
        if not any(w in joined for w in ['кІҖмҰқ н‘ңліё мўӢмқҢ', 'к°•м„ё нӣ„ мң м§Җ', 'мўӢмқҖ н‘ңліё', 'мһ¬м¶ңл°ң нҷ•мқёнҳ•', 'м Җм җ мһ¬мқҙнғҲ м—Ҷмқҙ лӢӨмӢң мӮҙм•„лӮЁ']):
            return False
        c = _v270_ctx(cls, row) if '_v270_ctx' in globals() else {}
        if bool(c.get('money_thin', False)):
            return False
        if bool(c.get('candle_weak', False)) and bool(c.get('money_weak', False)):
            return False
        if safe_float(c.get('from_low', 0), 0) > 3.2:
            return False
        if safe_float(c.get('money', 0), 0) < 20_000_000 and int(safe_float(c.get('trade_count', 0), 0)) < 2:
            return False
        return True
    except Exception:
        return False


try:
    _BASE_SIGNAL_CLASSIFY_V273 = _signal_v257_classify
    def _signal_v257_classify(row: dict) -> dict:
        cls = dict(_BASE_SIGNAL_CLASSIFY_V273(row) or {})
        try:
            # кІҖмҰқ н‘ңліё мўӢмқҢ/к°•м„ё нӣ„ мң м§Җ н‘ңліёмқҖ ліөкё°м—җм„ң лҒқлӮҙм§Җ м•Ҡкі  мһ¬мҠ№кІ© кҙҖм°°мёөмңјлЎң м—°кІ°н•ңлӢӨ.
            if _v273_is_good_sample_reentry(cls, row):
                if str(cls.get('v270_bucket', '')) not in {'buy_ready', 'early_entry', 'restart_pullback', 'good_sample_reentry'}:
                    cls['v270_bucket'] = 'good_sample_reentry'
                    cls['v266_bucket'] = 'good_sample_reentry'
                    cls['v266_reason'] = 'кІҖмҰқ н‘ңліё мўӢмқҢ вҶ’ 30~90мҙҲ мң м§Җ мһ¬мҠ№кІ©'
                    cls['v270_reason'] = 'кІҖмҰқ н‘ңліё мўӢмқҢ / мһ¬мҠ№кІ© кҙҖм°°'
                    cls['v270_entry_rule'] = 'pullback'
                    cls['v266_entry_rule'] = 'pullback'
                    cls['paper_entry_rule_v259'] = 'pullback'
                    cls['grade'] = 'PULLBACK_WAIT'
                    _v273_inc('good_sample_reentry', f"мўӢмқҖн‘ңліё мһ¬мҠ№кІ© {_v273_ticker(row, cls) or '?'}")
            # лҜёлҰ¬ліј нӣ„ліҙлҠ” 30/90мҙҲ м¶”м Ғн•ңлӢӨ. 90мҙҲ мҠ№кІ© к°ҖлҠҘмқҙл©ҙ лҢҖкё°мёөмңјлЎң мҳ¬л Ө paper м§„мһ… л¬ён„ұм—җм„ң кІҖмҰқн•ңлӢӨ.
            track = _v273_track_preview(cls, row)
            if track.get('promote') and str(cls.get('v270_bucket', '')) == 'preheat_preview':
                cls['v270_bucket'] = 'good_sample_reentry'
                cls['v266_bucket'] = 'good_sample_reentry'
                cls['v266_reason'] = 'лҜёлҰ¬ліј 90мҙҲ мғқмЎҙ вҶ’ мһ¬мҠ№кІ© кҙҖм°°'
                cls['v270_reason'] = '90мҙҲ мғқмЎҙ / мһ¬мҠ№кІ© кҙҖм°°'
                cls['v270_entry_rule'] = 'pullback'
                cls['v266_entry_rule'] = 'pullback'
                cls['paper_entry_rule_v259'] = 'pullback'
                cls['grade'] = 'PULLBACK_WAIT'
            if track.get('status_30'):
                cls['v273_preview_30'] = track.get('status_30')
            if track.get('status_90'):
                cls['v273_preview_90'] = track.get('status_90')
        except Exception as e:
            try: append_runtime_error_log('signal_v273_classify', str(e), exc=e, include_traceback=False)
            except Exception: pass
        return cls
except Exception:
    pass


try:
    _BASE_SIGNAL_FORMAT_V273 = _signal_v270_format_one
    def _signal_v270_format_one(row: dict, order: int = 1, show_detail: bool = True) -> str:
        text = _BASE_SIGNAL_FORMAT_V273(row, order=order, show_detail=show_detail)
        try:
            cls = _signal_v257_classify(row if isinstance(row, dict) else {})
            lines = str(text).splitlines()
            insert_at = 2 if len(lines) > 2 else len(lines)
            additions = []
            if cls.get('v273_preview_30') or cls.get('v273_preview_90'):
                additions.append(f"- v273м¶”м Ғ: 30мҙҲ {cls.get('v273_preview_30') or 'лҢҖкё°'} / 90мҙҲ {cls.get('v273_preview_90') or 'лҢҖкё°'}")
            if str(cls.get('v266_reason','')).startswith('кІҖмҰқ н‘ңліё мўӢмқҢ') or str(cls.get('v266_reason','')).startswith('лҜёлҰ¬ліј 90мҙҲ'):
                additions.append(f"- v273мһ¬мҠ№кІ©: {cls.get('v266_reason')}")
            for add in reversed(additions):
                if add and add not in lines:
                    lines.insert(insert_at, add)
            return '\n'.join(lines)
        except Exception:
            return text
except Exception:
    pass


def _v273_format_pf(pf: float) -> str:
    try:
        return "вҲһ" if safe_float(pf, 0) >= 900 else f"{safe_float(pf, 0):.2f}"
    except Exception:
        return "0.00"


