def _v273_cache_section_version(line: str):
    try:
        s = str(line or '').strip()
        if not s or s.startswith('-') or s.startswith('['):
            return None
        m = __import__('re').search(r'v2\.5\.(\d+)', s)
        if not m:
            return None
        return int(m.group(1))
    except Exception:
        return None


def _v273_compact_cache_status_versions(text: str, keep_n: int = 5) -> str:
    try:
        lines = str(text or '').splitlines()
        pre = []
        sections = []
        cur = None
        cur_ver = None
        for line in lines:
            ver = _v273_cache_section_version(line)
            if ver is not None:
                if cur is not None:
                    sections.append((cur_ver, cur))
                cur_ver = ver
                cur = [line]
            else:
                if cur is None:
                    pre.append(line)
                else:
                    cur.append(line)
        if cur is not None:
            sections.append((cur_ver, cur))
        if not sections:
            return str(text or '')
        max_ver = max(v for v, _ in sections if isinstance(v, int))
        keep_from = max_ver - max(1, int(keep_n)) + 1
        kept = [(v, sec) for v, sec in sections if v >= keep_from]
        hidden = [(v, sec) for v, sec in sections if v < keep_from]
        out = list(pre)
        if hidden:
            versions = sorted(set(v for v, _ in hidden))
            if versions:
                rng = f"v2.5.{versions[0]}~v2.5.{versions[-1]}" if len(versions) > 1 else f"v2.5.{versions[0]}"
            else:
                rng = "мқҙм „ лІ„м „"
            out += [
                '',
                'рҹ—Ӯ мқҙм „ лІ„м „ м•Ҳм •нҷ” мҡ”м•Ҫ',
                f"- {rng} мғҒм„ё м„№м…ҳ {len(hidden)}к°ң м ‘мқҢ / мөңк·ј {len(kept)}к°ң лІ„м „л§Ң мһҗм„ёнһҲ н‘ңмӢң",
                '- мҳӨлһҳлҗң м•Ҳм •нҷ”В·нҡҢк·Җ м җкІҖ лӮҙмҡ©мқҖ мөңмӢ  мқёмҲҳмқёкі„ нҢҢмқјм—җ мң м§Җ',
                '- ліҙкё° л¶ҲнҺён•ң лҲ„м Ғ м„ӨлӘ…л§Ң м ‘мқҖ кІғмқҙкі  кё°лҠҘмқ„ мӮӯм ңн•ң кІғмқҖ м•„лӢҳ',
            ]
        for _v, sec in kept:
            out.append('')
            out.extend(sec)
        return '\n'.join(out).strip()
    except Exception:
        return str(text or '')


