# =========================================================
# v2.5.274: лҜёлҰ¬ліј мғқмЎҙ нӣ„ліҙ вҶ’ м§„мһ…мӨҖл№„ лёҢлҰҝм§Җ ліҙк°•
# =========================================================
# лӘ©м Ғ:
# - мЎ°кұҙмқ„ мЎ°мқҙлҠ” лІ„м „мқҙ м•„лӢҲлӢӨ.
# - v273м—җм„ң 30мҙҲ мӮҙм•„лӮЁмқҖ лҜёлҰ¬ліј мӨ‘ лҸҲ/мІҙкІ°/нҳ„мһ¬лҙүмқҙ мӢӨм ңлЎң мӮҙм•„ мһҲлҠ” нӣ„ліҙлҘј
#   л°”лЎң л§ӨмҲҳн•ҳм§Җ м•Ҡкі  "м§„мһ…мӨҖл№„" нӣ„ліҙлЎң мҳ¬лҰ°лӢӨ.
# - кі м җ л§һлӢҝмқҢмқҖ мӢңмһҘк°Җ л§ӨмҲҳ кёҲм§Җ. лҸҢнҢҢ мң м§Җ нҷ•мқё/лҲҢлҰј лҢҖкё°лЎң л¶„лҰ¬н•ңлӢӨ.
# - мІҙкІ° 0, л§ӨлҸ„мҡ°м„ё, нҳ„мһ¬лҙү л°ҖлҰј/мң„кј¬лҰ¬ нӣ„ліҙлҠ” кі„мҶҚ м§„мһ…мӨҖл№„ мҠ№кІ©мқ„ л§үлҠ”лӢӨ.
PAPER_V274_START_TS = time.time()
PAPER_V274_STATS = {
    "bridge_ready": 0,
    "bridge_pullback": 0,
    "bridge_breakout_wait": 0,
    "bridge_blocked": 0,
    "doge_high_touch_wait": 0,
    "may_like_ready": 0,
    "blocked_zero_trade": 0,
    "blocked_sell_heavy": 0,
    "blocked_candle_weak": 0,
    "last_note": "лҢҖкё°",
}


def _v274_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V274_STATS:
            PAPER_V274_STATS[key] = int(safe_float(PAPER_V274_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V274_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v274_has(text, words) -> bool:
    try:
        t = str(text or "")
        return any(str(w) in t for w in list(words or []))
    except Exception:
        return False


def _v274_preview_track_snapshot(cls: dict, row: dict = None) -> dict:
    """v273 лҜёлҰ¬ліј м¶”м Ғ л©”лӘЁлҰ¬лҘј мқҪлҠ”лӢӨ. мғҲ API/OHLCV нҳём¶ң м—ҶмқҢ."""
    row = row if isinstance(row, dict) else {}
    cls = cls if isinstance(cls, dict) else {}
    out = {"elapsed": 0.0, "status_30": "", "status_90": "", "best_from_first": 0.0, "chg_from_first": 0.0}
    try:
        ticker = _v273_ticker(row, cls) if '_v273_ticker' in globals() else str(cls.get('ticker', row.get('ticker', '')) or '').upper().strip()
        if not ticker or 'PREHEAT_TRACK_V273' not in globals():
            return out
        tr = PREHEAT_TRACK_V273.get(ticker, {})
        if not isinstance(tr, dict):
            return out
        now_ts = time.time()
        first_ts = safe_float(tr.get('first_ts', 0), 0)
        first_price = safe_float(tr.get('first_price', 0), 0)
        last_price = _v273_current_price(row, cls) if '_v273_current_price' in globals() else safe_float(cls.get('price', row.get('price', 0)), 0)
        best_price = safe_float(tr.get('best_price', last_price), last_price)
        if first_ts > 0:
            out['elapsed'] = max(0.0, now_ts - first_ts)
        out['status_30'] = str(tr.get('status_30', cls.get('v273_preview_30', '')) or '')
        out['status_90'] = str(tr.get('status_90', cls.get('v273_preview_90', '')) or '')
        if first_price > 0 and last_price > 0:
            out['chg_from_first'] = ((last_price - first_price) / first_price) * 100.0
        if first_price > 0 and best_price > 0:
            out['best_from_first'] = ((best_price - first_price) / first_price) * 100.0
    except Exception:
        return out
    return out


def _v274_preview_bridge_eval(cls: dict, row: dict = None) -> dict:
    """лҜёлҰ¬ліјмқ„ мЈҪмқҙм§Җ м•Ҡкі , 30мҙҲ мғқмЎҙ + мӢӨмІҙ мһҲлҠ” нӣ„ліҙл§Ң м§„мһ…мӨҖл№„лЎң мҳ¬лҰҙм§Җ нҢҗлӢЁ."""
    cls = cls if isinstance(cls, dict) else {}
    row = row if isinstance(row, dict) else {}
    res = {
        "ok": False,
        "bucket": "",
        "grade": "",
        "entry_rule": "observe",
        "reason": "",
        "wait_reason": "",
        "may_like": False,
        "high_touch_wait": False,
    }
    try:
        if str(cls.get('v270_bucket', '') or '') != 'preheat_preview':
            return res
        c = _v270_ctx(cls, row) if '_v270_ctx' in globals() else {}
        joined = _v273_join_payload(cls, row) if '_v273_join_payload' in globals() else " ".join([str(cls), str(row)])[:1600]
        track = _v274_preview_track_snapshot(cls, row)
        status_30 = str(cls.get('v273_preview_30', '') or track.get('status_30', '') or '')
        elapsed = safe_float(track.get('elapsed', 0), 0)
        chg_from_first = safe_float(track.get('chg_from_first', 0), 0)
        best_from_first = safe_float(track.get('best_from_first', 0), 0)

        money = safe_float(c.get('money', cls.get('money_amount', 0)), 0)
        trade_count = int(safe_float(c.get('trade_count', cls.get('trade_count', 0)), 0))
        buy_ratio = safe_float(c.get('buy_ratio', cls.get('buy_ratio', 0)), 0)
        from_low = safe_float(c.get('from_low', cls.get('from_low', cls.get('from_30m_low_pct', 0))), 0)
        high_gap = safe_float(c.get('high_gap', cls.get('high_gap', 999)), 999)
        score = safe_float(c.get('score', cls.get('score', 0)), 0)
        chg = safe_float(c.get('chg', 0), 0)
        candle_weak = bool(c.get('candle_weak', False)) or _v274_has(joined, ['нҳ„мһ¬лҙү л°ҖлҰј', 'мң„кј¬лҰ¬', 'мң—кј¬лҰ¬', 'л§үнҢҗ л°ҖлҰј'])
        candle_alive = bool(c.get('candle_alive', False)) or _v274_has(joined, ['нҳ„мһ¬лҙү мӮҙм•„лӮЁ', 'мӮҙм•„лӮЁ', 'м•„лһ«кј¬лҰ¬ нҡҢліө', 'нҡҢліө к°•н•Ё'])
        money_weak = bool(c.get('money_weak', False)) or _v274_has(joined, ['л§ӨлҸ„мҡ°м„ё', 'л§ӨлҸ„ мҡ°м„ё', 'л°ҳм§қ/мӢқлҠ”', 'мӢқлҠ”мӨ‘', 'лҸҲмқҖ мһҲм§Җл§Ң л§ӨлҸ„мҡ°м„ё'])
        money_strong_text = _v274_has(joined, ['лҸҲмң м§Җ к°•н•Ё', 'лҸҲ мң м§Җ к°•н•Ё', 'лҢҖкёҲ м¶©л¶„', 'л§ӨмҲҳм„ё к°•н•Ё', 'мӢӨм ңлҸҲ м¶©л¶„'])
        high_touch = (0 <= high_gap <= 0.12) or _v274_has(joined, ['кі м җ л§һлӢҝмқҢ', 'кі м җ л°”лЎң м•һ', 'мөңк·ј30л¶„ кі м җ л°”лЎң к·јмІҳ'])
        high_hold = _v274_has(joined, ['лҸҢнҢҢ нӣ„ мң м§Җ', 'мһ¬лҸҢнҢҢ мң м§Җ', 'мң м§Җ нҷ•мқё', 'кі м җ лҸҢнҢҢ нӣ„ мң м§Җ'])

        # v274 н•өмӢ¬: 30мҙҲ мғқмЎҙмқҙ нҷ•мқёлҗң лҜёлҰ¬ліјл§Ң лёҢлҰҝм§Җ нӣ„ліҙк°Җ лҗңлӢӨ.
        survived_30 = (status_30 == 'мӮҙм•„лӮЁмқҢ') or (elapsed >= 30 and chg_from_first >= -0.25 and not (candle_weak and money_weak))
        may_like = bool(candle_alive and buy_ratio >= 78 and trade_count >= 5 and (money >= 30_000_000 or money_strong_text) and not money_weak)
        money_ok = bool(money >= 50_000_000 or money_strong_text or (may_like and money >= 20_000_000))
        buy_ok = bool(buy_ratio >= 55 or may_like)
        trade_ok = bool(trade_count >= 2 or may_like)
        not_overheated = bool(from_low <= 3.10 or (may_like and from_low <= 3.30))
        momentum_alive = bool(candle_alive or (not candle_weak and (best_from_first >= 0.20 or chg >= 0.45 or score >= 5.0)))

        if not survived_30:
            res['wait_reason'] = '30мҙҲ мғқмЎҙ нҷ•мқё м „'
            return res
        if trade_count <= 0:
            _v274_inc('blocked_zero_trade', f"мІҙкІ°0 мҠ№кІ©кёҲм§Җ {cls.get('ticker','?')}")
            res['wait_reason'] = 'мІҙкІ° 0мқҙлқј м§„мһ…мӨҖл№„ мҠ№кІ© кёҲм§Җ'
            return res
        if money_weak:
            _v274_inc('blocked_sell_heavy', f"л§ӨлҸ„мҡ°м„ё мҠ№кІ©кёҲм§Җ {cls.get('ticker','?')}")
            res['wait_reason'] = 'лҸҲмқҖ мһҲм§Җл§Ң л§ӨлҸ„мҡ°м„ё/мӢқмқҢмқҙлқј кө¬кІҪ мң м§Җ'
            return res
        if candle_weak and not may_like:
            _v274_inc('blocked_candle_weak', f"нҳ„мһ¬лҙүм•Ҫн•Ё мҠ№кІ©кёҲм§Җ {cls.get('ticker','?')}")
            res['wait_reason'] = 'нҳ„мһ¬лҙү л°ҖлҰј/мң„кј¬лҰ¬лқј м§„мһ… кёҲм§Җ'
            return res
        if not (money_ok and buy_ok and trade_ok and momentum_alive and not_overheated):
            _v274_inc('bridge_blocked', f"лёҢлҰҝм§Җ мЎ°кұҙл¶ҖмЎұ {cls.get('ticker','?')}")
            lack = []
            if not money_ok: lack.append('лҸҲмң м§Җ л¶ҖмЎұ')
            if not buy_ok: lack.append('л§ӨмҲҳл№„мңЁ л¶ҖмЎұ')
            if not trade_ok: lack.append('мІҙкІ° л¶ҖмЎұ')
            if not momentum_alive: lack.append('нҳ„мһ¬лҙү мғқмЎҙ л¶ҖмЎұ')
            if not not_overheated: lack.append('м Җм җлҢҖл№„ кіјм—ҙ')
            res['wait_reason'] = ' / '.join(lack[:3]) or 'лёҢлҰҝм§Җ мЎ°кұҙ нҷ•мқёмӨ‘'
            return res

        # DOGEнҳ•: кі м җ л§һлӢҝмқҢмқҖ мӢңмһҘк°Җ кёҲм§Җ. мң м§Җ нҷ•мқёмқҙ мһҲмңјл©ҙ лҸҢнҢҢлҢҖкё°, м—Ҷмңјл©ҙ лҜёлҰ¬ліј мң м§Җ.
        if high_touch and not high_hold:
            _v274_inc('doge_high_touch_wait', f"кі м җл§һлӢҝмқҢ лҢҖкё° {cls.get('ticker','?')}")
            res['high_touch_wait'] = True
            res['wait_reason'] = 'кі м җ л§һлӢҝмқҢ вҶ’ мӢңмһҘк°Җ кёҲм§Җ, лҲҢлҰј/лҸҢнҢҢ мң м§Җ нҷ•мқё лҢҖкё°'
            return res
        if high_touch and high_hold:
            res.update({
                'ok': True,
                'bucket': 'breakout_watch',
                'grade': 'BREAKOUT_WAIT',
                'entry_rule': 'breakout',
                'reason': 'лҜёлҰ¬ліј 30мҙҲ мғқмЎҙ + лҸҢнҢҢ мң м§Җ нҷ•мқё лҢҖкё°',
                'may_like': may_like,
            })
            return res

        # MAYнҳ•/мһ¬м¶ңл°ңнҳ•: л°”лЎң л§ӨмҲҳк°Җ м•„лӢҲлқј лҲҢлҰјВ·мһ¬м¶ңл°ң м§„мһ…мӨҖл№„лЎң мҳ¬лҰ°лӢӨ.
        res.update({
            'ok': True,
            'bucket': 'restart_pullback',
            'grade': 'PULLBACK_WAIT',
            'entry_rule': 'pullback',
            'reason': 'лҜёлҰ¬ліј 30мҙҲ мғқмЎҙ + лҸҲ/мІҙкІ°/нҳ„мһ¬лҙү мң м§Җ вҶ’ м§„мһ…мӨҖл№„',
            'may_like': may_like,
        })
        return res
    except Exception as e:
        try: append_runtime_error_log('v274_preview_bridge_eval', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return res


try:
    _BASE_SIGNAL_CLASSIFY_V274 = _signal_v257_classify
    def _signal_v257_classify(row: dict) -> dict:
        cls = dict(_BASE_SIGNAL_CLASSIFY_V274(row) or {})
        try:
            ev = _v274_preview_bridge_eval(cls, row if isinstance(row, dict) else {})
            if ev.get('ok'):
                bucket = str(ev.get('bucket') or 'restart_pullback')
                grade = str(ev.get('grade') or 'PULLBACK_WAIT')
                entry_rule = str(ev.get('entry_rule') or 'pullback')
                cls['v274_bridge_ok'] = True
                cls['v274_bridge_bucket'] = bucket
                cls['v274_bridge_reason'] = str(ev.get('reason') or '')
                cls['v274_entry_rule'] = entry_rule
                cls['v270_bucket'] = bucket
                cls['v266_bucket'] = bucket
                cls['v266_reason'] = str(ev.get('reason') or '')
                cls['v270_reason'] = str(ev.get('reason') or '')
                cls['v270_entry_rule'] = entry_rule
                cls['v266_entry_rule'] = entry_rule
                cls['paper_entry_rule_v259'] = entry_rule
                cls['paper_original_grade'] = str(cls.get('paper_original_grade', 'PREVIEW') or 'PREVIEW')
                cls['grade'] = grade
                cls['decision'] = 'лҜёлҰ¬ліј мғқмЎҙ м§„мһ…мӨҖл№„'
                cls['action'] = 'л°”лЎң л§ӨмҲҳ м•„лӢҳ. 30мҙҲ мӮҙм•„лӮЁмқҖ нӣ„ліҙлҘј лҲҢлҰј/лҸҢнҢҢ мң м§Җ нҷ•мқё лҢҖкё°лЎң мҳ¬л Ө paperм—җм„ң кІҖмҰқ.'
                if ev.get('may_like'):
                    cls['v274_may_like_ready'] = True
                    _v274_inc('may_like_ready', f"MAYнҳ• м§„мһ…мӨҖл№„ {cls.get('ticker','?')}")
                if bucket == 'breakout_watch':
                    _v274_inc('bridge_breakout_wait', f"лҸҢнҢҢмң м§Җ лҢҖкё° {cls.get('ticker','?')}")
                else:
                    _v274_inc('bridge_pullback', f"лҲҢлҰј/мһ¬м¶ңл°ң мӨҖл№„ {cls.get('ticker','?')}")
                _v274_inc('bridge_ready', f"лҜёлҰ¬ліјвҶ’м§„мһ…мӨҖл№„ {cls.get('ticker','?')}/{entry_rule}")
            elif ev.get('wait_reason'):
                cls['v274_wait_reason'] = str(ev.get('wait_reason') or '')
                cls['v274_high_touch_wait'] = bool(ev.get('high_touch_wait'))
        except Exception as e:
            try: append_runtime_error_log('signal_v274_classify', str(e), exc=e, include_traceback=False)
            except Exception: pass
        return cls
except Exception:
    pass


