PAPER_V277_START_TS = time.time()
PAPER_V277_STATS = {
    "paper_compact_calls": 0,
    "paper_stats_compact_calls": 0,
    "paper_stats_full_calls": 0,
    "paper_recent_compact_calls": 0,
    "signal_compact_calls": 0,
    "signal_full_calls": 0,
    "paper_wait_over_entry": 0,
    "paper_wait_chase_block": 0,
    "last_note": "лҢҖкё°",
    "last_command": "лҢҖкё°",
    "last_build_sec": 0.0,
    "last_chars": 0,
}

def _v277_inc(k, note=""):
    try:
        if k in PAPER_V277_STATS:
            PAPER_V277_STATS[k] = int(safe_float(PAPER_V277_STATS.get(k, 0), 0)) + 1
        if note:
            PAPER_V277_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass

def _v277_record_command(name: str, text: str, start_ts: float):
    try:
        PAPER_V277_STATS["last_command"] = str(name or "")[:60]
        PAPER_V277_STATS["last_build_sec"] = round(max(0.0, time.time() - safe_float(start_ts, time.time())), 3)
        PAPER_V277_STATS["last_chars"] = len(str(text or ""))
    except Exception:
        pass

def _v277_rows_by_window(kind: str):
    try:
        rows = _paper_closed_logs_v258()
        now_ts = time.time()
        start = _paper_window_start_v258(kind, now_ts)
        return [r for r in rows if safe_float(r.get("close_ts", 0), 0) >= start]
    except Exception:
        return []

def _v277_stats_short_line(label: str, rows: list) -> str:
    try:
        st = _paper_stats_for_rows_v258(rows)
        if st.get("n", 0) <= 0:
            return f"- {label}: кұ°лһҳ м—ҶмқҢ"
        pf = safe_float(st.get("profit_factor", 0), 0)
        pf_text = "вҲһ" if pf >= 900 else f"{pf:.2f}"
        return f"- {label}: {st['n']}м „ {st['wins']}мҠ№ {st['losses']}нҢЁ / мҠ№лҘ  {st['win_rate']:.1f}% / лҲ„м Ғ {st['total_pct']:+.2f}% / PF {pf_text}"
    except Exception:
        return f"- {label}: кі„мӮ° мҳӨлҘҳ"

def _v277_cancel_reason_top(limit: int = 4):
    try:
        rows = _paper_closed_logs_v258(include_cancelled=True)
        rows = [r for r in rows if str(r.get("status", "")).upper() == "CANCELLED"]
        rows.sort(key=lambda r: safe_float(r.get("close_ts", r.get("cancel_ts", 0)), 0), reverse=True)
        counts = {}
        for r in rows[:80]:
            reason = str(r.get("close_reason", "") or "-")
            key = reason
            if "early_pending_cancel" in reason:
                key = "лҢҖкё° мӨ‘ мӢ нҳём•…нҷ”"
            elif "preview_command_only" in reason:
                key = "мҲңмҲҳ лҜёлҰ¬ліј paper м ңмҷё"
            elif "entry_precheck" in reason:
                key = "м§„мһ…м§Ғм „ нһҳл№ м§җ"
            elif "chase_over" in reason:
                key = "м¶”кІ©кёҲм§Җ мҙҲкіј"
            elif "v276_prepare_sell" in reason:
                key = "м§„мһ…мӨҖл№„ нӣ„ л§ӨлҸ„л°ҳм „"
            elif "v276_prepare_high" in reason:
                key = "м§„мһ…мӨҖл№„ нӣ„ кі м җмң м§Җ мӢӨнҢЁ"
            counts[key] = counts.get(key, 0) + 1
        return sorted(counts.items(), key=lambda x: -x[1])[:max(1, int(limit))]
    except Exception:
        return []

