def _v277_pending_state_line(p: dict) -> str:
    try:
        price = safe_float(p.get("last_price", 0), 0)
        low = safe_float(p.get("planned_entry_low", 0), 0)
        high = safe_float(p.get("planned_entry_high", 0), 0)
        chase = safe_float(p.get("chase_stop", 0), 0)
        if price > 0 and chase > 0 and price >= chase:
            _v277_inc("paper_wait_chase_block", f"paper лҢҖкё° м¶”кІ©кёҲм§Җ мҙҲкіј {p.get('ticker','?')}")
            return "мғҒнғң: м¶”кІ©кёҲм§Җ мҙҲкіј/м·ЁмҶҢ нӣ„ліҙ"
        if price > 0 and high > 0 and price > high:
            _v277_inc("paper_wait_over_entry", f"paper лҢҖкё° м§„мһ…к°Җ мң„ {p.get('ticker','?')}")
            return "мғҒнғң: м§„мһ…к°Җ мң„лқј лҲҢлҰј лҢҖкё°"
        if price > 0 and low > 0 and price < low:
            return "мғҒнғң: м§„мһ…к°Җ м•„лһҳ/нһҳ м•Ҫнҷ” нҷ•мқё н•„мҡ”"
        return "мғҒнғң: м§„мһ…лҢҖкё° мң м§Җ"
    except Exception:
        return "мғҒнғң: нҷ•мқёмӨ‘"

try:
    _FULL_BUILD_PAPER_TEXT_V277 = build_paper_text_v258
    def build_paper_text_full_v277(limit:int=10):
        return str(_FULL_BUILD_PAPER_TEXT_V277(limit=limit))

    def build_paper_text_v258(limit:int=8):
        t0 = time.time()
        paper_update_positions_once_v258()
        with PAPER_STATE_LOCK:
            rows = [dict(p) for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() in {"PENDING", "OPEN"}]
        rows.sort(key=lambda x: (0 if str(x.get("status", "")).upper() == "OPEN" else 1, -safe_float(x.get("created_ts", 0), 0)))
        lines = [
            "рҹ§Ә лӘЁмқҳл§Өл§Ө /paper",
            "- мӢӨм ң мЈјл¬ё м•„лӢҳ / м§„н–ү мӨ‘мқё paperл§Ң м§§кІҢ н‘ңмӢң",
            "- мғҒм„ё м„ұкіј: /paper_stats_full, мөңк·ј кё°лЎқ: /paper_recent",
            "",
        ]
        if not rows:
            lines.append("- м§„н–ү мӨ‘мқё лӘЁмқҳ нҸ¬м§Җм…ҳ м—ҶмқҢ")
        for i, p in enumerate(rows[:max(1, int(limit))], start=1):
            ticker = str(p.get("ticker", "?") or "?")
            status = str(p.get("status", "") or "").upper()
            price = safe_float(p.get("last_price", 0), 0)
            entry = safe_float(p.get("entry_price", 0), 0)
            if status == "PENDING":
                lines += [
                    f"{i}. вҸі {ticker} / м§„мһ…лҢҖкё° / {p.get('entry_rule')} / {p.get('lane')}",
                    f"- нҳ„мһ¬ {fmt_price_detail(price)} / м§„мһ… {fmt_price_detail(p.get('planned_entry_low',0))}~{fmt_price_detail(p.get('planned_entry_high',0))} / м¶”кІ©кёҲм§Җ {fmt_price_detail(p.get('chase_stop',0))}",
                    f"- {_v277_pending_state_line(p)} / мҶҗм Ҳ {fmt_price_detail(p.get('stop',0))} / TP1 {fmt_price_detail(p.get('tp1',0))}",
                ]
                rr = str(p.get("register_reason", "") or "").strip()
                if rr:
                    lines.append(f"- мқҙмң : {rr[:80]}")
            else:
                pnl = _paper_pct_v258(entry, price) if entry > 0 else 0.0
                lines += [
                    f"{i}. вң… {ticker} / ліҙмң к°Җм • / {p.get('entry_rule', p.get('lane'))} / мҲҳмқө {pnl:+.2f}%",
                    f"- м§„мһ… {fmt_price_detail(entry)} / нҳ„мһ¬ {fmt_price_detail(price)} / мөңкі  {safe_float(p.get('max_up_pct',0),0):+.2f}% / мөңм Җ {safe_float(p.get('min_down_pct',0),0):+.2f}%",
                    f"- мҶҗм Ҳ {fmt_price_detail(p.get('stop',0))} / TP1 {fmt_price_detail(p.get('tp1',0))} / TP2 {fmt_price_detail(p.get('tp2',0))}",
                ]
            lines.append("")
        text = "\n".join(lines).strip()
        _v277_inc("paper_compact_calls", "paper м••м¶• м¶ңл Ҙ")
        _v277_record_command("paper", text, t0)
        return text
except Exception:
    pass

