try:
    _FULL_BUILD_SIGNAL_TEXT_V277 = build_signal_text_v256
    def build_signal_text_full_v277(args=None, limit:int=None):
        t0 = time.time()
        text = str(_FULL_BUILD_SIGNAL_TEXT_V277(args=args, limit=limit))
        _v277_inc("signal_full_calls", "signal_full мғҒм„ё м¶ңл Ҙ")
        _v277_record_command("signal_full", text, t0)
        return text

    def _v277_compact_signal_from_full(full_text: str, coin_specific: bool = False) -> str:
        try:
            lines = str(full_text or "").splitlines()
            out = []
            for ln in lines[:8]:
                st = ln.strip()
                if not st:
                    continue
                if st.startswith("рҹҺҜ") or st.startswith("- мӢңк°Ғ:") or "нҳ„мһ¬ мҰүмӢң л§ӨмҲҳ мӢ нҳё" in st:
                    out.append(st)
            current = []
            items = []
            for ln in lines:
                s = ln.strip()
                if len(s) >= 3 and s[0].isdigit() and ". " in s[:6]:
                    if current:
                        items.append(current)
                    current = [s]
                elif current:
                    if any(key in s for key in ["кІ°лЎ :", "мқҙмң :", "v275мІҙкІ°нқҗлҰ„", "v276кі м җм§„лӢЁ", "v276мһ¬м¶ңл°ңл¶„лҰ¬", "v274лҢҖкё°", "v273м¶”м Ғ", "л¬ён„ұмёө:", "м°ЁнҠёмғҒнғң:", "лҸҲ/мІҙкІ°:", "нқҗлҰ„:", "к°ҖкІ©н‘ң:"]):
                        current.append(s)
            if current:
                items.append(current)
            max_items = 1 if coin_specific else 3
            if items:
                if out:
                    out.append("")
                out.append("рҹ“Ң м••м¶• кІ°кіј")
                for block in items[:max_items]:
                    head = block[0]
                    out.append(head)
                    conclusion = [x for x in block if "кІ°лЎ :" in x]
                    reason = [x for x in block if "мқҙмң :" in x and x not in conclusion]
                    signal_bits = [x for x in block if any(k in x for k in ["v275мІҙкІ°нқҗлҰ„", "v276кі м җм§„лӢЁ", "v276мһ¬м¶ңл°ңл¶„лҰ¬", "v274лҢҖкё°", "v273м¶”м Ғ"])]
                    price_bits = [x for x in block if "к°ҖкІ©н‘ң:" in x]
                    flow_bits = [x for x in block if x.startswith("- лҸҲ/мІҙкІ°:") or x.startswith("- м°ЁнҠёмғҒнғң:")]
                    kept = []
                    for group in [conclusion, reason, signal_bits[:3], flow_bits[:2], price_bits[:1]]:
                        for x in group:
                            if x not in kept:
                                kept.append(x)
                    for x in kept[:8]:
                        out.append(x)
                    out.append("")
            else:
                out = [x for x in lines[:20] if x.strip()]
            out.append("- мғҒм„ё: /signal_full мҪ”мқёлӘ…")
            return "\n".join(out).strip()
        except Exception:
            return str(full_text or "")[:1800]

    def build_signal_text_v256(args=None, limit:int=None):
        t0 = time.time()
        args_list = list(args or []) if args is not None else []
        full = str(_FULL_BUILD_SIGNAL_TEXT_V277(args=args, limit=limit))
        coin_specific = bool(args_list)
        if coin_specific or len(full) > 2400:
            text = _v277_compact_signal_from_full(full, coin_specific=coin_specific)
            _v277_inc("signal_compact_calls", "signal м••м¶• м¶ңл Ҙ")
        else:
            text = full
        _v277_record_command("signal", text, t0)
        return text
except Exception:
    pass

