try:
    _V280_BASE_SOFT_RECOVER = soft_recover_market_refresh_state
    def soft_recover_market_refresh_state(reason: str = ""):
        try:
            r = str(reason or "")
            if ("мӢңмһҘ мәҗмӢң" in r or "1л¶„лҙү мӢңмһҘ мәҗмӢң" in r or "cache" in r.lower()):
                diag = _v280_market_cache_diagnosis(time.time())
                if diag.get("apparent") and not diag.get("true_stale"):
                    _v280_inc("soft_suppress", "н‘ңмӢңмғҒ м •мІҙ soft_recover м–өм ң")
                    now = time.time()
                    if now - safe_float(_V280_SOFT_SUPPRESS_LAST_LOG.get("ts", 0), 0) >= 120:
                        _V280_SOFT_SUPPRESS_LAST_LOG.update({"ts": now, "reason": r[:160]})
                        try:
                            append_runtime_event_log("scan_runtime_soft_recover_suppressed_v280", "н‘ңмӢңмғҒ мӢңмһҘ мәҗмӢң м •мІҙлқј soft_recover м–өм ң", extra={"reason": r, "diag": diag})
                        except Exception:
                            pass
                    return False
            _v280_inc("soft_allow", "soft_recover н—Ҳмҡ©")
        except Exception:
            pass
        return _V280_BASE_SOFT_RECOVER(reason)
except Exception:
    pass


def scan_watchdog_loop():
    global last_watchdog_cache_reset_ts
    while True:
        time.sleep(SCAN_WATCHDOG_CHECK_SEC)
        try:
            now_ts = time.time()
            if now_ts - BOT_START_TS < SCAN_WATCHDOG_STARTUP_GRACE_SEC:
                continue
            info = get_scan_runtime_health(now_ts)
            if info.get("loop_hard_stale"):
                age = info.get("loop_age")
                stage = str(info.get("stage", "?") or "?")
                if stage.startswith(("fetch_tickers", "build_universe", "build_cache")) and safe_float(age, 0) < (SCAN_HEARTBEAT_HARD_RESTART_SEC * 2):
                    continue
                print(f"[watchdog] л©”мқё лЈЁн”„ л©Ҳм¶Ө к°җм§Җ / {age}мҙҲ / stage={stage}", flush=True)
                append_runtime_error_log("watchdog_hard_stale", f"л©”мқё лЈЁн”„ л©Ҳм¶Ө / {age}мҙҲ / stage={stage}", extra={"health": info}, include_traceback=False)
                os._exit(1)
            diag = info.get("v280_market_diag") if isinstance(info.get("v280_market_diag"), dict) else _v280_market_cache_diagnosis(now_ts, base_info=info)
            if info.get("cache_hard_stale") and (now_ts - last_watchdog_cache_reset_ts >= SCAN_WATCHDOG_RESET_COOLDOWN_SEC):
                if diag.get("apparent") and not diag.get("true_stale"):
                    _v280_inc("soft_suppress", "watchdog н‘ңмӢңмғҒ м •мІҙ м–өм ң")
                    continue
                reason = f"мӢңмһҘ мәҗмӢң {info.get('cache_age')}мҙҲ м •мІҙ / stage={info.get('stage','?')} / v280={diag.get('state','?')}"
                ok = soft_recover_market_refresh_state(reason)
                if ok is not False:
                    _v280_inc("refresh_request", "watchdog refresh мҡ”мІӯ")
                    request_market_refresh(force=True, reason="watchdog_cache_soft_recover_v280")
                    last_watchdog_cache_reset_ts = now_ts
        except Exception as e:
            log_exception_details("watchdog_loop_v280", e, prefix="[watchdog мҳӨлҘҳ]")

