# - /rank_compare н•ҳлӮҳ м•Ҳм—җм„ң 1л¶„/3л¶„ м•ұмӢқ мғҒмҠ№лҘ кіј м „лһө мҲңмң„лҘј л№„көҗн•ңлӢӨ.
# - 15л¶„/30л¶„/1мӢңк°„мқҖ мӢӨм ң н‘ңліёмқҙ л¶ҖмЎұн•ҳл©ҙ 3л¶„к°’мқ„ ліөмӮ¬н•ҳм§Җ м•Ҡкі  кі„мӮ°лҢҖкё°лЎң н‘ңмӢңн•ңлӢӨ.
# ============================================================
PAPER_V281_START_TS = time.time()
PAPER_V281_STATS = {
    "build": 0, "cache_hit": 0, "rows": 0,
    "rank_1m_rows": 0, "rank_3m_rows": 0,
    "lack_15": 0, "lack_30": 0, "lack_60": 0,
    "early_both": 0, "one_min_only": 0, "repeat_top": 0,
    "sample_excluded": 0, "last_total_sec": 0.0, "last_build_sec": 0.0,
    "last_text_sec": 0.0, "last_note": "лҢҖкё°",
}
_RANK_COMPARE_V281_CACHE = {"ts": 0.0, "gen": 0, "rank_ts": 0.0, "data": None}


def _v281_inc(k, note=""):
    try:
        PAPER_V281_STATS[k] = int(safe_float(PAPER_V281_STATS.get(k, 0), 0)) + 1
        if note:
            PAPER_V281_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v281_row_change(row, key):
    try:
        row = row if isinstance(row, dict) else {}
        aliases = {
            "change_1": ["change_1", "chg_1m", "change_1m", "pct_1m", "change1", "chg1", "current_candle_change_pct"],
            "change_3": ["change_3", "chg_3m", "change_3m", "pct_3m", "change3", "chg3"],
            "change_15": ["change_15", "chg_15m", "change_15m", "pct_15m", "change15", "chg15"],
            "change_30": ["change_30", "chg_30m", "change_30m", "pct_30m", "change30", "chg30"],
            "change_60": ["change_60", "chg_60m", "change_60m", "pct_60m", "change_1h", "change60", "chg60"],
        }.get(key, [key])
        for k in aliases:
            if k in row:
                return safe_float(row.get(k, 0), 0)
        if key == "change_3":
            return safe_float(row.get("short_change", row.get("change_pct", 0)), 0)
        if key == "change_1":
            return safe_float(row.get("current_change", row.get("current_candle_pct", 0)), 0)
    except Exception:
        pass
    return 0.0


def _v281_sample_ok(row, seconds, key):
    try:
        row = row if isinstance(row, dict) else {}
        if seconds <= 180:
            val = _v281_row_change(row, key)
            return abs(val) > 1e-12, False
        sample_age = _v280_row_sample_age(row) if '_v280_row_sample_age' in globals() else None
        need = max(120.0, float(seconds) * 0.70)
        if sample_age is not None:
            if sample_age < need:
                return False, True
            return True, False
        return False, True
    except Exception:
        return False, True


def _v281_build_compare_data(force=False):
    t0 = time.time()
    try:
        gen = int(safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION", 0), 0))
        rank_ts = safe_float(globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_SNAPSHOT_TS", 0), 0)
        c = _RANK_COMPARE_V281_CACHE
        if (not force) and isinstance(c.get("data"), dict) and c.get("gen") == gen and abs(safe_float(c.get("rank_ts", 0), 0) - rank_ts) < 0.001 and time.time() - safe_float(c.get("ts", 0), 0) <= 6.0:
            _v281_inc("cache_hit", "rank_compare v281 cache hit")
            return c.get("data")
        rows = _v280_collect_rank_rows(limit=160) if '_v280_collect_rank_rows' in globals() else []
        specs = [("1л¶„", "change_1", 60), ("3л¶„", "change_3", 180), ("15л¶„", "change_15", 900), ("30л¶„", "change_30", 1800), ("1мӢңк°„", "change_60", 3600)]
        app = {}; app_counts = {}; insufficient = {}; row_by_ticker = {}
        for r in rows:
            t = _v280_row_ticker(r) if '_v280_row_ticker' in globals() else ""
            if t:
                row_by_ticker[t] = r
        for label, key, seconds in specs:
            picked = []; lack = 0
            for r in rows:
                t = _v280_row_ticker(r) if '_v280_row_ticker' in globals() else ""
                if not t:
                    continue
                ok, is_lack = _v281_sample_ok(r, seconds, key)
                if not ok:
                    if is_lack:
                        lack += 1
                    continue
                val = _v281_row_change(r, key)
                if val <= 0.0:
                    continue
                picked.append((val, _v280_row_score(r) if '_v280_row_score' in globals() else 0, _v280_row_money(r) if '_v280_row_money' in globals() else 0, t, r))
            picked.sort(key=lambda x: (x[0], x[1], x[2]), reverse=True)
            app[label] = picked[:10]
            insufficient[label] = lack
            for rank, item in enumerate(picked[:10], start=1):
                val, _, _, t, _ = item
                d = app_counts.setdefault(t, {"count": 0, "frames": [], "best_rank": 99, "best_change": -999})
                d["count"] += 1
                d["frames"].append(label)
                d["best_rank"] = min(int(d.get("best_rank", 99)), rank)
                d["best_change"] = max(safe_float(d.get("best_change", -999), -999), safe_float(val, 0))
        strategy_rows = []
        try:
            rr = globals().get("COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS", [])
            if isinstance(rr, list) and rr:
                strategy_rows = [r for r in rr if isinstance(r, dict) and (_v280_row_ticker(r) if '_v280_row_ticker' in globals() else "")][:8]
        except Exception:
            strategy_rows = []
        if not strategy_rows:
            strategy_rows = rows[:8]
        strategy = [_v280_row_ticker(r) for r in strategy_rows if (_v280_row_ticker(r) if '_v280_row_ticker' in globals() else "")]
        app_order = []
        for label, _, _ in specs:
            for item in app.get(label, [])[:8]:
                t = item[3]
                if t and t not in app_order:
                    app_order.append(t)
        overlap = [t for t in strategy if t in app_order]
        app_only = [t for t in app_order if t not in strategy]
        bot_only = [t for t in strategy if t not in app_order]
        set1 = {item[3] for item in app.get("1л¶„", [])[:10]}
        set3 = {item[3] for item in app.get("3л¶„", [])[:10]}
        early_both = [t for t in app_order if t in set1 and t in set3]
        one_min_only = [t for t in app_order if t in set1 and t not in set3]
        repeated = [t for t, info in sorted(app_counts.items(), key=lambda kv: (kv[1].get("count", 0), -kv[1].get("best_rank", 99), kv[1].get("best_change", 0)), reverse=True) if int(info.get("count", 0)) >= 2]
        sample_excluded = int(insufficient.get("15л¶„", 0) or 0) + int(insufficient.get("30л¶„", 0) or 0) + int(insufficient.get("1мӢңк°„", 0) or 0)
        data = {"rows": rows, "row_by_ticker": row_by_ticker, "app": app, "app_counts": app_counts, "insufficient": insufficient, "strategy": strategy, "strategy_rows": strategy_rows, "app_order": app_order, "overlap": overlap, "app_only": app_only, "bot_only": bot_only, "repeated": repeated, "early_both": early_both, "one_min_only": one_min_only, "sample_excluded": sample_excluded, "created_ts": time.time(), "build_sec": time.time() - t0}
        _RANK_COMPARE_V281_CACHE.update({"ts": time.time(), "gen": gen, "rank_ts": rank_ts, "data": data})
        PAPER_V281_STATS.update({"rows": len(rows), "rank_1m_rows": len(app.get("1л¶„", []) or []), "rank_3m_rows": len(app.get("3л¶„", []) or []), "lack_15": int(insufficient.get("15л¶„", 0)), "lack_30": int(insufficient.get("30л¶„", 0)), "lack_60": int(insufficient.get("1мӢңк°„", 0)), "early_both": len(early_both), "one_min_only": len(one_min_only), "repeat_top": len(repeated), "sample_excluded": sample_excluded, "last_build_sec": round(time.time() - t0, 4), "last_total_sec": round(time.time() - t0, 4)})
        try:
            PAPER_V280_STATS.update({"rank_rows": len(rows), "rank_app_rows": len(app_order), "rank_3m_rows": len(app.get("3л¶„", []) or []), "rank_lack_15": int(insufficient.get("15л¶„", 0)), "rank_lack_30": int(insufficient.get("30л¶„", 0)), "rank_lack_60": int(insufficient.get("1мӢңк°„", 0)), "rank_build_sec": round(time.time() - t0, 4)})
            PAPER_V279_STATS.update({"app_rows": len(app_order), "strategy_rows": len(strategy), "overlap": len(overlap), "app_only": len(app_only), "bot_only": len(bot_only), "repeat_top": len(repeated), "last_total_sec": round(time.time() - t0, 4)})
        except Exception:
            pass
        _v281_inc("build", f"v281 1m {len(app.get('1л¶„', []) or [])} / 3m {len(app.get('3л¶„', []) or [])}")
        return data
    except Exception as e:
        try:
            append_runtime_error_log("rank_compare_v281", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return {"rows": [], "row_by_ticker": {}, "app": {}, "app_counts": {}, "insufficient": {}, "strategy": [], "strategy_rows": [], "app_order": [], "overlap": [], "app_only": [], "bot_only": [], "repeated": [], "early_both": [], "one_min_only": [], "sample_excluded": 0, "created_ts": time.time(), "build_sec": time.time() - t0}


def _v281_format_app_item(t, info=None):
    try:
        frames = "/".join((info or {}).get("frames", [])[:5]) if isinstance(info, dict) else ""
        best = safe_float((info or {}).get("best_change", 0), 0) if isinstance(info, dict) else 0
        return f"{t} {best:+.2f}%" + (f"В·{frames}" if frames else "") if best > 0 else str(t)
    except Exception:
        return str(t)


def build_rank_compare_text_v279(args=None, top_n: int = 5):
    t0 = time.time()
    try:
        _v279_inc("compare")
    except Exception:
        pass
    data = _v281_build_compare_data(force=False)
    try:
        registered, tried = _v279_maybe_register_app_watch(data)
    except Exception:
        registered, tried = (0, 0)
    app = data.get("app") or {}; counts = data.get("app_counts") or {}; lack = data.get("insufficient") or {}
    lines = ["рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare", "- лӘ©м Ғ: м•ұмӢқ мғҒмҠ№лҘ  мҲңмң„мҷҖ мҡ°лҰ¬ лҙҮ м „лһө мҲңмң„лҘј л№„көҗн•ҙм„ң лҶ“м№Ёмқ„ м°ҫлҠ” мҡ©лҸ„", "- 1л¶„мқҖ мҙҲмһ… к°җм§Җмҡ©. л°”лЎң л§ӨмҲҳ/paper л“ұлЎқ м•„лӢҳ", f"- кё°мӨҖ: м ҖмһҘ мҠӨлғ…мғ· / мғқм„ұ {format_elapsed_text(time.time()-safe_float(data.get('created_ts',time.time()),time.time()))} м „ / мҶҢмҡ” {safe_float(data.get('build_sec',0),0):.3f}s", "", "[м•ұмӢқ мғҒмҠ№лҘ  TOP]"]
    for label in ["1л¶„", "3л¶„", "15л¶„", "30л¶„", "1мӢңк°„"]:
        bits = []
        for val, score, money, t, row in list(app.get(label) or [])[:max(1, int(top_n))]:
            item = f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money, 0) >= 100_000_000:
                try:
                    item += f"В·{format_money_compact_amount_krw(money)}"
                except Exception:
                    pass
            bits.append(item)
        lack_n = int(safe_float(lack.get(label, 0), 0))
        if label in {"15л¶„", "30л¶„", "1мӢңк°„"} and not bits and lack_n:
            lines.append(f"- {label}: н‘ңліёл¶ҖмЎұ / кі„мӮ° лҢҖкё° ({lack_n}к°ң)")
            continue
        suffix = f" / н‘ңліёл¶ҖмЎұ {lack_n}к°ң" if lack_n and label in {"15л¶„", "30л¶„", "1мӢңк°„"} else ""
        empty = "кі„мӮ° к°ҖлҠҘн•ң мғҒмҠ№ м—ҶмқҢ" if label in {"1л¶„", "3л¶„"} else "мғҒмҠ№ м—ҶмқҢ"
        lines.append(f"- {label}: " + (_v279_join(bits, limit=top_n, empty=empty) + suffix))
    strategy = data.get("strategy") or []
    overlap = data.get("overlap") or []; app_only = data.get("app_only") or []; bot_only = data.get("bot_only") or []
    repeated = data.get("repeated") or []; early_both = data.get("early_both") or []; one_min_only = data.get("one_min_only") or []
    app_only_fmt = [_v281_format_app_item(t, counts.get(t)) for t in app_only]
    repeated_fmt = [_v281_format_app_item(t, counts.get(t)) for t in repeated]
    early_fmt = [_v281_format_app_item(t, counts.get(t)) for t in early_both]
    one_min_fmt = [_v281_format_app_item(t, counts.get(t)) for t in one_min_only]
    lines += ["", "[мҙҲмһ… нӣ„ліҙ]", "- 1л¶„+3л¶„ лҸҷмӢң: " + _v279_join(early_fmt, limit=8, empty="м—ҶмқҢ"), "- 1л¶„л§Ң кёүл“ұ: " + _v279_join(one_min_fmt, limit=8, empty="м—ҶмқҢ") + (" / 3л¶„ мң м§Җ нҷ•мқё н•„мҡ”" if one_min_only else ""), "", "[мҡ°лҰ¬ лҙҮ м „лһө мҲңмң„ TOP]", "- " + _v279_join(strategy, limit=8, empty="м—ҶмқҢ"), "", "[л№„көҗ кІ°кіј]", "- кІ№м№Ё: " + _v279_join(overlap, limit=8, empty="м—ҶмқҢ"), "- м•ұмӢқ only лҶ“м№Ёнӣ„ліҙ: " + _v279_join(app_only_fmt, limit=10, empty="м—ҶмқҢ"), "- лҙҮ only лӢЁлҸ…нӣ„ліҙ: " + _v279_join(bot_only, limit=10, empty="м—ҶмқҢ"), "- м•ұмӢқ л°ҳліөмғҒмң„: " + _v279_join(repeated_fmt, limit=8, empty="м—ҶмқҢ"), f"- н‘ңліёл¶ҖмЎұ м ңмҷё: {int(safe_float(data.get('sample_excluded',0),0))}кұҙ / лӮҙл¶Җк°җмӢң л“ұлЎқ: {registered}/{tried}", "", "[нҢҗлӢЁлІ•]", "- 1л¶„л§Ң нҠ„ нӣ„ліҙлҠ” л°ҳм§қ к°ҖлҠҘм„ұ мһҲмқҢ. 3л¶„ мң м§ҖмҷҖ мІҙкІ°мқ„ к°ҷмқҙ нҷ•мқё", "- кІ№м№Ё нӣ„ліҙлҠ” мҡ°м„  кІҖнҶ , м•ұмӢқ onlyлҠ” лҶ“м№Ё нӣ„ліҙ мӣҗмқё нҷ•мқё"]
    sec = time.time() - t0
    try:
        PAPER_V279_STATS["last_total_sec"] = round(sec, 4)
        PAPER_V281_STATS["last_text_sec"] = round(sec, 4)
        PAPER_V281_STATS["last_total_sec"] = round(sec, 4)
    except Exception:
        pass
    return "\n".join(lines).strip()


