def _v283_format_app_item(t, info=None):
    try:
        frames = "/".join((info or {}).get("frames", [])[:5]) if isinstance(info, dict) else ""
        best = safe_float((info or {}).get("best_change", 0), 0) if isinstance(info, dict) else 0
        row = (info or {}).get("row", {}) if isinstance(info, dict) else {}
        src_txt = "В·мІҙкІ°ліҙмҷ„" if str(row.get("latest_price_source", "")) == "ws_trade" else ""
        return f"{t} {best:+.2f}%" + (f"В·{frames}" if frames else "") + src_txt if best > 0 else str(t)
    except Exception:
        return str(t)


def _v283_join(items, limit=8, empty="м—ҶмқҢ"):
    return _v282_join(items, limit=limit, empty=empty) if '_v282_join' in globals() else (", ".join(list(items or [])[:limit]) if items else empty)


def build_rank_compare_text_v279(args=None, top_n: int = 10):
    t0=time.time(); _v283_inc("compare")
    data=_v283_build_compare_data(force=False)
    app=data.get("app") or {}; counts=data.get("app_counts") or {}; lack=data.get("insufficient") or {}
    lines=["рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare", "- мҶҢмҠӨ: лҙҮ кі„мӮ° м•ұмӢқ мғҒмҠ№лҘ  мҲңмң„", "- л№—мҚё м•ұ мӣҗліё лһӯнӮ№ м•„лӢҳ. кіөмӢқ нҳ„мһ¬к°Җ/мІҙкІ°/мҠӨлғ…мғ·мңјлЎң мөңлҢҖн•ң л№„мҠ·н•ҳкІҢ л§Ңл“  мң мӮ¬ мҲңмң„", "- 1л¶„мқҖ мҙҲмһ… к°җм§Җмҡ©. л°”лЎң л§ӨмҲҳ/paper л“ұлЎқ м•„лӢҳ", f"- кё°мӨҖ: м „мІҙ light snapshot + WS нҳ„мһ¬к°Җ/мІҙкІ° ліҙмҷ„ / мғқм„ұ {format_elapsed_text(time.time()-safe_float(data.get('created_ts', time.time()), time.time()))} м „ / мҶҢмҡ” {safe_float(data.get('build_sec',0),0):.3f}s", "", "[лҙҮ кі„мӮ° мғҒмҠ№лҘ  TOP]"]
    for label in ["1л¶„","3л¶„","15л¶„","30л¶„","1мӢңк°„"]:
        bits=[]
        for val, _score, money, t, row in list(app.get(label) or [])[:max(1,int(top_n))]:
            item=f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money,0) >= 100_000_000:
                try: item += f"В·{format_money_compact_amount_krw(money)}"
                except Exception: pass
            if str(row.get("latest_price_source", "")) == "ws_trade": item += "В·мІҙкІ°к°Җліҙмҷ„"
            if label in {"1л¶„","3л¶„"}:
                age=safe_float(row.get(f"change_{'1' if label=='1л¶„' else '3'}_base_age_sec",0),0)
                if age>0: item += f"В·кё°мӨҖ{age:.0f}s"
            bits.append(item)
        lack_n=int(safe_float(lack.get(label,0),0))
        if label in {"15л¶„","30л¶„","1мӢңк°„"} and not bits and lack_n:
            lines.append(f"- {label}: н‘ңліёл¶ҖмЎұ / кі„мӮ° лҢҖкё° ({lack_n}к°ң)"); continue
        suffix=f" / кё°мӨҖк°Җл¶ҖмЎұ {lack_n}к°ң" if lack_n and label in {"1л¶„","3л¶„"} else (f" / н‘ңліёл¶ҖмЎұ {lack_n}к°ң" if lack_n and label in {"15л¶„","30л¶„","1мӢңк°„"} else "")
        lines.append(f"- {label}: " + (_v283_join(bits, limit=top_n, empty="кі„мӮ° к°ҖлҠҘн•ң мғҒмҠ№ м—ҶмқҢ") + suffix))
    low_bits=[]
    for val, _score, money, t, row in list(data.get("low_liquidity_rows") or [])[:6]:
        low_bits.append(f"{t} {safe_float(val,0):+.2f}%В·лҸҲ/мІҙкІ°м•Ҫн•Ё")
    if low_bits:
        lines += ["", "[м Җмң лҸҷм„ұ/мІҙкІ°м•Ҫн•Ё кёүл“ұ]", "- " + _v283_join(low_bits, limit=6)]
    strategy=data.get("strategy") or []; overlap=data.get("overlap") or []; app_only=data.get("app_only") or []; bot_only=data.get("bot_only") or []; repeated=data.get("repeated") or []; early_both=data.get("early_both") or []; one_min_only=data.get("one_min_only") or []
    lines += ["", "[мҙҲмһ… нӣ„ліҙ]", "- 1л¶„+3л¶„ лҸҷмӢң: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in early_both], limit=10, empty="м—ҶмқҢ"), "- 1л¶„л§Ң кёүл“ұ: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in one_min_only], limit=10, empty="м—ҶмқҢ") + (" / 3л¶„ мң м§Җ нҷ•мқё н•„мҡ”" if one_min_only else ""), "", "[мҡ°лҰ¬ лҙҮ м „лһө мҲңмң„ TOP]", "- " + _v283_join(strategy, limit=8, empty="м—ҶмқҢ"), "", "[л№„көҗ кІ°кіј]", "- кІ№м№Ё: " + _v283_join(overlap, limit=8, empty="м—ҶмқҢ"), "- м•ұмӢқ only лҶ“м№Ёнӣ„ліҙ: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in app_only], limit=12, empty="м—ҶмқҢ"), "- лҙҮ only лӢЁлҸ…нӣ„ліҙ: " + _v283_join(bot_only, limit=10, empty="м—ҶмқҢ"), "- л°ҳліөмғҒмң„: " + _v283_join([_v283_format_app_item(t, counts.get(t)) for t in repeated], limit=10, empty="м—ҶмқҢ"), f"- м „мІҙ нһҲмҠӨнҶ лҰ¬: {PAPER_V283_STATS.get('history_fresh',0)}/{PAPER_V283_STATS.get('history_total',0)}к°ң / мІҙкІ°к°Җліҙмҷ„ {PAPER_V283_STATS.get('trade_price_boost',0)} / м Җмң лҸҷм„ұл¶„лҰ¬ {PAPER_V283_STATS.get('low_liquidity',0)}", "", "[нҢҗлӢЁлІ•]", "- м•ұмӢқ onlyлҠ” м „мІҙ мӢңмһҘм—җм„ңлҠ” нҠҖлҠ”лҚ° м „лһө нӣ„ліҙм—җлҠ” м•Ҫн•ң лҶ“м№Ё кІҖмҰқ нӣ„ліҙ", "- л№—мҚё м•ұ мӣҗліёмқҙ м•„лӢҲлқј лҙҮ кі„мӮ° мң мӮ¬ мҲңмң„м•ј. м•ұ мҠӨмғ·кіј м°Ёмқҙк°Җ лӮҳл©ҙ кё°мӨҖк°Җ/мөңмӢ к°Җ/нӢ°м»ӨлӘ…мқ„ к°ҷмқҙ ліёлӢӨ."]
    PAPER_V283_STATS["last_text_sec"]=round(time.time()-t0,4); PAPER_V283_STATS["last_total_sec"]=round(time.time()-t0,4)
    return "\n".join(lines).strip()


