def _v284_inc(k, note=""):
    try:
        PAPER_V284_STATS[k] = int(safe_float(PAPER_V284_STATS.get(k, 0), 0)) + 1
        if note:
            PAPER_V284_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v284_norm(ticker):
    try:
        return _v283_key(ticker) if '_v283_key' in globals() else str(ticker or '').upper().replace('KRW-','').strip()
    except Exception:
        return str(ticker or '').upper().replace('KRW-','').strip()


def _v284_money(row):
    try:
        if '_v282_money' in globals():
            return safe_float(_v282_money(row), 0)
    except Exception:
        pass
    try:
        vals=[]
        for k in ('turnover_5m','turnover','acc_trade_value_24H','acc_trade_value','trade_amount_60s','money'):
            vals.append(safe_float((row or {}).get(k,0),0))
        return max(vals or [0.0])
    except Exception:
        return 0.0


def _v284_strategy_score(row):
    try:
        if '_v282_strategy_score' in globals():
            return safe_float(_v282_strategy_score(row), 0)
    except Exception:
        pass
    try:
        return safe_float((row or {}).get('score', (row or {}).get('snapshot_rank_score',0)),0)
    except Exception:
        return 0.0


def _v284_get_latest_rank_rows():
    rows=[]
    try:
        raw = globals().get('COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS', [])
        if isinstance(raw, list):
            rows += [dict(r) for r in raw if isinstance(r, dict)]
    except Exception:
        pass
    try:
        more = _v282_get_strategy_rows() if '_v282_get_strategy_rows' in globals() else []
        if isinstance(more, list):
            seen={_v284_norm(r.get('ticker')) for r in rows if isinstance(r,dict)}
            for r in more:
                if not isinstance(r, dict):
                    continue
                t=_v284_norm(r.get('ticker'))
                if t and t not in seen:
                    rows.append(dict(r)); seen.add(t)
    except Exception:
        pass
    return rows


def _v284_snapshot3m_items(existing_tickers=None):
    """rank_shortк°Җ мқҙлҜё ліҙм—¬мЈјлҠ” 3m к°’кіј rank_compare 3mк°Җ л№„лҠ” л¶Ҳмқјм№ҳ ліҙм •мҡ©."""
    existing=set([_v284_norm(x) for x in (existing_tickers or []) if _v284_norm(x)])
    out=[]
    try:
        for r in _v284_get_latest_rank_rows():
            t=_v284_norm(r.get('ticker'))
            if not t or t in existing or t=='BTC':
                continue
            ch3=safe_float(r.get('change_3', r.get('chg_3m', r.get('short_change',0))),0)
            if ch3 <= 0:
                continue
            money=_v284_money(r)
            row=dict(r)
            row.update({
                'ticker': t,
                'change_3': ch3,
                'change_3_ready': True,
                'change_3_base_age_sec': safe_float(r.get('change_3_base_age_sec', 180), 180) or 180,
                'latest_price_source': str(r.get('latest_price_source', r.get('source','rank_snapshot3m')) or 'rank_snapshot3m'),
                'turnover': money,
                'turnover_5m': money,
                'cache_source': 'snapshot3m_fallback_v284',
                'snapshot3m_fallback': True,
            })
            out.append((ch3, _v284_strategy_score(r), money, t, row))
    except Exception:
        pass
    out.sort(key=lambda x:(x[0], x[2], x[1]), reverse=True)
    return out[:10]


def _v284_row_by_ticker_from_data(data):
    try:
        d = data.get('row_by_ticker') if isinstance(data, dict) else None
        if isinstance(d, dict):
            return d
    except Exception:
        pass
    return {}


def _v284_build_compare_data(force=False):
    t0=time.time()
    try:
        c=_RANK_COMPARE_V284_CACHE
        data=c.get('data') if isinstance(c.get('data'), dict) else None
        if (not force) and isinstance(data, dict) and time.time()-safe_float(c.get('ts',0),0) <= RANK_COMPARE_V284_CACHE_TTL_SEC:
            # data мһҗмІҙк°Җ мҳӨлһҳлҗҗмңјл©ҙ cache hit кёҲм§Җ. v283мқҳ 5л¶„ stale мһ¬мӮ¬мҡ©мқ„ м°ЁлӢЁн•ңлӢӨ.
            if time.time()-safe_float(data.get('created_ts',0),0) <= RANK_COMPARE_V284_STALE_WARN_SEC:
                _v284_inc('cache_hit','v284 cache hit')
                return data
            _v284_inc('stale_block','old rank_compare cache ignored')
        _v284_inc('build','v284 rank_compare build')
        # v283мқҳ м „мІҙ нһҲмҠӨнҶ лҰ¬ кі„мӮ°мқҖ мһ¬мӮ¬мҡ©н•ҳлҗҳ forceлЎң мәҗмӢңлҘј л¬ҙмӢңн•ңлӢӨ.
        if '_v283_build_compare_data' in globals():
            base=_v283_build_compare_data(force=True)
        else:
            base={}
        if not isinstance(base, dict):
            base={}
        rows=list(base.get('rows') or [])
        app=dict(base.get('app') or {})
        counts=dict(base.get('app_counts') or {})
        lack=dict(base.get('insufficient') or {})
        strategy=list(base.get('strategy') or [])
        strategy_rows=list(base.get('strategy_rows') or [])
        row_by=dict(base.get('row_by_ticker') or {})
        # 3л¶„ fallback: нһҲмҠӨнҶ лҰ¬ кё°л°ҳ 3л¶„мқҙ л№„кұ°лӮҳ м Ғмқ„ л•Ң rank_short snapshotмқҳ 3mлҘј ліҙмЎ°лЎң м“ҙлӢӨ.
        existing3={item[3] for item in list(app.get('3л¶„') or []) if len(item)>=4}
        fallback3=[]
        if len(existing3) < 5:
            fallback3=_v284_snapshot3m_items(existing_tickers=existing3)
            if fallback3:
                merged=list(app.get('3л¶„') or []) + fallback3
                merged.sort(key=lambda x:(x[0],x[2],x[1]), reverse=True)
                app['3л¶„']=merged[:10]
                for _val,_score,_money,t,row in fallback3:
                    row_by[t]=row
                    info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                    if '3л¶„' not in info.get('frames',[]):
                        info['count']=int(safe_float(info.get('count',0),0))+1
                        info.setdefault('frames',[]).append('3л¶„')
                    info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(_val,0))
                    info['row']=row
                lack['3л¶„']=max(0, int(safe_float(lack.get('3л¶„',0),0))-len(fallback3))
        # app_order мһ¬кө¬м„ұ
        app_order=[]
        for label in ['1л¶„','3л¶„','15л¶„','30л¶„','1мӢңк°„']:
            for item in list(app.get(label) or [])[:8]:
                try: t=item[3]
                except Exception: continue
                if t and t not in app_order:
                    app_order.append(t)
        if not strategy:
            strategy=[_v284_norm(r.get('ticker')) for r in _v284_get_latest_rank_rows()[:8] if _v284_norm(r.get('ticker'))]
        overlap=[t for t in strategy if t in app_order]
        app_only=[t for t in app_order if t not in strategy]
        bot_only=[t for t in strategy if t not in app_order]
        set1={item[3] for item in list(app.get('1л¶„') or [])[:10] if len(item)>=4}
        set3={item[3] for item in list(app.get('3л¶„') or [])[:10] if len(item)>=4}
        early_both=[t for t in app_order if t in set1 and t in set3]
        one_min_only=[t for t in app_order if t in set1 and t not in set3]
        repeated=[t for t,info in sorted(counts.items(), key=lambda kv:(int(safe_float(kv[1].get('count',0),0)), -int(safe_float(kv[1].get('best_rank',99),99)), safe_float(kv[1].get('best_change',0),0)), reverse=True) if int(safe_float(info.get('count',0),0))>=2]
        created=time.time()
        out=dict(base)
        out.update({'app':app,'app_counts':counts,'insufficient':lack,'strategy':strategy,'strategy_rows':strategy_rows,'app_order':app_order,'overlap':overlap,'app_only':app_only,'bot_only':bot_only,'early_both':early_both,'one_min_only':one_min_only,'repeated':repeated,'row_by_ticker':row_by,'created_ts':created,'build_sec':round(time.time()-t0,4),'source':'bot_calc_app_rank_v284','fallback3_count':len(fallback3),'stale_fixed':True})
        _RANK_COMPARE_V284_CACHE.update({'ts':time.time(),'data':out})
        # statsлҠ” global PAPER_V283мқҙ м•„лӢҲлқј data кё°мӨҖмңјлЎңлҸ„ ліҙм •
        PAPER_V284_STATS.update({
            'history_rows': len(rows), 'rank_rows': len(_v284_get_latest_rank_rows()), 'snapshot3m_rows': len(fallback3),
            'app_1m': len(app.get('1л¶„') or []), 'app_3m': len(app.get('3л¶„') or []), 'fallback_3m': len(fallback3),
            'base_lack_3m': int(safe_float(lack.get('3л¶„',0),0)),
            'overlap': len(overlap), 'app_only': len(app_only), 'bot_only': len(bot_only), 'repeat': len(repeated),
            'last_build_sec': round(time.time()-t0,4), 'last_total_sec': round(time.time()-t0,4), 'last_note': 'v284 мөңмӢ  rank_compare мғқм„ұ',
        })
        return out
    except Exception as e:
        try: append_runtime_error_log('rank_compare_v284', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {'app':{},'app_counts':{},'insufficient':{},'strategy':[],'overlap':[],'app_only':[],'bot_only':[],'early_both':[],'one_min_only':[],'repeated':[],'row_by_ticker':{},'rows':[],'created_ts':time.time(),'build_sec':round(time.time()-t0,4),'source':'error'}


def _v284_join(items, limit=10, empty='м—ҶмқҢ'):
    try:
        items=[str(x) for x in list(items or []) if str(x).strip()]
        if not items: return empty
        extra=max(0,len(items)-limit)
        shown=items[:limit]
        return ', '.join(shown)+(f' мҷё {extra}к°ң' if extra else '')
    except Exception:
        return empty


def _v284_format_app_item(ticker, info):
    try:
        if '_v283_format_app_item' in globals():
            return _v283_format_app_item(ticker, info)
    except Exception:
        pass
    try:
        frames='/'.join(list((info or {}).get('frames') or [])[:4])
        best=safe_float((info or {}).get('best_change',0),0)
        return f'{ticker} {best:+.2f}%В·{frames}' if frames else str(ticker)
    except Exception:
        return str(ticker)


def build_rank_compare_text_v279(args=None, top_n:int=10):
    t0=time.time()
    data=_v284_build_compare_data(force=False)
    app=data.get('app') or {}; counts=data.get('app_counts') or {}; lack=data.get('insufficient') or {}
    created_age=max(0.0, time.time()-safe_float(data.get('created_ts',time.time()),time.time()))
    stale_msg=''
    if created_age > RANK_COMPARE_V284_STALE_WARN_SEC:
        stale_msg=' / вҡ пёҸ мҳӨлһҳлҗң л№„көҗкІ°кіј'
    lines=[
        'рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare',
        '- мҶҢмҠӨ: лҙҮ кі„мӮ° м•ұмӢқ мғҒмҠ№лҘ  мҲңмң„',
        '- л№—мҚё м•ұ мӣҗліё лһӯнӮ№ м•„лӢҳ. кіөмӢқ нҳ„мһ¬к°Җ/мІҙкІ°/мҠӨлғ…мғ·мңјлЎң мөңлҢҖн•ң л№„мҠ·н•ҳкІҢ л§Ңл“  мң мӮ¬ мҲңмң„',
        '- 1л¶„мқҖ мҙҲмһ… к°җм§Җмҡ©. л°”лЎң л§ӨмҲҳ/paper л“ұлЎқ м•„лӢҳ',
        f"- кё°мӨҖ: мөңмӢ  лӮҙл¶Җ мҠӨлғ…мғ· + WS/мІҙкІ°/bulk ліҙмҷ„ / мғқм„ұ {format_elapsed_text(created_age)} м „ / мҶҢмҡ” {safe_float(data.get('build_sec',0),0):.3f}s{stale_msg}",
        '', '[лҙҮ кі„мӮ° мғҒмҠ№лҘ  TOP]'
    ]
    for label in ['1л¶„','3л¶„','15л¶„','30л¶„','1мӢңк°„']:
        bits=[]
        for val,_score,money,t,row in list(app.get(label) or [])[:max(1,int(top_n))]:
            item=f'{t} {safe_float(val,0):+.2f}%'
            try:
                if safe_float(money,0)>=100_000_000:
                    item += f'В·{format_money_compact_amount_krw(money)}'
            except Exception: pass
            if bool((row or {}).get('snapshot3m_fallback')) and label=='3л¶„':
                item += 'В·snapshot3m'
            elif str((row or {}).get('latest_price_source',''))=='ws_trade':
                item += 'В·мІҙкІ°к°Җліҙмҷ„'
            if label in {'1л¶„','3л¶„'}:
                key='1' if label=='1л¶„' else '3'
                age=safe_float((row or {}).get(f'change_{key}_base_age_sec',0),0)
                if age>0:
                    item += f'В·кё°мӨҖ{age:.0f}s'
            bits.append(item)
        lack_n=int(safe_float(lack.get(label,0),0))
        if label in {'15л¶„','30л¶„','1мӢңк°„'} and not bits:
            lines.append(f'- {label}: н‘ңліёл¶ҖмЎұ / кі„мӮ° лҢҖкё° ({lack_n}к°ң)' if lack_n else f'- {label}: кі„мӮ° к°ҖлҠҘн•ң мғҒмҠ№ м—ҶмқҢ')
        else:
            suffix=''
            if lack_n and label in {'1л¶„','3л¶„'}:
                suffix=f' / кё°мӨҖк°Җл¶ҖмЎұ {lack_n}к°ң'
            lines.append(f'- {label}: '+_v284_join(bits, limit=top_n, empty='кі„мӮ° к°ҖлҠҘн•ң мғҒмҠ№ м—ҶмқҢ')+suffix)
    early=data.get('early_both') or []; one=data.get('one_min_only') or []
    strategy=data.get('strategy') or []; overlap=data.get('overlap') or []; app_only=data.get('app_only') or []; bot_only=data.get('bot_only') or []; repeated=data.get('repeated') or []
    # м Җмң лҸҷм„ұмқҖ v283 dataк°Җ мһҲмңјл©ҙ мң м§Җ
    low_bits=[]
    for item in list(data.get('low_liquidity_rows') or [])[:6]:
        try: val,_s,_m,t,row=item; low_bits.append(f'{t} {safe_float(val,0):+.2f}%В·лҸҲ/мІҙкІ°м•Ҫн•Ё')
        except Exception: pass
    if low_bits:
        lines += ['', '[м Җмң лҸҷм„ұ/мІҙкІ°м•Ҫн•Ё кёүл“ұ]', '- '+_v284_join(low_bits, limit=6)]
    lines += [
        '', '[мҙҲмһ… нӣ„ліҙ]',
        '- 1л¶„+3л¶„ лҸҷмӢң: '+_v284_join([_v284_format_app_item(t, counts.get(t)) for t in early], limit=10),
        '- 1л¶„л§Ң кёүл“ұ: '+_v284_join([_v284_format_app_item(t, counts.get(t)) for t in one], limit=10)+(' / 3л¶„ мң м§Җ нҷ•мқё н•„мҡ”' if one else ''),
        '', '[мҡ°лҰ¬ лҙҮ м „лһө мҲңмң„ TOP]', '- '+_v284_join(strategy, limit=8),
        '', '[л№„көҗ кІ°кіј]',
        '- кІ№м№Ё: '+_v284_join(overlap, limit=8),
        '- м•ұмӢқ only лҶ“м№Ёнӣ„ліҙ: '+_v284_join([_v284_format_app_item(t, counts.get(t)) for t in app_only], limit=12),
        '- лҙҮ only лӢЁлҸ…нӣ„ліҙ: '+_v284_join(bot_only, limit=10),
        '- л°ҳліөмғҒмң„: '+_v284_join([_v284_format_app_item(t, counts.get(t)) for t in repeated], limit=10),
        f"- м „мІҙ нһҲмҠӨнҶ лҰ¬ rows {len(data.get('rows') or [])} / rank snapshot 3m ліҙмҷ„ {int(safe_float(data.get('fallback3_count',0),0))}к°ң",
        '- лӮҙл¶Җк°җмӢң: мқҙ лӘ…л №мқҖ мқҪкё°м „мҡ©. м•ұмӢқ onlyлҠ” н‘ёмӢң/paper мһҗлҸҷл“ұлЎқ м•Ҳ н•Ё',
        '', '[нҢҗлӢЁлІ•]',
        '- м•ұмӢқ onlyлҠ” м „мІҙ мӢңмһҘм—җм„ңлҠ” нҠҖлҠ”лҚ° м „лһө нӣ„ліҙм—җлҠ” м•Ҫн•ң лҶ“м№Ё кІҖмҰқ нӣ„ліҙ',
        '- snapshot3mмқҖ м „мІҙ нһҲмҠӨнҶ лҰ¬ 3л¶„ кё°мӨҖк°Җ л¶ҖмЎұ мӢң rank_short 3л¶„к°’мңјлЎң ліҙмҷ„н•ң н‘ңмӢңм•ј.',
    ]
    PAPER_V284_STATS['last_text_sec']=round(time.time()-t0,4); PAPER_V284_STATS['last_total_sec']=round(time.time()-t0,4)
    return '\n'.join(lines).strip()

