def _v283_app_signal_note(ticker):
    try:
        raw=str(ticker or '').strip(); t=_v284_norm(raw)
        data=_v284_build_compare_data(force=False)
        row=(data.get('row_by_ticker') or {}).get(t)
        info=(data.get('app_counts') or {}).get(t)
        if isinstance(info, dict):
            PAPER_V284_STATS['signal_hint']=int(safe_float(PAPER_V284_STATS.get('signal_hint',0),0))+1
            frames='/'.join(info.get('frames',[])[:5]); best=safe_float(info.get('best_change',0),0)
            alias=f' / {raw}вҶ’{t}' if raw and raw.upper()!=t else ''
            return f'- л§ӨмҲҳ нӣ„ліҙм—җлҠ” м—ҶмқҢ / лҙҮкі„мӮ° м•ұмӢқмҲңмң„{alias}: {frames or "мғҒмң„к¶Ң"} / мөңкі  {best:+.2f}% / л§ӨмҲҳмӢ нҳё м•„лӢҳ'
        if isinstance(row, dict):
            c1=safe_float(row.get('change_1',0),0); c3=safe_float(row.get('change_3',0),0)
            r1='к°ҖлҠҘ' if row.get('change_1_ready') else 'кё°мӨҖк°Җл¶ҖмЎұ'; r3='к°ҖлҠҘ' if row.get('change_3_ready') else ('snapshot3m' if row.get('snapshot3m_fallback') else 'кё°мӨҖк°Җл¶ҖмЎұ')
            src=str(row.get('latest_price_source','') or row.get('cache_source',''))
            price=safe_float(row.get('current_price', row.get('price',0)),0)
            price_txt=f' / ліҙмҷ„нҳ„мһ¬к°Җ {price:g}' if price>0 else ''
            return f'- л§ӨмҲҳ нӣ„ліҙм—җлҠ” м—ҶмқҢ / м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬ мһҲмқҢ: 1л¶„ {c1:+.2f}%({r1}) / 3л¶„ {c3:+.2f}%({r3}) / мөңмӢ к°Җ {src}{price_txt} / л§ӨмҲҳмӢ нҳё м•„лӢҳ'
        return '- л§ӨмҲҳ нӣ„ліҙм—җлҠ” м—ҶмқҢ / м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҸ„ мөңк·ј н‘ңліё м—ҶмқҢ / нӢ°м»ӨлӘ… лҳҗлҠ” мғҒмһҘлӘ… нҷ•мқё н•„мҡ”'
    except Exception:
        return ''

try:
    _V284_BASE_BUILD_SIGNAL_TEXT = build_signal_text_v256
    def build_signal_text_v256(args=None, limit:int=None):
        args_list=list(args or []) if args is not None else []
        raw=str(args_list[0]) if args_list else ''
        text=str(_V284_BASE_BUILD_SIGNAL_TEXT(args=args, limit=limit))
        try:
            if raw:
                note=_v283_app_signal_note(raw)
                if note and note not in text:
                    lines=text.splitlines(); insert_at=len(lines)
                    for i,l in enumerate(lines):
                        if 'нӣ„ліҙ нҷ•мқё' in l or 'мғҒм„ё:' in l:
                            insert_at=i; break
                    lines.insert(insert_at, note)
                    text='\n'.join(lines).strip()
            # signal row нҳ„мһ¬к°Җ 0 ліҙмҷ„ н‘ңмӢң. кё°мЎҙ к°ҖкІ©н‘ң мһҗмІҙлҠ” ліҙмҲҳм ҒмңјлЎң л‘җкі , ліҙмҷ„ нҳ„мһ¬к°ҖлҘј лі„лҸ„ мӨ„лЎң л„ЈлҠ”лӢӨ.
            if 'нҳ„мһ¬ 0.000000' in text and raw:
                data=_v284_build_compare_data(force=False); row=(data.get('row_by_ticker') or {}).get(_v284_norm(raw))
                p=safe_float((row or {}).get('current_price',(row or {}).get('price',0)),0)
                src=str((row or {}).get('latest_price_source','') or '')
                if p>0 and f'к°ҖкІ©ліҙмҷ„ нҳ„мһ¬к°Җ' not in text:
                    PAPER_V284_STATS['signal_price_fix']=int(safe_float(PAPER_V284_STATS.get('signal_price_fix',0),0))+1
                    text=text.replace('нҳ„мһ¬ 0.000000', f'нҳ„мһ¬ 0.000000 / к°ҖкІ©ліҙмҷ„ нҳ„мһ¬к°Җ {p:g}({src})')
        except Exception:
            pass
        return text
except Exception:
    pass

try:
    _V284_BASE_CACHE_STATUS = build_cache_status_text
    def build_cache_status_text():
        base=str(_V284_BASE_CACHE_STATUS())
        try:
            extra=['', 'рҹӣ  v2.5.284 rank_compare мөңмӢ нҷ”/3л¶„ ліҙмҷ„',
                   f"- build {PAPER_V284_STATS.get('build',0)} / cache_hit {PAPER_V284_STATS.get('cache_hit',0)} / staleм°ЁлӢЁ {PAPER_V284_STATS.get('stale_block',0)}",
                   f"- rows history {PAPER_V284_STATS.get('history_rows',0)} / rank {PAPER_V284_STATS.get('rank_rows',0)} / snapshot3mліҙмҷ„ {PAPER_V284_STATS.get('snapshot3m_rows',0)}",
                   f"- м•ұмӢқ 1m {PAPER_V284_STATS.get('app_1m',0)} / 3m {PAPER_V284_STATS.get('app_3m',0)} / 3mкё°мӨҖл¶ҖмЎұ {PAPER_V284_STATS.get('base_lack_3m',0)}",
                   f"- л№„көҗ кІ№м№Ё {PAPER_V284_STATS.get('overlap',0)} / м•ұonly {PAPER_V284_STATS.get('app_only',0)} / лҙҮonly {PAPER_V284_STATS.get('bot_only',0)} / л°ҳліө {PAPER_V284_STATS.get('repeat',0)}",
                   f"- signal к°ҖкІ©ліҙмҷ„ {PAPER_V284_STATS.get('signal_price_fix',0)} / м•ұнһҢнҠё {PAPER_V284_STATS.get('signal_hint',0)} / мөңк·ј {PAPER_V284_STATS.get('last_note','-')}",
                   '- мү¬мҡҙ лң»: rank_compare мҳӨлһҳлҗң кІ°кіј мһ¬мӮ¬мҡ©мқ„ л§үкі , 3л¶„мқҖ rank_short мҠӨлғ…мғ·мңјлЎң ліҙмҷ„н•ңлӢӨ.']
            return base.rstrip()+'\n'+'\n'.join(extra)
        except Exception:
            return base
except Exception:
    pass

try:
    _V284_BASE_STARTUP = build_startup_notice_text
    def build_startup_notice_text():
        s=str(_V284_BASE_STARTUP())
        s=s.replace('v2.5.283','v2.5.284')
        s=s.replace('лҙҮкі„мӮ° м•ұмӢқ лһӯнҒ¬ м •нҷ•лҸ„/нӢ°м»ӨнһҢнҠё ліҙм •','rank_compare мөңмӢ нҷ”/3л¶„ліҙмҷ„/signalк°ҖкІ©ліҙмҷ„')
        return s
except Exception:
    pass


# ============================================================
# v2.5.285 - rank_compare кёҙкёү м•Ҳм •нҷ”
# - v284 ліҙм • лё”лЎқмқҙ main() м•„лһҳм—җ л¶ҷм–ҙ мӢӨм ң мӢӨн–үлҗҳм§Җ м•ҠлҚҳ л¬ём ңлҘј м •лҰ¬н•ңлӢӨ.
# - /rank_compareлҠ” мһ¬к·Җ/мһҘмӢңк°„ л№Ңл“ң м—Ҷмқҙ мөңмӢ  лӮҙл¶Җ мҠӨлғ…мғ·мңјлЎң л№ лҘҙкІҢ л§Ңл“ лӢӨ.
# - 3л¶„мқҖ м „мІҙ нһҲмҠӨнҶ лҰ¬к°Җ л¶ҖмЎұн•ҳл©ҙ rank_short snapshot3mмңјлЎң ліҙмҷ„н•ңлӢӨ.
# - мҳӨлһҳлҗң rank_compare кІ°кіјлҘј к·ёлҢҖлЎң ліҙм—¬мЈјм§Җ м•Ҡкі , stale м—¬л¶ҖлҘј н‘ңмӢңн•ңлӢӨ.
# ============================================================
PAPER_V285_STATS = {
    "build": 0, "cache_hit": 0, "stale_served": 0, "error": 0,
    "history_rows": 0, "rank_rows": 0, "snapshot3m_rows": 0,
    "app_1m": 0, "app_3m": 0, "base_lack_1m": 0, "base_lack_3m": 0,
    "overlap": 0, "app_only": 0, "bot_only": 0, "repeat": 0,
    "signal_hint": 0, "signal_price_fix": 0,
    "last_build_sec": 0.0, "last_text_sec": 0.0, "last_note": "лҢҖкё°",
}
_RANK_COMPARE_V285_CACHE = {"ts": 0.0, "data": None}
RANK_COMPARE_V285_CACHE_TTL_SEC = 6.0
RANK_COMPARE_V285_STALE_OK_SEC = 120.0


def _v285_inc(key, note=""):
    try:
        PAPER_V285_STATS[key] = int(safe_float(PAPER_V285_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V285_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _v285_norm(ticker):
    try:
        if '_v284_norm' in globals():
            return _v284_norm(ticker)
        if '_v283_key' in globals():
            return _v283_key(ticker)
        return str(ticker or '').upper().strip().replace('KRW-', '').replace('_KRW', '')
    except Exception:
        return str(ticker or '').upper().strip()


def _v285_money(row):
    try:
        if '_v284_money' in globals():
            return _v284_money(row)
    except Exception:
        pass
    vals=[]
    for k in ('turnover_5m','turnover','trade_amount_60s','acc_trade_value_24h','money_krw'):
        try: vals.append(safe_float((row or {}).get(k,0),0))
        except Exception: pass
    return max(vals or [0.0])


def _v285_score(row):
    try:
        if '_v284_strategy_score' in globals():
            return _v284_strategy_score(row)
    except Exception:
        pass
    return safe_float((row or {}).get('score', (row or {}).get('snapshot_rank_score', 0)), 0)


def _v285_rank_rows():
    try:
        rows = _v284_get_latest_rank_rows() if '_v284_get_latest_rank_rows' in globals() else []
        return list(rows or []) if isinstance(rows, list) else []
    except Exception:
        return []


def _v285_full_rows_fast():
    """м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬ row. мһ¬к·Җм„ұ compare builderлҘј м ҲлҢҖ нҳём¶ңн•ҳм§Җ м•ҠлҠ”лӢӨ."""
    try:
        if '_v283_full_history_rows' in globals():
            rows = _v283_full_history_rows(now_ts=time.time(), max_tickers=520)
            return list(rows or []) if isinstance(rows, list) else []
    except Exception:
        return []
    return []


def _v285_snapshot_items(frame='3л¶„', existing=None):
    existing=set(_v285_norm(x) for x in (existing or []) if _v285_norm(x))
    out=[]
    key_map={'1л¶„':'change_1','3л¶„':'change_3','5л¶„':'change_5','15л¶„':'change_15','30л¶„':'change_30','1мӢңк°„':'change_60'}
    key=key_map.get(frame,'change_3')
    try:
        for r in _v285_rank_rows():
            if not isinstance(r, dict):
                continue
            t=_v285_norm(r.get('ticker'))
            if not t or t in existing:
                continue
            val=safe_float(r.get(key, r.get('chg_3m', 0)), 0)
            if val <= 0:
                continue
            row=dict(r)
            row['ticker']=t
            row['current_price']=safe_float(row.get('current_price', row.get('price', 0)), 0)
            row[f'change_{"3" if frame=="3л¶„" else "1"}_ready']=True
            row[f'change_{"3" if frame=="3л¶„" else "1"}_base_age_sec']=180 if frame=='3л¶„' else 60
            row['cache_source']=f'snapshot{frame}_fallback_v285'
            row['latest_price_source']=row.get('latest_price_source') or 'rank_snapshot'
            out.append((val, _v285_score(row), _v285_money(row), t, row))
    except Exception:
        pass
    out.sort(key=lambda x:(x[0], x[2], x[1]), reverse=True)
    return out[:10]


def _v285_build_compare_data(force=False):
    t0=time.time()
    try:
        c=_RANK_COMPARE_V285_CACHE
        data=c.get('data') if isinstance(c.get('data'), dict) else None
        if (not force) and isinstance(data, dict):
            age=time.time()-safe_float(data.get('created_ts', c.get('ts',0)),0)
            if age <= RANK_COMPARE_V285_CACHE_TTL_SEC:
                _v285_inc('cache_hit','v285 fresh cache')
                return data
        _v285_inc('build','v285 fresh build')
        rows=_v285_full_rows_fast()
        # rowsк°Җ мһ кёҲ/мҙҲкё°нҷ”лЎң л№„л©ҙ rank snapshotл§ҢмңјлЎңлқјлҸ„ мҰүмӢң мқ‘лӢөн•ңлӢӨ.
        rank_rows=_v285_rank_rows()
        row_by={_v285_norm(r.get('ticker')): r for r in rows if isinstance(r,dict) and _v285_norm(r.get('ticker'))}
        specs=[('1л¶„','change_1','change_1_ready'),('3л¶„','change_3','change_3_ready'),('15л¶„','change_15','change_15_ready'),('30л¶„','change_30','change_30_ready'),('1мӢңк°„','change_60','change_60_ready')]
        app={}; counts={}; lack={}; low_rows=[]
        for label,key,ready_key in specs:
            picked=[]; missing=0
            for r in rows:
                if not isinstance(r,dict):
                    continue
                if not bool(r.get(ready_key, False)):
                    missing += 1; continue
                val=safe_float(r.get(key,0),0)
                if val <= 0:
                    continue
                t=_v285_norm(r.get('ticker'))
                item=(val, _v285_score(r), _v285_money(r), t, r)
                picked.append(item)
                if label in {'1л¶„','3л¶„'} and bool(r.get('low_liquidity_app_rank',False)):
                    low_rows.append(item)
            picked.sort(key=lambda x:(x[0],x[2],x[1]), reverse=True)
            app[label]=picked[:10]
            lack[label]=missing
            for rank,item in enumerate(app[label], start=1):
                val,_score,_money,t,row=item
                info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                info['count']=int(safe_float(info.get('count',0),0))+1
                if label not in info.get('frames',[]): info.setdefault('frames',[]).append(label)
                info['best_rank']=min(int(safe_float(info.get('best_rank',99),99)), rank)
                info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(val,0))
                info['row']=row
        # 3л¶„ fallback. м „мІҙ нһҲмҠӨнҶ лҰ¬ 3л¶„мқҙ л№„кұ°лӮҳ м Ғмңјл©ҙ rank_short change_3лЎң мұ„мҡҙлӢӨ.
        existing3={item[3] for item in list(app.get('3л¶„') or []) if len(item)>=4}
        fallback3=[]
        if len(existing3) < 5:
            fallback3=_v285_snapshot_items('3л¶„', existing=existing3)
            if fallback3:
                merged=list(app.get('3л¶„') or []) + fallback3
                merged.sort(key=lambda x:(x[0],x[2],x[1]), reverse=True)
                app['3л¶„']=merged[:10]
                for rank,item in enumerate(fallback3, start=1):
                    val,_score,_money,t,row=item
                    row_by[t]=row
                    info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                    info['count']=int(safe_float(info.get('count',0),0))+ (0 if '3л¶„' in info.get('frames',[]) else 1)
                    if '3л¶„' not in info.get('frames',[]): info.setdefault('frames',[]).append('3л¶„')
                    info['best_rank']=min(int(safe_float(info.get('best_rank',99),99)), rank)
                    info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(val,0))
                    info['row']=row
                lack['3л¶„']=max(0, int(safe_float(lack.get('3л¶„',0),0))-len(fallback3))
        # 1л¶„ fallbackмқҖ м“°лҗҳ, л„Ҳл¬ҙ кіјн•ҳкІҢлҠ” м“°м§Җ м•ҠлҠ”лӢӨ. м „мІҙ 1л¶„мқҙ м•„мҳҲ м—Ҷмқ„ л•Ңл§Ң ліҙмЎ°.
        if not app.get('1л¶„'):
            fb1=_v285_snapshot_items('1л¶„', existing=set())
            if fb1:
                app['1л¶„']=fb1[:10]
                for rank,item in enumerate(fb1, start=1):
                    val,_score,_money,t,row=item
                    row_by[t]=row
                    info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                    if '1л¶„' not in info.get('frames',[]):
                        info['count']=int(safe_float(info.get('count',0),0))+1; info.setdefault('frames',[]).append('1л¶„')
                    info['best_rank']=min(int(safe_float(info.get('best_rank',99),99)), rank)
                    info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(val,0))
                    info['row']=row
        # strategy
        try:
            strategy_rows=_v282_get_strategy_rows() if '_v282_get_strategy_rows' in globals() else rank_rows
        except Exception:
            strategy_rows=rank_rows
        strategy=[_v285_norm(r.get('ticker')) for r in list(strategy_rows or []) if isinstance(r,dict) and _v285_norm(r.get('ticker'))]
        if not strategy:
            strategy=[_v285_norm(r.get('ticker')) for r in rank_rows[:8] if _v285_norm(r.get('ticker'))]
        app_order=[]
        for label in ['1л¶„','3л¶„','15л¶„','30л¶„','1мӢңк°„']:
            for item in list(app.get(label) or [])[:8]:
                t=item[3]
                if t and t not in app_order: app_order.append(t)
        overlap=[t for t in strategy if t in app_order]
        app_only=[t for t in app_order if t not in strategy]
        bot_only=[t for t in strategy if t not in app_order]
        set1={item[3] for item in list(app.get('1л¶„') or [])[:10] if len(item)>=4}
        set3={item[3] for item in list(app.get('3л¶„') or [])[:10] if len(item)>=4}
        early=[t for t in app_order if t in set1 and t in set3]
        one=[t for t in app_order if t in set1 and t not in set3]
        repeated=[t for t,info in sorted(counts.items(), key=lambda kv:(int(safe_float(kv[1].get('count',0),0)), -int(safe_float(kv[1].get('best_rank',99),99)), safe_float(kv[1].get('best_change',0),0)), reverse=True) if int(safe_float(info.get('count',0),0))>=2]
        low_rows=sorted(low_rows, key=lambda x:(x[0],x[2]), reverse=True)[:8]
        out={'rows':rows,'rank_rows':rank_rows,'row_by_ticker':row_by,'app':app,'app_counts':counts,'insufficient':lack,'strategy':strategy,'strategy_rows':strategy_rows,'app_order':app_order,'overlap':overlap,'app_only':app_only,'bot_only':bot_only,'early_both':early,'one_min_only':one,'repeated':repeated,'low_liquidity_rows':low_rows,'created_ts':time.time(),'build_sec':round(time.time()-t0,4),'source':'bot_calc_app_rank_v285','fallback3_count':len(fallback3)}
        _RANK_COMPARE_V285_CACHE.update({'ts':time.time(),'data':out})
        PAPER_V285_STATS.update({'history_rows':len(rows),'rank_rows':len(rank_rows),'snapshot3m_rows':len(fallback3),'app_1m':len(app.get('1л¶„') or []),'app_3m':len(app.get('3л¶„') or []),'base_lack_1m':int(safe_float(lack.get('1л¶„',0),0)),'base_lack_3m':int(safe_float(lack.get('3л¶„',0),0)),'overlap':len(overlap),'app_only':len(app_only),'bot_only':len(bot_only),'repeat':len(repeated),'last_build_sec':round(time.time()-t0,4),'last_note':'v285 мөңмӢ  мғқм„ұ'})
        return out
    except Exception as e:
        _v285_inc('error', str(e))
        try: append_runtime_error_log('rank_compare_v285', str(e), exc=e, include_traceback=False)
        except Exception: pass
        data=(_RANK_COMPARE_V285_CACHE.get('data') if isinstance(_RANK_COMPARE_V285_CACHE.get('data'),dict) else None)
        if data and time.time()-safe_float(data.get('created_ts',0),0) <= RANK_COMPARE_V285_STALE_OK_SEC:
            _v285_inc('stale_served','v285 error stale served')
            data=dict(data); data['stale_served']=True; data['build_sec']=round(time.time()-t0,4)
            return data
        return {'rows':[],'rank_rows':[],'row_by_ticker':{},'app':{},'app_counts':{},'insufficient':{},'strategy':[],'strategy_rows':[],'app_order':[],'overlap':[],'app_only':[],'bot_only':[],'early_both':[],'one_min_only':[],'repeated':[],'low_liquidity_rows':[],'created_ts':time.time(),'build_sec':round(time.time()-t0,4),'source':'error'}


def _v285_join(items, limit=10, empty='м—ҶмқҢ'):
    try:
        arr=list(items or [])[:max(1,int(limit))]
        return ', '.join(str(x) for x in arr) if arr else empty
    except Exception:
        return empty


def _v285_format_app_item(ticker, info=None):
    try:
        if not isinstance(info, dict): return str(ticker)
        frames='/'.join(list(info.get('frames') or [])[:5])
        best=safe_float(info.get('best_change',0),0)
        row=info.get('row') if isinstance(info.get('row'),dict) else {}
        extra=''
        src=str(row.get('cache_source','') or row.get('latest_price_source',''))
        if 'snapshot3m' in src: extra+='В·snapshot3m'
        elif str(row.get('latest_price_source',''))=='ws_trade': extra+='В·мІҙкІ°ліҙмҷ„'
        return f"{ticker} {best:+.2f}%" + (f"В·{frames}" if frames else '') + extra
    except Exception:
        return str(ticker)


def build_rank_compare_text_v279(args=None, top_n:int=10):
    t0=time.time()
    data=_v285_build_compare_data(force=False)
    app=data.get('app') or {}; counts=data.get('app_counts') or {}; lack=data.get('insufficient') or {}
    age=time.time()-safe_float(data.get('created_ts',time.time()),time.time())
    stale=' / вҡ пёҸ мҳӨлһҳлҗң кІ°кіј' if bool(data.get('stale_served')) or age>RANK_COMPARE_V285_STALE_OK_SEC else ''
    lines=['рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare', '- мҶҢмҠӨ: лҙҮ кі„мӮ° м•ұмӢқ мғҒмҠ№лҘ  мҲңмң„', '- л№—мҚё м•ұ мӣҗліё лһӯнӮ№ м•„лӢҳ. кіөмӢқ нҳ„мһ¬к°Җ/мІҙкІ°/мҠӨлғ…мғ·мңјлЎң мөңлҢҖн•ң л№„мҠ·н•ҳкІҢ л§Ңл“  мң мӮ¬ мҲңмң„', '- 1л¶„мқҖ мҙҲмһ… к°җм§Җмҡ©. л°”лЎң л§ӨмҲҳ/paper л“ұлЎқ м•„лӢҳ', f"- кё°мӨҖ: мөңмӢ  лӮҙл¶Җ мҠӨлғ…мғ· + WS/мІҙкІ°/bulk ліҙмҷ„ / мғқм„ұ {format_elapsed_text(age)} м „ / мҶҢмҡ” {safe_float(data.get('build_sec',0),0):.3f}s{stale}", '', '[лҙҮ кі„мӮ° мғҒмҠ№лҘ  TOP]']
    for label in ['1л¶„','3л¶„','15л¶„','30л¶„','1мӢңк°„']:
        bits=[]
        for val,_score,money,t,row in list(app.get(label) or [])[:max(1,int(top_n))]:
            item=f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money,0)>=100_000_000:
                try: item += f"В·{format_money_compact_amount_krw(money)}"
                except Exception: pass
            src=str(row.get('cache_source','') or row.get('latest_price_source',''))
            if 'snapshot3m' in src: item+='В·snapshot3m'
            elif str(row.get('latest_price_source',''))=='ws_trade': item+='В·мІҙкІ°к°Җліҙмҷ„'
            if label=='1л¶„':
                ag=safe_float(row.get('change_1_base_age_sec',0),0)
                if ag>0: item += f"В·кё°мӨҖ{ag:.0f}s"
            if label=='3л¶„':
                ag=safe_float(row.get('change_3_base_age_sec',0),0)
                item += f"В·кё°мӨҖ{ag:.0f}s" if ag>0 else 'В·кё°мӨҖ180s'
            bits.append(item)
        lack_n=int(safe_float(lack.get(label,0),0))
        if label in {'15л¶„','30л¶„','1мӢңк°„'} and not bits and lack_n:
            lines.append(f"- {label}: н‘ңліёл¶ҖмЎұ / кі„мӮ° лҢҖкё° ({lack_n}к°ң)")
        else:
            suffix=f" / кё°мӨҖк°Җл¶ҖмЎұ {lack_n}к°ң" if lack_n and label in {'1л¶„','3л¶„'} else ''
            lines.append(f"- {label}: " + _v285_join(bits, limit=top_n, empty='кі„мӮ° к°ҖлҠҘн•ң мғҒмҠ№ м—ҶмқҢ') + suffix)
    low_bits=[]
    for val,_score,money,t,row in list(data.get('low_liquidity_rows') or [])[:6]:
        low_bits.append(f"{t} {safe_float(val,0):+.2f}%В·лҸҲ/мІҙкІ°м•Ҫн•Ё")
    if low_bits:
        lines += ['', '[м Җмң лҸҷм„ұ/мІҙкІ°м•Ҫн•Ё кёүл“ұ]', '- '+_v285_join(low_bits, limit=6)]
    strategy=data.get('strategy') or []; overlap=data.get('overlap') or []; app_only=data.get('app_only') or []; bot_only=data.get('bot_only') or []; repeated=data.get('repeated') or []; early=data.get('early_both') or []; one=data.get('one_min_only') or []
    lines += ['', '[мҙҲмһ… нӣ„ліҙ]', '- 1л¶„+3л¶„ лҸҷмӢң: '+_v285_join([_v285_format_app_item(t, counts.get(t)) for t in early], limit=10), '- 1л¶„л§Ң кёүл“ұ: '+_v285_join([_v285_format_app_item(t, counts.get(t)) for t in one], limit=10)+(' / 3л¶„ мң м§Җ нҷ•мқё н•„мҡ”' if one else ''), '', '[мҡ°лҰ¬ лҙҮ м „лһө мҲңмң„ TOP]', '- '+_v285_join(strategy, limit=8), '', '[л№„көҗ кІ°кіј]', '- кІ№м№Ё: '+_v285_join(overlap, limit=8), '- м•ұмӢқ only лҶ“м№Ёнӣ„ліҙ: '+_v285_join([_v285_format_app_item(t, counts.get(t)) for t in app_only], limit=12), '- лҙҮ only лӢЁлҸ…нӣ„ліҙ: '+_v285_join(bot_only, limit=10), '- л°ҳліөмғҒмң„: '+_v285_join([_v285_format_app_item(t, counts.get(t)) for t in repeated], limit=10), f"- м „мІҙ нһҲмҠӨнҶ лҰ¬ rows {len(data.get('rows') or [])} / rank snapshot 3m ліҙмҷ„ {safe_float(data.get('fallback3_count',0),0):.0f}к°ң", '- лӮҙл¶Җк°җмӢң: мқҙ лӘ…л №мқҖ мқҪкё°м „мҡ©. м•ұмӢқ onlyлҠ” н‘ёмӢң/paper мһҗлҸҷл“ұлЎқ м•Ҳ н•Ё', '', '[нҢҗлӢЁлІ•]', '- м•ұмӢқ onlyлҠ” м „мІҙ мӢңмһҘм—җм„ңлҠ” нҠҖлҠ”лҚ° м „лһө нӣ„ліҙм—җлҠ” м•Ҫн•ң лҶ“м№Ё кІҖмҰқ нӣ„ліҙ', '- snapshot3mмқҖ м „мІҙ нһҲмҠӨнҶ лҰ¬ 3л¶„ кё°мӨҖк°Җ л¶ҖмЎұ мӢң rank_short 3л¶„к°’мңјлЎң ліҙмҷ„н•ң н‘ңмӢңм•ј.']
    PAPER_V285_STATS['last_text_sec']=round(time.time()-t0,4)
    return '\n'.join(lines).strip()


