def _v285_app_signal_note(ticker):
    try:
        t=_v285_norm(ticker)
        data=_v285_build_compare_data(force=False)
        row=(data.get('row_by_ticker') or {}).get(t)
        info=(data.get('app_counts') or {}).get(t)
        if isinstance(info,dict):
            PAPER_V285_STATS['signal_hint']=int(safe_float(PAPER_V285_STATS.get('signal_hint',0),0))+1
            return '- м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҠ” мһҲмқҢ: '+_v285_format_app_item(t, info)+' / л§ӨмҲҳмӢ нҳё м•„лӢҳ'
        if isinstance(row,dict):
            c1=safe_float(row.get('change_1',0),0); c3=safe_float(row.get('change_3',0),0)
            r1='к°ҖлҠҘ' if row.get('change_1_ready') else 'кё°мӨҖк°Җл¶ҖмЎұ'; r3='к°ҖлҠҘ' if row.get('change_3_ready') else 'кё°мӨҖк°Җл¶ҖмЎұ'
            src=str(row.get('latest_price_source','') or row.get('cache_source','') or '-')
            return f"- м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҠ” мһҲмқҢ: 1л¶„ {c1:+.2f}%({r1}) / 3л¶„ {c3:+.2f}%({r3}) / мөңмӢ к°Җ {src} / л§ӨмҲҳмӢ нҳё м•„лӢҳ"
        return '- м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҸ„ мөңк·ј н‘ңліё м—ҶмқҢ / нӢ°м»ӨлӘ… лҳҗлҠ” мғҒмһҘлӘ… нҷ•мқё н•„мҡ”'
    except Exception:
        return ''


