def _v286_is_low_liquidity(row):
    try:
        if not isinstance(row, dict):
            return False
        reason = ' '.join(str(row.get(k,'') or '') for k in ('rank_reason','reason','decision_reason','entry_layer_reason','watch_reason','tier_reason'))
        money = _v286_money(row)
        tc = max(safe_float(row.get('trade_count_60s',0),0), safe_float(row.get('ws_trade_count_60s',0),0), safe_float(row.get('recent_trade_count',0),0))
        if 'мӢӨм ңлҸҲмһ‘мқҢ' in reason or 'лҸҲм–Ү' in reason or 'лҸҲ м•Ҫн•Ё' in reason:
            return True
        if money > 0 and money < 10_000_000:
            return True
        if tc > 0 and tc < 2 and money < 100_000_000:
            return True
    except Exception:
        pass
    return False


def _v286_candle_summary(row):
    try:
        if not isinstance(row, dict):
            return ''
        parts=[]
        candle = str(row.get('current_candle_status','') or row.get('candle_status','') or row.get('now_candle_status','') or '')
        if candle:
            parts.append(candle[:18])
        live = safe_float(row.get('candle_live_score', row.get('current_candle_live_score',0)),0)
        pull = safe_float(row.get('candle_pullback_score', row.get('current_candle_pullback_score',0)),0)
        if live or pull:
            parts.append(f"нҳ„мһ¬лҙү мғқмЎҙ{live:.1f}/л°ҖлҰј{pull:.1f}")
        tc = max(safe_float(row.get('trade_count_60s',0),0), safe_float(row.get('ws_trade_count_60s',0),0))
        br = safe_float(row.get('buy_ratio_60s', row.get('buy_ratio',0)),0)
        if tc:
            parts.append(f"мІҙкІ°{tc:.0f}кұҙВ·л§ӨмҲҳ{br:.0f}%")
        money=_v286_money(row)
        if money>=100_000_000:
            try: parts.append(f"лҸҲ{format_money_compact_amount_krw(money)}")
            except Exception: parts.append(f"лҸҲ{money/100_000_000:.1f}м–ө")
        elif money>0:
            parts.append('лҸҲм–ҮмқҢ')
        return ' / '.join(parts[:3])
    except Exception:
        return ''


def _v286_exclude_reason(row):
    try:
        if not isinstance(row, dict):
            return 'м „лһө нӣ„ліҙ м•„лӢҳ'
        reasons=[]
        money=_v286_money(row)
        tc=max(safe_float(row.get('trade_count_60s',0),0), safe_float(row.get('ws_trade_count_60s',0),0))
        buy=safe_float(row.get('buy_ratio_60s', row.get('buy_ratio',0)),0)
        txt=' '.join(str(row.get(k,'') or '') for k in ('rank_reason','reason','decision_reason','entry_layer_reason','watch_reason','tier_reason','conclusion','one_line'))
        if _v286_is_low_liquidity(row): reasons.append('м Җмң лҸҷм„ұ/лҸҲм–ҮмқҢ')
        if tc and tc < 3: reasons.append('мІҙкІ°м ҒмқҢ')
        if buy and buy < 45: reasons.append('л§ӨмҲҳм„ём•Ҫн•Ё')
        if 'л§ӨлҸ„мҡ°м„ё' in txt or 'л§ӨлҸ„ мҡ°м„ё' in txt: reasons.append('л§ӨлҸ„мҡ°м„ё')
        if 'нҳ„мһ¬лҙүм•Ҫн•Ё' in txt or 'нҳ„мһ¬лҙү м•Ҫн•Ё' in txt or 'л°ҖлҰј' in txt: reasons.append('нҳ„мһ¬лҙүм•Ҫн•Ё')
        if 'кі м җ' in txt and ('л§һлӢҝ' in txt or 'м¶”кІ©' in txt): reasons.append('кі м җк·јмІҳ')
        if not reasons:
            if money>0 and money<100_000_000: reasons.append('лҸҲ нҷ•мқё н•„мҡ”')
            else: reasons.append('м „лһө м җмҲҳ/к·јкұ° л¶ҖмЎұ')
        return '+'.join(dict.fromkeys(reasons[:3]))
    except Exception:
        return 'мӮ¬мң нҷ•мқён•„мҡ”'


def _v286_collect_history_rows():
    # м „мІҙ нһҲмҠӨнҶ лҰ¬ rowлҘј л°ұк·ёлқјмҡҙл“ңм—җм„ңл§Ң л§Ңл“ лӢӨ. мӢӨнҢЁ/л№Ҳк°’мқҙл©ҙ л№Ҳ лҰ¬мҠӨнҠё л°ҳнҷҳ.
    try:
        if '_v283_full_history_rows' in globals():
            rows = _v283_full_history_rows(now_ts=time.time())
        elif '_v282_full_history_rows' in globals():
            rows = _v282_full_history_rows(now_ts=time.time())
        else:
            rows = []
        return [r for r in list(rows or []) if isinstance(r, dict) and _v286_norm(r.get('ticker'))]
    except Exception as e:
        try: append_runtime_error_log('rank_compare_v286_history_rows', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return []


def _v286_snapshot_items(frame='3л¶„', existing=None, source_rows=None):
    # v285 snapshot fallback мһ¬мӮ¬мҡ© + м Җмң лҸҷм„ұ flag ліҙм •
    try:
        rows = _v285_snapshot_items(frame=frame, existing=existing) if '_v285_snapshot_items' in globals() else []
        fixed=[]
        for val,score,money,t,row in list(rows or []):
            if isinstance(row,dict):
                row=dict(row); row['ticker']=_v286_norm(t); row['low_liquidity_app_rank']=bool(row.get('low_liquidity_app_rank',False) or _v286_is_low_liquidity(row)); row['exclude_reason_v286']=_v286_exclude_reason(row); row['candle_summary_v286']=_v286_candle_summary(row)
            fixed.append((val,score,money,_v286_norm(t),row))
        return fixed
    except Exception:
        return []


def _v286_make_compare_data(rows=None, rank_rows=None, source='worker'):
    t0=time.time()
    rows=[r for r in list(rows or []) if isinstance(r,dict) and _v286_norm(r.get('ticker'))]
    rank_rows=[r for r in list(rank_rows if rank_rows is not None else _v286_rank_rows()) if isinstance(r,dict) and _v286_norm(r.get('ticker'))]
    row_by={_v286_norm(r.get('ticker')): r for r in rows}
    specs=[('1л¶„','change_1','change_1_ready'),('3л¶„','change_3','change_3_ready'),('15л¶„','change_15','change_15_ready'),('30л¶„','change_30','change_30_ready'),('1мӢңк°„','change_60','change_60_ready')]
    app={}; counts={}; lack={}; low_rows=[]
    try:
        for label,key,ready_key in specs:
            picked=[]; missing=0
            for r in rows:
                if not bool(r.get(ready_key, False)):
                    missing += 1; continue
                val=safe_float(r.get(key,0),0)
                if val <= 0: continue
                t=_v286_norm(r.get('ticker'))
                rr=dict(r); rr['ticker']=t; rr['low_liquidity_app_rank']=bool(rr.get('low_liquidity_app_rank',False) or _v286_is_low_liquidity(rr)); rr['exclude_reason_v286']=_v286_exclude_reason(rr); rr['candle_summary_v286']=_v286_candle_summary(rr)
                item=(val, _v286_score(rr), _v286_money(rr), t, rr)
                if rr.get('low_liquidity_app_rank') and label in {'1л¶„','3л¶„'}:
                    low_rows.append(item)
                else:
                    picked.append(item)
            picked.sort(key=lambda x:(x[0],x[2],x[1]), reverse=True)
            app[label]=picked[:10]
            lack[label]=missing
            for rank,item in enumerate(app[label], start=1):
                val,_score,_money,t,row=item
                info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                if label not in info.get('frames',[]):
                    info['count']=int(safe_float(info.get('count',0),0))+1; info.setdefault('frames',[]).append(label)
                info['best_rank']=min(int(safe_float(info.get('best_rank',99),99)), rank)
                info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(val,0))
                info['row']=row
        # 3л¶„ нһҲмҠӨнҶ лҰ¬к°Җ л№„л©ҙ л№ лҘё rank snapshot ліҙмЎ°лҘј л„ЈлҠ”лӢӨ. м „мІҙ мәҗмӢң мӨҖл№„ м „ мқ‘кёү н‘ңмӢңмҡ©.
        existing3={it[3] for it in list(app.get('3л¶„') or []) if len(it)>=4}
        fallback3=[]
        if len(existing3) < 5:
            fallback3=_v286_snapshot_items('3л¶„', existing=existing3)
            if fallback3:
                merged=list(app.get('3л¶„') or []) + fallback3
                merged.sort(key=lambda x:(x[0],x[2],x[1]), reverse=True)
                app['3л¶„']=merged[:10]
                for rank,item in enumerate(fallback3, start=1):
                    val,_score,_money,t,row=item
                    row_by[t]=row
                    info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                    if '3л¶„' not in info.get('frames',[]):
                        info['count']=int(safe_float(info.get('count',0),0))+1; info.setdefault('frames',[]).append('3л¶„')
                    info['best_rank']=min(int(safe_float(info.get('best_rank',99),99)), rank)
                    info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(val,0))
                    info['row']=row
        if not app.get('1л¶„'):
            fb1=_v286_snapshot_items('1л¶„', existing=set())[:8]
            app['1л¶„']=fb1
            for rank,item in enumerate(fb1, start=1):
                val,_score,_money,t,row=item; row_by[t]=row
                info=counts.setdefault(t, {'count':0,'frames':[],'best_rank':99,'best_change':-999.0,'row':row})
                if '1л¶„' not in info.get('frames',[]):
                    info['count']=int(safe_float(info.get('count',0),0))+1; info.setdefault('frames',[]).append('1л¶„')
                info['best_rank']=min(int(safe_float(info.get('best_rank',99),99)), rank)
                info['best_change']=max(safe_float(info.get('best_change',-999),-999), safe_float(val,0)); info['row']=row
        try:
            strategy_rows=_v282_get_strategy_rows() if '_v282_get_strategy_rows' in globals() else rank_rows
        except Exception:
            strategy_rows=rank_rows
        strategy=[_v286_norm(r.get('ticker')) for r in list(strategy_rows or []) if isinstance(r,dict) and _v286_norm(r.get('ticker'))]
        if not strategy:
            strategy=[_v286_norm(r.get('ticker')) for r in rank_rows[:8] if _v286_norm(r.get('ticker'))]
        app_order=[]
        for label in ['1л¶„','3л¶„','15л¶„','30л¶„','1мӢңк°„']:
            for item in list(app.get(label) or [])[:8]:
                t=item[3]
                if t and t not in app_order: app_order.append(t)
        overlap=[t for t in strategy if t in app_order]
        app_only=[t for t in app_order if t not in strategy]
        bot_only=[t for t in strategy if t not in app_order]
        set1={i[3] for i in list(app.get('1л¶„') or [])[:10] if len(i)>=4}
        set3={i[3] for i in list(app.get('3л¶„') or [])[:10] if len(i)>=4}
        early=[t for t in app_order if t in set1 and t in set3]
        one=[t for t in app_order if t in set1 and t not in set3]
        repeated=[t for t,info in sorted(counts.items(), key=lambda kv:(int(safe_float(kv[1].get('count',0),0)), -int(safe_float(kv[1].get('best_rank',99),99)), safe_float(kv[1].get('best_change',0),0)), reverse=True) if int(safe_float(info.get('count',0),0))>=2]
        low_rows=sorted(low_rows, key=lambda x:(x[0],x[2],x[1]), reverse=True)[:8]
        data={'rows':rows,'rank_rows':rank_rows,'row_by_ticker':row_by,'app':app,'app_counts':counts,'insufficient':lack,'strategy':strategy,'strategy_rows':strategy_rows,'app_order':app_order,'overlap':overlap,'app_only':app_only,'bot_only':bot_only,'early_both':early,'one_min_only':one,'repeated':repeated,'low_liquidity_rows':low_rows,'created_ts':time.time(),'build_sec':round(time.time()-t0,4),'source':source,'fallback3_count':len(fallback3),'full_rank_ready':bool(rows),'rank_snapshot_only':not bool(rows)}
        return data
    except Exception as e:
        try: append_runtime_error_log('rank_compare_v286_make', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {'rows':rows,'rank_rows':rank_rows,'row_by_ticker':row_by,'app':{},'app_counts':{},'insufficient':{},'strategy':[],'strategy_rows':[],'app_order':[],'overlap':[],'app_only':[],'bot_only':[],'early_both':[],'one_min_only':[],'repeated':[],'low_liquidity_rows':[],'created_ts':time.time(),'build_sec':round(time.time()-t0,4),'source':'error','fallback3_count':0,'rank_snapshot_only':True}


def _v286_refresh_app_rank_cache(reason='worker'):
    t0=time.time()
    try:
        PAPER_V286_STATS['worker_build']=int(safe_float(PAPER_V286_STATS.get('worker_build',0),0))+1
        rank_rows=_v286_rank_rows()
        rows=_v286_collect_history_rows()
        data=_v286_make_compare_data(rows=rows, rank_rows=rank_rows, source='bg_app_rank_v286')
        _RANK_COMPARE_V286_BG_CACHE.update({'ts':time.time(),'data':data,'build_sec':round(time.time()-t0,4),'note':reason})
        PAPER_V286_STATS.update({'cache_rows':len(rows),'cache_rank_rows':len(rank_rows),'cache_build_sec':round(time.time()-t0,4),'cache_age_sec':0.0,'app_1m':len((data.get('app') or {}).get('1л¶„') or []),'app_3m':len((data.get('app') or {}).get('3л¶„') or []),'snapshot3m':int(safe_float(data.get('fallback3_count',0),0)),'low_liquidity':len(data.get('low_liquidity_rows') or []),'overlap':len(data.get('overlap') or []),'app_only':len(data.get('app_only') or []),'bot_only':len(data.get('bot_only') or []),'repeat':len(data.get('repeated') or []),'last_note':f'{reason} cache'})
        return data
    except Exception as e:
        _v286_inc('worker_error', str(e))
        try: append_runtime_error_log('rank_compare_v286_refresh', str(e), exc=e, include_traceback=False)
        except Exception: pass
        return None


def _v286_get_compare_data():
    now=time.time()
    try:
        data=_RANK_COMPARE_V286_BG_CACHE.get('data') if isinstance(_RANK_COMPARE_V286_BG_CACHE.get('data'),dict) else None
        ts=safe_float(_RANK_COMPARE_V286_BG_CACHE.get('ts',0),0)
        age=now-ts if ts else 99999.0
        PAPER_V286_STATS['cache_age_sec']=round(age,1)
        if data and age <= RANK_COMPARE_V286_READY_TTL_SEC:
            _v286_inc('command_cache_hit','fresh app_rank cache')
            return data
        if data and age <= RANK_COMPARE_V286_STALE_OK_SEC:
            _v286_inc('command_cache_hit','stale-ok app_rank cache')
            d=dict(data); d['stale_served']=True
            return d
        # лӘ…л №м–ҙм—җм„ңлҠ” м „мІҙ нһҲмҠӨнҶ лҰ¬лҘј лӢӨмӢң нӣ‘м§Җ м•ҠлҠ”лӢӨ. rank snapshotмңјлЎңл§Ң мҰүмӢң мқ‘лӢө.
        _v286_inc('command_fallback','м „мІҙлһӯнҒ¬ мӨҖл№„мӨ‘: rank snapshot fallback')
        data=_v286_make_compare_data(rows=[], rank_rows=_v286_rank_rows(), source='rank_snapshot_fallback_v286')
        data['app_rank_preparing']=True
        return data
    except Exception as e:
        _v286_inc('worker_error', str(e))
        return _v286_make_compare_data(rows=[], rank_rows=_v286_rank_rows(), source='error_fallback_v286')


def _v286_join(items, limit=10, empty='м—ҶмқҢ'):
    try:
        arr=list(items or [])[:max(1,int(limit))]
        return ', '.join(str(x) for x in arr) if arr else empty
    except Exception:
        return empty


def _v286_format_app_item(ticker, info=None, include_reason=False):
    try:
        t=_v286_norm(ticker)
        if not isinstance(info,dict): return t
        row=info.get('row') if isinstance(info.get('row'),dict) else {}
        frames='/'.join(list(info.get('frames') or [])[:5])
        best=safe_float(info.get('best_change',0),0)
        out=f"{t} {best:+.2f}%" + (f"В·{frames}" if frames else '')
        src=str(row.get('cache_source','') or row.get('latest_price_source',''))
        if 'snapshot3m' in src: out+='В·snapshot3m'
        elif str(row.get('latest_price_source',''))=='ws_trade': out+='В·мІҙкІ°ліҙмҷ„'
        cs=str(row.get('candle_summary_v286','') or _v286_candle_summary(row))
        if cs:
            PAPER_V286_STATS['candle_summary']=int(safe_float(PAPER_V286_STATS.get('candle_summary',0),0))+1
            out += f"В·{cs}"
        if include_reason:
            reason=str(row.get('exclude_reason_v286','') or _v286_exclude_reason(row))
            if reason:
                PAPER_V286_STATS['reason_attached']=int(safe_float(PAPER_V286_STATS.get('reason_attached',0),0))+1
                out += f" / м ңмҷёмқҙмң  {reason}"
        return out
    except Exception:
        return str(ticker)


def build_rank_compare_text_v279(args=None, top_n:int=10):
    t0=time.time()
    data=_v286_get_compare_data()
    app=data.get('app') or {}; counts=data.get('app_counts') or {}; lack=data.get('insufficient') or {}
    age=time.time()-safe_float(data.get('created_ts',time.time()),time.time())
    stale=' / вҡ пёҸ м „мІҙлһӯнҒ¬ мӨҖл№„мӨ‘' if data.get('app_rank_preparing') or data.get('rank_snapshot_only') else (' / вҡ пёҸ мҳӨлһҳлҗң мәҗмӢң' if data.get('stale_served') else '')
    lines=['рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare', '- мҶҢмҠӨ: лҙҮ кі„мӮ° м•ұмӢқ мғҒмҠ№лҘ  мҲңмң„', '- л№—мҚё м•ұ мӣҗліё лһӯнӮ№ м•„лӢҳ. кіөмӢқ нҳ„мһ¬к°Җ/мІҙкІ°/мҠӨлғ…мғ·мңјлЎң мөңлҢҖн•ң л№„мҠ·н•ҳкІҢ л§Ңл“  мң мӮ¬ мҲңмң„', '- 1л¶„мқҖ мҙҲмһ… к°җм§Җмҡ©. л°”лЎң л§ӨмҲҳ/paper л“ұлЎқ м•„лӢҳ', f"- кё°мӨҖ: м „мІҙ м•ұмӢқлһӯнҒ¬ мәҗмӢң мҡ°м„  + rank snapshot ліҙмЎ° / мғқм„ұ {format_elapsed_text(age)} м „ / мҶҢмҡ” {safe_float(data.get('build_sec',0),0):.3f}s{stale}", '', '[лҙҮ кі„мӮ° мғҒмҠ№лҘ  TOP]']
    for label in ['1л¶„','3л¶„','15л¶„','30л¶„','1мӢңк°„']:
        bits=[]
        for val,_score,money,t,row in list(app.get(label) or [])[:max(1,int(top_n))]:
            if bool(row.get('low_liquidity_app_rank',False)):
                continue
            item=f"{t} {safe_float(val,0):+.2f}%"
            if safe_float(money,0)>=100_000_000:
                try: item += f"В·{format_money_compact_amount_krw(money)}"
                except Exception: pass
            src=str(row.get('cache_source','') or row.get('latest_price_source',''))
            if 'snapshot3m' in src: item+='В·snapshot3m'
            elif str(row.get('latest_price_source',''))=='ws_trade': item+='В·мІҙкІ°ліҙмҷ„'
            if label=='1л¶„':
                ag=safe_float(row.get('change_1_base_age_sec',0),0)
                if ag>0: item += f"В·кё°мӨҖ{ag:.0f}s"
            if label=='3л¶„':
                ag=safe_float(row.get('change_3_base_age_sec',0),0)
                item += f"В·кё°мӨҖ{ag:.0f}s" if ag>0 else 'В·кё°мӨҖ180s'
            cs=str(row.get('candle_summary_v286','') or _v286_candle_summary(row))
            if cs: item += f"В·{cs}"
            bits.append(item)
        lack_n=int(safe_float(lack.get(label,0),0))
        if label in {'15л¶„','30л¶„','1мӢңк°„'} and not bits and lack_n:
            lines.append(f"- {label}: н‘ңліёл¶ҖмЎұ / кі„мӮ° лҢҖкё° ({lack_n}к°ң)")
        else:
            suffix=f" / кё°мӨҖк°Җл¶ҖмЎұ {lack_n}к°ң" if lack_n and label in {'1л¶„','3л¶„'} else ''
            lines.append(f"- {label}: " + _v286_join(bits, limit=top_n, empty='кі„мӮ° к°ҖлҠҘн•ң мғҒмҠ№ м—ҶмқҢ') + suffix)
    low_bits=[]
    for val,_score,money,t,row in list(data.get('low_liquidity_rows') or [])[:8]:
        low_bits.append(f"{t} {safe_float(val,0):+.2f}%В·{_v286_exclude_reason(row)}")
    if low_bits:
        lines += ['', '[м Җмң лҸҷм„ұ/мІҙкІ°м•Ҫн•Ё кёүл“ұ]', '- ' + _v286_join(low_bits, limit=8)]
    strategy=data.get('strategy') or []; overlap=data.get('overlap') or []; app_only=data.get('app_only') or []; bot_only=data.get('bot_only') or []; repeated=data.get('repeated') or []; early=data.get('early_both') or []; one=data.get('one_min_only') or []
    lines += ['', '[мҙҲмһ… нӣ„ліҙ]', '- 1л¶„+3л¶„ лҸҷмӢң: '+_v286_join([_v286_format_app_item(t, counts.get(t)) for t in early], limit=10), '- 1л¶„л§Ң кёүл“ұ: '+_v286_join([_v286_format_app_item(t, counts.get(t)) for t in one], limit=10)+(' / 3л¶„ мң м§Җ нҷ•мқё н•„мҡ”' if one else ''), '', '[мҡ°лҰ¬ лҙҮ м „лһө мҲңмң„ TOP]', '- '+_v286_join(strategy, limit=8), '', '[л№„көҗ кІ°кіј]', '- кІ№м№Ё: '+_v286_join(overlap, limit=8), '- м•ұмӢқ only лҶ“м№Ёнӣ„ліҙ: '+_v286_join([_v286_format_app_item(t, counts.get(t), include_reason=True) for t in app_only], limit=12), '- лҙҮ only лӢЁлҸ…нӣ„ліҙ: '+_v286_join(bot_only, limit=10), '- л°ҳліөмғҒмң„: '+_v286_join([_v286_format_app_item(t, counts.get(t)) for t in repeated], limit=10), f"- м „мІҙ м•ұмӢқмәҗмӢң rows {len(data.get('rows') or [])} / rank snapshot ліҙмҷ„ {safe_float(data.get('fallback3_count',0),0):.0f}к°ң / мәҗмӢңлӮҳмқҙ {PAPER_V286_STATS.get('cache_age_sec',9999)}мҙҲ", '- лӮҙл¶Җк°җмӢң: мқҙ лӘ…л №мқҖ мқҪкё°м „мҡ©. м•ұмӢқ onlyлҠ” н‘ёмӢң/paper мһҗлҸҷл“ұлЎқ м•Ҳ н•Ё', '', '[нҢҗлӢЁлІ•]', '- м•ұмӢқ onlyлҠ” м „мІҙ мӢңмһҘм—җм„ңлҠ” нҠҖлҠ”лҚ° м „лһө нӣ„ліҙм—җлҠ” м•Ҫн•ң лҶ“м№Ё кІҖмҰқ нӣ„ліҙ', '- м „мІҙлһӯнҒ¬ мӨҖл№„мӨ‘мқҙл©ҙ мһ„мӢңлЎң rank snapshot ліҙмЎ°к°’мқ„ ліҙм—¬мӨҖлӢӨ. л№—мҚё м•ұ мӣҗліёмқҖ м•„лӢҳ.']
    PAPER_V286_STATS['last_note']='rank_compare text'; PAPER_V286_STATS['cache_age_sec']=round(time.time()-safe_float(_RANK_COMPARE_V286_BG_CACHE.get('ts',0),0),1) if _RANK_COMPARE_V286_BG_CACHE.get('ts') else 9999.0
    return '\n'.join(lines).strip()


