def _v286_app_signal_note(ticker):
    try:
        t=_v286_norm(ticker)
        data=_v286_get_compare_data()
        row=(data.get('row_by_ticker') or {}).get(t)
        info=(data.get('app_counts') or {}).get(t)
        if isinstance(info,dict):
            PAPER_V286_STATS['signal_hint']=int(safe_float(PAPER_V286_STATS.get('signal_hint',0),0))+1
            return '- л§ӨмҲҳ нӣ„ліҙм—җлҠ” м—ҶмқҢ / лҙҮкі„мӮ° м•ұмӢқмҲңмң„: ' + _v286_format_app_item(t, info) + ' / л§ӨмҲҳмӢ нҳё м•„лӢҳ'
        if isinstance(row,dict):
            c1=safe_float(row.get('change_1',0),0); c3=safe_float(row.get('change_3',0),0)
            r1='к°ҖлҠҘ' if row.get('change_1_ready') else 'кё°мӨҖк°Җл¶ҖмЎұ'; r3='к°ҖлҠҘ' if row.get('change_3_ready') else 'кё°мӨҖк°Җл¶ҖмЎұ'
            src=str(row.get('latest_price_source','') or row.get('cache_source','') or '-')
            return f"- л§ӨмҲҳ нӣ„ліҙм—җлҠ” м—ҶмқҢ / м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬ мһҲмқҢ: 1л¶„ {c1:+.2f}%({r1}) / 3л¶„ {c3:+.2f}%({r3}) / мөңмӢ к°Җ {src} / л§ӨмҲҳмӢ нҳё м•„лӢҳ"
        return '- л§ӨмҲҳ нӣ„ліҙм—җлҠ” м—ҶмқҢ / м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҸ„ мөңк·ј н‘ңліё м—ҶмқҢ / нӢ°м»ӨлӘ… лҳҗлҠ” мғҒмһҘлӘ… нҷ•мқё н•„мҡ”'
    except Exception:
        return ''

def _v279_app_signal_note(ticker): return _v286_app_signal_note(ticker)

try:
    _V286_BASE_SIGNAL_TEXT = build_signal_text_v256
    def build_signal_text_v256(args=None, limit:int=None):
        args_list=list(args or []) if args is not None else []
        raw=str(args_list[0]) if args_list else ''
        resolved=_v286_norm(raw) if raw else raw
        text=str(_V286_BASE_SIGNAL_TEXT(args=[resolved] if raw else args, limit=limit))
        if raw:
            # кё°мЎҙ мӨ‘ліө нһҢнҠё м ңкұ° нӣ„ v286 нһҢнҠё 1нҡҢл§Ң мӮҪмһ…
            lines=[]
            for l in text.splitlines():
                if 'м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҸ„ мөңк·ј н‘ңліё м—ҶмқҢ' in l or 'м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬ мһҲмқҢ:' in l or 'м „мІҙ м•ұмӢқ нһҲмҠӨнҶ лҰ¬м—җлҠ” мһҲмқҢ:' in l or 'лҙҮкі„мӮ° м•ұмӢқмҲңмң„:' in l:
                    continue
                lines.append(l)
            text='\n'.join(lines).strip()
            note=_v286_app_signal_note(raw)
            if note:
                lines=text.splitlines(); insert_at=len(lines)
                for i,l in enumerate(lines):
                    if 'нӣ„ліҙ нҷ•мқё' in l or 'мғҒм„ё:' in l:
                        insert_at=i; break
                lines.insert(insert_at,note); text='\n'.join(lines).strip()
        return text
except Exception:
    pass

