                   f"- worker_build {PAPER_V286_STATS.get('worker_build',0)} / command_cache_hit {PAPER_V286_STATS.get('command_cache_hit',0)} / fallback {PAPER_V286_STATS.get('command_fallback',0)} / error {PAPER_V286_STATS.get('worker_error',0)}",
