        s = s.replace("м „мІҙм•ұмӢқлһӯнҒ¬ мәҗмӢңнҷ”/м°ЁнҠёмҡ”м•Ҫ ліҙк°•", "мӨ‘м•ҷ лӘ…л № лҚ°мқҙн„° н—ҲлёҢ/м•ұмӢқлһӯнҒ¬ к°ұмӢ  м ңн•ң")
