PAPER_V288_STATS = {
    "text_cache_hit": 0, "text_cache_miss": 0, "text_build": 0, "text_error": 0,
    "worker_build": 0, "worker_skip": 0, "worker_busy": 0, "worker_error": 0,
    "fallback_rank_only": 0, "history_lock_busy": 0, "history_budget_cut": 0,
    "history_rows": 0, "history_total": 0, "history_fresh": 0,
    "data_build_sec": 0.0, "text_build_sec": 0.0, "command_return_sec": 0.0,
    "cache_age_sec": 9999.0, "app_1m": 0, "app_3m": 0, "app_15m": 0,
    "overlap": 0, "app_only": 0, "bot_only": 0, "repeat": 0,
    "last_note": "лҢҖкё°",
}
RANK_COMPARE_V288_REFRESH_LOCK = threading.Lock()
RANK_COMPARE_V288_TEXT_CACHE = {"ts": 0.0, "text": "", "data": None, "source": "лҢҖкё°", "generation": 0}
RANK_COMPARE_V288_WORKER_MIN_INTERVAL_SEC = 18.0
RANK_COMPARE_V288_STALE_OK_SEC = 180.0
