def _v288_inc(key, note=""):
    try:
        PAPER_V288_STATS[key] = int(safe_float(PAPER_V288_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V288_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v288_norm(ticker):
    try:
        return _v286_norm(ticker) if '_v286_norm' in globals() else str(ticker or '').upper().strip().replace('KRW-', '').replace('_KRW', '')
    except Exception:
        return str(ticker or '').upper().strip()


def _v288_rank_rows():
    try:
        rows = _v286_rank_rows() if '_v286_rank_rows' in globals() else []
        return list(rows or []) if isinstance(rows, list) else []
    except Exception:
        return []


def _v288_copy_light_history_items():
    try:
        hist = globals().get("LIGHT_SNAPSHOT_HISTORY", {})
        if not isinstance(hist, dict):
            return []
        lock = globals().get("LIGHT_SNAPSHOT_LOCK")
        if lock is not None:
            try:
                acquired = bool(lock.acquire(False))
            except Exception:
                acquired = False
            if not acquired:
                _v288_inc("history_lock_busy", "history lock busy")
                return []
            try:
                return list(hist.items())
            finally:
                try:
                    lock.release()
                except Exception:
                    pass
        return list(hist.items())
    except Exception:
        return []


def _v288_latest_price_fast(ticker, valid_rows, now_ts=None):
    now_ts = safe_float(now_ts, time.time())
    t = _v288_norm(ticker)
    try:
        lock = globals().get("WS_TICKER_LOCK")
        if lock is not None:
            try:
                acquired = bool(lock.acquire(False))
            except Exception:
                acquired = False
            if acquired:
                try:
                    row = dict((globals().get("WS_TICKER_CACHE", {}) or {}).get(t) or {})
                finally:
                    try:
                        lock.release()
                    except Exception:
                        pass
                p = safe_float(row.get("price", 0), 0)
                ts = safe_float(row.get("ts", 0), 0)
                if p > 0 and ts > 0 and now_ts - ts <= safe_float(globals().get("WS_TICKER_CACHE_TTL_SEC", 20), 20):
                    return {"price": p, "ts": ts, "source": "ws_ticker", "turnover": safe_float(row.get("turnover", 0), 0)}
    except Exception:
        pass
    try:
        cache = globals().get("LIGHT_SNAPSHOT_BULK_PRICE_CACHE", {})
        if isinstance(cache, dict):
            p = safe_float(cache.get(t, 0), 0)
            ts = safe_float(globals().get("LIGHT_SNAPSHOT_BULK_PRICE_TS", 0), 0)
            if p > 0 and ts > 0 and now_ts - ts <= safe_float(globals().get("LIGHT_SNAPSHOT_BULK_STALE_KEEP_SEC", 30), 30):
                return {"price": p, "ts": ts, "source": "bulk_ticker", "turnover": 0.0}
    except Exception:
        pass
    try:
        best = None
        best_ts = 0.0
        for r in list(valid_rows or []):
            if not isinstance(r, dict):
                continue
            p = safe_float(r.get("price", 0), 0)
            ts = safe_float(r.get("ts", 0), 0)
            if p > 0 and ts > best_ts:
                best = r
                best_ts = ts
        if isinstance(best, dict):
            return {"price": safe_float(best.get("price", 0), 0), "ts": best_ts, "source": "light_history", "turnover": safe_float(best.get("turnover_hint", 0), 0)}
    except Exception:
        pass
    return {"price": 0.0, "ts": 0.0, "source": "missing", "turnover": 0.0}


def _v288_base_change_fast(valid_rows, seconds, current_price, now_ts=None):
    now_ts = safe_float(now_ts, time.time())
    current_price = safe_float(current_price, 0)
    out = {"value": 0.0, "ready": False, "base_age_sec": 0.0, "base_price": 0.0}
    if current_price <= 0:
        return out
    try:
        best = None
        best_gap = 10**9
        best_age = 0.0
        for r in list(valid_rows or []):
            if not isinstance(r, dict):
                continue
            p = safe_float(r.get("price", 0), 0)
            ts = safe_float(r.get("ts", 0), 0)
            if p <= 0 or ts <= 0:
                continue
            age = now_ts - ts
            if age <= 3:
                continue
            gap = abs(age - float(seconds))
            if gap < best_gap:
                best = r
                best_gap = gap
                best_age = age
        if not isinstance(best, dict):
            return out
        base = safe_float(best.get("price", 0), 0)
        if base <= 0:
            return out
        if seconds <= 60:
            ready = 42 <= best_age <= 95
        elif seconds <= 180:
            ready = 120 <= best_age <= 240
        else:
            ready = best_age >= seconds * 0.78
        return {"value": round(((current_price - base) / base) * 100.0, 2), "ready": bool(ready), "base_age_sec": round(best_age, 1), "base_price": base}
    except Exception:
        return out


def _v288_rank_map(rank_rows):
    out = {}
    try:
        for r in list(rank_rows or []):
            if isinstance(r, dict):
                t = _v288_norm(r.get("ticker"))
                if t and t not in out:
                    out[t] = r
    except Exception:
        pass
    return out


def _v288_enrich_with_rank(row, rank_row):
    try:
        if not isinstance(row, dict):
            return row
        rr = rank_row if isinstance(rank_row, dict) else {}
        keys = ("turnover_5m","turnover","trade_amount_60s","trade_count_60s","ws_trade_count_60s","buy_ratio_60s","buy_ratio","current_candle_status","candle_status","now_candle_status","candle_live_score","current_candle_live_score","candle_pullback_score","current_candle_pullback_score","score","snapshot_rank_score","rank_reason","reason","decision_reason","entry_layer_reason","watch_reason","tier_reason")
        for k in keys:
            if (k not in row or row.get(k) in (None, "", 0, 0.0)) and k in rr:
                row[k] = rr.get(k)
        try:
            row["low_liquidity_app_rank"] = bool(_v286_is_low_liquidity(row)) if '_v286_is_low_liquidity' in globals() else False
            row["exclude_reason_v286"] = _v286_exclude_reason(row) if '_v286_exclude_reason' in globals() else "м „лһө м җмҲҳ/к·јкұ° л¶ҖмЎұ"
            row["candle_summary_v286"] = _v286_candle_summary(row) if '_v286_candle_summary' in globals() else ""
        except Exception:
            pass
        return row
    except Exception:
        return row


def _v288_collect_history_rows_fast(max_seconds=None, max_tickers=None):
    t0 = time.time()
    now_ts = time.time()
    max_seconds = safe_float(max_seconds if max_seconds is not None else RANK_COMPARE_V288_BUILD_BUDGET_SEC, RANK_COMPARE_V288_BUILD_BUDGET_SEC)
    max_tickers = int(safe_float(max_tickers if max_tickers is not None else RANK_COMPARE_V288_MAX_HISTORY_TICKERS, RANK_COMPARE_V288_MAX_HISTORY_TICKERS))
    items = _v288_copy_light_history_items()
    rank_rows = _v288_rank_rows()
    rmap = _v288_rank_map(rank_rows)
    out = []
    fresh = 0
    cut = False
    PAPER_V288_STATS["history_total"] = len(items)
    for tk, rows in list(items)[:max(1, max_tickers)]:
        if time.time() - t0 > max_seconds:
            cut = True
            break
        try:
            ticker = _v288_norm(tk)
            if not ticker or ticker == "BTC":
                continue
            try:
                if 'is_watch_excluded_ticker' in globals() and is_watch_excluded_ticker(ticker):
                    continue
            except Exception:
                pass
            valid = [r for r in list(rows or [])[-80:] if isinstance(r, dict) and safe_float(r.get("price", 0), 0) > 0 and safe_float(r.get("ts", 0), 0) > 0]
            if not valid:
                continue
            latest = _v288_latest_price_fast(ticker, valid, now_ts=now_ts)
            price = safe_float(latest.get("price", 0), 0)
            latest_ts = safe_float(latest.get("ts", 0), 0)
            if price <= 0 or latest_ts <= 0 or now_ts - latest_ts > 180:
                continue
            fresh += 1
            i1 = _v288_base_change_fast(valid, 60, price, now_ts)
            i3 = _v288_base_change_fast(valid, 180, price, now_ts)
            i15 = _v288_base_change_fast(valid, 900, price, now_ts)
            i30 = _v288_base_change_fast(valid, 1800, price, now_ts)
            i60 = _v288_base_change_fast(valid, 3600, price, now_ts)
            row = {
                "ticker": ticker, "current_price": price, "price": price,
                "latest_price_source": latest.get("source", ""), "cache_source": "v288_light_history_fast",
                "latest_ts": latest_ts, "turnover": safe_float(latest.get("turnover", 0), 0),
                "change_1": i1.get("value", 0), "change_1_ready": i1.get("ready", False), "change_1_base_age_sec": i1.get("base_age_sec", 0),
                "change_3": i3.get("value", 0), "change_3_ready": i3.get("ready", False), "change_3_base_age_sec": i3.get("base_age_sec", 0),
                "change_15": i15.get("value", 0), "change_15_ready": i15.get("ready", False), "change_15_base_age_sec": i15.get("base_age_sec", 0),
                "change_30": i30.get("value", 0), "change_30_ready": i30.get("ready", False), "change_30_base_age_sec": i30.get("base_age_sec", 0),
                "change_60": i60.get("value", 0), "change_60_ready": i60.get("ready", False), "change_60_base_age_sec": i60.get("base_age_sec", 0),
            }
            out.append(_v288_enrich_with_rank(row, rmap.get(ticker)))
        except Exception:
            continue
    if cut:
        _v288_inc("history_budget_cut", "history budget cut")
    PAPER_V288_STATS["history_rows"] = len(out)
    PAPER_V288_STATS["history_fresh"] = fresh
    return out, rank_rows, cut


def _v288_patch_text_age(text):
    try:
        age = max(0.0, time.time() - safe_float(RANK_COMPARE_V288_TEXT_CACHE.get("ts", 0), 0))
        PAPER_V288_STATS["cache_age_sec"] = round(age, 1)
        age_txt = format_elapsed_text(age) if 'format_elapsed_text' in globals() else f"{age:.0f}мҙҲ"
        s = str(text or "").replace("__AGE__", age_txt)
        if age > 90:
            s += "\n- вҡ пёҸ мәҗмӢңк°Җ 90мҙҲ мҙҲкіјлқј л§ӨмҲҳ нҢҗлӢЁ кёҲм§Җ. мөңмӢ  мҲңмң„лҠ” лӢӨмқҢ мәҗмӢң к°ұмӢ  нӣ„ нҷ•мқё."
        return s
    except Exception:
        return str(text or "")


def _v288_store_compare_cache(data, text, source):
    try:
        now_ts = time.time()
        gen = int(safe_float(RANK_COMPARE_V288_TEXT_CACHE.get("generation", 0), 0)) + 1
        RANK_COMPARE_V288_TEXT_CACHE.update({"ts": now_ts, "text": str(text or ""), "data": data if isinstance(data, dict) else {}, "source": str(source or "")[:80], "generation": gen})
        try:
            if "_RANK_COMPARE_V286_BG_CACHE" in globals():
                _RANK_COMPARE_V286_BG_CACHE.update({"ts": now_ts, "data": data, "build_sec": safe_float((data or {}).get("build_sec", 0), 0), "note": source})
        except Exception:
            pass
    except Exception:
        pass


def _v288_make_text_from_data(data):
    t0 = time.time()
    try:
        # кё°мЎҙ нҸ¬л§Өн„°лҘј н•ң лІҲл§Ң мӮ¬мҡ©н•ҙ мөңмў…л¬ёкө¬лҘј л§Ңл“ лӢӨ. мқҙнӣ„ лӘ…л №м–ҙлҠ” мқҙ кІ°кіјл§Ң мқҪлҠ”лӢӨ.
        if isinstance(_V288_BASE_RANK_COMPARE_TEXT, type(lambda: None)):
            text = _V288_BASE_RANK_COMPARE_TEXT(args=None, top_n=10)
        else:
            text = ""
    except Exception as e:
        _v288_inc("text_error", str(e))
        text = ""
    if not text:
        # к·№лӢЁм Ғ мҳӨлҘҳ fallback
        text = "рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare\n- v288 rank_compare н…ҚмҠӨнҠё мәҗмӢң мғқм„ұ мӨ‘. /cache_status нҷ•мқё н•„мҡ”."
    text = str(text).replace("м „мІҙ м•ұмӢқлһӯнҒ¬ мәҗмӢң мҡ°м„  + rank snapshot ліҙмЎ°", "v288 мөңмў…м¶ңл Ҙ мәҗмӢң / лӘ…л №м–ҙ м§Ғм ‘кі„мӮ° м—ҶмқҢ")
    text = text.replace(" / мҶҢмҡ” ", " / лҚ°мқҙн„°мғқм„ұ ")
    # кё°мЎҙ нҸ¬л§Өн„°лҠ” мҶҢмҡ”лҘј лҚ°мқҙн„° build_secлЎң ліҙм—¬мЈјлҜҖлЎң, лӘ…л №м–ҙ м§Ғм ‘кі„мӮ°мқҙ м•„лӢҳмқ„ лӘ…нҷ•нһҲ м¶”к°Җн•ңлӢӨ.
    if "лӘ…л №м–ҙ м§Ғм ‘кі„мӮ° м—ҶмқҢ" not in text.splitlines()[3:6]:
        lines = text.splitlines()
        if len(lines) >= 4:
            lines.insert(4, f"- v288: мқҙ м¶ңл ҘмқҖ лҜёлҰ¬ л§Ңл“  н…ҚмҠӨнҠё мәҗмӢңм•ј. лӘ…л №м–ҙлҠ” м „мІҙ 449к°ңлҘј лӢӨмӢң кі„мӮ°н•ҳм§Җ м•ҠмқҢ.")
            text = "\n".join(lines)
    PAPER_V288_STATS["text_build_sec"] = round(time.time() - t0, 4)
    _v288_inc("text_build", "rank_compare final text cached")
    return text


def _v288_refresh_rank_compare_text_cache(reason="worker", force=False):
    now_ts = time.time()
    try:
        age = now_ts - safe_float(RANK_COMPARE_V288_TEXT_CACHE.get("ts", 0), 0) if safe_float(RANK_COMPARE_V288_TEXT_CACHE.get("ts", 0), 0) > 0 else 9999.0
        if (not force) and age < RANK_COMPARE_V288_WORKER_MIN_INTERVAL_SEC:
            _v288_inc("worker_skip", f"skip fresh {age:.1f}s")
            return RANK_COMPARE_V288_TEXT_CACHE.get("data")
        if not RANK_COMPARE_V288_REFRESH_LOCK.acquire(False):
            _v288_inc("worker_busy", "busy")
            return RANK_COMPARE_V288_TEXT_CACHE.get("data")
        try:
            t0 = time.time()
            _v288_inc("worker_build", reason)
            rows, rank_rows, cut = _v288_collect_history_rows_fast(max_seconds=RANK_COMPARE_V288_BUILD_BUDGET_SEC, max_tickers=RANK_COMPARE_V288_MAX_HISTORY_TICKERS)
            source = "v288_light_history_fast_cut" if cut else "v288_light_history_fast"
            if not rows:
                _v288_inc("fallback_rank_only", "rank fallback")
                source = "v288_rank_snapshot_fallback"
            data = _v286_make_compare_data(rows=rows, rank_rows=rank_rows, source=source) if '_v286_make_compare_data' in globals() else {}
            if not isinstance(data, dict):
                data = {}
            data["source"] = source
            data["created_ts"] = time.time()
            data["build_sec"] = round(time.time() - t0, 4)
            _v288_store_compare_cache(data, "", source)
            text = _v288_make_text_from_data(data)
            _v288_store_compare_cache(data, text, source)
            PAPER_V288_STATS.update({
                "data_build_sec": round(time.time() - t0, 4),
                "app_1m": len(((data.get("app") or {}).get("1л¶„") or [])),
                "app_3m": len(((data.get("app") or {}).get("3л¶„") or [])),
                "app_15m": len(((data.get("app") or {}).get("15л¶„") or [])),
                "overlap": len(data.get("overlap") or []),
                "app_only": len(data.get("app_only") or []),
                "bot_only": len(data.get("bot_only") or []),
                "repeat": len(data.get("repeated") or []),
                "last_note": f"{reason} {source}",
            })
            return data
        finally:
            try:
                RANK_COMPARE_V288_REFRESH_LOCK.release()
            except Exception:
                pass
    except Exception as e:
        _v288_inc("worker_error", str(e))
        try:
            append_runtime_error_log("rank_compare_v288_refresh", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return RANK_COMPARE_V288_TEXT_CACHE.get("data")


def _v288_get_rank_compare_text():
    t0 = time.time()
    try:
        txt = str(RANK_COMPARE_V288_TEXT_CACHE.get("text", "") or "")
        ts = safe_float(RANK_COMPARE_V288_TEXT_CACHE.get("ts", 0), 0)
        if txt and ts > 0 and time.time() - ts <= RANK_COMPARE_V288_STALE_OK_SEC:
            _v288_inc("text_cache_hit", "rank_compare text cache hit")
            PAPER_V288_STATS["command_return_sec"] = round(time.time() - t0, 4)
            return _v288_patch_text_age(txt)
        _v288_inc("text_cache_miss", "rank_compare text miss")
        # лӘ…л №м–ҙм—җм„ңлҠ” м „мІҙ нһҲмҠӨнҶ лҰ¬ мҲҳм§‘ кёҲм§Җ. rank snapshot fallbackл§Ң мҰүмӢң л§Ңл“ лӢӨ.
        rank_rows = _v288_rank_rows()
        data = _v286_make_compare_data(rows=[], rank_rows=rank_rows, source="v288_command_rank_fallback") if '_v286_make_compare_data' in globals() else {}
        if isinstance(data, dict):
            data["app_rank_preparing"] = True
            data["created_ts"] = time.time()
            data["build_sec"] = 0.0
        _v288_store_compare_cache(data, "", "v288_command_rank_fallback")
        txt = _v288_make_text_from_data(data if isinstance(data, dict) else {})
        _v288_store_compare_cache(data, txt, "v288_command_rank_fallback")
        PAPER_V288_STATS["command_return_sec"] = round(time.time() - t0, 4)
        return _v288_patch_text_age(txt)
    except Exception as e:
        _v288_inc("text_error", str(e))
        PAPER_V288_STATS["command_return_sec"] = round(time.time() - t0, 4)
        try:
            append_runtime_error_log("rank_compare_v288_command", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return "рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare\n- v288 rank_compare мәҗмӢң мҳӨлҘҳ. /cache_statusмҷҖ /errorlog нҷ•мқё н•„мҡ”."


