def _v289_data(rows=None, rank=None, source="v289"):
    data = _ORIG_V293_V289_DATA(rows, rank, source) if callable(_ORIG_V293_V289_DATA) else {}
    try:
        if not isinstance(data, dict):
            data = {}
        diag = dict(RANK_COMPARE_V293_DIAG)
        final_rows = len(rows or []) if rows is not None else int(safe_float(diag.get("final_rows", 0), 0))
        diag["final_rows"] = final_rows
        diag["fallback_used"] = bool(data.get("rank_snapshot_only")) or final_rows <= 0 or "fallback" in str(source or "").lower() or "rank_snapshot" in str(source or "").lower()
        diag["primary_reason"] = _v293_rank_primary_reason(diag)
        diag["mode"] = "м •мғҒ м „мІҙ м•ұмӢқлһӯнҒ¬" if final_rows >= V293_RANK_COMPARE_MIN_FULL_ROWS and not diag["fallback_used"] else "мһ„мӢң rank snapshot л№„көҗ"
        data["rank_compare_diag_v293"] = diag
        data["rows_count_v293"] = final_rows
        data["full_rank_ready_v293"] = bool(diag["mode"] == "м •мғҒ м „мІҙ м•ұмӢқлһӯнҒ¬")
        if final_rows < V293_RANK_COMPARE_MIN_FULL_ROWS or diag["fallback_used"]:
            data["rank_snapshot_only"] = True
            data["app_rank_preparing"] = True
    except Exception:
        pass
    return data


