def _v293_btc_caller_lines(limit: int = 5) -> list:
    try:
        rows = sorted(BTC_V293_CALLER_STATS.items(), key=lambda kv: safe_float((kv[1] or {}).get("last_ts", 0), 0), reverse=True)
        out = []
        for caller, v in rows[:max(1, int(limit))]:
            out.append(f"{caller}: {int(safe_float(v.get('count',0),0))}нҡҢ / readonly_hit {int(safe_float(v.get('readonly_hit',0),0))} / readonly_miss {int(safe_float(v.get('readonly_miss',0),0))} / fetch {int(safe_float(v.get('fetch_pass',0),0))} / мөңк·ј {v.get('last','')}")
        return out
    except Exception:
        return []


