def _v294_norm_ticker(ticker: str) -> str:
    try:
        t = str(ticker or "").upper().strip()
        if t.startswith("KRW-"):
            t = t.split("-", 1)[1]
        if t.endswith("_KRW"):
            t = t[:-4]
        return t.strip()
    except Exception:
        return ""


def _v294_stage_reason_add(reasons: list, name: str):
    try:
        name = str(name or "").strip()
        if name and name not in reasons:
            reasons.append(name)
    except Exception:
        pass


def _v294_copy_light_history() -> dict:
    try:
        lock = globals().get("LIGHT_SNAPSHOT_LOCK")
        hist = globals().get("LIGHT_SNAPSHOT_HISTORY", {})
        if not isinstance(hist, dict):
            return {}
        if lock is not None:
            with lock:
                return {str(k).upper().strip(): list(v[-180:] if isinstance(v, list) else []) for k, v in hist.items()}
        return {str(k).upper().strip(): list(v[-180:] if isinstance(v, list) else []) for k, v in hist.items()}
    except Exception:
        return {}


