def build_rank_compare_text_v279(args=None, top_n: int = 10):
    txt = _ORIG_V294_BUILD_RANK_COMPARE_TEXT(args=args, top_n=top_n) if callable(_ORIG_V294_BUILD_RANK_COMPARE_TEXT) else _v289_get_text()
    try:
        if "рҹҸӯ v2.5.294 кіөмһҘ кё°мӨҖ" not in str(txt or ""):
            lines = str(txt or "").splitlines()
            insert_at = 1
            for idx, line in enumerate(lines[:16]):
                if "rows мӣҗмқёл¶„н•ҙ" in line or "v2.5.293" in line or "v2.5.292" in line:
                    insert_at = idx
                    break
            lines[insert_at:insert_at] = _v294_factory_rank_compare_lines()
            txt = "\n".join(lines)
    except Exception:
        pass
    return txt


