def _v295_norm_interval(interval: str) -> str:
    key = str(interval or "").lower().strip()
    aliases = {"1m": "minute1", "3m": "minute3", "5m": "minute5", "10m": "minute10", "15m": "minute15", "30m": "minute30", "60m": "minute60", "1h": "minute60", "4h": "minute240", "240m": "minute240", "1d": "day"}
    return aliases.get(key, key)


def _v295_interval_sec(interval: str) -> int:
    key = _v295_norm_interval(interval)
    for name, sec in FACTORY_V295_SELF_INTERVALS:
        if name == key:
            return int(sec)
    return 60


def _v295_connect_db():
    import sqlite3
    conn = sqlite3.connect(FACTORY_V295_DB_FILE, timeout=0.35)
    try:
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute("PRAGMA temp_store=MEMORY")
    except Exception:
        pass
    return conn


def _v295_init_db() -> bool:
    try:
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db()
            cur = conn.cursor()
            cur.execute("CREATE TABLE IF NOT EXISTS factory_meta (key TEXT PRIMARY KEY, value TEXT, updated_ts REAL)")
            cur.execute("""
                CREATE TABLE IF NOT EXISTS self_ohlcv (
                    ticker TEXT NOT NULL,
                    interval TEXT NOT NULL,
                    candle_start_ts INTEGER NOT NULL,
                    candle_end_ts INTEGER NOT NULL,
                    open REAL, high REAL, low REAL, close REAL,
                    volume REAL DEFAULT 0,
                    amount REAL DEFAULT 0,
                    buy_amount REAL DEFAULT 0,
                    sell_amount REAL DEFAULT 0,
                    sample_count INTEGER DEFAULT 0,
                    source TEXT,
                    confidence REAL DEFAULT 0,
                    closed INTEGER DEFAULT 0,
                    created_at REAL,
                    updated_at REAL,
                    PRIMARY KEY (ticker, interval, candle_start_ts)
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS ohlcv_verify (
                    ticker TEXT NOT NULL,
                    interval TEXT NOT NULL,
                    candle_start_ts INTEGER NOT NULL,
                    self_open REAL, self_high REAL, self_low REAL, self_close REAL,
                    rest_open REAL, rest_high REAL, rest_low REAL, rest_close REAL,
                    close_diff_pct REAL,
                    high_diff_pct REAL,
                    low_diff_pct REAL,
                    result TEXT,
                    note TEXT,
                    verified_at REAL,
                    PRIMARY KEY (ticker, interval, candle_start_ts)
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS factory_state_snapshot (
                    ticker TEXT PRIMARY KEY,
                    updated_ts REAL,
                    price REAL,
                    change_1 REAL,
                    change_3 REAL,
                    change_5 REAL,
                    change_10 REAL,
                    change_15 REAL,
                    from_low REAL,
                    below_high REAL,
                    turnover REAL,
                    trade_count_60 INTEGER,
                    trade_count_180 INTEGER,
                    factory_score REAL,
                    factory_stage TEXT,
                    stage2_reason TEXT,
                    data_confidence TEXT,
                    missing_info TEXT
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS miss_cause_log (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    ticker TEXT,
                    detected_ts REAL,
                    miss_stage TEXT,
                    reason TEXT,
                    action_taken TEXT,
                    raw_json TEXT
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS cleanup_log (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    cleaned_at REAL,
                    table_name TEXT,
                    interval TEXT,
                    deleted_rows INTEGER,
                    note TEXT
                )
            """)
            cur.execute("INSERT OR REPLACE INTO factory_meta(key,value,updated_ts) VALUES(?,?,?)", ("schema_version", str(FACTORY_V295_SCHEMA_VERSION), time.time()))
            cur.execute("INSERT OR REPLACE INTO factory_meta(key,value,updated_ts) VALUES(?,?,?)", ("bot_version", str(BOT_VERSION), time.time()))
            conn.commit()
            conn.close()
        FACTORY_V295_STATS["db_ok"] = True
        FACTORY_V295_STATS["schema_version"] = FACTORY_V295_SCHEMA_VERSION
        return True
    except Exception as e:
        FACTORY_V295_STATS["db_ok"] = False
        globals()["FACTORY_V295_LAST_ERROR"] = str(e)[:160]
        try:
            append_runtime_error_log("factory_v295_db_init", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return False


def _v295_db_size_mb() -> float:
    try:
        if os.path.exists(FACTORY_V295_DB_FILE):
            return round(os.path.getsize(FACTORY_V295_DB_FILE) / 1024 / 1024, 2)
    except Exception:
        pass
    return 0.0


def _v295_kst_timestamp_parts(ts: float):
    try:
        dt = datetime.fromtimestamp(float(ts), ZoneInfo(TIMEZONE))
        return dt
    except Exception:
        return now_kst()


def _v295_candle_start_ts(ts: float, interval: str) -> int:
    """KST кё°мӨҖ candle_start_ts. кІҖмҰқмқҖ ticker+interval+candle_start_tsк°Җ к°ҷмқҖ лҙүлҒјлҰ¬л§Ң н•ңлӢӨ."""
    try:
        key = _v295_norm_interval(interval)
        dt = _v295_kst_timestamp_parts(ts)
        if key == "day":
            dt0 = dt.replace(hour=0, minute=0, second=0, microsecond=0)
            return int(dt0.timestamp())
        if key == "minute240":
            h = (dt.hour // 4) * 4
            dt0 = dt.replace(hour=h, minute=0, second=0, microsecond=0)
            return int(dt0.timestamp())
        sec = _v295_interval_sec(key)
        if sec >= 3600:
            hour_span = max(1, sec // 3600)
            h = (dt.hour // hour_span) * hour_span
            dt0 = dt.replace(hour=h, minute=0, second=0, microsecond=0)
            return int(dt0.timestamp())
        minute_span = max(1, sec // 60)
        m = (dt.minute // minute_span) * minute_span
        dt0 = dt.replace(minute=m, second=0, microsecond=0)
        return int(dt0.timestamp())
    except Exception:
        sec = _v295_interval_sec(interval)
        return int(math.floor(float(ts) / sec) * sec)


def _v295_closed_candle(ts: float, interval: str, now_ts: float = None) -> bool:
    try:
        now_ts = time.time() if now_ts is None else float(now_ts)
        start = _v295_candle_start_ts(ts, interval)
        return now_ts >= start + _v295_interval_sec(interval) + 1.0
    except Exception:
        return False


def _v295_build_self_candles_from_rows(ticker: str, rows: list, trade_rows: list = None, now_ts: float = None) -> dict:
    """к°ҖкІ© нһҲмҠӨнҶ лҰ¬/мІҙкІ° нһҲмҠӨнҶ лҰ¬лЎң мһҗмІҙ OHLCVлҘј л§Ңл“ лӢӨ. REST нҳём¶ң м—ҶмқҢ."""
    now_ts = time.time() if now_ts is None else safe_float(now_ts, time.time())
    out = {}
    try:
        valid = _v294_valid_price_rows(rows) if '_v294_valid_price_rows' in globals() else []
        if not valid:
            return out
        trade_rows = trade_rows if isinstance(trade_rows, list) else []
        for interval, sec in FACTORY_V295_SELF_INTERVALS:
            # н•ҙлӢ№ interval кё°мӨҖ мөңк·ј 3к°ң лҙүл§Ң л§Ңл“ лӢӨ. DBм—җлҠ” мөңмӢ  лӢ«нһҢ лҙү мӨ‘мӢ¬ м ҖмһҘ.
            buckets = {}
            for r0 in valid:
                ts = safe_float(r0.get("ts", 0), 0)
                price = safe_float(r0.get("price", 0), 0)
                if ts <= 0 or price <= 0:
                    continue
                # л„Ҳл¬ҙ мҳӨлһҳлҗң raw к°ҖкІ©мқҖ мһҗмІҙлҙү мғқм„ұм—җм„ң м ңмҷё. кёҙ лҙүмқҖ DB лҲ„м ҒмңјлЎң ліҙк°•н•ңлӢӨ.
                if now_ts - ts > max(sec * 4, 6 * 3600):
                    continue
                start = _v295_candle_start_ts(ts, interval)
                b = buckets.setdefault(start, {"ticker": ticker, "interval": interval, "candle_start_ts": int(start), "candle_end_ts": int(start + sec), "open": price, "high": price, "low": price, "close": price, "sample_count": 0, "first_ts": ts, "last_ts": ts, "amount": 0.0, "buy_amount": 0.0, "sell_amount": 0.0})
                if ts < b.get("first_ts", ts):
                    b["first_ts"] = ts
                    b["open"] = price
                if ts >= b.get("last_ts", 0):
                    b["last_ts"] = ts
                    b["close"] = price
                b["high"] = max(safe_float(b.get("high", price), price), price)
                b["low"] = min(safe_float(b.get("low", price), price), price)
                b["sample_count"] = int(b.get("sample_count", 0)) + 1
            # мІҙкІ°кёҲм•ЎмқҖ к°ҷмқҖ мӢңк°„лҢҖм—җл§Ң н•©мӮ°
            try:
                for tr in trade_rows:
                    if not isinstance(tr, dict):
                        continue
                    ts = safe_float(tr.get("ts", 0), 0)
                    if ts <= 0 or now_ts - ts > max(sec * 4, 6 * 3600):
                        continue
                    start = _v295_candle_start_ts(ts, interval)
                    b = buckets.get(start)
                    if not b:
                        continue
                    amount = safe_float(tr.get("amount", 0), 0)
                    b["amount"] = safe_float(b.get("amount", 0), 0) + max(0.0, amount)
                    side = str(tr.get("side", "") or "").lower()
                    if side == "buy":
                        b["buy_amount"] = safe_float(b.get("buy_amount", 0), 0) + max(0.0, amount)
                    elif side == "sell":
                        b["sell_amount"] = safe_float(b.get("sell_amount", 0), 0) + max(0.0, amount)
            except Exception:
                pass
            closed = []
            forming = []
            for start, b in buckets.items():
                b["closed"] = 1 if now_ts >= start + sec + 1.0 else 0
                # мӢ лў°лҸ„: н‘ңліё мҲҳ + лҙү мӢңк°„ м»ӨлІ„ + мІҙкІ° мң л¬ҙ
                cover = max(0.0, safe_float(b.get("last_ts", 0), 0) - safe_float(b.get("first_ts", 0), 0))
                conf = 0.35
                if b.get("closed"):
                    conf += 0.25
                if cover >= max(20.0, sec * 0.50):
                    conf += 0.20
                if int(b.get("sample_count", 0)) >= 3:
                    conf += 0.12
                if safe_float(b.get("amount", 0), 0) > 0:
                    conf += 0.08
                b["confidence"] = round(min(1.0, conf), 3)
                if b["closed"]:
                    closed.append(b)
                else:
                    forming.append(b)
            closed.sort(key=lambda x: int(x.get("candle_start_ts", 0)))
            forming.sort(key=lambda x: int(x.get("candle_start_ts", 0)))
            chosen = closed[-1] if closed else (forming[-1] if forming else None)
            if chosen:
                out[interval] = chosen
    except Exception:
        return out
    return out


def _v295_rest_df_to_candle(df, interval: str, candle_start_ts: int):
    try:
        if df is None or len(df) <= 0:
            return None
        key = _v295_norm_interval(interval)
        for idx, row in list(df.tail(FACTORY_V295_REST_VERIFY_MAX_CACHED_ROWS).iterrows()):
            try:
                # pybithumb indexк°Җ naive datetimeмқҙл©ҙ KSTлЎң н•ҙм„қн•ңлӢӨ.
                if hasattr(idx, 'to_pydatetime'):
                    dt = idx.to_pydatetime()
                elif isinstance(idx, datetime):
                    dt = idx
                else:
                    continue
                if dt.tzinfo is None:
                    dt = dt.replace(tzinfo=ZoneInfo(TIMEZONE))
                ts = dt.timestamp()
                start = _v295_candle_start_ts(ts, key)
                if int(start) != int(candle_start_ts):
                    continue
                return {
                    "open": safe_float(row.get("open", 0), 0),
                    "high": safe_float(row.get("high", 0), 0),
                    "low": safe_float(row.get("low", 0), 0),
                    "close": safe_float(row.get("close", 0), 0),
                    "volume": safe_float(row.get("volume", 0), 0),
                }
            except Exception:
                continue
    except Exception:
        return None
    return None


def _v295_verify_self_candle_against_cached_rest(ticker: str, candle: dict) -> dict:
    """к°ҷмқҖ ticker+interval+candle_start_tsмқҳ лӢ«нһҢ лҙүл§Ң REST мәҗмӢңмҷҖ л№„көҗ. мғҲ REST нҳём¶ң м—ҶмқҢ."""
    result = {"checked": False, "result": "cached_rest_missing", "note": "REST мәҗмӢң м—ҶмқҢ"}
    try:
        if not isinstance(candle, dict):
            return result
        interval = _v295_norm_interval(candle.get("interval", ""))
        start_ts = int(safe_float(candle.get("candle_start_ts", 0), 0))
        if not start_ts or not int(safe_float(candle.get("closed", 0), 0)):
            return {"checked": False, "result": "not_closed", "note": "м§„н–ү мӨ‘ лҙүмқҖ кІҖмҰқ м ңмҷё"}
        cache_key = (str(ticker).upper().strip(), interval)
        df = get_api_cache_entry(API_OHLCV_CACHE, cache_key, get_ohlcv_cache_ttl(interval) * 20, copy_dataframe=True) if 'get_api_cache_entry' in globals() else None
        rest = _v295_rest_df_to_candle(df, interval, start_ts)
        if not rest:
            FACTORY_V295_STATS["verify_cached_rest_miss"] = int(FACTORY_V295_STATS.get("verify_cached_rest_miss", 0)) + 1
            return result
        self_close = safe_float(candle.get("close", 0), 0)
        self_high = safe_float(candle.get("high", 0), 0)
        self_low = safe_float(candle.get("low", 0), 0)
        rest_close = safe_float(rest.get("close", 0), 0)
        rest_high = safe_float(rest.get("high", 0), 0)
        rest_low = safe_float(rest.get("low", 0), 0)
        def diff_pct(a, b):
            a = safe_float(a, 0); b = safe_float(b, 0)
            if a <= 0 or b <= 0:
                return 999.0
            return abs(a - b) / max(abs(b), 1e-12) * 100.0
        close_d = diff_pct(self_close, rest_close)
        high_d = diff_pct(self_high, rest_high)
        low_d = diff_pct(self_low, rest_low)
        if close_d <= 0.10 and high_d <= 0.35 and low_d <= 0.35:
            res = "pass"
        elif close_d <= 0.35 and high_d <= 0.80 and low_d <= 0.80:
            res = "warn"
        else:
            res = "fail"
        row = {
            "checked": True, "result": res, "note": f"close {close_d:.3f}% / high {high_d:.3f}% / low {low_d:.3f}%",
            "close_diff_pct": round(close_d, 4), "high_diff_pct": round(high_d, 4), "low_diff_pct": round(low_d, 4),
            "rest": rest,
        }
        try:
            _v295_store_verify_result(ticker, interval, start_ts, candle, rest, row)
        except Exception:
            pass
        FACTORY_V295_VERIFY_RECENT.append({"ticker": ticker, "interval": interval, "start": start_ts, "result": res, "note": row["note"], "ts": time.time()})
        return row
    except Exception as e:
        return {"checked": False, "result": "error", "note": str(e)[:80]}


def _v295_store_verify_result(ticker: str, interval: str, start_ts: int, self_candle: dict, rest: dict, cmp_row: dict):
    try:
        if not _v295_init_db():
            return
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db(); cur = conn.cursor(); now_ts = time.time()
            cur.execute("""
                INSERT OR REPLACE INTO ohlcv_verify(
                    ticker, interval, candle_start_ts,
                    self_open, self_high, self_low, self_close,
                    rest_open, rest_high, rest_low, rest_close,
                    close_diff_pct, high_diff_pct, low_diff_pct, result, note, verified_at
                ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """, (
                str(ticker).upper().strip(), _v295_norm_interval(interval), int(start_ts),
                safe_float(self_candle.get("open", 0), 0), safe_float(self_candle.get("high", 0), 0), safe_float(self_candle.get("low", 0), 0), safe_float(self_candle.get("close", 0), 0),
                safe_float(rest.get("open", 0), 0), safe_float(rest.get("high", 0), 0), safe_float(rest.get("low", 0), 0), safe_float(rest.get("close", 0), 0),
                safe_float(cmp_row.get("close_diff_pct", 0), 0), safe_float(cmp_row.get("high_diff_pct", 0), 0), safe_float(cmp_row.get("low_diff_pct", 0), 0),
                str(cmp_row.get("result", "")), str(cmp_row.get("note", ""))[:200], now_ts,
            ))
            conn.commit(); conn.close()
    except Exception:
        pass


def _v295_should_verify_row(row: dict, idx: int = 0) -> bool:
    try:
        if not isinstance(row, dict):
            return False
        if bool(row.get("stage3_candidate_v294", False)):
            return True
        score = safe_float(row.get("factory_score_v294", 0), 0)
        ch = max(abs(safe_float(row.get("change_1", 0), 0)), abs(safe_float(row.get("change_3", 0), 0)), abs(safe_float(row.get("change_5", 0), 0)))
        if score >= 2.0 or ch >= 0.8:
            return (idx % max(1, FACTORY_V295_STRONG_VERIFY_DIVISOR)) == 0
        return (idx % max(1, FACTORY_V295_GENERAL_VERIFY_DIVISOR)) == 0
    except Exception:
        return False


def _v295_add_missing_request(row: dict, key: str, priority: str, reason: str):
    try:
        ticker = str((row or {}).get("ticker", "")).upper().strip()
        if not ticker or not key:
            return
        k = f"{ticker}:{key}"
        item = FACTORY_V295_MISSING_INFO_REQUESTS.get(k, {"ticker": ticker, "key": key, "count": 0, "priority": priority, "reason": reason, "last_ts": 0.0})
        item["count"] = int(item.get("count", 0)) + 1
        item["priority"] = priority if priority in {"кёҙкёү", "ліҙнҶө", "лӮ®мқҢ"} else item.get("priority", "ліҙнҶө")
        item["reason"] = reason
        item["last_ts"] = time.time()
        FACTORY_V295_MISSING_INFO_REQUESTS[k] = item
        # л„Ҳл¬ҙ мҳӨлһҳлҗң мҡ”мІӯ мІӯмҶҢ
        now_ts = time.time()
        for old_k in list(FACTORY_V295_MISSING_INFO_REQUESTS.keys())[:2000]:
            if now_ts - safe_float(FACTORY_V295_MISSING_INFO_REQUESTS.get(old_k, {}).get("last_ts", 0), 0) > 3600:
                FACTORY_V295_MISSING_INFO_REQUESTS.pop(old_k, None)
    except Exception:
        pass


try:
    _ORIG_V295_V294_FACTORY_ROW = _v294_factory_row
except Exception:
    _ORIG_V295_V294_FACTORY_ROW = None


def _v294_factory_row(ticker: str, hist_rows: list, ws_row: dict, trade_rows: list, bulk_price: float, rank_row: dict, now_ts: float) -> dict:
    row = _ORIG_V295_V294_FACTORY_ROW(ticker, hist_rows, ws_row, trade_rows, bulk_price, rank_row, now_ts) if callable(_ORIG_V295_V294_FACTORY_ROW) else {}
    try:
        ticker = _v294_norm_ticker(ticker) if '_v294_norm_ticker' in globals() else str(ticker).upper().strip()
        candles = _v295_build_self_candles_from_rows(ticker, hist_rows or [], trade_rows=trade_rows or [], now_ts=now_ts)
        row["factory_v295"] = True
        row["self_ohlcv_source_v295"] = "price_history+ws_trade"
        row["self_ohlcv_intervals_v295"] = sorted(list(candles.keys()))
        row["_v295_self_candles"] = candles
        confidence_bits = []
        for interval in ["minute1", "minute3", "minute5", "minute10", "minute15", "minute30", "minute60", "minute240", "day"]:
            c = candles.get(interval, {}) if isinstance(candles, dict) else {}
            short = {"minute1":"1m", "minute3":"3m", "minute5":"5m", "minute10":"10m", "minute15":"15m", "minute30":"30m", "minute60":"60m", "minute240":"4h", "day":"day"}.get(interval, interval)
            ready = bool(c and int(safe_float(c.get("closed", 0), 0)) == 1)
            row[f"self_ohlcv_{short}_ready_v295"] = ready
            row[f"self_ohlcv_{short}_confidence_v295"] = safe_float(c.get("confidence", 0), 0) if c else 0.0
            if ready:
                confidence_bits.append(f"{short}:{safe_float(c.get('confidence',0),0):.2f}")
                # нҒ° лҙүлҸ„ мөңк·ј кі м Җм җ/мғҒмң„нқҗлҰ„ ліҙмЎ°м—җ м“°лҸ„лЎқ к°ҖкІ© мҡ”м•Ҫмқ„ мӢ¬лҠ”лӢӨ.
                if interval == "minute1":
                    row["current_candle_change_pct"] = round(((safe_float(c.get("close",0),0) - safe_float(c.get("open",0),0)) / max(safe_float(c.get("open",0),0), 1e-12)) * 100.0, 3)
                    row["current_candle_upper_wick_pct"] = round(((safe_float(c.get("high",0),0) - max(safe_float(c.get("open",0),0), safe_float(c.get("close",0),0))) / max(max(safe_float(c.get("open",0),0), safe_float(c.get("close",0),0)), 1e-12)) * 100.0, 3)
                    row["current_candle_lower_wick_pct"] = round(((min(safe_float(c.get("open",0),0), safe_float(c.get("close",0),0)) - safe_float(c.get("low",0),0)) / max(min(safe_float(c.get("open",0),0), safe_float(c.get("close",0),0)), 1e-12)) * 100.0, 3)
        row["self_ohlcv_confidence_text_v295"] = ", ".join(confidence_bits[:8]) if confidence_bits else "мһҗмІҙлҙү н‘ңліё л¶ҖмЎұ"
        # л¶ҖмЎұм •ліҙ мҡ”мІӯ: м—ҶлҠ” м •ліҙлЎң л°”лЎң ліҙлҘҳн•ҳм§Җ м•Ҡкі , мҡ”мІӯ м°Ҫкі м—җ лӮЁкёҙлӢӨ.
        if not row.get("self_ohlcv_1m_ready_v295"):
            _v295_add_missing_request(row, "self_1m", "ліҙнҶө", "мһҗмІҙ 1л¶„лҙү л¶ҖмЎұ")
        if not row.get("self_ohlcv_5m_ready_v295") and safe_float(row.get("factory_score_v294", 0), 0) >= 1.2:
            _v295_add_missing_request(row, "self_5m", "кёҙкёү", "2м°Ё нӣ„ліҙ мһҗмІҙ 5л¶„лҙү л¶ҖмЎұ")
        if int(safe_float(row.get("ws_trade_count_180s", 0), 0)) <= 0:
            _v295_add_missing_request(row, "trade_3m", "ліҙнҶө", "3л¶„ мІҙкІ°м°Ҫкі  л¶ҖмЎұ")
    except Exception as e:
        try:
            append_runtime_error_log("factory_v295_row", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
    return row


try:
    _ORIG_V295_V294_SCORE_FACTORY_ROW = _v294_score_factory_row
except Exception:
    _ORIG_V295_V294_SCORE_FACTORY_ROW = None


def _v294_score_factory_row(row: dict, previous: dict = None) -> dict:
    row = _ORIG_V295_V294_SCORE_FACTORY_ROW(row, previous=previous) if callable(_ORIG_V295_V294_SCORE_FACTORY_ROW) else (row or {})
    try:
        if not isinstance(row, dict):
            return row
        # мһҗмІҙлҙүмқҙ мӨҖл№„лҗң кІҪмҡ° 2м°Ё м§Ғмӣҗл“Өмқҙ м“ё мҲҳ мһҲкІҢ ліҙмЎ° м җмҲҳл§Ң м¶”к°Җн•ңлӢӨ. кё°мЎҙ м „лһө мЎ°кұҙмқҖ мӮӯм ңн•ҳм§Җ м•ҠлҠ”лӢӨ.
        boost = 0.0
        if row.get("self_ohlcv_1m_ready_v295"):
            boost += 0.10
        if row.get("self_ohlcv_3m_ready_v295"):
            boost += 0.10
        if row.get("self_ohlcv_5m_ready_v295"):
            boost += 0.12
        if row.get("self_ohlcv_60m_ready_v295"):
            boost += 0.08
        # м •ліҙ мӢ лў°лҸ„ л¬ёкө¬
        ready_count = sum(1 for k, v in row.items() if str(k).startswith("self_ohlcv_") and str(k).endswith("_ready_v295") and bool(v))
        if ready_count >= 5:
            conf_label = "мһҗмІҙм°Ҫкі  мўӢмқҢ"
        elif ready_count >= 3:
            conf_label = "мһҗмІҙм°Ҫкі  ліҙнҶө"
        elif ready_count >= 1:
            conf_label = "мһҗмІҙм°Ҫкі  мқјл¶Җ"
        else:
            conf_label = "мһҗмІҙм°Ҫкі  л¶ҖмЎұ"
        row["data_confidence_v295"] = conf_label
        row["factory_score_v295_bonus"] = round(boost, 3)
        row["factory_score_v294"] = round(safe_float(row.get("factory_score_v294", 0), 0) + boost, 3)
        row["snapshot_rank_score"] = round(max(safe_float(row.get("snapshot_rank_score", 0), 0), safe_float(row.get("factory_score_v294", 0), 0)), 3)
        # signal/paper м•Ҳм „: кІҖмҰқ мӢӨнҢЁк°Җ м°ҚнһҢ мҪ”мқёмқҖ м§„мһ… м ңн•ң н”Ңлһҳк·ёл§Ң м„ёмҡҙлӢӨ.
        if str(row.get("self_ohlcv_verify_result_v295", "")) == "fail":
            row["factory_signal_block_v295"] = True
            row["factory_signal_block_reason_v295"] = "мһҗмІҙлҙү/RESTлҙү л¶Ҳмқјм№ҳ"
    except Exception:
        pass
    return row


try:
    _ORIG_V295_V294_REFRESH_STATS = _v294_refresh_stats
except Exception:
    _ORIG_V295_V294_REFRESH_STATS = None


def _v294_refresh_stats(stage1: dict, stage2: dict, stage3: dict, all_tickers: list):
    if callable(_ORIG_V295_V294_REFRESH_STATS):
        _ORIG_V295_V294_REFRESH_STATS(stage1, stage2, stage3, all_tickers)
    try:
        rows = list(stage1.values()) if isinstance(stage1, dict) else []
        def cnt(key):
            return sum(1 for r in rows if isinstance(r, dict) and bool(r.get(key, False)))
        FACTORY_V295_STATS.update({
            "self_ohlcv_1m": cnt("self_ohlcv_1m_ready_v295"),
            "self_ohlcv_3m": cnt("self_ohlcv_3m_ready_v295"),
            "self_ohlcv_5m": cnt("self_ohlcv_5m_ready_v295"),
            "self_ohlcv_10m": cnt("self_ohlcv_10m_ready_v295"),
            "self_ohlcv_15m": cnt("self_ohlcv_15m_ready_v295"),
            "self_ohlcv_30m": cnt("self_ohlcv_30m_ready_v295"),
            "self_ohlcv_60m": cnt("self_ohlcv_60m_ready_v295"),
            "self_ohlcv_4h": cnt("self_ohlcv_4h_ready_v295"),
            "self_ohlcv_day": cnt("self_ohlcv_day_ready_v295"),
            "db_size_mb": _v295_db_size_mb(),
        })
    except Exception:
        pass


def _v295_persist_factory_rows(stage1: dict):
    global FACTORY_V295_LAST_PERSIST_TS
    try:
        now_ts = time.time()
        if now_ts - safe_float(FACTORY_V295_LAST_PERSIST_TS, 0) < FACTORY_V295_PERSIST_INTERVAL_SEC:
            return
        if not isinstance(stage1, dict) or not stage1:
            return
        if not _v295_init_db():
            return
        snapshot_rows = []
        candle_rows = []
        for ticker, row in stage1.items():
            if not isinstance(row, dict):
                continue
            snapshot_rows.append((
                str(ticker).upper().strip(), now_ts, safe_float(row.get("price", 0), 0),
                safe_float(row.get("change_1", 0), 0), safe_float(row.get("change_3", 0), 0), safe_float(row.get("change_5", 0), 0), safe_float(row.get("change_10", 0), 0), safe_float(row.get("change_15", 0), 0),
                safe_float(row.get("from_low", 0), 0), safe_float(row.get("below_high", 999), 999), safe_float(row.get("turnover", 0), 0),
                int(safe_float(row.get("ws_trade_count_60s", 0), 0)), int(safe_float(row.get("ws_trade_count_180s", 0), 0)),
                safe_float(row.get("factory_score_v294", 0), 0), str(row.get("factory_stage", "")), str(row.get("factory_stage2_reason_text_v294", "")),
                str(row.get("data_confidence_v295", "")), str(row.get("self_ohlcv_confidence_text_v295", "")),
            ))
            for interval, c in (row.get("_v295_self_candles", {}) or {}).items():
                if not isinstance(c, dict):
                    continue
                candle_rows.append((
                    str(ticker).upper().strip(), _v295_norm_interval(interval), int(safe_float(c.get("candle_start_ts", 0), 0)), int(safe_float(c.get("candle_end_ts", 0), 0)),
                    safe_float(c.get("open", 0), 0), safe_float(c.get("high", 0), 0), safe_float(c.get("low", 0), 0), safe_float(c.get("close", 0), 0),
                    safe_float(c.get("volume", 0), 0), safe_float(c.get("amount", 0), 0), safe_float(c.get("buy_amount", 0), 0), safe_float(c.get("sell_amount", 0), 0),
                    int(safe_float(c.get("sample_count", 0), 0)), "self_v295", safe_float(c.get("confidence", 0), 0), int(safe_float(c.get("closed", 0), 0)), now_ts, now_ts,
                ))
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db(); cur = conn.cursor()
            cur.executemany("""
                INSERT OR REPLACE INTO factory_state_snapshot(
                    ticker, updated_ts, price, change_1, change_3, change_5, change_10, change_15, from_low, below_high, turnover,
                    trade_count_60, trade_count_180, factory_score, factory_stage, stage2_reason, data_confidence, missing_info
                ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """, snapshot_rows)
            cur.executemany("""
                INSERT OR REPLACE INTO self_ohlcv(
                    ticker, interval, candle_start_ts, candle_end_ts, open, high, low, close, volume, amount, buy_amount, sell_amount,
                    sample_count, source, confidence, closed, created_at, updated_at
                ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            """, candle_rows)
            conn.commit(); conn.close()
        FACTORY_V295_LAST_PERSIST_TS = now_ts
        FACTORY_V295_STATS["persist_rows"] = len(snapshot_rows)
        FACTORY_V295_STATS["persist_candles"] = len(candle_rows)
        FACTORY_V295_STATS["last_persist_ts"] = now_ts
        FACTORY_V295_STATS["db_size_mb"] = _v295_db_size_mb()
        FACTORY_V295_STATS["last_note"] = f"мғҒнғң {len(snapshot_rows)}к°ң / мһҗмІҙлҙү {len(candle_rows)}к°ң м ҖмһҘ"
    except Exception as e:
        globals()["FACTORY_V295_LAST_ERROR"] = str(e)[:160]
        try:
            append_runtime_error_log("factory_v295_persist", str(e), exc=e, include_traceback=False)
        except Exception:
            pass


def _v295_run_sample_verification(stage1: dict):
    try:
        if not isinstance(stage1, dict) or not stage1:
            return
        checked = passed = warned = failed = 0
        rows = sorted([r for r in stage1.values() if isinstance(r, dict)], key=lambda x: safe_float(x.get("factory_score_v294", 0), 0), reverse=True)
        for idx, row in enumerate(rows):
            if checked >= FACTORY_V295_MAX_VERIFY_PER_BUILD:
                break
            if not _v295_should_verify_row(row, idx=idx):
                continue
            ticker = str(row.get("ticker", "")).upper().strip()
            candles = row.get("_v295_self_candles", {}) or {}
            # к°ҷмқҖ мӢңк°„лҢҖ л№„көҗ. нҳ„мһ¬ м§„н–ү мӨ‘мқё лҙүмқҖ м ңмҷё. мҡ°м„  1m/3m/5m, мқҙнӣ„ нҒ° лҙүмқҖ мәҗмӢң мһҲмқ„ л•Ңл§Ң.
            for interval in ["minute1", "minute3", "minute5", "minute15", "minute60", "minute240", "day"]:
                c = candles.get(interval)
                if not c or not int(safe_float(c.get("closed", 0), 0)):
                    continue
                cmp_row = _v295_verify_self_candle_against_cached_rest(ticker, c)
                if not cmp_row.get("checked"):
                    continue
                checked += 1
                res = str(cmp_row.get("result", ""))
                if res == "pass": passed += 1
                elif res == "warn": warned += 1
                elif res == "fail": failed += 1
                row["self_ohlcv_verify_result_v295"] = res
                row["self_ohlcv_verify_note_v295"] = str(cmp_row.get("note", ""))
                break
        FACTORY_V295_STATS["verify_checked"] = int(FACTORY_V295_STATS.get("verify_checked", 0)) + checked
        FACTORY_V295_STATS["verify_pass"] = int(FACTORY_V295_STATS.get("verify_pass", 0)) + passed
        FACTORY_V295_STATS["verify_warn"] = int(FACTORY_V295_STATS.get("verify_warn", 0)) + warned
        FACTORY_V295_STATS["verify_fail"] = int(FACTORY_V295_STATS.get("verify_fail", 0)) + failed
    except Exception:
        pass


def _v295_cleanup_storage(force: bool = False):
    global FACTORY_V295_LAST_CLEANUP_TS
    try:
        now_ts = time.time()
        if (not force) and now_ts - safe_float(FACTORY_V295_LAST_CLEANUP_TS, 0) < FACTORY_V295_CLEANUP_INTERVAL_SEC:
            return
        if not _v295_init_db():
            return
        deleted_total = 0
        with FACTORY_V295_DB_LOCK:
            conn = _v295_connect_db(); cur = conn.cursor()
            for interval, keep_sec in FACTORY_V295_INTERVAL_RETENTION_SEC.items():
                cutoff = int(now_ts - keep_sec)
                # мқјлҙү/4мӢңк°„лҙү/кІҖмҰқкІ°кіјлҠ” кёёкІҢ ліҙкҙҖ. к°Ғ interval м •мұ…ліҙлӢӨ м§§кІҢ м§Җмҡ°м§Җ м•ҠлҠ”лӢӨ.
                cur.execute("DELETE FROM self_ohlcv WHERE interval=? AND candle_start_ts<?", (interval, cutoff))
                deleted = cur.rowcount if cur.rowcount is not None else 0
                deleted_total += max(0, deleted)
                if deleted:
                    cur.execute("INSERT INTO cleanup_log(cleaned_at,table_name,interval,deleted_rows,note) VALUES(?,?,?,?,?)", (now_ts, "self_ohlcv", interval, int(deleted), "interval retention cleanup"))
            # 1л…„ м§ҖлӮң кІҖмҰқ кІ°кіјлҠ” м ңкұ° к°ҖлҠҘ. лҶ“м№Ё/л§Өл§Ө н•өмӢ¬кё°лЎқмқҖ м—¬кё°м„ң м§Җмҡ°м§Җ м•ҠлҠ”лӢӨ.
            cur.execute("DELETE FROM ohlcv_verify WHERE verified_at<?", (now_ts - 400 * 24 * 3600,))
            deleted_v = cur.rowcount if cur.rowcount is not None else 0
            if deleted_v:
                deleted_total += max(0, deleted_v)
                cur.execute("INSERT INTO cleanup_log(cleaned_at,table_name,interval,deleted_rows,note) VALUES(?,?,?,?,?)", (now_ts, "ohlcv_verify", "all", int(deleted_v), "long retention cleanup"))
            conn.commit(); conn.close()
        FACTORY_V295_LAST_CLEANUP_TS = now_ts
        FACTORY_V295_STATS["last_cleanup_deleted"] = deleted_total
        FACTORY_V295_STATS["last_cleanup_ts"] = now_ts
        FACTORY_V295_STATS["db_size_mb"] = _v295_db_size_mb()
    except Exception as e:
        globals()["FACTORY_V295_LAST_ERROR"] = str(e)[:160]


def _v295_backup_db(force: bool = False):
    global FACTORY_V295_LAST_BACKUP_TS
    try:
        now_ts = time.time()
        if (not force) and now_ts - safe_float(FACTORY_V295_LAST_BACKUP_TS, 0) < FACTORY_V295_BACKUP_INTERVAL_SEC:
            return
        if not os.path.exists(FACTORY_V295_DB_FILE):
            return
        import shutil
        stamp = datetime.fromtimestamp(now_ts, ZoneInfo(TIMEZONE)).strftime("%Y%m%d_%H%M")
        dst = data_file(f"coin_factory_store_backup_{stamp}.sqlite3")
        shutil.copy2(FACTORY_V295_DB_FILE, dst)
        backups = sorted([p for p in os.listdir(BASE_DIR) if p.startswith("coin_factory_store_backup_") and p.endswith(".sqlite3")])
        if len(backups) > FACTORY_V295_BACKUP_KEEP:
            for old in backups[:-FACTORY_V295_BACKUP_KEEP]:
                try:
                    os.remove(data_file(old))
                except Exception:
                    pass
        FACTORY_V295_LAST_BACKUP_TS = now_ts
        FACTORY_V295_STATS["last_backup_ts"] = now_ts
    except Exception:
        pass


try:
    _ORIG_V295_BUILD_CENTRAL_DATA_FACTORY = build_central_data_factory_v294
except Exception:
    _ORIG_V295_BUILD_CENTRAL_DATA_FACTORY = None


def build_central_data_factory_v294(force: bool = False) -> dict:
    """v295: v294 кіөмһҘмқ„ мһ¬мӮ¬мҡ©н•ҳлҗҳ, м§§мқҖ мӢңк°„ м•Ҳм—җлҠ” мҷ„м„ұн’Ҳмқ„ мһ¬мӮ¬мҡ©н•ҳкі  мҳҒкө¬м°Ҫкі /кІҖмҰқ/мІӯмҶҢлҘј л¶ҷмқёлӢӨ."""
    try:
        now_ts = time.time()
        # лӘ…л №м–ҙ мәҗмӢңк°Җ м—¬лҹ¬ лӢЁкі„м—җм„ң кіөмһҘмқ„ кі„мҶҚ л¶ҖлҘҙл©ҙ лі‘лӘ©мқҙ лҗҳлҜҖлЎң, мөңк·ј мҷ„м„ұліёмқҖ мһ¬мӮ¬мҡ©н•ңлӢӨ.
        if (not force) and isinstance(globals().get("DATA_FACTORY_V294_STAGE1", {}), dict) and DATA_FACTORY_V294_STAGE1:
            if now_ts - safe_float(globals().get("DATA_FACTORY_V294_LAST_BUILD_TS", 0), 0) < FACTORY_V295_BUILD_REUSE_SEC:
                return dict(DATA_FACTORY_V294_STAGE1)
        out = _ORIG_V295_BUILD_CENTRAL_DATA_FACTORY(force=force) if callable(_ORIG_V295_BUILD_CENTRAL_DATA_FACTORY) else {}
        stage1 = globals().get("DATA_FACTORY_V294_STAGE1", {}) if isinstance(globals().get("DATA_FACTORY_V294_STAGE1", {}), dict) else {}
        _v295_persist_factory_rows(stage1)
        _v295_run_sample_verification(stage1)
        _v295_cleanup_storage(force=False)
        _v295_backup_db(force=False)
        return out
    except Exception as e:
        try:
            append_runtime_error_log("factory_v295_build_wrapper", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return _ORIG_V295_BUILD_CENTRAL_DATA_FACTORY(force=force) if callable(_ORIG_V295_BUILD_CENTRAL_DATA_FACTORY) else {}


def _v295_missing_request_summary(limit: int = 5) -> str:
    try:
        vals = list(FACTORY_V295_MISSING_INFO_REQUESTS.values())
        vals.sort(key=lambda x: (safe_float(x.get("count", 0), 0), safe_float(x.get("last_ts", 0), 0)), reverse=True)
        if not vals:
            return "м—ҶмқҢ"
        return ", ".join([f"{v.get('key')} {int(v.get('count',0))}нҡҢ/{v.get('priority','ліҙнҶө')}" for v in vals[:limit]])
    except Exception:
        return "нҷ•мқёмӢӨнҢЁ"


