def _v296_mark_light_row(row: dict) -> dict:
    try:
        if not isinstance(row, dict):
            return row
        row["factory_v296_light_mode"] = True
        row["self_ohlcv_source_v295"] = "v296_light_skip_in_command_cache"
        row["self_ohlcv_confidence_text_v295"] = "v296 лқјмқҙнҠёлӘЁл“ң: мһҗмІҙлҙү лҢҖлҹүмғқм„ұмқҖ лӘ…л №м–ҙ мәҗмӢңм—җм„ң м ңмҷё"
        for short in ["1m", "3m", "5m", "10m", "15m", "30m", "60m", "4h", "day"]:
            row.setdefault(f"self_ohlcv_{short}_ready_v295", False)
            row.setdefault(f"self_ohlcv_{short}_confidence_v295", 0.0)
        row.setdefault("data_confidence_v295", "мһҗмІҙлҙү лқјмқҙнҠёлӘЁл“ң")
    except Exception:
        pass
    return row


def _v294_factory_row(ticker: str, hist_rows: list, ws_row: dict, trade_rows: list, bulk_price: float, rank_row: dict, now_ts: float) -> dict:
    global FACTORY_V296_BYPASS_HEAVY_ROW_COUNT
    try:
        if callable(_ORIG_V296_BASE_FACTORY_ROW):
            row = _ORIG_V296_BASE_FACTORY_ROW(ticker, hist_rows, ws_row, trade_rows, bulk_price, rank_row, now_ts)
        else:
            row = {}
        FACTORY_V296_BYPASS_HEAVY_ROW_COUNT += 1
        return _v296_mark_light_row(row)
    except Exception as e:
        try:
            append_runtime_error_log("factory_v296_light_row", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return {}


