def build_central_data_factory_v294(force: bool = False) -> dict:
    global FACTORY_V296_LAST_BUILD_TS, FACTORY_V296_LAST_BUILD_SEC, FACTORY_V296_LAST_NOTE, FACTORY_V296_REUSE_COUNT, FACTORY_V296_DB_SKIP_COUNT
    start_ts = time.time()
    try:
        now_ts = start_ts
        cached = globals().get("DATA_FACTORY_V294_STAGE1", {})
        last_ts = safe_float(globals().get("DATA_FACTORY_V294_LAST_BUILD_TS", 0), 0)
        if (not force) and isinstance(cached, dict) and cached and now_ts - last_ts < FACTORY_V296_FACTORY_REUSE_SEC:
            FACTORY_V296_REUSE_COUNT += 1
            FACTORY_V296_LAST_NOTE = f"мөңк·ј кіөмһҘ мҷ„м„ұліё мһ¬мӮ¬мҡ©({format_elapsed_text(now_ts-last_ts)} м „)"
            return dict(cached)
        out = _ORIG_V296_HEAVY_BUILD_FACTORY(force=force) if callable(_ORIG_V296_HEAVY_BUILD_FACTORY) else {}
        FACTORY_V296_DB_SKIP_COUNT += 1
        FACTORY_V296_LAST_BUILD_TS = time.time()
        FACTORY_V296_LAST_BUILD_SEC = round(time.time() - start_ts, 3)
        FACTORY_V296_LAST_NOTE = "DB/кІҖмҰқ/мІӯмҶҢлҠ” лӘ…л №м–ҙ мәҗмӢң кІҪлЎңм—җм„ң мғқлһө"
        return out
    except Exception as e:
        FACTORY_V296_LAST_NOTE = f"мҳӨлҘҳ: {str(e)[:80]}"
        try:
            append_runtime_error_log("factory_v296_build", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return globals().get("DATA_FACTORY_V294_STAGE1", {}) if isinstance(globals().get("DATA_FACTORY_V294_STAGE1", {}), dict) else {}


def _v296_status_lines() -> list:
    try:
        age = time.time() - safe_float(globals().get("DATA_FACTORY_V294_LAST_BUILD_TS", 0), 0) if safe_float(globals().get("DATA_FACTORY_V294_LAST_BUILD_TS", 0), 0) else 0
        db_mb = _v295_db_size_mb() if '_v295_db_size_mb' in globals() else 0.0
        return [
            "рҹӘ¶ v2.5.296 кіөмһҘ/м¶ңл Ҙ кІҪлҹүнҷ”",
            f"- лқјмқҙнҠёлӘЁл“ң: {'мјңм§җ' if FACTORY_V296_LIGHT_MODE_ON else 'кәјм§җ'} / мһҗмІҙлҙү лҢҖлҹүмғқм„ұ {'лӘ…л №м–ҙкІҪлЎң м ңмҷё' if FACTORY_V296_SKIP_SELF_CANDLE_IN_CACHE else 'н—Ҳмҡ©'} / DBм“°кё° {'лӘ…л №м–ҙкІҪлЎң м ңмҷё' if FACTORY_V296_SKIP_DB_WRITE_IN_CACHE else 'н—Ҳмҡ©'}",
            f"- кіөмһҘ мһ¬мӮ¬мҡ©: {FACTORY_V296_REUSE_COUNT}нҡҢ / мөңк·ј кіөмһҘ {format_elapsed_text(age)} м „ / мөңк·ј л№Ңл“ң {FACTORY_V296_LAST_BUILD_SEC:.2f}s",
            f"- л¬ҙкұ°мҡҙ row мҡ°нҡҢ: {FACTORY_V296_BYPASS_HEAVY_ROW_COUNT}нҡҢ / DBВ·кІҖмҰқ мғқлһө {FACTORY_V296_DB_SKIP_COUNT}нҡҢ / DB {db_mb:.2f}MB мң м§Җ",
            f"- мөңк·ј л©”лӘЁ: {FACTORY_V296_LAST_NOTE}",
            "- лң»: v295 м°Ҫкі  л°©н–ҘмқҖ мң м§Җн•ҳм§Җл§Ң, н…”л Ҳк·ёлһЁ лӘ…л №м–ҙ мәҗмӢңлҠ” м ҖмһҘлҗң кіөмһҘ кІ°кіјл§Ң л№ лҘҙкІҢ мқҪкІҢ лҗҳлҸҢлҰј",
        ]
    except Exception as e:
        return ["рҹӘ¶ v2.5.296 кіөмһҘ/м¶ңл Ҙ кІҪлҹүнҷ”", f"- н‘ңмӢң мҳӨлҘҳ: {e}"]


def _v296_compact_legacy_sections(text: str) -> str:
    try:
        body = str(text or "")
        marker = "рҹ—Ӯ мқҙм „ лІ„м „ м•Ҳм •нҷ” мҡ”м•Ҫ"
        if marker not in body:
            return body.rstrip() + "\n\n" + "\n".join(_v296_status_lines())
        head = body.split(marker, 1)[0].rstrip()
        compact = [
            marker,
            "- v253~v295 кёҙ мғҒм„ёлҠ” мөңмӢ  мқёмҲҳмқёкі„ нҢҢмқјм—җ ліҙмЎҙ",
            "- н…”л Ҳк·ёлһЁ мҡҙмҳҒ м¶ңл Ҙм—җм„ңлҠ” мөңк·ј лі‘лӘ©/кіөмһҘ мғҒнғңл§Ң н‘ңмӢң",
            "- кёёкІҢ нҷ•мқён•  л•Ңл§Ң /review_dump лҳҗлҠ” мқёмҲҳмқёкі„ нҢҢмқј нҷ•мқё",
            "",
        ]
        compact += _v296_status_lines()
        return head + "\n\n" + "\n".join(compact)
    except Exception:
        return str(text or "")


