def _v297_pretty_line_expand(line: str) -> list:
    """мҡҙмҳҒ м¶ңл Ҙм—җм„ң кёҙ н•ң мӨ„мқ„ лӘҮ мӨ„лЎң мӘјк° лӢӨ."""
    try:
        s = str(line or "")
        if s.startswith("- мөңк·ј мәҗмӢң лӢЁкі„лі„ мҶҢмҡ”:"):
            rest = s.split(":", 1)[1].strip()
            parts = [p.strip() for p in rest.split(",") if p.strip()]
            out = ["- мөңк·ј мәҗмӢң лӢЁкі„лі„ мҶҢмҡ”"]
            for p in parts[:8]:
                out.append(f"  В· {p}")
            return out
        if s.startswith("- WebSocket нҳ„мһ¬к°Җ:") or s.startswith("- WebSocket мІҙкІ°:"):
            title, rest = s.split(":", 1)
            parts = [p.strip() for p in rest.split("/") if p.strip()]
            out = [title + ":"]
            for p in parts[:7]:
                out.append(f"  В· {p}")
            if len(parts) > 7:
                out.append("  В· " + " / ".join(parts[7:]))
            return out
        if s.startswith("- rank мғҒнғңн‘ң:"):
            return ["- rank мғҒнғңн‘ң", "  В· " + s.split(":",1)[1].strip()]
        if s.startswith("- rank мғқм„ұ м№ҙмҡҙн„°:"):
            return ["- rank мғқм„ұ м№ҙмҡҙн„°", "  В· " + s.split(":",1)[1].strip()]
    except Exception:
        pass
    return [line]


def _v297_pretty_operational_text(text: str) -> str:
    if not bool(globals().get("FACTORY_V297_PRETTY_OUTPUT_ON", True)):
        return str(text or "")
    try:
        raw_lines = str(text or "").splitlines()
        section_heads = ("рҹҢҗ ", "рҹ“Ң ", "мҡҙмҳҒ кё°мӨҖ", "рҹ—Ӯ ", "рҹӘ¶ ", "рҹ§ұ ", "рҹҸӯ ", "рҹ—„ ", "рҹ§Ә ", "рҹ§Ҝ ", "[лҙҮ кі„мӮ°", "[мҙҲмһ…", "[мҡ°лҰ¬ лҙҮ", "[л№„көҗ", "[нҢҗлӢЁлІ•]")
        out = []
        prev_blank = True
        for line in raw_lines:
            is_head = any(str(line).startswith(h) for h in section_heads)
            if is_head and out and out[-1] != "":
                out.append("")
            expanded = _v297_pretty_line_expand(line)
            for e in expanded:
                if e == "":
                    if out and out[-1] != "":
                        out.append("")
                else:
                    out.append(e)
        # кіјн•ң м—°мҶҚ кіөл°ұ м ңкұ°
        compact = []
        for x in out:
            if x == "" and compact and compact[-1] == "":
                continue
            compact.append(x)
        return "\n".join(compact).strip()
    except Exception:
        return str(text or "")

