def _v298_today_summary_text() -> str:
    try:
        closes = get_closed_logs_today() if 'get_closed_logs_today' in globals() else []
        info = summarize_logs(closes) if 'summarize_logs' in globals() else {"total":0,"wins":0,"losses":0,"win_rate":0,"total_pnl":0,"avg_pnl":0}
        if not closes:
            return "\n".join([
                "рҹ“Ҡ мҳӨлҠҳ мҠ№лҘ  /today",
                "- мҳӨлҠҳ мў…лЈҢлҗң лӘЁмқҳл§Өл§Өк°Җ м•„м§Ғ м—Ҷм–ҙ.",
                "- м§„н–ү мӨ‘ нҸ¬м§Җм…ҳмқҖ /paper лҳҗлҠ” /paper_recentлЎң л”°лЎң нҷ•мқё",
                "- м „мІҙВ·мөңк·ј 12мӢңк°„ м„ұкіјлҠ” /paper_stats нҷ•мқё",
            ])
        recent = []
        for x in list(closes)[-8:]:
            try:
                recent.append(f"- {x.get('ticker','?')} / {x.get('type','?')} / {float(x.get('pnl_pct',0)):+.2f}%")
            except Exception:
                pass
        return "\n".join([
            "рҹ“Ҡ мҳӨлҠҳ мҠ№лҘ  /today",
            f"- мў…лЈҢ кұ°лһҳ: {info.get('total',0)}м „",
            f"- кІ°кіј: {info.get('wins',0)}мҠ№ {info.get('losses',0)}нҢЁ",
            f"- мҠ№лҘ : {float(info.get('win_rate',0)):.2f}%",
            f"- лҲ„м Ғ мҲҳмқөлҘ : {float(info.get('total_pnl',0)):+.2f}%",
            f"- нҸүк·  мҲҳмқөлҘ : {float(info.get('avg_pnl',0)):+.2f}%",
            "",
            "мөңк·ј мў…лЈҢ кұ°лһҳ",
            *(recent or ["- н‘ңмӢңн•  мөңк·ј кұ°лһҳ м—ҶмқҢ"]),
            "",
            "к°ҷмқҙ ліј кІғ: /paper_stats, /today_strategy",
        ])
    except Exception as e:
        return f"рҹ“Ҡ мҳӨлҠҳ мҠ№лҘ  /today\n- мғқм„ұ мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:120]}"


