def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    args = list(args or [])
    cmd_l = str(cmd or '').lower().strip()
    arg_preview = ' '.join([str(x) for x in args]).strip()
    shown_cmd = f"/{cmd_l}" + (f" {arg_preview}" if arg_preview else "")
    label = f"в–¶пёҸ л¬¶мқҢ {idx}/{total} {shown_cmd}" if total > 1 else f"в–¶пёҸ {shown_cmd}"
    if bool(globals().get("FACTORY_V298_TODAY_BATCH_ON", True)) and cmd_l in {'today', 'today_win', 'today_stats'}:
        send_text_chunks(_v298_today_summary_text(), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if bool(globals().get("FACTORY_V298_TODAY_BATCH_ON", True)) and cmd_l in {'today_strategy', 'strategy_today'}:
        send_text_chunks(_v298_today_strategy_text(), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if callable(_ORIG_V298_EXECUTE_SINGLE_BATCH_COMMAND):
        return _ORIG_V298_EXECUTE_SINGLE_BATCH_COMMAND(cmd, args, idx, total)
    send(f"{label}\n- batch мІҳлҰ¬ мӣҗліё н•ЁмҲҳлҘј м°ҫм§Җ лӘ»н–Ҳм–ҙ")

