def _v300_fmt_age(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "м•„м§Ғ м—ҶмқҢ"
        return format_elapsed_text(max(0.0, time.time() - ts)) + " м „"
    except Exception:
        return "нҷ•мқё м•Ҳ лҗЁ"


def _v300_slowest_stage_text(limit: int = 4) -> str:
    try:
        round0 = globals().get("COMMAND_DISPLAY_CACHE_STAGE_LAST_ROUND", {})
        if not isinstance(round0, dict) or not round0:
            return "лҢҖкё°"
        slow = sorted(round0.items(), key=lambda kv: safe_float(kv[1], 0), reverse=True)[:max(1, int(limit))]
        return ", ".join([f"{k} {safe_float(v,0):.2f}s" for k, v in slow])
    except Exception:
        return "нҷ•мқё м•Ҳ лҗЁ"


def _v300_ws_brief() -> str:
    try:
        chunks = []
        for fn_name in ("get_websocket_status_line", "get_ws_trade_status_line"):
            fn = globals().get(fn_name)
            if not callable(fn):
                continue
            s0 = str(fn() or "")
            if not s0:
                continue
            parts = [p.strip() for p in s0.split(' / ') if p.strip()]
            head = parts[:4]
            recent = [p for p in parts if p.startswith('мөңк·ј ')]
            if recent:
                head.append(recent[-1])
            chunks.append(' / '.join(head))
        return ' | '.join(chunks[:2])
    except Exception:
        return ''


def _v300_cache_status_summary_lines() -> list:
    try:
        complete_ts = safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_COMPLETE_TS', 0), 0) or safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_REFRESH_TS', 0), 0)
        fast_ts = safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_FAST_TS', 0), 0)
        long_ts = safe_float(globals().get('COMMAND_DISPLAY_CACHE_LAST_LONG_TS', 0), 0)
        complete_gen = globals().get('COMMAND_DISPLAY_CACHE_LAST_COMPLETE_GENERATION', 0) or globals().get('COMMAND_DISPLAY_CACHE_GENERATION', 0)
        building = bool(globals().get('COMMAND_DISPLAY_CACHE_WORKER_BUILDING', False))
        total_stage = safe_float(globals().get('COMMAND_DISPLAY_CACHE_STAGE_LAST_TOTAL_SEC', 0), 0)
        stage = str(globals().get('COMMAND_DISPLAY_CACHE_BUILD_STAGE', 'лҢҖкё°') or 'лҢҖкё°')
        rank_note = str(globals().get('RANK_STATE_LAST_NOTE', 'лҢҖкё°') or 'лҢҖкё°')
        rows = len(globals().get('COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS', []) or []) if isinstance(globals().get('COMMAND_DISPLAY_CACHE_LAST_RANK_ROWS', []), list) else 0
        bulk_ts = safe_float(globals().get('LIGHT_SNAPSHOT_LAST_BULK_SWEEP_TS', 0), 0)
        bulk_count = int(safe_float(globals().get('LIGHT_SNAPSHOT_LAST_BULK_SWEEP_COUNT', 0), 0))
        df_stats = globals().get('DATA_FACTORY_V294_STATS', {}) if isinstance(globals().get('DATA_FACTORY_V294_STATS', {}), dict) else {}
        price_n = int(safe_float(df_stats.get('price_warehouse', 0), 0))
        hist_n = int(safe_float(df_stats.get('history_warehouse', 0), 0))
        base1 = int(safe_float(df_stats.get('base_1m', 0), 0))
        base3 = int(safe_float(df_stats.get('base_3m', 0), 0))
        stage2 = int(safe_float(df_stats.get('stage2_total', 0), 0))
        stage3 = int(safe_float(df_stats.get('stage3_total', 0), 0))
        api = get_api_bottleneck_snapshot() if 'get_api_bottleneck_snapshot' in globals() else {}
        v299 = globals().get('FACTORY_V299_STATS', {}) if isinstance(globals().get('FACTORY_V299_STATS', {}), dict) else {}
        v299_avg = (safe_float(v299.get('row_sec',0),0) / max(1, int(v299.get('fast_row',0)))) * 1000.0
        lines = [
            "рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status",
            f"- мӢңк°Ғ: {now_kst().strftime('%m-%d %H:%M:%S')} / лІ„м „ {BOT_VERSION}",
            f"- мәҗмӢң: мҷ„м„ұ {_v300_fmt_age(complete_ts)} / л¬¶мқҢ#{complete_gen} / л№ лҘё {_v300_fmt_age(fast_ts)} / кёҙ {_v300_fmt_age(long_ts)}",
            f"- мӣҢм»Ө: {'мғқм„ұ мӨ‘' if building else 'лҢҖкё°'} / нҳ„мһ¬лӢЁкі„ {stage} / м„ұкіө {globals().get('COMMAND_DISPLAY_CACHE_DONE',0)} / мӢӨнҢЁ {globals().get('COMMAND_DISPLAY_CACHE_FAIL',0)}",
            f"- мөңк·ј мғқм„ұ: н•©кі„ {total_stage:.2f}s / лҠҗлҰ°мҲң {_v300_slowest_stage_text(4)}",
            f"- мҲңмң„: м ҖмһҘ row {rows} / {rank_note}",
            f"- кіөмһҘмһ¬лЈҢ: к°ҖкІ© {price_n} / нһҲмҠӨнҶ лҰ¬ {hist_n} / 1л¶„ {base1} / 3л¶„ {base3} / 2м°Ё {stage2} / 3м°Ё {stage3}",
            f"- мӢӨмӢңк°„ мҠӨлғ…мғ·: {_v300_fmt_age(bulk_ts)} / м „мІҙмҠӨмң• {bulk_count}к°ң",
            f"- v299 row: л№ лҘён–ү {v299.get('fast_row',0)}к°ң / нҸүк·  {v299_avg:.2f}ms",
            f"- v300 кі„мёЎ: rank_source мөңк·ј {safe_float(FACTORY_V300_STATS.get('rank_rows_last_sec',0),0):.2f}s/{int(FACTORY_V300_STATS.get('rank_rows_last_len',0))}к°ң / rank_compare мөңк·ј {safe_float(FACTORY_V300_STATS.get('rank_compare_last_sec',0),0):.2f}s",
            f"- API: лҸҷмӢң {api.get('api_inflight',0)}/{globals().get('API_CALL_MAX_CONCURRENT',4)} / timeout {api.get('api_timeout_count',0)} / busy {api.get('api_rejected_count',0)} / лҠҗлҰ°нҳём¶ң {api.get('api_last_slow_name','') or '-'}",
        ]
        ws = _v300_ws_brief()
        if ws:
            lines.append(f"- WebSocket: {ws}")
        err = str(globals().get('COMMAND_DISPLAY_CACHE_LAST_ERROR', '') or '').strip()
        if err:
            lines.append(f"- мөңк·ј мәҗмӢң мҳӨлҘҳ: {err}")
        lines += ["", "рҹ§ӯ нҢҗлӢЁ"]
        if price_n >= 400 and hist_n >= 400 and rows >= 40 and total_stage <= 10:
            lines.append("- м „мІҙ 450к°ңкёү мһ¬лЈҢ мң м§Җ / мҶҚлҸ„ м •мғҒк¶Ң")
        elif price_n >= 400 and hist_n >= 400 and total_stage > 10:
            lines.append("- м „мІҙ мһ¬лЈҢлҠ” мӮҙм•„мһҲм§Җл§Ң мәҗмӢң мЎ°лҰҪмқҙ лҠҗлҰј. /cache_status_fullм—җм„ң лі‘лӘ© нҷ•мқё")
        elif price_n < 300 or hist_n < 300:
            lines.append("- мӣҢл°Қм—… лҳҗлҠ” мһ¬лЈҢ л¶ҖмЎұ. rank_short/rank_compareлҘј л§ӨмҲҳнҢҗлӢЁм—җ л°”лЎң м“°м§Җ л§җ кІғ")
        else:
            lines.append("- мқјл¶Җ мһ¬лЈҢ нҷ•мқё н•„мҡ”. /cache_status_fullлЎң мғҒм„ё нҷ•мқё")
        lines.append("- мғҒм„ё м§„лӢЁ: /cache_status_full лҳҗлҠ” /batch м•Ҳ /cache_status_full")
        FACTORY_V300_STATS["cache_status_compact"] += 1
        return lines
    except Exception as e:
        return ["рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status", f"- v300 мҡ”м•Ҫ мғқм„ұ мҳӨлҘҳ: {e}"]


