def get_light_snapshot_rank_rows(limit: int = REALTIME_RANK_DISPLAY_LIMIT, min_move_pct: float = REALTIME_RANK_MIN_RECORD_MOVE_PCT) -> list:
    t0 = time.time()
    try:
        rows = _ORIG_V300_GET_LIGHT_SNAPSHOT_RANK_ROWS(limit=limit, min_move_pct=min_move_pct) if callable(_ORIG_V300_GET_LIGHT_SNAPSHOT_RANK_ROWS) else []
        sec = max(0.0, time.time() - t0)
        FACTORY_V300_STATS["rank_rows_calls"] += 1
        FACTORY_V300_STATS["rank_rows_total_sec"] += sec
        FACTORY_V300_STATS["rank_rows_last_sec"] = round(sec, 3)
        FACTORY_V300_STATS["rank_rows_last_len"] = len(rows) if isinstance(rows, list) else 0
        try:
            df_sec = safe_float(globals().get('DATA_FACTORY_V294_LAST_BUILD_SEC', 0), 0)
            v299_sec = safe_float((globals().get('FACTORY_V299_STATS', {}) or {}).get('last_factory_sec', 0), 0) if isinstance(globals().get('FACTORY_V299_STATS', {}), dict) else 0
            effective_factory = df_sec if df_sec > 0 else v299_sec
            post = max(0.0, sec - min(sec, effective_factory)) if effective_factory > 0 else 0.0
            timings = dict(globals().get("RANK_SOURCE_STEP_LAST_TIMINGS", {}) or {}) if isinstance(globals().get("RANK_SOURCE_STEP_LAST_TIMINGS", {}), dict) else {}
            timings.update({"rank_source_total_v300": round(sec, 3), "factory_last_v300": round(effective_factory, 3), "postprocess_est_v300": round(post, 3), "rows_v300": len(rows) if isinstance(rows, list) else 0})
            globals()["RANK_SOURCE_STEP_LAST_TIMINGS"] = timings
            globals()["RANK_SOURCE_STEP_LAST_NOTE"] = f"rank_source {sec:.2f}s / кіөмһҘмөңк·ј {effective_factory:.2f}s / нӣ„мІҳлҰ¬м¶”м • {post:.2f}s"
            FACTORY_V300_STATS["rank_rows_last_note"] = globals()["RANK_SOURCE_STEP_LAST_NOTE"]
        except Exception:
            pass
        return rows
    except Exception as e:
        FACTORY_V300_STATS["rank_rows_last_note"] = f"мҳӨлҘҳ: {str(e)[:80]}"
        try:
            append_runtime_error_log("v300_rank_rows", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return []


