def _v300_extract_rows_from_rank_compare_text(txt: str) -> int:
    try:
        m = re.search(r"rows\s+(\d+)", str(txt or ""))
        return int(m.group(1)) if m else 0
    except Exception:
        return 0


def build_rank_compare_text_v279(args=None, top_n: int = 10):
    t0 = time.time()
    txt = _ORIG_V300_BUILD_RANK_COMPARE_TEXT(args=args, top_n=top_n) if callable(_ORIG_V300_BUILD_RANK_COMPARE_TEXT) else "рҹ“Ҳ мҲңмң„ л№„көҗ /rank_compare"
    sec = max(0.0, time.time() - t0)
    try:
        FACTORY_V300_STATS["rank_compare_calls"] += 1
        FACTORY_V300_STATS["rank_compare_total_sec"] += sec
        FACTORY_V300_STATS["rank_compare_last_sec"] = round(sec, 3)
        FACTORY_V300_STATS["rank_compare_last_rows"] = _v300_extract_rows_from_rank_compare_text(str(txt or ""))
    except Exception:
        pass
    return _v297_pretty_operational_text(txt) if '_v297_pretty_operational_text' in globals() else txt


