# v2.5.301: лӘЁмқҳл§ӨмҲҳ/мІӯмӮ° м•ҢлҰј + лӘЁмқҳл§Өл§Ө нқҗлҰ„н‘ң
# =========================================================
# мӣҗм№ҷ:
# - м „лһө мЎ°кұҙ, мһҗлҸҷл§ӨмҲҳ, мҶҗм Ҳ/мқөм Ҳк°’мқҖ кұҙл“ңлҰ¬м§Җ м•ҠлҠ”лӢӨ.
# - м§„мһ…м·ЁмҶҢлҠ” н‘ёмӢңн•ҳм§Җ м•Ҡкі  кё°лЎқл§Ң лӮЁкёҙлӢӨ.
# - мӢӨм ңлЎң лӘЁмқҳл§ӨмҲҳ(ліҙмң к°Җм • OPEN) лҳҗлҠ” лӘЁмқҳмІӯмӮ°(CLOSED)мқҙ мғқкёҙ кІҪмҡ°л§Ң н…”л Ҳк·ёлһЁмңјлЎң м•Ңл ӨмӨҖлӢӨ.
PAPER_ALERTS_V301_ON = True
PAPER_ALERT_STATE_FILE_V301 = data_file("paper_alert_state_v301.json")
PAPER_FLOW_DEFAULT_MINUTES_V301 = 30
PAPER_FLOW_FULL_MINUTES_V301 = 120
PAPER_ALERT_MAX_KEYS_V301 = 700
PAPER_V301_STATS = {
    "entry_alerts": 0,
    "exit_alerts": 0,
    "cancel_push_blocked": 0,
    "flow_calls": 0,
    "sync_calls": 0,
    "last_note": "лҢҖкё°",
}


def _v301_inc(key: str, note: str = ""):
    try:
        if key in PAPER_V301_STATS:
            PAPER_V301_STATS[key] = int(safe_float(PAPER_V301_STATS.get(key, 0), 0)) + 1
        if note:
            PAPER_V301_STATS["last_note"] = str(note)[:160]
    except Exception:
        pass


def _paper_v301_load_alert_state() -> dict:
    try:
        raw = load_json_file(PAPER_ALERT_STATE_FILE_V301, {})
        if not isinstance(raw, dict):
            raw = {}
        raw.setdefault("sent_entries", [])
        raw.setdefault("sent_exits", [])
        raw.setdefault("updated_ts", 0)
        return raw
    except Exception:
        return {"sent_entries": [], "sent_exits": [], "updated_ts": 0}


def _paper_v301_save_alert_state(state: dict):
    try:
        state = dict(state or {})
        for k in ("sent_entries", "sent_exits"):
            vals = list(state.get(k) or [])[-PAPER_ALERT_MAX_KEYS_V301:]
            state[k] = vals
        state["updated_ts"] = time.time()
        save_json_file(PAPER_ALERT_STATE_FILE_V301, state)
    except Exception as e:
        try:
            append_runtime_error_log("paper_v301_save_alert_state", str(e), exc=e, include_traceback=False)
        except Exception:
            pass


