def _v301_status_lines(compact: bool = True) -> list:
    try:
        with PAPER_STATE_LOCK:
            active_n = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "OPEN")
            pending_n = sum(1 for p in (paper_positions or {}).values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "PENDING")
        lines = [
            "рҹ§Ә v2.5.301 лӘЁмқҳл§ӨмҲҳ м•ҢлҰј/нқҗлҰ„н‘ң",
            f"- м•ҢлҰј: лӘЁмқҳл§ӨмҲҳ {PAPER_V301_STATS.get('entry_alerts',0)} / лӘЁмқҳмІӯмӮ° {PAPER_V301_STATS.get('exit_alerts',0)} / м§„мһ…м·ЁмҶҢ н‘ёмӢң м•Ҳ н•Ё",
            f"- нҳ„мһ¬: ліҙмң к°Җм • {active_n} / м§„мһ…лҢҖкё° {pending_n} / нқҗлҰ„н‘ң /paper_flow",
            "- м „лһө мЎ°кұҙВ·мһҗлҸҷл§ӨмҲҳВ·мҶҗм Ҳ/TP ліҖкІҪ м—ҶмқҢ",
        ]
        return lines if not compact else lines[:3]
    except Exception as e:
        return ["рҹ§Ә v2.5.301 лӘЁмқҳл§ӨмҲҳ м•ҢлҰј/нқҗлҰ„н‘ң", f"- н‘ңмӢң мҳӨлҘҳ: {e}"]


def build_cache_status_text():
    base = str(_ORIG_V301_BUILD_CACHE_STATUS_TEXT()) if callable(_ORIG_V301_BUILD_CACHE_STATUS_TEXT) else "рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status"
    if "рҹ§Ә v2.5.301 лӘЁмқҳл§ӨмҲҳ м•ҢлҰј/нқҗлҰ„н‘ң" not in base:
        base = base.rstrip() + "\n\n" + "\n".join(_v301_status_lines(compact=True))
    return base


