# ---- v302: л°”лЎңм§„мһ…нҳ• л¬ён„ұ мһ¬л¶„лҰ¬ ----
PAPER_V302_NOW_DIRECT_MONEY_MIN = 80_000_000
PAPER_V302_NOW_DIRECT_TRADE_MIN = 3
PAPER_V302_NOW_DIRECT_BUY_RATIO_MIN = 52.0
PAPER_V302_NOW_PREPARE_MONEY_MIN = 20_000_000
PAPER_V302_NOW_PREPARE_BUY_RATIO_MIN = 42.0
PAPER_V302_NOW_PREPARE_FROM_LOW_MAX = 3.60

try:
    _BASE_V268_NOW_STRENGTH_V302 = _v268_now_strength
except Exception:
    _BASE_V268_NOW_STRENGTH_V302 = None


def _v268_now_strength(cls: dict, row: dict = None) -> dict:
    st = dict(_BASE_V268_NOW_STRENGTH_V302(cls, row) if callable(_BASE_V268_NOW_STRENGTH_V302) else {})
    try:
        if not st.get("is_now_candidate") or st.get("true_discard"):
            return st
        money = safe_float(st.get("money", 0), 0)
        trade_count = int(safe_float(st.get("trade_count", 0), 0))
        buy_ratio = safe_float(st.get("buy_ratio", 0), 0)
        from_low = safe_float(st.get("from_low", 0), 0)
        candle_weak = bool(st.get("candle_weak", False))
        candle_alive = bool(st.get("candle_alive", False))
        money_weak = bool(st.get("money_weak", False))
        high_touch = bool(st.get("high_touch", False))
        high_hold = bool(st.get("high_hold", False))
        direct_relaxed = (
            not bool(st.get("direct_ok"))
            and money >= PAPER_V302_NOW_DIRECT_MONEY_MIN
            and trade_count >= PAPER_V302_NOW_DIRECT_TRADE_MIN
            and buy_ratio >= PAPER_V302_NOW_DIRECT_BUY_RATIO_MIN
            and not candle_weak
            and not money_weak
            and (candle_alive or buy_ratio >= 60)
            and from_low <= 2.80
            and not (high_touch and not high_hold and buy_ratio < 58)
        )
        if direct_relaxed:
            st["direct_ok"] = True
            st["v302_direct_relaxed"] = True
            _v302_inc("now_direct_relaxed", f"nowм§Ғн–ү мҷ„нҷ” {str((cls or {}).get('ticker','?'))}")
            return st
        prepare_relaxed = (
            not bool(st.get("prepare_ok"))
            and money >= PAPER_V302_NOW_PREPARE_MONEY_MIN
            and (trade_count >= 1 or buy_ratio >= PAPER_V302_NOW_PREPARE_BUY_RATIO_MIN)
            and not (candle_weak and money_weak)
            and from_low <= PAPER_V302_NOW_PREPARE_FROM_LOW_MAX
            and not (money <= 1_000_000)
            and not (high_touch and not high_hold and buy_ratio < 35 and trade_count <= 1)
        )
        if prepare_relaxed:
            st["prepare_ok"] = True
            st["v302_prepare_relaxed"] = True
            st["cancel_reason"] = ""
            _v302_inc("now_prepare_relaxed", f"nowмӨҖл№„ мҷ„нҷ” {str((cls or {}).get('ticker','?'))}")
    except Exception as e:
        try: append_runtime_error_log("v302_now_strength", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return st


# ---- v302: detail мЎ°нҡҢ мҪ”мқё к°•м ң к°җмӢң/мң лӢҲлІ„мҠӨ мЈјмһ… ----
def force_detail_ticker_into_rank_pool_v302(ticker: str, reason: str = "detail_v302") -> bool:
    global shared_market_cache, shared_market_cache_time, market_universe, market_universe_time, market_all_tickers
    try:
        ticker = str(ticker or "").upper().strip()
        if not ticker or is_watch_excluded_ticker(ticker):
            return False
        now_ts = time.time()
        try:
            get_bulk_current_price_snapshot(force=False)
        except Exception:
            pass
        price = 0.0
        try:
            price = safe_float((LIGHT_SNAPSHOT_BULK_PRICE_CACHE or {}).get(ticker, 0), 0) if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) else 0.0
        except Exception:
            price = 0.0
        try:
            if price > 0:
                record_light_price_snapshot(ticker, price, turnover_hint=0.0, source=f"force_detail:{reason}", now_ts=now_ts)
        except Exception:
            pass
        try:
            force_track_light_snapshot_ticker(ticker, price=price, reason=reason, now_ts=now_ts)
            _v302_inc("detail_force_track", f"detail к°•м ңк°җмӢң {ticker}")
        except Exception:
            pass
        metrics = compute_light_snapshot_metrics(ticker, current_price=price) if LIGHT_SNAPSHOT_ENGINE_ON else {}
        row = None
        try:
            row = build_light_snapshot_rank_row_for_ticker(ticker, metrics=metrics) if isinstance(metrics, dict) else None
        except Exception:
            row = None
        if not isinstance(row, dict):
            row = {"ticker": ticker, "price": price, "current_price": price, "snapshot_rank_score": 0.0, "change_1": 0.0, "change_3": 0.0, "change_5": 0.0, "change_30": 0.0, "change_60": 0.0}
        item = None
        try:
            item = build_snapshot_cache_item_from_row(ticker, row)
        except Exception:
            item = None
        if not isinstance(item, dict):
            item = dict(row)
        item.update({
            "ticker": ticker,
            "price": price or safe_float(item.get("price", item.get("current_price", 0)), 0),
            "current_price": price or safe_float(item.get("current_price", item.get("price", 0)), 0),
            "candidate_source": "detail_force_watch_v302",
            "realtime_rank_injected": True,
            "rank_precision_watch": True,
            "detail_force_watch_v302": True,
            "force_reason": reason,
            "updated_ts": now_ts,
            "rank_watch_action": "мғҒм„ёмЎ°нҡҢ к°•м ңк°җмӢң",
            "precision_stage": "мғҒм„ёмЎ°нҡҢ/м•ұмӮ¬м§„ лҢҖмЎ° вҶ’ к°җмӢңн’Җ к°•м ңл“ұлЎқ",
        })
        try:
            if isinstance(shared_market_cache, dict):
                merged = dict(shared_market_cache.get(ticker, {}) or {})
                merged.update({k: v for k, v in item.items() if v not in (None, "")})
                shared_market_cache[ticker] = merged
            else:
                shared_market_cache = {ticker: item}
            shared_cache_row_times[ticker] = now_ts
            shared_market_cache_time = max(safe_float(shared_market_cache_time, 0), now_ts)
            _v302_inc("detail_force_cache", f"detail мәҗмӢңмЈјмһ… {ticker}")
        except Exception:
            pass
        try:
            if isinstance(market_universe, list) and not any(str((x.get('ticker','') if isinstance(x, dict) else x) or '').upper().strip() == ticker for x in market_universe):
                market_universe.insert(0, dict(item))
                if len(market_universe) > max(TOP_TICKERS + 80, 200):
                    market_universe = market_universe[:max(TOP_TICKERS + 80, 200)]
                market_universe_time = max(safe_float(market_universe_time, 0), now_ts)
            if isinstance(market_all_tickers, list) and ticker not in {str(x or '').upper().strip() for x in market_all_tickers}:
                market_all_tickers.append(ticker)
                market_all_tickers_time = max(safe_float(globals().get('market_all_tickers_time', 0), 0), now_ts)
        except Exception:
            pass
        try:
            saved = append_realtime_rank_min_trace(row, item=item, now_ts=now_ts, force=True)
            if saved:
                _v302_inc("detail_force_trace", f"detail traceм ҖмһҘ {ticker}")
        except Exception:
            pass
        return True
    except Exception as e:
        try: append_runtime_error_log("v302_detail_force", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False


