def build_review_trace_detail_text(ticker: str, limit: int = REVIEW_TRACE_DETAIL_RECENT_LIMIT) -> str:
    raw_query = str(ticker or '').strip()
    resolved, _note = resolve_user_ticker_query(raw_query)
    resolved = str(resolved or raw_query).upper().strip()
    if resolved:
        force_detail_ticker_into_rank_pool_v302(resolved, reason="review_trace_detail")
    text = str(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V302(ticker, limit=limit)) if callable(_BASE_BUILD_REVIEW_TRACE_DETAIL_TEXT_V302) else ""
    try:
        if resolved and "v302" not in text and ("м—ӯм¶”м Ғ кё°лЎқмқҙ м•„м§Ғ м—Ҷм–ҙ" in text or "лҲ„лқҪ м§„лӢЁ" in text):
            text += "\n- v302 ліҙм •: мғҒм„ёмЎ°нҡҢн•ң мҪ”мқёмқҖ к°җмӢңн’Җ/нҳ„мһ¬к°Җ мҠӨлғ…мғ·м—җ к°•м ң л“ұлЎқн–Ҳм–ҙ. лӘҮ л¶„ л’Ө /rank_compare, /review_trace_detailм—җм„ң лӢӨмӢң нҷ•мқё."
    except Exception:
        pass
    return text


try:
    _BASE_SEED_UNIVERSE_WITH_SNAPSHOT_ROWS_V302 = seed_universe_with_snapshot_rows
except Exception:
    _BASE_SEED_UNIVERSE_WITH_SNAPSHOT_ROWS_V302 = None


def seed_universe_with_snapshot_rows(tickers: list, base_map: dict, limit: int = None) -> dict:
    base_map = _BASE_SEED_UNIVERSE_WITH_SNAPSHOT_ROWS_V302(tickers, base_map, limit=limit) if callable(_BASE_SEED_UNIVERSE_WITH_SNAPSHOT_ROWS_V302) else (base_map if isinstance(base_map, dict) else {})
    try:
        forced = globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
        if isinstance(forced, dict):
            for ft, meta in list(forced.items()):
                t = str(ft or "").upper().strip()
                if not t or t in base_map or is_watch_excluded_ticker(t):
                    continue
                pv = safe_float((meta or {}).get("last_price", 0) if isinstance(meta, dict) else 0, 0)
                metrics = compute_light_snapshot_metrics(t, current_price=pv) if LIGHT_SNAPSHOT_ENGINE_ON else {}
                chg5 = safe_float(metrics.get('change_5', 0), 0) if isinstance(metrics, dict) else 0.0
                chg30 = safe_float(metrics.get('change_30', 0), 0) if isinstance(metrics, dict) else 0.0
                vol = safe_float(metrics.get('vol_ratio_snapshot', 0), 0) if isinstance(metrics, dict) else 0.0
                turn = safe_float(metrics.get('snapshot_turnover_hint', 0), 0) if isinstance(metrics, dict) else 0.0
                base_map[t] = {
                    'ticker': t,
                    'snapshot_seed': True,
                    'detail_force_watch_v302': True,
                    'last_price': safe_float(metrics.get('snapshot_price', pv), pv) if isinstance(metrics, dict) else pv,
                    'turnover_recent': turn,
                    'turnover_score': math.log10(max(turn, 1)),
                    'surge_score': max(chg5, 0) * 2.5 + max(chg30, 0) * 0.8 + max(vol - 1.0, 0) * 0.8,
                    'short_change': chg5,
                    'change_15': safe_float(metrics.get('change_15', 0), 0) if isinstance(metrics, dict) else 0.0,
                    'change_30': chg30,
                    'change_60': safe_float(metrics.get('change_60', 0), 0) if isinstance(metrics, dict) else 0.0,
                    'vol_ratio': vol,
                    'range_pct': 0.0,
                }
    except Exception as e:
        try: append_runtime_error_log("v302_seed_forced_universe", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return base_map


try:
    _BASE_INJECT_REALTIME_SNAPSHOT_ROWS_V302 = inject_realtime_snapshot_rows_into_cache
except Exception:
    _BASE_INJECT_REALTIME_SNAPSHOT_ROWS_V302 = None


def inject_realtime_snapshot_rows_into_cache(cache: dict, limit: int = REALTIME_RANK_INJECT_LIMIT) -> dict:
    cache = _BASE_INJECT_REALTIME_SNAPSHOT_ROWS_V302(cache, limit=limit) if callable(_BASE_INJECT_REALTIME_SNAPSHOT_ROWS_V302) else (cache if isinstance(cache, dict) else {})
    try:
        forced = globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
        if not isinstance(forced, dict):
            return cache
        for ft, meta in list(forced.items()):
            t = str(ft or "").upper().strip()
            if not t or is_watch_excluded_ticker(t):
                continue
            pv = safe_float((meta or {}).get("last_price", 0) if isinstance(meta, dict) else 0, 0)
            metrics = compute_light_snapshot_metrics(t, current_price=pv) if LIGHT_SNAPSHOT_ENGINE_ON else {}
            row = build_light_snapshot_rank_row_for_ticker(t, metrics=metrics) if isinstance(metrics, dict) else {"ticker": t, "price": pv}
            item = build_snapshot_cache_item_from_row(t, row) if isinstance(row, dict) else None
            if not isinstance(item, dict):
                item = dict(row or {"ticker": t, "price": pv})
            item.update({"ticker": t, "detail_force_watch_v302": True, "realtime_rank_injected": True, "rank_precision_watch": True, "candidate_source": "detail_force_watch_v302"})
            existing = cache.get(t) if isinstance(cache, dict) else None
            if isinstance(existing, dict):
                merged = dict(existing); merged.update({k: v for k, v in item.items() if v not in (None, "")}); cache[t] = merged
            else:
                cache[t] = item
    except Exception as e:
        try: append_runtime_error_log("v302_inject_forced", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return cache


