def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    args = list(args or [])
    cmd_l = str(cmd or '').lower().strip()
    arg_preview = ' '.join([str(x) for x in args]).strip()
    shown_cmd = f"/{cmd_l}" + (f" {arg_preview}" if arg_preview else "")
    label = f"в–¶пёҸ л¬¶мқҢ {idx}/{total} {shown_cmd}" if total > 1 else f"в–¶пёҸ {shown_cmd}"
    if cmd_l in {'paper_recent_full'}:
        send_text_chunks(build_paper_recent_full_text_v277(limit=20), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if callable(_BASE_EXECUTE_SINGLE_BATCH_COMMAND_V302):
        return _BASE_EXECUTE_SINGLE_BATCH_COMMAND_V302(cmd, args, idx, total)
    send(f"{label}\n- batch мІҳлҰ¬ мӣҗліё н•ЁмҲҳлҘј м°ҫм§Җ лӘ»н–Ҳм–ҙ")


