# v2.5.304: н—ҲлёҢ row н‘ңмӨҖнҷ” + 1/2/3м°Ё м°Ҫкі  м—°кІ° м•Ҳм •нҷ”
# =========================================================
# мӣҗм№ҷ:
# - м „мІҙ мЎ°кұҙмқ„ мЎ°мқҙлҠ” мҲҳм •мқҙ м•„лӢҲлӢӨ.
# - н—ҲлёҢ/кіөмһҘ/м°Ҫкі к°Җ мЈјкі л°ӣлҠ” row к·ңкІ©мқ„ лЁјм Җ л§һм¶°м„ң turnover_scoreлҘҳ лҲ„лқҪ мһ¬л°ңмқ„ л§үлҠ”лӢӨ.
# - мҠӨлғ…мғ·м—җлҠ” мһҲлҠ”лҚ° мң лӢҲлІ„мҠӨ/мәҗмӢң/traceм—җ лӘ» лӮҙл Өк°ҖлҠ” нӣ„ліҙлҠ” мқҙмң лҘј лӮЁкёҙлӢӨ.
# - rank_compareмқҳ лҚ°мқҙн„°мғқм„ұ мӢңк°„мқҖ "лӘ…л №м–ҙ м§Ғм ‘кі„мӮ°"кіј н—·к°ҲлҰ¬м§Җ м•ҠкІҢ н‘ңмӢңн•ңлӢӨ.
V304_HUB_SCHEMA_VERSION = "hub_row_v304"
V304_STATS = {
    "hub_row_normalized": 0,
    "hub_row_defaulted": 0,
    "hub_row_missing_logged": 0,
    "rank_universe_normalized": 0,
    "cache_normalized": 0,
    "force_cache_verified": 0,
    "force_trace_saved": 0,
    "force_trace_failed": 0,
    "force_universe_inserted": 0,
    "errorlog_classified": 0,
    "last_note": "лҢҖкё°",
}
V304_REQUIRED_NUMERIC_DEFAULTS = {
    "turnover_recent": 0.0,
    "turnover": 0.0,
    "turnover_krw": 0.0,
    "turnover_1m": 0.0,
    "turnover_3m": 0.0,
    "turnover_5m": 0.0,
    "turnover_15m": 0.0,
    "turnover_score": 0.0,
    "money_score": 0.0,
    "surge_score": 0.0,
    "leader_score": 0.0,
    "snapshot_rank_score": 0.0,
    "strategy_score": 0.0,
    "vol_ratio": 0.0,
    "range_pct": 0.0,
    "change_1": 0.0,
    "change_3": 0.0,
    "change_5": 0.0,
    "change_15": 0.0,
    "change_30": 0.0,
    "change_60": 0.0,
    "trade_count_60s": 0,
    "buy_ratio_60s": 0.0,
    "ws_trade_count_60s": 0,
    "ws_trade_buy_ratio_60s": 0.0,
}
V304_REQUIRED_TEXT_DEFAULTS = {
    "rank_reason": "",
    "watch_route": "",
    "trace_reason": "",
    "candidate_source": "",
    "rank_watch_action": "",
    "precision_stage": "",
    "cache_source": "",
    "hub_stage": "",
    "hub_source": "",
}
V304_MISSING_LOG_COOLDOWN_SEC = 180
V304_LAST_MISSING_LOG_TS = {}


def _v304_inc(key: str, note: str = ""):
    try:
        if key in V304_STATS:
            V304_STATS[key] = int(safe_float(V304_STATS.get(key, 0), 0)) + 1
        if note:
            V304_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v304_price_from_row(row: dict) -> float:
    try:
        for k in ("price", "current_price", "last_price", "snapshot_price"):
            v = safe_float((row or {}).get(k, 0), 0)
            if v > 0:
                return v
    except Exception:
        pass
    return 0.0


def _v304_money_from_row(row: dict) -> float:
    try:
        if '_v303_money' in globals():
            v = safe_float(_v303_money(row), 0)
            if v > 0:
                return v
    except Exception:
        pass
    for k in ("turnover_5m", "turnover_recent", "turnover", "turnover_krw", "money_amount", "ws_trade_amount_60s", "trade_amount_60s", "snapshot_turnover_hint"):
        v = safe_float((row or {}).get(k, 0), 0)
        if v > 0:
            return v
    return 0.0


def _v304_log_missing_once(ticker: str, stage: str, missing: list):
    try:
        if not missing:
            return
        now_ts = time.time()
        key = f"{stage}:{ticker}:{','.join(sorted(set(missing))[:8])}"
        last = safe_float(V304_LAST_MISSING_LOG_TS.get(key, 0), 0)
        if now_ts - last < V304_MISSING_LOG_COOLDOWN_SEC:
            return
        V304_LAST_MISSING_LOG_TS[key] = now_ts
        _v304_inc("hub_row_missing_logged", f"{stage} кё°ліён•„л“ң ліҙм • {ticker}")
        append_runtime_event_log(
            "v304_hub_row_defaulted",
            "н—ҲлёҢ row кё°ліён•„л“ң ліҙм •",
            extra={
                "ticker": ticker,
                "stage": stage,
                "missing": list(sorted(set(missing)))[:20],
                "schema": V304_HUB_SCHEMA_VERSION,
            },
        )
    except Exception:
        pass


def ensure_v304_hub_row_defaults(row: dict, stage: str = "hub", source: str = "") -> dict:
    """н—ҲлёҢвҶ’кіөмһҘвҶ’м°Ҫкі лЎң лӮҙл ӨліҙлӮј row кіөнҶө к·ңкІ©мқ„ л§һм¶ҳлӢӨ.

    мқҙ н•ЁмҲҳлҠ” л§ӨмҲҳ мЎ°кұҙмқ„ мЎ°мқҙлҠ” мһҘм№ҳк°Җ м•„лӢҲлӢӨ.
    turnover_score к°ҷмқҖ н•„мҲҳ н•„л“ңк°Җ л№ м§„ rowк°Җ м •л ¬/workerм—җм„ң н„°м§Җм§Җ м•ҠкІҢ
    1м°Ё/2м°Ё/3м°Ё кіөнҶө кё°ліёк°’мқ„ ліҙмһҘн•ҳлҠ” н‘ңмӨҖнҷ” л Ҳмқҙм–ҙлӢӨ.
    """
    try:
        if not isinstance(row, dict):
            return row
        missing = []
        ticker = str(row.get("ticker", "") or row.get("symbol", "") or "").upper().strip()
        if ticker:
            row["ticker"] = ticker
        price = _v304_price_from_row(row)
        money = _v304_money_from_row(row)

        # к°ҖкІ© 3мў…мқҖ м„ңлЎң мқҙлҰ„мқҙ лӢ¬лқјлҸ„ downstreamмқҙ к°ҷмқҖ к°’мңјлЎң мқҪкІҢ л§һм¶ҳлӢӨ.
        for k in ("price", "current_price", "last_price"):
            if k not in row or row.get(k) in (None, ""):
                row[k] = price
                missing.append(k)

        # кұ°лһҳлҢҖкёҲ мқҙлҰ„лҸ„ 1м°Ё/2м°Ё/3м°Ём—җм„ң м„һм—¬ м“°мқҙлҜҖлЎң кіөнҶөк°’мқ„ мұ„мҡҙлӢӨ.
        if money > 0:
            for k in ("turnover_recent", "turnover", "turnover_krw"):
                if k not in row or row.get(k) in (None, ""):
                    row[k] = money
                    missing.append(k)

        # н•„мҲҳ мҲ«мһҗ н•„л“ң. 0мқҖ "м—ҶмқҢ/лҜёкІҖмҰқ"мқҙм§Җ к°•н•ң н•„н„°к°Җ м•„лӢҲлӢӨ.
        for k, default in V304_REQUIRED_NUMERIC_DEFAULTS.items():
            if k not in row or row.get(k) in (None, ""):
                if k == "turnover_score":
                    row[k] = math.log10(max(money, 1)) if money > 0 else 0.0
                elif k in {"turnover_recent", "turnover", "turnover_krw", "turnover_5m"} and money > 0:
                    row[k] = money
                elif k == "surge_score":
                    row[k] = safe_float(row.get("snapshot_rank_score", row.get("score", 0)), 0)
                elif k == "leader_score":
                    row[k] = safe_float(row.get("snapshot_rank_score", row.get("score", 0)), 0)
                elif k == "snapshot_rank_score":
                    row[k] = safe_float(row.get("lite_score", row.get("score", 0)), 0)
                else:
                    row[k] = default
                missing.append(k)

        for k, default in V304_REQUIRED_TEXT_DEFAULTS.items():
            if k not in row or row.get(k) is None:
                row[k] = default
                missing.append(k)

        # unknown/verified кө¬л¶„мҡ© л©”нғҖ. м¶ңл Ҙм—җм„ң н—·к°ҲлҰ¬л©ҙ мқҙ к°’мқ„ м°ёкі н•ңлӢӨ.
        row["row_schema_version"] = V304_HUB_SCHEMA_VERSION
        row["v304_hub_normalized"] = True
        row["v304_hub_stage_last"] = str(stage or "hub")
        if source:
            row["v304_hub_source_last"] = str(source)[:80]
            if not row.get("hub_source"):
                row["hub_source"] = str(source)[:80]
        if not row.get("hub_stage"):
            row["hub_stage"] = str(stage or "hub")
        if missing:
            prev = row.get("v304_defaulted_fields", [])
            if not isinstance(prev, list):
                prev = []
            row["v304_defaulted_fields"] = sorted(set(prev + missing))[:40]
            _v304_inc("hub_row_defaulted", f"{stage} row кё°ліёк°’ {ticker or '?'}")
            _v304_log_missing_once(ticker or "UNKNOWN", str(stage or "hub"), missing)
        _v304_inc("hub_row_normalized")
        return row
    except Exception as e:
        try:
            append_runtime_error_log("v304_hub_row_defaults", str(e), exc=e, extra={"stage": stage, "source": source}, include_traceback=False)
        except Exception:
            pass
        return row


def normalize_v304_hub_rows(rows, stage: str = "hub", source: str = ""):
    try:
        if isinstance(rows, dict):
            return {k: ensure_v304_hub_row_defaults(dict(v), stage=stage, source=source) if isinstance(v, dict) else v for k, v in rows.items()}
        out = []
        for r in list(rows or []):
            out.append(ensure_v304_hub_row_defaults(dict(r), stage=stage, source=source) if isinstance(r, dict) else r)
        return out
    except Exception:
        return rows


try:
    _BASE_RANK_UNIVERSE_ROWS_V304 = rank_universe_rows
except Exception:
    _BASE_RANK_UNIVERSE_ROWS_V304 = None


def rank_universe_rows(rows):
    fixed = normalize_v304_hub_rows(rows, stage="1м°Ё мң лӢҲлІ„мҠӨ", source="rank_universe_rows")
    try:
        _v304_inc("rank_universe_normalized", "1м°Ё мң лӢҲлІ„мҠӨ row н‘ңмӨҖнҷ”")
        if callable(_BASE_RANK_UNIVERSE_ROWS_V304):
            result = _BASE_RANK_UNIVERSE_ROWS_V304(fixed)
        else:
            result = list(fixed or [])
        return normalize_v304_hub_rows(result, stage="1м°Ё мң лӢҲлІ„мҠӨ м„ м •", source="rank_universe_rows_result")
    except Exception as e:
        try:
            append_runtime_error_log("v304_rank_universe_rows", str(e), exc=e, extra={"rows": len(fixed or [])}, include_traceback=True)
        except Exception:
            pass
        # лһӯнӮ№ н•ЁмҲҳк°Җ н„°м ёлҸ„ н—ҲлёҢ rowлҠ” лІ„лҰ¬м§Җ м•ҠлҠ”лӢӨ. лӢЁ, мқҙ fallbackмқҖ м •л ¬ м •нҷ•лҸ„ліҙлӢӨ мғқмЎҙ мҡ°м„ мқҙлӢӨ.
        try:
            fallback = list(fixed or [])
            fallback.sort(key=lambda x: (
                safe_float((x or {}).get("leader_score", 0), 0) * 1.20
                + safe_float((x or {}).get("surge_score", 0), 0) * 0.95
                + safe_float((x or {}).get("turnover_score", 0), 0) * 0.35
            ), reverse=True)
            return fallback[:TOP_TICKERS]
        except Exception:
            return list(fixed or [])[:TOP_TICKERS]


