try:
    _BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V304 = force_detail_ticker_into_rank_pool_v302
except Exception:
    _BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V304 = None


def force_detail_ticker_into_rank_pool_v302(ticker: str, reason: str = "detail_v304") -> bool:
    """мғҒм„ёмЎ°нҡҢ/PENDLEлҘҳ к°•м ңк°җмӢңк°Җ мәҗмӢң/мң лӢҲлІ„мҠӨ/traceк№Ңм§Җ лӮҙл Өк°ҖкІҢ н•ң лІҲ лҚ” ліҙк°•."""
    global shared_market_cache, market_universe, shared_market_cache_time, market_universe_time
    t = str(ticker or "").upper().strip()
    ok = False
    try:
        ok = bool(_BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V304(t, reason=reason)) if callable(_BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V304) else False
    except Exception as e:
        try:
            append_runtime_error_log("v304_force_detail_base", str(e), exc=e, extra={"ticker": t, "reason": reason}, include_traceback=False)
        except Exception:
            pass
    try:
        if not t or ('is_watch_excluded_ticker' in globals() and is_watch_excluded_ticker(t)):
            return ok
        now_ts = time.time()
        existing = {}
        if isinstance(shared_market_cache, dict) and isinstance(shared_market_cache.get(t), dict):
            existing = dict(shared_market_cache.get(t) or {})
        price = _v304_price_from_row(existing)
        if price <= 0:
            try:
                price = safe_float((LIGHT_SNAPSHOT_BULK_PRICE_CACHE or {}).get(t, 0), 0) if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) else 0.0
            except Exception:
                price = 0.0
        if price <= 0:
            try:
                get_bulk_current_price_snapshot(force=False)
                price = safe_float((LIGHT_SNAPSHOT_BULK_PRICE_CACHE or {}).get(t, 0), 0) if isinstance(LIGHT_SNAPSHOT_BULK_PRICE_CACHE, dict) else 0.0
            except Exception:
                price = 0.0

        if not existing:
            existing = {"ticker": t, "price": price, "current_price": price, "last_price": price}
        existing.update({
            "ticker": t,
            "price": price or _v304_price_from_row(existing),
            "current_price": price or _v304_price_from_row(existing),
            "last_price": price or _v304_price_from_row(existing),
            "detail_force_watch_v304": True,
            "detail_force_watch_v302": True,
            "realtime_rank_injected": True,
            "rank_precision_watch": True,
            "candidate_source": existing.get("candidate_source") or "detail_force_watch_v304",
            "force_reason": reason,
            "updated_ts": now_ts,
            "rank_watch_action": existing.get("rank_watch_action") or "мғҒм„ёмЎ°нҡҢ/м•ұмӢқ к°•м ңк°җмӢң",
            "precision_stage": existing.get("precision_stage") or "мғҒм„ёмЎ°нҡҢ/м•ұмӮ¬м§„ лҢҖмЎ° вҶ’ к°җмӢңн’Җ/м°Ҫкі  к°•м ңл“ұлЎқ",
        })
        existing = ensure_v304_hub_row_defaults(existing, stage="3м°Ё к°•м ңк°җмӢң", source=reason)

        if not isinstance(shared_market_cache, dict):
            shared_market_cache = {}
        merged = dict(shared_market_cache.get(t, {}) or {})
        merged.update({k: v for k, v in existing.items() if v not in (None, "")})
        merged = ensure_v304_hub_row_defaults(merged, stage="3м°Ё к°•м ңк°җмӢң мәҗмӢң", source=reason)
        shared_market_cache[t] = merged
        shared_cache_row_times[t] = now_ts
        shared_market_cache_time = max(safe_float(shared_market_cache_time, 0), now_ts)
        _v304_inc("force_cache_verified", f"к°•м ңк°җмӢң мәҗмӢңнҷ•мқё {t}")

        try:
            found = False
            fixed = []
            for x in list(market_universe or []):
                if isinstance(x, dict) and str(x.get("ticker", "")).upper().strip() == t:
                    nx = dict(x)
                    nx.update({k: v for k, v in merged.items() if v not in (None, "")})
                    fixed.append(ensure_v304_hub_row_defaults(nx, stage="3м°Ё к°•м ңк°җмӢң мң лӢҲлІ„мҠӨ", source=reason))
                    found = True
                else:
                    fixed.append(x)
            if not found:
                fixed.insert(0, dict(merged))
                _v304_inc("force_universe_inserted", f"к°•м ңк°җмӢң мң лӢҲлІ„мҠӨмӮҪмһ… {t}")
            market_universe = fixed[:max(TOP_TICKERS + 80, 200)]
            market_universe_time = max(safe_float(market_universe_time, 0), now_ts)
        except Exception:
            pass

        saved = False
        try:
            if 'append_realtime_rank_min_trace' in globals():
                saved = bool(append_realtime_rank_min_trace(dict(merged), item=dict(merged), now_ts=now_ts, force=True))
        except Exception as e:
            _v304_inc("force_trace_failed", f"к°•м ңк°җмӢң traceмӢӨнҢЁ {t}")
            try:
                append_runtime_error_log("v304_force_trace", str(e), exc=e, extra={"ticker": t, "reason": reason}, include_traceback=False)
            except Exception:
                pass
        if saved:
            _v304_inc("force_trace_saved", f"к°•м ңк°җмӢң traceм ҖмһҘ {t}")
            try:
                if '_v302_inc' in globals():
                    _v302_inc("detail_force_trace", f"v304 traceм ҖмһҘ {t}")
            except Exception:
                pass
        else:
            _v304_inc("force_trace_failed", f"к°•м ңк°җмӢң traceлҜём ҖмһҘ {t}")
            append_runtime_event_log("v304_force_trace_not_saved", "к°•м ңк°җмӢң trace м ҖмһҘ м•Ҳ лҗЁ", extra={
                "ticker": t,
                "reason": reason,
                "price": price,
                "cache_present": t in shared_market_cache if isinstance(shared_market_cache, dict) else False,
                "schema": V304_HUB_SCHEMA_VERSION,
            })
        return bool(ok or t in shared_market_cache or saved)
    except Exception as e:
        try:
            append_runtime_error_log("v304_force_detail", str(e), exc=e, extra={"ticker": t, "reason": reason}, include_traceback=True)
        except Exception:
            pass
        return ok


try:
    _BASE_V289_TEXT_V304 = _v289_text
except Exception:
    _BASE_V289_TEXT_V304 = None


def _v289_text(data):
    text = str(_BASE_V289_TEXT_V304(data)) if callable(_BASE_V289_TEXT_V304) else ""
    try:
        data = data if isinstance(data, dict) else {}
        build_sec = safe_float(data.get("build_sec", 0), 0)
        rows_n = len(data.get("rows") or [])
        note = ""
        if build_sec >= 8.0:
            note = "- v304 н‘ңмӢң: лҚ°мқҙн„°мғқм„ұ мӢңк°„мқҖ л°ұк·ёлқјмҡҙл“ң кіөмһҘ/н…ҚмҠӨнҠёмәҗмӢңк°Җ л§Ңл“  мӢңк°„мһ„. лӘ…л №м–ҙк°Җ м§ҖкёҲ мғҲлЎң 450к°ңлҘј кі„мӮ°н•ң лң»мқҖ м•„лӢҳ."
        elif rows_n >= 400:
            note = "- v304 н‘ңмӢң: rows 400к°ң мқҙмғҒмқҙл©ҙ м •мғҒ м „мІҙ л№„көҗнҢҗмңјлЎң лҙҗлҸ„ лҗЁ."
        if note and note not in text:
            lines = text.splitlines()
            insert_at = 5 if len(lines) >= 5 else len(lines)
            lines.insert(insert_at, note)
            text = "\n".join(lines)
    except Exception:
        pass
    return text


try:
    _BASE_BUILD_ERRORLOG_TEXT_V304 = build_errorlog_text_v250
except Exception:
    _BASE_BUILD_ERRORLOG_TEXT_V304 = None


def _v304_errorlog_summary_from_text(body: str) -> list:
    lines = []
    try:
        txt = str(body or "")
        cur_new_none = "нҳ„мһ¬ л¶ҖнҢ… мқҙнӣ„ мғҲ мҳӨлҘҳ м—ҶмқҢ" in txt
        turnover_hits = txt.count("'turnover_score'") + txt.count("turnover_score")
        v302_hits = txt.count("v302_cancel") + txt.count("PAPER_CANCEL_WATCH")
        if cur_new_none:
            lines.append("- нҳ„мһ¬ л¶ҖнҢ… мқҙнӣ„ мғҲ мҳӨлҘҳ м—ҶмқҢ: кё°ліё нҷ”л©ҙм—җм„ңлҠ” кіјкұ° tailл§Ң м°ёкі ")
        if turnover_hits:
            lines.append(f"- кіјкұ°/нҳ„мһ¬ tailм—җ turnover_score кҙҖл Ё кё°лЎқ {turnover_hits}кұҙ к°җм§Җ: v304 н—ҲлёҢ row н‘ңмӨҖнҷ”лЎң мһ¬л°ң л°©м§Җ лҢҖмғҒ")
        if v302_hits:
            lines.append(f"- v302 м·ЁмҶҢм¶”м Ғ кҙҖл Ё кё°лЎқ {v302_hits}кұҙ к°җм§Җ: v303 м ҖмһҘ ліҙм • + v304 л¶„лҘҳ лҢҖмғҒ")
        if not lines:
            lines.append("- нҳ„мһ¬ кё°ліё нҷ”л©ҙ кё°мӨҖмңјлЎң мғҲлЎң л¶„лҘҳн•  н•өмӢ¬ мҳӨлҘҳ м—ҶмқҢ")
    except Exception:
        lines = ["- мҳӨлҘҳ л¶„лҘҳ мҡ”м•Ҫ мғқм„ұ мӢӨнҢЁ"]
    return lines


def build_errorlog_text_v250(full: bool = False, batch_short: bool = False) -> str:
    base = str(_BASE_BUILD_ERRORLOG_TEXT_V304(full=full, batch_short=batch_short)) if callable(_BASE_BUILD_ERRORLOG_TEXT_V304) else ""
    try:
        if full:
            return base
        if "рҹ§© v2.5.304 мҳӨлҘҳ л¶„лҘҳ" not in base:
            summary = _v304_errorlog_summary_from_text(base)
            base = base.rstrip() + "\n\nрҹ§© v2.5.304 мҳӨлҘҳ л¶„лҘҳ\n" + "\n".join(summary)
            _v304_inc("errorlog_classified", "errorlog кё°ліё л¶„лҘҳ н‘ңмӢң")
    except Exception:
        pass
    return base


# errorlog_commandлҠ” build_errorlog_text_v250мқ„ м§Ғм ‘ м°ёмЎ°н•ҳлҜҖлЎң лі„лҸ„ мһ¬м •мқҳ м—ҶмқҙлҸ„ v304 л¶„лҘҳк°Җ л¶ҷлҠ”лӢӨ.


try:
    _BASE_V302_STATUS_LINES_V304 = _v302_status_lines
except Exception:
    _BASE_V302_STATUS_LINES_V304 = None


def _v304_status_lines(compact: bool = True) -> list:
    forced_n = 0
    cache_hit = 0
    try:
        forced = globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
        forced_n = len(forced) if isinstance(forced, dict) else 0
        if isinstance(forced, dict) and isinstance(shared_market_cache, dict):
            for t in forced.keys():
                if str(t or "").upper().strip() in shared_market_cache:
                    cache_hit += 1
    except Exception:
        pass
    lines = [
        "рҹҸӯ v2.5.304 н—ҲлёҢ/м°Ҫкі  н‘ңмӨҖнҷ”",
        f"- н—ҲлёҢrow: н‘ңмӨҖнҷ” {V304_STATS.get('hub_row_normalized',0)} / кё°ліёк°’ліҙм • {V304_STATS.get('hub_row_defaulted',0)} / лҲ„лқҪкё°лЎқ {V304_STATS.get('hub_row_missing_logged',0)}",
        f"- 1м°Ё/2м°Ё: мң лӢҲлІ„мҠӨн‘ңмӨҖнҷ” {V304_STATS.get('rank_universe_normalized',0)} / мәҗмӢңн‘ңмӨҖнҷ” {V304_STATS.get('cache_normalized',0)}",
        f"- к°•м ңк°җмӢң: л“ұлЎқ {forced_n} / мәҗмӢңнҷ•мқё {cache_hit} / traceм ҖмһҘ {V304_STATS.get('force_trace_saved',0)} / traceлҜём ҖмһҘ {V304_STATS.get('force_trace_failed',0)}",
        "- кё°мӨҖ: мЎ°кұҙ к°•нҷ” м•„лӢҳ. 1м°Ё/2м°Ё/3м°Ё row к·ңкІ©мқ„ л§һм¶° м°Ҫкі лЎң м•Ҳм •м ҒмңјлЎң лӮҙл ӨліҙлӮҙлҠ” мҲҳм •",
        f"- мөңк·ј: {V304_STATS.get('last_note','лҢҖкё°')}",
    ]
    return lines[:4] if compact else lines


def _v302_status_lines(compact: bool = True) -> list:
    base = list(_BASE_V302_STATUS_LINES_V304(compact=compact)) if callable(_BASE_V302_STATUS_LINES_V304) else []
    return base + _v304_status_lines(compact=compact)


