# =========================================================
# v2.5.305: мҲҳм • мң„м№ҳн‘ң кі м • + н—ҲлёҢ лҲ„лқҪл¶„н•ҙ + к°•м ңк°җмӢң traceмӣҗмқё + мһ¬к°җмӢң л¬ён„ұ
# =========================================================
# мң„м№ҳн‘ң:
# - н—ҲлёҢ/кіөмһҘ: v304м—җм„ң н‘ңмӨҖнҷ”н•ң rowмқҳ лҲ„лқҪ н•„л“ңк°Җ м–ҙлҠҗ stage/sourceм—җм„ң мғқкё°лҠ”м§Җ л¶„н•ҙн•ңлӢӨ.
# - 1м°Ё/2м°Ё/3м°Ё: кё°мЎҙ нқҗлҰ„мқ„ к№Ём§Җ м•Ҡкі , нӣ„ліҙк°Җ м–ҙлҠҗ лӢЁкі„м—җм„ң мһ¬к°җмӢң/кё°лЎқмңјлЎң лӮҙл Өк°ҖлҠ”м§Җ н‘ңмӢңн•ңлӢӨ.
# - м°Ҫкі /trace: к°•м ңк°җмӢң нӣ„ліҙк°Җ traceм—җ м•Ҳ лӮЁмңјл©ҙ мҷң м•Ҳ лӮЁм•ҳлҠ”м§Җ мқҙмң лҘј лӮЁкёҙлӢӨ.
# - paper/trace: м·ЁмҶҢ нӣ„ лӢӨмӢң мӮҙм•„лӮң нӣ„ліҙлҠ” л°”лЎң м•ҢлҰјмқҙ м•„лӢҲлқј 3м°Ё мһ¬к°җмӢң нӣ„ліҙлЎң м—°кІ°н•ңлӢӨ.
# - л°”лЎңм§„мһ…: м „мІҙ мЎ°кұҙ к°•нҷ”к°Җ м•„лӢҲлқј, л§ӨлҸ„мҡ°м„ё/нҳ„мһ¬лҙү л°ҖлҰј нӣ„ліҙл§Ң л°”лЎңм§„мһ… л¬ём—җм„ң мӨҖл№„лҢҖкё°лЎң лҸҢлҰ°лӢӨ.
# - м¶ңл Ҙ/мқёмҲҳмқёкі„: м•һмңјлЎң лӘЁл“  мҲҳм • м „ "м–ҙлҠҗ мң„м№ҳлҘј кі м№ҳлҠ”м§Җ"лҘј лЁјм Җ м ҒлҠ”лӢӨ.
V305_SCHEMA_VERSION = "flow_guard_v305"
V305_STATS = {
    "hub_missing_seen": 0,
    "force_trace_saved": 0,
    "force_trace_not_saved": 0,
    "force_trace_no_attempt": 0,
    "cancel_rewatch_promoted": 0,
    "cancel_rewatch_precision_allowed": 0,
    "now_direct_demoted": 0,
    "now_prepare_after_demote": 0,
    "last_note": "лҢҖкё°",
}
V305_HUB_MISSING_FIELD_COUNTS = {}
V305_HUB_MISSING_STAGE_COUNTS = {}
V305_HUB_MISSING_SOURCE_COUNTS = {}
V305_FORCE_TRACE_REASON_COUNTS = {}
V305_CANCEL_REWATCH_MIN_UP_PCT = 0.70
V305_CANCEL_REWATCH_STRONG_UP_PCT = 1.50
V305_CANCEL_REWATCH_MIN_CURRENT_UP_PCT = 0.35
V305_NOW_DIRECT_SELL_BUY_RATIO_MAX = 35.0
V305_NOW_DIRECT_PRESSURE_BLOCK_SCORE = 1.20


def _v305_inc(key: str, note: str = ""):
    try:
        if key in V305_STATS:
            V305_STATS[key] = int(safe_float(V305_STATS.get(key, 0), 0)) + 1
        if note:
            V305_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v305_count(d: dict, key: str, amount: int = 1):
    try:
        k = str(key or "лҜёл¶„лҘҳ")[:80]
        d[k] = int(safe_float(d.get(k, 0), 0)) + int(amount)
    except Exception:
        pass


def _v305_top_counts_text(d: dict, limit: int = 3) -> str:
    try:
        rows = sorted([(str(k), int(safe_float(v, 0))) for k, v in (d or {}).items()], key=lambda kv: kv[1], reverse=True)
        rows = rows[:max(1, int(limit))]
        if not rows:
            return "м—ҶмқҢ"
        return ", ".join([f"{k} {v}" for k, v in rows])
    except Exception:
        return "м—ҶмқҢ"


def _v305_missing_fields_before_standardize(row: dict) -> list:
    try:
        if not isinstance(row, dict):
            return []
        keys = []
        for k in list(globals().get("V304_REQUIRED_NUMERIC_DEFAULTS", {}).keys()) + list(globals().get("V304_REQUIRED_TEXT_DEFAULTS", {}).keys()):
            if k not in row or row.get(k) in (None, ""):
                keys.append(k)
        if not any((row.get(k) not in (None, "", 0, 0.0)) for k in ("price", "current_price", "last_price", "snapshot_price")):
            keys.append("price/current_price")
        return sorted(set(keys))
    except Exception:
        return []


try:
    _BASE_ENSURE_V304_HUB_ROW_DEFAULTS_V305 = ensure_v304_hub_row_defaults
except Exception:
    _BASE_ENSURE_V304_HUB_ROW_DEFAULTS_V305 = None


def ensure_v304_hub_row_defaults(row: dict, stage: str = "hub", source: str = "") -> dict:
    """v305: v304 н‘ңмӨҖнҷ”лҠ” мң м§Җн•ҳкі , лҲ„лқҪ н•„л“ң/кІҪлЎңлҘј л¶„н•ҙн•ҙм„ң ліҙм—¬мӨҖлӢӨ."""
    try:
        missing = _v305_missing_fields_before_standardize(row)
        if missing:
            _v305_inc("hub_missing_seen", f"лҲ„лқҪл¶„н•ҙ {stage}")
            for k in missing[:40]:
                _v305_count(V305_HUB_MISSING_FIELD_COUNTS, k)
            _v305_count(V305_HUB_MISSING_STAGE_COUNTS, stage or "hub")
            _v305_count(V305_HUB_MISSING_SOURCE_COUNTS, source or "unknown")
            try:
                if isinstance(row, dict):
                    row["v305_missing_fields_before_standardize"] = missing[:40]
                    row["v305_flow_position"] = "н—ҲлёҢ/кіөмһҘ row н‘ңмӨҖнҷ”"
            except Exception:
                pass
    except Exception:
        pass
    if callable(_BASE_ENSURE_V304_HUB_ROW_DEFAULTS_V305):
        return _BASE_ENSURE_V304_HUB_ROW_DEFAULTS_V305(row, stage=stage, source=source)
    return row


def _v305_trace_rows_for_ticker(ticker: str, lookback: int = 900) -> list:
    try:
        t = str(ticker or "").upper().strip()
        if not t:
            return []
        rows = reverse_trace_logs if isinstance(globals().get("reverse_trace_logs", []), list) else []
        return [r for r in rows[-max(20, int(lookback)):] if isinstance(r, dict) and str(r.get("ticker", "") or "").upper().strip() == t]
    except Exception:
        return []


def _v305_force_trace_reason_for_ticker(ticker: str, meta: dict = None) -> str:
    try:
        t = str(ticker or "").upper().strip()
        if not t:
            return "нӢ°м»Өм—ҶмқҢ"
        if _v305_trace_rows_for_ticker(t, lookback=1200):
            return "traceмһҲмқҢ"
        cache_row = {}
        if isinstance(shared_market_cache, dict) and isinstance(shared_market_cache.get(t), dict):
            cache_row = dict(shared_market_cache.get(t) or {})
        price = _v304_price_from_row(cache_row) if '_v304_price_from_row' in globals() else safe_float(cache_row.get('price', 0), 0)
        if not cache_row:
            return "мәҗмӢңм—ҶмқҢ/м§ҒмӣҗлҢҖкё°"
        if price <= 0:
            return "к°ҖкІ©м—ҶмқҢ"
        if bool(cache_row.get("rank_tick_noise_block", False)) or bool(cache_row.get("ultra_low_tick_noise_block", False)):
            return "нӢұл…ёмқҙмҰҲм ңмҷё"
        if bool(cache_row.get("rank_precision_watch", False)):
            return "м •л°Җк°җмӢңм§Җл§Ң traceмӢңлҸ„м „"
        money = _v304_money_from_row(cache_row) if '_v304_money_from_row' in globals() else safe_float(cache_row.get('turnover_5m', 0), 0)
        trade_cnt = max(int(safe_float(cache_row.get('trade_count_60s', 0), 0)), int(safe_float(cache_row.get('ws_trade_count_60s', 0), 0)), int(safe_float(cache_row.get('trade_count', 0), 0)))
        if money <= 0:
            return "лҢҖкёҲлҜёнҷ•мқё"
        if trade_cnt <= 0:
            return "мІҙкІ°н‘ңліём—ҶмқҢ"
        return "traceмЎ°кұҙлҜём¶©мЎұ/ліөкё°лҢҖкё°"
    except Exception:
        return "мӣҗмқёнҢҗлӢЁмҳӨлҘҳ"


