def force_detail_ticker_into_rank_pool_v302(ticker: str, reason: str = "detail_v305") -> bool:
    t = str(ticker or "").upper().strip()
    before = len(_v305_trace_rows_for_ticker(t, lookback=1200)) if t else 0
    ok = False
    try:
        ok = bool(_BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V305(t, reason=reason)) if callable(_BASE_FORCE_DETAIL_TICKER_INTO_RANK_POOL_V305) else False
    except Exception as e:
        try:
            append_runtime_error_log("v305_force_detail_base", str(e), exc=e, extra={"ticker": t, "reason": reason}, include_traceback=False)
        except Exception:
            pass
    try:
        after = len(_v305_trace_rows_for_ticker(t, lookback=1200)) if t else 0
        if after > before:
            _v305_inc("force_trace_saved", f"к°•м ңк°җмӢң traceнҷ•мқё {t}")
        else:
            why = _v305_force_trace_reason_for_ticker(t, meta={})
            _v305_count(V305_FORCE_TRACE_REASON_COUNTS, why)
            if why == "traceмһҲмқҢ":
                _v305_inc("force_trace_saved", f"к°•м ңк°җмӢң кё°мЎҙtrace {t}")
            else:
                _v305_inc("force_trace_no_attempt", f"к°•м ңк°җмӢң traceлҜёнҷ•мқё {t}/{why}")
                append_runtime_event_log("v305_force_trace_reason", "к°•м ңк°җмӢң trace лҜём ҖмһҘ/лҜёмӢңлҸ„ мқҙмң ", extra={
                    "ticker": t,
                    "reason": why,
                    "detail_reason": reason,
                    "schema": V305_SCHEMA_VERSION,
                    "flow_position": "3м°Ё к°•м ңк°җмӢң вҶ’ м°Ҫкі /trace",
                })
    except Exception:
        pass
    return ok


def _v305_forced_watch_snapshot() -> dict:
    out = {"forced": 0, "cache": 0, "trace": 0, "reasons": {}}
    try:
        forced = globals().get("LIGHT_SNAPSHOT_FORCE_TRACK_TICKERS", {})
        if not isinstance(forced, dict):
            return out
        out["forced"] = len(forced)
        for ft, meta in list(forced.items()):
            t = str(ft or "").upper().strip()
            if not t:
                continue
            if isinstance(shared_market_cache, dict) and t in shared_market_cache:
                out["cache"] += 1
            reason = _v305_force_trace_reason_for_ticker(t, meta=meta if isinstance(meta, dict) else {})
            if reason == "traceмһҲмқҢ":
                out["trace"] += 1
            else:
                out["reasons"][reason] = out["reasons"].get(reason, 0) + 1
    except Exception:
        pass
    return out


def _v305_cancel_watch_row_for_ticker(ticker: str) -> dict:
    try:
        t = str(ticker or "").upper().strip()
        if not t:
            return {}
        _v302_load_cancel_watch_state()
        now_ts = time.time()
        with PAPER_CANCEL_WATCH_LOCK_V302:
            rows = [dict(v) for v in (PAPER_CANCEL_WATCH_STATE_V302 or {}).values() if isinstance(v, dict) and str(v.get("ticker", "") or "").upper().strip() == t]
        rows = [r for r in rows if safe_float(r.get("cancel_ts", 0), 0) > 0 and now_ts - safe_float(r.get("cancel_ts", 0), 0) <= PAPER_CANCEL_WATCH_TTL_SEC_V302]
        rows.sort(key=lambda r: (safe_float(r.get("max_up_after_cancel_pct", 0), 0), safe_float(r.get("current_after_cancel_pct", 0), 0), safe_float(r.get("cancel_ts", 0), 0)), reverse=True)
        return rows[0] if rows else {}
    except Exception:
        return {}


def is_v305_cancel_rewatch_candidate(row: dict) -> bool:
    try:
        row = row if isinstance(row, dict) else {}
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker or bool(row.get("rank_tick_noise_block", False)):
            return False
        cw = _v305_cancel_watch_row_for_ticker(ticker)
        if not cw:
            return False
        max_up = safe_float(cw.get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float(cw.get("current_after_cancel_pct", 0), 0)
        if max_up >= V305_CANCEL_REWATCH_STRONG_UP_PCT:
            return True
        if max_up >= V305_CANCEL_REWATCH_MIN_UP_PCT and cur_up >= V305_CANCEL_REWATCH_MIN_CURRENT_UP_PCT:
            return True
        return False
    except Exception:
        return False


