def _v268_now_strength(cls: dict, row: dict = None) -> dict:
    st = dict(_BASE_V268_NOW_STRENGTH_V305(cls, row) if callable(_BASE_V268_NOW_STRENGTH_V305) else {})
    try:
        if not bool(st.get("direct_ok", False)):
            return st
        money = safe_float(st.get("money", 0), 0)
        trade_count = int(safe_float(st.get("trade_count", 0), 0))
        buy_ratio = safe_float(st.get("buy_ratio", 0), 0)
        candle_weak = bool(st.get("candle_weak", False))
        pressure = 0.0
        try:
            r = row if isinstance(row, dict) else {}
            pressure = safe_float(r.get("current_candle_pressure_score", r.get("candle_pressure_score", 0)), 0)
            label_txt = " ".join(str(r.get(k, "") or "") for k in ("current_candle_label", "rank_watch_action", "final_candidate_state_v251"))
            if any(x in label_txt for x in ("л§үнҢҗк°•л°ҖлҰј", "мң„кј¬лҰ¬к°•л°ҖлҰј", "нҳ„мһ¬лҙү л°ҖлҰј")):
                candle_weak = True
        except Exception:
            pass
        sell_heavy = bool((trade_count >= 3 and buy_ratio > 0 and buy_ratio <= V305_NOW_DIRECT_SELL_BUY_RATIO_MAX) or pressure >= V305_NOW_DIRECT_PRESSURE_BLOCK_SCORE or candle_weak)
        if sell_heavy:
            st["direct_ok"] = False
            st["v305_direct_demoted"] = True
            st["cancel_reason"] = "л°”лЎңм§„мһ… кёҲм§Җ: л§ӨлҸ„мҡ°м„ё/нҳ„мһ¬лҙү л°ҖлҰј вҶ’ мӨҖл№„лҢҖкё°"
            _v305_inc("now_direct_demoted", f"л°”лЎңм§„мһ… мӨҖл№„лҢҖкё° м „нҷҳ {str((cls or {}).get('ticker','?'))}")
            # нӣ„ліҙ мһҗмІҙлҠ” мЈҪмқҙм§Җ м•ҠлҠ”лӢӨ. лҸҲмқҙ м•„мЈј м–Үм§Җ м•Ҡмңјл©ҙ м§„мһ… м „ мӨҖл№„/мһ¬нҷ•мқёмңјлЎң лҸҢлҰ°лӢӨ.
            if money >= PAPER_V302_NOW_PREPARE_MONEY_MIN and not bool(st.get("true_discard", False)):
                st["prepare_ok"] = True
                st["v305_prepare_after_direct_block"] = True
                _v305_inc("now_prepare_after_demote", f"мӨҖл№„лҢҖкё° мң м§Җ {str((cls or {}).get('ticker','?'))}")
        return st
    except Exception as e:
        try:
            append_runtime_error_log("v305_now_strength_split", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return st


