def _v305_status_lines(compact: bool = True) -> list:
    forced = _v305_forced_watch_snapshot()
    force_reason_txt = _v305_top_counts_text(forced.get("reasons", {}), limit=2)
    miss_field_txt = _v305_top_counts_text(V305_HUB_MISSING_FIELD_COUNTS, limit=3)
    miss_stage_txt = _v305_top_counts_text(V305_HUB_MISSING_STAGE_COUNTS, limit=2)
    lines = [
        "рҹ§ӯ v2.5.305 мҲҳм •мң„м№ҳ/мһ¬к°җмӢң нқҗлҰ„",
        "- мң„м№ҳ: н—ҲлёҢ/кіөмһҘ лҲ„лқҪл¶„н•ҙ + 3м°Ё к°•м ңк°җмӢң/м°Ҫкі  traceмӣҗмқё + paper м·ЁмҶҢнӣ„ мһ¬к°җмӢң + л°”лЎңм§„мһ… л¬ён„ұл¶„лҰ¬",
        f"- н—ҲлёҢлҲ„лқҪ: н•„л“ң {miss_field_txt} / кІҪлЎң {miss_stage_txt}",
        f"- к°•м ңк°җмӢң trace: л“ұлЎқ {forced.get('forced',0)} / мәҗмӢң {forced.get('cache',0)} / traceмһҲмқҢ {forced.get('trace',0)} / лҜём ҖмһҘмқҙмң  {force_reason_txt}",
        f"- мһ¬к°җмӢң/м§„мһ…л¬ён„ұ: м·ЁмҶҢнӣ„мһ¬к°җмӢң {V305_STATS.get('cancel_rewatch_promoted',0)} / м •л°Җн—Ҳмҡ© {V305_STATS.get('cancel_rewatch_precision_allowed',0)} / л°”лЎңм§„мһ…вҶ’мӨҖл№„ {V305_STATS.get('now_direct_demoted',0)}",
        "- кё°мӨҖ: мЎ°кұҙ м „мІҙ к°•нҷ” м•„лӢҳ. нӣ„ліҙлҠ” мӮҙлҰ¬кі , л°”лЎңм§„мһ…/мһ¬к°җмӢң/кё°лЎқ л¬ён„ұл§Ң лӮҳлҲ”",
    ]
    return lines[:5] if compact else lines


def _v302_status_lines(compact: bool = True) -> list:
    base = list(_BASE_V302_STATUS_LINES_V305(compact=compact)) if callable(_BASE_V302_STATUS_LINES_V305) else []
    return base + _v305_status_lines(compact=compact)


