def _v306_status_lines() -> list:
    try:
        return [
            "рҹ§Ә v2.5.306 APE/DOGE л°”лЎңм§„мһ… ліҙк°•",
            "- мң„м№ҳ: 2м°Ё нӣ„ліҙ л¶„лҘҳ вҶ’ 3м°Ё м§„мһ… м „ мӨҖл№„ вҶ’ paper кІҖмҰқ / мЎ°кұҙ м „мІҙ к°•нҷ” м•„лӢҳ",
            f"- л°”лЎңм§„мһ…вҶ’мӨҖл№„ {V306_STATS.get('paper_direct_to_prepare',0)} / лӮ®мқҖм җмҲҳ {V306_STATS.get('paper_direct_low_score_block',0)} / н‘ңліёл¶ҖмЎұ {V306_STATS.get('paper_direct_thin_sample_block',0)} / нҳ„мһ¬лҙүВ·л§ӨлҸ„мҡ°м„ё {V306_STATS.get('paper_direct_candle_block',0)}",
            f"- мІӯмӮ° мөңкі /мөңм Җ ліҙм • {V306_STATS.get('paper_range_fix_on_close',0)} / мөңк·ј {V306_STATS.get('last_note','лҢҖкё°')}",
        ]
    except Exception as e:
        return [f"рҹ§Ә v2.5.306 н‘ңмӢң мҳӨлҘҳ: {e}"]


def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_V306()) if callable(_BASE_CACHE_STATUS_V306) else "рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status"
    try:
        if "рҹ§Ә v2.5.306 APE/DOGE л°”лЎңм§„мһ… ліҙк°•" not in base:
            base += "\n" + "\n".join(_v306_status_lines())
    except Exception:
        pass
    return base


def build_cache_status_full_text():
    try:
        base = build_cache_status_text()
        return base
    except Exception:
        return build_cache_status_text()

# =========================================================
# v2.5.307: v306 л°°м№ҳмң„м№ҳ мҲҳм • + м„ұкіјл¶„н•ҙ/мһ¬к°җмӢң ліём„  ліҙк°•
# мң„м№ҳ: paperВ·trace + 2м°Ё/3м°Ё м§„мһ…л¬ён„ұ + м¶ңл Ҙ
# н•өмӢ¬:
# - v306 APE/DOGE л°”лЎңм§„мһ… ліҙк°• лё”лЎқмқҙ main() м•„лһҳм—җ мһҲм–ҙ мӢӨн–үлҗҳм§Җ м•ҠлҚҳ л°°м№ҳ л¬ём ңлҘј мҲҳм •н•ңлӢӨ.
# - мЎ°кұҙ м „мІҙ к°•нҷ”к°Җ м•„лӢҲлқј paper л°”лЎңм§„мһ… л¬ёл§Ң лҚ” л¶„лҰ¬н•ңлӢӨ.
# - /paper_statsм—җ л¬ён„ұлі„ м„ұкіјлҘј л¶ҷм—¬ м–ҙлҠҗ л¬ём—җм„ң мҶҗмӢӨмқҙ лӮҳлҠ”м§Җ ліҙмқҙкІҢ н•ңлӢӨ.
# =========================================================
V307_SCHEMA_VERSION = "paper_route_perf_v307"
V307_STATS = {
    "late_patch_position_fixed": 1,
    "paper_direct_final_guard": 0,
    "paper_direct_to_prepare_v307": 0,
    "paper_route_stats_rendered": 0,
    "rewatch_return_candidate_seen": 0,
    "last_note": "v306 лё”лЎқмқ„ main() мӢӨн–ү м „мңјлЎң мқҙлҸҷ",
}
V307_DIRECT_PRESSURE_BLOCK = 1.00
V307_DIRECT_MIN_TRADE_COUNT = 10
V307_DIRECT_MIN_SCORE_WITH_SMALL_SAMPLE = 6.40
V307_DIRECT_SELL_HEAVY_BUY_RATIO_MAX = 45.0
V307_REWATCH_RETURN_STRONG_UP = 1.50
V307_REWATCH_RETURN_KEEP_CURRENT = 0.70


def _v307_inc(key: str, note: str = ""):
    try:
        if key in V307_STATS:
            V307_STATS[key] = int(safe_float(V307_STATS.get(key, 0), 0)) + 1
        if note:
            V307_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v307_text_blob(row: dict, cls: dict = None) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        vals = []
        for src in (row, cls):
            for k in (
                "current_candle_label", "current_candle_code", "rank_watch_action", "rank_watch_explain",
                "final_candidate_state_v251", "decision", "signal_decision", "money_flow_text",
                "rank_reason", "watch_route", "trace_reason", "paper_v306_direct_block_reason", "paper_v307_direct_block_reason",
            ):
                v = src.get(k, "") if isinstance(src, dict) else ""
                if v:
                    vals.append(str(v))
            rs = src.get("reasons", []) if isinstance(src, dict) else []
            if isinstance(rs, list):
                vals.extend(str(x) for x in rs[:10])
            elif rs:
                vals.append(str(rs))
        return " ".join(vals)
    except Exception:
        return ""


def _v307_final_direct_guard_reason(row: dict, cls: dict) -> str:
    """v306мқҙ мӢӨн–үлҗҳлҚ”лқјлҸ„ л§Ҳм§Җл§ү н•ң лІҲ лҚ” paper л°”лЎңм§„мһ… л¬ёл§Ң м җкІҖн•ңлӢӨ.

    мЎ°кұҙ м „мІҙ к°•нҷ”к°Җ м•„лӢҲлӢӨ. BUY_OK нӣ„ліҙлҘј DISCARDн•ҳм§Җ м•Ҡкі  PULLBACK_WAIT/мӨҖл№„лҢҖкё°лЎң лӮҙлҰ°лӢӨ.
    MBX н‘ңліёмІҳлҹј лҸҲмқҖ нҒ¬м§Җл§Ң л°ҳм§қнҳ•/нҳ„мһ¬лҙү л°ҖлҰј/л§ӨлҸ„мҡ°м„ёмқёлҚ° мӢӨм „кёү л°”лЎңм§„мһ…мңјлЎң м—ҙлҰ¬лҠ” кІғмқ„ л§үлҠ”лӢӨ.
    """
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        grade = str(cls.get("grade", row.get("grade", "")) or "").upper().strip()
        if grade != "BUY_OK":
            return ""
        score = safe_float(cls.get("score", row.get("score", 0)), 0)
        trade_count = int(safe_float(cls.get("trade_count", row.get("trade_count", row.get("trade_count_60s", 0))), 0))
        buy_ratio = safe_float(cls.get("buy_ratio", row.get("buy_ratio", row.get("buy_ratio_60s", 0))), 0)
        pressure = safe_float(row.get("current_candle_pressure_score", row.get("candle_pressure_score", cls.get("current_candle_pressure_score", 0))), 0)
        txt = _v307_text_blob(row, cls)
        has_sell_heavy = any(x in txt for x in ["л§ӨлҸ„мҡ°м„ё", "л§ӨлҸ„ мҡ°м„ё", "лҸҲмқҖ нҒ¬м§Җл§Ң л§ӨлҸ„мҡ°м„ё"])
        has_candle_weak = any(x in txt for x in ["л§үнҢҗк°•л°ҖлҰј", "л§үнҢҗ л°ҖлҰј", "мң„кј¬лҰ¬к°•л°ҖлҰј", "мң„кј¬лҰ¬ л°ҖлҰј", "нҳ„мһ¬лҙү л°ҖлҰј", "мң„кј¬лҰ¬/нҳ„мһ¬лҙү л°ҖлҰј"])
        has_flash = any(x in txt for x in ["л°ҳм§қнҳ•", "мӢқлҠ”мӨ‘", "л°ҳм§қ/мӢқлҠ”мӨ‘"])
        if pressure >= V307_DIRECT_PRESSURE_BLOCK or has_candle_weak:
            return "нҳ„мһ¬лҙү л°ҖлҰј/мң„кј¬лҰ¬лқј л°”лЎңм§„мһ… кёҲм§Җ"
        if has_sell_heavy:
            return "л§ӨлҸ„мҡ°м„ёлқј л°”лЎңм§„мһ… кёҲм§Җ"
        if has_flash:
            return "л°ҳм§қнҳ•/мӢқлҠ”мӨ‘мқҙлқј л°”лЎңм§„мһ…ліҙлӢӨ мһ¬к°җмӢң"
        if trade_count > 0 and trade_count < V307_DIRECT_MIN_TRADE_COUNT and score < V307_DIRECT_MIN_SCORE_WITH_SMALL_SAMPLE:
            return f"м җмҲҳ {score:.2f}В·мІҙкІ° {trade_count}кұҙмқҙлқј л°”лЎңм§„мһ…ліҙлӢӨ мӨҖл№„лҢҖкё°"
        if trade_count >= 3 and buy_ratio > 0 and buy_ratio <= V307_DIRECT_SELL_HEAVY_BUY_RATIO_MAX and score < 7.0:
            return f"л§ӨмҲҳл№„мңЁ {buy_ratio:.0f}%лЎң м•Ҫн•ҙ л°”лЎңм§„мһ… ліҙлҘҳ"
        return ""
    except Exception as e:
        try:
            append_runtime_error_log("v307_final_direct_guard_reason", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return ""


try:
    _BASE_PAPER_CLASSIFY_V307 = _paper_classify_for_register_v258
except Exception:
    _BASE_PAPER_CLASSIFY_V307 = None


def _paper_classify_for_register_v258(row: dict):
    if not callable(_BASE_PAPER_CLASSIFY_V307):
        return False, "", "л¶„лҘҳн•ЁмҲҳм—ҶмқҢ", {}
    ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V307(row)
    try:
        if ok and isinstance(cls, dict) and str(cls.get("grade", "") or "").upper().strip() == "BUY_OK":
            guard = _v307_final_direct_guard_reason(row if isinstance(row, dict) else {}, cls)
            if guard:
                original_grade = str(cls.get("grade", "BUY_OK") or "BUY_OK")
                cls = dict(cls)
                cls["paper_original_grade"] = str(cls.get("paper_original_grade", original_grade) or original_grade)
                cls["paper_v307_direct_block_reason"] = guard
                cls["paper_v307_flow_position"] = "2м°Ё нӣ„ліҙ вҶ’ 3м°Ё м§„мһ… м „ мӨҖл№„ вҶ’ paper кІҖмҰқ"
                cls["grade"] = "PULLBACK_WAIT"
                cls["decision"] = "л°”лЎңм§„мһ… ліҙлҘҳ / м§„мһ… м „ мӨҖл№„"
                lane = str(lane or "strict_signal") + "_prepare_v307"
                reason = (str(reason or "мӢ нҳёмёө") + " / v307 л°”лЎңм§„мһ… ліҙлҘҳ: " + guard)[:260]
                _v307_inc("paper_direct_final_guard", f"мөңмў… л°”лЎңм§„мһ… ліҙлҘҳ {str((row or {}).get('ticker', cls.get('ticker','?')))}")
                _v307_inc("paper_direct_to_prepare_v307", f"л°”лЎңм§„мһ…вҶ’мӨҖл№„ {guard}")
        return ok, lane, reason, cls
    except Exception as e:
        try:
            append_runtime_error_log("v307_paper_classify", str(e), exc=e, include_traceback=False)
        except Exception:
            pass
        return ok, lane, reason, cls


def _v307_paper_route_label(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        lane = str(row.get("lane", "") or "")
        entry_rule = str(row.get("entry_rule", "") or "")
        sig = str(row.get("signal_grade", row.get("original_grade", "")) or "").upper()
        reason = str(row.get("register_reason", "") or "")
        close_reason = str(row.get("close_reason", "") or "")
        if "prepare_v307" in lane or "prepare_v306" in lane or row.get("paper_v307_direct_block_reason"):
            return "л°”лЎңм§„мһ… ліҙлҘҳвҶ’мӨҖл№„"
        if "мІҙкІ°нқҗлҰ„" in reason or "flow" in lane.lower():
            return "мІҙкІ°нқҗлҰ„ м§„мһ…лҢҖкё°"
        if entry_rule == "now" or sig == "BUY_OK":
            return "л°”лЎңм§„мһ…нҳ•"
        if entry_rule == "pullback" or sig == "PULLBACK_WAIT":
            return "лҲҢлҰј/мӨҖл№„лҢҖкё°"
        if entry_rule == "breakout" or sig == "BREAKOUT_WAIT":
            return "лҸҢнҢҢлҢҖкё°"
        if "cancel" in close_reason.lower() or str(row.get("status", "")).upper() == "CANCELLED":
            return "м·ЁмҶҢ/лҜём§„мһ…"
        return "кё°нғҖ"
    except Exception:
        return "кё°нғҖ"


def _v307_route_stats_section(rows: list, title: str = "мөңк·ј 6мӢңк°„") -> list:
    try:
        groups = {}
        for r in list(rows or []):
            if not isinstance(r, dict):
                continue
            label = _v307_paper_route_label(r)
            groups.setdefault(label, []).append(r)
        order = ["л°”лЎңм§„мһ…нҳ•", "л°”лЎңм§„мһ… ліҙлҘҳвҶ’мӨҖл№„", "мІҙкІ°нқҗлҰ„ м§„мһ…лҢҖкё°", "лҲҢлҰј/мӨҖл№„лҢҖкё°", "лҸҢнҢҢлҢҖкё°", "кё°нғҖ"]
        out = [f"[v307 л¬ён„ұлі„ м„ұкіј - {title}]", "- лӘ©м Ғ: мЎ°кұҙ м „мІҙ к°•нҷ”к°Җ м•„лӢҲлқј м–ҙлҠҗ л¬ём—җм„ң мҶҗмӢӨлӮҳлҠ”м§Җ л¶„н•ҙ"]
        any_line = False
        for label in order:
            vals = groups.get(label, [])
            if vals:
                any_line = True
                out.append(_paper_stats_line_v258(label, vals))
        if not any_line:
            out.append("- м•„м§Ғ м§‘кі„н•  мў…лЈҢ кұ°лһҳ м—ҶмқҢ")
        _v307_inc("paper_route_stats_rendered", "л¬ён„ұлі„ м„ұкіј м¶ңл Ҙ")
        return out
    except Exception as e:
        return [f"[v307 л¬ён„ұлі„ м„ұкіј] мғқм„ұ мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:120]}"]


try:
    _BASE_BUILD_PAPER_STATS_V307 = build_paper_stats_text_v258
except Exception:
    _BASE_BUILD_PAPER_STATS_V307 = None


def build_paper_stats_text_v258() -> str:
    base = str(_BASE_BUILD_PAPER_STATS_V307()) if callable(_BASE_BUILD_PAPER_STATS_V307) else "рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats"
    try:
        now_ts = time.time()
        rows = _paper_closed_logs_v258()
        recent6 = [r for r in rows if safe_float(r.get("close_ts", 0), 0) >= now_ts - 6 * 3600]
        section = _v307_route_stats_section(recent6, title="мөңк·ј 6мӢңк°„")
        if "[v307 л¬ён„ұлі„ м„ұкіј" not in base:
            base += "\n\n" + "\n".join(section)
    except Exception as e:
        base += f"\n\n[v307 л¬ён„ұлі„ м„ұкіј] н‘ңмӢң мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:120]}"
    return base


def _v307_status_lines() -> list:
    return [
        "рҹ§Ә v2.5.307 м„ұкіјл¶„н•ҙ/л°”лЎңм§„мһ… мөңмў…к°Җл“ң",
        "- мң„м№ҳ: paperВ·trace + 2м°Ё нӣ„ліҙл¶„лҘҳ + 3м°Ё м§„мһ… м „ мӨҖл№„ + м¶ңл Ҙ / мЎ°кұҙ м „мІҙ к°•нҷ” м•„лӢҳ",
        "- л°°м№ҳмҲҳм •: v306 ліҙк°• лё”лЎқмқ„ main() мӢӨн–ү м „мңјлЎң мқҙлҸҷн•ҙ мӢӨм ң мӢӨн–үлҗҳкІҢ н•Ё",
        f"- л°”лЎңм§„мһ… мөңмў…к°Җл“ң {V307_STATS.get('paper_direct_final_guard',0)} / л°”лЎңм§„мһ…вҶ’мӨҖл№„ {V307_STATS.get('paper_direct_to_prepare_v307',0)} / м„ұкіјн‘ңм¶ңл Ҙ {V307_STATS.get('paper_route_stats_rendered',0)}",
        f"- мөңк·ј: {V307_STATS.get('last_note','лҢҖкё°')}",
    ]


