def build_paper_stats_text_v258() -> str:
    base = str(_BASE_BUILD_PAPER_STATS_V308()) if callable(_BASE_BUILD_PAPER_STATS_V308) else "рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats"
    try:
        rows = _paper_closed_logs_v258() if '_paper_closed_logs_v258' in globals() else []
        since = [r for r in rows if safe_float(r.get("close_ts", 0), 0) >= V308_MODULE_LOAD_TS]
        if "[v308 м Ғмҡ© мқҙнӣ„ м„ұкіј" not in base:
            base += "\n\n[v308 м Ғмҡ© мқҙнӣ„ м„ұкіј - м°ёкі ]\n"
            base += "- лӘ©м Ғ: мғҲ л¬ён„ұмқҙ лЁ№мқҖ л’Ө н‘ңліёл§Ң л”°лЎң ліҙкё°. н‘ңліё м Ғмңјл©ҙ м•„м§Ғ нҢҗлӢЁ ліҙлҘҳ\n"
            base += _paper_stats_line_v258("v308 мқҙнӣ„", since)
    except Exception as e:
        base += f"\n\n[v308 мқҙнӣ„ м„ұкіј н‘ңмӢң мҳӨлҘҳ: {e.__class__.__name__}]"
    return base


