def _v308_event_check_line(ts: float) -> str:
    try:
        return f"м°ЁнҠёкІҖмҰқ: л№—мҚё 1л¶„лҙү { _v308_time_window_text(ts, 10, 10) } кө¬к°„м—җм„ң лҙҮ лҚ°мқҙн„°мҷҖ л№„көҗ"
    except Exception:
        return "м°ЁнҠёкІҖмҰқ: /review_sampleм—җм„ң кё°мӨҖмӢңк°Ғ нҷ•мқё"


def _paper_v301_send_entry_alert(pos: dict):
    """v308: н…”л Ҳк·ёлһЁ лӘЁмқҳл§ӨмҲҳ м•ҢлҰјм—җ м°ЁнҠё кІҖмҰқ кё°мӨҖмӢңк°Ғмқ„ к°ҷмқҙ л„ЈлҠ”лӢӨ."""
    if not PAPER_ALERTS_V301_ON:
        return
    try:
        # v306 мӨҖл№„лҢҖкё° м „нҷҳ нӣ„ліҙлҠ” мҰүмӢң м•ҢлҰјмңјлЎң л°Җм§Җ м•ҠлҠ”лӢӨ.
        if str((pos or {}).get("lane", "")) and ("prepare_v306" in str((pos or {}).get("lane", "")) or "prepare_v307" in str((pos or {}).get("lane", ""))) and str((pos or {}).get("status", "")).upper() != "OPEN":
            return None
        ticker = str(pos.get("ticker", "?") or "?").upper().strip()
        entry = safe_float(pos.get("entry_price", 0), 0)
        stop = safe_float(pos.get("stop", 0), 0)
        tp1 = safe_float(pos.get("tp1", 0), 0); tp2 = safe_float(pos.get("tp2", 0), 0); tp3 = safe_float(pos.get("tp3", 0), 0)
        lane = _paper_v301_easy_lane(pos.get("lane", "")); rule = _paper_v301_easy_rule(pos.get("entry_rule", ""))
        reason = _paper_v301_easy_reason(pos.get("register_reason", pos.get("signal_decision", "")))
        score = safe_float(pos.get("score", 0), 0); money = safe_float(pos.get("money_amount", 0), 0)
        trade_count = int(safe_float(pos.get("trade_count", 0), 0)); buy_ratio = safe_float(pos.get("buy_ratio", 0), 0)
        ts = safe_float(pos.get("entered_ts", pos.get("created_ts", time.time())), time.time())
        lines = [
            "рҹ§Ә лӘЁмқҳл§ӨмҲҳ л°ңмғқ",
            "",
            f"мҪ”мқё: {ticker}",
            f"мң нҳ•: {lane} / {rule}",
            f"лӘЁмқҳм§„мһ…к°Җ: {fmt_price_detail(entry)}",
            f"мҶҗм Ҳ: {fmt_price_detail(stop)}",
            f"мқөм Ҳ: TP1 {fmt_price_detail(tp1)} / TP2 {fmt_price_detail(tp2)} / TP3 {fmt_price_detail(tp3)}",
            f"к·јкұ°: {reason}",
            f"м җмҲҳ/лҸҲ/мІҙкІ°: {score:.2f} / {money/100000000:.2f}м–ө / {trade_count}кұҙВ·л§ӨмҲҳ {buy_ratio:.0f}%",
            f"кІҖмҰқкё°мӨҖ: {_v308_ts_text(ts)}",
            _v308_event_check_line(ts),
            "",
            "мЈјмқҳ: мӢӨм ң мЈјл¬ё м•„лӢҳ. лӘЁмқҳл§Өл§Ө кІҖмҰқ м•ҢлҰјмқҙм•ј.",
            "нқҗлҰ„ нҷ•мқё: /paper_flow / кІҖмҰқн‘ңліё: /review_sample",
        ]
        send("\n".join(lines))
        _v308_inc("entry_alert_patched", f"лӘЁмқҳл§ӨмҲҳ м•ҢлҰј {ticker}")
        try: _v301_inc("entry_alerts", f"лӘЁмқҳл§ӨмҲҳ м•ҢлҰј {ticker}")
        except Exception: pass
    except Exception as e:
        try: append_runtime_error_log("paper_v308_entry_alert", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _paper_v301_send_exit_alert(row: dict):
    """v308: лӘЁмқҳмІӯмӮ° м•ҢлҰјм—җлҸ„ м§„мһ…~мІӯмӮ° м°ЁнҠё л№„көҗ мӢңк°„лҢҖлҘј н‘ңмӢңн•ңлӢӨ."""
    if not PAPER_ALERTS_V301_ON:
        return
    try:
        ticker = str(row.get("ticker", "?") or "?").upper().strip()
        pnl = safe_float(row.get("pnl_pct", 0), 0); gross = safe_float(row.get("gross_pnl_pct", pnl), pnl)
        entry = safe_float(row.get("entry_price", 0), 0); close_price = safe_float(row.get("close_price", row.get("last_price", 0)), 0)
        reason = _paper_v301_easy_reason(row.get("close_reason", ""))
        held = int(max(0, safe_float(row.get("held_sec", 0), 0)))
        max_up = safe_float(row.get("max_up_pct", 0), 0); min_down = safe_float(row.get("min_down_pct", 0), 0)
        lane = _paper_v301_easy_lane(row.get("lane", ""))
        result_icon = "вң…" if pnl > 0 else ("вҡ пёҸ" if pnl < 0 else "вһ–")
        enter_ts = safe_float(row.get("entered_ts", row.get("created_ts", 0)), 0)
        close_ts = safe_float(row.get("close_ts", time.time()), time.time())
        lines = [
            f"рҹ§Ә лӘЁмқҳмІӯмӮ° кІ°кіј {result_icon}",
            "",
            f"мҪ”мқё: {ticker}",
            f"кІ°кіј: {pnl:+.2f}% / мҲҳмҲҳлЈҢм „ {gross:+.2f}%",
            f"мң нҳ•: {lane}",
            f"м§„мһ…вҶ’мІӯмӮ°: {fmt_price_detail(entry)} вҶ’ {fmt_price_detail(close_price)}",
            f"мӮ¬мң : {reason}",
            f"ліҙмң мӢңк°„: {held//60}л¶„ {held%60}мҙҲ",
            f"мөңкі /мөңм Җ: {max_up:+.2f}% / {min_down:+.2f}%",
            f"кІҖмҰқкё°мӨҖ: м§„мһ… {_v308_ts_text(enter_ts)} вҶ’ мІӯмӮ° {_v308_ts_text(close_ts)}",
            f"м°ЁнҠёкІҖмҰқ: л№—мҚё 1л¶„лҙү { _v308_time_window_text(enter_ts or close_ts, 10, max(10, int(held/60)+5)) } кө¬к°„ нҷ•мқё",
            "",
            "мЈјмқҳ: мӢӨм ң мЈјл¬ё м•„лӢҳ. лӘЁмқҳл§Өл§Ө кІҖмҰқ м•ҢлҰјмқҙм•ј.",
            "нқҗлҰ„ нҷ•мқё: /paper_flow / кІҖмҰқн‘ңліё: /review_sample",
        ]
        send("\n".join(lines))
        _v308_inc("exit_alert_patched", f"лӘЁмқҳмІӯмӮ° м•ҢлҰј {ticker}/{pnl:+.2f}%")
        try: _v301_inc("exit_alerts", f"лӘЁмқҳмІӯмӮ° м•ҢлҰј {ticker}/{pnl:+.2f}%")
        except Exception: pass
    except Exception as e:
        try: append_runtime_error_log("paper_v308_exit_alert", str(e), exc=e, include_traceback=False)
        except Exception: pass


