# =========================================================
# v2.5.310: мҲҳмқөлҘ  ліём„  мһ¬л°°м№ҳ + review_sample лҚ°мқҙн„°н’Ҳм§Ҳ ліҙк°•
# мң„м№ҳ: н—ҲлёҢ мӢңк°Ғн‘ңмӢң + кіөмһҘ OHLC н‘ңмӢңл¶„лҰ¬ + м°Ҫкі  today/history + м¶ңл Ҙ + м•ҢлҰјмӢңк°Ғ
# н•өмӢ¬:
# - KST н‘ңмӢңлҘј кі м •н•ңлӢӨ. UTC/лЎңм»¬ нҳјлҸҷмқ„ л§үлҠ”лӢӨ.
# - 1л¶„лҙү OHLCмҷҖ кІҖмҰқкө¬к°„ мөңкі /мөңм ҖлҘј л¶„лҰ¬н•ҙм„ң ліҙм—¬мӨҖлӢӨ.
# - мҳӨлҠҳ н‘ңліё л¶ҖмЎұ мӢң мөңк·ј 24мӢңк°„ ліҙм¶© н‘ңліёмһ„мқ„ лӘ…нҷ•нһҲ н‘ңмӢңн•ңлӢӨ.
# - н‘ңліёлі„ нҢЁн„ҙ нғңк·ёмҷҖ мІҙнҒ¬лҰ¬мҠӨнҠёлҘј л¶ҷм—¬ л№—мҚё м°ЁнҠё кІҖмҰқмқ„ мүҪкІҢ н•ңлӢӨ.
# - мЎ°кұҙ м „мІҙ к°•нҷ”, мһҗлҸҷл§ӨмҲҳ, мҶҗм Ҳ/TP ліҖкІҪ м—ҶмқҢ.
# =========================================================
V309_SCHEMA_VERSION = "review_sample_v309"
V309_MODULE_LOAD_TS = time.time()
REVIEW_SAMPLE_TODAY_FILE_V309 = data_file("review_sample_today_v309.json")
REVIEW_SAMPLE_HISTORY_FILE_V309 = data_file("review_sample_history_v309.json")
REVIEW_SAMPLE_HISTORY_KEEP_DAYS_V309 = 90
V309_STATS = {
    "sample_generated": 0,
    "sample_reused": 0,
    "history_saved": 0,
    "chart_snapshot_saved": 0,
    "today_samples": 0,
    "fallback_24h_samples": 0,
    "cache_status_shown": 0,
    "last_note": "лҢҖкё°",
}


def _v309_inc(key: str, note: str = ""):
    try:
        if key in V309_STATS:
            V309_STATS[key] = int(safe_float(V309_STATS.get(key, 0), 0)) + 1
        if note:
            V309_STATS["last_note"] = str(note)[:180]
    except Exception:
        pass


def _v309_tz():
    try:
        return ZoneInfo(TIMEZONE)
    except Exception:
        return ZoneInfo("Asia/Seoul")


def _v308_today_key() -> str:
    try:
        return datetime.now(_v309_tz()).strftime("%Y-%m-%d")
    except Exception:
        return time.strftime("%Y-%m-%d", time.localtime(time.time() + 9 * 3600))


def _v309_day_key_from_ts(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return ""
        return datetime.fromtimestamp(ts, _v309_tz()).strftime("%Y-%m-%d")
    except Exception:
        return ""


def _v308_ts_text(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "мӢңк°Ғм—ҶмқҢ"
        return datetime.fromtimestamp(ts, _v309_tz()).strftime("%m-%d %H:%M KST")
    except Exception:
        return "мӢңк°ҒмҳӨлҘҳ"


def _v308_time_window_text(ts: float, minute_before: int = 10, minute_after: int = 10) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "кё°мӨҖмӢңк°Ғ м—ҶмқҢ"
        a = _v308_ts_text(ts - int(minute_before) * 60)
        b = _v308_ts_text(ts + int(minute_after) * 60)
        return f"{a} ~ {b}"
    except Exception:
        return "мӢңк°„лҢҖ кі„мӮ° мҳӨлҘҳ"


def _v309_scope_label(ts: float) -> str:
    try:
        d = _v309_day_key_from_ts(ts)
        today = _v308_today_key()
        if not d:
            return "мӢңк°Ғ нҷ•мқё н•„мҡ”"
        if d == today:
            return "KST мҳӨлҠҳ н‘ңліё"
        return "мөңк·ј24мӢңк°„ ліҙм¶© н‘ңліё"
    except Exception:
        return "н‘ңліёлІ”мң„ нҷ•мқё н•„мҡ”"


def _v309_pick_first_with_key(d: dict, keys: list, default=None):
    try:
        d = d if isinstance(d, dict) else {}
        for k in keys:
            if k in d and d.get(k) not in (None, ""):
                return d.get(k), k
    except Exception:
        pass
    return default, ""


def _v309_pattern_tag(sample: dict) -> str:
    try:
        s = sample if isinstance(sample, dict) else {}
        kind = str(s.get("kind", ""))
        reason = str(s.get("reason", ""))
        snap = s.get("chart_snapshot", {}) if isinstance(s.get("chart_snapshot", {}), dict) else {}
        candle = str(snap.get("current_candle", ""))
        bot_reason = str(snap.get("bot_reason", ""))
        brief = s.get("source_row_brief", {}) if isinstance(s.get("source_row_brief", {}), dict) else {}
        max_after = safe_float(brief.get("max_up_after_cancel_pct", 0), 0)
        cur_after = safe_float(brief.get("current_after_cancel_pct", 0), 0)
        joined = " ".join([kind, reason, candle, bot_reason])
        if "мҶҗмӢӨ" in kind:
            return "мҶҗмӢӨ м§„мһ…л¬ё кІҖмҰқ"
        if "м•ұмӢқ" in kind:
            return "м•ұмӢқ only лҚ°мқҙн„° кІҖмҰқ"
        if max_after >= 3.0:
            if cur_after > 0 and max_after > 0 and cur_after < max_after * 0.55:
                return "к°•н•ң лҶ“м№Ё / нҳ„мһ¬ м¶”кІ©кёҲм§Җ нҷ•мқё"
            return "к°•н•ң лҶ“м№Ё / мһ¬к°җмӢң ліөк·Җ нӣ„ліҙ"
        if "мһ¬к°җмӢң" in kind:
            return "мһ¬к°җмӢң ліөк·Җ нӣ„ліҙ"
        if any(x in joined for x in ["мң„кј¬лҰ¬", "л°ҖлҰј", "л§ӨлҸ„мҡ°м„ё", "л°ҳм§қ"]):
            return "мғҒмң„ ліҙлҘҳ / л°ҖлҰјВ·л°ҳм§қ кІҖмҰқ"
        return "м°ЁнҠё лҚ°мқҙн„° мқјм№ҳ кІҖмҰқ"
    except Exception:
        return "м°ЁнҠё лҚ°мқҙн„° мқјм№ҳ кІҖмҰқ"


def _v308_chart_snapshot(ticker: str, primary: dict = None, rank_row: dict = None, event_ts: float = None, source: str = "") -> dict:
    """v309: мғҲ мЎ°нҡҢ м—Ҷмқҙ м ҖмһҘк°’л§Ң мӮ¬мҡ©н•ҳлҗҳ, нҳ„мһ¬к°Җ/1л¶„лҙү/кІҖмҰқкө¬к°„ н‘ңмӢңлҘј л¶„лҰ¬н•ңлӢӨ."""
    try:
        primary = primary if isinstance(primary, dict) else {}
        rank_row = rank_row if isinstance(rank_row, dict) else {}
        merged = {}
        for src in (rank_row, primary):
            if isinstance(src, dict):
                merged.update(src)
        ts = safe_float(event_ts, 0) or safe_float(_v308_pick_first(merged, ["snapshot_ts", "updated_ts", "last_check_ts", "close_ts", "cancel_ts", "created_ts", "entered_ts"], 0), 0) or time.time()
        price, price_key = _v309_pick_first_with_key(merged, ["price", "current_price", "last_price", "close_price", "entry_price", "cancel_price"], 0)
        open_p, open_key = _v309_pick_first_with_key(merged, ["open", "current_open", "candle_open", "open_price"], 0)
        # нҳ„мһ¬лҙү OHLCлҠ” candle/current кі„м—ҙл§Ң мҡ°м„ н•ңлӢӨ. м·ЁмҶҢнӣ„мөңкі /мөңм ҖлҠ” кІҖмҰқкө¬к°„ м°ёкі к°’мңјлЎң л”°лЎң л‘”лӢӨ.
        high_p, high_key = _v309_pick_first_with_key(merged, ["current_high", "candle_high", "high", "high_price"], 0)
        low_p, low_key = _v309_pick_first_with_key(merged, ["current_low", "candle_low", "low", "low_price"], 0)
        close_p, close_key = _v309_pick_first_with_key(merged, ["current_close", "candle_close", "close", "last_price", "price"], 0)
        range_high, range_high_key = _v309_pick_first_with_key(merged, ["window_high", "range_high", "max_price_after_cancel", "highest_after_cancel", "high_price_after"], 0)
        range_low, range_low_key = _v309_pick_first_with_key(merged, ["window_low", "range_low", "min_price_after_cancel", "lowest_after_cancel", "low_price_after"], 0)
        money = _v308_pick_first(merged, ["money_amount", "turnover_krw", "turnover_recent", "turnover", "recent_turnover", "volume_krw"], 0)
        trade_count = _v308_pick_first(merged, ["trade_count", "trade_count_60s", "ws_trade_count_60s", "count_60s"], 0)
        buy_ratio = _v308_pick_first(merged, ["buy_ratio", "buy_ratio_60s", "ws_buy_ratio_60s"], 0)
        chg1 = _v308_pick_first(merged, ["change_1m", "chg_1m", "change_1", "change_rate_1m", "pct_1m", "rank_chg_1m"], None)
        chg3 = _v308_pick_first(merged, ["change_3m", "chg_3m", "change_3", "change_rate_3m", "pct_3m", "rank_chg_3m"], None)
        chg5 = _v308_pick_first(merged, ["change_5m", "chg_5m", "change_5", "change_rate_5m", "pct_5m", "rank_chg_5m"], None)
        chg15 = _v308_pick_first(merged, ["change_15m", "chg_15m", "change_15", "pct_15m"], None)
        candle = _v308_pick_first(merged, ["current_candle_label", "current_candle_code", "candle_label", "candle_status", "rank_watch_action"], "-")
        candle_closed = _v308_pick_first(merged, ["candle_closed", "is_closed", "is_candle_closed"], None)
        candle_ts = safe_float(_v308_pick_first(merged, ["candle_ts", "candle_start_ts", "current_candle_ts", "snapshot_ts", "updated_ts"], ts), ts)
        pressure = _v308_pick_first(merged, ["current_candle_pressure_score", "candle_pressure_score", "pressure_score"], None)
        live = _v308_pick_first(merged, ["current_candle_live_score", "candle_live_score", "alive_score"], None)
        tail = _v308_pick_first(merged, ["upper_tail_pct", "current_upper_tail_pct", "wick_up_pct"], None)
        lower = _v308_pick_first(merged, ["lower_tail_pct", "current_lower_tail_pct", "wick_down_pct"], None)
        reason = _v308_pick_first(merged, ["rank_reason", "watch_route", "trace_reason", "signal_decision", "decision", "register_reason"], "-")
        out = {
            "ticker": str(ticker or _v308_pick_first(merged, ["ticker"], "")).upper().strip(),
            "basis_ts": ts,
            "basis_time_text": _v308_ts_text(ts),
            "basis_day_key": _v309_day_key_from_ts(ts),
            "scope_label": _v309_scope_label(ts),
            "price": safe_float(price, 0),
            "price_key": price_key,
            "open": safe_float(open_p, 0),
            "high": safe_float(high_p, 0),
            "low": safe_float(low_p, 0),
            "close": safe_float(close_p, 0),
            "ohlc_keys": {"open": open_key, "high": high_key, "low": low_key, "close": close_key},
            "candle_ts": candle_ts,
            "candle_time_text": _v308_ts_text(candle_ts),
            "candle_closed": candle_closed,
            "range_high": safe_float(range_high, 0),
            "range_low": safe_float(range_low, 0),
            "range_keys": {"high": range_high_key, "low": range_low_key},
            "change_1m": None if chg1 is None else safe_float(chg1, 0),
            "change_3m": None if chg3 is None else safe_float(chg3, 0),
            "change_5m": None if chg5 is None else safe_float(chg5, 0),
            "change_15m": None if chg15 is None else safe_float(chg15, 0),
            "money": safe_float(money, 0),
            "trade_count": int(safe_float(trade_count, 0)),
            "buy_ratio": safe_float(buy_ratio, 0),
            "current_candle": str(candle or "-"),
            "pressure": None if pressure is None else safe_float(pressure, 0),
            "live_score": None if live is None else safe_float(live, 0),
            "upper_tail_pct": None if tail is None else safe_float(tail, 0),
            "lower_tail_pct": None if lower is None else safe_float(lower, 0),
            "bot_reason": str(reason or "-"),
            "source": str(source or _v308_pick_first(merged, ["source", "rank_source"], "stored")),
            "chart_data_note": "м ҖмһҘлҗң кіөмһҘ/paper/trace к°’л§Ң мӮ¬мҡ©. мғҲ OHLCV/API мЎ°нҡҢ м—ҶмқҢ.",
        }
        _v309_inc("chart_snapshot_saved", f"м°ЁнҠёлҚ°мқҙн„° {out.get('ticker','?')}")
        return out
    except Exception as e:
        try: append_runtime_error_log("v309_chart_snapshot", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {"ticker": str(ticker or "").upper().strip(), "basis_ts": safe_float(event_ts, 0), "basis_time_text": _v308_ts_text(event_ts), "source": "error"}


def _v309_fmt_pct(v):
    return "-" if v is None else f"{safe_float(v,0):+.2f}%"


def _v309_snapshot_lines(snap: dict) -> list:
    try:
        s = snap if isinstance(snap, dict) else {}
        price = safe_float(s.get("price", 0), 0)
        o = safe_float(s.get("open", 0), 0); h = safe_float(s.get("high", 0), 0); l = safe_float(s.get("low", 0), 0); c = safe_float(s.get("close", 0), 0)
        rh = safe_float(s.get("range_high", 0), 0); rl = safe_float(s.get("range_low", 0), 0)
        closed = s.get("candle_closed", None)
        if closed is True:
            closed_text = "лӢ«нһҢ лҙү"
        elif closed is False:
            closed_text = "м§„н–ү мӨ‘ лҙү"
        else:
            closed_text = "м ҖмһҘк°’ м—ҶмқҢ(л№—мҚё м°ЁнҠёлЎң нҷ•мқё)"
        lines = [
            "[кё°мӨҖмӢңк°Ғ мҠӨлғ…мғ·]",
            f"- кё°мӨҖмӢңк°Ғ(KST): {s.get('basis_time_text','-')} / н‘ңліёлІ”мң„: {s.get('scope_label','-')}",
            f"- нҳ„мһ¬к°Җ: {fmt_price_detail(price) if price > 0 else '-'} / к°ҖкІ©н•„л“ң: {s.get('price_key','-')}",
            f"- лҚ°мқҙн„°м¶ңмІҳ: {s.get('source','stored')} / {s.get('chart_data_note','')}",
            "[1л¶„/нҳ„мһ¬лҙү лҚ°мқҙн„°]",
            f"- лҙүмӢңк°Ғ(KST): {s.get('candle_time_text','-')} / лҙүмғҒнғң: {closed_text}",
            f"- OHLC м ҖмһҘк°’: мӢң {fmt_price_detail(o) if o>0 else '-'} / кі  {fmt_price_detail(h) if h>0 else '-'} / м Җ {fmt_price_detail(l) if l>0 else '-'} / мў… {fmt_price_detail(c) if c>0 else '-'}",
            f"- OHLC н•„л“ң: {s.get('ohlc_keys',{})}",
            f"- ліҖнҷ”мңЁ: 1m {_v309_fmt_pct(s.get('change_1m'))} / 3m {_v309_fmt_pct(s.get('change_3m'))} / 5m {_v309_fmt_pct(s.get('change_5m'))} / 15m {_v309_fmt_pct(s.get('change_15m'))}",
            f"- лҸҲ/мІҙкІ°: {_v308_money_text(s.get('money'))} / {int(safe_float(s.get('trade_count',0),0))}кұҙВ·л§ӨмҲҳ {safe_float(s.get('buy_ratio',0),0):.0f}%",
            f"- нҳ„мһ¬лҙү н•ҙм„қ: {s.get('current_candle','-')} / м••л Ҙ {s.get('pressure','-')} / мғқмЎҙ {s.get('live_score','-')} / мң—кј¬лҰ¬ {s.get('upper_tail_pct','-')} / м•„лһ«кј¬лҰ¬ {s.get('lower_tail_pct','-')}",
            f"- лҙҮнҢҗлӢЁ: {str(s.get('bot_reason','-'))[:140]}",
            "[кІҖмҰқкө¬к°„ м°ёкі ]",
            f"- м „нӣ„ кө¬к°„ мөңкі /мөңм Җ м ҖмһҘк°’: кі  {fmt_price_detail(rh) if rh>0 else '-'} / м Җ {fmt_price_detail(rl) if rl>0 else '-'} / н•„л“ң {s.get('range_keys',{})}",
            "- нҳ„мһ¬к°ҖмҷҖ 1л¶„лҙү OHLCк°Җ нҒ¬кІҢ лӢӨлҘҙл©ҙ лЁјм Җ н—ҲлёҢ/кіөмһҘ/м°Ҫкі  лҚ°мқҙн„° л¬ём ңлЎң ліёлӢӨ.",
        ]
        return lines
    except Exception as e:
        return [f"- м°ЁнҠё лҚ°мқҙн„° н‘ңмӢң мҳӨлҘҳ: {e}"]


def _v309_sample_summary_line(sample: dict, idx: int) -> list:
    s = sample if isinstance(sample, dict) else {}
    snap = s.get("chart_snapshot", {}) if isinstance(s.get("chart_snapshot", {}), dict) else {}
    tag = s.get("pattern_tag") or _v309_pattern_tag(s)
    return [
        f"{idx}. {s.get('ticker','?')} / {s.get('kind','кІҖмҰқ н‘ңліё')} / {tag}",
        f"- мқҙмң : {s.get('reason','-')}",
        f"- кё°мӨҖмӢңк°Ғ(KST): {s.get('event_time_text','-')} / н‘ңліёлІ”мң„: {snap.get('scope_label', _v309_scope_label(safe_float(s.get('event_ts',0),0)))}",
        f"- 1л¶„лҙү л№„көҗ(KST): {s.get('compare_1m_window','-')}",
        f"- лҙҮм°ЁнҠё: нҳ„мһ¬к°Җ {fmt_price_detail(safe_float(snap.get('price',0),0)) if safe_float(snap.get('price',0),0)>0 else '-'} / 1m {_v309_fmt_pct(snap.get('change_1m'))} / 3m {_v309_fmt_pct(snap.get('change_3m'))} / 5m {_v309_fmt_pct(snap.get('change_5m'))}",
        f"- лҙҮн•ҙм„қ: {str(snap.get('current_candle','-'))[:50]} / {str(snap.get('bot_reason','-'))[:100]}",
        f"- мӢӨм ңм°ЁнҠё мІҙнҒ¬: {s.get('check_hint','л№—мҚё м°ЁнҠёмҷҖ лҚ°мқҙн„° мқјм№ҳ нҷ•мқё')}",
    ]


def _v309_filter_kst_today(rows: list, ts_keys: list) -> list:
    today = _v308_today_key()
    out = []
    for r in list(rows or []):
        if not isinstance(r, dict):
            continue
        ts = 0
        for k in ts_keys:
            ts = safe_float(r.get(k, 0), 0)
            if ts > 0:
                break
        if ts > 0 and _v309_day_key_from_ts(ts) == today:
            out.append(r)
    return out


def _v309_mark_sample(sample: dict) -> dict:
    try:
        if isinstance(sample, dict):
            sample["pattern_tag"] = _v309_pattern_tag(sample)
            sample["event_time_text"] = _v308_ts_text(safe_float(sample.get("event_ts", 0), 0))
            sample["compare_1m_window"] = _v308_time_window_text(safe_float(sample.get("event_ts", 0), 0), 10, 10)
            sample["compare_5m_window"] = _v308_time_window_text(safe_float(sample.get("event_ts", 0), 0), 30, 30)
        return sample
    except Exception:
        return sample


def _v308_select_review_samples() -> list:
    """v309: KST мҳӨлҠҳ н‘ңліё мҡ°м„ , л¶ҖмЎұн•ҳл©ҙ мөңк·ј 24мӢңк°„ ліҙм¶©."""
    rank_rows = _v308_cached_rank_rows(120)
    samples = []
    used = set()
    now_ts = time.time()
    try:
        closed_all = _paper_closed_logs_v258(include_cancelled=True) if '_paper_closed_logs_v258' in globals() else []
    except Exception:
        closed_all = []
    closed = [r for r in closed_all if isinstance(r, dict) and str(r.get("status", "")).upper() == "CLOSED"]
    recent_closed = [r for r in closed if safe_float(r.get("close_ts", 0), 0) >= now_ts - 24 * 3600]
    today_closed = _v309_filter_kst_today(recent_closed, ["close_ts", "entered_ts", "created_ts"])
    loss_pool = today_closed or recent_closed
    losses = [r for r in loss_pool if safe_float(r.get("pnl_pct", 0), 0) < 0]
    losses.sort(key=lambda r: (safe_float(r.get("pnl_pct", 0), 0), -safe_float(r.get("close_ts", 0), 0)))
    if losses:
        r = losses[0]
        t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v309_mark_sample(_v308_make_sample("мҶҗмӢӨ н‘ңліё", t, f"лӘЁмқҳмІӯмӮ° {safe_float(r.get('pnl_pct',0),0):+.2f}% / мҶҗмӢӨ м§„мһ…л¬ё кІҖмҰқ", r, rank_rows, event_ts=safe_float(r.get("entered_ts", r.get("close_ts", 0)), 0), priority=90, check_hint="м§„мһ… мӢңк°Ғ 1л¶„лҙүм—җм„ң мқҙлҜё кі м җ/мң„кј¬лҰ¬/л°ҖлҰјмқҙм—ҲлҠ”м§Җ лЁјм Җ лҙҗ.")))
        used.add(_v308_sample_key("мҶҗмӢӨ", t)); used.add(t)
    cw_rows_all = _v308_cancel_watch_rows()
    cw_rows_today = _v309_filter_kst_today(cw_rows_all, ["cancel_ts", "last_check_ts", "created_ts"])
    cw_rows = cw_rows_today or [r for r in cw_rows_all if safe_float(r.get("last_check_ts", r.get("cancel_ts", 0)), 0) >= now_ts - 24*3600] or cw_rows_all
    strong = [r for r in cw_rows if safe_float(r.get("max_up_after_cancel_pct", 0), 0) >= 3.0]
    if strong:
        r = strong[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v309_mark_sample(_v308_make_sample("м·ЁмҶҢ нӣ„ к°•н•ң лҶ“м№Ё", t, f"м·ЁмҶҢ нӣ„ мөңкі  {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / нҳ„мһ¬ {safe_float(r.get('current_after_cancel_pct',0),0):+.2f}%", r, rank_rows, event_ts=safe_float(r.get("cancel_ts", 0), 0), priority=88, check_hint="м·ЁмҶҢ мқҙнӣ„ 1л¶„/5л¶„лҙүм—җм„ң лӢӨмӢң мӮҙм•„лӮң мӢ нҳёк°Җ мһҲм—ҲлҠ”м§Җ, нҳ„мһ¬ м¶”кІ©кёҲм§Җмқём§Җ к°ҷмқҙ лҙҗ.")))
        used.add(t)
    rewatch = [r for r in cw_rows if str(r.get("ticker", "")).upper().strip() not in used and safe_float(r.get("max_up_after_cancel_pct", 0), 0) >= 1.5]
    if rewatch:
        r = rewatch[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v309_mark_sample(_v308_make_sample("мһ¬к°җмӢң к°•н•Ё", t, f"м·ЁмҶҢ нӣ„ {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / мһ¬к°җмӢң ліөк·Җ нӣ„ліҙ", r, rank_rows, event_ts=safe_float(r.get("cancel_ts", 0), 0), priority=82, check_hint="м·ЁмҶҢ нӣ„ лӢӨмӢң кі м җ/м Җм җмқ„ лҶ’мҳҖлҠ”м§Җ, мһ¬к°җмӢңвҶ’м§„мһ…лҢҖкё° ліөк·Җк°Җ л§һм•ҳлҠ”м§Җ лҙҗ.")))
        used.add(t)
    for r in rank_rows[:20]:
        t = str(r.get("ticker", "")).upper().strip()
        if not t or t in used:
            continue
        txt = " ".join(str(r.get(k, "")) for k in ["rank_watch_action", "rank_watch_explain", "final_candidate_state_v251", "money_flow_text", "rank_reason", "watch_route", "trace_reason"])
        if any(x in txt for x in ["л°ҳм§қнҳ•", "л°ҖлҰј", "л§ӨлҸ„мҡ°м„ё", "лӮҙл¶Җк°җмӢң", "ліөкё° кё°лЎқ", "мҲңмң„к¶Ң мӣҖм§Ғмһ„"]):
            samples.append(_v309_mark_sample(_v308_make_sample("мғҒмң„ ліҙлҘҳ/м°ЁнҠёнҢҗлӢЁ", t, "rank_short мғҒмң„м§Җл§Ң мҰүмӢңм§„мһ…мқҙ м•„лӢҢ нӣ„ліҙ. м°ЁнҠё н•ҙм„қмқҙ мӢӨм ңмҷҖ л§һлҠ”м§Җ нҷ•мқё", r, rank_rows, event_ts=safe_float(r.get("snapshot_ts", r.get("updated_ts", now_ts)), now_ts), priority=70, check_hint="лҙҮмқҳ нҳ„мһ¬лҙү/мң„кј¬лҰ¬/л§ӨлҸ„мҡ°м„ё/л°ҳм§қнҳ• нҢҗлӢЁмқҙ мӢӨм ң л№—мҚё м°ЁнҠёмҷҖ л§һлҠ”м§Җ лҙҗ.")))
            used.add(t)
            break
    app_candidates = []
    for r in rank_rows[:50]:
        t = str(r.get("ticker", "")).upper().strip()
        if not t or t in used:
            continue
        txt = " ".join(str(r.get(k, "")) for k in ["app_compare_candidate", "app_only", "exclude_reason", "rank_compare_reason", "rank_reason", "watch_route"])
        if bool(r.get("app_compare_candidate", False)) or bool(r.get("app_only", False)) or "м•ұмӢқ" in txt or "м „лһө м җмҲҳ" in txt or "мІҙкІ°м ҒмқҢ" in txt:
            app_candidates.append(r)
    if not app_candidates:
        for r in rank_rows[:30]:
            t = str(r.get("ticker", "")).upper().strip()
            if t and t not in used:
                app_candidates.append(r); break
    if app_candidates:
        r = app_candidates[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v309_mark_sample(_v308_make_sample("м•ұмӢқ/rank_compare only", t, "мӢңмһҘм—җм„ңлҠ” мӣҖм§ҒмҳҖм§Җл§Ң лҙҮ м „лһө нӣ„ліҙм—җлҠ” м•Ҫн•ҳкұ°лӮҳ ліҙлҘҳлҗң нӣ„ліҙ", r, rank_rows, event_ts=safe_float(r.get("snapshot_ts", r.get("updated_ts", now_ts)), now_ts), priority=60, check_hint="мҲңмң„лҠ” лӢӨлҘј мҲҳ мһҲмқҢ. лӢӨл§Ң к°ҷмқҖ мӢңк°Ғ м°ЁнҠё лҚ°мқҙн„°мҷҖ нҳ„мһ¬лҙү н•ҙм„қмқҙ л§һлҠ”м§Җ лЁјм Җ нҷ•мқё.")))
        used.add(t)
    wins = [r for r in today_closed if safe_float(r.get("pnl_pct", 0), 0) > 0 and str(r.get("ticker", "")).upper().strip() not in used]
    if not wins:
        wins = [r for r in recent_closed if safe_float(r.get("pnl_pct", 0), 0) > 0 and str(r.get("ticker", "")).upper().strip() not in used]
    wins.sort(key=lambda r: safe_float(r.get("pnl_pct", 0), 0), reverse=True)
    if len(samples) < REVIEW_SAMPLE_DAILY_TARGETS_V308 and wins:
        r = wins[0]; t = str(r.get("ticker", "")).upper().strip()
        samples.append(_v309_mark_sample(_v308_make_sample("мһҳ мһЎмқҖ н‘ңліё", t, f"лӘЁмқҳмІӯмӮ° {safe_float(r.get('pnl_pct',0),0):+.2f}% / мўӢмқҖ кө¬мЎ° нҷ•мқё", r, rank_rows, event_ts=safe_float(r.get("entered_ts", r.get("close_ts",0)),0), priority=50, check_hint="лҙҮмқҙ мўӢкІҢ ліё м°ЁнҠёк°Җ мӢӨм ңлЎңлҸ„ мҙҲмһ…/мһ¬м¶ңл°ң кө¬мЎ°мҳҖлҠ”м§Җ нҷ•мқё.")))
    # нҶөкі„
    try:
        today_key = _v308_today_key()
        for smp in samples[:REVIEW_SAMPLE_DAILY_TARGETS_V308]:
            if _v309_day_key_from_ts(safe_float(smp.get("event_ts", 0), 0)) == today_key:
                _v309_inc("today_samples")
            else:
                _v309_inc("fallback_24h_samples")
    except Exception:
        pass
    return samples[:REVIEW_SAMPLE_DAILY_TARGETS_V308]


def _v308_load_today_sample(force_new: bool = False) -> dict:
    today = _v308_today_key()
    if not force_new:
        obj = load_json_file(REVIEW_SAMPLE_TODAY_FILE_V309, {})
        if isinstance(obj, dict) and obj.get("date") == today and isinstance(obj.get("samples"), list) and obj.get("samples"):
            # м¶ңл Ҙ мӢңк°Ғ/нҢЁн„ҙмқҖ нҳ„мһ¬ v309 нҳ•мӢқмңјлЎң мһ¬ліҙм •н•ңлӢӨ.
            obj["created_time_text"] = _v308_ts_text(safe_float(obj.get("created_ts", 0), 0))
            for smp in obj.get("samples", []):
                _v309_mark_sample(smp)
            _v309_inc("sample_reused", "v309 лӢ№мқј н‘ңліё мһ¬мӮ¬мҡ©")
            _v308_inc("sample_reused", "v309 лӢ№мқј н‘ңліё мһ¬мӮ¬мҡ©")
            return obj
    try:
        old = load_json_file(REVIEW_SAMPLE_TODAY_FILE_V309, {})
        if isinstance(old, dict) and old.get("date") and old.get("date") != today and old.get("samples"):
            hist = load_json_file(REVIEW_SAMPLE_HISTORY_FILE_V309, [])
            if not isinstance(hist, list):
                hist = []
            if not any(isinstance(x, dict) and x.get("date") == old.get("date") for x in hist):
                hist.append(old)
                hist = hist[-REVIEW_SAMPLE_HISTORY_KEEP_DAYS_V309:]
                save_json_file(REVIEW_SAMPLE_HISTORY_FILE_V309, hist)
                _v309_inc("history_saved", f"v309 history м ҖмһҘ {old.get('date')}")
    except Exception:
        pass
    samples = _v308_select_review_samples()
    now_ts = time.time()
    obj = {"schema": V309_SCHEMA_VERSION, "date": today, "created_ts": now_ts, "created_time_text": _v308_ts_text(now_ts), "timezone": "KST", "samples": samples}
    save_json_file(REVIEW_SAMPLE_TODAY_FILE_V309, obj)
    _v309_inc("sample_generated", f"v309 мҳӨлҠҳ н‘ңліё мғқм„ұ {len(samples)}к°ң")
    _v308_inc("sample_generated", f"v309 мҳӨлҠҳ н‘ңліё мғқм„ұ {len(samples)}к°ң")
    return obj


def build_review_sample_text_v308(full: bool = False, force_new: bool = False) -> str:
    try:
        obj = _v308_load_today_sample(force_new=force_new)
        samples = list(obj.get("samples") or []) if isinstance(obj, dict) else []
        lines = [
            "рҹ§Ә мҳӨлҠҳ кІҖмҰқ н‘ңліё /review_sample",
            f"- лӮ м§ң: {obj.get('date','-')} / мғқм„ұ { _v308_ts_text(safe_float(obj.get('created_ts',0),0)) }",
            "- мӢңк°„ кё°мӨҖ: KST кі м •. л°Өм—җ лҙҗлҸ„ н‘ңліёмқҳ кё°мӨҖмӢңк°ҒмңјлЎң л№—мҚё кіјкұ° м°ЁнҠёлҘј л§һм¶°м„ң л№„көҗ",
            "- лӘ©м Ғ: лҙҮмқҙ м ҖмһҘн•ң м°ЁнҠё лҚ°мқҙн„°к°Җ л№—мҚё мӢӨм ң м°ЁнҠёмҷҖ к°ҷмқҖм§Җ лЁјм Җ нҷ•мқё",
            "- мҲңмң„лҠ” л№—мҚё м•ұкіј лӢӨлҘј мҲҳ мһҲмқҢ. н•ҳм§Җл§Ң к°ҷмқҖ мӢңк°Ғмқҳ м°ЁнҠё лҚ°мқҙн„°к°Җ лӢӨлҘҙл©ҙ м•Ҳ лҗЁ.",
            "- KST мҳӨлҠҳ н‘ңліёмқ„ мҡ°м„  лҪ‘кі , л¶ҖмЎұн•ҳл©ҙ мөңк·ј24мӢңк°„ ліҙм¶© н‘ңліёмқҙлқјкі  н‘ңмӢңн•Ё.",
            "- к°ҷмқҖ лӮ  лӢӨмӢң лҲҢлҹ¬лҸ„ к°ҷмқҖ н‘ңліё мң м§Җ. кіјкұ° н‘ңліёмқҖ historyлЎң ліҙкҙҖ.",
            "",
            "[мҳӨлҠҳ ліј н‘ңліё]",
        ]
        if not samples:
            lines.append("- м•„м§Ғ м ҖмһҘн•  н‘ңліёмқҙ л¶ҖмЎұн•Ё. paper/rank кё°лЎқмқҙ лҚ” мҢ“мқҙл©ҙ мғқм„ұлҗЁ.")
        for i, smp in enumerate(samples, start=1):
            lines.extend(_v309_sample_summary_line(smp, i))
            if full:
                lines.append("  [лҙҮ м°ЁнҠё лҚ°мқҙн„° - v309 л¶„лҰ¬н‘ңмӢң]")
                lines.extend(["  " + x for x in _v309_snapshot_lines(smp.get("chart_snapshot", {}))])
                lines.append(f"  - 5л¶„лҙү л№„көҗ(KST): {smp.get('compare_5m_window','-')}")
                br = smp.get("source_row_brief", {}) if isinstance(smp.get("source_row_brief", {}), dict) else {}
                lines.append(f"  - мӣҗліёмҡ”м•Ҫ: мғҒнғң {br.get('status','-')} / мӮ¬мң  {br.get('close_reason','-')} / мҶҗмқө {safe_float(br.get('pnl_pct',0),0):+.2f}% / м·ЁмҶҢнӣ„мөңкі  {safe_float(br.get('max_up_after_cancel_pct',0),0):+.2f}%")
                lines += [
                    "  [кІҖмҰқ мІҙнҒ¬]",
                    "  в–Ў л№—мҚё 1л¶„лҙүмқҳ к°ҷмқҖ мӢңк°„лҢҖ нҳ„мһ¬к°Җк°Җ лҙҮ нҳ„мһ¬к°ҖмҷҖ л№„мҠ·н•Ё",
                    "  в–Ў л№—мҚё 1л¶„лҙүмқҳ кі к°Җ/м Җк°Җ/мў…к°Җ нқҗлҰ„мқҙ лҙҮ OHLC м ҖмһҘк°’кіј нҒ¬кІҢ м–ҙкёӢлӮҳм§Җ м•ҠмқҢ",
                    "  в–Ў лҙҮмқҳ нҳ„мһ¬лҙү/мң„кј¬лҰ¬/м•„лһ«кј¬лҰ¬/л°ҖлҰј/нҡҢліө нҢҗлӢЁмқҙ мӢӨм ң м°ЁнҠёмҷҖ л§һмқҢ",
                    "  в–Ў лҚ°мқҙн„°к°Җ л§һлӢӨл©ҙ л§ӨмҲҳ/лҢҖкё°/м·ЁмҶҢ/мһ¬к°җмӢң л¬ён„ұмқҙ л§һлҠ”м§Җ нҢҗлӢЁ",
                ]
            lines.append("")
        lines += [
            "[м°ЁнҠё л№„көҗ мҲңм„ң]",
            "1. л№—мҚё 1л¶„лҙүм—җм„ң кё°мӨҖмӢңк°Ғ(KST) м „нӣ„ 10л¶„мқ„ лЁјм Җ л§һм¶ҳлӢӨ.",
            "2. лҙҮ нҳ„мһ¬к°Җ/OHLC/кұ°лһҳлҹү/нҳ„мһ¬лҙү нҢҗлӢЁмқҙ мӢӨм ң м°ЁнҠёмҷҖ к°ҷмқҖм§Җ ліёлӢӨ.",
            "3. лҚ°мқҙн„°к°Җ л§һмңјл©ҙ к·ёлӢӨмқҢм—җ мҙҲмһ…В·мһ¬м¶ңл°ңВ·л°ҖлҰјВ·м¶”кІ©кёҲм§Җ нҢҗлӢЁмқ„ ліёлӢӨ.",
            "4. лҚ°мқҙн„°к°Җ лӢӨлҘҙл©ҙ м „лһө л¬ём ңк°Җ м•„лӢҲлқј н—ҲлёҢ/кіөмһҘ/м°Ҫкі  лҚ°мқҙн„° л¬ём ңлЎң ліёлӢӨ.",
        ]
        if full:
            try:
                hist = load_json_file(REVIEW_SAMPLE_HISTORY_FILE_V309, [])
                if isinstance(hist, list) and hist:
                    lines += ["", "[history мөңк·ј]", "- " + ", ".join(str(x.get("date","?")) for x in hist[-7:] if isinstance(x, dict))]
            except Exception:
                pass
        return "\n".join(lines).strip()
    except Exception as e:
        try: append_runtime_error_log("build_review_sample_v309", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return f"вҡ пёҸ /review_sample мғқм„ұ мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:160]}"


try:
    _BASE_CACHE_STATUS_V309 = build_cache_status_text
except Exception:
    _BASE_CACHE_STATUS_V309 = None


def _v309_status_lines() -> list:
    try:
        today_obj = load_json_file(REVIEW_SAMPLE_TODAY_FILE_V309, {})
        today_exists = isinstance(today_obj, dict) and today_obj.get("date") == _v308_today_key() and bool(today_obj.get("samples"))
        hist = load_json_file(REVIEW_SAMPLE_HISTORY_FILE_V309, [])
        hist_n = len(hist) if isinstance(hist, list) else 0
    except Exception:
        today_exists = False; hist_n = 0
    return [
        "рҹ§ӯ v2.5.309 review_sample KST/OHLC м •л°Җнҷ”",
        "- мң„м№ҳ: н—ҲлёҢ мӢңк°Ғн‘ңмӢң + кіөмһҘ OHLC л¶„лҰ¬ + м°Ҫкі  today/history + м¶ңл Ҙ + м•ҢлҰјмӢңк°Ғ / мЎ°кұҙ м „мІҙ к°•нҷ” м•„лӢҳ",
        "- мӢңк°„: мғқм„ұмӢңк°ҒВ·кё°мӨҖмӢңк°ҒВ·л№„көҗкө¬к°„ лӘЁл‘җ KSTлЎң н‘ңмӢң",
        "- OHLC: кё°мӨҖмӢңк°Ғ нҳ„мһ¬к°Җ / 1л¶„В·нҳ„мһ¬лҙү OHLC / кІҖмҰқкө¬к°„ мөңкі В·мөңм ҖлҘј л¶„лҰ¬ н‘ңмӢң",
        "- н‘ңліё: KST мҳӨлҠҳ мҡ°м„ , л¶ҖмЎұн•ҳл©ҙ мөңк·ј24мӢңк°„ ліҙм¶© н‘ңліёмңјлЎң лӘ…мӢң",
        f"- м ҖмһҘмғҒнғң: мҳӨлҠҳн‘ңліё {'мһҲмқҢ' if today_exists else 'м—ҶмқҢ'} / history {hist_n}к°ң / мғқм„ұ {V309_STATS.get('sample_generated',0)} / мһ¬мӮ¬мҡ© {V309_STATS.get('sample_reused',0)} / м°ЁнҠём ҖмһҘ {V309_STATS.get('chart_snapshot_saved',0)}",
        f"- н‘ңліёлІ”мң„: мҳӨлҠҳ {V309_STATS.get('today_samples',0)} / 24hліҙм¶© {V309_STATS.get('fallback_24h_samples',0)}",
        "- лі‘лӘ©н•ҙм„қ: build_rank_sourceк°Җ 15мҙҲ мқҙмғҒмқҙл©ҙ мәҗмӢң мЎ°лҰҪ м§Җм—°мңјлЎң ліҙкі  /cache_status_fullм—җм„ң мӣҗмқё нҷ•мқё. лӘ…л №м–ҙк°Җ мғҲ мҠӨмә”н•ҳлҠ” лң»мқҖ м•„лӢҳ.",
        f"- мөңк·ј: {V309_STATS.get('last_note','лҢҖкё°')}",
    ]


def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_V309()) if callable(_BASE_CACHE_STATUS_V309) else "рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status"
    try:
        if "рҹ§ӯ v2.5.309 review_sample KST/OHLC м •л°Җнҷ”" not in base:
            base += "\n" + "\n".join(_v309_status_lines())
        _v309_inc("cache_status_shown", "cache_status v309 н‘ңмӢң")
    except Exception:
        pass
    return base


def build_cache_status_full_text():
    return build_cache_status_text()


def send_startup_message():
    lines = [
        "вң… лҙҮ мӢңмһ‘ мҷ„лЈҢ",
        f"нҳ„мһ¬ лІ„м „: {BOT_VERSION}",
        "",
        f"мһҗлҸҷл§ӨмҲҳ: {'мјңм§җ' if AUTO_BUY else 'кәјм§җ'}",
        f"мҡҙмҳҒмӢңк°„: {AUTO_BUY_START_HOUR}:00 ~ {AUTO_BUY_END_HOUR}:00",
        f"мЈјл¬ё мөңлҢҖкёҲм•Ў: {MAX_ENTRY_KRW:,}мӣҗ",
        "",
        "мқҙлІҲ н•өмӢ¬ ліҖкІҪ",
        "- /review_sample мӢңк°„ н‘ңмӢңлҘј KSTлЎң кі м •. л°Өм—җ лҙҗлҸ„ кё°мӨҖмӢңк°ҒмңјлЎң л№—мҚё кіјкұ° м°ЁнҠё л№„көҗ",
        "- лҙҮ м°ЁнҠё лҚ°мқҙн„° н‘ңмӢңлҘј нҳ„мһ¬к°Җ / 1л¶„В·нҳ„мһ¬лҙү OHLC / кІҖмҰқкө¬к°„ мөңкі В·мөңм ҖлЎң л¶„лҰ¬",
        "- н‘ңліёл§ҲлӢӨ нҢЁн„ҙ нғңк·ёмҷҖ м°ЁнҠё лҚ°мқҙн„° мқјм№ҳ мІҙнҒ¬лҰ¬мҠӨнҠё м¶”к°Җ",
        "- мҳӨлҠҳ н‘ңліё мҡ°м„ , л¶ҖмЎұн•ҳл©ҙ мөңк·ј24мӢңк°„ ліҙм¶© н‘ңліёмңјлЎң н‘ңмӢң",
        "- лӘЁмқҳл§ӨмҲҳ/лӘЁмқҳмІӯмӮ° м•ҢлҰјмқҳ кІҖмҰқ кё°мӨҖмӢңк°ҒлҸ„ KST кё°мӨҖмңјлЎң м •лҰ¬",
        "- мЎ°кұҙ м „мІҙ к°•нҷ”, мһҗлҸҷл§ӨмҲҳ, мҶҗм Ҳ/TP ліҖкІҪ м—ҶмқҢ",
        "",
        "мһҗм„ён•ң м„ӨлӘ…мқҖ /info",
    ]
    try:
        send("\n".join(lines))
    except Exception:
        pass


# =========================================================
# v2.5.310: мҲҳмқөлҘ  ліём„  мһ¬л°°м№ҳ + review_sample лҚ°мқҙн„° н’Ҳм§Ҳ ліҙк°•
# мң„м№ҳ: н—ҲлёҢ/кіөмһҘ лҚ°мқҙн„°н’Ҳм§Ҳ + 2м°Ё/3м°Ё нӣ„ліҙл¬ён„ұ + м°Ҫкі /paper/trace + м¶ңл Ҙ
# н•өмӢ¬:
# - мӢӨм „ кё°мӨҖмқҖ мҳӨлҘҳ м—ҶмқҢмқҙ м•„лӢҲлқј 6мӢңк°„ мҲҳмқөлҘ /PF к°ңм„ мқҙлӢӨ.
# - мЎ°кұҙ м „мІҙ к°•нҷ”к°Җ м•„лӢҲлқј л°”лЎңм§„мһ… л¬ёл§Ң лҚ” мўҒнһҲкі  мӨҖл№„лҢҖкё°/лҲҢлҰјлҢҖкё° л№„мӨ‘мқ„ лҠҳлҰ°лӢӨ.
# - м·ЁмҶҢ нӣ„ нҒ¬кІҢ к°„ нӣ„ліҙлҠ” л¬ҙмЎ°кұҙ м¶”кІ©н•ҳм§Җ м•Ҡкі , мһ¬к°җмӢң ліөк·Җ/м¶”кІ©кёҲм§ҖлЎң л¶„лҰ¬н•ңлӢӨ.
# - review_sampleмқҖ м°ЁнҠё лҚ°мқҙн„° м¶©л¶„/л¶ҖмЎұ, кё°мӨҖмӢңк°Ғ/лҙүмӢңк°Ғ л¶Ҳмқјм№ҳ мқҳмӢ¬мқ„ ліҙм—¬мӨҖлӢӨ.
# =========================================================
V310_SCHEMA_VERSION = "profit_rebalance_v310"
V310_MODULE_LOAD_TS = time.time()
V310_STATS = {
    "direct_to_prepare": 0,
    "direct_low_quality": 0,
    "breakout_fail_to_rewatch": 0,
    "strong_miss_rewatch": 0,
    "strong_miss_chase_block": 0,
    "chart_quality_full": 0,
    "chart_quality_partial": 0,
    "chart_quality_price_only": 0,
    "chart_time_mismatch_fixed": 0,
    "paper_stats_rendered": 0,
    "last_note": "лҢҖкё°",
}

V310_DIRECT_MIN_SCORE = 6.20
V310_DIRECT_MIN_TRADES = 12
V310_DIRECT_LOW_SCORE_HARD = 4.20
V310_DIRECT_SMALL_SAMPLE_SCORE = 6.80
V310_DIRECT_PRESSURE_BLOCK = 0.90
V310_REWATCH_STRONG_UP = 1.50
V310_REWATCH_BIG_UP = 3.00
V310_REWATCH_KEEP_RATIO = 0.58


def _v310_inc(key: str, note: str = ""):
    try:
        if key in V310_STATS:
            V310_STATS[key] = int(safe_float(V310_STATS.get(key, 0), 0)) + 1
        if note:
            V310_STATS["last_note"] = str(note)[:200]
    except Exception:
        pass


def _v310_text_blob(row: dict, cls: dict = None) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        vals = []
        for src in (row, cls):
            if not isinstance(src, dict):
                continue
            for k in (
                "current_candle_label", "current_candle_code", "rank_watch_action", "rank_watch_explain",
                "final_candidate_state_v251", "decision", "signal_decision", "money_flow_text",
                "rank_reason", "watch_route", "trace_reason", "paper_v306_direct_block_reason",
                "paper_v307_direct_block_reason", "paper_v310_rebalance_reason", "v310_route_tag",
            ):
                v = src.get(k, "")
                if v:
                    vals.append(str(v))
            rs = src.get("reasons", [])
            if isinstance(rs, list):
                vals.extend(str(x) for x in rs[:12])
            elif rs:
                vals.append(str(rs))
        return " ".join(vals)
    except Exception:
        return ""


def _v310_rewatch_signal(row: dict, cls: dict) -> tuple[str, str]:
    """м·ЁмҶҢ нӣ„ к°•н•ң лҶ“м№Ё нӣ„ліҙлҘј мһ¬к°җмӢң ліөк·Җ/м¶”кІ©кёҲм§ҖлЎң л¶„лҰ¬н•ңлӢӨ."""
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        max_up = safe_float(row.get("max_up_after_cancel_pct", row.get("cancel_after_max_pct", row.get("missed_max_pct", 0))), 0)
        cur_up = safe_float(row.get("current_after_cancel_pct", row.get("cancel_after_current_pct", row.get("missed_current_pct", 0))), 0)
        if max_up < V310_REWATCH_STRONG_UP:
            return "", ""
        txt = _v310_text_blob(row, cls)
        weak_now = any(x in txt for x in ["мң„кј¬лҰ¬", "л§үнҢҗк°•л°ҖлҰј", "л§үнҢҗ л°ҖлҰј", "нҳ„мһ¬лҙү л°ҖлҰј", "л§ӨлҸ„мҡ°м„ё", "л°ҳм§қ/мӢқлҠ”мӨ‘", "л°ҳм§қнҳ•"])
        if max_up >= V310_REWATCH_BIG_UP and (cur_up <= 0 or cur_up < max_up * V310_REWATCH_KEEP_RATIO or weak_now):
            _v310_inc("strong_miss_chase_block", f"к°•н•ңлҶ“м№Ё м¶”кІ©кёҲм§Җ {row.get('ticker', cls.get('ticker','?'))}/{max_up:+.2f}%")
            return "chase_block", f"м·ЁмҶҢ нӣ„ +{max_up:.2f}% к°”м§Җл§Ң нҳ„мһ¬ нһҳ/мң„м№ҳк°Җ м•Ҫн•ҙ м¶”кІ©кёҲм§Җ"
        if cur_up >= 0.70 and cur_up >= max_up * V310_REWATCH_KEEP_RATIO:
            _v310_inc("strong_miss_rewatch", f"к°•н•ңлҶ“м№Ё мһ¬к°җмӢңліөк·Җ {row.get('ticker', cls.get('ticker','?'))}/{cur_up:+.2f}%")
            return "rewatch_return", f"м·ЁмҶҢ нӣ„ +{max_up:.2f}% / нҳ„мһ¬ +{cur_up:.2f}% мң м§Җлқј мһ¬к°җмӢң ліөк·Җ нӣ„ліҙ"
        return "", ""
    except Exception as e:
        try: append_runtime_error_log("v310_rewatch_signal", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return "", ""


def _v310_direct_rebalance_reason(row: dict, cls: dict) -> str:
    """мҲҳмқөлҘ  к°ңм„ мҡ© л°”лЎңм§„мһ… л¬ён„ұ мһ¬л°°м№ҳ.

    нӣ„ліҙлҘј мЈҪмқҙм§Җ м•Ҡкі  BUY_OK л°”лЎңм§„мһ…л§Ң PULLBACK_WAIT/мӨҖл№„лҢҖкё°лЎң лӮҙлҰ°лӢӨ.
    """
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        grade = str(cls.get("grade", row.get("grade", "")) or "").upper().strip()
        if grade != "BUY_OK":
            return ""
        score = safe_float(cls.get("score", row.get("score", 0)), 0)
        trade_count = int(safe_float(cls.get("trade_count", row.get("trade_count", row.get("trade_count_60s", 0))), 0))
        buy_ratio = safe_float(cls.get("buy_ratio", row.get("buy_ratio", row.get("buy_ratio_60s", 0))), 0)
        pressure = safe_float(row.get("current_candle_pressure_score", row.get("candle_pressure_score", cls.get("current_candle_pressure_score", 0))), 0)
        live = safe_float(row.get("current_candle_live_score", row.get("candle_live_score", cls.get("current_candle_live_score", 0))), 0)
        txt = _v310_text_blob(row, cls)
        weak_candle = any(x in txt for x in ["л§үнҢҗк°•л°ҖлҰј", "л§үнҢҗ л°ҖлҰј", "мң„кј¬лҰ¬к°•л°ҖлҰј", "мң„кј¬лҰ¬ л°ҖлҰј", "нҳ„мһ¬лҙү л°ҖлҰј", "кі м җ м•һ л°ҖлҰј"])
        sell_heavy = any(x in txt for x in ["л§ӨлҸ„мҡ°м„ё", "л§ӨлҸ„ мҡ°м„ё", "лҸҲмқҖ нҒ¬м§Җл§Ң л§ӨлҸ„мҡ°м„ё"])
        flash = any(x in txt for x in ["л°ҳм§қнҳ•", "мӢқлҠ”мӨ‘", "л°ҳм§қ/мӢқлҠ”мӨ‘"])
        tiny_meaning = any(x in txt for x in ["нҳ„мһ¬лҙү мқҳлҜё мһ‘мқҢ", "мһ‘мқҖмӣҖм§Ғмһ„"])
        if score > 0 and score < V310_DIRECT_LOW_SCORE_HARD:
            _v310_inc("direct_low_quality", f"лӮ®мқҖм җмҲҳ л°”лЎңм§„мһ… ліҙлҘҳ {score:.2f}")
            return f"м җмҲҳ {score:.2f}лқј л°”лЎңм§„мһ…ліҙлӢӨ мӨҖл№„лҢҖкё°"
        if pressure >= V310_DIRECT_PRESSURE_BLOCK or weak_candle or sell_heavy or flash:
            _v310_inc("direct_low_quality", f"нҳ„мһ¬лҙү/л§ӨлҸ„мҡ°м„ё/л°ҳм§қ ліҙлҘҳ {row.get('ticker', cls.get('ticker','?'))}")
            return "нҳ„мһ¬лҙү л°ҖлҰјВ·л§ӨлҸ„мҡ°м„ёВ·л°ҳм§қнҳ• мӨ‘ н•ҳлӮҳк°Җ мһҲм–ҙ л°”лЎңм§„мһ… кёҲм§Җ"
        if trade_count > 0 and trade_count < V310_DIRECT_MIN_TRADES and score < V310_DIRECT_SMALL_SAMPLE_SCORE:
            _v310_inc("direct_low_quality", f"н‘ңліё/м җмҲҳ л¶ҖмЎұ {score:.2f}/{trade_count}кұҙ")
            return f"м җмҲҳ {score:.2f}В·мІҙкІ° {trade_count}кұҙмқҙлқј л°”лЎңм§„мһ…ліҙлӢӨ мӨҖл№„лҢҖкё°"
        if tiny_meaning and score < 7.0 and live < 1.5:
            _v310_inc("direct_low_quality", f"нҳ„мһ¬лҙү мқҳлҜё м•Ҫн•Ё {score:.2f}")
            return "нҳ„мһ¬лҙү мқҳлҜёк°Җ м•Ҫн•ҙ л°”лЎңм§„мһ…ліҙлӢӨ лҲҢлҰј/мӨҖл№„лҢҖкё°"
        if buy_ratio > 0 and buy_ratio < 55 and score < 7.0:
            _v310_inc("direct_low_quality", f"л§ӨмҲҳл№„мңЁ м•Ҫн•Ё {buy_ratio:.0f}%")
            return f"л§ӨмҲҳл№„мңЁ {buy_ratio:.0f}%лЎң м•Ҫн•ҙ л°”лЎңм§„мһ… ліҙлҘҳ"
        return ""
    except Exception as e:
        try: append_runtime_error_log("v310_direct_rebalance_reason", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ""


def _v310_breakout_fail_reason(row: dict, cls: dict) -> str:
    """лҸҢнҢҢлҢҖкё° мӢӨнҢЁнҳ•мқ„ кі м җ м•һ л°ҖлҰј/мң„кј¬лҰ¬ мӢӨнҢЁлЎң л¶„лҰ¬н•ңлӢӨ."""
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        grade = str(cls.get("grade", row.get("grade", "")) or "").upper().strip()
        entry_rule = str(cls.get("paper_entry_rule_v259", cls.get("v270_entry_rule", row.get("entry_rule", ""))) or "").lower()
        if grade != "BREAKOUT_WAIT" and entry_rule != "breakout":
            return ""
        txt = _v310_text_blob(row, cls)
        if any(x in txt for x in ["кі м җ м•һ л°ҖлҰј", "мң„кј¬лҰ¬", "л§үнҢҗк°•л°ҖлҰј", "нҳ„мһ¬лҙү л°ҖлҰј", "мһ¬лҸҢнҢҢ мң м§Җ лҜёнҷ•мқё", "м¶”кІ©кёҲм§Җ"]):
            _v310_inc("breakout_fail_to_rewatch", f"лҸҢнҢҢлҢҖкё° мӢӨнҢЁл¶„лҰ¬ {row.get('ticker', cls.get('ticker','?'))}")
            return "лҸҢнҢҢлҢҖкё°м§Җл§Ң кі м җ м•һ л°ҖлҰј/мң„кј¬лҰ¬лқј мһ¬к°җмӢңВ·лҲҢлҰјлҢҖкё°лЎң мқҙлҸҷ"
        return ""
    except Exception as e:
        try: append_runtime_error_log("v310_breakout_fail_reason", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ""


try:
    _BASE_PAPER_CLASSIFY_V310 = _paper_classify_for_register_v258
except Exception:
    _BASE_PAPER_CLASSIFY_V310 = None


def _paper_classify_for_register_v258(row: dict):
    if not callable(_BASE_PAPER_CLASSIFY_V310):
        return False, "", "л¶„лҘҳн•ЁмҲҳм—ҶмқҢ", {}
    ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V310(row)
    try:
        if ok and isinstance(cls, dict):
            row = row if isinstance(row, dict) else {}
            # 1) м·ЁмҶҢ нӣ„ к°•н•ң лҶ“м№ЁмқҖ мһ¬к°җмӢң ліөк·Җ/м¶”кІ©кёҲм§Җ нғңк·ёлҘј лЁјм Җ л¶ҷмқёлӢӨ.
            action, why = _v310_rewatch_signal(row, cls)
            if action == "rewatch_return":
                cls = dict(cls)
                cls["v310_route_tag"] = "м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё вҶ’ мһ¬к°җмӢң ліөк·Җ"
                cls["paper_v310_rebalance_reason"] = why
                cls["paper_entry_rule_v259"] = "pullback"
                cls["grade"] = "PULLBACK_WAIT"
                cls["decision"] = "мһ¬к°җмӢң ліөк·Җ / лҲҢлҰјлҢҖкё°"
                lane = str(lane or "strict_signal") + "_rewatch_return_v310"
                reason = (str(reason or "мӢ нҳёмёө") + " / v310 мһ¬к°җмӢңліөк·Җ: " + why)[:280]
            elif action == "chase_block":
                cls = dict(cls)
                cls["v310_route_tag"] = "к°•н•ңлҶ“м№Ё / нҳ„мһ¬ м¶”кІ©кёҲм§Җ"
                cls["paper_v310_rebalance_reason"] = why
                cls["decision"] = "к°•н•ң лҶ“м№Ё кё°лЎқ / нҳ„мһ¬ м¶”кІ©кёҲм§Җ"
                lane = str(lane or "watch") + "_chase_block_v310"
                reason = (str(reason or "мӢ нҳёмёө") + " / v310 м¶”кІ©кёҲм§Җ: " + why)[:280]
            # 2) BUY_OK л°”лЎңм§„мһ… мң„н—ҳмқҖ мӨҖл№„лҢҖкё°лЎң лӮҙлҰ°лӢӨ.
            direct_why = _v310_direct_rebalance_reason(row, cls)
            if direct_why and str(cls.get("grade", "") or "").upper().strip() == "BUY_OK":
                original_grade = str(cls.get("grade", "BUY_OK") or "BUY_OK")
                cls = dict(cls)
                cls["paper_original_grade"] = str(cls.get("paper_original_grade", original_grade) or original_grade)
                cls["paper_v310_rebalance_reason"] = direct_why
                cls["v310_route_tag"] = "л°”лЎңм§„мһ… мң„н—ҳ вҶ’ мӨҖл№„/лҲҢлҰјлҢҖкё°"
                cls["grade"] = "PULLBACK_WAIT"
                cls["paper_entry_rule_v259"] = "pullback"
                cls["decision"] = "л°”лЎңм§„мһ… ліҙлҘҳ / лҲҢлҰјВ·мӨҖл№„лҢҖкё°"
                lane = str(lane or "strict_signal") + "_prepare_v310"
                reason = (str(reason or "мӢ нҳёмёө") + " / v310 л°”лЎңм§„мһ… ліҙлҘҳ: " + direct_why)[:280]
                _v310_inc("direct_to_prepare", f"л°”лЎңм§„мһ…вҶ’мӨҖл№„ {str(row.get('ticker', cls.get('ticker','?')))}")
            # 3) лҸҢнҢҢлҢҖкё° мӢӨнҢЁнҳ•мқҖ лҸҢнҢҢлҢҖкё°м—җм„ң л№јм„ң мһ¬к°җмӢң/лҲҢлҰјлҢҖкё°лЎң ліҙлӮёлӢӨ.
            breakout_why = _v310_breakout_fail_reason(row, cls)
            if breakout_why:
                cls = dict(cls)
                cls["paper_v310_rebalance_reason"] = breakout_why
                cls["v310_route_tag"] = "лҸҢнҢҢлҢҖкё° мӢӨнҢЁнҳ• вҶ’ мһ¬к°җмӢң/лҲҢлҰјлҢҖкё°"
                cls["grade"] = "PULLBACK_WAIT"
                cls["paper_entry_rule_v259"] = "pullback"
                cls["decision"] = "лҸҢнҢҢ мӢӨнҢЁнҳ• л¶„лҰ¬ / лҲҢлҰјлҢҖкё°"
                lane = str(lane or "breakout") + "_breakout_fail_v310"
                reason = (str(reason or "мӢ нҳёмёө") + " / v310 лҸҢнҢҢлҢҖкё°л¶„лҰ¬: " + breakout_why)[:280]
        return ok, lane, reason, cls
    except Exception as e:
        try: append_runtime_error_log("v310_paper_classify", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ok, lane, reason, cls


try:
    _BASE_PAPER_EASY_LANE_V310 = _paper_v301_easy_lane
except Exception:
    _BASE_PAPER_EASY_LANE_V310 = None


def _paper_v301_easy_lane(raw: str) -> str:
    try:
        txt = str(raw or "")
        if "prepare_v310" in txt:
            return "мӢӨм „кёү нӣ„ліҙ / л°”лЎңм§„мһ… ліҙлҘҳ"
        if "rewatch_return_v310" in txt:
            return "м·ЁмҶҢнӣ„ мһ¬к°җмӢң ліөк·Җ нӣ„ліҙ"
        if "chase_block_v310" in txt:
            return "к°•н•ң лҶ“м№Ё / нҳ„мһ¬ м¶”кІ©кёҲм§Җ"
        if "breakout_fail_v310" in txt:
            return "лҸҢнҢҢ мӢӨнҢЁнҳ• / лҲҢлҰјлҢҖкё°"
        return str(_BASE_PAPER_EASY_LANE_V310(raw)) if callable(_BASE_PAPER_EASY_LANE_V310) else txt
    except Exception:
        return str(raw or "")


