def _v309_sample_summary_line(sample: dict, idx: int) -> list:
    lines = list(_BASE_V309_SAMPLE_SUMMARY_V310(sample, idx)) if callable(_BASE_V309_SAMPLE_SUMMARY_V310) else []
    try:
        snap = (sample or {}).get("chart_snapshot", {}) if isinstance((sample or {}).get("chart_snapshot", {}), dict) else {}
        quality = snap.get("chart_data_quality") or _v310_chart_quality(snap)[0]
        # лҙҮм°ЁнҠё мӨ„ л°”лЎң л’Өм—җ н’Ҳм§Ҳмқ„ л¶ҷмқёлӢӨ.
        out = []
        done = False
        for line in lines:
            out.append(line)
            if (not done) and str(line).startswith("- лҙҮм°ЁнҠё:"):
                out.append(f"- м°ЁнҠёлҚ°мқҙн„° н’Ҳм§Ҳ: {quality}")
                done = True
        return out
    except Exception:
        return lines


