def build_paper_stats_text_v258() -> str:
    base = str(_BASE_BUILD_PAPER_STATS_V311()) if callable(_BASE_BUILD_PAPER_STATS_V311) else "рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats"
    try:
        rows = _paper_closed_logs_v258()
        since = [r for r in rows if safe_float(r.get("close_ts", 0), 0) >= V311_MODULE_LOAD_TS]
        section = [
            "",
            "[v311 м Ғмҡ© мқҙнӣ„ м„ұкіј - к°•н•ңлҶ“м№Ё ліөк·Җ/кіөнҶөнҷ•мқё]",
            "- лӘ©н‘ң: л°”лЎңм§„мһ… мҶҗмӢӨмқҖ мӨ„мқҙкі , м·ЁмҶҢ нӣ„ к°•н•ң мӣҖм§Ғмһ„мқҖ мһ¬к°җмӢңлЎң мӮҙлҰ¬лҠ”м§Җ нҷ•мқё",
        ]
        if since:
            section.append(_paper_stats_line_v258("v311 мқҙнӣ„", since))
            try:
                section.extend(_v307_route_stats_section(since, title="v311 мқҙнӣ„ л¬ён„ұлі„"))
            except Exception:
                pass
        else:
            section.append("- кұ°лһҳ: м—ҶмқҢ")
        if "[v311 м Ғмҡ© мқҙнӣ„ м„ұкіј" not in base:
            base += "\n" + "\n".join(section)
        _v311_inc("paper_stats_rendered", "v311 м„ұкіјн‘ң м¶ңл Ҙ")
    except Exception as e:
        base += f"\n\n[v311 м„ұкіјн‘ң] н‘ңмӢң мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:120]}"
    return base


