def _v311_status_lines() -> list:
    return [
        "рҹ”Ҙ v2.5.311 к°•н•ңлҶ“м№Ё ліөк·Җ/кіөнҶө м¶”м„ёнҷ•мқё",
        "- мң„м№ҳ: 2м°Ё нӣ„ліҙл¶„лҘҳ + 3м°Ё мһ¬к°җмӢңліөк·Җ + paper/trace м„ұкіј + м¶ңл Ҙ / мЎ°кұҙ м „мІҙ к°•нҷ” м•„лӢҳ",
        "- м°ёкі мЎ°кұҙ: мқјл°ҳ л§Өл§Ө н”„лЎңк·ёлһЁмӢқ 1mВ·3mВ·5m мң м§Җ, мІҙкІ°н‘ңліё, л§ӨмҲҳл№„мңЁ, кұ°лһҳлҢҖкёҲ, нҳ„мһ¬лҙү л°ҖлҰј м—¬л¶ҖлҘј к°ҷмқҙ лҙ„",
        f"- л°”лЎңм§„мһ…: кіөнҶөнҷ•мқёнҶөкіј {V311_STATS.get('common_confirm_pass',0)} / мӨҖл№„лҢҖкё°м „нҷҳ {V311_STATS.get('weak_direct_to_prepare',0)}",
        f"- к°•н•ңлҶ“м№Ё: ліөк·Җк°җмӢң {V311_STATS.get('strong_miss_reentry_watch',0)} / лҲҢлҰјк°җмӢң {V311_STATS.get('strong_miss_pullback_watch',0)} / м¶”кІ©вҶ’лҲҢлҰј {V311_STATS.get('chase_to_pullback_watch',0)}",
        f"- м„ұкіјн‘ңм¶ңл Ҙ {V311_STATS.get('paper_stats_rendered',0)} / мөңк·ј: {V311_STATS.get('last_note','лҢҖкё°')}",
    ]


def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_V311()) if callable(_BASE_CACHE_STATUS_V311) else "рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status"
    try:
        if "рҹ”Ҙ v2.5.311 к°•н•ңлҶ“м№Ё ліөк·Җ/кіөнҶө м¶”м„ёнҷ•мқё" not in base:
            base += "\n" + "\n".join(_v311_status_lines())
    except Exception:
        pass
    return base


def build_cache_status_full_text():
    return build_cache_status_text()


def send_startup_message():
    lines = [
        "вң… лҙҮ мӢңмһ‘ мҷ„лЈҢ",
        f"нҳ„мһ¬ лІ„м „: {BOT_VERSION}",
        "",
        f"мһҗлҸҷл§ӨмҲҳ: {'мјңм§җ' if AUTO_BUY else 'кәјм§җ'}",
        f"мҡҙмҳҒмӢңк°„: {AUTO_BUY_START_HOUR}:00 ~ {AUTO_BUY_END_HOUR}:00",
        f"мЈјл¬ё мөңлҢҖкёҲм•Ў: {MAX_ENTRY_KRW:,}мӣҗ",
        "",
        "мқҙлІҲ н•өмӢ¬ ліҖкІҪ",
        "- v310 лҜём Ғмҡ© мғҒнғңлҘј к°җм•Ҳн•ҙ v310 ліём„  мһ¬л°°м№ҳ мң„м—җ v311 к°•н•ңлҶ“м№Ё ліөк·ҖлҘј н•Ёк»ҳ л°ҳмҳҒ",
        "- мқјл°ҳ л§Өл§Ө н”„лЎңк·ёлһЁм—җм„ң л§Һмқҙ м“°лҠ” 1m/3m/5m лҸҷмӢңмң м§Җ, мІҙкІ°н‘ңліё, л§ӨмҲҳл№„мңЁ, кұ°лһҳлҢҖкёҲ, нҳ„мһ¬лҙү л°ҖлҰј нҷ•мқёмқ„ м°ёкі ",
        "- л°”лЎңм§„мһ…мқҖ кіөнҶөнҷ•мқёмқҙ л¶ҖмЎұн•ҳл©ҙ мӨҖл№„лҢҖкё°лЎң лӮҙлҰ¬кі , нӣ„ліҙ мһҗмІҙлҠ” мЈҪмқҙм§Җ м•ҠмқҢ",
        "- MBX/XPLA/KNCнҳ• к°•н•ң лҶ“м№ЁмқҖ кё°лЎқл§Ң н•ҳм§Җ м•Ҡкі  мһ¬к°җмӢң ліөк·Җ/лҲҢлҰј мһ¬м§„мһ… к°җмӢңлЎң л¶„лҰ¬",
        "- /paper_statsм—җ v311 мқҙнӣ„ м„ұкіјлҘј л”°лЎң н‘ңмӢң. мӢӨм „ кё°мӨҖмқҖ 6мӢңк°„ +4~5% л°ҳліө нҷ•мқё",
        "- мһҗлҸҷл§ӨмҲҳ, мҶҗм Ҳ/TP, м „мІҙ мЎ°кұҙ к°•нҷ” м—ҶмқҢ",
        "",
        "мһҗм„ён•ң м„ӨлӘ…мқҖ /info",
    ]
    try:
        send("\n".join(lines))
    except Exception:
        pass


# =========================================================
# v2.5.312: м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё ліөк·Җ м—°кІ° мҲҳлҰ¬ + л§ӨлҸ„мҡ°м„ё лІ„лҰј л°©м§Җ
# мң„м№ҳ: н—ҲлёҢ/кіөмһҘ м·ЁмҶҢнӣ„ row лі‘н•© + 2м°Ё нӣ„ліҙл¶„лҘҳ + 3м°Ё ліөк·Җк°җмӢң + paper/trace м„ұкіј + м¶ңл Ҙ
# н•өмӢ¬:
# - v311м—җм„ң ліҙмҳҖлҚҳ л¬ём ң: paper_cancel_watchм—җлҠ” +15% лҶ“м№Ёмқҙ мһҲлҠ”лҚ° paper/register/review_traceлЎң м—°кІ°лҗҳм§Җ м•ҠмқҢ.
# - ticker кё°мӨҖмңјлЎң cancel_watch rowлҘј нӣ„ліҙ rowм—җ лі‘н•©н•ҙ ліөк·Җк°җмӢң/лҲҢлҰјк°җмӢң м№ҙмҡҙн„°к°Җ мӢӨм ңлЎң мӣҖм§ҒмқҙкІҢ н•ңлӢӨ.
# - м¶”кІ©кёҲм§Җ/нһҳл№ м§җ м·ЁмҶҢлҠ” мҷ„м „ мў…лЈҢк°Җ м•„лӢҲлқј мһ¬нҷ•мқё/лҲҢлҰјк°җмӢңлЎң мң м§Җн•ңлӢӨ.
# - л§ӨлҸ„мҡ°м„ёлҠ” л°”лЎңм§„мһ… кёҲм§Җ мӢ нҳёмқҙм§Җ, лҸҲ/к°ҖкІ©/нҳ„мһ¬лҙүмқҙ лІ„нӢ°лҠ” нӣ„ліҙлҘј лІ„лҰ¬лҠ” мӢ нҳёлЎң м“°м§Җ м•ҠлҠ”лӢӨ.
# =========================================================
V312_SCHEMA_VERSION = "cancel_reentry_bridge_v312"
V312_MODULE_LOAD_TS = time.time()
V312_STATS = {
    "cancel_bridge_rows": 0,
    "cancel_bridge_used": 0,
    "strong_miss_force_reentry": 0,
    "strong_miss_pullback_watch": 0,
    "chase_to_pullback_watch": 0,
    "weak_cancel_recheck": 0,
    "sell_heavy_keep_watch": 0,
    "discard_rescued_to_watch": 0,
    "paper_stats_rendered": 0,
    "cancel_watch_rows_seen": 0,
    "last_note": "лҢҖкё°",
}

V312_STRONG_MISS_UP = 1.50
V312_BIG_MISS_UP = 3.00
V312_REENTRY_CUR_UP = 0.70
V312_MIN_KEEP_RATIO = 0.35
V312_PULLBACK_KEEP_RATIO = 0.18
V312_MIN_TURNOVER_EOK = 1.00
V312_SELL_HEAVY_KEEP_LIVE = 1.70
V312_SELL_HEAVY_KEEP_SCORE = 5.20


def _v312_inc(key: str, note: str = ""):
    try:
        if key in V312_STATS:
            V312_STATS[key] = int(safe_float(V312_STATS.get(key, 0), 0)) + 1
        if note:
            V312_STATS["last_note"] = str(note)[:240]
    except Exception:
        pass


def _v312_ticker(row: dict = None, cls: dict = None) -> str:
    try:
        for src in (row, cls):
            if isinstance(src, dict):
                t = str(src.get("ticker", src.get("symbol", "")) or "").upper().strip()
                if t:
                    return t
    except Exception:
        pass
    return ""


def _v312_cancel_rows_map() -> dict:
    """v302/v303 cancel_watch мғҒнғңлҘј tickerлі„ мөңмӢ /к°•н•ң rowлЎң л¬¶лҠ”лӢӨ. мғҲ API нҳём¶ң м—ҶмқҢ."""
    out = {}
    try:
        if callable(globals().get("update_paper_cancel_watch_v302")):
            try:
                update_paper_cancel_watch_v302(max_items=45)
            except Exception:
                pass
        if callable(globals().get("_v302_load_cancel_watch_state")):
            try:
                _v302_load_cancel_watch_state()
            except Exception:
                pass
        state = globals().get("PAPER_CANCEL_WATCH_STATE_V302", {})
        now_ts = time.time()
        rows = []
        if isinstance(state, dict):
            rows = [dict(v) for v in state.values() if isinstance(v, dict)]
        ttl = safe_float(globals().get("PAPER_CANCEL_WATCH_TTL_SEC_V302", 3600), 3600)
        for r in rows:
            t = str(r.get("ticker", "") or "").upper().strip()
            if not t:
                continue
            cts = safe_float(r.get("cancel_ts", r.get("ts", 0)), 0)
            if cts > 0 and now_ts - cts > ttl * 3:
                continue
            max_up = safe_float(r.get("max_up_after_cancel_pct", 0), 0)
            cur_up = safe_float(r.get("current_after_cancel_pct", 0), 0)
            # к°•н•ң лҶ“м№Ё/нҳ„мһ¬ мң м§Җ нӣ„ліҙлҘј мҡ°м„ . к°ҷмңјл©ҙ мөңмӢ .
            score = max_up * 10 + max(cur_up, 0) + safe_float(r.get("updated_ts", cts), cts) / 10_000_000_000
            old = out.get(t)
            old_score = old.get("_v312_select_score", -1) if isinstance(old, dict) else -1
            rr = dict(r)
            rr["_v312_select_score"] = score
            if old is None or score > old_score:
                out[t] = rr
        if out:
            V312_STATS["cancel_watch_rows_seen"] = len(out)
    except Exception as e:
        try: append_runtime_error_log("v312_cancel_rows_map", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return out


def _v312_cancel_row_for_ticker(ticker: str) -> dict:
    t = str(ticker or "").upper().strip()
    if not t:
        return {}
    try:
        # v305 helperк°Җ мһҲмңјл©ҙ лЁјм Җ мӮ¬мҡ©. м—Ҷкұ°лӮҳ м•Ҫн•ҳл©ҙ м§Ғм ‘ map мӮ¬мҡ©.
        row = {}
        if callable(globals().get("_v305_cancel_watch_row_for_ticker")):
            try:
                row = _v305_cancel_watch_row_for_ticker(t) or {}
            except Exception:
                row = {}
        max_up = safe_float((row or {}).get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float((row or {}).get("current_after_cancel_pct", 0), 0)
        if max_up >= V312_STRONG_MISS_UP or cur_up >= V312_REENTRY_CUR_UP:
            return dict(row)
        return dict(_v312_cancel_rows_map().get(t, {}) or {})
    except Exception as e:
        try: append_runtime_error_log("v312_cancel_row_for_ticker", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {}


def _v312_merge_cancel_context(row: dict, cls: dict = None) -> tuple[dict, dict, dict]:
    row = dict(row) if isinstance(row, dict) else {}
    cls = dict(cls) if isinstance(cls, dict) else {}
    ticker = _v312_ticker(row, cls)
    cw = _v312_cancel_row_for_ticker(ticker)
    if not isinstance(cw, dict) or not cw:
        return row, cls, {}
    try:
        # paper/review/rank rowм—җ cancel_watch н•өмӢ¬ к°’мқ„ м§Ғм ‘ лі‘н•©н•ңлӢӨ.
        mapping = {
            "max_up_after_cancel_pct": "max_up_after_cancel_pct",
            "current_after_cancel_pct": "current_after_cancel_pct",
            "cancel_ts": "cancel_ts",
            "cancel_price": "cancel_price",
            "max_price_after_cancel": "max_price_after_cancel",
            "min_price_after_cancel": "min_price_after_cancel",
            "cancel_reason": "cancel_reason",
            "seconds_to_high_after_cancel": "seconds_to_high_after_cancel",
            "updated_ts": "cancel_watch_updated_ts_v312",
        }
        for src_k, dst_k in mapping.items():
            v = cw.get(src_k)
            if v not in (None, ""):
                row.setdefault(dst_k, v)
                cls.setdefault(dst_k, v)
        row["v312_cancel_bridge"] = True
        cls["v312_cancel_bridge"] = True
        cls["v312_cancel_bridge_reason"] = f"м·ЁмҶҢнӣ„ мөңкі  {safe_float(cw.get('max_up_after_cancel_pct',0),0):+.2f}% / нҳ„мһ¬ {safe_float(cw.get('current_after_cancel_pct',0),0):+.2f}%"
        _v312_inc("cancel_bridge_rows", f"м·ЁмҶҢнӣ„row лі‘н•© {ticker}")
    except Exception as e:
        try: append_runtime_error_log("v312_merge_cancel_context", str(e), exc=e, include_traceback=False)
        except Exception: pass
    return row, cls, cw


def _v312_context(row: dict, cls: dict) -> dict:
    row = row if isinstance(row, dict) else {}
    cls = cls if isinstance(cls, dict) else {}
    try:
        base = _v311_common_context(row, cls) if callable(globals().get("_v311_common_context")) else {}
    except Exception:
        base = {}
    def g(*keys, default=0):
        try:
            if callable(globals().get("_v311_get")):
                return _v311_get(row, cls, *keys, default=default)
            for src in (cls, row):
                if isinstance(src, dict):
                    for k in keys:
                        if src.get(k) not in (None, ""):
                            return src.get(k)
        except Exception:
            pass
        return default
    txt = " ".join(str(x or "") for x in [
        base.get("txt", ""), row.get("decision", ""), cls.get("decision", ""),
        row.get("rank_reason", ""), row.get("trace_reason", ""), row.get("watch_route", ""),
        cls.get("v312_cancel_bridge_reason", ""), row.get("cancel_reason", ""), cls.get("cancel_reason", ""),
    ])
    max_up = safe_float(g("max_up_after_cancel_pct", "cancel_after_max_pct", "missed_max_pct", default=base.get("max_up", 0)), 0)
    cur_up = safe_float(g("current_after_cancel_pct", "cancel_after_current_pct", "missed_current_pct", default=base.get("cur_up", 0)), 0)
    keep_ratio = (cur_up / max_up) if max_up > 0 else 0
    ch1 = safe_float(g("change_1m", "change_1", "chg_1m", default=base.get("ch1", 0)), 0)
    ch3 = safe_float(g("change_3m", "change_3", "chg_3m", default=base.get("ch3", 0)), 0)
    ch5 = safe_float(g("change_5m", "change_5", "chg_5m", default=base.get("ch5", 0)), 0)
    score = safe_float(g("score", "final_score", default=base.get("score", 0)), 0)
    trades = int(safe_float(g("trade_count_60s", "trade_count", "trades_60s", default=base.get("trades", 0)), 0))
    buy_ratio = safe_float(g("buy_ratio_60s", "buy_ratio", default=base.get("buy_ratio", 0)), 0)
    pressure = safe_float(g("current_candle_pressure_score", "candle_pressure_score", default=base.get("pressure", 0)), 0)
    live = safe_float(g("current_candle_live_score", "candle_live_score", default=base.get("live", 0)), 0)
    try:
        turnover_eok = _v311_turnover_eok(row, cls) if callable(globals().get("_v311_turnover_eok")) else 0
    except Exception:
        turnover_eok = 0
    weak_words = ["мң„кј¬лҰ¬к°•", "л§үнҢҗк°•л°ҖлҰј", "нҳ„мһ¬лҙү л°ҖлҰј", "кі м җ м•һ л°ҖлҰј", "л°ҳм§қ/мӢқлҠ”мӨ‘", "л°ҳм§қнҳ•"]
    weak_candle = any(w in txt for w in weak_words) or pressure >= 1.35
    sell_heavy = any(w in txt for w in ["л§ӨлҸ„мҡ°м„ё", "л§ӨлҸ„ мҡ°м„ё", "лҸҲмқҖ нҒ¬м§Җл§Ң л§ӨлҸ„"])
    trend_count = sum(1 for x in (ch1, ch3, ch5) if x >= 0.10)
    price_alive = (live >= V312_SELL_HEAVY_KEEP_LIVE) or (trend_count >= 2) or (cur_up >= V312_REENTRY_CUR_UP) or (score >= 6.5)
    return {
        "txt": txt,
        "max_up": max_up, "cur_up": cur_up, "keep_ratio": keep_ratio,
        "ch1": ch1, "ch3": ch3, "ch5": ch5, "score": score, "trades": trades,
        "buy_ratio": buy_ratio, "pressure": pressure, "live": live, "turnover_eok": turnover_eok,
        "weak_candle": weak_candle, "sell_heavy": sell_heavy, "trend_count": trend_count,
        "price_alive": price_alive,
        "has_cancel_bridge": bool(row.get("v312_cancel_bridge") or cls.get("v312_cancel_bridge")),
    }


def _v312_cancel_action(row: dict, cls: dict, lane: str = "", reason: str = "") -> tuple[str, str]:
    """cancel_watchмҷҖ нӣ„ліҙл¶„лҘҳлҘј мӢӨм ң м—°кІ°н•ңлӢӨ. л°”лЎң л§ӨмҲҳліҙлӢӨ ліөк·Җк°җмӢң/лҲҢлҰјлҢҖкё°лҘј мҡ°м„ н•ңлӢӨ."""
    try:
        c = _v312_context(row, cls)
        txt = c["txt"] + " " + str(lane or "") + " " + str(reason or "")
        max_up = c["max_up"]; cur_up = c["cur_up"]; keep = c["keep_ratio"]
        if max_up < V312_STRONG_MISS_UP and cur_up < V312_REENTRY_CUR_UP:
            return "", ""
        if c["turnover_eok"] < V312_MIN_TURNOVER_EOK and max_up < V312_BIG_MISS_UP:
            return "", ""
        # нһҳл№ м§җ м·ЁмҶҢлҠ” м§§мқҖ мһ¬нҷ•мқё лЈЁн”„лЎң л°ҳл“ңмӢң лӮЁкёҙлӢӨ.
        if any(x in txt for x in ["нһҳл№ м§җ", "мӢ нҳём•…нҷ”", "before_entry", "cancel"]):
            if cur_up >= 0.20 or max_up >= V312_BIG_MISS_UP:
                _v312_inc("weak_cancel_recheck", f"нһҳл№ м§җ/мӢ нҳём•…нҷ” мһ¬нҷ•мқё {_v312_ticker(row, cls)}/{max_up:+.2f}%")
        # м¶”кІ©кёҲм§Җ мҙҲкіјлҠ” л°”лЎң л§ӨмҲҳ кёҲм§Җм§Җл§Ң лҲҢлҰјк°җмӢңлЎң мң м§Җн•ңлӢӨ.
        if any(x in txt for x in ["м¶”кІ©кёҲм§Җ", "chase_over", "chase_block"]):
            if max_up >= V312_STRONG_MISS_UP:
                _v312_inc("chase_to_pullback_watch", f"м¶”кІ©вҶ’лҲҢлҰј {_v312_ticker(row, cls)}/{max_up:+.2f}%")
                return "pullback_watch", f"м¶”кІ©кёҲм§Җ мҙҲкіјм§Җл§Ң м·ЁмҶҢ нӣ„ +{max_up:.2f}% нҷ•мқё. л°”лЎң м¶”кІ© кёҲм§Җ, лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
        # нҳ„мһ¬лҸ„ мғҒмҠ№л¶„мқ„ кҪӨ мң м§Җн•ҳл©ҙ ліөк·Җк°җмӢң. м•Ҫк°„ м•Ҫн•ҳл©ҙ лҲҢлҰјк°җмӢң.
        if cur_up >= V312_REENTRY_CUR_UP and keep >= V312_MIN_KEEP_RATIO:
            _v312_inc("strong_miss_force_reentry", f"к°•н•ңлҶ“м№Ё ліөк·Җм—°кІ° {_v312_ticker(row, cls)}/{cur_up:+.2f}%")
            return "reentry_watch", f"м·ЁмҶҢ нӣ„ +{max_up:.2f}% / нҳ„мһ¬ +{cur_up:.2f}% мң м§Җ. ліөк·Җк°җмӢң к°•м ң м—°кІ°"
        if max_up >= V312_BIG_MISS_UP and keep >= V312_PULLBACK_KEEP_RATIO:
            _v312_inc("strong_miss_pullback_watch", f"к°•н•ңлҶ“м№Ё лҲҢлҰјм—°кІ° {_v312_ticker(row, cls)}/{max_up:+.2f}%")
            return "pullback_watch", f"м·ЁмҶҢ нӣ„ +{max_up:.2f}% к°•н•ң лҶ“м№Ё. нҳ„мһ¬лҠ” л°”лЎң м¶”кІ©ліҙлӢӨ лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
        return "", ""
    except Exception as e:
        try: append_runtime_error_log("v312_cancel_action", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return "", ""


def _v312_sell_heavy_keep_reason(row: dict, cls: dict) -> str:
    """л§ӨлҸ„мҡ°м„ёлқјлҸ„ к°ҖкІ©/лҸҲ/нҳ„мһ¬лҙүмқҙ лІ„нӢ°л©ҙ лІ„лҰ¬м§Җ м•Ҡкі  к°җмӢң мң м§Җн•ңлӢӨ."""
    try:
        c = _v312_context(row, cls)
        if not c["sell_heavy"]:
            return ""
        if c["turnover_eok"] >= V312_MIN_TURNOVER_EOK and c["price_alive"] and (c["score"] >= V312_SELL_HEAVY_KEEP_SCORE or c["live"] >= V312_SELL_HEAVY_KEEP_LIVE):
            _v312_inc("sell_heavy_keep_watch", f"л§ӨлҸ„мҡ°м„ём§Җл§Ң к°җмӢңмң м§Җ {_v312_ticker(row, cls)}/м җмҲҳ{c['score']:.2f}")
            return "л§ӨлҸ„мҡ°м„ёлқј л°”лЎңм§„мһ…мқҖ кёҲм§Җ. н•ҳм§Җл§Ң лҸҲ/к°ҖкІ©/нҳ„мһ¬лҙүмқҙ лІ„н…Ё мһ¬к°җмӢңВ·лҲҢлҰјлҢҖкё° мң м§Җ"
        return ""
    except Exception as e:
        try: append_runtime_error_log("v312_sell_heavy_keep_reason", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ""


try:
    _BASE_PAPER_CLASSIFY_V312 = _paper_classify_for_register_v258
except Exception:
    _BASE_PAPER_CLASSIFY_V312 = None


def _paper_classify_for_register_v258(row: dict):
    if not callable(_BASE_PAPER_CLASSIFY_V312):
        return False, "", "л¶„лҘҳн•ЁмҲҳм—ҶмқҢ", {}
    ok, lane, reason, cls = _BASE_PAPER_CLASSIFY_V312(row)
    try:
        row = row if isinstance(row, dict) else {}
        cls = cls if isinstance(cls, dict) else {}
        merged_row, merged_cls, cw = _v312_merge_cancel_context(row, cls)
        if cw:
            row, cls = merged_row, merged_cls
            _v312_inc("cancel_bridge_used", f"cancelвҶ’paper м—°кІ° {_v312_ticker(row, cls)}")
        # 1) cancel_watchм—җ к°•н•ң лҶ“м№Ёмқҙ мһҲмңјл©ҙ base okк°Җ м•Ҫн•ҙлҸ„ ліөк·Җ/лҲҢлҰј к°җмӢңлЎң мӮҙлҰ°лӢӨ.
        action, why = _v312_cancel_action(row, cls, lane, reason)
        if action in {"reentry_watch", "pullback_watch"}:
            cls = dict(cls)
            cls["paper_v312_bridge_reason"] = why
            cls["v312_route_tag"] = "м·ЁмҶҢнӣ„ ліөк·Җк°җмӢң м—°кІ°" if action == "reentry_watch" else "м·ЁмҶҢнӣ„ лҲҢлҰјмһ¬м§„мһ… к°җмӢң"
            cls["grade"] = "PULLBACK_WAIT"
            cls["paper_entry_rule_v259"] = "pullback"
            cls["decision"] = "м·ЁмҶҢнӣ„ ліөк·Җк°җмӢң" if action == "reentry_watch" else "м·ЁмҶҢнӣ„ лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
            lane = str(lane or "watch") + ("_cancel_reentry_v312" if action == "reentry_watch" else "_cancel_pullback_v312")
            reason = (str(reason or "мӢ нҳёмёө") + " / v312 " + why)[:360]
            ok = True
        # 2) discard/л°ҳм§қнҳ•мқҙм–ҙлҸ„ л§ӨлҸ„мҡ°м„ё н•ҳлӮҳлЎң лІ„лҰ¬л©ҙ м•Ҳ лҗҳлҠ” нӣ„ліҙлҠ” лҲҢлҰјлҢҖкё°лЎң мӮҙлҰ°лӢӨ.
        keep_why = _v312_sell_heavy_keep_reason(row, cls)
        cls_txt = " ".join([str(cls.get("decision", "")), str(cls.get("final_decision", "")), str(lane), str(reason)])
        if keep_why and ("discard" in str(lane).lower() or "лІ„лҰҙ" in cls_txt or "л°ҳм§қнҳ•" in cls_txt):
            cls = dict(cls)
            cls["paper_v312_bridge_reason"] = keep_why
            cls["v312_route_tag"] = "л§ӨлҸ„мҡ°м„ём§Җл§Ң к°ҖкІ©лІ„нҢҖ вҶ’ мһ¬к°җмӢң мң м§Җ"
            cls["grade"] = "PULLBACK_WAIT"
            cls["paper_entry_rule_v259"] = "pullback"
            cls["decision"] = "л§ӨлҸ„мҡ°м„ё л°”лЎңм§„мһ… кёҲм§Җ / мһ¬к°җмӢң мң м§Җ"
            lane = str(lane or "watch") + "_sellheavy_keep_v312"
            reason = (str(reason or "мӢ нҳёмёө") + " / v312 " + keep_why)[:360]
            ok = True
            _v312_inc("discard_rescued_to_watch", f"лІ„лҰјл°©м§Җ {_v312_ticker(row, cls)}")
        return ok, lane, reason, cls
    except Exception as e:
        try: append_runtime_error_log("v312_paper_classify", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return ok, lane, reason, cls


