# =========================================================
# v2.5.313: к°•н•ңлҶ“м№Ё cancel_watch м§Ғм ‘ мЈјмһ… лЈЁн”„ кі м •
# мң„м№ҳ: cancel_watch м°Ҫкі  + worker к°•м ң reentry queue + paper pending м§Ғм ‘л“ұлЎқ + м¶ңл Ҙ
# н•өмӢ¬:
# - v312лҠ” нӣ„ліҙк°Җ paper/register кІҪлЎңлҘј лӢӨмӢң нғҖм•ј ліөк·Җк°җмӢңк°Җ мӣҖм§Ғмқј мҲҳ мһҲм—ҲлӢӨ.
# - v313мқҖ м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ёмқҙ л°ңмғқн•ҳл©ҙ rank нӣ„ліҙ мһ¬л“ұмһҘ м—¬л¶ҖмҷҖ мғҒкҙҖм—Ҷмқҙ cancel_reentry_queueм—җ к°•м ң мЈјмһ…н•ңлӢӨ.
# - лӢЁ, л°”лЎң л§ӨмҲҳлҠ” кёҲм§Җн•ҳкі  PENDING мғҒнғңмқҳ ліөк·Җк°җмӢң/лҲҢлҰјк°җмӢңлЎңл§Ң л“ұлЎқн•ңлӢӨ.
# - мқҙмғҒн•ҳл©ҙ мЎ°кұҙмқ„ лҚ” мЎ°мқҙлҠ” кІҢ м•„лӢҲлқј, мқҙ л¬ён„ұ мһҗмІҙмқҳ кё°мӨҖк°’мқ„ мЎ°м •н•ңлӢӨ.
# =========================================================
V313_SCHEMA_VERSION = "cancel_reentry_force_queue_v313"
V313_MODULE_LOAD_TS = time.time()
V313_REENTRY_FILE = data_file("paper_cancel_reentry_queue_v313.json")
V313_REENTRY_STATE = {}
V313_STATE_LOADED = False
V313_STATE_LOCK = threading.RLock()
V313_FORCE_WATCH_TTL_SEC = 40 * 60
V313_READD_COOLDOWN_SEC = 20 * 60
V313_MAX_FORCE_PER_CYCLE = 4
V313_MIN_MAX_UP = 1.50
V313_MIN_CUR_UP = 0.70
V313_BIG_MISS_UP = 3.00
V313_CHASE_PULLBACK_UP = 5.00
V313_MIN_TURNOVER_EOK = 1.00
V313_PULLBACK_HIGH_RATIO = 0.995
V313_PULLBACK_LOW_RATIO = 0.982
V313_BREAKOUT_TRIGGER_RATIO = 1.002
V313_BREAKOUT_CHASE_RATIO = 1.012
V313_STATS = {
    "cancel_rows_seen": 0,
    "force_candidates": 0,
    "force_registered": 0,
    "force_pullback": 0,
    "force_breakout": 0,
    "skip_active": 0,
    "skip_recent": 0,
    "skip_weak": 0,
    "skip_no_price": 0,
    "queue_active": 0,
    "queue_loaded": 0,
    "paper_flow_rendered": 0,
    "paper_stats_rendered": 0,
    "last_note": "лҢҖкё°",
}


def _v313_inc(key: str, note: str = ""):
    try:
        if key in V313_STATS:
            V313_STATS[key] = int(safe_float(V313_STATS.get(key, 0), 0)) + 1
        if note:
            V313_STATS["last_note"] = str(note)[:260]
    except Exception:
        pass


def _v313_load_state(force: bool = False) -> dict:
    global V313_STATE_LOADED, V313_REENTRY_STATE
    try:
        with V313_STATE_LOCK:
            if V313_STATE_LOADED and not force:
                return V313_REENTRY_STATE
            raw = load_json_file(V313_REENTRY_FILE, {})
            rows = raw.get("rows", raw) if isinstance(raw, dict) else {}
            if isinstance(rows, list):
                rows = {str(x.get("key", i)): dict(x) for i, x in enumerate(rows) if isinstance(x, dict)}
            if not isinstance(rows, dict):
                rows = {}
            now_ts = time.time()
            cleaned = {}
            for k, r in rows.items():
                if not isinstance(r, dict):
                    continue
                ts = safe_float(r.get("registered_ts", r.get("created_ts", 0)), 0)
                if ts > 0 and now_ts - ts > V313_FORCE_WATCH_TTL_SEC * 3:
                    continue
                cleaned[str(k)] = dict(r)
            V313_REENTRY_STATE = cleaned
            V313_STATE_LOADED = True
            V313_STATS["queue_loaded"] = len(cleaned)
            return V313_REENTRY_STATE
    except Exception as e:
        try: append_runtime_error_log("v313_load_state", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return {}


def _v313_save_state():
    try:
        _v313_load_state()
        now_ts = time.time()
        with V313_STATE_LOCK:
            rows = {str(k): dict(v) for k, v in (V313_REENTRY_STATE or {}).items() if isinstance(v, dict)}
        cleaned = {}
        for k, r in rows.items():
            ts = safe_float(r.get("registered_ts", r.get("created_ts", 0)), 0)
            if ts > 0 and now_ts - ts > V313_FORCE_WATCH_TTL_SEC * 3:
                continue
            cleaned[str(k)] = dict(r)
        save_json_file(V313_REENTRY_FILE, {"schema": V313_SCHEMA_VERSION, "updated_ts": now_ts, "rows": cleaned})
        with V313_STATE_LOCK:
            V313_REENTRY_STATE.clear()
            V313_REENTRY_STATE.update(cleaned)
        V313_STATS["queue_active"] = len([1 for r in cleaned.values() if str(r.get("status", "")).upper() in {"WATCH", "PENDING", "REGISTERED"}])
    except Exception as e:
        try: append_runtime_error_log("v313_save_state", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _v313_cancel_rows(limit: int = 80) -> list:
    """cancel_watch к°•н•ң лҶ“м№Ё rowsлҘј м§Ғм ‘ мҲҳм§‘н•ңлӢӨ. мғҲ API нҳём¶ң м—ҶмқҢ."""
    try:
        if callable(globals().get("update_paper_cancel_watch_v302")):
            try:
                update_paper_cancel_watch_v302(max_items=max(20, int(limit)))
            except Exception:
                pass
        if callable(globals().get("_v302_important_cancel_rows")):
            rows = list(_v302_important_cancel_rows(limit=max(20, int(limit)), include_weak=False) or [])
        else:
            if callable(globals().get("_v302_load_cancel_watch_state")):
                try: _v302_load_cancel_watch_state()
                except Exception: pass
            state = globals().get("PAPER_CANCEL_WATCH_STATE_V302", {})
            rows = [dict(v) for v in (state or {}).values() if isinstance(v, dict)]
        out = []
        for r in rows:
            if not isinstance(r, dict):
                continue
            t = str(r.get("ticker", "") or "").upper().strip()
            if not t:
                continue
            max_up = safe_float(r.get("max_up_after_cancel_pct", 0), 0)
            cur_up = safe_float(r.get("current_after_cancel_pct", 0), 0)
            if max_up >= V313_MIN_MAX_UP or cur_up >= V313_MIN_CUR_UP:
                out.append(dict(r))
        out.sort(key=lambda r: (safe_float(r.get("max_up_after_cancel_pct", 0), 0), safe_float(r.get("current_after_cancel_pct", 0), 0), safe_float(r.get("cancel_ts", 0), 0)), reverse=True)
        V313_STATS["cancel_rows_seen"] = len(out)
        return out[:max(1, int(limit))]
    except Exception as e:
        try: append_runtime_error_log("v313_cancel_rows", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return []


def _v313_reentry_key(row: dict) -> str:
    try:
        t = str(row.get("ticker", "") or "").upper().strip()
        src_key = str(row.get("key", "") or "")
        cts = int(safe_float(row.get("cancel_ts", row.get("created_ts", 0)), 0))
        if src_key:
            return f"{t}:{src_key}"
        return f"{t}:cancel:{cts}"
    except Exception:
        return str(time.time())


def _v313_recently_queued(key: str, ticker: str) -> bool:
    try:
        _v313_load_state()
        now_ts = time.time()
        with V313_STATE_LOCK:
            rows = list((V313_REENTRY_STATE or {}).values())
            cur = V313_REENTRY_STATE.get(str(key))
        if isinstance(cur, dict):
            ts = safe_float(cur.get("registered_ts", cur.get("created_ts", 0)), 0)
            if ts > 0 and now_ts - ts < V313_READD_COOLDOWN_SEC:
                return True
        ticker = str(ticker or "").upper().strip()
        for r in rows:
            if not isinstance(r, dict):
                continue
            if str(r.get("ticker", "")).upper().strip() != ticker:
                continue
            ts = safe_float(r.get("registered_ts", r.get("created_ts", 0)), 0)
            if ts > 0 and now_ts - ts < V313_READD_COOLDOWN_SEC:
                return True
    except Exception:
        pass
    return False


def _v313_turnover_eok_from_cancel(row: dict) -> float:
    try:
        money = safe_float(row.get("money_amount", row.get("turnover", row.get("turnover_krw", 0))), 0)
        if money > 0:
            return money / 100000000.0
        # кіјкұ° cancel rowк°Җ moneyлҘј лӘ» лӢҙмқҖ кІҪмҡ°, +3% мқҙмғҒ к°•н•ң лҶ“м№ЁмқҖ мөңмҶҢ мһ¬к°җмӢң лҢҖмғҒ м·Ёкёү
        if safe_float(row.get("max_up_after_cancel_pct", 0), 0) >= V313_BIG_MISS_UP:
            return V313_MIN_TURNOVER_EOK
    except Exception:
        pass
    return 0.0


def _v313_choose_mode(row: dict) -> tuple[str, str]:
    try:
        max_up = safe_float(row.get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float(row.get("current_after_cancel_pct", 0), 0)
        keep = (cur_up / max_up) if max_up > 0 else 0
        reason = str(row.get("close_reason", row.get("cancel_reason", "")) or "")
        # мқҙлҜё л§Һмқҙ мҳӨлҘё нӣ„ліҙлҠ” л°”лЎң м¶”кІ©н•ҳм§Җ м•Ҡкі  лҲҢлҰј мһ¬м§„мһ…мңјлЎң кі м •н•ңлӢӨ.
        if "м¶”кІ©" in reason or "chase" in reason.lower() or max_up >= V313_CHASE_PULLBACK_UP or cur_up >= 2.50:
            return "pullback", f"к°•н•ңлҶ“м№Ё +{max_up:.2f}% / нҳ„мһ¬ +{cur_up:.2f}% вҶ’ м¶”кІ©кёҲм§Җ, лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
        if "нһҳл№ м§җ" in reason or "мӢ нҳём•…нҷ”" in reason or "weak" in reason.lower():
            if cur_up >= V313_MIN_CUR_UP or keep >= 0.35:
                return "breakout", f"нһҳл№ м§җм·ЁмҶҢ нӣ„ мһ¬нҡҢліө к°ҖлҠҘ / мөңкі  +{max_up:.2f}% / нҳ„мһ¬ +{cur_up:.2f}% вҶ’ м§§мқҖ мһ¬нҷ•мқё"
            return "pullback", f"нһҳл№ м§җм·ЁмҶҢ нӣ„ к°•н•ңлҶ“м№Ё +{max_up:.2f}% вҶ’ лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
        if cur_up >= V313_MIN_CUR_UP and keep >= 0.35:
            return "breakout", f"м·ЁмҶҢнӣ„ нҳ„мһ¬мғҒмҠ№ мң м§Җ +{cur_up:.2f}% вҶ’ ліөк·Җк°җмӢң"
        return "pullback", f"м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё +{max_up:.2f}% вҶ’ лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
    except Exception:
        return "pullback", "м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё вҶ’ лҲҢлҰј мһ¬м§„мһ… к°җмӢң"


def _v313_register_forced_pending(row: dict, mode: str, why: str) -> bool:
    """cancel_watch rowлҘј paper PENDINGмңјлЎң м§Ғм ‘ л“ұлЎқн•ңлӢӨ. мӢӨм ң мЈјл¬ё м•„лӢҳ. л°”лЎң л§ӨмҲҳ кёҲм§Җ."""
    try:
        ticker = str(row.get("ticker", "") or "").upper().strip()
        if not ticker:
            return False
        now_ts = time.time()
        if callable(globals().get("_paper_has_active_ticker_v258")) and _paper_has_active_ticker_v258(ticker):
            _v313_inc("skip_active", f"мқҙлҜё м§„н–үмӨ‘ {ticker}")
            return False
        key = _v313_reentry_key(row)
        if _v313_recently_queued(key, ticker):
            _v313_inc("skip_recent", f"мөңк·ј к°•м ңк°җмӢң мһҲмқҢ {ticker}")
            return False
        price_fallback = safe_float(row.get("last_price", row.get("current_price", row.get("max_price_after_cancel", row.get("cancel_price", 0)))), 0)
        try:
            price, src, age = _paper_price_v258(ticker, fallback=price_fallback)
        except Exception:
            price, src, age = price_fallback, "fallback", 0
        price = safe_float(price, 0)
        if price <= 0:
            _v313_inc("skip_no_price", f"к°ҖкІ©м—ҶмқҢ {ticker}")
            return False
        max_up = safe_float(row.get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float(row.get("current_after_cancel_pct", 0), 0)
        turnover_eok = _v313_turnover_eok_from_cancel(row)
        if (max_up < V313_MIN_MAX_UP and cur_up < V313_MIN_CUR_UP) or turnover_eok < V313_MIN_TURNOVER_EOK:
            _v313_inc("skip_weak", f"к°•м ңк°җмӢң м•Ҫн•Ё {ticker}/{max_up:+.2f}/{turnover_eok:.2f}м–ө")
            return False
        if len(_paper_open_rows_v258()) >= max(1, int(globals().get("PAPER_MAX_ACTIVE", 24))):
            _v313_inc("skip_active", "paper active м ңн•ң")
            return False
        mode = "pullback" if mode not in {"breakout", "pullback"} else mode
        if mode == "breakout":
            entry_rule = "breakout"
            planned_low = price * V313_BREAKOUT_TRIGGER_RATIO
            planned_high = planned_low
            chase_stop = price * V313_BREAKOUT_CHASE_RATIO
            _v313_inc("force_breakout", f"ліөк·Җк°җмӢң л“ұлЎқ {ticker}")
        else:
            entry_rule = "pullback"
            planned_high = price * V313_PULLBACK_HIGH_RATIO
            planned_low = price * V313_PULLBACK_LOW_RATIO
            chase_stop = price * 1.008
            _v313_inc("force_pullback", f"лҲҢлҰјк°җмӢң л“ұлЎқ {ticker}")
        entry_base = planned_low if mode == "breakout" else planned_high
        stop = entry_base * 0.985
        tp1 = entry_base * 1.012
        tp2 = entry_base * 1.022
        tp3 = entry_base * 1.035
        pos_id = _paper_make_id_v258(ticker)
        pos = {
            "id": pos_id,
            "ticker": ticker,
            "status": "PENDING",
            "lane": f"cancel_reentry_forced_v313_{mode}",
            "trigger": "cancel_watch_force_v313",
            "register_reason": str(why or "м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё к°•м ңк°җмӢң")[:360],
            "signal_grade": "PULLBACK_WAIT",
            "signal_decision": "м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё к°•м ңк°җмӢң / л°”лЎңл§ӨмҲҳ м•„лӢҳ",
            "original_grade": "CANCEL_REENTRY_FORCE",
            "created_ts": now_ts,
            "entry_rule": entry_rule,
            "planned_entry_low": safe_float(planned_low, 0),
            "planned_entry_high": safe_float(planned_high, 0),
            "chase_stop": safe_float(chase_stop, 0),
            "entry_price": 0.0,
            "entered_ts": 0.0,
            "last_price": price,
            "last_price_source": f"v313_{src}",
            "last_price_age": safe_float(age, 0),
            "stop": safe_float(stop, 0),
            "tp1": safe_float(tp1, 0),
            "tp2": safe_float(tp2, 0),
            "tp3": safe_float(tp3, 0),
            "remaining_ratio": 1.0,
            "realized_pct": 0.0,
            "tp1_hit": False,
            "tp2_hit": False,
            "tp3_hit": False,
            "max_up_pct": 0.0,
            "min_down_pct": 0.0,
            "score": safe_float(row.get("score", 0), 0),
            "money_amount": safe_float(row.get("money_amount", 0), 0),
            "trade_count": int(safe_float(row.get("trade_count", 0), 0)),
            "buy_ratio": safe_float(row.get("buy_ratio", 0), 0),
            "cancel_watch_key": str(row.get("key", key)),
            "cancel_price": safe_float(row.get("cancel_price", 0), 0),
            "cancel_ts": safe_float(row.get("cancel_ts", 0), 0),
            "max_up_after_cancel_pct": max_up,
            "current_after_cancel_pct": cur_up,
            "max_price_after_cancel": safe_float(row.get("max_price_after_cancel", 0), 0),
            "min_price_after_cancel": safe_float(row.get("min_price_after_cancel", 0), 0),
            "reasons": ["v313 к°•м ңк°җмӢң", str(why or "")[:120]],
            "note": "мӢӨм ң мЈјл¬ё м•„лӢҳ / м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё к°•м ңк°җмӢң",
        }
        with PAPER_STATE_LOCK:
            paper_positions[pos_id] = dict(pos)
        PAPER_V258_STATS["registered"] = int(safe_float(PAPER_V258_STATS.get("registered", 0), 0)) + 1
        PAPER_V258_STATS["last_note"] = f"v313 к°•м ңк°җмӢң л“ұлЎқ {ticker}/{entry_rule}"
        save_paper_state_v258()
        _v313_load_state()
        with V313_STATE_LOCK:
            V313_REENTRY_STATE[str(key)] = {
                "key": str(key), "ticker": ticker, "status": "REGISTERED", "mode": mode,
                "paper_pos_id": pos_id, "registered_ts": now_ts, "price": price,
                "max_up_after_cancel_pct": max_up, "current_after_cancel_pct": cur_up,
                "why": str(why or "")[:240],
            }
        _v313_save_state()
        _v313_inc("force_registered", f"к°•м ңк°җмӢң л“ұлЎқ {ticker}/{mode}/{max_up:+.2f}%")
        return True
    except Exception as e:
        try: append_runtime_error_log("v313_register_forced_pending", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return False


def force_cancel_reentry_queue_v313(max_register: int = None) -> int:
    """к°•н•ңлҶ“м№Ё нӣ„ліҙлҘј rank мһ¬л“ұмһҘ м—¬л¶ҖмҷҖ л¬ҙкҙҖн•ҳкІҢ paper PENDING к°җмӢңлЎң м§Ғм ‘ мЈјмһ…н•ңлӢӨ."""
    added = 0
    try:
        max_register = V313_MAX_FORCE_PER_CYCLE if max_register is None else max(1, int(max_register))
        rows = _v313_cancel_rows(limit=80)
        if rows:
            V313_STATS["force_candidates"] = len(rows)
        for row in rows:
            if added >= max_register:
                break
            mode, why = _v313_choose_mode(row)
            if _v313_register_forced_pending(row, mode, why):
                added += 1
        if added:
            _v313_inc("force_candidates", f"к°•м ңк°җмӢң мЈјмһ… {added}к°ң")
        return added
    except Exception as e:
        try: append_runtime_error_log("force_cancel_reentry_queue_v313", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return added


