def _v313_active_queue_rows(limit: int = 6) -> list:
    try:
        _v313_load_state()
        now_ts = time.time()
        with V313_STATE_LOCK:
            rows = [dict(v) for v in (V313_REENTRY_STATE or {}).values() if isinstance(v, dict)]
        rows.sort(key=lambda r: safe_float(r.get("registered_ts", 0), 0), reverse=True)
        out = []
        for r in rows:
            ts = safe_float(r.get("registered_ts", 0), 0)
            if ts > 0 and now_ts - ts <= V313_FORCE_WATCH_TTL_SEC * 3:
                out.append(r)
        return out[:max(1, int(limit))]
    except Exception:
        return []


def _v313_queue_section(full: bool = False) -> str:
    rows = _v313_active_queue_rows(limit=8 if full else 4)
    lines = ["рҹ§І v313 к°•н•ңлҶ“м№Ё к°•м ңк°җмӢң"]
    lines.append("- к°•н•ң лҶ“м№ЁмқҖ кё°лЎқмңјлЎң лҒқлӮҙм§Җ м•Ҡкі , л°”лЎңл§ӨмҲҳ м—Ҷмқҙ лҲҢлҰј/ліөк·Җ PENDINGмңјлЎң к°•м ң м—°кІ°")
    if not rows:
        lines.append("- нҳ„мһ¬ к°•м ңк°җмӢң л“ұлЎқ м—ҶмқҢ")
        return "\n".join(lines)
    for i, r in enumerate(rows, start=1):
        t = str(r.get("ticker", "?") or "?").upper()
        mode = "лҲҢлҰјк°җмӢң" if str(r.get("mode", "")) == "pullback" else "ліөк·Җк°җмӢң"
        age = format_elapsed_text(max(0, time.time() - safe_float(r.get("registered_ts", 0), 0))) if callable(globals().get("format_elapsed_text")) else f"{int(max(0, time.time()-safe_float(r.get('registered_ts',0),0)))}мҙҲ"
        lines.append(f"{i}. {t} / {mode} / мөңкі  {safe_float(r.get('max_up_after_cancel_pct',0),0):+.2f}% / нҳ„мһ¬ {safe_float(r.get('current_after_cancel_pct',0),0):+.2f}% / л“ұлЎқ {age} м „")
        if full:
            lines.append(f"   - мӮ¬мң : {str(r.get('why',''))[:180]}")
    return "\n".join(lines)


