# =========================================================
# v2.5.314: мҲҳмқөлҘ  ліём„  - к°•н•ңлҶ“м№Ё ліөк·Җк°•н•Ё / мЈҪмқҖ к°җмӢң мў…лЈҢм„ 
# мң„м№ҳ: cancel_watch/reentry queue + paper PENDING м „мІҳлҰ¬ + paper OPEN ліҙнҳёмІӯмӮ° + м¶ңл Ҙ
# н•өмӢ¬:
# - v313мқҖ к°•н•ңлҶ“м№Ёмқ„ к°җмӢң лЈЁн”„лЎң к°•м ң м—°кІ°н•ҳлҠ” лҚ° м„ұкіөн–ҲлӢӨ.
# - v314лҠ” к·ё к°җмӢң нӣ„ліҙ мӨ‘ KNCнҳ• ліөк·Җк°•н•ЁмқҖ лӘЁмқҳм§„мһ…к№Ңм§Җ лҚ” л№ лҘҙкІҢ м—°кІ°н•ҳкі ,
#   AWEнҳ• л¬ҙл„Ҳм§„ лҲҢлҰјк°җмӢңлҠ” к°җмӢңм№ём—җм„ң л№ЁлҰ¬ м ңкұ°н•ңлӢӨ.
# - мЎ°кұҙ м „мІҙ к°•нҷ”к°Җ м•„лӢҲлқј, мҲҳмқө лӮҳлҠ” л¬ён„ұкіј мҶҗмӢӨ лӮҳлҠ” л¬ён„ұмқҳ мң„м№ҳлҘј мһ¬л°°м№ҳн•ңлӢӨ.
# =========================================================
V314_SCHEMA_VERSION = "profit_reentry_guard_v314"
V314_MODULE_LOAD_TS = time.time()
V314_STRONG_RETURN_MAX_UP = 3.00
V314_STRONG_RETURN_CUR_UP = 1.20
V314_STRONG_RETURN_KEEP_RATIO = 0.38
V314_STRONG_ENTRY_TRIGGER = 1.001
V314_STRONG_CHASE_STOP = 1.010
V314_STRONG_STOP = 0.994
V314_STRONG_TP1 = 1.009
V314_STRONG_TP2 = 1.018
V314_STRONG_TP3 = 1.032
V314_DEAD_FROM_REGISTER_PCT = -2.00
V314_DEAD_FROM_CANCEL_PCT = -2.00
V314_DEAD_FROM_HIGH_DROP_PCT = 5.00
V314_PENDING_MAX_SEC = 28 * 60
V314_OPEN_FAST_LOSS_PCT = -0.45
V314_OPEN_PROFIT_PROTECT_MAX_UP = 0.90
V314_OPEN_PROFIT_PROTECT_FLOOR = 0.18
V314_STATS = {
    "strong_return_convert": 0,
    "pullback_to_breakout": 0,
    "dead_pending_cancel": 0,
    "stale_pending_cancel": 0,
    "open_fast_loss_cut": 0,
    "open_profit_protect": 0,
    "queue_dead_closed": 0,
    "paper_stats_rendered": 0,
    "last_note": "лҢҖкё°",
}


def _v314_inc(key: str, note: str = ""):
    try:
        if key in V314_STATS:
            V314_STATS[key] = int(safe_float(V314_STATS.get(key, 0), 0)) + 1
        if note:
            V314_STATS["last_note"] = str(note)[:260]
    except Exception:
        pass


def _v314_forced_lane(pos: dict) -> bool:
    try:
        lane = str((pos or {}).get("lane", "") or "")
        trig = str((pos or {}).get("trigger", "") or "")
        return "cancel_reentry_forced_v313" in lane or "cancel_watch_force_v313" in trig
    except Exception:
        return False


def _v314_price_change_from(base_price: float, price: float) -> float:
    try:
        base_price = safe_float(base_price, 0)
        price = safe_float(price, 0)
        if base_price <= 0 or price <= 0:
            return 0.0
        return (price / base_price - 1.0) * 100.0
    except Exception:
        return 0.0


def _v314_pending_strength(pos: dict, price: float) -> dict:
    try:
        pos = pos if isinstance(pos, dict) else {}
        price = safe_float(price, 0)
        cancel_price = safe_float(pos.get("cancel_price", 0), 0)
        registered_price = safe_float(pos.get("v314_registered_price", pos.get("last_price", pos.get("price", 0))), 0)
        max_up = safe_float(pos.get("max_up_after_cancel_pct", 0), 0)
        cur_from_cancel = _v314_price_change_from(cancel_price, price) if cancel_price > 0 else safe_float(pos.get("current_after_cancel_pct", 0), 0)
        keep_ratio = (cur_from_cancel / max_up) if max_up > 0 else 0.0
        max_price = safe_float(pos.get("max_price_after_cancel", 0), 0)
        drop_from_high = _v314_price_change_from(max_price, price) if max_price > 0 else 0.0
        change_from_reg = _v314_price_change_from(registered_price, price) if registered_price > 0 else 0.0
        return {
            "cancel_price": cancel_price,
            "registered_price": registered_price,
            "max_up": max_up,
            "cur_from_cancel": cur_from_cancel,
            "keep_ratio": keep_ratio,
            "max_price": max_price,
            "drop_from_high": drop_from_high,
            "change_from_reg": change_from_reg,
        }
    except Exception:
        return {"max_up": 0.0, "cur_from_cancel": 0.0, "keep_ratio": 0.0, "drop_from_high": 0.0, "change_from_reg": 0.0}


def _v314_is_strong_return(pos: dict, price: float) -> tuple[bool, str, dict]:
    """KNCнҳ•: м·ЁмҶҢ нӣ„ нҒ¬кІҢ к°”кі  нҳ„мһ¬лҸ„ мӮҙм•„ мһҲмңјл©ҙ лҲҢлҰјл§Ң кё°лӢӨлҰ¬лӢӨ лҶ“м№ҳм§Җ м•ҠкІҢ ліөк·Җк°•н•ЁмңјлЎң м „нҷҳ."""
    try:
        c = _v314_pending_strength(pos, price)
        max_up = safe_float(c.get("max_up", 0), 0)
        cur_up = safe_float(c.get("cur_from_cancel", 0), 0)
        keep = safe_float(c.get("keep_ratio", 0), 0)
        drop_high = safe_float(c.get("drop_from_high", 0), 0)
        if max_up >= V314_STRONG_RETURN_MAX_UP and cur_up >= V314_STRONG_RETURN_CUR_UP and keep >= V314_STRONG_RETURN_KEEP_RATIO and drop_high > -V314_DEAD_FROM_HIGH_DROP_PCT:
            return True, f"к°•н•ңлҶ“м№Ё ліөк·Җк°•н•Ё: мөңкі  +{max_up:.2f}% / нҳ„мһ¬ +{cur_up:.2f}% / мң м§Җ {keep:.2f}", c
        return False, "", c
    except Exception:
        return False, "", {}


# v313мқҳ mode м„ нғқмқ„ v314 кё°мӨҖмңјлЎң н•ң лІҲ лҚ” лҚ®лҠ”лӢӨ.
try:
    _BASE_V313_CHOOSE_MODE_V314 = _v313_choose_mode
except Exception:
    _BASE_V313_CHOOSE_MODE_V314 = None


def _v313_choose_mode(row: dict) -> tuple[str, str]:
    try:
        row = row if isinstance(row, dict) else {}
        max_up = safe_float(row.get("max_up_after_cancel_pct", 0), 0)
        cur_up = safe_float(row.get("current_after_cancel_pct", 0), 0)
        keep = (cur_up / max_up) if max_up > 0 else 0.0
        reason = str(row.get("close_reason", row.get("cancel_reason", "")) or "")
        # м¶”кІ©кёҲм§Җ м·ЁмҶҢлҠ” к·ёлҢҖлЎң лҲҢлҰјк°җмӢң. лӢЁ, нһҳл№ м§җ/мӢ нҳём•…нҷ” м·ЁмҶҢ нӣ„ нҳ„мһ¬лҸ„ к°•н•ҳл©ҙ ліөк·Җк°•н•ЁмңјлЎң ліёлӢӨ.
        if not ("м¶”кІ©" in reason or "chase" in reason.lower()):
            if max_up >= V314_STRONG_RETURN_MAX_UP and cur_up >= V314_STRONG_RETURN_CUR_UP and keep >= V314_STRONG_RETURN_KEEP_RATIO:
                _v314_inc("strong_return_convert", f"mode ліөк·Җк°•н•Ё {row.get('ticker','?')}/{cur_up:+.2f}%")
                return "breakout", f"v314 ліөк·Җк°•н•Ё: мөңкі  +{max_up:.2f}% / нҳ„мһ¬ +{cur_up:.2f}% мң м§Җ вҶ’ м§§мқҖ мһ¬мғҒмҠ№ нҷ•мқё"
        if callable(_BASE_V313_CHOOSE_MODE_V314):
            return _BASE_V313_CHOOSE_MODE_V314(row)
        return "pullback", "м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё вҶ’ лҲҢлҰј мһ¬м§„мһ… к°җмӢң"
    except Exception:
        return ("pullback", "м·ЁмҶҢнӣ„ к°•н•ңлҶ“м№Ё вҶ’ лҲҢлҰј мһ¬м§„мһ… к°җмӢң")


def _v314_prepare_forced_pending_once() -> int:
    """base paper update м „м—җ мӢӨн–ү. к°•н•ң ліөк·Җ нӣ„ліҙк°Җ chase_overлЎң м·ЁмҶҢлҗҳкё° м „м—җ breakout лҢҖкё°лЎң м „нҷҳн•ңлӢӨ."""
    changed = 0
    try:
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            if str(pos.get("status", "") or "").upper() != "PENDING":
                continue
            if not _v314_forced_lane(pos):
                continue
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            fallback = safe_float(pos.get("last_price", pos.get("planned_entry_high", 0)), 0)
            try:
                price, src, age = _paper_price_v258(ticker, fallback=fallback)
            except Exception:
                price, src, age = fallback, "fallback", 0
            price = safe_float(price, 0)
            if price <= 0:
                continue
            is_strong, why, ctx = _v314_is_strong_return(pos, price)
            if not is_strong:
                continue
            lane = str(pos.get("lane", "") or "")
            # мқҙлҜё v314 м „нҷҳлҗң кұҙ л°ҳліөн•ҳм§Җ м•ҠмқҢ.
            if "strong_return_v314" in lane:
                continue
            low = price * V314_STRONG_ENTRY_TRIGGER
            high = low
            chase = price * V314_STRONG_CHASE_STOP
            stop = price * V314_STRONG_STOP
            tp1 = price * V314_STRONG_TP1
            tp2 = price * V314_STRONG_TP2
            tp3 = price * V314_STRONG_TP3
            with PAPER_STATE_LOCK:
                cur = paper_positions.get(pid)
                if not isinstance(cur, dict):
                    continue
                cur["entry_rule"] = "breakout"
                cur["planned_entry_low"] = safe_float(low, 0)
                cur["planned_entry_high"] = safe_float(high, 0)
                cur["chase_stop"] = safe_float(chase, 0)
                cur["stop"] = safe_float(stop, 0)
                cur["tp1"] = safe_float(tp1, 0)
                cur["tp2"] = safe_float(tp2, 0)
                cur["tp3"] = safe_float(tp3, 0)
                cur["lane"] = (lane + "_strong_return_v314")[:180]
                cur["signal_decision"] = "к°•н•ңлҶ“м№Ё ліөк·Җк°•н•Ё / мһ¬мғҒмҠ№ нҷ•мқёлҢҖкё°"
                cur["register_reason"] = (str(cur.get("register_reason", "")) + " / " + why)[:420]
                cur["v314_route"] = "strong_return_breakout"
                cur["v314_reason"] = why
                cur["last_price"] = price
                cur["last_price_source"] = f"v314_{src}"
                cur["last_price_age"] = safe_float(age, 0)
                cur["updated_ts"] = now_ts
            changed += 1
            _v314_inc("pullback_to_breakout", f"ліөк·Җк°•н•Ё м „нҷҳ {ticker}")
        if changed:
            save_paper_state_v258()
        return changed
    except Exception as e:
        try: append_runtime_error_log("v314_prepare_forced_pending", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return changed


def _v314_cleanup_forced_positions_once() -> int:
    """к°•м ңк°җмӢң мӨ‘ мЈҪмқҖ нӣ„ліҙлҘј л№ЁлҰ¬ мў…лЈҢн•ҳкі , м—ҙлҰ° нӣ„ліҙмқҳ мҶҗмӢӨ/мҲҳмқөліҙнҳёлҘј кҙҖлҰ¬н•ңлӢӨ."""
    changed = 0
    try:
        now_ts = time.time()
        with PAPER_STATE_LOCK:
            items = [(pid, dict(pos)) for pid, pos in (paper_positions or {}).items() if isinstance(pos, dict)]
        for pid, pos in items:
            if not _v314_forced_lane(pos):
                continue
            ticker = str(pos.get("ticker", "") or "").upper().strip()
            if not ticker:
                continue
            fallback = safe_float(pos.get("last_price", pos.get("entry_price", pos.get("planned_entry_high", 0))), 0)
            try:
                price, src, age = _paper_price_v258(ticker, fallback=fallback)
            except Exception:
                price, src, age = fallback, "fallback", 0
            price = safe_float(price, 0)
            if price <= 0:
                continue
            status = str(pos.get("status", "") or "").upper()
            ctx = _v314_pending_strength(pos, price)
            age_sec = now_ts - safe_float(pos.get("created_ts", now_ts), now_ts)
            if status == "PENDING":
                change_reg = safe_float(ctx.get("change_from_reg", 0), 0)
                change_cancel = safe_float(ctx.get("cur_from_cancel", 0), 0)
                drop_high = safe_float(ctx.get("drop_from_high", 0), 0)
                if change_reg <= V314_DEAD_FROM_REGISTER_PCT or change_cancel <= V314_DEAD_FROM_CANCEL_PCT or drop_high <= -V314_DEAD_FROM_HIGH_DROP_PCT:
                    reason = f"v314_force_watch_dead: л“ұлЎқлҢҖл№„ {change_reg:+.2f}% / м·ЁмҶҢлҢҖл№„ {change_cancel:+.2f}% / кі м җлҢҖл№„ {drop_high:+.2f}%"
                    _paper_cancel_pending_v258(pid, pos, reason, now_ts)
                    _v314_mark_queue_status(pid, "DEAD", reason)
                    _v314_inc("dead_pending_cancel", f"мЈҪмқҖ к°•м ңк°җмӢң мў…лЈҢ {ticker}")
                    changed += 1
                    continue
                if age_sec >= V314_PENDING_MAX_SEC and change_cancel < 0.50:
                    _paper_cancel_pending_v258(pid, pos, "v314_force_watch_stale_no_reentry", now_ts)
                    _v314_mark_queue_status(pid, "STALE", "v314_force_watch_stale_no_reentry")
                    _v314_inc("stale_pending_cancel", f"мҳӨлһҳлҗң к°•м ңк°җмӢң мў…лЈҢ {ticker}")
                    changed += 1
                    continue
            elif status == "OPEN":
                entry = safe_float(pos.get("entry_price", 0), 0)
                if entry <= 0:
                    continue
                pnl = _paper_pct_v258(entry, price)
                max_up = safe_float(pos.get("max_up_pct", pnl), pnl)
                if pnl <= V314_OPEN_FAST_LOSS_PCT and max_up < 0.40:
                    _paper_close_position_v258(pid, pos, price, "v314 к°•м ңк°җмӢң мӢӨнҢЁ л№ лҘём •лҰ¬", now_ts)
                    _v314_mark_queue_status(pid, "CLOSED", "v314 к°•м ңк°җмӢң мӢӨнҢЁ л№ лҘём •лҰ¬")
                    _v314_inc("open_fast_loss_cut", f"к°•м ңк°җмӢң л№ лҘёмҶҗм Ҳ {ticker}/{pnl:+.2f}%")
                    changed += 1
                    continue
                if max_up >= V314_OPEN_PROFIT_PROTECT_MAX_UP and pnl <= V314_OPEN_PROFIT_PROTECT_FLOOR:
                    _paper_close_position_v258(pid, pos, price, "v314 к°•м ңк°җмӢң мҲҳмқөліҙнҳё", now_ts)
                    _v314_mark_queue_status(pid, "CLOSED", "v314 к°•м ңк°җмӢң мҲҳмқөліҙнҳё")
                    _v314_inc("open_profit_protect", f"к°•м ңк°җмӢң мҲҳмқөліҙнҳё {ticker}/{pnl:+.2f}%")
                    changed += 1
                    continue
        return changed
    except Exception as e:
        try: append_runtime_error_log("v314_cleanup_forced_positions", str(e), exc=e, include_traceback=False)
        except Exception: pass
        return changed


try:
    _BASE_PAPER_UPDATE_POSITIONS_V314 = paper_update_positions_once_v258
except Exception:
    _BASE_PAPER_UPDATE_POSITIONS_V314 = None


def paper_update_positions_once_v258():
    try:
        _v314_prepare_forced_pending_once()
    except Exception as e:
        try: append_runtime_error_log("v314_pre_update", str(e), exc=e, include_traceback=False)
        except Exception: pass
    if callable(_BASE_PAPER_UPDATE_POSITIONS_V314):
        _BASE_PAPER_UPDATE_POSITIONS_V314()
    try:
        _v314_cleanup_forced_positions_once()
    except Exception as e:
        try: append_runtime_error_log("v314_post_update", str(e), exc=e, include_traceback=False)
        except Exception: pass


try:
    _BASE_V307_ROUTE_LABEL_V314 = _v307_paper_route_label
except Exception:
    _BASE_V307_ROUTE_LABEL_V314 = None


def _v307_paper_route_label(row: dict) -> str:
    try:
        row = row if isinstance(row, dict) else {}
        lane = str(row.get("lane", "") or "")
        reason = str(row.get("close_reason", "") or "") + " " + str(row.get("v314_route", "") or "")
        if "strong_return_v314" in lane or "strong_return" in reason:
            return "к°•н•ңлҶ“м№Ё ліөк·Җк°•н•Ё"
        if "v314_force_watch_dead" in reason:
            return "к°•м ңк°җмӢң л¬ҙл„Ҳм§җ мў…лЈҢ"
        if callable(_BASE_V307_ROUTE_LABEL_V314):
            return _BASE_V307_ROUTE_LABEL_V314(row)
        return "кё°нғҖ"
    except Exception:
        return "кё°нғҖ"


try:
    _BASE_BUILD_PAPER_STATS_V314 = build_paper_stats_text_v258
except Exception:
    _BASE_BUILD_PAPER_STATS_V314 = None


def build_paper_stats_text_v258() -> str:
    base = str(_BASE_BUILD_PAPER_STATS_V314()) if callable(_BASE_BUILD_PAPER_STATS_V314) else "рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats"
    try:
        rows = _paper_closed_logs_v258()
        since = [r for r in rows if safe_float(r.get("close_ts", 0), 0) >= V314_MODULE_LOAD_TS]
        sec = ["", "[v314 м Ғмҡ© мқҙнӣ„ м„ұкіј - ліөк·Җк°•н•Ё/мў…лЈҢм„ ]"]
        sec.append("- лӘ©н‘ң: к°•н•ңлҶ“м№Ё к°җмӢңлҠ” мӮҙлҰ¬лҗҳ, л¬ҙл„Ҳм§„ лҲҢлҰјк°җмӢңлҠ” л№ЁлҰ¬ мў…лЈҢн•ҙ 6мӢңк°„ мҲҳмқөлҘ мқ„ мҳ¬лҰ¬лҠ”м§Җ нҷ•мқё")
        if since:
            sec.append(_paper_stats_line_v258("v314 мқҙнӣ„", since))
            try:
                sec.extend(_v307_route_stats_section(since, title="v314 мқҙнӣ„ л¬ён„ұлі„"))
            except Exception:
                pass
        else:
            sec.append("- кұ°лһҳ: м—ҶмқҢ")
        if "[v314 м Ғмҡ© мқҙнӣ„ м„ұкіј" not in base:
            base += "\n" + "\n".join(sec)
        _v314_inc("paper_stats_rendered", "v314 м„ұкіјн‘ң м¶ңл Ҙ")
    except Exception as e:
        base += f"\n\n[v314 м„ұкіјн‘ң] н‘ңмӢң мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:120]}"
    return base




try:
    _BASE_V313_ACTIVE_QUEUE_ROWS_V314 = _v313_active_queue_rows
except Exception:
    _BASE_V313_ACTIVE_QUEUE_ROWS_V314 = None


def _v313_active_queue_rows(limit: int = 6) -> list:
    """v314: v313 queue м¶ңл Ҙм—җм„ң мқҙлҜё м·ЁмҶҢ/мў…лЈҢлҗң к°•м ңк°җмӢңлҠ” мҲЁкёҙлӢӨ."""
    try:
        rows = list(_BASE_V313_ACTIVE_QUEUE_ROWS_V314(limit=999) or []) if callable(_BASE_V313_ACTIVE_QUEUE_ROWS_V314) else []
        active = []
        for r in rows:
            if not isinstance(r, dict):
                continue
            st = str(r.get("status", "") or "").upper()
            if st in {"CANCELLED", "CLOSED", "DEAD", "EXPIRED", "STALE"}:
                continue
            active.append(r)
        return active[:max(1, int(limit))]
    except Exception:
        return []


def _v314_mark_queue_status(paper_pos_id: str, status: str, note: str = ""):
    try:
        if not paper_pos_id:
            return
        _v313_load_state()
        changed = False
        with V313_STATE_LOCK:
            for k, r in (V313_REENTRY_STATE or {}).items():
                if isinstance(r, dict) and str(r.get("paper_pos_id", "")) == str(paper_pos_id):
                    r["status"] = str(status or "CLOSED")
                    r["closed_ts"] = time.time()
                    if note:
                        r["close_note"] = str(note)[:180]
                    changed = True
        if changed:
            _v313_save_state()
    except Exception:
        pass


