def _v315_new_entry_pause_remaining_sec() -> int:
    try:
        return max(0, int(safe_float(V315_NEW_ENTRY_PAUSED_UNTIL, 0) - time.time()))
    except Exception:
        return 0


def v315_new_entry_paused() -> bool:
    return _v315_new_entry_pause_remaining_sec() > 0


def set_v315_new_entry_pause(enabled: bool, minutes: int = 30, reason: str = "manual"):
    global V315_NEW_ENTRY_PAUSED_UNTIL, V315_NEW_ENTRY_PAUSE_REASON
    try:
        if enabled:
            minutes = max(1, min(int(minutes), 360))
            V315_NEW_ENTRY_PAUSED_UNTIL = time.time() + minutes * 60
            V315_NEW_ENTRY_PAUSE_REASON = str(reason or "manual")[:180]
            _v315_inc("entry_pause_set", f"мӢ к·ңм§„мһ… мқјмӢңм •м§Җ {minutes}л¶„")
        else:
            V315_NEW_ENTRY_PAUSED_UNTIL = 0.0
            V315_NEW_ENTRY_PAUSE_REASON = ""
            _v315_inc("entry_pause_resume", "мӢ к·ңм§„мһ… мһ¬к°ң")
        try:
            save_runtime_settings()
        except Exception:
            pass
        return True
    except Exception:
        return False


