def _v315_balance_reconcile_check(full_balance: bool = False) -> tuple[bool, bool, str]:
    try:
        apos = active_positions if isinstance(active_positions, dict) else {}
        if not apos:
            return True, False, "ліҙмң  м—ҶмқҢ / мһ”кі лҢҖмЎ° кІҪлЎң нҶөкіј"
        if not full_balance:
            return True, True, f"ліҙмң  {len(apos)}к°ң / мӢӨмһ”кі  лҢҖмЎ°лҠ” /route_doctor fullм—җм„ңл§Ң мӢӨн–ү"
        checked = []
        warn = False
        for ticker, pos in list(apos.items())[:3]:
            t = str(ticker or "").upper().strip()
            expected_qty = safe_float((pos or {}).get("qty", 0), 0) if isinstance(pos, dict) else 0
            qty = get_balance(t)
            price = get_price(t)
            value = qty * price if qty > 0 and price > 0 else 0
            if expected_qty > 0 and qty <= 0:
                warn = True
            checked.append(f"{t} мһ”кі  {qty:.8f} / нҸүк°Җ {value:,.0f}мӣҗ")
        return True, warn, " / ".join(checked) if checked else "ліҙмң  мһҲмқҢ / нҷ•мқёлҢҖмғҒ м—ҶмқҢ"
    except Exception as e:
        return False, False, f"мһ”кі лҢҖмЎ° мӢӨнҢЁ: {e.__class__.__name__}: {str(e)[:120]}"


def _v315_run_route_doctor(full_balance: bool = False, auto: bool = False) -> dict:
    checks = []
    now_ts = time.time()
    try:
        compile_ok, compile_msg = _v315_compile_self_check()
        checks.append(_v315_check_item("мҪ”л“ң л¬ёлІ•/лІ„м „", compile_ok and ("v2.5.315" in BOT_VERSION or "v2.5.316" in BOT_VERSION), f"{BOT_VERSION} / {compile_msg}"))

        handler_ok = callable(globals().get("route_doctor_command")) and _v315_source_contains('CommandHandler("route_doctor"')
        checks.append(_v315_check_item("route_doctor м—°кІ°", handler_ok, "лӘ…л № н•ёл“Өлҹ¬ л“ұлЎқ нҷ•мқё" if handler_ok else "н•ёл“Өлҹ¬ л“ұлЎқ нҷ•мқё н•„мҡ”"))

        tmp_ok = False
        tmp_detail = ""
        try:
            fd, tmp_path = tempfile.mkstemp(prefix="v315_state_test_", suffix=".json", dir=BASE_DIR)
            os.close(fd)
            save_json_file(tmp_path, {"schema": V315_SCHEMA_VERSION, "ts": now_ts})
            ok, msg, data = _v315_read_json_quick(tmp_path)
            tmp_ok = bool(ok and isinstance(data, dict) and data.get("schema") == V315_SCHEMA_VERSION)
            tmp_detail = "мһ„мӢң м ҖмһҘ/мқҪкё° нҶөкіј" if tmp_ok else msg
            try: os.remove(tmp_path)
            except Exception: pass
        except Exception as e:
            tmp_detail = f"мһ„мӢң м ҖмһҘ мӢӨнҢЁ: {e.__class__.__name__}: {str(e)[:100]}"
        checks.append(_v315_check_item("мғҒнғңм ҖмһҘ н…ҢмҠӨнҠё", tmp_ok, tmp_detail))

        file_parts = []
        file_ok_all = True
        warn_files = False
        for label, path in [
            ("ліҙмң ", POSITIONS_FILE),
            ("л§ӨлҸ„лҢҖкё°", PENDING_SELLS_FILE),
            ("м§„мһ…лҢҖкё°", PENDING_BUYS_FILE),
            ("м„Өм •", RUNTIME_SETTINGS_FILE),
            ("paper", globals().get("PAPER_POSITIONS_FILE", data_file("paper_positions.json"))),
            ("reentry", globals().get("V313_REENTRY_FILE", data_file("paper_cancel_reentry_queue_v313.json"))),
        ]:
            ok, msg, _data = _v315_read_json_quick(path)
            file_ok_all = file_ok_all and bool(ok)
            # нҢҢмқј м—ҶмқҢмқҖ мІ« мӢӨн–ү/нҸ¬м§Җм…ҳ м—ҶмқҢмқҙл©ҙ м •мғҒмқј мҲҳ мһҲмңјлҜҖлЎң мЈјмқҳлЎң мҳ¬лҰ¬м§Җ м•ҠлҠ”лӢӨ.
            file_parts.append(f"{label}:{msg}")
        checks.append(_v315_check_item("л¶ҖнҢ…ліөкө¬ нҢҢмқј мқҪкё°", file_ok_all, " / ".join(file_parts)[:260], warn=warn_files))

        funcs = ["load_positions", "load_pending_sells", "load_pending_buys", "load_paper_state_v258", "recover_positions_from_exchange"]
        missing = [name for name in funcs if not callable(globals().get(name))]
        checks.append(_v315_check_item("л¶ҖнҢ…ліөкө¬ н•ЁмҲҳ", not missing, "н•„мҲҳ н•ЁмҲҳ нҶөкіј" if not missing else "лҲ„лқҪ: " + ", ".join(missing)))

        bal_ok, bal_warn, bal_msg = _v315_balance_reconcile_check(full_balance=full_balance)
        checks.append(_v315_check_item("кұ°лһҳмҶҢ мһ”кі  лҢҖмЎ°", bal_ok, bal_msg, warn=bal_warn))

        protect_ok = callable(globals().get("monitor_positions")) and callable(globals().get("check_pending_sells")) and callable(globals().get("save_positions"))
        protect_detail = f"мӢӨліҙмң  {len(active_positions) if isinstance(active_positions, dict) else 0} / pending_sell {len(pending_sells) if isinstance(pending_sells, dict) else 0}"
        checks.append(_v315_check_item("кё°мЎҙ ліҙмң  ліҙнҳёкҙҖлҰ¬", protect_ok, protect_detail))

        paper_ok = callable(globals().get("paper_update_positions_once_v258")) and callable(globals().get("paper_trade_worker_loop_v258"))
        paper_n = 0
        paper_pending = 0
        paper_open = 0
        try:
            pp = globals().get("paper_positions", {})
            if isinstance(pp, dict):
                paper_n = len(pp)
                paper_pending = sum(1 for p in pp.values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "PENDING")
                paper_open = sum(1 for p in pp.values() if isinstance(p, dict) and str(p.get("status", "")).upper() == "OPEN")
        except Exception:
            pass
        checks.append(_v315_check_item("paper worker м—°кІ°", paper_ok, f"paper м „мІҙ {paper_n} / PENDING {paper_pending} / OPEN {paper_open}"))

        reentry_ok = callable(globals().get("force_cancel_reentry_queue_v313")) and callable(globals().get("_v314_prepare_forced_pending_once"))
        checks.append(_v315_check_item("к°•н•ңлҶ“м№Ё ліөк·Җ кІҪлЎң", reentry_ok, "v313 reentry вҶ’ v314 ліөк·Җк°•н•Ё/мў…лЈҢм„  кІҪлЎң нҷ•мқё" if reentry_ok else "reentry/paper м—°кІ° нҷ•мқё н•„мҡ”"))

        pause_ok = callable(globals().get("set_v315_new_entry_pause")) and callable(globals().get("process_pending_buy_promotions")) and callable(globals().get("scan_and_auto_trade"))
        rem = _v315_new_entry_pause_remaining_sec()
        pause_detail = "нҳ„мһ¬ мқјмӢңм •м§Җ м•„лӢҳ" if rem <= 0 else f"нҳ„мһ¬ мӢ к·ңм§„мһ… м •м§Җ мӨ‘ {format_elapsed_text(rem)} лӮЁмқҢ / мӮ¬мң  {V315_NEW_ENTRY_PAUSE_REASON}"
        checks.append(_v315_check_item("мӢ к·ңм§„мһ… мқјмӢңм •м§Җ", pause_ok, pause_detail))

        err_text = read_runtime_error_log_current_boot(max_lines=30) if callable(globals().get("read_runtime_error_log_current_boot")) else ""
        err_ok = not bool(str(err_text or "").strip())
        checks.append(_v315_check_item("нҳ„мһ¬л¶ҖнҢ… мҳӨлҘҳлЎңк·ё", err_ok, "нҳ„мһ¬ л¶ҖнҢ… мқҙнӣ„ мғҲ мҳӨлҘҳ м—ҶмқҢ" if err_ok else "нҳ„мһ¬ л¶ҖнҢ… мҳӨлҘҳ мһҲмқҢ: /errorlog нҷ•мқё", warn=not err_ok))

    except Exception as e:
        checks.append(_v315_check_item("route_doctor мһҗмІҙ", False, f"мһҗк°ҖкІҖмӮ¬ мһҗмІҙ мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:160]}"))

    hard_fail = any((not c.get("ok")) for c in checks)
    warn = any(bool(c.get("warn")) for c in checks)
    result = {
        "schema": V315_SCHEMA_VERSION,
        "bot_version": BOT_VERSION,
        "checked_ts": now_ts,
        "checked_text": format_ts_mdhm(now_ts),
        "auto": bool(auto),
        "full_balance": bool(full_balance),
        "ok": not hard_fail,
        "warn": bool(warn),
        "checks": checks,
        "summary": "нҶөкіј" if (not hard_fail and not warn) else ("мЈјмқҳ" if not hard_fail else "мӢӨнҢЁ"),
    }
    _v315_save_guard_state(result)
    if auto:
        _v315_inc("auto_doctor_run", result["summary"])
    else:
        _v315_inc("manual_doctor_run", result["summary"])
    if result["ok"] and not result["warn"]:
        _v315_inc("doctor_pass", "route_doctor нҶөкіј")
    else:
        _v315_inc("doctor_warn", "route_doctor мЈјмқҳ/мӢӨнҢЁ")
    return result


def _v315_format_route_doctor_result(result: dict) -> str:
    result = result if isinstance(result, dict) else {}
    checks = result.get("checks", []) if isinstance(result.get("checks", []), list) else []
    summary = str(result.get("summary", "лҢҖкё°") or "лҢҖкё°")
    lines = [
        "рҹ§Ә кІҪлЎң мһҗк°ҖкІҖмӮ¬ /route_doctor",
        "",
        f"- лІ„м „: {result.get('bot_version', BOT_VERSION)}",
        f"- кІҖмӮ¬мӢңк°Ғ: {result.get('checked_text', format_ts_mdhm(time.time()))}",
        f"- мў…н•©: {summary}",
        "",
    ]
    for idx, c in enumerate(checks, start=1):
        ok = bool(c.get("ok"))
        warn = bool(c.get("warn"))
        mark = "вң…" if ok and not warn else ("вҡ пёҸ" if ok and warn else "вқҢ")
        name = str(c.get("name", "кІҖмӮ¬"))
        detail = str(c.get("detail", "") or "")
        lines.append(f"{idx}. {mark} {name}: {_v315_status_word(ok, warn)}")
        if detail:
            lines.append(f"   - {detail}")
    lines.append("")
    if result.get("ok") and not result.get("warn"):
        lines.append("кІ°лЎ : м—…лҚ°мқҙнҠён•ҙлҸ„ кё°мЎҙ нҸ¬м§Җм…ҳ кҙҖлҰ¬к°Җ лҒҠкё°м§Җ м•ҠлҠ” мғҒнғңлЎң ліҙмһ„")
    elif result.get("ok"):
        lines.append("кІ°лЎ : нҒ° мӢӨнҢЁлҠ” м—Ҷм§Җл§Ң мЈјмқҳ н•ӯлӘ©мқҙ мһҲмқҢ. м„ёл¶Җ н•ӯлӘ© лЁјм Җ нҷ•мқё")
    else:
        lines.append("кІ°лЎ : мӢӨнҢЁ н•ӯлӘ© мһҲмқҢ. мӢ к·ңм§„мһ…мқҖ л§үкі  мӣҗмқёл¶Җн„° нҷ•мқё")
    lines.append("")
    lines.append("- мӢӨмһ”кі к№Ңм§Җ м§Ғм ‘ лҢҖмЎ°н•ҳл Өл©ҙ /route_doctor full")
    lines.append("- мӢ к·ңм§„мһ…л§Ң л§үмңјл Өл©ҙ /entry_pause 30")
    lines.append("- мӢ к·ңм§„мһ… мһ¬к°ңлҠ” /entry_resume")
    return "\n".join(lines)


def route_doctor_command(update, context: CallbackContext):
    try:
        args = [str(x).lower().strip() for x in list(getattr(context, "args", []) or [])]
        full = any(x in {"full", "balance", "мһ”кі ", "м „мІҙ"} for x in args)
        result = _v315_run_route_doctor(full_balance=full, auto=False)
        send_text_chunks(_v315_format_route_doctor_result(result), limit=3200)
    except Exception as e:
        log_exception_details("route_doctor_command", e, prefix="[route_doctor мҳӨлҘҳ]")
        send(f"рҹ§Ә /route_doctor мӢӨн–ү мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:160]}")


def entry_pause_command_v315(update, context: CallbackContext):
    try:
        args = list(getattr(context, "args", []) or [])
        minutes = 30
        if args:
            minutes = int(safe_float(args[0], 30))
        minutes = max(1, min(minutes, 360))
        set_v315_new_entry_pause(True, minutes=minutes, reason="manual_command")
        send(f"рҹӣЎ мӢ к·ңм§„мһ…л§Ң {minutes}л¶„ мқјмӢңм •м§Җ\n- кё°мЎҙ ліҙмң /л§ӨлҸ„/мҶҗм Ҳ к°җмӢңлҠ” кі„мҶҚ мң м§Җ")
    except Exception as e:
        send(f"рҹӣЎ мӢ к·ңм§„мһ… мқјмӢңм •м§Җ мӢӨнҢЁ: {e.__class__.__name__}: {str(e)[:120]}")


def entry_resume_command_v315(update, context: CallbackContext):
    set_v315_new_entry_pause(False)
    send("рҹҹў мӢ к·ңм§„мһ… мқјмӢңм •м§Җ н•ҙм ң\n- мһҗлҸҷл§ӨмҲҳ мһҗмІҙлҠ” кё°мЎҙ м„Өм •мқ„ л”°лҰ„")


def v315_auto_route_doctor_worker():
    try:
        time.sleep(max(1, int(V315_ROUTE_DOCTOR_AUTO_DELAY_SEC)))
        result = _v315_run_route_doctor(full_balance=False, auto=True)
        # нҶөкіјлҠ” мЎ°мҡ©нһҲ м ҖмһҘл§Ң н•ңлӢӨ. мӢӨнҢЁ/мЈјмқҳл§Ң м•Ңл Өм„ң мұ„нҢ…мқ„ м–ҙм§ҖлҹҪнһҲм§Җ м•ҠлҠ”лӢӨ.
        if not result.get("ok") or result.get("warn"):
            txt = _v315_format_route_doctor_result(result)
            send_text_chunks("рҹӣЎ v315 м—…лҚ°мқҙнҠё м•Ҳм „кІҖмӮ¬ мЈјмқҳ\n\n" + txt, limit=3000)
    except Exception as e:
        try: append_runtime_error_log("v315_auto_route_doctor_worker", str(e), exc=e, include_traceback=False)
        except Exception: pass


