def _v315_cache_status_lines() -> list:
    state = _v315_load_guard_state()
    checked_ts = safe_float(state.get("checked_ts", 0), 0)
    age_text = "м•„м§Ғ м—ҶмқҢ" if checked_ts <= 0 else format_elapsed_text(time.time() - checked_ts) + " м „"
    summary = str(state.get("summary", "лҢҖкё°") or "лҢҖкё°")
    checks = state.get("checks", []) if isinstance(state.get("checks", []), list) else []
    def _one(name):
        for c in checks:
            if str(c.get("name", "")) == name:
                return _v315_status_word(bool(c.get("ok")), bool(c.get("warn")))
        return "лҢҖкё°"
    rem = _v315_new_entry_pause_remaining_sec()
    pause_text = "к°ҖлҠҘ / нҳ„мһ¬ кәјм§җ" if rem <= 0 else f"мһ‘лҸҷмӨ‘ {format_elapsed_text(rem)} лӮЁмқҢ"
    return [
        "рҹӣЎ v315 м—…лҚ°мқҙнҠё м•Ҳм „мһҘм№ҳ",
        f"- мөңк·ј route_doctor: {summary} / {age_text}",
        f"- мғҒнғңм ҖмһҘ: {_one('мғҒнғңм ҖмһҘ н…ҢмҠӨнҠё')}",
        f"- л¶ҖнҢ…ліөкө¬: нҢҢмқј {_one('л¶ҖнҢ…ліөкө¬ нҢҢмқј мқҪкё°')} / н•ЁмҲҳ {_one('л¶ҖнҢ…ліөкө¬ н•ЁмҲҳ')}",
        f"- мһ”кі лҢҖмЎ°: {_one('кұ°лһҳмҶҢ мһ”кі  лҢҖмЎ°')}",
        f"- кё°мЎҙліҙмң  ліҙнҳёкҙҖлҰ¬: {_one('кё°мЎҙ ліҙмң  ліҙнҳёкҙҖлҰ¬')}",
        f"- мӢ к·ңм§„мһ… мқјмӢңм •м§Җ: {pause_text}",
        f"- м°ЁлӢЁнҡҹмҲҳ: мӢ к·ңм§„мһ… {V315_STATS.get('new_entry_blocked',0)} / мөңк·ј: {V315_STATS.get('last_note','лҢҖкё°')}",
    ]


