# v2.5.316: route_doctor мӢӨм—°кІ° + нӣ„ліҙн’Ҳм§Ҳ м§„лӢЁ
# мң„м№ҳ: м¶ңл Ҙ + batch лқјмҡ°нҢ… + лӘ…л № н•ёл“Өлҹ¬ + paper/trace н’Ҳм§Ҳ м§„лӢЁ
# н•өмӢ¬:
# - v315 м•Ҳм „мһҘм№ҳк°Җ лӮҙл¶Җ мһҗк°ҖкІҖмӮ¬л§Ң нҶөкіјн•ҳкі  мӢӨм ң н…”л Ҳк·ёлһЁ лӘ…л №мқҙ л¬ҙмқ‘лӢөмқё мғҒнҷ©мқ„ мһЎлҠ”лӢӨ.
# - /batch м•Ҳм—җм„ңлҸ„ /route_doctorлҘј мӢӨн–үн•  мҲҳ мһҲкІҢ н•ңлӢӨ.
# - нӣ„ліҙн’Ҳм§Ҳмқ„ ліҙм§Җ лӘ»н•ҳлҠ” л¬ём ңлҘј мӨ„мқҙкё° мң„н•ҙ мғҲ API/OHLCV м—Ҷмқҙ paper лЎңк·ё кё°мӨҖ н’Ҳм§Ҳ м§„лӢЁмқ„ л§Ңл“ лӢӨ.
# - м „лһө мЎ°кұҙ м „мІҙ к°•нҷ”к°Җ м•„лӢҲлқј, мҶҗмӢӨ/м·ЁмҶҢ/к°•н•ңлҶ“м№Ё/ліөк·Җк°•н•Ё лҜём „нҷҳ мӣҗмқёмқ„ лЁјм Җ ліҙмқҙкІҢ н•ңлӢӨ.
# =========================================================
V316_SCHEMA_VERSION = "route_quality_guard_v316"
V316_MODULE_LOAD_TS = time.time()
V316_STATS = {
    "manual_route_command": 0,
    "manual_route_fallback": 0,
    "batch_route_doctor": 0,
    "quality_command": 0,
    "quality_batch": 0,
    "cache_status_rendered": 0,
    "paper_stats_quality_rendered": 0,
    "last_route_ts": 0.0,
    "last_quality_ts": 0.0,
    "last_note": "лҢҖкё°",
}


def _v316_inc(key: str, note: str = ""):
    try:
        if key in V316_STATS:
            V316_STATS[key] = int(safe_float(V316_STATS.get(key, 0), 0)) + 1
        if key == "manual_route_command":
            V316_STATS["last_route_ts"] = time.time()
        if key in {"quality_command", "quality_batch"}:
            V316_STATS["last_quality_ts"] = time.time()
        if note:
            V316_STATS["last_note"] = str(note)[:260]
    except Exception:
        pass


def _v316_status_age(ts: float) -> str:
    try:
        ts = safe_float(ts, 0)
        if ts <= 0:
            return "м•„м§Ғ м—ҶмқҢ"
        return format_elapsed_text(max(0, time.time() - ts)) + " м „"
    except Exception:
        return "нҷ•мқё м•Ҳ лҗЁ"


def _v316_rows_recent(hours: float = 6.0, include_cancelled: bool = True) -> list:
    try:
        rows = _paper_closed_logs_v258(include_cancelled=include_cancelled) if '_paper_closed_logs_v258' in globals() else []
        start = time.time() - max(0.5, float(hours)) * 3600.0
        out = []
        for r in rows:
            if not isinstance(r, dict):
                continue
            ts = safe_float(r.get("close_ts", r.get("cancel_ts", r.get("created_ts", 0))), 0)
            if ts >= start:
                out.append(dict(r))
        return out
    except Exception:
        return []


def _v316_easy_lane(row: dict) -> str:
    try:
        raw = str((row or {}).get("lane", (row or {}).get("trigger", (row or {}).get("entry_rule", ""))) or "")
        if '_paper_v301_easy_lane' in globals():
            txt = str(_paper_v301_easy_lane(raw))
            if txt and txt != raw:
                return txt
        if "strong_return_v314" in raw or str((row or {}).get("v314_route", "")) == "strong_return_breakout":
            return "v314 ліөк·Җк°•н•Ё"
        if "cancel_reentry_forced_v313_breakout" in raw:
            return "к°•н•ңлҶ“м№Ё ліөк·Җк°җмӢң"
        if "cancel_reentry_forced_v313_pullback" in raw:
            return "к°•н•ңлҶ“м№Ё лҲҢлҰјк°җмӢң"
        if str((row or {}).get("entry_rule", "")) == "breakout":
            return "лҸҢнҢҢлҢҖкё°"
        if str((row or {}).get("entry_rule", "")) == "pullback":
            return "лҲҢлҰј/мӨҖл№„лҢҖкё°"
        if str((row or {}).get("entry_rule", "")) == "now":
            return "л°”лЎңм§„мһ…нҳ•"
        return raw or "л¶„лҘҳм—ҶмқҢ"
    except Exception:
        return "л¶„лҘҳмҳӨлҘҳ"


def _v316_quality_stats(hours: float = 6.0) -> dict:
    rows = _v316_rows_recent(hours=hours, include_cancelled=True)
    closed = [r for r in rows if str(r.get("status", "")).upper() == "CLOSED"]
    cancelled = [r for r in rows if str(r.get("status", "")).upper() == "CANCELLED"]
    wins = [safe_float(r.get("pnl_pct", 0), 0) for r in closed if safe_float(r.get("pnl_pct", 0), 0) > 0]
    losses = [safe_float(r.get("pnl_pct", 0), 0) for r in closed if safe_float(r.get("pnl_pct", 0), 0) < 0]
    total = sum(safe_float(r.get("pnl_pct", 0), 0) for r in closed)
    pf = (sum(wins) / abs(sum(losses))) if losses and abs(sum(losses)) > 0 else (999.0 if wins else 0.0)
    cancel_reason = {}
    for r in cancelled:
        reason = str(r.get("close_reason", r.get("cancel_reason", "м·ЁмҶҢмӮ¬мң  м—ҶмқҢ")) or "м·ЁмҶҢмӮ¬мң  м—ҶмқҢ")
        cancel_reason[reason] = cancel_reason.get(reason, 0) + 1
    lane_stats = {}
    for r in closed:
        lane = _v316_easy_lane(r)
        st = lane_stats.setdefault(lane, {"n": 0, "wins": 0, "losses": 0, "pnl": 0.0})
        pnl = safe_float(r.get("pnl_pct", 0), 0)
        st["n"] += 1
        st["pnl"] += pnl
        if pnl > 0:
            st["wins"] += 1
        elif pnl < 0:
            st["losses"] += 1
    missed = []
    for r in cancelled:
        best = safe_float(r.get("max_up_after_cancel_pct", r.get("cancel_watch_max_up_pct", r.get("max_up_pct", 0))), 0)
        cur = safe_float(r.get("current_after_cancel_pct", r.get("last_up_pct", 0)), 0)
        if best >= 0.70:
            missed.append((best, cur, str(r.get("ticker", "?")), str(r.get("close_reason", ""))))
    missed.sort(reverse=True, key=lambda x: x[0])
    active_pending = []
    strong_mismatch = []
    try:
        with PAPER_STATE_LOCK:
            pos_rows = [dict(p) for p in (paper_positions or {}).values() if isinstance(p, dict)]
        for p in pos_rows:
            status = str(p.get("status", "")).upper()
            if status == "PENDING":
                active_pending.append(p)
                lane = str(p.get("lane", "") or "")
                route = str(p.get("v314_route", "") or "")
                if ("strong_return" in lane or route == "strong_return_breakout") and str(p.get("entry_rule", "")) != "breakout":
                    strong_mismatch.append(p)
    except Exception:
        pass
    return {
        "hours": hours,
        "rows": rows,
        "closed": closed,
        "cancelled": cancelled,
        "wins": wins,
        "losses": losses,
        "total": total,
        "pf": pf,
        "cancel_reason": cancel_reason,
        "lane_stats": lane_stats,
        "missed": missed,
        "active_pending": active_pending,
        "strong_mismatch": strong_mismatch,
    }


def build_quality_check_text_v316(full: bool = False, hours: float = 6.0) -> str:
    try:
        q = _v316_quality_stats(hours=hours)
        closed = q.get("closed", [])
        cancelled = q.get("cancelled", [])
        wins = q.get("wins", [])
        losses = q.get("losses", [])
        n = len(closed)
        win_rate = (len(wins) / n * 100.0) if n else 0.0
        pf = safe_float(q.get("pf", 0), 0)
        total = safe_float(q.get("total", 0), 0)
        lines = [
            "рҹ§Ә нӣ„ліҙн’Ҳм§Ҳ м§„лӢЁ /quality_check",
            f"- кё°мӨҖ: мөңк·ј {hours:g}мӢңк°„ / мғҲ APIВ·OHLCV нҳём¶ң м—ҶмқҢ / paper м ҖмһҘк°’л§Ң мӮ¬мҡ©",
            f"- лӘЁмқҳмІӯмӮ°: {n}м „ {len(wins)}мҠ№ {len(losses)}нҢЁ / мҠ№лҘ  {win_rate:.1f}% / лҲ„м Ғ {total:+.2f}% / PF {pf:.2f}",
            f"- м§„мһ…м·ЁмҶҢ: {len(cancelled)}к°ң / нҳ„мһ¬лҢҖкё° {len(q.get('active_pending', []))}к°ң",
        ]
        if n == 0 and not cancelled:
            lines.append("- м•„м§Ғ нҢҗлӢЁн•  paper н‘ңліёмқҙ м—ҶмқҢ")
        # нӣ„ліҙн’Ҳм§Ҳ кІ°лЎ 
        if n >= 3 and (total < 0 or pf < 1.0):
            lines.append("- кІ°лЎ : нӣ„ліҙн’Ҳм§Ҳ мҲҳм • н•„мҡ”. м§ҖкёҲмқҖ мўӢмқҖ нӣ„ліҙлҘј кі лҘҙлҠ” лӢЁкі„ліҙлӢӨ м§„мһ… м „ м·ЁмҶҢ/л¬ён„ұ л¶„лҰ¬к°Җ лЁјм Җ л¬ём ңлЎң ліҙмһ„")
        elif n >= 3 and pf >= 1.3:
            lines.append("- кІ°лЎ : мөңк·ј н‘ңліёмқҖ лӮҳмҒҳм§Җ м•ҠмқҢ. мЎ°кұҙмқ„ лҚ” мЎ°мқҙкё°ліҙлӢӨ лҶ“м№ң нӣ„ліҙ/м·ЁмҶҢ нӣ„ мғҒмҠ№мқ„ мҡ°м„  нҷ•мқё")
        else:
            lines.append("- кІ°лЎ : н‘ңліёмқҙ м Ғм–ҙм„ң лӢЁм • кёҲм§Җ. к·ёлһҳлҸ„ м·ЁмҶҢ нӣ„ к°•н•ң лҶ“м№Ёкіј лҢҖкё° мӨ‘ мӢ нҳём•…нҷ”лҠ” кі„мҶҚ лҙҗм•ј н•Ё")
        # м·ЁмҶҢ мӣҗмқё TOP
        cr = sorted(q.get("cancel_reason", {}).items(), key=lambda x: x[1], reverse=True)[:5]
        lines.append("")
        lines.append("рҹ§Ҝ м·ЁмҶҢ мӣҗмқё TOP")
        if cr:
            for i, (reason, cnt) in enumerate(cr, 1):
                lines.append(f"{i}. {reason[:90]}: {cnt}нҡҢ")
        else:
            lines.append("- мөңк·ј м·ЁмҶҢ м—ҶмқҢ")
        # lane stats
        lane_stats = sorted(q.get("lane_stats", {}).items(), key=lambda kv: abs(safe_float(kv[1].get('pnl',0),0)), reverse=True)[:6]
        lines.append("")
        lines.append("рҹ“Ҡ л¬ён„ұлі„ нӣ„ліҙн’Ҳм§Ҳ")
        if lane_stats:
            for lane, st in lane_stats:
                n2 = int(st.get("n", 0)); w = int(st.get("wins", 0)); l = int(st.get("losses", 0)); pnl = safe_float(st.get("pnl", 0), 0)
                wr = (w / n2 * 100.0) if n2 else 0.0
                lines.append(f"- {lane}: {n2}м „ {w}мҠ№ {l}нҢЁ / мҠ№лҘ  {wr:.0f}% / лҲ„м Ғ {pnl:+.2f}%")
        else:
            lines.append("- мөңк·ј мІӯмӮ° н‘ңліё м—ҶмқҢ")
        # missed suspects
        missed = q.get("missed", [])[:5 if full else 3]
        lines.append("")
        lines.append("рҹҡЁ м·ЁмҶҢ нӣ„ лҶ“м№Ё мқҳмӢ¬")
        if missed:
            for i, (best, cur, ticker, reason) in enumerate(missed, 1):
                lines.append(f"{i}. {ticker} / м·ЁмҶҢ нӣ„ мөңкі  {best:+.2f}% / нҳ„мһ¬ {cur:+.2f}% / мӣҗмқё {reason[:70]}")
        else:
            lines.append("- мөңк·ј к°•н•ң лҶ“м№Ё мқҳмӢ¬ м—ҶмқҢ")
        # v314 mismatch / active pending
        mismatch = q.get("strong_mismatch", [])
        lines.append("")
        lines.append("рҹ§І v314 ліөк·Җк°•н•Ё м—°кІ° нҷ•мқё")
        if mismatch:
            lines.append(f"- мЈјмқҳ: ліөк·Җк°•н•Ё н‘ңмӢңмқёлҚ° entry_ruleмқҙ breakoutмқҙ м•„лӢҢ лҢҖкё° {len(mismatch)}к°ң")
            for p in mismatch[:3]:
                lines.append(f"  В· {str(p.get('ticker','?')).upper()} / rule {p.get('entry_rule','?')} / lane {str(p.get('lane',''))[:70]}")
        else:
            lines.append("- ліөк·Җк°•н•Ё н‘ңмӢңмҷҖ breakout лҢҖкё° л¶Ҳмқјм№ҳ м—ҶмқҢ")
        if full:
            lines.append("")
            lines.append("вҸі нҳ„мһ¬ м§„мһ…лҢҖкё°")
            active = q.get("active_pending", [])[:10]
            if active:
                for p in active:
                    age = format_elapsed_text(max(0, time.time() - safe_float(p.get('created_ts', 0), 0))) if safe_float(p.get('created_ts', 0), 0) > 0 else "лӮҳмқҙ нҷ•мқёл¶Ҳк°Җ"
                    lines.append(f"- {str(p.get('ticker','?')).upper()} / {_v316_easy_lane(p)} / rule {p.get('entry_rule','?')} / {age} м „ / мӮ¬мң  {str(p.get('register_reason',''))[:80]}")
            else:
                lines.append("- нҳ„мһ¬ м§„мһ…лҢҖкё° м—ҶмқҢ")
        lines.append("")
        lines.append("лӢӨмқҢ нҢҗлӢЁ: /paper_flow_full лҳҗлҠ” /review_trace_detail мҪ”мқёлӘ…мңјлЎң мӣҗмқё нҷ•мқё")
        return "\n".join(lines)
    except Exception as e:
        return f"рҹ§Ә нӣ„ліҙн’Ҳм§Ҳ м§„лӢЁ мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:160]}"


