def route_doctor_command(update, context: CallbackContext):
    try:
        _v316_inc("manual_route_command", "route_doctor м§Ғм ‘ мӢӨн–ү")
        args = [str(x).lower().strip() for x in list(getattr(context, "args", []) or [])]
        full = any(x in {"full", "balance", "мһ”кі ", "м „мІҙ"} for x in args)
        # мӮ¬мҡ©мһҗк°Җ лҲҢл ҖлҠ”лҚ° мЎ°мҡ©н•ҳл©ҙ л¶Ҳм•Ҳн•ҳлҜҖлЎң мӢңмһ‘ л©”мӢңм§ҖлҘј лЁјм Җ ліҙлӮёлӢӨ.
        try:
            send("рҹ§Ә /route_doctor кІҖмӮ¬ мӢңмһ‘\n- м ҖмһҘмғҒнғң/л¶ҖнҢ…ліөкө¬/нҸ¬м§Җм…ҳ ліҙнҳё/worker м—°кІ°мқ„ нҷ•мқё мӨ‘")
        except Exception:
            pass
        result = _v315_run_route_doctor(full_balance=full, auto=False)
        txt = _v315_format_route_doctor_result(result)
        # v316м—җм„ң мӢӨм ң лӘ…л №/л°°м№ҳ м—°кІ° мғҒнғңлҘј кІ°кіјм—җ лҚ§л¶ҷмқёлӢӨ.
        extra = [
            "",
            "рҹ§© v316 лӘ…л № м—°кІ° нҷ•мқё",
            "- м§Ғм ‘ /route_doctor: мӢӨн–үлҗЁ",
            "- /batch /route_doctor: м§ҖмӣҗлҗЁ",
            "- л¬ҙмқ‘лӢө л°©м§Җ: кІҖмӮ¬ мӢңмһ‘ л©”мӢңм§Җ лЁјм Җ м „мҶЎ",
        ]
        send_text_chunks(txt.rstrip() + "\n" + "\n".join(extra), limit=3400)
    except Exception as e:
        log_exception_details("route_doctor_command_v316", e, prefix="[route_doctor мҳӨлҘҳ]")
        send(f"рҹ§Ә /route_doctor мӢӨн–ү мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:160]}")


