        _v316_inc("quality_command", "нӣ„ліҙн’Ҳм§Ҳ м§„лӢЁ м§Ғм ‘ мӢӨн–ү")
        args = [str(x).lower().strip() for x in list(getattr(context, "args", []) or [])]
        full = any(x in {"full", "м „мІҙ", "detail", "мғҒм„ё"} for x in args)
