# v316: batch лқјмҡ°нҢ… ліҙк°•. route_doctor/quality_checkлҠ” м ҖмһҘк°’л§Ң мқҪмңјлҜҖлЎң batch н—Ҳмҡ©.
try:
    _BASE_EXECUTE_SINGLE_BATCH_V316 = _execute_single_batch_command
except Exception:
    _BASE_EXECUTE_SINGLE_BATCH_V316 = None


def _execute_single_batch_command(cmd: str, args: list, idx: int, total: int):
    cmd_l = str(cmd or "").lower().strip().lstrip('/')
    args = list(args or [])
    shown_cmd = f"/{cmd_l}" + (" " + " ".join([str(a) for a in args]) if args else "")
    label = f"в–¶пёҸ л¬¶мқҢ {idx}/{total} {shown_cmd}" if total > 1 else f"в–¶пёҸ {shown_cmd}"
    if cmd_l in {"route_doctor", "doctor"}:
        _v316_inc("batch_route_doctor", "batch route_doctor")
        full = any(str(x).lower().strip() in {"full", "balance", "мһ”кі ", "м „мІҙ"} for x in args)
        result = _v315_run_route_doctor(full_balance=full, auto=False)
        send_text_chunks(_v315_format_route_doctor_result(result), prefix=label, limit=3400)
        return
    if cmd_l in {"quality_check", "quality", "candidate_quality"}:
        _v316_inc("quality_batch", "batch quality_check")
        full = any(str(x).lower().strip() in {"full", "м „мІҙ", "detail", "мғҒм„ё"} for x in args)
        hours = 6.0
        for x in args:
            sx = str(x).lower().strip()
            try:
                if sx.endswith('h'):
                    hours = float(sx[:-1])
                elif sx.replace('.', '', 1).isdigit():
                    hours = float(sx)
            except Exception:
                pass
        hours = max(1.0, min(hours, 24.0))
        send_text_chunks(build_quality_check_text_v316(full=full, hours=hours), prefix=label, limit=TG_MESSAGE_SOFT_LIMIT)
        return
    if callable(_BASE_EXECUTE_SINGLE_BATCH_V316):
        return _BASE_EXECUTE_SINGLE_BATCH_V316(cmd, args, idx, total)
    send(f"{label}\n- batch мІҳлҰ¬ мӣҗліё н•ЁмҲҳлҘј м°ҫм§Җ лӘ»н–Ҳм–ҙ")


