            BotCommand("paper_flow", "лӘЁмқҳл§ӨмҲҳ нқҗлҰ„"),
            BotCommand("route_doctor", "м—…лҚ°мқҙнҠё м•Ҳм „кІҖмӮ¬"),
            BotCommand("paper_recent", "мөңк·ј лӘЁмқҳл§Өл§Ө"),
            BotCommand("work_check", "мқјн•  л•Ң м••м¶• м җкІҖ"),
            BotCommand("rank_short", "м „лһө мҲңмң„ м§§кІҢ"),
            BotCommand("review_watch", "лӮҙл¶Җк°җмӢң м§§кІҢ"),
            BotCommand("cache_status", "лӘ…л №м–ҙ мәҗмӢң мғҒнғң"),
            BotCommand("batch", "м—¬лҹ¬ лӘ…л №м–ҙ л¬¶мқҢ мӢӨн–ү"),
            BotCommand("review_sample", "мҳӨлҠҳ кІҖмҰқ н‘ңліё"),
