        closed_n = len(q.get("closed", [])); cancel_n = len(q.get("cancelled", [])); missed_n = len(q.get("missed_grouped_v317", []))
        total = safe_float(q.get("total", 0), 0); pf = safe_float(q.get("pf", 0), 0)
