def build_paper_stats_text_v258() -> str:
    base = str(_BASE_BUILD_PAPER_STATS_V317()) if callable(_BASE_BUILD_PAPER_STATS_V317) else "рҹ“Ҡ лӘЁмқҳл§Өл§Ө м„ұкіј /paper_stats"
    try:
        rows = _paper_closed_logs_v258(include_cancelled=False) if callable(globals().get("_paper_closed_logs_v258")) else []
        since = []
        for r in rows:
            if not isinstance(r, dict):
                continue
            # v317л¶Җн„°лҠ” version_tagк°Җ мһҲмңјл©ҙ к·ёкІғмқ„ мҡ°м„  мӮ¬мҡ©н•ҳкі , м—Ҷмңјл©ҙ нҳ„мһ¬ мһ¬мӢңмһ‘ мқҙнӣ„ н‘ңліёл§Ң ліҙмЎ°лЎң ліёлӢӨ.
            tag = str(r.get("version_tag", r.get("bot_version_at_close", "")) or "")
            ts = safe_float(r.get("close_ts", 0), 0)
            if "v2.5.317" in tag or ts >= V317_MODULE_LOAD_TS:
                since.append(r)
        sec = ["", "[v317 м Ғмҡ© мқҙнӣ„ м„ұкіј - early м·ЁмҶҢ мһ¬к°җмӢң/нӣ„ліҙн’Ҳм§Ҳ]"]
        sec.append("- лӘ©н‘ң: мўӢмқҖ нӣ„ліҙлҘј early_pending_cancelм—җм„ң л°”лЎң мЈҪмқҙм§Җ м•Ҡкі  н•ң лІҲмқҖ лҲҢлҰј/ліөк·Җ мһ¬к°җмӢңлЎң лӮЁкё°лҠ”м§Җ нҷ•мқё")
        if since:
            sec.append(_paper_stats_line_v258("v317 мқҙнӣ„", since))
            try:
                sec.extend(_v307_route_stats_section(since, title="v317 мқҙнӣ„ л¬ён„ұлі„"))
            except Exception:
                pass
        else:
            sec.append("- кұ°лһҳ: м—ҶмқҢ / v317 м Ғмҡ© нӣ„ мғҲ мІӯмӮ°мқҙ мҢ“мқҙл©ҙ н‘ңмӢң")
        sec.append(f"- мһ¬к°җмӢң м „нҷҳ: лҲҢлҰј {V317_STATS.get('reroute_to_pullback',0)} / ліөк·Җ {V317_STATS.get('reroute_to_breakout',0)}")
        sec.append(f"- м„ёл¶Җмӣҗмқё/мӨ‘ліөлҶ“м№ЁмқҖ /quality_check fullм—җм„ң нҷ•мқё")
        if "[v317 м Ғмҡ© мқҙнӣ„ м„ұкіј" not in base:
            base += "\n" + "\n".join(sec)
        _v317_inc("paper_stats_rendered", "paper_stats v317 н‘ңмӢң")
    except Exception as e:
        base += f"\n\n[v317 м„ұкіјн‘ң] н‘ңмӢң мҳӨлҘҳ: {e.__class__.__name__}: {str(e)[:120]}"
    return base


