def v315_auto_route_doctor_worker():
    try:
        time.sleep(V315_ROUTE_DOCTOR_AUTO_DELAY_SEC)
        result = _v315_run_route_doctor(full_balance=False, auto=True)
        if (not result.get("ok")) or result.get("warn"):
            txt = _v315_format_route_doctor_result(result)
            send_text_chunks("рҹӣЎ v318 м—…лҚ°мқҙнҠё м•Ҳм „кІҖмӮ¬ мЈјмқҳ\n\n" + txt, limit=3200)
    except Exception as e:
        try: append_runtime_error_log("v318_auto_route_doctor_worker", str(e), exc=e, include_traceback=False)
        except Exception: pass


def _v315_cache_status_lines() -> list:
    state = _v315_load_guard_state() if callable(globals().get("_v315_load_guard_state")) else {}
    checked_ts = safe_float(state.get("checked_ts", 0), 0) if isinstance(state, dict) else 0
    age_text = format_elapsed_text(time.time() - checked_ts) + " м „" if checked_ts > 0 else "м•„м§Ғ м—ҶмқҢ"
    summary = str(state.get("summary", "лҢҖкё°") or "лҢҖкё°") if isinstance(state, dict) else "лҢҖкё°"
    checks = state.get("checks", []) if isinstance(state, dict) and isinstance(state.get("checks", []), list) else []
    def _find_status(name):
        for c in checks:
            if isinstance(c, dict) and str(c.get("name", "")) == name:
                return _v315_status_word(bool(c.get("ok")), bool(c.get("warn")))
        return "лҜёнҷ•мқё"
    rem = _v315_new_entry_pause_remaining_sec() if callable(globals().get("_v315_new_entry_pause_remaining_sec")) else 0
    return [
        "рҹӣЎ v318 м—…лҚ°мқҙнҠё м•Ҳм „мһҘм№ҳ",
        f"- мөңк·ј route_doctor: {summary} / {age_text}",
        f"- мғҒнғңм ҖмһҘ: {_find_status('мғҒнғңм ҖмһҘ н…ҢмҠӨнҠё')}",
        f"- л¶ҖнҢ…ліөкө¬: нҢҢмқј {_find_status('л¶ҖнҢ…ліөкө¬ нҢҢмқј мқҪкё°')} / н•ЁмҲҳ {_find_status('л¶ҖнҢ…ліөкө¬ н•ЁмҲҳ')}",
        f"- мһ”кі лҢҖмЎ°: {_find_status('кұ°лһҳмҶҢ мһ”кі  лҢҖмЎ°')}",
        f"- кё°мЎҙліҙмң  ліҙнҳёкҙҖлҰ¬: {_find_status('кё°мЎҙ ліҙмң  ліҙнҳёкҙҖлҰ¬')}",
        f"- л¶ҖнҢ…м¶”м Ғ: {_find_status('л¶ҖнҢ…/мһ¬мӢңмһ‘ м¶”м Ғ')} / {_v318_boot_line()}",
        f"- мӢ к·ңм§„мһ… мқјмӢңм •м§Җ: {'мјңм§җ ' + format_elapsed_text(rem) + ' лӮЁмқҢ' if rem > 0 else 'к°ҖлҠҘ / нҳ„мһ¬ кәјм§җ'}",
        f"- м°ЁлӢЁнҡҹмҲҳ: мӢ к·ңм§„мһ… {V315_STATS.get('new_entry_blocked',0)} / мөңк·ј: {V318_STATS.get('last_note','лҢҖкё°')}",
    ]


try:
    _BASE_RECEIVER_READY_V318 = send_receiver_ready_message
except Exception:
    _BASE_RECEIVER_READY_V318 = None


def send_receiver_ready_message():
    global V318_STARTUP_READY_SENT
    try:
        if V318_STARTUP_READY_SENT:
            _v318_inc("ready_duplicate_blocked", "мҲҳмӢ  мӢңмһ‘ мӨ‘ліө м•ҢлҰј м°ЁлӢЁ")
            return
        V318_STARTUP_READY_SENT = True
        _v318_inc("ready_sent", "н…”л Ҳк·ёлһЁ мҲҳмӢ  мӢңмһ‘ м•ҢлҰј")
        send("\n".join([
            "вң… н…”л Ҳк·ёлһЁ мҲҳмӢ  мӢңмһ‘",
            f"нҳ„мһ¬ лІ„м „: {BOT_VERSION}",
            f"- {_v318_boot_line()}",
            "- л¬ҙкұ°мҡҙ мӢңмһ‘ мһ‘м—…ліҙлӢӨ лӘ…л №м–ҙ мҲҳмӢ мқ„ лЁјм Җ м—ҙм—Ҳм–ҙ.",
            "- мӢңмһ‘ м§Ғнӣ„ нҷ•мқёмқҖ /ping лҳҗлҠ” /cache_status",
        ]))
    except Exception as e:
        log_exception_details("receiver_ready_send_v318", e, prefix="[мҲҳмӢ  мӢңмһ‘ м•ҢлҰј мҳӨлҘҳ]")


def send_startup_message():
    global V318_STARTUP_DONE_SENT
    try:
        if V318_STARTUP_DONE_SENT:
            _v318_inc("startup_duplicate_blocked", "мӢңмһ‘ мҷ„лЈҢ мӨ‘ліө м•ҢлҰј м°ЁлӢЁ")
            return
        V318_STARTUP_DONE_SENT = True
        _v318_inc("startup_sent", "лҙҮ мӢңмһ‘ мҷ„лЈҢ м•ҢлҰј")
        lines = [
            "вң… лҙҮ мӢңмһ‘ мҷ„лЈҢ",
            f"нҳ„мһ¬ лІ„м „: {BOT_VERSION}",
            f"- {_v318_boot_line()}",
            "",
            f"мһҗлҸҷл§ӨмҲҳ: {'мјңм§җ' if AUTO_BUY else 'кәјм§җ'}",
            f"мҡҙмҳҒмӢңк°„: {AUTO_BUY_START_HOUR}:00 ~ {AUTO_BUY_END_HOUR}:00",
            f"мЈјл¬ё мөңлҢҖкёҲм•Ў: {MAX_ENTRY_KRW:,}мӣҗ",
            "",
            "мқҙлІҲ н•өмӢ¬ ліҖкІҪ",
            "- v318: route_doctor л¬ёлІ•нҶөкіјмқёлҚ° мӢӨнҢЁлЎң лңЁлҚҳ false fail мҲҳм •",
            "- v318: v315 мҳӨлһҳлҗң м•Ҳм „кІҖмӮ¬ л¬ёкө¬лҘј мөңмӢ  м•Ҳм „кІҖмӮ¬лЎң көҗмІҙ",
            "- v318: к°ҷмқҖ н”„лЎңм„ёмҠӨ лӮҙ мӢңмһ‘ м•ҢлҰј мӨ‘ліө м°ЁлӢЁ + м§§мқҖ мһ¬л¶ҖнҢ… кё°лЎқ н‘ңмӢң",
            "- v317 нӣ„ліҙн’Ҳм§Ҳ мҲҳм •мқҖ мң м§Җ: early м·ЁмҶҢ мӣҗмқёл¶„н•ҙ/мһ¬к°җмӢң/мӨ‘ліөлҶ“м№Ё л¬¶мқҢ",
            "- мЎ°кұҙ м „мІҙ к°•нҷ”, мһҗлҸҷл§ӨмҲҳ, мҶҗм Ҳ/TP кё°ліёк°’ ліҖкІҪ м—ҶмқҢ",
            "",
            "мһҗм„ён•ң м„ӨлӘ…мқҖ /info",
        ]
        send("\n".join(lines))
    except Exception:
        pass


try:
    _BASE_CACHE_STATUS_TEXT_V318 = build_cache_status_text
except Exception:
    _BASE_CACHE_STATUS_TEXT_V318 = None


def _v318_cache_status_lines() -> list:
    return [
        "рҹ§Ҝ v318 л¶ҖнҢ…/мһҗк°ҖкІҖмӮ¬ ліҙм •",
        "- мң„м№ҳ: м¶ңл Ҙ + route_doctor нҢҗм • + л¶ҖнҢ…м¶”м Ғ + мӢ к·ңм§„мһ… ліҙнҳё",
        "- false fail: v317 л¬ёлІ•нҶөкіјмқёлҚ° лІ„м „н—Ҳмҡ© лҲ„лқҪмңјлЎң мӢӨнҢЁ мІҳлҰ¬лҗҳлҚҳ л¬ём ң ліҙм •",
        f"- мӢңмһ‘м•ҢлҰј: мҲҳмӢ  {V318_STATS.get('ready_sent',0)} / мҷ„лЈҢ {V318_STATS.get('startup_sent',0)} / мӨ‘ліөм°ЁлӢЁ {V318_STATS.get('ready_duplicate_blocked',0)+V318_STATS.get('startup_duplicate_blocked',0)}",
        f"- {_v318_boot_line()}",
        f"- м№ҳлӘ…мӢӨнҢЁ мӢ к·ңм§„мһ… мһҗлҸҷліҙнҳё: {V318_STATS.get('critical_pause_set',0)}нҡҢ",
        f"- мөңк·ј: {V318_STATS.get('last_note','лҢҖкё°')}",
    ]


def build_cache_status_text():
    base = str(_BASE_CACHE_STATUS_TEXT_V318()) if callable(_BASE_CACHE_STATUS_TEXT_V318) else "рҹ§Ҡ лӘ…л №м–ҙ мәҗмӢң мғҒнғң /cache_status"
    try:
        # кё°мЎҙ v315 л¬ёкө¬к°Җ лӮЁм•„ мһҲмңјл©ҙ ліҙкё° мўӢкІҢ мөңмӢ  л¬ёкө¬лЎң л°”кҫјлӢӨ.
        base = base.replace("рҹӣЎ v315 м—…лҚ°мқҙнҠё м•Ҳм „мһҘм№ҳ", "рҹӣЎ v318 м—…лҚ°мқҙнҠё м•Ҳм „мһҘм№ҳ")
        if "рҹ§Ҝ v318 л¶ҖнҢ…/мһҗк°ҖкІҖмӮ¬ ліҙм •" not in base:
            base += "\n" + "\n".join(_v318_cache_status_lines())
    except Exception:
        pass
    return base


def build_cache_status_full_text():
    return build_cache_status_text()


